INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqeg5x002epotakbb0c2t2','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Дизайнер из Лысьвы, Ольга Бучина, о моде в регионах, создании коллекций и вдохновении','Узнайте, как дизайнер Ольга Бучина из Лысьвы, Пермского края, создала коллекцию Сказки леса с грибом мухомором, победив на Fashion bitva в Екатеринбурге.','675-dizajner-iz-lysvy-olga-buchina-pro-sozdanie-kollekcij-vdohnovenie-i-ponimanie-industrii','[{"html":"<strong>В России огромное множество красивых мест с неисчерпаемым запасом энергии и вдохновения. Тому подтверждение наша героиня – дизайнер Ольга Бучина из города Лысьва, Пермский край. На конкурсе </strong><strong>Fashion </strong><strong>bitva в Екатеринбурге Ольга заняла 1 место. Тема коллекции была весьма необычна «Сказки леса», а главным героем выступил гриб мухомор. Мы долго гадали, откуда возник этот образ и, как Ольга продумала свою коллекцию. В этом интервью, мы получили ответы на все свои вопросы. </strong>","type":"paragraph"},{"html":"<strong>ESQUE:</strong> Ольга, здравствуйте. Расскажите, как вы стали дизайнером?","type":"paragraph"},{"html":"<strong>Ольга Бучина:</strong> Здравствуйте. Я тот самый дизайнер, который прошёл все этапы обучения. С самого детства было понятно, кем я буду. В детстве я шила наряды куклам и подругам, устраивала дефиле, наматывая на девчонок мамины платья. Все поля в моих тетрадях были изрисованы яркими эскизами.","type":"paragraph"},{"html":"Первым учебным заведением по профилю было УПК швейного профиля и, конечно же, после 11 класса я уехала к тёте в Екатеринбург, где собственно и поступила в лицей моды. Это был 1995 год. Лихие девяностые.","type":"paragraph"},{"html":"Очень интересные времена были. Помниться, как-то мы даже красили бисер синькой к синему платью, потому что в магазине не было такого цвета.","type":"paragraph"},{"html":"После получения диплома конструктора –модельера, я приняла участие в первом Всероссийском конкурсе дизайнеров, основанным Вячеславом Зайцевым. Там я завоевала почетное второе место. Это был 1998 год.","type":"paragraph"},{"html":"Затем нас 14 человек уехали в Курган и продолжили учёбу в филиале Омского института на технологов лёгкого женского платья.","type":"paragraph"},{"html":"Первой моей работой стало ателье в пригороде Екатеринбурга. Это был огромный и незабываемый опыт.","type":"paragraph"},{"html":"Работа закройщиком помогла мне в развитии своего собственного продукта и почерка.","type":"paragraph"},{"html":"Но нужен был какой-то свежий воздух...","type":"paragraph"},{"html":"И 2003 год стал судьбоносным в моей жизни. Я улетела по контракту в Японию на полгода. Не шить, а танцевать. В школьные годы я ходила в танцевальный кружок и совершенно неожиданно мне предложили контракт.","type":"paragraph"},{"html":"Япония для меня стала страной открытий и перевернула все мое видение на моду, другой мир, другие возможности. Это была моя любовь. Люди с другой планеты. Я впитывала всё, что можно было впитать. Именно там начался мой путь, как дизайнера.","type":"paragraph"},{"html":"<strong>ESQUE:</strong> Ольга, я знаю, что после странствий по городам и странам, вы обосновались в своем родном городке. Откуда черпаете вдохновение там?","type":"paragraph"},{"html":"<strong>Ольга Бучина:</strong> Да, городок наш не большой, но поверьте, у нас есть, где черпать вдохновение. Лысьва в переводе «Лесная вода», вот вам и первое вдохновение - сказочные леса и поля. У нас очень много красивых цветов, грибов, деревьев, необыкновенных мест. Близлежащая деревня Кын, к примеру, - это таинственное и умиротворенное место, место силы. А вообще меня очень вдохновляют люди. И сама я сплошное вдохновение для себя самой и окружающих. Это у меня в крови.","type":"paragraph"},{"html":"<strong>ESQUE:</strong> Ваша конкурсная коллекция в Екатеринбурге про мухоморы – она навеяна природой ваших мест?","type":"paragraph"},{"html":"<strong>Ольга Бучина:</strong> Коллекция называется \"Сказки леса\". Мысли про мухоморы зародились ещё год назад. И грибов этих в наших лесах было видимо невидимо. В очередную прогулку по лесу и пришёл инсайт, а почему бы и да. Гриб к тому же ещё и с интересной биографией. Он может, как вылечить, так и убить. В 19 веке мухомор был символов удачи, богатства и процветания. К тому же, здесь еще сыграла любовь к натуральным тканям и многослойности. А стоило добавить образы элементами вышивки и вязаными чокерами в виде грибов и она заиграла яркими красками. Результат вы увидели на подиуме Fashion bitva.","type":"paragraph"},{"html":"<strong>ESQUE:</strong> Ольга, вы шьете сами коллекции или доверяете это производству?","type":"paragraph"},{"html":"<strong>Ольга Бучина:</strong> Все коллекции я шью сама. Бывает, если что-то не успеваю, девчонки мои мне помогают, но как правило я сама. Все эскизы в моей голове и когда я начинаю творить, то в потоке рождаются новые идеи.","type":"paragraph"},{"html":"<strong>ESQUE:</strong> На конкурсе мы столкнулись с тем, что многие дизайнеры не умеют шить. Отшив коллекции они делегируют швейным цехам. Хотелось бы услышать ваше мнение по этому поводу.","type":"paragraph"},{"html":"<strong>Ольга Бучина:</strong> Цех - это может и хорошо, но я люблю создавать и шить коллекции сама, это как детище и только я знаю, как, что, куда и кому . Я за то, чтобы дизайнеры умели и шить и конструировать и рисовать, это даёт больше возможностей.","type":"paragraph"},{"html":"<strong>ESQUE:</strong> Ваш основной вид деятельности – это ваш бренд или зарабатываете вы на чем-то другом?","type":"paragraph"},{"html":"<strong>Ольга Бучина:</strong> Я, конечно же, развиваю свой Бренд. Мои вещи на подиуме уже адаптированы для ношения аутфитов на улицах города. Я всегда очень тщательно продумываю этот момент, создавая свои коллекции.","type":"paragraph"},{"html":"Так же мы занимаемся пошивом авторских и индивидуальных аутфитов. В первую очередь, шьем для людей. Я очень люблю сама заниматься подборкой ткани для изделий, поэтому они в наличии у меня всегда имеются.","type":"paragraph"},{"html":"<strong>ESQUE: </strong>Дизайнер творческий человек, может ли он стать хорошим бизнесменом?","type":"paragraph"},{"html":"<strong>Ольга Бучина:</strong> Безусловно, дизайнеры - это творческие люди и иногда тяжело совмещать бизнес и творчество, но сейчас такое время, что всему надо учиться.","type":"paragraph"},{"html":"<strong>ESQUE: </strong> Ольга, с какими основными проблемами вы сталкиваетесь в развитии бренда?","type":"paragraph"},{"html":"<strong>Ольга Бучина:</strong> Проблем я не вижу. С большим удовольствием и любовью несу и делаю своё дело. Мои образы разлетаются как горячие пирожки сразу с подиумов.","type":"paragraph"},{"html":"<strong>ESQUE: </strong>Спасибо за интервью. Скажите пару слов начинающим дизайнерам.","type":"paragraph"},{"html":"<strong>Ольга Бучина:</strong> Вериьте в себя и делайте действия, чтобы получать желаемое. И, конечно же, мечтайте!","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqef6y002bpotalgl0hz2a"},{"mediaId":"cmrmqefqo002cpotag7lirert"},{"mediaId":"cmrmqeg2n002dpotas74olkct"}]}]'::jsonb,'cmrmqeelu002apota4t7kr9jq','cmrm8ky9t0000kwta6h8ifq47','cmrm8kyog0005kwta01b9favo','cmrmpdrom0000sstarkqxwts4','2024-08-07T06:00:00.000Z'::timestamp,NULL,NULL,NULL,675,'/fashion/interview/675-dizajner-iz-lysvy-olga-buchina-pro-sozdanie-kollekcij-vdohnovenie-i-ponimanie-industrii.html','2026-07-15T20:48:53.205Z'::timestamp,'2026-07-16T13:56:31.360Z'::timestamp,'''1'':68C ''11'':180C ''14'':262C ''19'':570C ''1995'':197C ''1998'':255C ''2003'':325C ''bitva'':33B,63C,614C ''cmrmqef6y002bpotalgl0hz2a'':948C ''cmrmqefqo002cpotag7lirert'':950C ''cmrmqeg2n002dpotas74olkct'':952C ''esqu'':109C,403C,502C,618C,673C,749C,836C,874C,916C ''fashion'':32B,62C,613C ''galleri'':946C ''paragraph'':107C,118C,165