INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqecel0022pota4qo0asuk','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Константин Маршенин: о роботизированной медицине, бесплатных услугах и  жизни врача в России','Современная медицина кардинально отличается от той, что была еще 30 лет назад.','678-konstantin-marshenin-o-robotizirovannoj-medicine-besplatnyh-uslugah-i-zhizni-vracha-v-rossii','[{"html":"<strong>Современная медицина кардинально отличается от той, что была еще 30 лет назад. Вся наша жизнь с трудом напоминает советскую эпоху. </strong>","type":"paragraph"},{"html":"<strong>В погоне за современными благами, мы стараемся прийти к равновесию и стать успешными во всех сферах своей жизни. Но забываем, что, как и 30 лет назад, человек смертен, а наш организм – хрупкий сосуд, который в одно мгновение может сломаться.</strong>","type":"paragraph"},{"html":"<strong>Наши размышления мы решили подкрепить разговором о ноу-хау в сфере российской медицины. Мы побеседовали с неврологом и мануальным терапевтом Константином Маршениным, основателем собственной одноименной клиники, о нелегком пути врача, новейших разработках и существовании в России бесплатной медицины. И раз уж, речь зашла о роботизации, не заменят ли нас роботы?</strong>","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Константин, здравствуйте. Расскажите об истории создания вашей клиники.","type":"paragraph"},{"html":"<strong>Константин Маршенин:</strong> Здравствуйте. В нашем направлении не так много высококвалифицированных специалистов, особенно в государственных клиниках. Более того, если обратиться к статистике, то в нашем сегменте проблема кадров закрыта лишь на 30%. Именно поэтому передо мной стояла задача не просто открыть клинику, а создать селекцию высококлассных специалистов, с помощью которой мы можем оказать комплексный подход к заболеванию. Можно сказать, что я всю жизнь жил с этой идеей, и как только появилась возможность, сразу воплотил свою мечту в жизнь!","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Какие основные специализации лежат в основе?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>Клиника основана на проблемах лечения опорно-двигательного аппарата, также мы занимаемся функциональной реабилитацией пациентов.","type":"paragraph"},{"html":"Cоответственно, специалисты в клинике это - травматолог, мануальный терапевт, остеопат, реабилитолог и массажисты.","type":"paragraph"},{"html":"Также у нас работают высококлассные спинальные хирурги, и любое хирургическое вмешательство с ними не страшно.","type":"paragraph"},{"html":"В нашей клинике есть магнитно-резонансный стол, разработанный в Новосибирске. Он был изначально предназначен для лечения раковых больных, сейчас его применяют для лечения в частности мышц, связок и суставов. Магнитный стол разгоняет кровоток, стимулируя правильный баланс связок и суставов. Процесс восcтановления ускоряется в разы.","type":"paragraph"},{"html":"Такое бывает, что аппарат создается для одного, а используется позже для совсем других целей.","type":"paragraph"},{"html":"Оборудование в клинике закупается под запрос определенных пациентов. Так в клинике появился еще один инновационный аппарат, который придумали в Швейцарии, а производят в Корее - «робот-мануальный терапевт». Выглядит он абсолютно космически. Его уникальной особенностью является сухое вытяжение позвоночника в мягком щадящем режиме, что не позволяет навредить пациенту. Человек садится в кресло в позицию, как называют лётчика, подключаются датчики и прибор начинает постепенно вытягивать позвоночник, при перенапряжении мышечного волокна аппарат отключается автоматически.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Я слышала, что подобный робот в данный момент только в вашей клинике?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>На сегодняшний день четыре клиники имеют подобный аппарат. Мы вторые кто приобрели этого автоматизированного с искусственным интеллектом мануального терапевта. Особенность аппарата в мягком вытяжении позвоночного столба и отдельного сегмента позвоночника. Компьютер и датчики регулируют степень нагрузки на сегмент, а также степень ротации.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Константин, давайте поговорим немного о вас. Хотелось бы узнать вашу историю. Вы из семьи потомственных врачей и пошли по стопам отца. Верно?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>Не совсем и не то чтобы по стопам. Ещё в школе я работал санитаром в морге. Мое первое знакомство с медициной произошло в большой клинической больнице, потом меня повысили до санитара приемного отделения. Также я работал массажистом, работал медбратом, обучение проходил на базе неврологического отделения. Там и была выбрана специальность – неврология, психоневрология, мануальная терапия, сосудистая неврология – все они тесно связаны между собой.","type":"paragraph"},{"html":"Собственно, так я начал свой профессиональный путь 27 лет назад. И вы знаете, если оглянуться назад, если бы я не стал мануальным терапевтом и неврологом, то я бы стал либо фотографом, либо поваром! Довольно чёткие параллели прослеживаются: повар и фотограф дают достаточно моментальный результат. Человек в этой профессии в моменте понимает что делать, щелк и готов результат, мануальный терапевт почти всегда делает тоже самое - одна манипуляция и мгновенное облегчение.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Очень необычное сравнение. Но хотелось бы, спросить все-таки не об этом, а о том, как школьник оказался санитаром, да еще и работающим с трупами? Вы помните свои ощущения, когда столкнулись впервые со смертью и усопшими?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>Я всегда стремился к самостоятельности, а так как все в семье врачи и квалификации еще не было никакой, поэтому и работа такая - санитар-труповоз. Ощущения только в первые 2-3 дня - холодок под ложечкой, а потом это входит в привычный ритм жизни.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Подскажите, чем неврология отличается от вертебневрологии и психоневрологии?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>Неврология – это здоровье нервной системы, центральной и периферической.","type":"paragraph"},{"html":"Соответственно, неврологи – это врачи, которые занимаются изучением причин и особенностей нервных заболеваний, а также их выявлением, лечением и профилактикой.","type":"paragraph"},{"html":"Неврологические заболевания, которые мы называем проклятием нашей эпохи, на самом деле известны с незапамятных времен.","type":"paragraph"},{"html":"Психоневрология – это про неврозы и другие пограничные состояния, методы их предупреждения. Диагностика, лечение и профилактика.","type":"paragraph"},{"html":"Можно долго углубляться в терминологию, но в общем и целом, стоит понимать одну простую вещь и рассматривать человеческий организм в целом. Это единая система и именно холистический подход на основе доказательных методик лежит в основе деятельности специалистов нашей клиники.","type":"paragraph"},{"html":"Расскажу простой пример. Грыжа в редких случаях является источником боли. Хотя маркетинговая медицинская формулировка звучит по-другому. Действительно, существует ряд грыж, которые дают болевой синдром. Но такое бывает крайне редко. Остальная боль носит связочный или мышечный характер, что в свою очередь ведет к пережатию спинно-мозгового корешка. То есть причина боли при грыжи в 90 процентах случаев связана с мышцей. Следовательно, не всегда причина боли лежит в рамках локализации боли, как все привыкли думать.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Константин, хотелось бы затронуть социальный аспект. Судя по нашей беседе, вы имеете не малый опыт работы в государственных больницах. За последние годы как-то меняется уровень бесплатной медицины в России?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>Уровень государственной медицины, безусловно, растет, особенно это заметно по крупным городам и федеральным центрам. Благодаря этому уровню в РФ есть уникальные специалисты и методики не хуже, чем в других странах.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Я посещала бесплатные больницы и приходила в ужас от качества зданий: разрушенные стены, протекшие потолки и сквозящие окна. К сожалению, у большинства населения нет выбора, и им приходится лежать в государственных больницах, но я, как понимаю, у врачей выбор есть. Что удерживает врачей на работе в государственных учреждениях?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>Сначала удерживает желание получить опыт. Так или иначе нужно его накопить, насмотреть, увидеть, наработать и только тогда возможно какое либо движение в сторону платной медицины. В любом случае, возвращаясь к холистическому подходу, всегда важен широкий спектр взгляда и опыта.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>А как быть с нехваткой кадров в государственных учреждениях? Вы видите решение этой проблемы?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>Кадры, как говорится, решают все. Проблема более широкая, начиная с воспитания дошкольного возраста (формирование в ребенке здорового мышления) и заканчивая построением новой системы для обучения кадров. Конечно же, вопрос заработной платы очень важен. Необходимо создание инфраструктуры в маленьких городах и поселениях, куда доктора смогут поехать работать без страха.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Если сравнивать медицину в России и в других странах – как оцените наше развитие?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>Я думаю, что нет беспроблемных стран, континентов и клиник. Методики, специалисты и аппаратура, даже сейчас в не самые простые времена, есть. При желании возможно все.","type":"paragraph"},{"html":"Я не люблю жаловаться. Хочешь изменить ситуацию - создавай, открывай, передавай опыт. Чем мы активно и занимаемся в рамках клиники.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Рассматривая ваш новый аппарат-робот, невольно возникает вопрос. Смогут ли роботы заменить врачей?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>Конечно же, нет. Все же мы не просто «ставим диагноз». Прежде всего, мы люди, люди в помогающей профессии. И залог успешного результата всегда - это совместная слаженная работа врача и пациента. Умение слышать, успокоить и быть на связи и поддерживать 24/7. Сомневаюсь, что роботам это под силу. Если убрать психоэмоциональные факторы и говорить более серьезно, то понятно, что медицина идет в сторону цифровизации. Мы уже записываемся к врачу online, нам уже рекомендуют те или иные продукты, проекты, посещения тех или иных мест исходя из анализа нашего поиска и потребностей, паттернов поведения, зафиксированных в цифровом следе.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Каким вы видите развитие медицины в России в ближайшие 5 лет?","type":"paragraph"},{"html":"<strong>Константин Маршенин: </strong>Все в наших руках. Ситуации геополитические, экономические и культурные бывают разные. Наша задача – несмотря ни на что, максимально качественно делать свою работу.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqec4q0020pota5z7lmhwm"},{"mediaId":"cmrmqecd90021potal3ndkyck"}]}]'::jsonb,'cmrmqebuz001zpotaijap4kjc','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyz0000akwtaq6w9733r','cmrmpdrom0000sstarkqxwts4','2024-08-23T06:00:00.000Z'::timestamp,NULL,NULL,NULL,678,'/beauty/mnenie/678-konstantin-marshenin-o-robotizirovannoj-medicine-bespl