INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqr548003luktat6d392nb','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'«ПУАНТЫ ДЛЯ МОЕЙ МАМЫ» - новый фильм режиссера Яны Недзвецкой','Весной 2024 года состоится премьера нового фильма режиссера Яны Недзвецкой – «Пуанты для моей мамы».Если в мире несчастлив хотя бы один ребенок - вина лежит на каждом из нас.В современном мире аутизм в той или иной степе','630-puanty-dlja-moej-mamy-novyj-film-rezhissera-jany-nedzveckoj','[{"html":"Весной 2024 года состоится премьера нового фильма режиссера Яны Недзвецкой – «Пуанты для моей мамы».","type":"paragraph"},{"html":"Если в мире несчастлив хотя бы один ребенок - вина лежит на каждом из нас.","type":"paragraph"},{"html":"В современном мире аутизм в той или иной степени диагностируется у каждого 88-го ребенка. Это не проблема нашей страны, это общемировая проблема.","type":"paragraph"},{"html":"В фильме режиссера Яны Недзвецкой «Пуанты для моей мамы» главная героиня - девчонка 15 лет, с обидной кличкой \"Крыся\", с синдромом Аспергера, до 7 лет жила в чуме на стойбище оленеводов в тундре. \"Крысю\" до школы воспитывал отчим - хант, от которого сбежала 16-летняя жена сразу после родов, оставив новорожденную, не родную ему дочь.","type":"paragraph"},{"html":"В небольшой малокомплектной северной школе \"Крысю\" отбирают в балетную школу-интернат в Вологде. Там, как и в начальной школе, ее не любят одноклассники, не понимания сути ее заболевания.","type":"paragraph"},{"html":"У \"Крыси\" одна мечта - стать знаменитой балериной. Ее диагноз – не приговор. Дети с синдромом Аспергера (слабая степень аутизма) часто талантливы, хотя и плохо социализированы.","type":"paragraph"},{"html":"В фильме прослеживается жизнь героини от ее рождения на стоянке оленеводов на крайнем севере России до учебы в Академии балета в Москве.","type":"paragraph"},{"html":"В этом фильме все подлинное - съемки начались в республике Коми, на стойбище оленеводов - братьев Чупровых, продолжились в Карелии, в исторической деревне Пяльма на Онежском озере.","type":"paragraph"},{"html":"После Пяльмы съемки проходили в Вологде и ее окрестностях. Потрясающая природа Вологодской области, ее самые красивые места, удивительные люди этого города — все это отражено в фильме Яны.","type":"paragraph"},{"html":"Яна Недзвецкая снимает красивые фильмы, каждый кадр которых - живописная картина с четко выверенными пропорциями и тонко подобранными цветами. Одним из главных героев фильмов Яны всегда выступает потрясающе красивая природа русского Севера, что добавляет фильмам Яны настоящую подлинность.","type":"paragraph"},{"html":"Удивительно талантливых актеров собрал этот глубокий и по сути, и по смыслу фильм. Героиню на главную роль - Инну Новикову искали больше года. Если бы не случайная статья в местной прессе о талантливой девочке, поступившей в Академию балета - фильма могло бы и не случиться. Друга \"Крыси\" играет уже известный юный актер Сергей Федоров (12 лет).","type":"paragraph"},{"html":"Одну из главных ролей в фильме - бабушки \"Крыси\" играет удивительная актриса, Заслуженная артистка Российской Федерации Оксана Сташенко - пластичная, яркая, харизматичная. Роль ее сестры играет известная актриса - Дина Корзун. В роли ректора Академии, самого себя играет в фильме Народный артист России, премьер балета - Сергей Филин.","type":"paragraph"},{"html":"Красивые сцены фильма были сняты в Вологодском Детском музыкальном театре, (хореографическое отделение) с его удивительными преподавателями - фанатами своего дела и талантливыми детьми.","type":"paragraph"},{"html":"Подлинность фильму добавляет то, что всех преподавателей балета в фильме играют настоящие преподаватели балетных школ Москвы и Вологды.","type":"paragraph"},{"html":"Настоящая находка фильма - юная Лина Базаева, которая сыграла героиню в детстве - обе девочки внешне похожи между собой.","type":"paragraph"},{"html":"Сыграть больного аутизмом ребенка - невероятно сложно. Обе актрисы - Инна и Лина справились с этим отлично. Удивительно ювелирно подобрана и другая пара актрис - Ольга Макеева и Татьяна - сыгравшие роль Сашки в 16 и в 35 лет. Впечатление, что это родные сестры. Хотя это не так.","type":"paragraph"},{"html":"Подлинность фильма видна даже в мелочах. В доме и квартире \"Крыси\" стены украшает живопись Михаила Комарова - известного мальчика с синдромом РАС (расстройства аутистического спектра) из Астрахани. Картины Миши уже покорили весь мир! Надежда - мама Миши, разрешила использовать копии потрясающих работ Миши в фильме «Пуанты для моей мамы». Тем более - по мистическому совпадению - героиня фильма любит рисовать странных рыб, которых часто рисует и Миша.","type":"paragraph"},{"html":"Яна Недзвецкая все свои фильмы уже много лет снимает с талантливым оператором - постановщиком Василием Очеретнюком.","type":"paragraph"},{"html":"Ждем премьеру фильма. Надеемся увидеть этот интересный, сложный и глубокий по смыслу фильм в нашем прокате.","type":"paragraph"},{"html":"<b><i>Тизеры:</i></b>","type":"paragraph"},{"html":"<b><i><a href=\"https://youtu.be/jpjBsDKp9hg\" target=\"_blank\" rel=\"noopener noreferrer\">https://youtu.be/jpjBsDKp9hg</a></i></b>","type":"paragraph"},{"html":"<b><i><a href=\"https://youtu.be/fFio-44Fti8\" target=\"_blank\" rel=\"noopener noreferrer\">https://youtu.be/fFio-44Fti8</a></i></b>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqr4qo003jukta1gmvsmby"},{"mediaId":"cmrmqr52n003kuktazbwuz87k"}]}]'::jsonb,'cmrmqr2k3003iukta8a21inw4','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz6g000dkwtai45m48bj','cmrmpdrom0000sstarkqxwts4','2023-12-19T06:00:00.000Z'::timestamp,NULL,NULL,NULL,630,'/sobytija/kino/630-puanty-dlja-moej-mamy-novyj-film-rezhissera-jany-nedzveckoj.html','2026-07-15T20:58:45.416Z'::timestamp,'2026-07-16T13:57:01.694Z'::timestamp,'''/ffio