24C,554C ''синдром'':126C,208C,581C ''слаб'':210C ''сложн'':520C,653C ''случ'':387C ''случайн'':370C ''смысл'':356C,657C ''снима'':307C,636C ''снят'':453C ''соб'':511C ''собра'':348C ''совпаден'':613C ''современ'':39B,82C ''состо'':13B,50C ''социализирова'':218C ''спектр'':585C ''справ'':526C ''сраз'':151C ''стат'':199C,371C ''сташенк'':418C ''стен'':573C ''степ'':46B ''степен'':89C,211C ''стойбищ'':135C,258C ''стоянк'':231C ''стран'':100C,618C ''сут'':189C,353C ''сцен'':450C ''съемк'':252C,277C ''сыгра'':502C,515C,541C ''талантлив'':214C,346C,376C,469C,638C ''татья'':540C ''театр'':458C ''тизер'':665C ''то'':43B,86C ''тонк'':320C ''тундр'':138C ''увидет'':650C ''удивительн'':292C,345C,411C,463C,530C ''украша'':574C ''учеб'':238C ''фанат'':465C ''федерац'':416C ''федор'':396C ''филин'':445C ''фильм'':6A,16B,53C,108C,223C,249C,300C,309C,327C,338C,357C,382C,407C,438C,451C,475C,483C,497C,563C,604C,615C,632C,648C,658C ''хант'':144C ''харизматичн'':421C ''хореографическ'':459C ''хот'':28B,68C,215C,555C ''цвет'':322C ''част'':213C,621C ''четк'':316C ''чум'':133C ''чупров'':261C ''школ'':141C,167C,173C,182C,488C ''школу-интернат'':172C ''эт'':96C,101C,297C,528C,552C,556C ''ювелирн'':531C ''юн'':393C,498C ''ян'':8A,18B,55C,110C,301C,305C,328C,339C,628C ''ярк'':420C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmpdujc001ossta59vr9ruj','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Евгений Первушин: "Нас долгое время учили: любить всё западное, ведь там все красивее"','ESQUE: Евгений, здравствуйте.','687-evgenij-pervushin','[{"html":"<strong>Интерес к устройству event-индустрии в России зрел у нас уже давно. Откровенно и обо всем мы решили поговорить с Евгением Первушиным - ведущим крайних показов Fashion bitva 12. Интересен тот факт, что у Евгения свой взгляд на устройство event-рынка, жизни российского глянца и русских женщин. Здесь есть над чем задуматься и во что поверить! </strong>","type":"paragraph"},{"html":"<strong>ESQUE:</strong> Евгений, здравствуйте. Расскажите немного о себе.","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> Здравствуйте, Уважаемая редакция. Меня зовут Евгений Первушин. Во-первых, я отец и муж. Мне 37 лет. Большую часть своей жизни я работаю ведущим различного рода мероприятий.","type":"paragraph"},{"html":"<strong>ESQUE:</strong> Вы были ведущим на нашем показе в Новосибирске, а потом и на финале в Москве. Начнем с регионального показа. Как вам коллекции наших сибирских дизайнеров?","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> Честно говоря, мир моды для меня не был открытием и я примерно понимал, что я там увижу, но сама тема «Народы мира» - это было тем, чего я ждал очень давно.","type":"paragraph"},{"html":"Мне было очень приятно наблюдать, как дизайнеры, не стесняясь, делали в своих коллекциях упор на традиционные мотивы. И было видно, что данная тема помогает людям поверить в себя и в своё будущее, а фундаментом для этого становятся наши традиции!","type":"paragraph"},{"html":"<strong>ESQUE:</strong> Евгений, да, это сейчас очень актуальная тема, вы правы. Когда мы стали изучать эту ее, то увидели, что сейчас очень много народности во всем: в моде, в культуре, в здравоохранении, в искусстве. Как вы считаете, почему такой активный прицел идет именно в этом направлении?","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> Я не считаю, что этот прицел появился сейчас, это было всегда, во все времена. Просто у нас есть определенная проблема - нас иногда уносит. Но после этого всегда все возвращается с ещё большей степенью. Мы вспоминаем про свои корни, традиции, истоки и начинается дикий поиск и попытка понять кто мы.","type":"paragraph"},{"html":"Мне кажется, именно сейчас мы это и наблюдаем.","type":"paragraph"},{"html":"<strong>ESQUE:</strong> Вы долгое время жили в Казахстане. Там так же?","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> Я родился и вырос в Казахстане. И там это особо остро чувствуется.","type":"paragraph"},{"html":"Всю свою жизнь я наблюдал, как разные национальности проявляли стремление не потерять свои традиции, с гордостью их, проявляя и внедряя во все сферы жизни.","type":"paragraph"},{"html":"<strong>ESQUE:</strong> А почему решили вернуться на Родину?","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> Благодаря тому, что запрос на аутентичность был всегда в моей жизни, я так до конца и не смог ассимилироваться, - поэтому и решил вернуться на историческую родину.","type":"paragraph"},{"html":"<strong>ESQUE: </strong>Бытует мнение, что русскому человеку будет сложно ужиться с менталитетом чужой страны.","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> В корне с вами не согласен.","type":"paragraph"},{"html":"Я очень часто наблюдал за тем, как другие народы отмечают свои праздники, прославляют свои традиции, а русский человек, наоборот, хочет уйти от них и мимикрировать под сложившиеся ситуации, как будто бы стесняясь…","type":"paragraph"},{"html":"Это происходит не только за рубежом, но наблюдается и на исконно русских территориях.","type":"paragraph"},{"html":"Русскому человеку всегда кажется, что если он на свадьбе откусит каравай, то все над ним будут смеяться и упрекать в старомодности.","type":"paragraph"},{"html":"В то время как в том же Казахстане, любой праздник - это набор всевозможных обрядов и традиций и там этого никто не стесняется, а наоборот, испытывают гордость.","type":"paragraph"},{"html":"Поэтому я считаю, что русскому человеку не то чтобы сложно ужиться, сложнее не потерять себя и свой ДНК. В тот момент, когда русский человек отбрасывает эти страхи и начинает демонстрировать свои традиции - тут и появляются подобного рода мнения и сложности. Может потому что эти поведения просто непривычны для других?","type":"paragraph"},{"html":"<strong>ESQUE: </strong>Очень интересные выводы. Мне кажется, что просто наши старые традиции изжили себя, а новые еще не созданы. Мы немного потерялись в быстро меняющемся мире, где русские народные костюмы и нано технологии идут бок о бок друг с другом.","type":"paragraph"},{"html":"Евгений, раз мы начали говорить о традициях, то не могу не затронуть тему различий в этой области. Есть принципиальная разница в event индустрии в Москве, в регионах России и других странах? Можно рассмотреть на примере Казахстана, Москвы и Новосибирска.","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> Для начала давайте переведём с английского на понятный нам русский язык и дадим четкое определение: Event (с англ. «событие») — публичные мероприятия, которые носят развлекательный и/или рекламный характер. Относится также и к бьюти и фэшн индустрии.","type":"paragraph"},{"html":"Главные отличия заключаются в масштабах, профессионализме и ожиданиях аудитории, что в свою очередь, влияет на подход к подготовке и проведению мероприятий.","type":"paragraph"},{"html":"Наша страна огромна и разнообразна и любое событие будет отличаться в зависимости от того региона, в котором оно происходит. Каждый регион - это свои традиции, свое видение и понимание: про эти факторы не стоит забывать.","type":"paragraph"},{"html":"Безусловно, в регионах есть оглядка на столицу, которая во все времена задавала тренды и это нормально, но нельзя просто взять и организовать событие по одному и тому же сценарию и в Москве и в регионе.","type":"paragraph"},{"html":"В Москве, как правило, более разнообразная аудитория с высокой концентрацией людей, имеющих опыт участия в различных мероприятиях. Это может быть связано с большим количеством культурных, образовательных и бизнес активностей. В регионах же аудитория часто менее избалована и готова воспринимать события с большим интересом, при этом внимание к деталям может быть более искренним и непосредственным.","type":"paragraph"},{"html":"И вот в чем парадокс. Я, наверное, вас сильно не удивлю, когда скажу, что большинство работников публичных событий Москвы, которые задают тренды мероприятий, выходцы из тех же регионов. Я и сам такой. И таких примеров тысячи.","type":"paragraph"},{"html":"Вот такой круговорот и получается, что и регионы не могут без Москвы, а Москва без регионов.","type":"paragraph"},{"html":"А если коснуться моего опыта работы в Казахстане, а я там работал и в регионах и в столице, скажу, что там всё то же самое: также с оглядкой на столицу, но за небольшим исключением, что они не боятся делать упор на национальные традиции и там даже есть негласное соревнование - кто в этом круче и богаче.","type":"paragraph"},{"html":"<strong>ESQUE: </strong>Хорошо, в этом разобрались. Вернемся к теме народности в нашем конкурсе. Несмотря на исконно русскую тему показов, мы все же видим отголоски запада в коллекциях и пусть даже бессознательно, пытаемся повторить за ними. Вы заметили это?","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> Я не стал бы говорить, что это происходит бессознательно. Наоборот, вполне осознанно, и это мы наблюдаем не только в моде.","type":"paragraph"},{"html":"Это то, чему нас долгое время учили: любить всё западное, ведь там все красивее. Однако несмотря на это, я считаю, что наша мода и наши женщины во много раз красивее и интереснее!","type":"paragraph"},{"html":"И больше чем уверен, если всё пойдёт так, как сейчас, то в скором будущем это «у них» будут заметны отголоски наших коллекций.","type":"paragraph"},{"html":"<strong>ESQUE: </strong>Евгений, вы увидели как изменилась развлекательная индустрия после пандемии?","type":"paragraph"},{"html":"<strong>Евгений Первушин: </strong>Мне кажется, что весь мир в целом изменился после пандемии.","type":"paragraph"},{"html":"<strong>ESQUE: </strong>Если судить по Москве, то в столице стало гораздо меньше масштабных мероприятий. И это напрямую связано с уходом иностранного глянца. Как бы мы не любили Россию, но маркетинг и глянец наши делать, еще не научились. Возможно, именно поэтому, мы все еще оглядываемся туда? Конечно, никто не отрицает, что когда-то, возможно, равняться будут на нас, но пока это продолжаем делать все еще мы.","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> Давайте разберёмся. В какой момент мы решили, что мы чего-то не умели и наш глянец чем-то уступает? Вспомним наших мам и бабушек - разве они были не модные, не красивые? Тут, наверное, дело в восприятии.","type":"paragraph"},{"html":"Европейская мода и стиль жизни - это все на продажу. 80% того, что показано в зарубежных журналах не является носибельным.","type":"paragraph"},{"html":"А наша мода и наши журналы имели более прикладной характер. Нашим женщинам недостаточно просто что-то купить, им нужно понять, как и из чего это сшить (наши мамы всегда умели и шить и вязать). Наш глянец и мода - это не только про светские мероприятия, а про то, как выглядеть красиво и в повседневной жизни, каждый день!","type":"paragraph"},{"html":"И поэтому я считаю, что мы ни в чем не отстаём, мы просто идём другим путём.","type":"paragraph"},{"html":"А что касаемо ухода каких-то европейских брендов - я этот факт считаю очень позитивным. Ни для кого не секрет, что у нас огромное количество отечественных брендов, которым долгое время приходилось мимикрировать под зарубежные и быть в тени, сейчас же все стало на свои места.","type":"paragraph"},{"html":"И поверьте мне, брендов станет еще больше!","type":"paragraph"},{"html":"Скажу также про мероприятия. Их не стало меньше. Далеко ходить не будем. Fashion bitva от вашего издания, которая дала жизнь коллекциям и дизайнерам, была, на мой взгляд, покруче любой недели моды в Европе.","type":"paragraph"},{"html":"<strong>ESQUE: </strong>Евгений, спасибо за такое лестное сравнение.","type":"paragraph"},{"html":"Скажите, а event-сфера она живет по тому же принципу, что и глянец. Пытаются ли event-организаторы европеизировать мероприятия?","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> Я работаю ведущим с 2005 года и event-сфера тогда уже была завязана на европеизацию, была придумана такая концепция, как «европейская» свадьба, но вот в чем парадокс - каждая невеста представляла ее себе по-своему.","type":"paragraph"},{"html":"И это иногда переходило в абсурд. Здесь я могу признаться - в этом виноваты и сами организаторы, потому что опять же включалась боязнь продемонстрировать свои русские традиции и, казалось, если мы уберём со свадебного вечера «выкуп невесты», то всё сразу заиграет модными красками и будет похоже на фильм «Великий Гэтсби».","type":"paragraph"},{"html":"Но есть и хорошая новость!","type":"paragraph"},{"html":"В последние годы в event-сфере так же, как и во всех других, стал появляться запрос на аутентичность. Мы перестаём стесняться своей культуры и традиций, чему я очень рад способствовать! Если еще год назад мне приходилось рассказывать заказчикам о значимости и важности традиций, то сейчас просто стоит вопрос - как красиво их вписать в мероприятие.","type":"paragraph"},{"html":"<strong>ESQUE: </strong> Звучит очень обнадеживающе. Евгений, спасибо за очень интересное интервью!","type":"paragraph"},{"html":"Хотелось бы услышать от вас пару напутственных советов начинающим ведущим.","type":"paragraph"},{"html":"<strong>Евгений Первушин:</strong> Давать советы - это дурной тон, но я лишь могу дать рекомендации, чего точно не следует делать:","type":"paragraph"},{"html":"- не всегда стоит слепо соглашаться с заказчиком, нужно видеть все мероприятие в целом и иногда объяснять важность того или иного действия;","type":"paragraph"},{"html":"- не говорить скриптами - каждое мероприятие всегда индивидуально.","type":"paragraph"},{"type":"image","mediaId":"cmrmpox1z001m8gtagixnkmdi"}]'::jsonb,'cmrmpdug2001nssta2cmn7bck','cmrm8kzli000ikwtafbw33jnj','cmrm8kzns000jkwtahwuubl9w','cmrmpdrom0000sstarkqxwts4','2024-12-21T06:00:00.000Z'::timestamp,NULL,NULL,NULL,687,'/persona/intervju/687-evgenij-pervushin.html','2026-07-15T20:20:25.560Z'::timestamp,'2026-07-16T13:56:17.473Z'::timestamp,'''12'':45C ''2005'':1515C ''37'':104C ''80'':1289C ''bitva'':44C,1452C ''cmrmpox1z001m8gtagixnkmdi'':1751C ''esqu'':14B,77C,119C,225C,338C,395C,436C,619C,1016C,1141C,1169C,1475C,1668C ''event'':21C,57C,682C,720C,1488C,1502C,1519C,1615C ''event-индустр'':20C ''event-организатор'':1501C ''event-рынк'':56C ''event-сфер'':1487C,1518C,1614C ''fashion'':43C,1451C ''imag'':1749C ''paragraph'':75C,85C,117C,146C,181C,223C,271C,325C,336C,349C,366C,393C,403C,434C,450C,461C,496C,512C,536C,565C,617C,659C,701C,742C,766C,803C,841C,898C,937C,956C,1014C,1054C,1079C,1114C,1139C,1152C,1167C,1235C,1278C,1300C,1360C,1379C,1427C,1437C,1473C,1483C,1507C,1548C,1600C,1608C,1666C,1679C,1692C,1713C,1737C,1747C ''абсурд'':1555C ''активн'':263C,871C ''актуальн'':231C ''англ'':722C ''английск'':710C ''ассимилирова'':425C ''аудитор'':752C,849C,875C ''аутентичн'':412C,1628C ''бабушек'':1264C ''безусловн'':805C ''бессознательн'':1045C,1066C ''бизнес'':870C ''благодар'':407C ''бо'':995C ''богач'':1012C ''бок'':652C,654C ''больш'':106C,306C,865C,884C ''большинств'':914C ''боязн'':1571C ''бренд'':1389C,1407C,1432C ''буд'':1450C ''будут'':529C,1133C,1223C ''будущ'':214C,1129C ''быстр'':641C ''быт'':437C ''бьют'':73