INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmpduum001qsstacymwolvs','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Я СГОРЕЛА','В гонке за успехом, признанием и очередным трофеем в современном мире очень важно не упустить главное – СЕБЯ!','685-ja-sgorela','[{"html":"В гонке за успехом, признанием и очередным трофеем в современном мире очень важно не упустить главное – СЕБЯ! Все чаще в толпе мы видим людей с потухшими глазами и уставшим лицом. Очень часто люди не понимают себя, не знают, что действительно хотят и для чего или кого ставят цели, ведущие в никуда. В итоге результат один: ВЫГОРАНИЕ. Что это такое? Как с ним справиться? И почему выгорание – это бич современного мира?","type":"paragraph"},{"html":"Мы поговорили с психологами и психотерапевтами и ответили на самые важные для себя вопросы. Мы уверены, что благодаря этому фильму, на свои вопросы ответите и вы!","type":"paragraph"},{"html":"<em><u>Благодарим наших героинь:</u></em>","type":"paragraph"},{"html":"Каллаева Карина – психоаналитический психотерапевт и тренинговый групп-аналитик","type":"paragraph"},{"html":"Ковтун Татьяна – психолог, сексолог, энерготерапевт","type":"paragraph"},{"html":"Луневская Марина - интегративный психолог, когнитивно-поведенческий терапевт и тренер по развитию эмоционального интеллекта","type":"paragraph"},{"html":"Мокина Алена – врач, психолог КПТ","type":"paragraph"},{"html":"Мелкая Анастасия – практический и кризисный психолог","type":"paragraph"},{"html":"Романова Елена – психолог, гештальт-терапевт","type":"paragraph"},{"html":"Гильванова Лилиана - психолог (юридический психолог), сертифицированный психолог-консультант в краткосрочных видах психотерапии (символдрама, психосоматичечкая кинезиология)","type":"paragraph"},{"html":"<iframe width=\"853\" height=\"480\" src=\"https://vk.com/video_ext.php?oid=-30954338&amp;id=456239083&amp;hd=2&amp;autoplay=1\" frameborder=\"0\" allowfullscreen=\"\"></iframe>","type":"embed"}]'::jsonb,'cmrmpoxlk001o8gtaz7j51zdv','cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2024-10-14T06:00:00.000Z'::timestamp,NULL,NULL,NULL,685,'/psihologija/intervju-2/685-ja-sgorela.html','2026-07-15T20:20:25.966Z'::timestamp,'2026-07-16T13:56:20.290Z'::timestamp,'''emb'':209C ''paragraph'':90C,119C,125C,137C,145C,162C,170C,179C,188C,207C ''ал'':165C ''аналитик'':135C ''анастас'':173C ''бич'':86C ''благодар'':109C,121C ''важн'':15B,31C,102C ''ведущ'':67C ''вид'':41C,201C ''вопрос'':105C,114C ''врач'':166C ''выгоран'':74C,84C ''героин'':123C ''гештальт'':185C ''гештальт-терапевт'':184C ''гильванов'':190C ''главн'':18B,34C ''глаз'':45C ''гонк'':4B,20C ''групп'':134C ''групп-аналитик'':133C ''действительн'':58C ''ел'':182C ''знают'':56C ''интегративн'':149C ''интеллект'':160C ''итог'':71C ''каллаев'':127C ''карин'':128C ''кинезиолог'':205C ''ковтун'':139C ''ког'':64C ''когнитивн'':152C ''когнитивно-поведенческ'':151C ''консультант'':198C ''кпт'':168C ''краткосрочн'':200C ''кризисн'':176C ''лилиа'':191C ''лиц'':48C ''луневск'':147C ''люд'':42C,51C ''марин'':148C ''мелк'':172C ''мир'':13B,29C,88C ''мокин'':164C ''наш'':122C ''никуд'':69C ''ответ'':99C,115C ''очен'':14B,30C,49C ''очередн'':9B,25C ''поведенческ'':153C ''поговор'':93C ''понима'':53C ''потухш'':44C ''поч'':83C ''практическ'':174C ''признан'':7B,23C ''психоаналитическ'':129C ''психолог'':95C,141C,150C,167C,177C,183C,192C,194C,197C ''психолог-консультант'':196C ''психосоматичечк'':204C ''психотерап'':202C ''психотерапевт'':97C,130C ''развит'':158C ''результат'':72C ''романов'':181C ''сам'':101C ''сво'':113C ''сгорел'':2A ''сексолог'':142C ''сертифицирова'':195C ''символдрам'':203C ''современ'':12B,28C,87C ''справ'':81C ''став'':65C ''так'':77C ''татья'':140C ''терапевт'':154C,186C ''толп'':39C ''тренер'':156C ''тренинго