INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmpdv2n001ssstaeabyjs3j','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Прилучные будни: как бывший муж отбирает детей у матери','2 октября состоялся суд по определению места жительства детей Павла и Агаты Прилучных.','684-priluchnye-budni-kak-byvshij-muzh-otbiraet-detej-u-materi','[{"html":"2 октября состоялся суд по определению места жительства детей Павла и Агаты Прилучных. Заседание продолжалось около 5 часов, и если Прилучный вышел бодрый и веселый, то Агата покидала здание суда, молча, в спешке и явно расстроенная.","type":"paragraph"},{"html":"Позже она прокомментировала суд весьма емко, но достаточно категорично:","type":"paragraph"},{"html":"«Друзья! Прокомментирую вчерашний день, знаю, что вы переживаете! Я вчера ушла из зала суда абсолютно без сил, всё, что происходит — это полный ад! Я не желаю ни одной матери испытать то, что испытала вчера я»!","type":"paragraph"},{"html":"Поклонники бывшей звездной четы разделились на два лагеря. Кто-то поддерживает актрису и призывает многодетного отца остановиться, не лишая мать детей, а кто-то обвиняет Муцениецу в жадности, упрекая в желании увеличить алименты, ведь именно после того, как актриса подала в суд на бывшего мужа по алиментам, началась «война» за опеку над детьми.","type":"paragraph"},{"html":"«Не стыдно вам отбирать сынульку у мамы, нда …» - одни пишут возмущенные люди в запрещенной сети актера.","type":"paragraph"},{"html":"«Павел, вы великий актер, пожалуйста, оставайтесь таким же человеком» - другие призывают одуматься Прилучного.","type":"paragraph"},{"html":"В звездном сообществе актеру пророчат забвение после такого отношения к бывшей жене, коллеги по цеху высказываются очень смело и категорично.","type":"paragraph"},{"html":"Интересен тот факт, что в России нужен веский повод для определения места жительства ребенка с отцом при наличии матери. В первую очередь, ребенок остается с отцом, когда мать имеет пагубные пристрастия, к которым относятся алкоголь или наркотики.","type":"paragraph"},{"html":"И, конечно же, суд на стороне отца, если ребенок, достигший 10-летнего возраста, сам решает остаться с ним жить.","type":"paragraph"},{"html":"Именно на второй пункт намекает Прилучный, отправившись с сыном в Геленджик во время учебного года, объясняя это желанием Тимофея.","type":"paragraph"}]'::jsonb,'cmrmpoy8i001q8gtal3xi6y8m','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-10-05T06:00:00.000Z'::timestamp,NULL,NULL,NULL,684,'/v-mire/684-priluchnye-budni-kak-byvshij-muzh-otbiraet-detej-u-materi.html','2026-07-15T20:20:26.255Z'::timestamp,'2026-07-16T13:56:22.067Z'::timestamp,'''10'':278C ''2'':10B,23C ''5'':39C ''paragraph'':60C,72C,110C,168C,187C,203C,226C,266C,288C,310C ''абсолютн'':88C ''агат'':21B,34C,49C ''ад'':96C ''актер'':185C,192C,208C ''актрис'':124C,152C ''алимент'':146C,160C ''алкогол'':262C ''бодр'':45C ''будн'':2A ''бывш'':4A,113C,157C,215C ''велик'':191C ''весел'':47C ''веск'':235C ''весьм'':66C ''возмущен'':180C ''возраст'':280C ''войн'':162C ''врем'':302C ''все'':91C ''втор'':292C ''вчер'':83C,107C ''вчерашн'':76C ''высказыва'':220C ''вышел'':44C ''геленджик'':300C ''год'':304C ''ден'':77C ''дет'':7A,18B,31C,133C ''детьм'':166C ''достаточн'':69C ''достигш'':277C ''друг'':198C ''друз'':74C ''емк'':67C ''жадност'':141C ''жела'':99C ''желан'':144C,307C ''жен'':216C ''жит'':286C ''жительств'':17B,30C,240C ''забвен'':210C ''зал'':86C ''запрещен'':183C ''заседан'':36C ''звездн'':114C,206C ''здан'':51C ''зна'':78C ''имеет'':256C ''имен'':148C,290C ''интерес'':228C ''испыта'':103C,106C ''категоричн'':70C,224C ''коллег'':217C ''котор'':260C ''кто-т'':120C,135C ''лагер'':119C ''летн'':279C ''лиш'':131C ''люд'':181C ''мам'':176C ''мат'':132C,255C ''матер'':9A,102C,246C ''мест'':16B,29C,239C ''многодетн'':127C ''молч'':53C ''муж'':5A,158C ''муцениец'':139C ''налич'':245C ''намека'':294C ''наркотик'':264C ''нача'':161C ''нда'':177C ''нуж'':234C ''обвиня'':138C ''объясн'':305C ''одн'':101C,178C ''одума'':200C ''окол'':38C ''октябр'':11B,24C ''опек'':164C ''определен'':15B,28C,238C ''оста'':251C,283C ''остава'':194C ''останов'':129C ''отбира'':6A,173C ''относ'':261C ''отношен'':213C ''отправ'':296C ''отц'':128C,243C,253C,274C ''очен'':221C ''очеред'':249C ''павел'':189C ''павл'':19B,32C ''пагубн'':257C ''перв'':248C ''пережива'':81C ''пишут'':179C ''повод'':236C ''пода'':153C ''поддержива'':123C ''пожалуйст'':193C ''позж'':62C ''покида'':50C ''поклонник'':112C ''полн'':95C ''призыва'':126C,199C ''прилучн'':1A,22B,35C,43C,201C,295C ''пристраст'':258C ''продолжа'':37C ''происход'':93C ''прокомментир'':75C ''прокомментирова'':64C ''пророчат'':209C ''пункт'':293C ''раздел'':116C ''расстроен'':58C ''ребенк'':241C ''ребенок'':250C,276C ''реша'':282C ''росс'':233C ''сет'':184C ''сил'':90C ''смел'':222C ''сообществ'':207C ''состоя'':12B,25C ''спешк'':55C ''сторон'':273C ''стыдн'':171C ''суд'':13B,26C,52C,65C,87C,155C,271C ''сын'':298C ''сынульк'':174C ''так'':195C,212C ''тимофе'':308C ''увелич'':145C ''упрек'':142C ''учебн'':303C ''ушл'':84C ''факт'':230C ''цех'':219C ''час'':40C ''человек'':197C ''чет'':115C ''эт'':94C,306C ''явн'':57C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqf20a004tpotabrzpg9l7','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'RUSSIAN FASHION DISPLAY в Китае','3 марта 2024 года в жемчужине Северо-Восточного края, северной Даляне, прошел RUSSIAN FASHION DISPLAY 2024 — одно из самых значимых событий в мире моды, направленное на развитие российской fashion-индустрии за границей.','647-russian-fashion-display-v-kitae-istorija-rossijskoj-mody-v-novom-ispolnenii','[{"html":"<strong>3 марта 2024 года</strong> в жемчужине Северо-Восточного края, <strong>северной Даляне</strong>, прошел <strong>RUSSIAN FASHION DISPLAY 2024</strong> — одно из самых значимых событий в мире моды, направленное на развитие российской fashion-индустрии за границей. Принимающей стороной fashion-делегации выступил медиа-холдинг Dalian Qending Media Co., Ltd. Двенадцать дизайнеров из разных уголков России вывели на подиум свои яркие коллекции, чтобы продемонстрировать китайским коллегам всю красоту и колорит нашей многогранной страны.","type":"paragraph"},{"html":"Так<strong> дизайнер одежды</strong> Наталья Халанская погрузила зрителей в настоящую сказку, показывая многогранность и неповторимость России через историю костюма и традиции. Этой же концепции придерживалась и <strong>Светлана Черемных</strong>, продемонстрировав коллекцию «Марфа», вдохновением для которой послужили мотивы русской традиционной одежды, пересмотренные в современном прочтении.","type":"paragraph"},{"html":"Дизайнер <strong>Яна Весна</strong> (Janavesna) пошла другим путем, представив на подиуме новую футуристическую коллекцию с эффектом космического погружения в коллаборации с Акси Алексеенко под названием “COSMOS VENOM”. Вместе с ней заглянуть в будущее удалось <strong>модному продюсеру и дизайнеру Ладе Котовой</strong>, создателю бренда LA.`KO &amp; FASHION SHOW GROUPE \"VARIATION\", которая представила китайской стороне технологичный проект \"REVOLUTION\", а также <strong>дизайнеру Елене Козьминой</strong> с настоящим модным перформансом «CHANEL №5 &amp; COSMIC».","type":"paragraph"},{"html":"JANA VESNA","type":"paragraph"},{"html":"Ряд участников сделали акцент на ткани и декорировании. Так <strong>модельер и руководитель Школы Моды и дизайна Наталья</strong> Веревкина познакомила китайскую аудиторию с двумя коллекциями, особое внимание в которых было уделено именно деталям отделки, созданных вручную. <strong>Ирина Акулина</strong> представила капсульную коллекцию для юных модниц \"Мой каприз\", выполненную из натуральных тканей. А <strong>Ульяна Бронская </strong>продемонстрировала на подиуме эксклюзивные вечерние наряды и деловые костюмы для истинных леди из шелка, премиальной шерсти, бархата и кашемира.","type":"paragraph"},{"html":"К слову о премиальности и эксклюзиве: еще одна участница, <strong>Людмила Килибеева</strong> — это дизайнер, которая создает изделия вручную посредством крючочной вязки, а также эмоции и желаний клиента.","type":"paragraph"},{"html":"<strong>Ольга Бучина</strong> подошла к вопросу участия по-восточному философски, продемонстрировав коллекцию «Равновесие», где за счет одежды и ярких акцентных пятен можно привести к гармонии две противоположности: мужское и женское начала.","type":"paragraph"},{"html":"Ольга Бучина","type":"paragraph"},{"html":"Кстати, о мужском начале: свой бренд, который существует уже с 2011 года, презентовал китайской стороне в рамках мероприятия единственный российский дизайнер-мужчина <strong>Гера Скандал,</strong> участник телепроекта Подиум на телеканала “Пятница”.","type":"paragraph"},{"html":"Во время подготовки к показу стало известно, что <strong>дизайнер Анна Серая</strong>, <strong>создатель бренда GREY, </strong>наперекор своей фамилии, предпочитает яркие краски, как в одежде, так и в стиле жизни. <em>“Мероприятие не просто оправдало все мои ожидания, но и превзошло их по всем фронтам!” </em>— делится впечатлениями от поездки в Китай дизайнер, <em>“Это получилась очень яркая и запоминающаяся поездка. Для меня она стала ростом во многих сферах жизни. Я получила огромный опыт, множество новых знакомств, которые непременно пригодятся мне в профессиональной деятельности. Самым ярким событием для меня оказался, конечно же, показ. Собственно, то, ради чего все и затевалось. Столько прессы разом я еще не видела никогда! А это ведь далеко не дебютное мое мероприятие. Жаль, что такие моменты пролетают за считанные минуты</em>”.","type":"paragraph"},{"html":"Анна Серая","type":"paragraph"},{"html":"Помимо российских дизайнеров, в показе RUSSIAN FASHION DISPLAY 2024 приняли участие и представители китайской стороны: многогранный <strong>SONG YANG</strong> — основатель одноименного бренда одежды, лицензированный международный имиджмейкер в Китае, старший инструктор по этикету, консультант по брендам и традиционный ремесленник, а также <strong>WANG ZHAN HONG</strong> — судья конкурсов \"Мисс Азия — Тихоокеанская Мисс\", \"Образ посла Даляни\" и \"Дети в Китае\", который входит в ТОП-10 лучших дизайнеров Недели моды в Даляни.","type":"paragraph"},{"html":"Проект покорил всех своим масштабом! Организаторы и участники начали готовиться к мероприятию заранее. Было продумано все до мелочей: от концепции до ярких перформансов при показе. И результат не заставил себя ждать: десятки представителей СМИ, крупнейшие блогеры и представители fashion-индустрии страны, полный аншлаг с открытия и до последнего показа. Далянь встретил RUSSIAN FASHION DISPLAY 2024 со свойственным китайцам размахом.","type":"paragraph"},{"html":"<em>“На это мероприятие мы собирались заранее”</em>, рассказывает <strong>Татьяна Дьяконова, Генеральный директор MMA MODELLINE</strong>, “<em>Уже в ноябре 2023 года моя большая команда Modelline купили билеты и сделали визы. Более тридцати моделей разного возраста из нашего модельного агентства представляли коллекции дизайнеров на RUSSIAN FASHION DISPLAY 2024<strong>.</strong> А это не только хороший закрепляющий опыт в моделинге, но и огромная ответственность! Организация, конечно, безумно порадовала: красивая большая площадка, что очень важно для ощущения масштаба мероприятия. Главный акцент я, как директор и постановщик fashion show во Владивостоке, делаю на большое количество папарацци и СМИ на площадке, подчеркиваю </em>—<em> это важно для определения уровня события, что сильно выделяло данный модный праздник среди других. Модели работали на камеры, вдохновлялись увиденным и получали невероятные эмоции. За кулисами мы это бурно обсуждали. Многие из учеников ACADEMY MODELLINE впервые получили такой масштабный модельный опыт, за что мы благодарим создателя проекта Алену Балагурову.</em>”","type":"paragraph"},{"html":"И действительно, половина проекта, его душа и сила лежит в его организаторах. <strong>Алена Балагурова,</strong> <strong>создатель RUSSIAN FASHION DISPLAY, учредитель крупнейшего модного конкурса России Fashion bitva, </strong>подвела итоги поездки российской модной делегации за ту сторону горизонта, в Китай.","type":"paragraph"},{"html":"<em>“Да, я действительно считаю, что RUSSIAN FASHION DISPLAY </em>— <em>это значимый проект для развития российской индустрии моды. И, уверена, многие мои коллеги по цеху согласятся со мной. В прошлый раз мы были в Италии, где показали себя лучшим образом. Сейчас же мы подняли планку и продемонстрировали наших дизайнеров разительно другой культуре и менталитету. Китай </em>—<em> удивительная страна, мы были рады стать ее частью на какое-то время. Я думаю, что наши участники понравились китайской аудитории. Это подтверждает реакция зрителей, интерес СМИ, на коллекции дизайнеров, которые мы презентовали. Они были абсолютно разные, у всех </em>— <em>свой индивидуальный и неповторимый стиль. И это очень здорово, что мы смогли донести до многочисленной китайской публики, которая присутствовала в зале, наше видение моды и эксклюзивные инструменты ее реализации. Я от души хочу поблагодарить всех тех, без кого мероприятие было бы просто невозможным: дизайнеров и моделей,</em> <em>соорганизатора мероприятия Светлану Никонову и, конечно же, принимающую сторону в лице холдинга Dalian Qending Media Co., Ltd. Уверена, что это не последнее наше сотрудничество с удивительным Китаем”.</em>","type":"paragraph"},{"html":"Участники получили порцию вдохновения и свежих идей для создания новых коллекций, а команда организаторов RUSSIAN FASHION DISPLAY уже вовсю обдумывают, чем порадовать искушенного зрителя в рамках следующего мероприятия.","type":"paragraph"},{"html":"Елена Козьмина","type":"paragraph"},{"html":"Ирина Акулина","type":"paragraph"},{"html":"Ульяна Бронская","type":"paragraph"},{"html":"Наталья Веревкина","type":"paragraph"},{"html":"Лада Котова","type":"paragraph"},{"html":"Людмила Килибеева","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqewos004epotawp2esssj"},{"mediaId":"cmrmqexc9004fpotadaljsjzc"},{"mediaId":"cmrmqexo6004gpota9onawnj1"},{"mediaId":"cmrmqey28004hpotanf8o5upi"},{"mediaId":"cmrmqeyau004ipota9b2yt0lj"},{"mediaId":"cmrmqeym3004jpotaeu8u0pkn"},{"mediaId":"cmrmqeyu9004kpotawja8v6fi"},{"mediaId":"cmrmqezsf004lpotai5zmj6k2"},{"mediaId":"cmrmqf076004mpotaprej4oui"},{"mediaId":"cmrmqf0i6004npotapgadty7f"},{"mediaId":"cmrmqf0s7004opotad872omid"},{"mediaId":"cmrmqf10x004ppotalj4omdwh"},{"mediaId":"cmrmqf1cy004qpota23f6d1bb"},{"mediaId":"cmrmqf1po004rpota14obcytr"},{"mediaId":"cmrmqf1z1004spotafn5ugoz4"}]}]'::jsonb,'cmrmqew9t004dpotaumafbdqj','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2024-03-10T06:00:00.000Z'::timestamp,NULL,NULL,NULL,647,'/projects-esque/russian-fashion-display/647-russian-fashion-display-v-kitae-istorija-rossijskoj-mody-v-novom-ispolnenii.html','2026-07-15T20:49:21.514Z'::timestamp,'2026-07-16T13:56:54.497Z'::timestamp,'''-10'':595C ''2011'':385C ''2023'':684C ''2024'':8B,22B,42C,56C,544C,660C,711C ''3'':6B