C ''сми'':638C,756C,931C ''смогл'':955C ''собира'':672C ''собствен'':497C ''событ'':27B,61C,490C,765C ''современ'':154C ''соглас'':875C ''созда'':266C,321C ''создан'':1028C ''создател'':198C,420C,805C,826C ''соорганизатор'':990C ''сотрудничеств'':1013C ''сред'':772C ''стал'':414C,468C ''старш'':563C ''стат'':910C ''стил'':435C,948C ''стольк'':504C ''сторон'':75C,209C,389C,550C,845C,998C ''стран'':110C,646C,906C ''суд'':578C ''существ'':382C ''сфер'':472C ''счет'':351C ''счита'':526C,855C ''так'':522C ''такж'':214C,328C,574C ''татья'':675C ''телекана'':404C ''телепроект'':401C ''тех'':979C ''технологичн'':210C ''тихоокеанск'':582C ''ткан'':238C,281C ''топ'':594C ''традиц'':133C ''традицион'':150C,571C ''тридцат'':696C ''ту'':844C ''увер'':869C,1007C ''увиден'':779C ''уголк'':92C ''уда'':191C ''удел'':262C ''удивительн'':905C,1015C ''улья'':283C,1061C ''уровн'':764C ''участ'':341C,546C ''участник'':234C,400C,612C,922C,1020C ''участниц'':315C ''ученик'':792C ''учредител'':830C ''фамил'':425C ''философск'':345C ''фронт'':450C ''футуристическ'':170C ''халанск'':118C ''холдинг'':82C,1001C ''хорош'':716C ''хоч'':976C ''цех'':874C ''част'':912C ''черемн'':140C ''шелк'':298C ''шерст'':300C ''школ'':245C ''эксклюзив'':312C ''эксклюзивн'':288C,969C ''эмоц'':329C,783C ''эт'':318C,458C,513C,669C,713C,760C,787C,860C,926C,950C,1009C ''этикет'':566C ''эффект'':173C ''юн'':274C ''ян'':160C ''ярк'':98C,354C,427C,461C,489C,626C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdA