INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqeru4003tpota6zpb8vjw','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Ксения Нечаева: "Россия никогда не была страной про моду"','Индустрия моды в России всегда была сложной и неоднозначной.','658-ksenija-nechaeva-rossija-nikogda-ne-byla-stranoj-pro-modu','[{"html":"Индустрия моды в России всегда была сложной и неоднозначной. Ее существование, то отрицали, то порицали. Последние же годы наступило понимание, чего мы хотим и как этого достичь. Кажется ли нам, или это действительно так, но в воздухе как будто бы веет принятием, какой она должна быть и какой она становится. Все тоже удобство, но уже в красивой упаковке, спокойные тона и легкие ткани, никакого крика агрессии и блесток.","type":"paragraph"},{"html":"<u><i>Так ли это на самом деле?</i></u>","type":"paragraph"},{"html":"<u><i>Что такое мода в России? Какая она? И кто те люди, которые ее создают?</i></u>","type":"paragraph"},{"html":"Расскажет нам маркетолог <b>Ксения Нечаева.</b>","type":"paragraph"},{"html":"К слову, Ксения побывала у нас в качестве члена жюри на финале Fashion bitva на Цветном и у нее есть мнение и по этому поводу!","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Ксения, здравствуй. Расскажи немного о себе.","type":"paragraph"},{"html":"<strong>Ксения Нечаева:</strong> Алена, привет! Я Ксения, и я маркетолог до мозга костей. Воспринимаю мир через призму психологии и продаж. Я недавно посчитала, что уже 16 лет в практике, и за это время прошла путь от джуниора до директора по маркетингу. Сейчас я ухожу в стратегический маркетинг и брендинг, веду индивидуальные консультации, обучаю команды, “упаковываю” экспертов, преподаю маркетинг и веду тренинги.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> В своей работе ты делаешь акцент на сферу моды и красоты. Рассматриваешь другие направления?","type":"paragraph"},{"html":"<strong>Ксения Нечаева:</strong> Конечно, у меня были и автомобили, и гостиницы, и рестораны, и магазины. Новое – это всегда интересно с точки зрения расширения кругозора и спектра инструментов. А мода – это то, что ближе по интересам, и то, за что я всегда более охотно берусь.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Как ты оцениваешь развитие маркетинга в сфере fashion в России?","type":"paragraph"},{"html":"<strong>Ксения Нечаева:</strong> То, что я наблюдаю - это полнейшая биполярка. Сейчас объясню. Есть проекты, которые на 99% состоят из маркетинга. Там и ДНК бренда ярко считывается и транслируется на всех точках касания, и сервис выстроен, и продажи отрабатывают (я это кстати тоже к маркетингу отношу), и сайт шикарный, и социальные сети и с креативом, и со смыслом, и с красотой. Молодцы.","type":"paragraph"},{"html":"И где-то в этом же мире, на параллельной улице, есть проекты, которые вообще не представляют, что делать после того, как создали продукт (одну коллекцию, например).","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Я понимаю о чем ты говоришь. У наших дизайнеров мода воспринимается, как творчество и не так много брендов выстраивают успешный бизнес. Дизайнер должен быть в первую очередь творцом или бизнесменом?","type":"paragraph"},{"html":"<strong>Ксения Нечаева:</strong> Из команд, которые я знаю лично, или тех, за кем подглядываю в нельзяграме, хорошо получается у тех, кто работает в команде. За создание коллекций отвечает дизайнер (он же творец), а корректирует и направляет - продюсер или отдел маркетинга, в зависимости от масштаба команды.","type":"paragraph"},{"html":"Если ответить строго на вопрос: Что первично для дизайнера?","type":"paragraph"},{"html":"Конечно, творчество. Но если есть цель развития - то нужно или самостоятельно прокачивать скилы, или собирать команду из тех, кто будет хорошо дополнять. Лучше - команду. Тогда все при деле, и никто не выгорит.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Тогда задам самый больной вопрос. Чего не хватает нашей российской индустрии моды?","type":"paragraph"},{"html":"<strong>Ксения Нечаева:</strong> Наверное, самое главное - это насмотренности и понимания, что мы не одни. Что есть мировые тренды, которые нельзя не учитывать.","type":"paragraph"},{"html":"И второе - это маркетинг и бизнес образование. Многие дизайнеры - это творцы, как мы уже сказали выше. А сегодня мир работает так, что если ты хочешь быть признанным в своей сфере, то без бизнес-подхода и понимания возможностей маркетинга будет сложно (или будет одна коллекция “для себя и друзей” и дальше дело не пойдет).","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Что мешает вдохновляться и изучать развитие других брендов? Играет ли в этом роль отделение в какой-то степени от остального мира? Мы больше не можем, как раньше, посещать Неделю моды в Милане, ездить на выставки в Париж.","type":"paragraph"},{"html":"<strong>Ксения Нечаева:</strong> Ты знаешь, я тут на одной из лекций услышала фразу, от которой стало очень грустно и обидно: <em>«Россия никогда не была страной про моду. Наша культура (балет, к примеру) – влияла на мировую моду. Но сами мы ничего меняющего в мире моды не создавали.»</em>","type":"paragraph"},{"html":"Мне кажется, что каждая сложность – это скрытая возможность. И, возможно, именно сейчас будет формироваться что-то действительно новое, аутентичное, исходящее из культурного кода. Для того, чтобы собирать насмотренность и уметь анализировать тренды – не нужно никуда выезжать. Многие показы сегодня проводят с онлайн-трансляциями, мгновенно выходят обзоры в СМИ и у инфлюэнсеров в социальных сетях. Глобально проблемы с тем, что выезжать стало сложнее – не вижу.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Давай дадим дизайнерам порцию полезной информации. У многих дизайнеров есть непонимание в чем отличие марки от бренда? Расскажи, пожалуйста.","type":"paragraph"},{"html":"<strong>Ксения Нечаева:</strong> Ой, это мы надолго сейчас остановимся. Я по этой теме читаю лекции) Если очень коротко, то товарная марка - это любой продукт, который имеет логотип. Который играет “в рынке”, который не формирует тренды, а следует им, который если уйдет, то никто не заметит и особо не расстроится. А вот Бренд - это тот, кто сумел “хакнуть” рынок, не играет по правилам, не конкурирует по цене, его выбирают по ценностям. И если брать брендинг как процесс - то это деятельность, направленная на выстраивание образа продукта, узнаваемости и для прагматичных - это увеличение добавленной стоимости продукта. Бренд - это капитал вашего имени.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Для дизайнера правильнее всего создавать бренд?","type":"paragraph"},{"html":"<strong>Ксения Нечаева:</strong> Ну тут сложно сказать, что правильнее. Смотря, какая цель. Всегда стоит отталкиваться именно от того, чего вы хотите, и какие ресурсы имеете. Создание бренда – это длительный процесс, требующий терпения, системности, регулярности, упорства и внутренней веры в то, что делаешь.","type":"paragraph"},{"html":"<em><u>Простой пример:</u></em>","type":"paragraph"},{"html":"Цель – быстро выйти на заработок +300к в месяц через пошив худи.","type":"paragraph"},{"html":"Решение: минимизируем производство, встаем на маркетплейсы, цену ставим в рынке или чуть ниже похожих товаров, выдаем блогерам толстовки, запускаем продажи. Все, путь к цели намечен, быстро выходим на окупаемость.","type":"paragraph"},{"html":"Будет ли тут сила бренда? Важна ли она для того, чтобы заработать? Вообще нет.","type":"paragraph"},{"html":"<em><u>И другой пример.</u></em> Цель – создать первый в России Люкс-бренд нижнего белья, выйти на международный уровень.","type":"paragraph"},{"html":"Решение: инвестиция в материалы, в мастеров пошива, в упаковку, выбор значимых мест для продажи (Патрики, Столешников и тд), создание имиджевого сайта, выстраивание качественных продаж, обучение команд, амбассадорские контракты со звездами…","type":"paragraph"},{"html":"Путь длиннее, сложнее, окупаемость видим не на ближайшем горизонте. Но это – игра в долгую, тут есть миссия, смыслы, и каждый покупатель, который будет – запомнит покупку и расскажет о ней ближнему кругу.","type":"paragraph"},{"html":"Это не продажа, это выстраивание репутации для дальнейшего заработка х10 больше, чем в первом случае.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Ты была в качестве члена жюри на нашем конкурсе молодых дизайнеров «Fashion bitva». Расскажи о своем впечатлении от коллекции наших дизайнеров.","type":"paragraph"},{"html":"<strong>Ксения Нечаева:</strong> На Fashion Bitva было круто.","type":"paragraph"},{"html":"Организаторы собрали классных дизайнеров в зале на Цветном - это высокая планка для проекта, надеюсь, что дальше - больше!","type":"paragraph"},{"html":"Дизайнеры - это победители региональных конкурсов, то есть уже априори у них хорошая подготовка и за плечами не один отбор. Это чувствовалось. Я оценивала с точки зрения маркетинга: эффектность и уникальность постановки, соответствие логотипа и визуального ряда коллекции, выход дизайнера, самопрезентация, единство стиля и умение донести силу бренда в формате показа. И тут были явные фавориты и те, кто не был готов к оценке по таким параметрам.","type":"paragraph"},{"html":"Из тех, кто зацепил сильнее всего. До сих пор помню Оксану - самого молодого участника показа, которая в 15 лет сделала сумасшедшую гранжевую коллекцию, Эффектнейший показ в стиле зомби-апокалипсис (моя интерпретация), и ее выход - вишенка на торте: образ как продолжение коллекции, энергия от проходки такая, что аж мурашки. С моей стороны, были замечания по не очень читабельному лого, но это чтобы совсем все было идеально).","type":"paragraph"},{"html":"Показ MARUSSIA был пропитан маркетингом, смотрела с наслаждением. Очень целостная подача, продуманная до мельчайших деталей.","type":"paragraph"},{"html":"SOLOVE - потрясающий показ, единственный, у которого была цель. Вероятно, у других она тоже была, но SOLOVE ее озвучила (а это всегда самый лучший способ донести свою мысль - как говорят психологи, сказать ее “языком через рот”): поменять представление о трикотаже, показать его с другой, новой, непривычной зрителю стороны. И, действительно, - смотришь и удивляешься, насколько эффектными могут быть образы из трикотажа. Также, есть атрибут коллекции - в каждом образе использована красная нить, которая для дизайнера имеет личное значение. Коллекция, пропитанная смыслом, 100% коммерческая, круто поданная.","type":"paragraph"},{"html":"И несколько общих моментов, которые врезались в память с негативной оценкой:","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Ксения, спасибо большое за такие подробные ответы. Напоследок скажи пару напутственных слов начинающим дизайнерам.","type":"paragraph"},{"html":"<strong>Ксения Нечаева:</strong> Будьте смелыми, решительными, креативными. Ставьте цели и идите к ним! Сейчас то самое время, чтобы задавать себе самые масштабные миссии. Например, «глобальная смена российской моды в мировом сообществе».","type":"paragraph"},{"html":"С горящими глазами следуйте за своей мечтой!","type":"paragraph"},{"html":"Окружайте себя правильными людьми, которые Вас дополняют и усиливают!","type":"paragraph"},{"html":"Коллаборируйтесь и партнерьтесь – это бесплатно, приятно и выгодно!","type":"paragraph"},{"html":"Действуйте системно: продумывайте каждый шаг таким образом, чтобы у вашего Клиента складывалась понятная картинка «про что ваш продукт».","type":"paragraph"},{"html":"Учитесь, общайтесь, изучайте, что творится в косвенных индустриях – иногда так может родиться свежая идея для продукта или его продвижения.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqermj003rpotaletlfpp3"},{"mediaId":"cmrmqert4003spotagig14iqq"}]}]'::jsonb,'cmrmqercm003qpotab685gttp','cmrm8ky9t0000kwta6h8ifq47','cmrm8kyog0005kwta01b9favo','cmrmpdrom0000sstarkqxwts4','2024-06-11T06:00:00.000Z'::timestamp,NULL,NULL,NULL,658,'/fashion/interview/658-ksenija-nechaeva-rossija-nikogda-ne-byla-stranoj-pro-modu.html','2026-07-15T20:49:08.332Z'::timestamp,'2026-07-16T13:56:47.465Z'::timestamp,'''+300'':967C ''100'':1420C ''15'':1272C ''16'':186C ''99'':318C ''bitva'':137C,1144C,1160C ''cmrmqermj003rpotaletlfpp3'':1570C ''cmrmqert4003spotagig14iqq'':1572C ''esqu'':152C,225C,289C,396C,524C,621C,780C,903C,1131C,1441C ''fashion'':136C,297C,1143C,1159C ''galleri'':1568C ''marussia'':1325C ''paragraph'':88C,97C,114C,122C,150C,160C,223C,241C,287C,301C,364C,394C,428C,475C,487C,522C,538C,562C,619C,661C,709C,778C,801C,901C,911C,955C,960C,975C,1007C,1024C,1044C,1077C,1111C,1129C,1154C,1164C,1184C,1253C,1322C,1340C,1425C,1439C,1457C,1490C,1500C,1512C,1523C,1544C,1566C ''solov'':1342C,1357C ''автомоб'':250C ''агресс'':84C ''аж'':1302C ''акцент'':231C ''ал'':164C ''амбассадорск'':1072C ''анализирова'':742C ''апокалипсис'':1284C ''априор'':1194C ''атрибут'':1403C ''аутентичн'':730C ''балет'':691C ''бел'':1038C ''бер'':285C ''бесплатн'':1518C ''бизнес'':417C,569C,597C ''бизнес-подход'':596C ''бизнесмен'':426C ''биполярк'':311C ''блесток'':86C ''ближ'':274C ''ближайш'':1086C ''ближн'':1108C ''блогер'':993C ''больн'':528C ''больш'':1444C ''брат'':874C ''бренд'':325C,414C,629C,797C,853C,895C,909C,938C,1013C,1036C,1232C ''брендинг'':209C,875C ''будьт'':1461C ''быстр'':963C,1002C ''важн'':1014C ''ваш'':898C,1534C,1541C ''вдохновля'':624C ''вед'':210C,220C ''веет'':59C ''вер'':949C ''вероятн'':1350C ''вид'':1083C ''виж'':776C ''визуальн'':1220C ''вишенк'':1290C ''влия'':694C ''внутрен'':948C ''воздух'':55C ''возможн'':601C,718C,720C ''вообщ'':380C,1021C ''вопрос'':481C,529C ''воспринима'':174C,407C ''впечатлен'':1148C ''вреза'':1432C ''врем'':193C,1474C ''вста'':980C ''втор'':565C ''выбира