INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqr5mo003pukta2bcwd7kv','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Зимняя сказка','Два самых волшебных новогодних балета прозвучат в обработке для двух фортепиано в исполнении лауреатов международных конкурсов Татьяны Чистяковой и Алексея Кудряшова.Балет «Щелкунчик» – традиционно связан с Рождеством и ','629-zimnjaja-skazka','[{"html":"<i><strong>Фортепианный дуэт Татьяна ЧИСТЯКОВА и Алексей КУДРЯШОВ</strong></i>","type":"paragraph"},{"html":"<i>Мастер песочной анимации – <strong>Виктория ВОЛОДИНА</strong></i>","type":"paragraph"},{"html":"Два самых волшебных новогодних балета прозвучат в обработке для двух фортепиано в исполнении лауреатов международных конкурсов Татьяны Чистяковой и Алексея Кудряшова.","type":"paragraph"},{"html":"Балет «Щелкунчик» – традиционно связан с Рождеством и Новым годом, как и сама волшебная сказка Гофмана. Сюита, составленная Чайковским еще в процессе работы над балетом, содержит 8 наиболее ярких в музыкальном отношении номеров. Это характерные танцы из второго действия балета – Марш, Танец феи Драже, Трепак, Арабский танец, Китайский танец, Танец пастушков, а также Увертюра и Вальс цветов; в завершение прозвучит знаменитое Andante Maestoso.","type":"paragraph"},{"html":"«Золушка» – классический балет, продолжающий традиции романтического сказочного спектакля, с колоритными изобразительными моментами. М. Плетнев нередко обращался к жанру балетной транскрипции, однако транскрипция избранных отрывков оркестровой партитуры балета «Золушка» превзошла все ожидания. Версия музыки С. Прокофьева воспринимается не как переложение, а как равноправный вариант популярного опуса. Звучание фортепианного дуэта производит незабываемое впечатление – темброво-интонационная палитра ансамбля столь разнообразна, что трудно поверить, что играют лишь два пианиста.","type":"paragraph"},{"html":"Концерт украсит песочная анимация, что, несомненно, сделает его незабываемым!","type":"paragraph"},{"html":"<b>7 января 2024</b>","type":"paragraph"},{"html":"<b>Зал Шнитке</b>","type":"paragraph"},{"html":"<b>13.00</b>","type":"paragraph"},{"html":"<b>6+</b>","type":"paragraph"},{"html":"<em><u><i><b>Билеты</b></i></u>: </em><a href=\"https://www.mmdm.ru/event/zimnyaya-skazka?event_pk=4549\" target=\"_blank\" rel=\"noopener noreferrer\"><em>https://www.mmdm.ru/event/zimnyaya-skazka?event_pk=4549</em></a>","type":"paragraph"},{"html":"<u><b><i><em>Программа:</em></i></b></u>","type":"paragraph"},{"html":"<em>1 отделение</em>","type":"paragraph"},{"html":"<i><em>П. Чайковский – Д. Молин</em></i>","type":"paragraph"},{"html":"<i><em>Концертная сюита из балета «Щелкунчик»</em></i>","type":"paragraph"},{"html":"<i><em>Маленькая увертюра</em></i>","type":"paragraph"},{"html":"<i><em>Марш</em></i>","type":"paragraph"},{"html":"<i><em>Танец феи Драже</em></i>","type":"paragraph"},{"html":"<i><em>Трепак</em></i>","type":"paragraph"},{"html":"<i><em>Арабский танец</em></i>","type":"paragraph"},{"html":"<i><em>Китайский танец</em></i>","type":"paragraph"},{"html":"<i><em>Танец пастушков</em></i>","type":"paragraph"},{"html":"<i><em>Вальс цветов</em></i>","type":"paragraph"},{"html":"<i><em>Andante Maеstoso</em></i>","type":"paragraph"},{"html":"<em>2 отделение </em>","type":"paragraph"},{"html":"<em>С. Прокофьев – М. Плетнев</em>","type":"paragraph"},{"html":"<em>Сюита из балета «Золушка»</em>","type":"paragraph"},{"html":"<em>Интродукция</em>","type":"paragraph"},{"html":"<em>Ссора</em>","type":"paragraph"},{"html":"<em>Зима</em>","type":"paragraph"},{"html":"<em>Весна</em>","type":"paragraph"},{"html":"<em>Вальс Золушки</em>","type":"paragraph"},{"html":"<em>Гавот</em>","type":"paragraph"},{"html":"<em>Галоп</em>","type":"paragraph"},{"html":"<em>Медленный вальс</em>","type":"paragraph"},{"html":"<em>Финал</em>","type":"paragraph"},{"html":"<em>*В программе возможны изменения</em>","type":"paragraph"},{"type":"image","mediaId":"cmrmqr5lc003ouktanhiz32xr"}]'::jsonb,'cmrmqr5fr003nuktacvmxk7n6','cmrm8kz36000ckwtabqfh3f4h','cmrm8kzc0000fkwtauqqmw2lw','cmrmpdrom0000sstarkqxwts4','2023-12-19T06:00:00.000Z'::timestamp,NULL,NULL,NULL,629,'/sobytija/teatr/629-zimnjaja-skazka.html','2026-07-15T20:58:46.080Z'::timestamp,'2026-07-16T13:57:02.476Z'::timestamp,'''/event/zimnyaya-skazka?event_pk=4549'':240C ''1'':248C ''13.00'':229C ''2'':312C ''2024'':220C ''6'':233C ''7'':218C ''8'':97C ''andant'':132C,307C ''cmrmqr5lc003ouktanhiz32xr'':378C ''imag'':376C ''maestoso'':133C ''maеstoso'':308C ''paragraph'':38C,46C,70C,135C,204C,216C,222C,227C,231C,235C,242C,246C,251C,258C,266C,271C,275C,281C,285C,290C,295C,300C,305C,310C,315C,322C,329C,333C,337C,341C,345C,350C,354C,358C,363C,367C,374C ''www.mmdm.ru'':239C ''www.mmdm.ru/event/zimnyaya-skazka?event_pk=4549'':238C ''алекс'':35C ''алексе'':22B,67C ''анимац'':42C,209C ''ансамбл'':192C ''арабск'':116C,287C ''балет'':7B,24B,52C,72C,95C,110C,139C,163C,263C,326C ''балетн'':155C ''билет'':237C ''вальс'':126C,302C,347C,361C ''вариант'':179C ''верс'':168C ''весн'':343C ''виктор'':43C ''возможн'':371C ''володин'':44C ''волшебн'':5B,50C,84C ''воспринима'':172C ''впечатлен'':187C ''втор'':108C ''гавот'':352C ''галоп'':356C ''год'':80C ''гофма'':86C ''д'':255C ''двух'':12B,57C ''действ'':109C ''драж'':114C,279C ''дуэт'':31C,184C ''жанр'':154C ''завершен'':129C ''зал'':224C ''звучан'':182C ''зим'':339C ''зимн'':1A ''знаменит'':131C ''золушк'':137C,164C,327C,348C ''игра'':199C ''избра'':159C ''изменен'':372C ''изобразительн'':147C ''интонацион'':190C ''интродукц'':331C ''исполнен'':15B,60C ''китайск'':118C,292C ''классическ'':138C ''колоритн'':146C ''конкурс'':18B,63C ''концерт'':206C ''концертн'':260C ''кудряш'':36C ''кудряшов'':23B,68C ''лауреат'':16B,61C ''лиш'':200C ''м'':149C,319C ''маленьк'':268C ''марш'':111C,273C ''мастер