INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqeotj003fpotaf4sw48sr','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Правила жизни Тома Круза','Сегодня 62 года отмечает голливудский актер Том Круз.','662-pravila-zhizni-toma-kruza','[{"html":"Сегодня 62 года отмечает голливудский актер Том Круз. Один из самых неоднозначных, но горячо любимых мировых звезд не имеет актерского образования и с раннего детства был болен дислексией. Казалось бы, такого будущего и представить было невозможно.","type":"paragraph"},{"html":"<b>1.</b> Том Круз из тех актеров, которые не имеют актерского образования. А ведь он входит ТОП-4 в рейтинге популярных современных актеров","type":"paragraph"},{"html":"<b>2.</b> В Японии существует официальный день Тома Круза – 10 октября. Его отмечают с 2006 года","type":"paragraph"},{"html":"<b>3.</b> Том Круз не допускает к своей работе дублеров. Например, на съемках фильма «Миссия невыполнима: Последствия» 56-летний актер не только сам летал на вертолете, но и висел в воздухе над землей, ухватившись лишь одной рукой за раму воздушного судна","type":"paragraph"},{"html":"<b>4. </b>Том Круз долгие годы занимается благотворительностью. Зная, что такое тяжелое детство и дислексия (актер болеет ей с самого детства и вопреки тяжелому заболеванию стал всемирной звездой), помогает тяжелобольным детям и даже выступил основателем проекта в сфере грамотности и образования","type":"paragraph"},{"html":"<b>5.</b> Том Круз - саентолог. По словам Тони Ортеги, редактора блога саентологии The Underground Bunker, актер достиг такого статуса в саентологии, что может исцелять вывихнутые суставы, простуду, многое другое. Сам же Круз заявляет, что именно это учение помогло ему победить дислексию","type":"paragraph"},{"html":"<b>6.</b> Все три его жены были одного возраста на момент развода с Томом Крузом. Мими Роджерс, Николь Кидман и Кэти Холмс на момент расставания с Крузом было по 33 года и каждая на одиннадцать лет моложе предыдущей","type":"paragraph"},{"html":"<b>7.</b> После расставания с Николь Кидман Том Круз устроил смотрины для своей второй жены. Первое свидание Круза и его третьей жены, Кэти Холмс, также было организовано Церковью саентологии","type":"paragraph"},{"html":"<b>8.</b> Том Круз утверждает, что психиатрия является лженаукой","type":"paragraph"},{"html":"<b>9.</b> В 1990 году он был признан самым красивым человеком на Земле","type":"paragraph"},{"html":"<b>10.</b> Знаменитый главный герой диснеевского мультфильма «Аладдин» был срисован с образа Тома Круза","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqeomh003dpota2zgwkes5"},{"mediaId":"cmrmqeos9003epotav3f41a15"}]}]'::jsonb,'cmrmqeo0r003cpotaspsiryrd','cmrm8kzli000ikwtafbw33jnj','cmrm8kzoi000kkwtachb0mt9u','cmrmpdrom0000sstarkqxwts4','2024-07-03T06:00:00.000Z'::timestamp,NULL,NULL,NULL,662,'/persona/about-life/662-pravila-zhizni-toma-kruza.html','2026-07-15T20:49:04.423Z'::timestamp,'2026-07-16T13:56:43.480Z'::timestamp,'''-4'':68C ''1'':52C ''10'':85C,321C ''1990'':308C ''2'':77C ''2006'':90C ''3'':95C ''33'':252C ''4'':138C ''5'':181C ''56'':111C ''6'':224C ''62'':6B,14C ''7'':264C ''8'':295C ''9'':306C ''bunker'':194C ''cmrmqeomh003dpota2zgwkes5'':339C ''cmrmqeos9003epotav3f41a15'':341C ''galleri'':337C ''paragraph'':50C,75C,93C,136C,179C,222C,262C,293C,304C,319C,335C ''underground'':193C ''актер'':10B,18C,57C,73C,113C,152C,195C ''актерск'':32C,61C ''аладдин'':327C ''благотворительн'':144C ''блог'':190C ''бол'':39C ''болеет'':153C ''будущ'':44C ''вертолет'':119C ''висел'':122C ''воздух'':124C ''воздушн'':133C ''возраст'':231C ''вопрек'':159C ''всемирн'':163C ''втор'':276C ''вход'':66C ''вывихнут'':204C ''выступ'':170C ''гер'':324C ''главн'':323C ''год'':7B,15C,91C,142C,253C,309C ''голливудск'':9B,17C ''горяч'':26C ''грамотн'':175C ''