INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqek60002upotaqmx5ifd9','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Помогите! Мне изменили','Узнайте, почему измены играют ключевую роль в разрушении отношений.','669-pomogite-mne-izmenili','[{"html":"Тема измен была актуальна во все времена. Именно измены являются причиной распада многих отношений.","type":"paragraph"},{"html":"Мы можем бесконечно говорить о том, что толкает одного из партнеров, в объятия другого человека. Это могут быть и детские травмы, и желание доказать свою значимость, и банальная нелюбовь.","type":"paragraph"},{"html":"Однако больно всегда!","type":"paragraph"},{"html":"У каждого боль своя: кто-то ранимее переживает предательство некогда любимого человека, кто-то пытается заглушить боль в чем-то или в ком-то.","type":"paragraph"},{"html":"В этом интервью с помощью квалифицированных психологов, мы постараемся вместе разобраться с природой измен.","type":"paragraph"},{"html":"Порассуждаем, как правильно переживать предательство и что сподвигает человека его совершать.","type":"paragraph"},{"html":"<u><i>Благодарим наших героинь:</i></u>","type":"paragraph"},{"html":"Анастасия Букач - практикующий психолог, ведущая терапевтических групп, спикер","type":"paragraph"},{"html":"Диана Коррэа Родригес - психолог, гештальт-терапевт, автор колод метафорических карт","type":"paragraph"},{"html":"Ирина Тарасова - психолог, гештальт - терапевт, ведущая тематических и терапевтических групп","type":"paragraph"},{"html":"Наталья Андреева - клинический психолог, гештальт терапевт, специалист по семейным отношениям","type":"paragraph"},{"html":"Анастасия Долгова - клинический психолог, сексолог, аккредитованный супервизор","type":"paragraph"},{"html":"Наталья Котова - психолог, психоаналитик. Интегральный подход","type":"paragraph"},{"html":"Екатерина Тишкина - психолог, системный терапевт, автор программ и расстановочной игры","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/yZzsM-4M-Uw?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen=\"\" title=\"Помогите! МНЕ ИЗМЕНИЛИ\"></iframe>","type":"embed"}]'::jsonb,'cmrmqek2p002tpotagciick6u','cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2024-07-15T06:00:00.000Z'::timestamp,NULL,NULL,NULL,669,'/psihologija/intervju-2/669-pomogite-mne-izmenili.html','2026-07-15T20:48:58.392Z'::timestamp,'2026-07-16T13:56:37.790Z'::timestamp,'''emb'':219C ''paragraph'':28C,60C,66C,97C,114C,128C,134C,145C,159C,172C,185C,195C,204C,217C ''автор'':154C,211C ''аккредитова'':192C ''актуальн'':16C ''анастас'':136C,187C ''андреев'':175C ''банальн'':57C ''бесконечн'':32C ''благодар'':130C ''бол'':70C,86C ''больн'':63C ''букач'':137C ''ведущ'':140C,166C ''вмест'':108C ''врем'':19C ''героин'':132C ''гештальт'':152C,164C,178C ''гештальт-терапевт'':151C ''говор'':33C ''групп'':142C,170C ''детск'':49C ''диа'':147C ''доказа'':53C ''долгов'':188C ''друг'':43C ''екатерин'':206C ''желан'':52C ''заглуш'':85C ''значим'':55C ''игр'':215C ''игра'':7B ''изм'':6B,14C,21C,112C ''измен'':3A ''имен'':20C ''интегральн'':201C ''интерв'':101C ''ирин'':161C ''кажд'':69C ''карт'':157C ''квалифицирова'':104C ''клиническ'':176C,189C ''ключев'':8B ''колод'':155C ''ком'':94C ''ком-т'':93C ''коррэ'':148C ''котов'':198C ''кто-т'':72C,81C ''любим'':79C ''метафорическ'':156C ''мног'':25C ''могут'':46C ''мож'':31C ''натал'':174C,197C ''наш'':131C ''некогд'':78C ''нелюбов'':58C ''объят'':42C ''одн'':38C ''однак'':62C ''отношен'':12B,26C,183C ''партнер'':40C ''пережива'':76C,119C ''подход'':202C ''помог'':1A ''помощ'':103C ''порассужда''