INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmpdvpf001vsstamzc9bz22','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Cупруги Чекалины вновь под следствием','Вчера вечером в Москве были задержаны бывшие супруги Чекалины.','683-cuprugi-chekaliny-vnov-pod-sledstviem','[{"html":"Вчера вечером в Москве были задержаны бывшие супруги Чекалины.","type":"paragraph"},{"html":"Еще совсем недавно в интервью на youtube-канале «Респиратор Бабушкина», Лерчек рассказывала про страшный год, который провела под домашним арестом, мог ли кто-то подумать, что впереди звездных экс-супругов ждет история куда пострашнее.","type":"paragraph"},{"html":"Эту ночь Чекалины проведут в СИЗО в ожидании суда по избранию меры пресечения.","type":"paragraph"},{"html":"Их обвиняют в нелегальном выводе за границу 250 млн рублей.","type":"paragraph"},{"html":"Полицейские и служба безопасности ПАО \"Сбербанк\", выяснили, что блогеры продавали россиянам фитнес-марафоны, но средства уходили на зарубежные счета.","type":"paragraph"},{"html":"В контролирующие органы передавались документы с недостоверными сведениями об основаниях, целях и назначении переводов. По этой схеме за полгода фигуранты вывели 250 миллионов рублей.","type":"paragraph"},{"html":"Возбуждено уголовное дело и звездной паре грозит до 10 лет лишения свободы.","type":"paragraph"},{"html":"Поспособствовал задержанию и допрос самой Лерчек, которая по сведениям приближенных к ситуации, наговорила лишнего. Именно после ее допроса, экс супруги были задержаны на 48 часов. Узнав о задержании, у девушки случилась истерика. Она плакала, кричала и падала на пол.","type":"paragraph"},{"html":"А вот Артем, по словам его адвоката Сергея Гурова, утверждает, что лично у его клиента настрой боевой.","type":"paragraph"},{"html":"\"Он боец, молодец, мы настроены на победу. В массы ничего не передавал, кроме: \"Платите налоги, живите честно\", – рассказал Гуров.","type":"paragraph"},{"html":"Продлят ли блогерам арест или отправят домой, мы узнаем уже совсем скоро!","type":"paragraph"},{"type":"image","mediaId":"cmrmpoyq3001s8gta2gfnc6k8"}]'::jsonb,'cmrmpdvo6001usstayuutjyk6','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-10-03T06:00:00.000Z'::timestamp,NULL,NULL,NULL,683,'/v-mire/683-cuprugi-chekaliny-vnov-pod-sledstviem.html','2026-07-15T20:20:27.075Z'::timestamp,'2026-07-16T13:56:23.132Z'::timestamp,'''10'':154C ''250'':90C,140C ''48'':184C ''cmrmpoyq3001s8gta2gfnc6k8'':262C ''cупруг'':1A ''imag'':260C ''paragraph'':25C,65C,81C,94C,117C,144C,159C,201C,221C,243C,258C ''youtub'':34C ''youtube-канал'':33C ''адвокат'':209C ''арест'':47C,248C ''арт'':205C ''бабушкин'':37C ''безопасн'':99C ''блогер'':104C,247C ''боев'':219C ''боец'':224C ''бывш'':12B,21C ''вечер'':7B,16C ''внов'':3A ''возбужд'':146C ''вперед'':55C ''вчер'':6B,15C ''вывел'':139C ''вывод'':87C ''выясн'':102C ''год'':42C ''границ'':89C ''гроз'':152C ''гур'':241C ''гуров'':211C ''девушк'':190C ''дел'':148C ''документ'':123C ''дом'':251C ''домашн'':46C ''допрос'':164C,178C ''ждет'':60C ''жив'':238C ''задержа'':11B,20C,182C ''задержан'':162C,188C ''зарубежн'':114C ''звездн'':56C,150C ''избран'':77C ''имен'':175C ''интерв'':31C ''истерик'':192C ''истор'':61C ''канал'':35C ''клиент'':217C ''контролир'':120C ''котор'':43C,167C ''крича'':195C ''кром'':235C ''кто-т'':50C ''лерчек'':38C,166C ''лет'':155C ''личн'':214C ''лишен'':156C ''лишн'':174C ''марафон'':109C ''масс'':231C ''мер'':78C ''миллион'':141C ''млн'':91C ''мог'':48C ''молодец'':225C ''москв'':9B,18C ''наговор'':173C ''назначен'':131C ''налог'':237C ''настр'':218C ''настро'':227C ''недавн'':29C ''недостоверн'':125C ''нелегальн'':86C ''ноч'':68C ''обвиня'':84C ''ожидан'':74C ''орга'':121C ''основан'':128C ''отправ'':250C ''па'':100C ''пада'':197C ''пар'':151C ''перевод'':132C ''переда