INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqqzf50033uktanknc001u','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'RUSSIAN FASHION DISPLAY, курс на Китай','Какие мысли приходят вам в голову, когда вы слышите про Китай?','635-russian-fashion-display-kurs-na-kitaj','[{"html":"Какие мысли приходят вам в голову, когда вы слышите про Китай? Крупнейшее по численности и одно из самых прогрессивных государств мира? Бесспорно! Последние годы все индустрии там переживают беспрецедентный рост. И модная — в том числе.","type":"paragraph"},{"html":"Именно поэтому в этом году мы берем курс на Китай.","type":"paragraph"},{"html":"Он единогласно избран встречающей стороной для <strong>RUSSIAN FASHION DISPLAY 2024</strong> — одного из самых значимых событий в мире моды, направленного на развитие российской fashion-индустрии за границей.","type":"paragraph"},{"html":"<strong>3 марта 2024 года</strong> в жемчужине Северо-Восточного края – <strong>северной Даляне</strong>, российские дизайнеры выйдут на подиум, чтобы продемонстрировать всю красоту и колорит нашей многогранной страны.","type":"paragraph"},{"html":"<strong>Гера Скандал</strong> — российский дизайнер, фотограф, организатор мероприятий, ментор и мизантроп, а также креативный директор журнала \"GS news magazine\" и участник телепроекта \"Подиум\" на телеканале Пятница, продемонстрирует модному миру КНР яркое сочетание различных материалов, от шелка, до расшитых вручную люксовых тканей. Дизайнер достиг того уровня мастерства, когда для того, чтобы творить, ему не требуется ждать музы. Все креативные идеи уже есть в его голове: \"<em>Просто захотел и сделал </em><em>—</em> вот мой принцип. Я с легкостью и удовольствием создаю индивидуальность и характер для каждой своей модели,\" — так Гера Скандал покорил подиумы Московской, Малазийской, Японской, Индонезийской, Берлинской, Парижской и Миланских Модных Недель. Очередь за Китаем.","type":"paragraph"},{"html":"Еще один участник показа, <strong>дизайнер Ольга Бучина</strong>, создательница бренда «Otbucci», ждет от мероприятия возможности территориального расширения для носящей ее имя Галереи Моды, а также масштабного процветания. В качестве составной части ДНК бренда в коллекциях Ольги Бучиной часто преобладает многослойность, любовь к которой зародилась в годы жизни дизайнера в Японии: <em>\"Мода продолжает эпатировать, ставя под сомнения гендерные представления и предлагая более универсальный и экономичный подход к стилю. Основное ее правило сегодня </em><em>—</em> носить элементы гардероба унисекс с неким безразличием, даже самоиронией. Именно этот расслабленный вайб и придает образу некий street style шик. На пороге триумф технологий и торжество этики\".","type":"paragraph"},{"html":"Уж с чем-чем, а с технологиями в футуристическом Китае все обстоит на высшем уровне. <strong>Дизайнер Наталья Халанская</strong>, участница показа, решила немного заглянуть в будущее: \"<em>Самое важное, что нас ждет это изменение самой модели отношений «продавец </em><em>—</em> покупатель». Потребление будущего — это микс товаров и сервисов. Потому что самое дорогое, что есть и будет у человека — это время. И модным станет то, что нам его сохранит: будь то сервис или многофункциональность образа. И, конечно, нас ожидает развитие трех ветвей эволюции дизайна одежды: высокотехнологичности, инклюзивности и экоориентированности\".","type":"paragraph"},{"html":"RUSSIAN FASHION DISPLAY в Даляне — это новый виток знакомства зарубежных коллег мира fashion с Россией. Современный бохо стиль Сочи, интеллигентный casual Санкт-Петербурга, татарский колорит Казани и этническая мода Сибири — нам найдется, чем удивить модных блогеров, байеров, дизайнеров и стилистов Китая.","type":"paragraph"},{"html":"<br />Наталья Веревкина, дизайнер и создатель одноименного бренда «VEREVKINA NATALIA», уверена, что Китай и Россия — две великие страны, которым точно будет чем поделиться друг с другом: <em>\"Россия </em><em>—</em> это всегда о красоте, гармонии, почитании и уважении культуры и традиций, духовности. Добавим сюда огромное количество талантливых людей, проживающих в ней. Я уверена, что Россия даст миру новые имена и новые направления, как некогда это сделал Дягилев с нашим \"русским стилем\". Мы, дизайнеры, будем рады продемонстрировать это на подиуме в Китае\".","type":"paragraph"},{"html":"RUSSIAN FASHION DISPLAY в Китае — это история российской моды в новом исполнении!","type":"paragraph"}]'::jsonb,'cmrmqqzdq0032ukta3qvpkd0y','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2024-01-26T06:00:00.000Z'::timestamp,NULL,NULL,NULL,635,'/projects-esque/russian-fashion-display/635-russian-fashion-display-kurs-na-kitaj.html','2026-07-15T20:58:38.033Z'::timestamp,'2026-07-16T13:56:58.804Z'::timestamp,'''2024'':78C,101C ''3'':99C ''casual'':440C ''display'':3A,77C,422C,547C ''fashion'':2A,76C,92C,421C,432C,546C ''fashion-индустр'':91C ''gs'':143C ''magazin'':145C ''natalia'':473C ''news'':144C ''otbucci'':241C ''paragraph'':54C,67C,97C,126C,230C,330C,418C,463C,543C,558C ''russian'':1A,75C,420C,545C ''street'':319C ''style'':320C ''verevkina'':472C ''байер'':457C ''безразлич'':308C ''бер'':62C ''берлинск'':220C ''беспрецедентн'':46C ''бесспорн'':39C ''блогер'':456C ''бох'':436C ''бренд'':240C,263C,471C ''буд'':397C,534C ''будущ'':357C,371C ''бучин'':238C,267C ''важн'':359C ''вайб'':314C ''велик'':480C ''веревкин'':466C ''ветв'':409C ''виток'':427C ''возможн'':245C ''восточн'':107C ''врем'':388C ''вручн'':165C ''встреча'':72C ''выйдут'':113C ''высокотехнологичн'':413C ''высш'':346C ''галер'':252C ''гардероб'':304C ''гармон'':495C ''гендерн'':287C ''гер'':128C,212C ''год'':41C,60C,102C,276C ''голов'':12B,23C,190C ''государств'':37C ''границ'':95C ''далян'':110C,424C ''даст'':516C ''две'':479C ''дизайн'':411C ''дизайнер'':112