INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqeuci0045potaqww9hilu','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'30 апреля  в РусМанекене пройдет презентация коллекции SS24 бренда "FARRDI"','Бренд одежды FARRDI и «Корпорация роботов» объявляют о запуске коллаборации и 30 апреля представят первый совместный дизайн проект.','654-30-aprelja-farrdi-predstavit-kollekciju-ss24-i-start-kollaboracii-s-korporaciej-robotov','[{"html":"30 апреля в пространстве \"РусМанекен\" бренд \"FARRDI\" представит коллекцию SS24 и объявит о старте коллаборации с компанией «Корпорацией роботов». Это партнерство обещает принести уникальные идеи и удивительные возможности для Fashion сферы.","type":"paragraph"},{"html":"Презентация пройдет под лозунгом:","type":"paragraph"},{"html":"<em>«В будущее возьмут не всех, а только тех, кто подготовился». </em>","type":"paragraph"},{"html":"Компании решили объединить усилия в направлении популяризации тренда на технологии и науку. Этот момент стал возможным благодаря творческому подходу команды FARRDI, которые первыми в мире стали выпускать одежду из карбона.","type":"paragraph"},{"html":"На мероприятии бренд представит летнюю коллекцию в своих лучших традициях: сочетании лаконичного кроя и футуристичных мотивов, которые создают образ в стиле неоклассики. Акцентом станут образы из денима.","type":"paragraph"},{"html":"На презентации гостей ждет не только знакомство с новой коллекцией, но и перформанс с участием робособаки, предоставленной \"Корпорацией роботов\". Гости смогут ознакомиться с передовыми технологиями и увидеть в действии уникального робота.","type":"paragraph"},{"html":"<em>«Корпорация роботов» - современная инновационная компания, цель которой - популяризация технологий. </em>","type":"paragraph"},{"html":"<em>Мы рады, что наши ценности в части развития отечественных технологий перекликаются с ценностями бренда FARRDI. Наш совместный проект демонстрирует, как инновации сегодня успешно интегрируются в Fashion индустрию. </em>","type":"paragraph"},{"html":"- Артур Зархи, генеральный директор \"Корпорации роботов\".","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqett00043potat9mk9d37"},{"mediaId":"cmrmqeuav0044pota5g964hfk"}]}]'::jsonb,'cmrmqetlh0042pota0m90fjzt','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2024-04-29T06:00:00.000Z'::timestamp,NULL,NULL,NULL,654,'/fashion/news-2/654-30-aprelja-farrdi-predstavit-kollekciju-ss24-i-start-kollaboracii-s-korporaciej-robotov.html','2026-07-15T20:49:11.586Z'::timestamp,'2026-07-16T13:56:51.451Z'::timestamp,'''30'':1A,22B,29C ''cmrmqett00043potat9mk9d37'':233C ''cmrmqeuav0044pota5g964hfk'':235C ''farrdi'':10A,13B,35C,103C,206C ''fashion'':58C,217C ''galleri'':231C ''paragraph'':61C,68C,81C,114C,144C,178C,190C,220C,229C ''ss24'':8A,38C ''акцент'':138C ''апрел'':2A,23B,30C ''артур'':222C ''благодар'':99C ''бренд'':9A,11B,34C,118C,205C ''будущ'':71C ''возможн'':56C,98C ''возьмут'':72C ''выпуска'':109C ''генеральн'':224C ''гост'':148C,165C ''действ'':174C ''демонстрир'':210C ''деним'':142C ''дизайн'':27B ''директор'':225C ''ждет'':149C ''запуск'':19B ''зарх'':223C ''знакомств'':152C ''ид'':53C ''индустр'':218C ''инновац'':212C ''инновацион'':183C ''интегрир'':215C ''карбон'':112C ''коллаборац'':20B,43C ''коллекц'':7A,37C,121C,155C ''команд'':102C ''компан'':45C,83C,184C ''корпорац'':15B,46C,163C,180C,226C ''котор'':104C,132C,186C ''кро'':128C ''лаконичн'':127C ''летн'':120C ''лозунг'':66C ''лучш'':124C ''мероприят'':117C ''мир'':107C ''момент'':96C ''мотив'':131C ''направлен'':88C ''наук'':94C ''наш'':195C,207C ''неоклассик'':137C ''нов'':154C ''обеща'':50C ''образ'':134C,140C ''объедин'':85C ''объяв'':40C ''объявля'':17B ''одежд'':12B,110C ''ознаком'':167C ''отечествен'':200C ''партнерств'':49C ''перв'':25B,105C ''передов'':169C ''переклика'':202C ''перформанс'':158C ''подготов'':79C ''подход'':101C ''популяризац'':89C,187C ''предоставлен'':162C ''представ'':24B,36C,119C ''презентац'':6A,63C,147C ''принест'':51C ''проект'':28B,209C ''пройдет'':5A,64C ''пространств'':32C ''рад'':193C ''развит'':199C ''реш'':84C ''робособак'':161C ''робот'':16B,47C,164C,176C,181C,227C ''русманек'':33C ''русманекен'':4A ''сво'':123C ''сегодн'':213C ''смогут'':166C ''совместн'':26B,208C ''современ'':182C ''созда'':133C ''сочетан'':126C ''стал'':97C,108C ''станут'':139C ''старт'':42C ''стил'':136C ''сфер'':59C ''творческ'':100C ''тех'':77C ''технолог'':92C,170C,188C,201C ''традиц'':125C ''тренд'':90C ''увидет'':172C ''удивительн'':55C ''уникальн'':52C,175C ''усил'':86C ''успешн'':214C ''участ'':160C ''футуристичн'':130C ''цел'':185C ''ценност'':196C,204C ''част'':198C ''эт'':48C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqs8aa007qukta99y4h5fc','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Cоздатель гигиенических органических бальзамов для губ «С-Н» о сложности развития производства косметики','Это интервью мы задумали еще в декабре прошлого года.','590-kurtajkina-ekaterina-ja-blagodarna-sama-sebe-za-vse-svoi-oshibki-potomu-chto-jeto-rost','[{"html":"<strong>Это интервью мы задумали еще в декабре прошлого года. Это история о большом трудолюбии и любви к своему делу. </strong>","type":"paragraph"},{"html":"<strong>Увидев как-то небольшой флакончик бальзама для губ со сладким послевкусием в США, наша героиня пронесла эту идею сквозь года. Сейчас Екатерина Куртайкина – владелица компании по производству органических бальзамов для губ «С-Н» с точками продаж по всей России.</strong>","type":"paragraph"},{"html":"<strong>Esque:</strong> Екатерина, здравствуйте. Расскажите, как вы пришли к решению создания бальзамов для губ?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Привет! Это кстати интересная история. По первому образованию я инженер и много лет назад работала в офисе проектной организации. В один из отпусков я поехала в большое путешествие по США, одна из локаций был остров Кауаи – это самый древний остров Гавайского архипелага. И именно на этом острове у меня закончился бальзам. Тогда я особо не разбиралась в составах и не парилась по этому поводу, пользовалась масс-маркетом по типу пантенол из аптеки или NIVEA. И вот в местном магазинчике сувениров я увидела большую напольную корзину, в которой с горой лежали маленькие бальзамчики для губ. И висела вывеска «made on Hawaii», на упаковке гордо было написано organic и handmade, а стоил он в районе одного доллара. Я естественно, его купила. Никакого вау эффекта он на меня тогда не произвел. Но потом я вернулась в Россию, в серый скучный офис. И в один из дней, облизывая губы, заметила, что они почему-то сладкие, хоть я и не ела ничего сладкого. Потом я поняла, что это бальзам, судорожно начала изучать состав, первый раз в жизни. Почему то меня это так впечатлило, что я всем подряд в нашем open space офисе начала рассказывать, что вот этот бальзам сделал мои губы сладкими. Все смотрели на меня очень удивленно. В составе, кстати, оказались понятные ингредиенты: масла, воск и мед. Ну а потом, я хотела найти что-то подобное в России, но тщетно. В какой-то момент психанула и решила сама сварить себе бальзамы для губ. Начала изучать блоги о handmade косметике, закупила ингредиенты и решила повторить один рецепт. Но у меня ничего не вышло. С тех пор, я не особо доверяю рецептурам из интернета. Доверилась интуиции и смешала свою собственную смесь по процентовкам, опираясь на ощущения от текстуры.","type":"paragraph"},{"html":"<strong>Esque:</strong> На сколько я понимаю, в начале пути – это было хобби?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Сначала был долгий этап осознания. Со своих первых экспериментов с бальзамами для губ я переключилась на мыло с нуля. Потом начала делать уходовую косметику для лица и тела. Потом я наконец-то собралась с духом и ушла из офиса. Но, открыла бизнес по доставке продуктовых наборов с рецептами на неделю. Через год поняла, что это не мое. Нужно что-то другое. Вспомнила про увлечение изготовлением косметики и решила попробовать запустить свой бренд. Тогда он назывался «KATYA&amp;CO». Все происходило интуитивно и очень неосознанно. Подсказать, как и что правильно делать в плане бизнеса было некому. Очень жаль, конечно, зато я получила свой собственный бизнес-опыт методом проб и ошибок. В общем, я накидала рецептуры, закупила ингредиенты, распечатала этикетки, все смешала, отфотографировала и в контакте создала группу. Разослала всем друзьям просьбы рассказать обо мне. И сидела ждала заказы. Но заказов не было. Зато один из знакомых знакомых увидел мой проект, а он был организатором дизайнерских маркетов в Самаре (я тогда жила в Самаре) и написал мне: «Не хотите поучаствовать?». Я сначала отказалась, так как надо было платить взнос за участие, делать много продукции. Но потом за месяц до мероприятия внезапно передумала. Кстати, мне очень повезло. Вообще, публика в Самаре крайне тяжелая на подъем, я знаю многих организаторов разных интересных мероприятий в Самаре, но порой люди ленятся и просто не приходят! Бывали мероприятия супер провальные в плане посетителей и следовательно покупателей. Но мне повезло, и тот дизайн маркет был просто супер посещаемый, толпы людей, прямо как в Москве. И «KATYA&amp;CO» тогда имела оглушительный успех в плане продаж и я решила продолжить.","type":"paragraph"},{"html":"<strong>Esque:</strong> Какие основные компоненты используются при создании бальзамов?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Я выучилась на технолога именно органических рецептур в английской школе «Formula Botanica на advanced skincare formulater». И с детства я люблю травы, я даже помню, что в детстве у меня был свой собственный календарь сборки трав, я ходила по полям и лесам, звучит криптово, но это факт, и собирала их (выросла в деревне). В общем, я люблю работать с натуральными компонентами: растительными и эфирными маслами, восками, травами. Следовательно, в бальзамах для губ основа - это смесь растительных, эфирных масел, пчелиного воска и добавок-суперфудов, например, зеленый чай матча в бальзаме МАТЧА&amp;МЯТА, тертые какао-бобы в бальзаме КАКАО&amp;КАРДАМОН и др.","type":"paragraph"},{"html":"<strong> Esque:</strong> Есть ли в российском сегменте аналоги вашего продукта?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Мне очень нравится американский бренд «hurraw». Многие наши клиенты сравнивают мои бальзамы именно с ними. И мне это нравится, потому что я сама большой поклонник бальзамов hurraw. У них крутые составы, вкусы, я, конечно же, на них равняюсь и вдохновляюсь ими, как старшим братом, знаете.","type":"paragraph"},{"html":"<strong>Esque:</strong> На рынке вы уже несколько лет. Тяжело ли развивать бизнес в России и как вы ищите точки продаж продукта?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> У каждого предпринимателя получается крайне интересный жизненный опыт. И мне кажется, не важно в какой стране ты строишь бизнес, предпринимателем ты останешься в любой геолокации. Последние события показали мне, что Россия – это буквально чистое поле для бизнеса, здесь главное, все правильно делать. Это, конечно, самое сложное. Еще в России есть очень много ресурсов, очень. Но они часто крайне нерационально используются, это грустно. Надеюсь, что все-таки ситуация исправится в ближайшем будущем. Еще я женщина и это вносит свои нюансы в ведение бизнеса. Все таки, чтобы сохранять душевный баланс как женщина, нужно по-другому действовать в мужском мире. Через избитую фразу «делай-то, что любишь». Я когда делаю дело через мужской принцип «достигай, еще выше, еще сильнее, еще быстрее», я впадаю в минус мораль и мне кажется, что все бессмысленно, теряется любовь к делу в этой спешке, в этом достигаторстве. Поэтому в последнее время я позволяю себе просто делать то, что люблю по максимуму хорошо, а это уже вам клиентам решать – понравится вам продукт или нет. Будете ли вы его покупать или нет. Сейчас мы продаемся через маркетплейсы России и дизайнерские магазины, салоны красоты по России. Обычно, нас сами находят и хотят представлять наш продукт в своем регионе.","type":"paragraph"},{"html":"<strong>Esque:</strong> Вы анализировали ошибки, которые были на старте? Чего не допустили бы сейчас?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Ошибок было очень много. Самое главное для предпринимателя – это его ментальное здоровье. Будет ментальное здоровье – будет энергия, остальное дело действий. Команду, деньги – все это можно найти. Я долго училась самомотивации, долго взращивала опору внутри себя, разбиралась с тем, кто я и что я. Что мне важно. Что я хочу дать и сказать этому миру? Недавно открыла для себя классную технику «неваляшки». Будем честны, у всех у нас одни планы на жизнь, но жизнь частенько сбивает нас с ног. Можно сильно упасть морально, долго барахтаться в депрессии, самообесценивании (у каждого свое), поэтому нужно иметь свой личный список действий, которые, во-первых, действуют на 99%, во-вторых, ресурсируют и восстанавливают внутреннюю гармонию. Этот список у каждого человека свой, потому что все мы уникальны. Банально, но я очень долго вырабатывала свой личный список, чтобы как барон Мюнгхаузена самой себя вытаскивать из болота за волосы в тяжелые моменты.","type":"paragraph"},{"html":"Кстати, я благодарна сама себе за все свои ошибки, потому что это рост. Но, наверное, если бы я встретила сейчас себя из прошлого я бы себе посоветовала бы поменьше прокрастинировать, работать с концентрацией внимания, чтобы не распыляться на все подряд, пойти учиться бизнес-образованию и слушать советы умных людей-бизнесменов с опытом, разумеется, не забывая прислушиваться к себе. Но знаете, все эти советики в тот момент были бы бесполезны для меня, потому что самое сложное заключалось в том, что я не знала чего хочу. Сейчас знаю.","type":"paragraph"},{"html":"<strong>Esque:</strong> Екатерина, отражается ли ситуация в мире, на развитии бизнеса?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> После февральских событий, началась паника у всех производителей косметики в России с одной стороны. У поставщиков сырья крупные бренды скупили вообще все. Плюс поставщики сырья необоснованно задрали цены на сырье. Типографии туда же. Сейчас более менее стабилизировалась ситуация. Но с другой стороны, крупный ритейл открыл двери для маленьких российских брендов.","type":"paragraph"},{"html":"<strong>Esque:</strong> Наметили уже планы на 2023 год?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Да, наметили планы по развитию компании, увеличения доли присутствия на рынке, побольше социальной активности. Было здорово поучаствовать в качестве партнера в Fashion bitva. Плюс очень буду стараться создать новые вкусы бальзамов для губ и возможно, органический уход для лица.","type":"paragraph"},{"html":"<strong>Esque:</strong> Спасибо вам за нашу беседу. Думаю, ваши советы вдохновят многих. И напоследок, пару слов нашим читателям.","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Если вы хотите что-то сделать, но боитесь. Правильно, что боитесь, но лучше зажмуриться и прыгнуть в бездну, там будет большой рост.","type":"paragraph"},{"type":"image","mediaId":"cmrmqs892007puktafiv5ppyc"}]'::jsonb,'cmrmqs7xb007oukta0gk2oudu','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyz0000akwtaq6w9733r','cmrmpdrom0000sstarkqxwts4','2023-01-17T06:00:00.000Z'::timestamp,NULL,NULL,NULL,590,'/beauty/mnenie/590-kurtajkina-ekaterina-ja-blagodarna-sama-sebe-za-vse-svoi-oshibki-potomu-chto-jeto-rost.html','2026-07-15T20:59:36.178Z'::timestamp,'2026-07-16T13:57:33.042Z'::timestamp,'''2023'':1410C ''99'':1201C ''advanc'':701C ''bitva'':1438C ''botanica'':699C ''cmrmqs892007puktafiv5ppyc'':1507C ''co'':489C,661C ''cоздател'':1A ''esqu'':90C,396C,676C,793C,854C,1081C,1338C,1405C,1458C ''fashion'':1437C ''formula'':698C ''formulat'':703C ''handmad'':215C,354C ''hawaii'':207C ''hurraw'':811C,832C ''imag'':1505C ''katya'':488C,660C ''made'':205C ''nivea'':181C ''open'':293C ''organ'':213C ''paragraph'':44C,88C,104C,394C,408C,674C,685C,791C,803C,852C,875C,1079C,1095C,1245C,1336C,1349C,1403C,1413C,1456C,1476C,1503C ''skincar'':702C ''space'':294C ''активн'':1429C ''американск'':809C ''анализирова'':1083C ''аналог'':799C ''английск'':696C ''аптек'':179C ''архипелаг'':148C ''баланс'':966C ''бальз'':157C,272C,301C ''бальзам'':4A,52C,75C,100C,347C,421C,683C,757C,777C,785C,817C,831C,1446C ''бальзамчик'':199C ''банальн'':1221C ''барахта'':1181C ''барон'':1232C ''бездн'':1497C ''бесед'':1463C ''бесполезн'':1317C ''бессмыслен'':10