INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqr6mp003vuktavc159aww','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Нани Ева представила сольный альбом “Между небом и водой”','Сегодня на основных стриминговых сервисах вышел первый официальный студийный альбом известной певицы и автора песен Нани Евы, ставшей известной широкому зрителю благодаря проектам “Голос” и “Главная Сцена”.','627-nani-eva-predstavila-solnyj-albom-mezhdu-nebom-i-vodoj','[{"html":"Сегодня на основных стриминговых сервисах вышел первый официальный студийный альбом известной певицы и автора песен Нани Евы, ставшей известной широкому зрителю благодаря проектам “Голос” и “Главная Сцена”.","type":"paragraph"},{"html":"Нани Еву называют восходящим феноменом русского jazz-soul-rnb, поскольку ей удается самобытно и изящно воплощать лучшие традиции мировой сцены в русскоязычном исполнении. Яркая, немного экзотичная внешность, филигранный вокал с бархатистым тембром, фирмовое звучание, дополненное глубокой лирикой и музыкой в исполнении состава сильнейших московских джазменов - такие козыри в руках вызывают интерес и (с большой долью вероятности) привыкание.","type":"paragraph"},{"html":"Из всех певиц данного жанра, Нани Еву отличает способность погрузить слушателя в медитативное состояние. Тут важной деталью пазла данного артиста является факт образования и деятельности тренера по йоге, а также диплом психолога.","type":"paragraph"},{"html":"За мягкий стиль пения и меланхоличную женственность ее сравнивают с иконами соула Sade и Maysa, но она все же стоит особняком от всех певиц. Личность этой артистки словно существует вне стандартов и рамок, но каким-то образом она проницательно ловит тонкие вибрации мира и предлагает музыкальный продукт, который оказывается невероятно в тему. И тут уже становится неважно, какой у него жанр и формат. Неудивительно, что среди почитателей таланта Нани - множество звезд российской сцены.","type":"paragraph"},{"html":"Ранее певица выпустила EP сборник, песни из которого вошли в различные плейлисты smooth-джаза Яндекса и ВК, а также 2 песни стали саундтреками сериала “Мафия”.","type":"paragraph"},{"html":"Альбом “Между небом и водой” представляет собой сборник из 11 авторских песен Нани, написанных в течение 11 лет жизни. Некоторые уже были известны поклонникам, но в иных аранжировках, другие - станут сюрпризом. Для обложки альбома певица выбрала фото 2012 года, и будто приглашает слушателя отправиться из этой точки вместе с ней в путешествие в ее неповторимый космос, погружаться в который необходимо исключительно не спеша. И с каждым новым треком проходить путь развития вместе с ней, совершая настоящий полет, в котором Нани Ева - капитан, ведущий вас. Это море музыки вокруг одновременно и расслабляет, и держит в тонком эмоциональном напряжении, что неосознанно возникает из-за свойства ее стихов - они требуют твоего внимания, анализа, осмысления, осознания. Именно ее поэзия не позволяет поставить треки как фон, под который можно работать. Остроумная игра слов, образов и ассоциаций словно формируют диско-шар, который будет отвлекать вас. Например, “Все зависит от тебя, но ты зависишь от меня” (трек “Нет никого”). Или вокализованное путешествие по лабиринтам собственного ума на фоне настойчивого басового рифа Кирилла Афонина и почти трансцендентного соло саксофона Тимура Некрасова (“Пазл”).","type":"paragraph"},{"html":"Где-то там между строк все дышит любовью. Да, конечно, не обошлось без нее. Только Нани загадочно, атмосферно, метафорично и нестандартно воспевает об этом прекрасном чувстве, которое веками творит чудеса и заставляет одних людей вдохновлять, других - наслаждаться плодами вдохновения.","type":"paragraph"},{"html":"Резюмируя самую джазовую пятничнкю новинку, можно сказать, что перед нами - музыка для интеллектуалов, эстетичных слушателей в поисках истины и с запросом на соединение красоты и духовности, а также для тонко-чувствующих душ и сердец. Альбом погружает в состояние рефлексии, это вдумчивый, объемный, обволакивающий процесс, но без надрыва и экзальтированной драмы, а уводящий в глубокие метафизические размышления и оставляющий светлое послевкусие.","type":"paragraph"},{"html":"Новинка доступна на всех популярных платформах.","type":"paragraph"},{"html":"<a href=\"https://band.link/NaniEvaLP2023\" target=\"_blank\" rel=\"noopener noreferrer\">https://band.link/NaniEvaLP2023</a>","type":"paragraph"}]'::jsonb,'cmrmqr6lg003uuktaxvkulbrj','cmrm8kz36000ckwtabqfh3f4h','cmrm8kze2000gkwtad8wkij5y','cmrmpdrom0000sstarkqxwts4','2023-12-08T06:00:00.000Z'::timestamp,NULL,NULL,NULL,627,'/sobytija/muzyka/627-nani-eva-predstavila-solnyj-albom-mezhdu-nebom-i-vodoj.html','2026-07-15T20:58:47.377Z'::timestamp,'2026-07-16T13:57:03.779Z'::timestamp,'''/nanievalp2023'':566C ''11'':278C,285C ''2'':260C ''2012'':306C ''band.link'':565C ''band.link/nanievalp2023'':564C ''ep'':243C ''jazz'':74C ''jazz-soul-rnb'':73C ''maysa'':177C ''paragraph'':65C,126C,161C,238C,267C,446C,489C,553C,562C,568C ''rnb'':76C ''sade'':175C ''smooth'':253C ''smooth-джаз'':252C ''soul'':75C ''автор'':23B,50C ''авторск'':279C ''альб'':5A,19B,46C,269C,526C ''альбом'':302C ''анализ'':379C ''аранжировк'':296C ''артист'':147C ''артистк'':189C ''ассоциац'':400C ''атмосферн'':466C ''афонин'':436C ''бархатист'':98C ''басов'':433C ''благодар'':31B,58C ''больш'':121C ''важн'':143C ''вдохновен'':487C ''вдохновля'':483C ''вдумчив'':532C ''ведущ'':351C ''век'':476C ''вероятн'':123C ''вибрац'':205C ''вк'':257C ''вмест'':316C,340C ''вне'':192C ''внешност'':94C ''вниман'':378C ''вод'':9A,273C ''возника'':368C ''вока'':96C ''вокализова'':424C ''вокруг'':356C ''воплоща'':83C ''воспева'':470C ''восходя'':70C ''вошл'':248C ''выбра'':304C ''вызыва'':117C ''выпуст'':242C ''вышел'':15B,42C ''где-т'':448C ''главн'':35B,62C ''глубок'':103C,545