INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqf71r005fpota38vqyrn3','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Александр Давыдов: "От любви до ненависти один шаг. Сегодня тебя любят, а завтра будут ненавидеть"','Александр Давыдов – российский актер театра и кино.','639-aleksandr-davydov-ot-ljubvi-do-nenavisti-odin-shag-segodnja-tebja-ljubjat-a-zavtra-budut-nenavidet','[{"html":"Александр Давыдов – российский актер театра и кино. За плечами молодого артиста сотни постановок в театре и более 60 ролей в кино. Его персонаж Егор Смолов в фильме «Птица в клетке», несмотря на отрицательную роль в фильме, покорил сердца российских женщин, а Владимир в сериале «Маруся» подарил актеру всероссийскую известность!","type":"paragraph"},{"html":"<br />Наше интервью – это откровенный разговор о самом главном: о российском кинематографе, планах на будущее, сложности актерской профессии и жизни за кадром!","type":"paragraph"},{"html":"<br />Благодарим за теплый и искренний разговор!","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/D6_pttdo7oc?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" title=\"Александр Давыдов: &quot;От любви до ненависти один шаг. Сегодня тебя любят, а завтра будут ненавидеть&quot;\"></iframe>","type":"embed"}]'::jsonb,'cmrmqf701005epotaake0eias','cmrm8kzli000ikwtafbw33jnj','cmrm8kzns000jkwtahwuubl9w','cmrmpdrom0000sstarkqxwts4','2024-02-14T06:00:00.000Z'::timestamp,NULL,NULL,NULL,639,'/persona/intervju/639-aleksandr-davydov-ot-ljubvi-do-nenavisti-odin-shag-segodnja-tebja-ljubjat-a-zavtra-budut-nenavidet.html','2026-07-15T20:49:28.047Z'::timestamp,'2026-07-16T13:56:55.944Z'::timestamp,'''60'':40C ''emb'':108C ''paragraph'':73C,97C,106C ''актер'':19B,26C,69C ''актерск'':90C ''александр'':1A,16B,23C ''артист'':33C ''благодар'':99C ''будут'':14A ''будущ'':88C ''владимир'':64C ''всероссийск'':70C ''главн'':82C ''давыд'':2A,17B,24C ''егор'':46C ''женщин'':62C ''жизн'':93C ''завтр'':13A ''известн'':71C ''интерв'':76C ''искрен'':103C ''кадр'':95C ''кин'':22B,29C,43C ''кинематограф'':85C ''клетк'':52C ''люб'':11A ''любв'':4A ''мар'':67C ''молод'':32C ''наш'':75C ''ненавидет'':15A ''ненавист'':6A ''несмотр'':53C ''откровен'':78C ''отрицательн'':55C ''персонаж'':45C ''план'':86C ''плеч'':31C ''подар'':68C ''покор'':59C ''постановок'':35C ''професс'':91C ''птиц'':50C ''разговор'':79C,104C ''рол'':41C,56C ''российск'':18B,25C,61C,84C ''сам'':81C ''сегодн'':9A ''сердц'':60C ''сериал'':66C ''сложност'':89C ''смол'':47C ''сотн'':34C ''театр'':20B,27C,37C ''тепл'':101C ''фильм'':49C,58C ''шаг'':8A ''эт'':77C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqelut0031potanecpicyn','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Я отец! Я не плачу алименты!','Вопрос алиментов один из самых основных моментов при разводе пар, в которых есть несовершеннолетние дети.','667-ja-otec-ja-ne-plachu-alimenty','[{"html":"Вопрос алиментов один из самых основных моментов при разводе пар, в которых есть несовершеннолетние дети. И судя по статистике, решить его получается далеко не у всех. По данным службы судебных приставов в 2023 году с неплательщиков было взыскано 68 млрд рублей, а это на 39% больше по сравнению с предыдущим годом.","type":"paragraph"},{"html":"<i>«Если в 2022 году федеральная служба за год произвела взыскание 48 млрд руб., то по итогам 2023 года уже можно говорить о 68 млрд руб., то есть почти на 19–20 млрд руб. больше», — приводит цифры министр юстиции Константин Чуйченко.</i>","type":"paragraph"},{"html":"В желании отомстить женщине мужчина (подавляющим числом неплательщиков являются именно мужчины) идет на самые крайние меры, лишая своего ребенка помощи и присутствия в его жизни отца, перекладывая всю ответственность на мать. Реже причиной неуплаты является отсутствие денежных средств, но зачастую корни подобных отговорок лежат все также в желании позлить женщину.","type":"paragraph"},{"html":"В подавляющем большинстве мужчины считают, что деньги пойдут бывшей жене. Тут играет роль обиды и желание мести. Как будто деньги идут не детям, а жене. Такой мужчина психологически не взрослый, отсюда нет соединения, что это мои дети, я тоже поучаствовал в их появлении. Если дети живут с мамой, то могут восприниматься преградой для мужчины - тут перенос неотреагированных эмоций с жены на детей.","type":"paragraph"},{"html":"И завершающая причина, мужчина не платя алименты, хочет побыстрее выйти из отношений с бывшей женой. Сцепка жена и дети про одно. Развод - травматичный опыт. Чтобы избежать боли - избегаю контакта через деньги – <strong>рассказывает о психологических причинах психолог и системный терапевт Екатерина Тишкина.</strong>","type":"paragraph"},{"html":"Очень часто состоятельные мужчины отказываются помогать детям, вкладывая в это время свои финансы в строительство недвижимости или новой личной жизни. В некоторых случаях настолько принципиальная позиция и желание мстить берут верх над разумом и бывший партнер, переписывает свое имущество на родственников и прибегает к «серым схемам работы».","type":"paragraph"},{"html":"«У моего бывшего мужа 2 квартиры, загородный дом и дорогая машина, но все это записано на родителей. Он отказывается от выплаты даже минимального прожиточного минимума, аргументируя это тем, что я слишком много говорю» - рассказывает свою историю жительница Саратова, Маргарита Лесова.","type":"paragraph"},{"html":"К сожалению, в подобных ситуациях бессильно даже правосудие, ведь доказать, что имущество мужа и он специально пошел на такие меры ради неуплаты алиментов, очень сложно.","type":"paragraph"},{"html":"«В последнее время наблюдается увеличение случаев, когда мужчины выражают желание уйти от исполнения алиментных обязательств. Скажем прямо, они и раньше были не редкостью. Но сегодня, в эру \"интернет-подкованности\" и эпохи психологических дилем \"должен-не должен\" - все усугубилось. Причины могут быть различными: от финансовых трудностей до изменения семейной ситуации. Однако, важно помнить, что алименты являются законным обязательством и их уклонение может повлечь за собой серьезные последствия.","type":"paragraph"},{"html":"Недавно ко мне обратился клиент, который столкнулся с проблемой уплаты алиментов из-за потери работы. Вместо того чтобы обратиться к суду с запросом о снижении размера алиментов в связи с изменением финансового положения, он решил просто перестать их выплачивать. Это привело к возникновению судебного спора и дополнительным финансовым затратам на оплату штрафов. Я уже молчу об этнической стороне вопроса. Ведь я и сам - отец двоих детей.","type":"paragraph"},{"html":"Поэтому, в случае возникновения сложностей с уплатой алиментов, важно обратиться к профессиональному юристу, который поможет найти оптимальное решение с учетом законодательства и защиты ваших интересов. И, в то же время, необходимо помнить, что соблюдение законных обязательств - залог сохранения мирных отношений и защиты прав всех сторон» - <b>дает свою консультацию генеральный директор компании \"Честный Юрист\", специалист по банкротству физических лиц, Руслан Мирзеханов.</b>","type":"paragraph"},{"html":"В то время, как растет статистика неплательщиков, растет и статистика платежеспособных женщин. Индекс деловой активности женщин в России (Women Business Index — WBI – индекст деловой активности женщин в России) в 2023 году достиг 73,7 процентного пункта), а это максимальное значение с 2015 года.","type":"paragraph"},{"html":"Все больше женщин растят детей, занимаются бизнесом и прекрасно выглядят!","type":"paragraph"}]'::jsonb,'cmrmqelqq0030pota9vbelffl','cmrm8kzpw000mkwtaocyn5161','cmrm8kzra000okwtaqek3edwq','cmrmpdrom0000sstarkqxwts4','2024-07-11T06:00:00.000Z'::timestamp,NULL,NULL,NULL,667,'/psihologija/samosovershenstvovanie/667-ja-otec-ja-ne-plachu-alimenty.html','2026-07-15T20:49:00.581Z'::timestamp,'2026-07-16T13:56:39.563Z'::timestamp,'''19'':105C ''2'':335C ''20'':106C ''2015'':647C ''2022'':78C ''2023'':54C,92C,635C ''39'':66C ''48'':86C ''68'':60C,98C ''7'':639C ''73'':638C ''busi'':625C ''index'':626C ''paragraph'':74C,117C,170C,235C,279C,329C,372C,400C,471C,541C,604C,650C,663C ''wbi'':627C ''women'':624C ''активн'':620C,630C ''алимент'':6A,8B,23C,243C,396C,457C,483C,500C,550C ''алиментн'':415C ''аргументиру'':356C ''банкротств'':598C ''берут'':310C ''бессильн'':379C ''бизнес'':658C ''бол'':263C ''большинств'':174C ''бывш'':180C,250C,315C,333C ''важн'':454C,551