INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqeajc001upota9fxccqnz','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'В городах России объявлена программа фестиваля Beat Weekend 2024','Узнайте, какие фильмы будут показаны на фестивале Beat Weekend 2024 в Казани, Екатеринбурге, Воронеже, Санкт-Петербурге и других городах с 12 по 22 сентября.','680-v-gorodah-rossii-objavlena-programma-festivalja-beat-weekend-2024','[{"html":"С 12 по 22 сентября в 27 городах России пройдет фестиваль документального кино Beat Weekend 2024. Казань, Екатеринбург, Воронеж, Санкт-Петербург уже активно анонсируют расписание показов.","type":"paragraph"},{"html":"Известно, что в программу Beat Film Festival вошли фильмы о режиссере Мишеле Гондри, голливудском кастинг-директоре Бонни Тиммерман, звезде фотографии Джеймсе Хэмилтоне. Кроме того зрители смогут увидеть лучшие картины Beat прошлых лет и ленту-победитель программы «Док Индустрия».","type":"paragraph"},{"html":"Сеансы будут дополнены образовательной программой с участием местных культурных героев, журналистов, представителей городских сообществ.","type":"paragraph"},{"html":"В прошлом году зрителей привлекла картина Аманды Ким «Нам Джун Пайк: Луна - это первый телевизор» (Nam June Paik: Moon is the oldest TV). В основу фильма легла биография легендарного художника. Из российских работ публика отметила фильм о лесных пожарах в Якутии в 21 году Александра Абатурова «Рай».","type":"paragraph"},{"html":"Больше всего отрицательных отзывов получила картинка \"32 звука\" Сэма Грин. Критиков не вдохновил эксперимент режиссера на тему «как мы слышим и слушаем».","type":"paragraph"}]'::jsonb,'cmrmqeahx001tpotakpe9kkf3','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-08-26T06:00:00.000Z'::timestamp,NULL,NULL,NULL,680,'/soby