''узна'':10B ''участ'':114C ''фестивал'':6A,16B,45C ''фильм'':12B,73C,150C,160C ''фотограф'':85C ''художник'':154C ''хэмилтон'':87C ''эксперимент'':188C ''эт'':137C ''якут'':165C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqriok004suktacyaq25zd','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Финал 11 сезона конкурса дизайнеров FASHION bitva прошел в концертном зале "Мир"','19 ноября в Москве в концертном зале «Мир» состоялся финал 11 сезона конкурса дизайнеров Fashion bitva.','624-final-11-sezona-konkursa-dizajnerov-fashion-bitva-proshel-v-koncertnom-zale-mir','[{"html":"19 ноября в Москве в концертном зале «Мир» состоялся финал 11 сезона конкурса дизайнеров Fashion bitva. В показе приняли участие 20 российских дизайнеров: победители региональных этапов 2023 года и дизайнеры, прошедшие онлайн-отбор.","type":"paragraph"},{"html":"География проекта обширна: от Владивостока до Краснодара. У каждого участника свое видение, своя история и, несомненно, свое мнение о тенденциях весеннего сезона грядущего года.","type":"paragraph"},{"html":"Почетное жюри отметило многих дизайнеров, но первое почетное место присудило дизайнеру из Владивостока Марго Авоян и ее коллекции «Восточные муссоны»! Вдохновением для коллекции послужил симбиоз азиатской и восточной культур. Азиатское - смелое и прогрессивное, а восточное- таинственное и завораживающее. Поздравляем победителя и желаем успехов в Китае, ведь главный приз проекта – это поездка в Китай на Russian Fashion display!","type":"paragraph"},{"html":"Марго Авоян","type":"paragraph"},{"html":"Оксана Шахбазян – молодой дизайнер из города Волжский была удостоена 2 места. Оксана создаёт яркую, провокационную, но в тоже время удобную одежду. Одежда бренда \"ArtOks\" создана для тех, кто не любит рамки и не боится показать себя. Этой же позиции придерживается и сам дизайнер, ведь Оксане всего 15 лет! Желаем развития и дальнейшего продвижения, а конкурс ей в этом поможет. Оксана получает 2-месячное обучение в академии Fashion Marketing.","type":"paragraph"},{"html":"Оксана Шахбазян","type":"paragraph"},{"html":"В конкурсе были представлены, взрослые, возрастные, детские и подростковые коллекции.","type":"paragraph"},{"html":"Яркие вечерние платья от казанского бренда «SafiNelli» растопили сердца всех гостей. Девиз бренда «Быть главной героиней своей сказки и своего праздника»!","type":"paragraph"},{"html":"Главными принцессами почувствовали себя и модели в коллекции московского дизайнера Ольги Доброй! Показ соединил в себе две коллекции \"Tропические цветы\" и \"Пространственные фигуры\" – сложные техники ручной работы сегмента couture.","type":"paragraph"},{"html":"Пышные платья были представлены и ростовским дизайнером Раисой Мирошниченко. Но вместо нежных образов перед нами предстали эпатажные дерзкие наряды. Дизайнер явно любит удивлять и шокировать и это у нее получилось!","type":"paragraph"},{"html":"Дизайнер Дарья Звягина представила 2 коллекции: детскую для маленьких леди и элегантную линейку для взрослых женщин.","type":"paragraph"},{"html":"Волна шлейфов, бриз бантов и бесконечный горизонт линий – почерк дизайнера невозможно перепутать.","type":"paragraph"},{"html":"Дарья Звягина","type":"paragraph"},{"html":"Детская Коллекция «Формула» барнаульского бренда «NS» была создана по мотивам гонок «Формула 1». Все изделия выполнены из искусственной кожи и декорированы клепками и шипами. Благодаря стильным аппликациям из кожи, которыми декорированы костюмы, зритель видит гоночные машины прямо на платьях и костюмах коллекции.","type":"paragraph"},{"html":"Также бренд представил взрослую коллекцию «Сквозь рамки». С самого детства человека ограничивают рамками: школа, работа, обязанности. Одежда – это средство самовыражения, через которое мы можем проявить себя и пробиться сквозь рамки общества. Ярко и дерзко в юности, но чем старше мы становимся, тем больше раскрываем себя, не подчиняясь, а уже управляя этими рамками. Коллекция сквозь рамки – это одежда для смелых, уверенных в себе девушек, управляющих своей жизнью, а не поддающихся течению.","type":"paragraph"},{"html":"NS BRAND","type":"paragraph"},{"html":"Коллекция Анастасии Кузнецовой, дизайнера из Екатеринбурга, включает в себя актуальные фасоны платьев и костюмов. Главные акценты сделаны на необычные и яркие детали, добавляющие изюминку внешнему виду наших маленьких модников.","type":"paragraph"},{"html":"И завершает детско-подростковое отделение победитель регионального показа в Краснодаре, Наталья Халанская. Красно-черные образы королев – леденящие и в тоже время обжигающие сердца. В этой коллекции совпало все: актуальность, качество пошива и целостность коллекции.","type":"paragraph"},{"html":"Открыла взрослое отделение дизайнер Юлия Бардина с коллекцией «Wonderland 23»! Яркие цвета, сложные фактуры и объемные силуэты – для смелых и уверенных женщин.","type":"paragraph"},{"html":"Юлия Бардина","type":"paragraph"},{"html":"Следом за Юлией на подиуме появились модели Виктории Утробиной. Дизайнер специализируется на создании свадебных и вечерних платьев. Все ее образы созданы вручную.","type":"paragraph"},{"html":"Такого же стиля придерживается и дизайнер Шабнами Шах. Все ее дизайнерские платья исключительно авторской ручной работы.","type":"paragraph"},{"html":"Коллекция «Философия счастья» бренда из Липецка «MARUSSIA» исключительно о хрупкости и нежности счастья, о его стремительности и силе<em>. «Его можно почувствовать, его можно потрогать, его можно НАДЕТЬ…»</em> - девиз дизайнера.","type":"paragraph"},{"html":"Нежности на подиуме конкурса в этот день было очень много. Московский дизайнер Елена Гузева и молодой сибирский бренд “Kristaf” также представили вечернюю коллекцию.","type":"paragraph"},{"html":"Победитель регионального этапа в Екатеринбурге Ольга Соловьева показала зрителям и членам жюри трикотажную коллекцию «Эликсир». Цель бренда «SO Love» — изменить отношение к трикотажу как к чему-то универсально-простому, нафталиновому, бесформенному и обыденному… Жюри высоко отметили ее авторский метод!","type":"paragraph"},{"html":"Ольга Соловьева","type":"paragraph"},{"html":"Эпатажная коллекция Зарины Арус внесла на подиум некую таинственность, ведь лица многих девушек были закрыты. Как призналась сама дизайнер, она любит креативные и сложные решения в костюме. Именно поэтому дерзкая сексуальность остро граничила с таинственностью и закрытостью образа.","type":"paragraph"},{"html":"Любит выделяться из толпы и казанский дизайнер Динара Шакирова. Главная идея бренда - адаптировать одежду к любым условиям в течение дня, именно поэтому все образы Динары созданы в виде трансформера.","type":"paragraph"},{"html":"Свобода движений – главная задача еще одного бренда. Бренд с Байкала «MISHA» - это простые формы и функциональность моделей, для того, чтобы почувствовать настроение Байкала, и одев вещь, совершить мысленное путешествие.","type":"paragraph"},{"html":"Бренд «GS collection» представил на подиуме образы, созданные вручную дизайнером Галиной Спириной. Из тоненькой кашемировой, шёлковой или мериносовой ниточки, спицами или крючком, дизайнер создает красивые и уютные изделия: шапки, шарфы, пуловеры и джемпера, которые не только согреют вас, но о и подчеркнут вашу индивидуальность.","type":"paragraph"},{"html":"11 сезон подошел к концу, а его финал в концертном зале «Мир» был его триумфальным завершением. Смелые идеи дизайнеров, глянцевый подиум и необычная шоу программа - все это сопровождало весь год команду проекта от Дальнего Востока до юга России.","type":"paragraph"},{"html":"До встречи в 12 сезоне!","type":"paragraph"},{"html":"Раиса Мирошниченко","type":"paragraph"},{"html":"Ольга Добрая","type":"paragraph"},{"html":"Наталья Халанская","type":"paragraph"},{"html":"SafiNelli","type":"paragraph"},{"html":"Анастасия Кузнецова","type":"paragraph"},{"html":"KRISTAF","type":"paragraph"},{"html":"MARUSSIA","type":"paragraph"},{"html":"GS","type":"paragraph"},{"html":"MISHA","type":"paragraph"},{"html":"Виктория Утробина","type":"paragraph"},{"html":"Динара Шакирова","type":"paragraph"},{"html":"Елена Гузева","type":"paragraph"},{"html":"Зарина Арус","type":"paragraph"},{"html":"Шабнами Шах","type":"paragraph"},{"html":"<em><u>Благодарим жюри за честное судейство:</u></em>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqr8uh0044uktao037rari"},{"mediaId":"cmrmqr98j0045uktaq645fh58"},{"mediaId":"cmrmqr9pp0046uktarfr3l2h4"},{"mediaId":"cmrmqra3z0047uktaqrr7k3zh"},{"mediaId":"cmrmqrajl0048ukta4qkc6nua"},{"mediaId":"cmrmqrauu0049uktaqepxbhrs"},{"mediaId":"cmrmqrb5s004auktaieh3mpsp"},{"mediaId":"cmrmqrbhg004bukta5o1b5lvm"},{"mediaId":"cmrmqrbyk004cuktar5ij2mg6"},{"mediaId":"cmrmqrca5004dukta1jk14u63"},{"mediaId":"cmrmqrcml004euktajvsllrvg"},{"mediaId":"cmrmqrd1k004fuktabqjglm0w"},{"mediaId":"cmrmqrdi3004gukta4a3kiiug"},{"mediaId":"cmrmqrdzc004huktahfw3xzkl"},{"mediaId":"cmrmqrecr004iuktakwx80acx"},{"mediaId":"cmrmqresb004juktahf7ayl2j"},{"mediaId":"cmrmqrfda004kuktad11yq89w"},{"mediaId":"cmrmqrg3r004lukta8daluw9g"},{"mediaId":"cmrmqrgjs004mukta55p38nws"},{"mediaId":"cmrmqrh3e004nukta5147h102"},{"mediaId":"cmrmqrhm9004oukta0zcwtlyq"},{"mediaId":"cmrmqrhzn004puktarvebjxj3"},{"mediaId":"cmrmqrid4004quktakilgycea"},{"mediaId":"cmrmqrimz004rukta4ybwh6rc"}]}]'::jsonb,'cmrmqr8hr0043uktawl5w14kg','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2023-11-23T06:00:00.000Z'::timestamp,NULL,NULL,NULL,624,'/projects-esque/fashion-bitva/624-final-11-sezona-konkursa-dizajnerov-fashion-bitva-proshel-v-koncertnom-zale-mir.html','2026-07-15T20:59:02.996Z'::timestamp,'2026-07-16T13:57:05.373Z'::timestamp,'''1'':387C ''11'':2A,23B,39C,902C ''12'':946C ''15'':204C ''19'':13B,29C ''2'':167C,219C,340C ''20'':49C ''2023'':55C ''23'':578C ''artok'':181C ''bitva'':7A,28B,44C ''brand'':494C ''cmrmqr8uh0044uktao037rari'':1026C ''cmrmqr98j0045uktaq645fh58'':1028C ''cmrmqr9pp0046uktarfr3l2h4'':1030C ''cmrmqra3z0047uktaqrr7k3zh'':1032C ''cmrmqrajl0048ukta4qkc6nua'':1034C ''cmrmqrauu0049uktaqepxbhrs