азя'':159C,230C ''шелков'':870C ''шип'':398C ''школ'':433C ''шлейф'':356C ''шо'':925C ''шокирова'':327C ''элегантн'':347C ''эликсир'':715C ''эпатажн'':319C,750C ''эт'':142C,329C,437C,470C,475C,834C,928C ''этап'':54C,703C ''юг'':938C ''юл'':573C,594C,601C ''юност'':455C ''явн'':323C ''ярк'':171C,247C,451C,518C,579C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqeuqy0047potafup5f3ih','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'ПУТЬ ДИЗАЙНЕРА от А до Я','Стать дизайнером в России - это нелегкий и отчаянный выбор.','653-put-dizajnera-ot-a-do-ja','[{"html":"Стать дизайнером в России - это нелегкий и отчаянный выбор. Для каждого хоть немного понимающего в этой сфере понятно, что обладать талантом мало, нужно еще и хорошее понимание бизнес-рынка.","type":"paragraph"},{"html":"Создание успешной коллекции в современных реалиях, где рынок пресыщен всем и вся, мало! Нужно ее продать.","type":"paragraph"},{"html":"Как правило, не все дизайнеры хорошие предприниматели. И после создания нескольких коллекций, становится понятно, что ничего не понятно. Будущее туманно, бюджет исчерпан, а коллекции висят в шкафу!","type":"paragraph"},{"html":"В этой серии интервью мы поговорили с маркетологом Ксенией Нечаевой, стилистом Оксаной Огневой и дизайнером Еленой Тарасенко. У каждого из них своя боль в мире моды. Каждый точно и четко понимает чего не хватает российской индустрии моды! Вместе мы постарались найти выход и ответы на наши вопросы!","type":"paragraph"},{"html":"А на сколько у нас это получилось, судить вам!","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/Yhe_L4QBGHY?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen=\"\" title=\"ПУТЬ ДИЗАЙНЕРА от А до Я\"></iframe>","type":"embed"}]'::jsonb,NULL,'cmrm8ky9t0000kwta6h8ifq47','cmrm8kyog0005kwta01b9favo','cmrmpdrom0000sstarkqxwts4','2024-04-22T06:00:00.000Z'::timestamp,NULL,NULL,NULL,653,'/fashion/interview/653-put-dizajnera-ot-a-do-ja.html','2026-07-15T20:49:12.106Z'::timestamp,'2026-07-16T13:56:52.708Z'::timestamp,'''emb'':156C ''paragraph'':43C,62C,92C,142C,154C ''бизнес'':40C ''бизнес-рынк'':39C ''бол'':116C ''будущ'':82C ''бюджет'':84C ''вис'':88C ''вмест'':131C ''вопрос'':140C ''всем'':54C ''вся'':56C ''выбор'':11B,20C ''выход'':135C ''дизайнер'':2A,4B,13C,68C,108C ''елен'':109C ''индустр'':129C ''интерв'':97C ''исчерпа'':85C ''кажд'':22C,112C,120C ''коллекц'':47C,75C,87C ''ксен'':102C ''мал'':33C,57C ''маркетолог'':101C ''мир'':118C ''мод'':119C,130C ''найт'':134C ''наш'':139C ''нелегк'':8B,17C ''немн'':24C ''нескольк'':74C ''нечаев'':103C ''нужн'':34C,58C ''облада'':31C ''огнев'':106C ''оксан'':105C ''ответ'':137C ''отчая'':10B,19C ''поговор'':99C ''получ'':150C ''понима'':25C,124C ''пониман'':38C ''понятн'':29C,77C,81C ''постара'':133C ''прав'':65C ''предпринимател'':70C ''пресыщ'':53C ''прода'':60C ''пут'':1A ''реал'':50C ''росс'':6B,15C ''российск'':128C ''рынк'':41C ''рынок'':52C ''сво'':115C ''сер'':96C ''скольк'':146C ''современ'':49C ''создан'':45C,73C ''станов'':76C ''стат'':3B,12C ''стилист'':104C ''суд'':151C ''сфер'':28C ''талант'':32C ''тарасенк'':110C ''точн'':121C ''тума'':83C ''успешн'':46C ''хвата'':127C ''хорош'':37C,69C ''четк'':123C ''шкаф'':90C ''эт'':7B,16C,149C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsb220081uktaljqnojsq','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'ВИТАМИН D3: НОВЫЕ ДАННЫЕ','О пользе и необходимости приёма витамина D3 (холекальциферола) сейчас не знает, наверное, только ленивый.','589-vitamin-d3-novye-dannye','[{"html":"О пользе и необходимости приёма витамина D3 (холекальциферола) сейчас не знает, наверное, только ленивый. А с появлением соцсетей еще и каждый блоггер написал о том, как надо принимать витамин D, и дал свою субъективную рекомендацию. Кто-то даже рекомендует пить сразу по 20 000 МЕ данного витамина на постоянной основе, не задумываясь о последствиях.","type":"paragraph"},{"html":"В этой статье я решила подробно разобрать кому и в каких количествах действительно необходим витамин D. Какие дозировки безопасны, а какие токсичны. Тем более, что с 2020 года отношение к витамину D и к дозировкам витамина D снова поменялись. C одной стороны - в лучшую сторону. С другой - не в самую лучшею. Здесь только факты, научные данные, исследования.","type":"paragraph"},{"html":"<u><b>История</b></u>","type":"paragraph"},{"html":"Буквально несколько слов о том, когда мир узнал об этом витамине. Вещество, влияющее на лечение детского рахита, было открыто в начале 20 века. В 1914 году, после открытия американским биохимиком Элмером Макколумом витамина А, английский ветеринар Эдвард Мелленби, наблюдая за собаками, обратил внимание, что те не страдают рахитом, если их кормят рыбьим жиром. О чем всенародно и заявил. Было решено, что от рахита спасает именно витамин А. Чтобы выяснить это наверняка, в 1922 году Макколум поставил очередной эксперимент, удалив из рыбьего жира витамин A. Собаки, которым он давал этот продукт, благополучно излечились от рахита. Так было доказано, что за излечение от рахита отвечает не витамин A, а другой, неизвестный элемент. Поскольку это был четвёртый по счёту витамин, открытый наукой, его назвали четвёртой буквой латинского алфавита - D.","type":"paragraph"},{"html":"Годом позже еще один именитый американский биохимик Гарри Стенбок изобрёл облучение пищи ультрафиолетом. Благодаря этому витамин D в пище увеличивался в разы. Так было открыто, что витамин D может производиться в организме самостоятельно под воздействием солнечного света. Но, как известно, не все регионы в мире богаты инсоляцией. А в начале 20 века была буквально эпидемия рахита. Поэтому облучение еды ультрафиолетом дало потрясающие результаты. Америка тут же победила эпидемию. Но…","type":"paragraph"},{"html":"Обогащение молока витамином D началось и в Европе, однако процесс облучения не контролировался строго, что вызвало вспышку интоксикации витамином D и гиперкальциемию. Симптомы интоксикации: потеря аппетита, заторможенность, сонливость, сильная жажда и учащенное мочеиспускание, тошнота и рвота, запоры, мышечная слабость, гиперкальциемия, которая тогда не лечилась, и самый распространённый симптом переизбытка D - острая почечная недостаточность. В результате это привело к запрету на обогащение продуктов витамином D в большинстве стран Европы.","type":"paragraph"},{"html":"К слову, в СССР данный метод обогащения витамин D никогда не использовали.","type":"paragraph"},{"html":"<u><b>ПОЛЬЗА И ВРЕД </b></u>","type":"paragraph"},{"html":"Итак, даже из приведённых исторических сведений наглядно видно, что от витамина D можно получить интоксикацию. Особенно при бесконтрольном приеме. Однако в мире до сих существует скрытая эпидемия дефицита витамина D, ведь он отвечает не только за кости (напомню, что ранее считалось, что главная задача D - это правильное усвоение кальция и фосфора).","type":"paragraph"},{"html":"Установлено, что витамин D взаимодействует с 2727 изученными генами в организме. И только 7% из них приходятся на костную ткань. Поэтому современное представление о витамине D дает полное право называть его гормоном эндокринной системы. А это значит, что витамин D имеет огромное значение для всего организма в целом.","type":"paragraph"},{"html":"Витамин D имеет важное значение в синтезе молекулы АТФ, а значит в производстве энергии (исследование на рис. 2). Если нет сил в течение дня, то первым делом стоит проверить уровень витамина D.","type":"paragraph"},{"html":"Также доказано, что рецепторы к инсулину - витамин-Д-зависимые. А это значит, что недостаток данного витамина провоцирует и ускоряет развитие инсулинорезистентности и сахарного диабета.","type":"paragraph"},{"html":"Люди, страдающие железодефицитной анемией, как правило, имеют и сильный недостаток витамина D. Дело в том, что усвоение железа без этого витамина ухудшается в разы. А это значит, что и функции щитовидной железы будут снижаться. Людям, у которых проблемы со щитовидной обязательно нужно обратить внимание на витамин D.","type":"paragraph"},{"html":"Также огромная часть детоксикационных процессов в печени (вывод ядов, особенно вывод этанола) связаны с витамином D. Если, к примеру, сильно болеете с похмелья, то тоже стоит обратить внимание на уровень D. Также D служит самым недорогим и простым профилактическим средством против образования и замедления течения фиброза печени.","type":"paragraph"},{"html":"Плюс ко всему, усвоение многих питательных веществ в кишечнике зависит от уровня витамина D. Производство серотонина зависит от уровня витамина D. Достаточное количество витамина D улучшает выживаемость после инфарктов и инсультов. Витамин D уменьшает развитие эндометриоза.","type":"paragraph"},{"html":"Еще долго можно перечислять пользу этого витамина. Даже в лечении некоторых раковых опухолей стали использовать витамин D. Опубликованы тысячи исследований и десятки новых ведутся.","type":"paragraph"},{"html":"Но, как говорил великий Парацельс, яд от лекарства отличается только дозой.","type":"paragraph"},{"html":"Так, например, из последних исследованиях, которые были опубликованы совсем недавно, выявлено, что большие дозировки витамина D не помогают при лечении остеопороза, как считалось до этого. А если дозировки слишком завышены, то и можно ухудшить состояние. Кальцинаты в стенках артерий наблюдались на фоне как избытка, так и недостатка витамина D. Идеально при данных диагнозах работают средние, профилактические дозировки витамина D.","type":"paragraph"},{"html":"Также появилось достаточное количество публикаций, указывающих на то, что в связи с популярностью витамина D участились случаи интоксикаций. Симптомы передозировки те же, что и описаны выше: тошнота, рвота, бессонница, частые мочеиспускания, жажда, сонливость, заторможенность. В 2021 году, например, в одну из больниц США была доставлена женщина в очень тяжёлом состоянии. У неё были повреждены почки, выявлена гиперкальциемия. Как выяснилось женщина принимала по 78 000 ME витамина D в сутки на протяжении полутора лет. И это не могло не привести к таким плачевным последствиям.","type":"paragraph"},{"html":"Более того, у полных людей показатели витамина D в крови очень низки, и это не значит, что его у них совсем нет. Витамин D очень любит запасаться в жировой ткани. И у людей с абдоминальным ожирением, витамин D напрямую депонируется именно в этот жир. И большие дозировки полным людям могут быть противопоказаны.","type":"paragraph"},{"html":"Но, чтобы не заканчивать статью на печальной ноте, хочется привести еще одни свежие данные, связанные с изучением D и Covid-19. Витамин D активирует противовирусный и противоопухолевый иммунитет. Ежедневный прием витамина D может защитить от инфекций дыхательных путей и снизить риск вирусной инфекции, подавить излишний цитокиновый ответ.","type":"paragraph"},{"html":"<u><b>ДОЗИРОВКИ </b></u>","type":"paragraph"},{"html":"Так какие же дозировки витамина D безопасные, и одновременно принесут только пользу? В связи с тем, что до 1 млрд человек страдает дефицитом витамина D и около половины пожилых жителей стран Северной Америки и Европы не получают достаточного количества витамина D, а обеспеченность населения России витамином D признается очень низкой, особенно в Северных регионах, мегаполисах и экологически неблагоприятных районах, то приём профилактических доз этого витамина обязателен. Особенно необходимо дополнительно обогатить себя холекальциферолом тем, в чьём рационе совсем нет жирной рыбы, печени, яиц, вегетарианцам (рис. 8а «Продукты,богаты витамином D»). Также в группе риска по дефициту D дети, кого зачали с ноября по апрель.","type":"paragraph"},{"html":"Кстати, полгода назад я присутствовала на медицинской конференции по реабилитации детей после Covid. Так вот на ней говорилось, что для подростков абсолютно безопасная ежедневная доза витамина D в средних и северных широтах в размере 2 000 МЕ. Детям от 7 до 12 лет - 1 000 МЕ. Взрослым - 5 000 МЕ в сутки.","type":"paragraph"},{"html":"Но все-таки лучше опираться на клинические рекомендации Российской ассоциации эндокринологов по диагностике, профилактике витамина D взрослых. В них сказано, что для поддержания нормального уровня в крови витамина D необходимо на ежедневной основе принимать от 800-1200 МЕ. При заболеваниях дозировки витамина D корректируются индивидуально лечащим врачом. Собственно, вот она самая лучшая, безопасная и необходимая каждому организму золотая середина по ежедневному профилактическому приему витамина D.","type":"paragraph"},{"html":"<u><b>КАК ВЫБРАТЬ? </b></u>","type":"paragraph"},{"html":"Пожалуй, это один из самых важных вопросов, ведь производителей витамина D на фоне его популярности становится все больше и больше. Где найти качество и по разумной цене? Ниже характеристики пяти самых известных препаратов:","type":"paragraph"},{"html":"<u><i>АКВАДЕТРИМ </i></u>","type":"paragraph"},{"html":"Пожалуй, самый известный и самый часто назначаемый препарат. Более того, если недавно был только водный раствор, то сейчас появилась таблетированная форма. Но таблетки все равно нужно растворять в воде. «Аквадетрим» производится либо в Польше, либо в России. Препарат содержит водорастворимую форму витамина D. Каждая капля содержит 500 МЕ витамина. То есть три капли являются средней ежедневной порцией витамина. Бутылочка должна быть обязательно темного цвета, что защищает ее от попадания солнечных лучей. Водный раствор усваивается в организме лучше, чем масляной. Витамин D поднимается быстро (проверено на себе). Но в составе водного «Аквадетрима» есть бензиновый спирт. Это ароматический спирт, при увеличении концентрации которого, может вызывать дистрофические изменения в печени, почках, легких и селезенке. А в составе таблеток - бензонат натрия. Этот вид соли может провоцировать аллергические реакции, а при взаимодействии бензоата натрия с аскорбиновой кислотой (витамин C) образуется бензол – опасный канцероген. То есть на постоянной основе «Аквадетрим» лучше не принимать.","type":"paragraph"},{"html":"<i><u>ВИГАНТОЛ </u></i>","type":"paragraph"},{"html":"Следующий не менее известный и не менее популярный препарат немецкого производства. Всего в двух каплях содержится суточная профилактическая дозировка витамина - 1 000 МЕ. Раствор сделан на основе среднецепочечных триглицеридов и безопасен даже для младенцев с 2-х недельного возраста. Также выпускается в тёмных солнцезащитных флаконах. Однако по отзывам у кого-то может вызывать аллергию, что для данного состава очень странно. Но индивидуальная непереносимость имеет место с любым продуктом. Поэтому при приёме любых витаминов будьте внимательны. Единственное неудобства данного препарата - это то, что он имеет капельный дозатор, как и «Аквадетрим». В остальном - вполне подходит для длительного приёма.","type":"paragraph"},{"html":"<u><i>ДЕТРИМАКС </i></u>","type":"paragraph"},{"html":"Разработан американской фармацевтической компанией. Выпускается в таблетированной форме и сразу в дозировке 1 000 МЕ. В составе содержит короткоцепочные триглицериды, с чем витамин D сочетается неплохо. Однако в составе есть и диоксид титана. К слову, очень многие биологические добавки, витамины и лекарства содержат в составе диоксид титана. Это вещество имеет антислеживающие качества и используется как пищевой краситель. Он считается безвредным. И интоксикация им возможна только при употреблении в большом количестве. В целом же отзывы о препарате «Детримакс» хорошие, многие отмечают, что при приёме на регулярной основе замечают у себя повышение настроения.","type":"paragraph"},{"html":"<u><i>Витамин D3 NOW FOODS</i></u>","type":"paragraph"},{"html":"Еще один неплохой и доступный препарат. Жаль только, что в последнее время очень сильно подорожал. Также стоит быть внимательным, что у этого производителя есть три разных вида, отличающихся по дозировкам, баночек. Это и 2 000 ME, и 5 000 ME. Баночки очень похожи, поэтому будьте бдительны. Большие дозировки - это лечение, а не профилактика.","type":"paragraph"},{"html":"Данные витамины выпускаются в капсулах. В составе капсул только холекальцеферол и оливковое масло. Очень хорошо усваивается, удобно глотать. По отзывам, люди с инсулинорезестентностью и сахарным диабетом (группа риска по дефициту витамина D) наблюдают у себя значительное улучшение самочувствия и настроения.","type":"paragraph"},{"html":"<u><i>Витамин D-солнце (Эвалар) </i></u>","type":"paragraph"},{"html":"Сразу стоит обратить внимание, что данный вид витамина D в форме для рассасывания. Усваивается ли витамин в такой форме лучшее и быстрее? Не факт. Таких исследований нет. Сначала витамин D должен попасть в желудок, затем в кишечник, печень, почки, а потом - в кровоток. То есть в ротовой полости D не усваивается. Но отзывы о данном препарате неплохие. Однако нужно учитывать, что в составе есть сорбит, который при неконтролируемом приёме может вызывать диарею. Плюс данная дозировка значительно ниже профилактической нормы и быстро поднять уровень витамина D у дефицитного человека не сможет. А вот для профилактики в летний период вполне безопасно.","type":"paragraph"},{"html":"<b>ВОДОРАСТВОРИМЫЙ ИЛИ МАСЛЯНАЯ ФОРМА?</b>","type":"paragraph"},{"html":"В идеале в организме лучше всего и быстрее всего усвоиться витамин D в водорастворимой форме. Почему? Ведь D относится к жирорастворимым витаминнам. Все верно. Однако при поступлении витамина D с пищей или препаратами необходимо протий процесс мицеллирования, вступив в реакцию с желчными кислотами. А мицеллы водорастворимые вещества. Чем меньше диаметр мицелл, тем быстрее и эффективнее они действуют. Поэтому из всего перечисленного «Аквадетрим» действительно эффективный. Но… здесь каждый сам решает, что для его организма будет безопаснее.","type":"paragraph"},{"html":"<u><i>Наталья ДЮЖАЯ-РЕШЕТНИКОВА, диетолог-нутрициолог</i></u>","type":"paragraph"},{"html":"*Статья подготовлена специалистом исключительно в ознакомительных целях. Мы настоятельно призываем вас не заниматься самолечением и проконсультироваться со своим лечащим специалистом.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqs91u007tuktafmrra1d6"},{"mediaId":"cmrmqs9d0007uuktai6uegw9q"},{"mediaId":"cmrmqs9tz007vukta24hjq1zn"},{"mediaId":"cmrmqsa3d007wuktayyrvfceb"},{"mediaId":"cmrmqsaey007xuktadq20ojly"},{"mediaId":"cmrmqsaqs007yuktac6iz7v0d"},{"mediaId":"cmrmqsavm007zuktapk50r8us"},{"mediaId":"cmrmqsb0o0080uktav7e67whh"}]}]'::jsonb,'cmrmqs8ny007sukta19jqftly','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyun0008kwtasfd55v5y','cmrmpdrom0000sstarkqxwts4','2023-01-17T06:00:00.000Z'::timestamp,NULL,NULL,NULL,589,'/beauty/tendencii/589-vitamin-d3-novye-dannye.html','2026-07-15T20:59:39.770Z'::timestamp,'2026-07-16T13:57:34.560Z'::timestamp,'''-1200'':1237C ''-19'':1005C ''000'':63C,907C,1180C,1189C,1193C,1489C,1585C,1707C,1711C ''1'':1057C,1188C,1488C,1584C ''12'':1186C ''1914'':165C ''1922'':213C ''2'':556C,1179C,1503C,1706C ''20'':62C,162C,320C ''2020'':103C ''2021'':879C ''2727'':494C ''5'':1192C,1710C ''500'':1360C ''7'':501C,1184C ''78'':906C ''800'':1236C ''8а'':1123C ''c'':116C,1447C ''cmrmqs91u007tuktafmrra1d6'':2002C ''cmrmqs9d0007uu