INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqs7gr007mukta6460elob','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Аили: «Не быть музыкантом я не могу»','Творческий путь артиста в России нелегок.','591-aili-ne-byt-muzykantom-ja-ne-mogu','[{"html":"Творческий путь артиста в России нелегок. Мечтания, бессонные ночи, посвященные написанию того самого шедевра, который выстрелит и дни ожиданий твоего звездного часа. Мы решили поговорить с юной певицей Аили, которая уже на своем опыте знает что такое быть музыкантом!","type":"paragraph"},{"html":"<b>Esque: Аили, здравствуй. Расскажи, как ты решила стать певицей. С чего начинался твой творческий путь?</b>","type":"paragraph"},{"html":"<b>Аили:</b> Привет. Вряд ли мне удастся вспомнить момент, когда я приняла это решение. Думаю, оно пришло ко мне еще в неосознанном возрасте. Есть записи, где мне года три, но я уже нежно нажимаю на клавиши фортепиано и пытаюсь что-то напевать. Первую песню я написала в 14 лет. Тогда я, наверное, четко поняла, чего хочу. Но все равно не позволяла себе верить, что такой путь вообще возможен.","type":"paragraph"},{"html":"<b>А что казалось возможным? Кем хотела стать в детстве?</b>","type":"paragraph"},{"html":"<b>Аили: </b>Хотя я всегда мечтала петь, быть музыкантом, я не могла не слышать мнения других: музыка – это хобби, это несерьезно, это не принесет денег, на этом нельзя заработать, это невозможно и так далее. Поэтому периодически у меня появлялись мысли о другой профессии. Например, я очень любила английский в школе, думала стать переводчиком. Кстати, одно из моих высших образований как раз связано с этим делом.","type":"paragraph"},{"html":"<b> Насколько тяжело артисту прорываться на большую сцену? Многие, как известно, сдаются.</b>","type":"paragraph"},{"html":"<b>Аили: </b>Да, тяжело, это правда. Но это мой опыт, мой путь. Он получился нелегким. Но я не хочу, чтобы кто-то прочитал эти строки и подумал: «Ой, там так трудно, я туда не пойду». Но, возможно, у кого-то все сложится быстро и легко. Главное – верить и не сдаваться.","type":"paragraph"},{"html":"<b>У тебя были моменты отчаяния, когда хотелось уйти в другую профессию?</b>","type":"paragraph"},{"html":"<b>Аили: </b>Я не могу не заниматься музыкой. Поэтому в моменты отчаяния она как раз мне нужна еще больше. Да, я параллельно работаю где-то еще, потому что музыка меня не обеспечивает, но, как бы ни было сложно, я думаю так: «Окей, даже если вдруг по каким-то причинам я не смогу быть успешным музыкантом, буду обычным». Но не быть музыкантом я не могу.","type":"paragraph"},{"html":"<b>Аили – это же псевдоним? Расскажи его историю.</b>","type":"paragraph"},{"html":"<b>Аили: </b>Да, псевдоним и по совместительству мое китайское имя. Я полтора года жила в Китае. Поскольку китайцам сложно произносить иностранные слова, они всему дают китайское имя или название. Аили – так назвали там меня. Впоследствии, когда я вернулась в Россию и начала выпускать музыку на разных площадках, я думала: «Так, какой же у меня будет творческий псевдоним?» Думала, наверное, один день. Я настолько привыкла к этому имени, что не было других вариантов – только Аили.","type":"paragraph"},{"html":"<b>Все то, о чем ты поешь, это твой жизненный опыт или вдохновляет что-то другое?</b>","type":"paragraph"},{"html":"<b>Аили: </b>Это мой опыт, то, что происходило со мной или происходит сейчас. О других людях, к сожалению, у меня писать не получается. Я очень надеюсь, что когда-нибудь научусь. Мне бы хотелось уметь писать песню в любой момент, когда мне это нужно, но пока что песни приходят сами тогда, когда я чем-то вдохновлена.","type":"paragraph"},{"html":"<b>На нашем показе мы очень тебя поддерживали. Особенно всем понравился сингл «Не безопасно». А выделяешь ли ты у себя какую-то песню особенно?</b>","type":"paragraph"},{"html":"<b>Аили: </b>Да, меня очень хорошо приняли на показе. Я благодарна за поддержку. Наверное, в разные моменты для меня важны разные песни. Обычно это та песня, над которой я сейчас работаю и готовлю к релизу.","type":"paragraph"},{"html":"<b>Близкие понимают тебя, нет сопротивления твоему выбору в семье?</b>","type":"paragraph"},{"html":"<b>Аили: </b>Да, сестра слушает все мои песни, читает, что мне пишут в комментариях. Мама все ролики пересматривает, отправляет своим подругам все, что со мной связано.","type":"paragraph"},{"html":"<b>Дай пару советов начинающим артистам. С чего нужно начинать и каких ошибок не допускать?</b>","type":"paragraph"},{"html":"<b>Аили: </b>Главное – слушать свое сердце. Есть такая цитата: «Мастер потерпел неудачу больше раз, чем новичок даже попытался». Не нужно бояться ошибаться.","type":"paragraph"},{"html":"<b>Пару слов нашим читателям.</b>","type":"paragraph"},{"html":"<b>Аили: </b>Всем добра и хорошей музыки!","type":"paragraph"},{"html":"<i>Группа Вконтакте: https://vk.com/ailimusic</i>","type":"paragraph"},{"html":"<i>Телеграм-канал АИЛИ: https://t.me/aili_music</i>","type":"paragraph"},{"type":"image","mediaId":"cmrmqs7fu007luktal2hyrwvd"}]'::jsonb,'cmrmqs6xd007kuktaj6rrc2jl','cmrm8kz36000ckwtabqfh3f4h','cmrm8kze2000gkwtad8wkij5y','cmrmpdrom0000sstarkqxwts4','2023-01-30T06:00:00.000Z'::timestamp,NULL,NULL,NULL,591,'/zhizn/music/591-aili-ne-byt-muzykantom-ja-ne-mogu.html','2026-07-15T20:59:35.115Z'::timestamp,'2026-07-16T13:57:31.709Z'::timestamp,'''/aili_music'':713C ''/ailimusic'':703C ''14'':121C ''cmrmqs7fu007luktal2hyrwvd'':719C ''esqu'':56C ''imag'':717C ''paragraph'':54C,72C,143C,155C,222C,236C,290C,304C,372C,382C,458C,477C,536C,563C,600C,612C,640C,657C,681C,688C,697C,705C,715C ''t.me'':712C ''t.me/aili_music'':711C ''vk.com'':702C ''vk.com/ailimusic'':701C ''а'':1A,42C,57C,74C,157C,238C,306C,374C,384C,412C,456C,479C,565C,614C,659C,690C,710C ''английск'':203C ''артист'':10B,16C,226C,646C ''безопасн'':550C ''бесс