INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrmwb005buktacv1h5wyx','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Алена Яковлева: "За мной по-прежнему ухаживают молодые мужчины!"','Глядя на эту стройную изящную красавицу, сложно поверить в то, что народной артистке России Алене Яковлевой в этом году исполнилось 62 года!','617-alena-jakovleva-za-mnoj-po-prezhnemu-uhazhivajut-molodye-muzhchiny','[{"html":"Глядя на эту стройную изящную красавицу, сложно поверить в то, что народной артистке России Алене Яковлевой в этом году исполнилось 62 года! Алена пользуется большим успехом у мужчин, которые готовы и миллион алых роз подарить, и серенады под окном спеть, и в ЗАГС сводить.","type":"paragraph"},{"html":"\"Когда мне оказывают знаки внимания молодые мужчины - причем иногда очень настойчиво - я им говорю: \"Ты знаешь, сколько мне лет?\", - смеется Алена. - А они в ответ говорят, что им это совершенно неважно! Врут, наверное!» (Смеется)","type":"paragraph"},{"html":"Чтобы плодотворно работать, время от времени нужно давать себе несколько дней отдыха, считает актриса. Перезагрузиться, так сказать. Поэтому, между премьерой спектакля \"Дядюшкин сон\", съемками в сериале телеканала Россия и репетициями нового спектакля \"Скамейка\" Алена отправилась на отдых в горы, на курорт \"Роза Хутор\".","type":"paragraph"},{"html":"\"Меня часто просят рассказать мои секреты красоты, - делится актриса.","type":"paragraph"},{"html":"- Конечно, как у любой женщины, у меня есть свои программы ухода за телом и лицом.","type":"paragraph"},{"html":"Во-первых, я каждое утро протираю лицо и шею кубиками льда из трав.","type":"paragraph"},{"html":"Во-вторых, я пользуюсь жирными кремами для увлажнения кожи - моя мама всю жизнь наносила на лицо и шею крем \"Янтарь\" и выглядела великолепно! Кстати, моя коллега по театру Ольга Аросева дома наносила на лицо оливковое масло и таким образом увлажняла кожу. Сейчас огромное количество различных кремов, поэтому к таким методам можно и не прибегать, хотя маски для лица, сделанные из натуральных продуктов - самые лучшие!","type":"paragraph"},{"html":"Я, например, до сих пор очень люблю маску из овсяных хлопьев с яйцом и молоком - она обладает прекрасным натуральным лифтинг- эффектом! Говоря об уходе за телом, я очень люблю массажи и делаю их часто.","type":"paragraph"},{"html":"Еще я на регулярной основе принимаю грязевые ванны - они тонизируют и увлажняют кожу, а также помогают снять боль в суставах, если таковые имеются. Ну и самое главное, это физические нагрузки. Поскольку я в детстве часто болела ангиной, да и сейчас подвержена простудным заболеваниям, особо заниматься спортом не могу. Поэтому сейчас хожу на ЛФК или просто совершаю пешие прогулки. Да и 3 часа на сцене - это тоже большая физическая нагрузка.","type":"paragraph"},{"html":"На Роза Хутор я старалась ходить пешком как можно больше - прошла по большому маршруту парка водопадов Менделиха, с удовольствием гуляла в Роза Долине...","type":"paragraph"},{"html":"Вообще, этот мой мини-отпуск был очень насыщенным: я и в откры","type":"paragraph"},{"html":"том горном бассейне плавала, и на родельбане впервые в жизни прокатилась. Практически каждый день ходила в СПА на массаж... Но самым ярким стал день, во время которого я побывала в парке альпак \"Пача Мама\" (там, помимо альпак, есть еще кролики, козы и баран), на \"Хаски Хутор\", где проживают 62 собаки пород хаски, маломуты и самоеды; на этно-хуторе \"Шишин двор\", где живут козы и даже на «Оленьей ферме»...","type":"paragraph"},{"html":"Все животные ухожены, сыты и довольны жизнью. А самое главное, что у многих из них вскоре ожидается пополнение. От них шла такая хорошая, такая добрая энергия, которая меня наполнила позитивом. А ведь радость и счастье также являются составляющими хорошего внешнего вида!\"","type":"paragraph"},{"html":"<i>Текст: Марина Сальникова</i>","type":"paragraph"},{"html":"<i>Фото: Игорь Харитонов</i>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqrm310058uktakyv07lhw"},{"mediaId":"cmrmqrmil0059uktaxdk8q5xx"},{"mediaId":"cmrmqrmv2005auktafdwficpi"}]}]'::jsonb,'cmrmqrloe0057uktau9uqigre','cmrm8kzli000ikwtafbw33jnj','cmrm8kzoi000kkwtachb0mt9u','cmrmpdrom0000sstarkqxwts4','2023-10-09T06:00:00.000Z'::timestamp,NULL,NULL,NULL,617,'/persona/dostizhenija/617-alena-jakovleva-za-mnoj-po-prezhnemu-uhazhivajut-molodye-muzhchiny.html','2026-07-15T20:59:08.459Z'::timestamp,'2026-07-16T13:57:09.681Z'::timestamp,'''3'':375C ''62'':31B,53C,477C ''cmrmqrm310058uktakyv07lhw'':559C ''cmrmqrmil0059uktaxdk8q5xx'':561C ''cmrmqrmv2005auktafdwficpi'':563C ''galleri'':557C ''paragraph'':78C,115C,161C,173C,191C,208C,276C,313C,385C,411C,427C,499C,543C,549C,555C ''актрис'':130C,171C ''ал'':1A,55C,65C,100C,150C ''ален'':25B,47C ''альпак'':460C,465C ''ангин'':351C ''аросев'':240C ''артистк'':23B,45C ''бара'':471C ''бассейн'':431C ''бол'':332C ''болел'':350C ''больш'':57C,381C,399C ''ван'':322C ''великолепн'':233C ''вид'':541C ''внешн'':540C ''вниман'':84C ''во-втор'':210C ''во-перв'':193C ''водопад'':402C ''вообщ'':413C ''вперв'':436C ''врем'':120C,454C ''времен'':122C ''врут'':111C ''вскор'':516C ''втор'':212C ''выглядел'':232C ''главн'':341C,510C ''гляд'':11B,33C ''говор'':93C,105C,299C ''год'':29B,32B,51C,54C ''гор'':155C ''горн'':430C ''готов'':62C ''грязев'':321C ''гуля'':406C ''дава'':124C ''двор'':489C ''дел'':170C ''дела'':309C ''ден'':442C,452C ''детств'':348C ''дне'':127C ''добр'':525C ''довольн'':506C ''долин'':409C ''дом'':241C ''дядюшкин'':138C ''женщин'':179C ''животн'':502C ''живут'':491C ''жизн'':223C,438C,507C ''жирн'':215C ''заболеван'':357C ''загс'':75C ''занима'':359C ''знаеш'':95C ''знак'':83C ''игор'':552C ''изящн'':15B,37C ''имеют'':337C ''исполн'':30B,52C ''кажд'':197C,441C ''кож'':219C,251C,327C ''коз'':469C,492C ''количеств