INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqet610040potab68mxitb','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Чиним или расстаемся?','Порой мы годами уничтожаем себя, живя в несчастливых отношений.','655-chinim-ili-rasstaemsja','[{"html":"Порой мы годами уничтожаем себя, живя в несчастливых отношений. Причин тому множество: боязнь уйти, страх одиночества, реакция общества! Кажется, что выхода нет, но этот замкнутый круг рисуем мы сами и сами лишаем себя выхода из него!","type":"paragraph"},{"html":"В этой серии интервью мы пообщались не только с психологами, но и с девушками, которые на собственном опыте знают, что такое боль и предательство! Если вы сейчас на перепутье и не знаете что делать, этот выпуск для вас! Это сигнал к действию!","type":"paragraph"},{"html":"<u><i>Благодарим наших героинь: </i></u>","type":"paragraph"},{"html":"Инна Ермакова – психолог, семейный терапевт","type":"paragraph"},{"html":"Алена Любимова – клинический психолог, полимодальный психотерапевт","type":"paragraph"},{"html":"Алена Лобанова – интегративный психолог","type":"paragraph"},{"html":"Елена Нагельман – психолог-консультант, клинический психолог, семейный психотерпевт","type":"paragraph"},{"html":"Романова Юлия – директор салона красоты. <i>Рассказывает свою историю знакомства с мужчиной в интернете </i>","type":"paragraph"},{"html":"Ольшанская Алёна – дизайнер интерьера, видеооператор. <i>Вышла замуж за абьюзера</i>","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/jWraBxa4Acg?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" referrerpolicy=\"strict-origin-when-cross-origin\" allowfullscreen=\"\" title=\"Чиним или расстаемся?\"></iframe>","type":"embed"}]'::jsonb,'cmrmqet4o003zpotaagwsyong','cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2024-04-30T06:00:00.000Z'::timestamp,NULL,NULL,NULL,655,'/psihologija/intervju-2/655-chinim-ili-rasstaemsja.html','2026-07-15T20:49:10.057Z'::timestamp,'2026-07-16T13:56:50.363Z'::timestamp,'''emb'':167C ''paragraph'':50C,95C,101C,109C,118C,125C,137C,153C,165C ''абьюзер'':163C ''ал'':111C,120C,156C ''благодар'':97C ''бол'':73C ''боязн'':25C ''видеооператор'':159C ''выпуск'':87C ''выход'':33C,46C ''вышл'':160C ''героин'':99C ''год'':6B,15C ''девушк'':65C ''действ'':93C ''дела'':85C ''дизайнер'':157C ''директор'':141C ''ел'':127C ''ермаков'':104C ''жив'':9B,18C ''замкнут'':37C ''замуж'':161C ''знает'':83C ''знакомств'':147C ''знают'':70C ''ин'':103C ''интегративн'':122C ''интерв'':55C ''интернет'':151C ''интерьер'':158C ''истор'':146C ''кажет'':31C ''клиническ'':113C,132C ''консультант'':131C ''котор'':66C ''красот'':143C ''круг'':38C ''лиша'':44C ''лобанов'':121C ''любимов'':112C ''множеств'':24C ''мужчин'':149C ''нагельма'':128C ''наш'':98C ''несчастлив'':11B,20C ''обществ'':30C ''одиночеств'':28C ''ольшанск'':155C ''опыт'':69C ''отношен'':12B,21C ''перепут'':80C ''полимодальн'':115C ''пообща'':57C ''пор'':4B,13C ''предательств'':75C ''причин'':22C ''психолог'':61C,105C,114C,123C,130C,133C ''психолог-консультант'':129C ''психотерапевт'':116C ''психотерпевт'':135C ''рассказыва'':144C ''расста'':3A ''реакц'':29C ''рису'':39C ''романов'':139C ''салон'':142C ''сам'':41C,43C ''семейн'':106C,134C ''сер'':54C ''сигна'':91C ''собствен'':68C ''страх'':27C ''так'':72C ''терапевт'':107C ''том'':23C ''уйт'':26C ''уничтожа'':7B,16C ''чин'':1A ''эт'':90C ''юл'':140C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","ru