INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqebd0001xpotaks7ep6vs','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'В аэропорту Франции задержан Павел Дуров','Сегодня вечером Павел Дуров был задержан в аэропорту Франции.','679-v-ajeroportu-francii-zaderzhan-pavel-durov','[{"html":"Сегодня вечером в аэропорту Франции при выходе из своего частного самолета был задержан Павел Дуров. Операцию провела жандармерия воздушного транспорта.","type":"paragraph"},{"html":"39-летний бизнесмен прибыл из Азербайджана. Его сопровождали телохранитель и женщина.","type":"paragraph"},{"html":"По информации французского телеканала TF1 Дуров был объявлен в федеральный розыск. Детали задержания не уточняются. По информации СМИ создатель телеграмм не сотрудничал с французскими силовиками. Ему вменяют обвинение сразу по нескольким тяжким статьям: терроризм, отмывание денег, наркотики, мошенничество, педофильный контент. Бизнесмену грозит до 20 лет лишения свободы.","type":"paragraph"},{"html":"Основная претензия властей EC к Telegram - зашифрованные сообщения\", пишет TF1.","type":"paragraph"},{"html":"00:23","type":"paragraph"},{"html":"Задержание Павла Дурова подтвердило еще одно французском CМИ BFMTV. Издание пишет, что бизнесмен знал о выдаче ордера и не посещал Францию и Европу. Все это время он находился чаще всего в Арабских Эмиратах, Южной Америке и странах бывшего СССР. Учитывая все детали, его прибытие в Ле Бурже (аэропорт Франции) кажется очень странным. По неподтвержденным данным, частный борт остановился в Париже для дозаправки.","type":"paragraph"},{"html":"2:47","type":"paragraph"},{"html":"Уже вечером состоится суд над предпринимателем.","type":"paragraph"},{"html":"После ареста курс его криптовалюты сразу рухнул, а будущее Telegram под большим вопросом. Согласно заявлению MASH, у сотрудников телеги разработан целый план на случай ареста его основателя","type":"paragraph"},{"html":"Пока Павел Дуров находится под стражей всего несколько часов, а в его поддержку выступают российские депутаты и певцы. Админы зарубежных каналов постят значок с иконкой телеги в его поддержку.","type":"paragraph"},{"html":"11:48","type":"paragraph"},{"html":"Посольство России во Франции потребовало предоставить доступ к консулу и обеспечить защиту прав Дурова.","type":"paragraph"},{"html":"Французская сторона от взаимодействия не уклоняется.","type":"paragraph"},{"html":"14:01","type":"paragraph"},{"html":"Прокуратуру Франции просят освободить Павла Дурова. Местонахождение предпринимателя неизвестно. У российского посольства доступа к нему нет. МИД до сих пор не в курсе, где бизнесмен и в каком он состоянии. Французская сторона не реагирует на запрос.","type":"paragraph"},{"html":"19:23","type":"paragraph"},{"html":"К посольству Франции продолжают приходить люди, поддерживающие Павла Дурова. Некоторые из них приходят с его фотографией, некоторые с плакатами. Свое неравнодушие люди объясняют просто: \"Телеграмм - это единственная площадка, где мы можем не бояться блокировок\".","type":"paragraph"},{"html":"22:14","type":"paragraph"},{"html":"Появился первый официальный пост от Telegram. Краткая суть заявления: Мы соблюдаем законы! Ситуация абсурдна! Ждем ее скорейшего разрешения.","type":"paragraph"},{"html":"01:15","type":"paragraph"},{"html":"Срок задержания Павла Дурова под стражей продлили на 48 часов.","type":"paragraph"}]'::jsonb,'cmrmqebbl001wpotasu5ugst9','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-08-24T06:00:00.000Z'::timestamp,NULL,NULL,NULL,679,'/v-mire/679-v-ajeroportu-francii-zaderzhan-pavel-durov.html','2026-07-15T20:48:46.980Z'::timestamp,'2026-07-16T13:56:26.511Z'::timestamp,'''00'':116C ''01'':294C,405C ''11'':262C ''14'':293C,380C ''15'':406C ''19'':337C ''2'':186C ''20'':96C ''22'':379C ''23'':117C,338C ''39'':