INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrjyt004zukta6hr0nwtm','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Fashion bitva, финал сезона: тут творят моду','19 ноября в концертном зале «Мир» на Цветном бульваре состоится одно из самых долгожданных событий модной индустрии страны — финал 11 сезона конкурса Fashion bitva.','621-fashion-bitva-final-sezona-tut-tvorjat-modu','[{"html":"<b>19 ноября в концертном зале «Мир» на Цветном бульваре состоится одно из самых долгожданных событий модной индустрии страны — финал 11 сезона конкурса Fashion bitva. Одиннадцатый раз дизайнеры России вступят в борьбу за звание лучшего из лучших.</b><br /><b>В Битве примут участие более двадцати российских модельеров: как победители региональных этапов 2023 года, так и дизайнеры, прошедшие строгий онлайн-отбор.</b>","type":"paragraph"},{"html":"<i>Это будет действительно сильнейшая Битва, ведь ставки невероятно высоки: победитель конкурса получит полностью оплачиваемую поездку в Китай на Russian Fashion Display — культовый показ российских дизайнеров, который в этот раз пройдет 3 марта 2024 года в Даляне.</i><br /><i>«Нас ждет супер-шоу! Мы с трепетом и волнением готовимся к этому событию и с нетерпением ждем 19 ноября. В этом году очень много сильных дизайнеров, каждый из которых расскажет свою особенную историю и представит свой край. Ведь в каждом уголке России мода у нас абсолютно разная», — делится впечатлениями от подготовки к мероприятию создатель и бессменный идейный вдохновитель проекта Fashion bitva Алена Балагурова.</i>","type":"paragraph"},{"html":"<br />Ежегодно повышается уровень организации мероприятия. Подбираются лучшие площадки, придумываются оригинальные концепции. Так, чуть меньше года назад под девизом «Мода будущего» показ коллекций в Казани состоялся на… шахматной доске. Динара Шакирова, победитель той самой Битвы, представит в финале новую капсульную коллекцию своего бренда “Di Shakir-a”. <br />«Я с детства мечтала стать дизайнером. Мода для меня, без преувеличений, — это жизнь! В финал Fashion битвы я попала с коллекцией одежды-трансформер на тему \"Мода будущего 2032\". Новые изделия, которые я презентую 19 ноября в Москве, тоже будут с изюминкой. Я пытаюсь повлиять на то, чтобы мода была не только для подиума, но и для жизни. Участие в Fashion bitva — это возможность для дизайнеров громко заявить о себе, своей философии в моде и познать свои новые грани».","type":"paragraph"},{"html":"<br />Fashion bitva — это место, где встречаются инновации и классика. Возможно, вы помните культовое «Брюки превращаются… брюки превращаются…. в модные шорты». В этом ноябре цитата советской классики кинематографа получит новое звучание. Победитель регионального этапа Иркутска Елена Вахрушева отправится на финал Битвы с новой коллекцией собственного бренда VMESTE MISHA. <br />«Бренд одежды VMESTE MISHA — это моя, пока еще, небольшая история о том, что мечты сбываются. Тут курка может превратиться в жилетку, а жилетка бывает сразу и голубой, и розовой. Ярко-малиновый бомбер внутри может оказаться белым. А футболка — это еще и платье. Каждый дизайнер — творец и артист. Свои ценности мы показываем через одежду. Участие в Fashion битве — это топливо, а победа — это турбо топливо, настоящий космос для дальнейших действий!»","type":"paragraph"},{"html":"<br />Для модной битвы нет границ. Испытать свои силы тут может каждый. Дизайнер Раиса Мирошниченко, основатель бренда Lina_malina_fashion_kidss, пришла потягаться с сильнейшими модной индустрии, не имея профильного образования. Все свои изделия она отшивает исключительно вручную при помощи лишь только иглы и нити, не используя швейной машины. В финале 19 ноября Раиса представит яркую и эпатажную детскую коллекцию «Феерия».","type":"paragraph"},{"html":"<br /><i>«Рецепт появления каждого моего платья — это союз вдохновения и любви. Каждое мое платье — это эксклюзив, рожденный в моем воображении и созданный моими руками и вдохновением, который никто не сможет повторить. Участие в проекте Fashion Bitva для меня — это возможность проверить свои силы в конкурентной борьбе с профессиональными дизайнерами. А победа в проекте — это победа над самой собой и сложившимися стереотипами».</i>","type":"paragraph"},{"html":"<br />Традиционно модели и дизайнеры собираются на конкурс со всех уголков страны: от юга до Дальнего Востока. Ольга Соловьева, победитель регионального этапа Екатеринбурга, представит свой бренд интеллектуального вязаного трикотажа SO Love. Вдохновение для своих конкурсных работ Ольга нашла на Дальнем Востоке.","type":"paragraph"},{"html":"<br /><i>«Проживая на Дальнем Востоке, я просто влюбилась в дерево гинкго билоба. Я создала авторский принт его листа и перенесла на свои вязанные изделия. За новой порцией вдохновения для финала я снова вернулась во Владивосток. На этот раз я нашла эликсир молодости и женского долголетия — женьшень. Я являюсь постоянным участником различных конкурсов, модных fashion-показов и мероприятий. Но участие в проекте Fashion Bitva для меня особенно волнительно! Это не просто показ. Здесь раскрывается душа дизайнера».</i>","type":"paragraph"},{"html":"Вот уже семь лет Fashion bitva исполняет мечты и взращивает новые таланты российской моды. Дизайнер Елена Гузева оказалась в финале Битвы, пройдя жесткий онлайн-отбор. Ее бренд Elena Belle призывает, чтобы девушки не боялись проявлять себя и транслирует, что быть яркой, легкой и красивой можно в любом возрасте.","type":"paragraph"},{"html":"<br />«Для меня само участие в проекте Fashion bitva — это уже победа. Большой концертный зал «Мир», мои модели на подиуме, я — на сцене с микрофоном в руках пою свои авторские песни во время показа своей же коллекции. Просто голова кругом! Для меня это сказка, ставшая реальностью. Моя коллекция создана для творческих и уверенных в себе девушек, которые любят быть в центре внимания: как на сцене, так и в жизни. Не нужно прятаться в темные цвета и мешковатые силуэты. Красивую фигуру нужно подчеркивать, а цвет должен радовать глаз и дарить настроение».","type":"paragraph"},{"html":"<br />Каждый участник подготовил эксклюзивную коллекцию, которая несет не только красоту, но и определенный философский посыл. Ведь Fashion bitva — это не только конкурс, но и площадка для диалога профессионалов отрасли. Галина Спирина примет участие в финале Fashion битвы с коллекцией «Индивидуальность» своего бренда GS collection. Главной фишкой дизайнера является внедрение подиумных изделий в повседневную жизнь. Высокое качество и доступность — вот главные тезисы идеи коллекции.","type":"paragraph"},{"html":"<br /><u>«Когда я была моделью, то обратила внимание, что на подиуме практически не было изделий, связанных вручную: свитеров, шапок, шарфов. Так и возникла идея создания собственной коллекции. Мои ценности, как дизайнера — это комфорт, здоровье и экологичность. Каждый человек — это индивидуальность. А мы, специалисты по моде и красоте, стараемся помочь ему это подчеркнуть. Я — в том числе. Ведь все люди, как и мои изделия — в единственном экземпляре».</u>","type":"paragraph"},{"html":"<br />Культовый конкурс дизайнерского искусства Fashion bitva существует в России с 2016 года. Одиннадцать сезонов, десятки городов, несколько стран и сотни дизайнеров — вот она, история проекта в цифрах. Но главной его ценностью являются, конечно же, талантливые люди, идеи и неиссякаемое вдохновение, которое является постоянным спутником как организаторов, так и участников.","type":"paragraph"}]'::jsonb,'cmrmqrjx5004yuktabqyyx5kj','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2023-11-05T06:00:00.000Z'::timestamp,NULL,NULL,NULL,621,'/projects-esque/fashion-bitva/621-fashion-bitva-final-sezona-tut-tvorjat-modu.html','2026-07-15T20:59:04.661Z'::timestamp,'2026-07-16T13:57:07.058Z'::timestamp,'''11'':27B,51C ''19''