ED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqevp0004bpota0jtdt0sz','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Выбраны победители юбилейного сезона PROfashion Masters','21 февраля 2024 на подиуме крупнейшей индустриальной выставки Collection Premiere Moscow состоялся финальный гала-показ X Всероссийского конкурса дизайнеров одежды PROfashion Masters.','650-vybrany-pobediteli-jubilejnogo-sezona-profashion-masters','[{"html":"21 февраля 2024 на подиуме крупнейшей индустриальной выставки Collection Premiere Moscow состоялся финальный гала-показ X Всероссийского конкурса дизайнеров одежды PROfashion Masters. Судейская коллегия отметила высокий уровень работ и серьезный рост проекта в юбилейном сезоне. Тема конкурса осталась неизменной — создание коллекции верхней одежды.","type":"paragraph"},{"html":"<br />В новом сезоне организаторы получили около 400 заявок от молодых дизайнеров из России, Китая и Беларуси. В честь юбилея конкурса впервые было принято решение провести полуфинал конкурса в формате выставки-презентации коллекций участников. В полуфинал вышли 21 дизайнер и дизайнерский коллектив, которые бесплатно получили пальтовые ткани от компании «Ткани Престиж», курточные материалы, базовые комплекты лекал и консультацию по моделированию от конструкторского бюро GRASSER, инновационный утеплитель от производителя «C2ГРУПП» и возможность печати авторского принта от компанииSaliteks. Участники впервые представили широкой<br />публике 105 курточных и пальтовых изделий на выставке в МОК «Смоленский пассаж-2». С 12 по 18 февраля мероприятие посетили члены жюри, которые выбрали 11 дизайнеров, вышедших в финал, и гости торгового центра, которые примеряли, фотографировались и оформляли предзаказы на понравившиеся модели.","type":"paragraph"},{"html":"По итогам голосования судейской коллегии в финал конкурса прошли: Иван Бутырский (Москва), Ксения Духанова (Ульяновск), Виктория Куценко (Ростов-на-Дону), Инна Гриор (Москва), Виктория Павлова (Иваново), Тамила Серова (Москва), Ульяна Васенкова (Краснодар), Анастасия Гордеенкова и Ирина Цветнова (Москва), Софья Соловьева (Москва). В числе финалистов оказались Антон Мажарин (Витебск) и Никита Баранов (Екатеринбург), которые второй сезон подряд участвуют в конкурсном гала- показе и задают высокую планку портновского мастерства.","type":"paragraph"},{"html":"<br />Глава представительства компании «Ткани Престиж» и почетный член жюри конкурса Хулки Оз отметил эффектность юбилейного показа и выразил надежду на дальнейшее развитие конкурса, а генеральный директор медиахолдинга PROfashion Олеся Орлова выделила интересный тренд последних сезонов — преобладание мужских образов на подиуме: «Образ российского мужчины во всемирном сообществе — брутальный и консервативный. То, что представляют наши молодые дизайнеры, очень красиво и действительно носибельно».","type":"paragraph"},{"html":"<br />Главный приз в номинации «Лучшая творческая коллекция» в размере 150 000 рублей был присужден финалисту из Москвы Ивану Бутырскому. Члены жюри отдельно подчеркнули мастерскую работу дизайнера над конструкцией изделий. Второй приз в размере 150 000 рублей в номинации «Лучшая коммерческая коллекция» получил творческий коллектив из Москвы — Ирина Цветнова и Анастасия Гордеенкова. Девушки также были награждены премией в 70 000 рублей от компании «С2ГРУПП» за лучшую работу с инновационным утеплителем «Атмо».Приз зрительских симпатий также достался Ивану Бутырскому, а специальный приз от редакции PROfashion получил Антон Мажарин из Витебска.","type":"paragraph"},{"type":"image","mediaId":"cmrmqevnq004apotaqj1tjzy8"}]'::jsonb,'cmrmqevea0049potajp9b378o','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2024-03-12T06:00:00.000Z'::timestamp,NULL,NULL,NULL,650,'/fashion/news-2/