INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsdrs0085uktaoxg325ig','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Анна Тури: "Косметическое аргановое масло одно из самых ценных в мире!"','Несколько лет назад, побывав в Марокко, Анна Тури влюбилась в эту страну.','588-anna-turi-kosmeticheskoe-arganovoe-maslo-odno-iz-samyh-cennyh-v-mire','[{"html":"<i>Несколько лет назад, побывав в Марокко, Анна Тури влюбилась в эту страну. А познакомившись с аргановым маслом, вместе с мужем марокканцем открыла магазин косметики под названием «Argania du maroc» в России. Мы решили побеседовать лично и узнать какими волшебными свойствами обладает натуральная косметика из арганового масла и насколько сложно, живя в России, иметь производство в Марокко. Оказалось, все просто, когда занимаешься любимым делом!</i>","type":"paragraph"},{"html":"<strong>Esque:</strong> Анна, здравствуйте. Расскажите, как пришла идея создания магазина косметики с применением арганового масла.","type":"paragraph"},{"html":"<strong>Анна:</strong> Здравствуйте. Мой муж марокканец. Как известно, аргановое масло производится только в Марокко. Приехав первый раз в эту страну, и попробовав 100% натуральное БИО аргановое масло, я поняла, что это поистине удивительный продукт. Мне захотелось, чтобы, как можно больше людей узнали о нем и начали пользоваться. Так пришла идея создания магазина.","type":"paragraph"},{"html":"<strong>Esque:</strong> В состав каждого продукта вашего бренда входит аргановое масло?","type":"paragraph"},{"html":"<strong>Анна:</strong> В нашем ассортименте есть чистое, 100% натуральное БИО аргановое масло - косметическое и пищевое, а также другие БИО продукты: косметическая глина гассул, гидролат дамасской розы, масло семян кактуса опунции, чёрное мыло-скраб Бельди и всеми известная рукавица для пилинга Кесса.","type":"paragraph"},{"html":"<strong>Esque:</strong> Расскажите чуть подробнее о каждом средстве бренда.","type":"paragraph"},{"html":"<b>Анна:</b>","type":"paragraph"},{"html":"- 100% натуральное аргановое масло БИО, которое способно быстро и качественно восстановить даже самые поврежденные волосы, предотвращает появление морщин и старение кожи, а также разглаживает морщинки.","type":"paragraph"},{"html":"- 100% натуральное масло семян кактуса опунции БИО - является номер один в мире по борьбе с морщинами и признано настоящим эликсиром молодости. Оно способно не только предотвратить появление морщин, но и разгладить самые глубокие.","type":"paragraph"},{"html":"- 100% натуральная Косметическая глина Гассул БИО - отшелушивает омертвевшие клетки кожи, глубоко очищает и сужает поры, смягчает кожу, борется с высыпаниями, устраняет жирный блеск и излишки кожного сала.","type":"paragraph"},{"html":"- розовая вода (гидролат дамасской розы) 100% натуральный БИО продукт. Она идеально подходит для очищения лица и тела в качестве тоника. Восстанавливает волосы и предотвращает появление секущихся кончиков.","type":"paragraph"},{"html":"-100% натуральный БИО продукт - чёрное мыло-скраб Бельди и рукавица Кесса. Это крутая процедура гоммажа и марокканский хаммам у вас дома. Настоящий ритуал красоты и чистоты восточных красавиц.","type":"paragraph"},{"html":"<strong>Esque:</strong> Аргановое масло, как мы уже поняла, производится в Марокко. Где находится ваше производство?","type":"paragraph"},{"html":"<strong>Анна:</strong> Да, аргановое масло производится ТОЛЬКО в Марокко, так как деревья аргании растут только в этой стране и вывозить плоды запрещено на законодательном уровне. Наше производство находится в прекрасном городе Агадир.","type":"paragraph"},{"html":"<strong>Esque:</strong> Сложно было подбирать команду? Особенно на расстоянии?","type":"paragraph"},{"html":"<strong>Анна:</strong> Нет, как ни странно, оказалось очень просто. В нашей команде: марокканцы в Марокко и русские в России, а мы с мужем между двух стран. Это наше любимое дело, наверное, поэтому любые трудности мы встречаем с улыбкой и двигаемся дальше.","type":"paragraph"},{"html":"<strong> Esque:</strong> А как осуществляется поставка?","type":"paragraph"},{"html":"<strong>Анна:</strong> У нас есть все разрешающие документы на импорт. Мы являемся официальным дистрибьютором в России. Доставка в РФ из Марокко осуществляется при помощи транспортной компании.","type":"paragraph"},{"html":"<strong>Esque:</strong> Расскажите читателям, о плюсах арганового масла. В чем его отличительная особенность?","type":"paragraph"},{"html":"<strong>Анна:</strong> Косметическое аргановое масло одно из самых ценных в мире! В чем секрет? В составе этого уникального средства большое количество веществ отвечающих за молодость:","type":"paragraph"},{"html":"▪ высокое содержание витамина E, которого в 3 раза больше, чем в оливковом масле;","type":"paragraph"},{"html":"▪ жирные кислоты: омега-9 до 60% (олеиновая), омега-6 около 30% (линолевая), пальмитиновая — около 16%, стеариновая около 8%","type":"paragraph"},{"html":"▪ феруловая кислота;","type":"paragraph"},{"html":"▪ полифенолы;","type":"paragraph"},{"html":"▪ фитостеролы;","type":"paragraph"},{"html":"▪ и мощный антиоксидант - сквален.","type":"paragraph"},{"html":"Именно поэтому оно питает, смягчает, усиливает обменные и регенерационные процессы кожных покровов, борется со старением кожи, уменьшает глубину морщин, а мимические и неглубокие морщины полностью разглаживает, подтягивает контур лица, восстанавливает сияние тусклых, безжизненных, ломких, сухих волос, препятствует выпадению, способствует росту волос;","type":"paragraph"},{"html":"Отличается оно от других косметических масел тем, что имеет легкую текстуру, очень хорошо и быстро впитывается и комфортное для кожи.","type":"paragraph"},{"html":"Его можно использовать вместо крема, сыворотки до крема, основы под макияж, маски для лица.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Для каких типов кожи подходит ваша косметика?","type":"paragraph"},{"html":"<strong>Анна:</strong> Один из самых частых вопросов наших клиентов: «Можно ли использовать аргановое и масло семян кактуса опунции для жирной кожи?»","type":"paragraph"},{"html":"Нужно. Сейчас объясню почему.","type":"paragraph"},{"html":"Начнем с того, что зачастую обладатели жирной кожи хотят ее обезжирить. Согласны? Но в этот момент кожа лишь начинает вырабатывать больше жира, появляются прыщи и черные точки и кожа начинает шелушиться.","type":"paragraph"},{"html":"Так делать ненужно.","type":"paragraph"},{"html":"Аргановое и масло семян кактуса опунции — это жир максимально приближенный к нашему натуральному, поэтому когда мы используем эти масла для жирной кожи, то кожа постепенно успокаивается и выдает меньше жирного блеска. Это называется балансировка выработки себума. То есть чтобы уменьшить жирность кожи, нам нужно ее не обезжиривать, а добавлять жир максимально похожий на ее собственный.","type":"paragraph"},{"html":"А как же для сухой кожи? Спросите вы.","type":"paragraph"},{"html":"Все также, просто наносите аргановое и масло семян кактуса опунции и кожа питается необходимыми элементами и становится более увлажненной.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Где можно приобрести продукцию бренда?","type":"paragraph"},{"html":"<strong>Анна:</strong> Наш бренд «Argania du Maroc» - это качественная БИО косметика марокканского производителя. Наша продукция представлена на витрине известных маркетплейсов: озон и вайлдберис. Найти нашу линейку можно по названию в поисковой строке: argania du maroc.","type":"paragraph"},{"html":"Также познакомиться поближе и приобрести наши уникальные БИО продукты можно на нашем официальном сайте: argana-maslo.ru.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Анна, спасибо за подробный рассказ об аргановом масле. И напоследок, пару слов нашим читателям.","type":"paragraph"},{"html":"<strong>Анна:</strong> Дорогие читатели журнала Esque! Мы от всей души желаем вам успехов во всех начинаниях, а мы будем продолжать радовать, восхищать и удивлять вас нашей линейкой БИО продуктов!","type":"paragraph"},{"type":"image","mediaId":"cmrmqsdqt0084ukta767phnzc"}]'::jsonb,'cmrmqscng0083uktaj08ew0sb','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyz0000akwtaq6w9733r','cmrmpdrom0000sstarkqxwts4','2023-01-12T06:00:00.000Z'::timestamp,NULL,NULL,NULL,588,'/beauty/mnenie/588-anna-turi-kosmeticheskoe-arganovoe-maslo-odno-iz-samyh-cennyh-v-mire.html','2026-07-15T20:59:43.288Z'::timestamp,'2026-07-16T13:57:35.075Z'::timestamp,'''-100'':357C ''-6'':596C ''-9'':591C ''100'':128C,180C,233C,261C,297C,332C ''16'':602C ''3'':578C ''30'':598C ''60'':593C ''8'':605C ''argana-maslo.ru'':945C ''argania'':50C,897C,925C ''cmrmqsdqt0084ukta767phnzc'':1000C ''du'':51C,898C,926C ''e'':575C ''esqu'':90C,161C,218C,389C,440C,494C,530C,713C,885C,949C,971C ''imag'':998C ''maroc'':52C,899C,927C ''paragraph'':88C,105C,159C,172C,216C,227C,231C,259C,295C,325C,355C,387C,404C,438C,449C,492C,500C,528C,543C,570C,586C,607C,612C,616C,620C,627C,671C,694C,711C,722C,745C,752C,786C,792C,850C,861C,883C,892C,929C,947C,965C,996C ''агадир'':436C ''ан'':1A,18B,30C,91C,107C,174C,229C,406C,451C,502C,545C,724C,894C,950C,967C ''антиоксидант'':624C ''арган'':417C ''арганов'':4A,39C,68C,102C,114C,131C,169C,183C,235C,390C,408C,535C,547C,735C,794C,867C,956C ''ассортимент'':177C ''балансировк'':827C ''безжизнен'':661C ''бельд'':207C,365C ''би'':130C,182C,191C,237C,267C,302C,334C,359C,902C,938C,993C ''блеск'':319C,824C ''больш'':563C ''борет'':314C,641C ''борьб'':274C ''бренд'':167C,225C,890C,896C ''буд'':984C ''быстр'':240C,687C ''вайлдберис'':915C ''ваш'':166C,401C,719C ''веществ'':565C ''витамин'':574C ''витрин'':910C ''влюб'':20B,32C ''вмест'':41C,699C ''вод'':328C ''волос'':247C,348C,664C,669C ''волшебн'':62C ''вопрос'':729C ''восстанавлива'':347C,658C ''восстанов'':243C ''восточн'':384C '