C,512C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqtc7k00c8uktals6bp47o','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Ушедшая в закат волна Годара','Что, зачем и как смотреть французского режиссера Жан-Люка Годара.','545-ushedshaja-v-zakat-volna-godara','[{"html":"<strong>Что, зачем и как смотреть французского режиссера Жан-Люка Годара. </strong>","type":"paragraph"},{"html":"<strong>13 сентября 2022 года в своем доме в кругу семьи умер французский кинематографист Жан-Люк Годар. Режиссеру был 91 год. Он серьезно не болел, но со словами “я устал” ушел из жизни путем эвтаназии. Даже эта шокирующая “деталь” смерти Годара подтверждает принцип его жизни вопреки всем традициям и устоям. Чем же так знаменит и важен для мира искусства этот взбалмошный режиссер?</strong>","type":"paragraph"},{"html":"<b>МАЛОБЮДЖЕТНЫЙ ДЕБЮТ В БОЛЬШОМ КИНО</b>","type":"paragraph"},{"html":"В первую очередь, вместе с началом творчества Годара в 1960-е родилась «Новая волна» во французском кино. Под лозунгом «в фильме должны быть начало, середина и конец, но необязательно в таком порядке» режиссер стал снимать другое кино. Он первый, кто начал использовать рваный монтаж, съемку ручной камерой и постоянные оммажи. Годар был против правил старого поколения в кинематографе и снимал, как чувствуется. Сначала получалось малобюджетно, но от этого так искренне и глубоко.","type":"paragraph"},{"html":"Все картины Годара это выраженный на пленке протест против общества в картине «На последнем дыхании» (1960), политической структуры в «Маленьком солдате» (1960), продюсерского кино в «Презрении» (1963) и государства в «Альфавиле» (1965). Годар высмеивал Голливуд и его зацикленность на коммерческом успехе. Например, деньги на дебютный «На последнем дыхании» (À bout de souffle) помогли собрать коллеги-режиссеры, писавшие тогда для французского издания про кино Cahiers du Cinéma вместе с Годаром. Получилась небольшая сумма, поэтому пришлось снимать в режиме жесткой экономии.","type":"paragraph"},{"html":"Представить в Голливуде, что Годар не получал разрешений на съемка на улицах Парижа, не платил массовке, а вместо операторской тележки использовал инвалидное кресло, просто невозможно. Сценарий фильма Годар и Трюффо писали перед съемочным днем, а все диалоги были импровизацией актеров. Кажется, что благодаря этой свободе история про прожигателя жизни Мишеля Пуакара в роли Бильмондо и прилежную ученицу Патрисию встретила в самое сердце. Прямо как герой фильма в полицейского – необъяснимо и без явной причины.","type":"paragraph"},{"html":"<b>КИНО, КАК ВЫСКАЗЫВАНИЕ </b>","type":"paragraph"},{"html":"Первый успех позволил снимать смелее и жестче. Фильм «Маленьком солдате» (Le petit soldat) - это открытое заявление против войны в Алжире и роли Франции в ней. Ленту запретили к показу из-за слишком реалистичных сцен насилия.","type":"paragraph"},{"html":"Потом, в 1963, Годар снял свое «Презрение» (Le mépris) с Бриджит Бордо. Эта история о медленно угасающей любви сценариста и его жены, которая в конечном счете перерастает в презрение. Сквозь фильм сквозит мысль, что искусство всегда ставит творческого человека перед выбором: деньги и успех или свобода самовыражения вне рамок. Для Годара ответ очевиден: выбора нет, иначе презрение.","type":"paragraph"},{"html":"Через 2 года, в 1965, у Годара получился фильм в популярном сейчас стиле si-fi. «Альфавиль» (Alphaville, une étrange aventure de Lemmy Caution) – вымышленный город будущего, где под запретов любовь, поэзия и романтика. Картина переосмысливает разрушающую силу тоталитаризма, ведь человек - существо чувствительное и нежное. Оно не может бек любви и ласки.","type":"paragraph"},{"html":"А «Китаянка» (La Chinoise) 67-го года стала яркой предвестницей социалистической революции 1968 года. Кинолента повествует про жизнь парижских студентов, которые исследуют манифесты Мао Цзэдуна и живут идеей революции.","type":"paragraph"},{"html":"<b>ГОДАР, ПРОТЕСТЫ И СОРВАННЫЕ КАННЫ </b>","type":"paragraph"},{"html":"Невероятно, но факт .Спустя год после «Китаянки» во Франции происходит майская революция. Социальный кризис, который начнется со студенческих протестов, превращается в 10-миллионную забастовку. При этом сложно сказать, это фильм режиссера и его коллег «Новой волны» повлияли на исторические события или фильм олицетворял то, что происходило.","type":"paragraph"},{"html":"Сам Годар рассматривал свои фильмы, как зеркало поколения молодых французов. Считал, что это отражение реальности и называл их «киноправдой». ака документальным кино. Так или иначе, забастовки переросли в жестокие стычки с полицией и отставкой Шарля де Голля.","type":"paragraph"},{"html":"Годар, естественно, примет активное участие в свержении власти и начнет с Каннского кинофестиваля, который был олицетворением ненавистной к буржуазии и незаслуженного достатка. Перед началом одного из фильмов-конкурсантов Жан-Люк Годар вместе со своим другом-режиссером Франсуа Трюффо повисли на большом занавесе дворца Круазетт, чтобы сорвать показ. Члены жюри и гости одетые в смокинги и бриллианты были возмущены. Баталия привела к закрытию Каннского кинофестиваля.","type":"paragraph"},{"html":"Фильмы Годара — сложносочинённое искусство. После них будешь читать рецензии критиков, чтобы понять что это вообще было. После просмотра будешь долго думать, обсуждать с друзьями и спорить, ведь каждый поймёт что-то своё. Все потому что в фильмах Годара нет правил. Они про свободу. Для каждого свою.","type":"paragraph"}]'::jsonb,'cmrmqtc5r00c7uktauo93viig','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz6g000dkwtai45m48bj','cmrmpdrom0000sstarkqxwts4','2022-09-16T06:00:00.000Z'::timestamp,NULL,NULL,NULL,545,'/sobytija/kino/545-ushedshaja-v-zakat-volna-godara.html','2026-07-15T21:00:27.920Z'::timestamp,'2026-07-16T13:58:07.035Z'::timestamp,'''10'':559C ''13'':3