INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrs1j005wuktaz7nvfrsl','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Мария Козакова о сцене, кино и жизни вне кулис','Мария Козакова – российская актриса театра и кино.','609-marija-kozakova-o-scene-kino-i-zhizni-vne-kulis','[{"html":"Мария Козакова – российская актриса театра и кино. Несмотря на то, что Мария - наследница сразу двух звездных династий, ей удалось запомниться поклонникам благодаря своему творчеству и таланту. К 30 годам на счету актрисы более 30 киноработ. Ее героини в фильмах «Дурная кровь» и «Кармелита» покорили зрителей и навсегда оставили в их сердцах любовь к творчеству молодой актрисы.","type":"paragraph"},{"html":"Наше интервью – это разговор о самом важном: творчестве, семье и дальнейших планах!","type":"paragraph"},{"html":"Благодарим Марию за добрую и теплую беседу!","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/kFcn9zIAqSQ?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" title=\"Мария Козакова о сцене, кино и жизни вне кулис\"></iframe>","type":"embed"}]'::jsonb,'cmrmqrs01005vuktamcbjkutl','cmrm8kzli000ikwtafbw33jnj','cmrm8kzns000jkwtahwuubl9w','cmrmpdrom0000sstarkqxwts4','2023-08-28T06:00:00.000Z'::timestamp,NULL,NULL,NULL,609,'/persona/intervju/609-marija-kozakova-o-scene-kino-i-zhizni-vne-kulis.html','2026-07-15T20:59:15.127Z'::timestamp,'2026-07-16T13:57:13.656Z'::timestamp,'''30'':44C,50C ''emb'':101C ''paragraph'':74C,89C,99C ''актрис'':13B,20C,48C,72C ''бесед'':97C ''благодар'':38C,91C ''важн'':82C ''вне'':8A ''героин'':53C ''год'':45C ''дальн'':86C ''двух'':31C ''династ'':33C ''добр'':94C ''дурн'':56C ''жизн'':