INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqqyw30030ukta0txerfyc','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'ЭРА НЕВРОТИКОВ! Откуда берутся страхи и фобии?','Последние годы наш мир претерпевает изменения.','636-jera-nevrotikov-otkuda-berutsja-strahi-i-fobii','[{"html":"Последние годы наш мир претерпевает изменения. Мы учимся жить по новым правилам и подстраиваться под реалии, которые уже не изменить. Для многих - это очень тревожное время, время, когда жить по-новому еще не научились, а по-старому уже нельзя. Тревоги, страхи и депрессии переполняют общество.","type":"paragraph"},{"html":"Наш фильм поможет разобраться, почему так происходит и как найти баланс между светом и тьмой! Как научиться видеть яркие краски, ведь даже самая безвыходная ситуация может стать началом нового счастливого пути.","type":"paragraph"},{"html":"Совместно с психологами в этом интервью мы разобрали природу появления тревожных состояний, симптомы панических атак, отчего появляется депрессия и как с ней бороться, как каждый день наполнять свою жизнь приятными моментами, научиться любить и принимать себя!","type":"paragraph"},{"html":"Благодарим наших героинь:","type":"paragraph"},{"html":"Мария Чумак – психотерапевт, расстановщик <a href=\"https://t.me/chumak_mariya_psycholog\" target=\"_blank\" rel=\"noopener noreferrer\">https://t.me/chumak_mariya_psycholog </a>","type":"paragraph"},{"html":"Алиса Хачатрян – психолог, экзистенциально-гуманистический психотерапевт <a href=\"https://t.me/alisa_psy\" target=\"_blank\" rel=\"noopener noreferrer\">https://t.me/alisa_psy </a>","type":"paragraph"},{"html":"Ирина Архипова - психолог в модальности интегрального нейропрограммирования и КПТ <a href=\"https://tenchat.ru/2284774?ysclid=ls1lfxm070812364493\" target=\"_blank\" rel=\"noopener noreferrer\">https://tenchat.ru/irinaarhipova</a>","type":"paragraph"},{"html":"Альбина Маннанова - квантовый психолог, автор и ведущая женских тренингов, расстановщик <a href=\"https://t.me/lybov_i_blagodarnoct\" target=\"_blank\" rel=\"noopener noreferrer\">https://t.me/lybov_i_blagodarnoct </a>","type":"paragraph"},{"html":"Инна Богданович - психолог, парапсихолог","type":"paragraph"},{"html":"Ольга Царева - магистр психологии, руководитель психологического центра <a href=\"https://dzen.ru/tsarevaovl\" target=\"_blank\" rel=\"noopener noreferrer\">https://dzen.ru/tsarevaovl </a>","type":"paragraph"},{"html":"Карина Арасланова – психолог, наставник <a href=\"https://t.me/araslanovakarina\" target=\"_blank\" rel=\"noopener noreferrer\">https://t.me/araslanovakarina </a>","type":"paragraph"},{"html":"Екатерина Кисловская - коуч для жизни, бизнеса и души, психолог, спикер <a href=\"https://vk.com/kislovskaia_ekaterina\" target=\"_blank\" rel=\"noopener noreferrer\">https://vk.com/kislovskaia_ekaterina</a>","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/Mx-pr2UZovw?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" title=\"ЭРА НЕВРОТИКОВ! Откуда берутся страхи и фобии?\"></iframe>","type":"embed"},{"html":"*Благодарим российские бренды премиальной одежды micutti.ru и middlemist.ru за предоставление образов нашим героиням","type":"paragraph"}]'::jsonb,'cmrmqqyu9002zuktashtq6unn','cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2024-01-30T06:00:00.000Z'::timestamp,NULL,NULL,NULL,636,'/psihologija/intervju-2/636-jera-nevrotikov-otkuda-berutsja-strahi-i-fobii.html','2026-07-15T20:58:37.347Z'::timestamp,'2026-07-16T13:56:58.296Z'::timestamp,'''/alisa_psy'':162C ''/araslanovakarina'':223C ''/chumak_mariya_psycholog'':149C ''/irinaarhipova'':177C ''/kislovskaia_ekaterina'