,159C ''пут'':94C ''разобра'':67C,105C ''расстановщик'':146C,190C ''реал'':29C ''российск'':246C ''руководител'':208C ''сам'':86C ''свет'':76C ''симптом'':110C ''ситуац'':88C ''совместн'':98C ''состоян'':109C ''спикер'':236C ''стар'':52C ''стат'':90C ''страх'':5A,56C ''счастлив'':93C ''тревог'':55C ''тревожн'':38C,108C ''тренинг'':189C ''тьмо'':78C ''уч'':21C ''фильм'':65C ''фоб'':7A ''хачатря'':154C ''царев'':205C ''центр'':210C ''чумак'':144C ''экзистенциальн'':157C ''экзистенциально-гуманистическ'':156C ''эр'':1A ''эт'':36C ''ярк'':82C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqecyo0025potakp91t01z','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'"Зачем нарываешься снова?": Кушанашвили отсчитал Ивлееву','Российская звезда Анастасия Ивлеева не пропустила завершение Олимпийских игр во Франции, нашла им «уместное» сравнение.','677-zachem-naryvaeshsja-snova-kushanashvili-otschital-ivleevu','[{"html":"Во Франции завершились Олимпийские игры. За ними наблюдал весь мир, исключением не стали и российские селебрити. Анастасия Ивлеева, скандальный блогер, канувшая в небытие после зимней «головой вечеринки», тоже с любопытством и азартом наблюдала за играми и даже нашла им «уместное» сравнение.","type":"paragraph"},{"html":"«Немного подглядела за церемонией открытия Олимпиады в Пориже (через о, да). Что, собственно, хочу сказать: вечеринка у нас была стильнее. Спасибо всем за Сочи и ЧМ по футболу», — отмечала 33-летняя звезда соцсети.","type":"paragraph"},{"html":"Сарказм разглядели не все. Многие расценили сравнение Олимпиады с «голой» вечеринкой, за которую Ивлеева долгое время извинялась. В действительности сравнение было с Олимпиадой в Сочи, но, волну СМИ было уже не остановить. Тысячи публикации в изданиях и комментарии звезд.","type":"paragraph"},{"html":"«Она пишет после открытия Олимпиады, что у нас голая вечеринка была стильнее. Ну зачем ты нарываешься? Белокурая ты дура! Зачем нарываешься снова? Не стильнее у вас было, а сборище людей с пониженной социальной ответственностью у тебя было с тобой во главе», — не прошел мимо поста Анастасии Отар Кушанашвили.","type":"paragraph"},{"html":"Порыв девушки напомнить о себе, даже таким путем, выглядит весьма понятным. В одночасье успешный блогер лишилась признания звезд, контрактов и многочисленной толпы поклонников. И как, не старалась «угаснувшая» звезда в черном бадлоне с русской косой вымолить прощение, народ и рекламодатели оказались проницательнее и увидев фальш, в умоляющих извинениях, списали Ивлееву.","type":"paragraph"}]'::jsonb,'cmrmqecwi0024potagsshm9hm','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-08-12T06:00:00.000Z'::timestamp,NULL,NULL,NULL,677,'/v-mire/677-zachem-naryvaeshsja-snova-kushanashvili-otschital-ivleevu.html','2026-07-15T20:48:49.056Z'::timestamp,'2026-07-16T13:56:28.862Z'::timestamp,'''33'':95C ''paragraph'':64C,100C,142C,193C,246C ''азарт'':53C ''анастас'':9B,38C,189C ''бадлон'':226C ''белокур'':160C ''блогер'':41C,209C ''ве'':30C ''весьм'':204C ''вечеринк'':48C,81C,112C,153C ''волн'':128C ''врем'':117C ''всем'':87C ''выгляд'':203C ''вымол'':230C ''глав'':184C ''гол'':111C,152C ''голов'':47C ''девушк'':196C ''действительн'':120C ''долг'':116C ''дур'':162C ''заверш'':24C ''завершен'':13B ''звезд'':8B,97C,140C,212C,223C ''зимн'':46C ''ивлеев'':6A,10B,39C,115C,244C ''игр'':15B,26C,56C ''извинен'':242C ''извиня'':118C ''издан'':137C ''исключен'':32C ''канувш'':42C ''комментар'':139C ''контракт'':213C ''кос'':229C ''котор'':114C ''кушанашв'':4A,191C ''летн'':96C ''лиш'':210C ''любопытств'':51C ''люд'':173C ''мим'':187C ''мир'':31C ''мног'':106C ''многочислен'':215C ''наблюда'':29C,54C ''напомн'':197C ''народ'':232C ''нарыва'':2A,159C,164C ''нашл'':18B,59C ''небыт'':44C ''немн'':66C ''ним'':28C ''одночас'':207C ''оказа'':235C ''олимпиад'':71C,109C,124C,148C ''олимпийск'':14B,25C ''останов'':133C ''отар'':190C ''ответствен'':177C ''открыт'':70C,147C ''отмеча'':94C ''отсчита'':5A ''пишет'':145C ''подглядел'':67C ''поклонник'':217C ''понижен'':175C ''понятн'':205C ''пор'':195C ''пориж'':73C ''пост'':188C ''признан'':211C ''проницательн'':236C ''пропуст'':12B ''прошел'':186C ''прощен'':231C ''публикац'':135C ''пут'':202C ''разглядел'':103C ''расцен'':107C ''рекламодател'':234C ''российск'':7B,36C ''русск'':228C ''сарказм'':102C ''сборищ'':172C ''селебрит'':37C ''сказа'':80C ''скандальн'':40C ''сми'':129C ''снов'':3A,165C ''собствен'':78C ''социальн'':176C ''соцсет'':98C ''соч'':89C,126C ''спасиб'':86C ''списа'':243C ''сравнен'':21B,62C,108C,121C ''стал'':34C ''стара'':221C ''стильн'':85C,155C,167C ''так'':201C ''тоб'':182C ''толп'':216C ''тысяч'':134C ''увид'':238C ''угаснувш'':222C ''уместн'':20B,61C ''умоля'':241C ''успешн'':208C ''фальш'':239C ''франц'':17B,23C ''футбол'':93C ''хоч'':79C ''церемон'':69C ''черн'':225C ''чм'':91C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrntu005fukta2u3rrlkh','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Fashion bitva во Владивостоке','23 сентября во Владивостоке в креативном пространстве «Place» пройдет региональный этап 11 сезона международного конкурса дизайнеров Fashion bitva.Осенний сезон предлагает участникам порассуждать на тему весенне-летних т','616-fashion-bitva-vo-vladivostoke','[{"html":"23 сентября во Владивостоке в креативном пространстве «Place» пройдет региональный этап 11 сезона международного конкурса дизайнеров Fashion bitva.","type":"paragraph"},{"html":"Осенний сезон предлагает участникам порассуждать на тему весенне-летних тенденций грядущего года. Перед нами предстанут коллекции из Владивостока, Хабаровска, Комсомольска-на-Амуре и Иркутска.","type":"paragraph"},{"html":"<em> «</em><em>Вот уже пятый раз во Владивостоке пройдёт региональный этап конкурса дизайнеров одежды Fashion Bitva</em><em>,</em><em> и с каждым годом география участников расширяется. Что очень радует, значит, есть доверие и интерес к модной индустрии. Профессиональное жюри выберет победителя, который представит Владивосток в финале конкурса в Москве</em><em>» - рассказывает организатор конкурса на Дальнем Востоке, Ирина Акулина.</em>","type":"paragraph"},{"html":"Участники готовятся к показу и у каждого из них свое видение моды. Коллекция Ольги Нарватовой сочетает в себе изысканную вечернюю моду и элементы street style в современном исполнении: прозрачные шифоновые платья дополняются атласными бомберами, декорированными волшебными мандалами. Галина Потехина также продемонстрирует на подиуме вечернюю моду. Ее коллекция «Жемчужина» состоит из кутюрных платьев, расшитых бисером, стеклярусом и стразами и декорированная кружевом.","type":"paragraph"},{"html":"Иное видение на современную моду нам покажет дизайнер Ирина Смирнова.","type":"paragraph"},{"html":"Ее коллекция «Без слов. Посвящается…» совмещает в себе африканские мотивы и образы со славянской вышивкой крестом. Задача дизайнера: осовременить ушедшую моду.","type":"paragraph"},{"html":"Мария Соколова из Комсомольска-на-амуре в своей коллекции «Чужестранка» также решила обратиться к русской культуре - истории русского костюма и головных уборов. Большая часть образов выполнена из натуральных материалов: крапива, конопляное полотно, лен, хлопок.","type":"paragraph"},{"html":"Чужестранка завораживает своей загадочностью и волшебством!","type":"paragraph"},{"html":"В коллекции дизайнера Марго Авоян воспеты мотивы азиатской и восточной культур. По мнению дизайнера, все азиатское - смелое прогрессивное, а восточное - таинственное и завораживающее. Также, как и в ее коллекции \"Восточные Муссоны\", - многослойные и разнофактурные образы из неопрена, органзы и жаккарда умело сочетаются в одной коллекции и завораживают своей смелостью фактур и форм.","type":"paragraph"},{"html":"Вдохновляет своей смелостью и Оксана Киричевская. Идея коллекции дизайнера - сохранение природы, которая показывает нам как нужно жить. Натуральные ткани в сочетании с искусственными ручного окраса, ботанический принт и головные уборы с растениями, шляпы и короны, – Оксане определено нравится использовать в своем творчестве сказочные мотивы!","type":"paragraph"},{"html":"<em>«</em><em>Не могу сказать, что всё даётся легко, многое еще предстоит сделать, чтобы модное направление заняло по праву лидирующие позиции на Дальнем Востоке. Ведь у нас столько талантливых ребят</em><em>» - к моде на Дальнем Востоке дизайнер и по совместительству организатор конкурса, Ирина Акулина, относится бережно и трепетно</em><em>.</em>","type":"paragraph"},{"html":"Детское и подростковое направление конкурса наравне с взрослым занимает сильные позиции, а идеи дизайнеров поражают своей новизной.","type":"paragraph"},{"html":"Дизайнер Дарья Иванчук в своей коллекции «Vintage Dolls» рассказывает удивительную историю из собственной жизни: <em>«Моя новая коллекция началась с находки куклы на чердаке. Да именно так. Старая, запыленная, без одежды, кукла. Мне захотелось дать ей новую жизнь, продолжить историю.</em>","type":"paragraph"},{"html":"<em>Это было заразительное начало моей коллекции. Я погрузилась полностью в загадочную историю мира кукол». </em>В своей коллекции она использует только натуральные ткани, чтобы приблизиться к ощущению внутреннего комфорта и защищенности.","type":"paragraph"},{"html":"«Такая, какая есть!» - этим названием дизайнер Вера Григорьева подчеркивает главный девиз современных подростков. Сегодня можно быть собой, стирать рамки и размывать границы, сочетать нежность и бунтарский дух. Ровно также дизайнер стирает все стереотипы и условности в своей коллекции: современный крой, грубость и нежность в едином ансамбле, разные фактуры: от кожи до фатина, разный декор: от страз до – цепей. Будь нежной! Будь грубой!","type":"paragraph"},{"html":"Весьма интересный подход мы увидим и еще у одного детского дизайнера. Школьная форма в исполнении Ирины Чернюк – это нестандартный подход к одежде в рамках школьного устава. Каждая ученица уникальна! Одинаковых не бывает, даже среди подружек или сестёр!","type":"paragraph"},{"html":"Использование съёмных и взаимозаменяемых деталей в одежде дает массу разнообразных образов. А недорогие, но очень износостойкие и неприхотливые в уходе, ткани (габардин, фатин, тиси, ситец) вполне устраивают родителей.","type":"paragraph"},{"html":"И наш крайний бренд молодежной одежды «Gbuyer» из Хабаровска во главе с Фалеевой Анастасией представит зрителю коллекцию, выполненную в японских мотивах. Главная цель дизайнера – продемонстрировать неочевидность добра и зла.","type":"paragraph"},{"html":"<b><u><i>Ждем Вас 23 сентября в пространстве «Place» на Днепропетровской 100/12</i></u></b>","type":"paragraph"},{"html":"<b><u><i>Сбор гостей: 17:00</i></u></b>","type":"paragraph"},{"html":"<b><u><i>Купить билет: <a href=\"https://fashion-bitva.qtickets.ru/event/82143\" target=\"_blank\" rel=\"noopener noreferrer\">https://fashion-bitva.qtickets.ru/event/82143</a></i></u></b>","type":"paragraph"},{"type":"image","mediaId":"cmrmqrnqq005euktalqpbf8wn"}]'::jsonb,'cmrmqrnh5005duktabhv85lsy','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2023-09-13T06:00:00.000Z'::timestamp,NULL,NULL,NULL,616,'/projects-esque/fashion-bitva/616-fashion-bitva-vo-vladivostoke.html','2026-07-15T20:59:09.666Z'::timestamp,'2026-07-16T13:57:10.491Z'::timestamp,'''/event/82143'':723C ''00'':715C ''100/12'':708C ''11'':16B,45C ''17'':714C ''23'':5B,34C,701C ''bitva'':2A,22B,51C,97C ''cmrmqrnqq005euktalqpbf8wn'':729C ''doll'':463C ''fashion'':1A,21B,50C,96C ''fashion-bitva.qtickets.ru'':722C ''fashion-bitva.qtickets.ru/event/82143'':721C ''gbuyer'':673C ''imag'':727C ''paragraph'':53C,82C,137C,200C,213C,237C,275C,284C,339C,386C,434C,454C,496C,529C,594C,634C,665C,697C,710C,717C,725C ''place'':12B,41C,705C ''street'':162C ''style'':163C ''vintag'':462C ''авоя'':290C ''азиатск'':293C,301C ''акулин'':135C,428C ''амур'':78C,245C ''анастас'':680C ''ансамбл'':576C ''атласн'':171C ''африканск'':223C ''бережн'':430C ''билет'':720C ''бисер'':192C ''больш'':262C ''бомбер'':172C ''ботаническ'':366C ''бренд'':670C ''буд'':589C,591C ''бунтарск'':556C ''быва'':627C ''вдохновля'':341C ''вер'':537C ''весен'':31B,63C ''весенне-летн'':30B,62C ''весьм'':596C ''вечерн'':158C,182C ''взаимозаменя'':639C ''взросл'':443C ''виден'':149C,203C ''владивосток'':4A,8B,37C,73C,89C,122C ''внутрен'':524C ''волшебн'':174C ''волшебств'':282C ''воспет'':291C ''восток'':133C,409C,420C ''восточн'':295C,305C,315C ''вполн'':661C ''все'':392C ''выберет'':118C ''выполн'':265C ''выполнен'':684C ''вышивк'':229C ''габардин'':657C ''галин'':176C ''географ'':102C ''глав'':677C ''главн'':540C,688C ''год'':67C,101C ''головн'':260C,369C ''гост'':713C ''готов'':140C ''границ'':