INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqqxfv002suktacm8783qv','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'В Санкт-Петербурге при поддержке ПФКИ стартовал конкурс "Пушкинский бал"','Международный конкурс дизайнеров и художников на лучший костюм героев произведений А.С.Пушкина Пушкинский бал, посвященный​ 225-летию со дня рождения Александра Сергеевича Пушкина стартовал в Петербурге при поддержке ПФК','638-v-sankt-peterburge-pri-podderzhke-pfki-startoval-konkurs-pushkinskij-bal','[{"html":"Международный конкурс дизайнеров и художников на лучший костюм героев произведений А.С. Пушкина \"Пушкинский бал\", посвященный​ 225-летию со дня рождения Александра Сергеевича Пушкина, стартовал в Петербурге при поддержке ПФКИ.","type":"paragraph"},{"html":"Конкурс станет ярким событием в культурной жизни​ не только​ Санкт-Петербурга, но и России!​ Молодые, амбициозные,​ талантливые​ и дерзкие​ дизайнеры одежды,​ художники-модельеры, ювелиры,​ дизайнеры​ по обуви и аксессуарам, фотографы со всех регионов РФ, стран СНГ и БРИКС смогут​ прикоснуться к​ наследию​ А.С.Пушкина, погрузиться в мир его ​ литературных​ героев​ ​ и сказочных​ персонажей, проявить свои творческие,​ профессиональные навыки​ и компетенции​ в области дизайна костюма, для того, чтобы​ создать ​ фантастические​ образы,​ театральные ​ и маскарадные костюмы,​ необычные зрелищные​ аксессуары​ и​ высоко-художественные постеры и​ ​ фотоплакаты, применяя самые современные технологии и тренды.","type":"paragraph"},{"html":"Цель конкурса​ —​ реализация​ творческого потенциала​ молодого поколения в области культуры, искусства и дизайна​ и​ создания условий для укрепления, дружбы и развития дальнейших профессиональных ​ ​ связей с​ талантливой​ молодежью стран ближнего и дальнего зарубежья.<br />Основные задачи конкурса — популяризация и продвижение творческого наследия А.С. Пушкина в мире, рост углубленного изучения русской классической литературы среди молодежи и юношества, креативное осмысление лучших образцов русской поэзии.","type":"paragraph"},{"html":"Конкурс​ \"Пушкинский бал\" продолжает​ традицию проведения Большого Бала героев пушкинских произведений, который впервые состоялся​ в 1899 году в Таврическом дворце – в год столетия со дня рождения великого русского поэта.","type":"paragraph"},{"html":"Работы дизайнеров будут оценивать члены​ Экспертного совета:​ профессионалы мира моды, известные ​ деятели культуры и искусства из разных стран.","type":"paragraph"},{"html":"Итоги​ международного​ конкурса дизайнеров и художников на лучший костюм героев произведений А.С.Пушкина \"Пушкинский бал\" будут подведены​ в​ начале​ июня​ 2024 г.​ в​ рамках финального​ Гала-показа. Работы победителей конкурса​ будут представлены на​ уникальном​ событии​,​ которое будет проходить в одном из знаковых мест Петербурга в традиционном формате проведения балов конца​ XVIII​ – начала​ XIX​ веков.​","type":"paragraph"},{"html":"​Герои самых известных произведений А.С. Пушкина оживут под звуки знаменитых мелодий музыкальной пушкинианы.","type":"paragraph"},{"html":"Учредителем конкурса является Санкт-Петербургский Пушкинский фонд культуры.​","type":"paragraph"},{"html":"<br /><i>Организаторы:</i><br /><i>- РОО \"Алые паруса\",</i><br /><i>- Всероссийский музей А.С. Пушкина,​</i><br /><i>- Санкт-Петербургский государственный университет промышленных технологий и дизайна — Международный​ фестиваль моды, искусства и​ дизайна​ \"Адмиралтейская игла\".</i>","type":"paragraph"},{"html":"Сергей Михайлович Некрасов, директор Всероссийского музея А.С. Пушкина, академик, писатель, сценарист, историк, просветитель, заслуженный деятель искусств России отметил, что проект, поддержанный ПФКИ — Международный конкурс дизайнеров и художников на лучший костюм героев произведений А.С.Пушкина \"Пушкинский бал\" станет важным и масштабным событием северный столицы в юбилейный год великого поэта год. Это будет грандиозный финальный бал, который отчасти повторит знаменитый бал, который прошел в год столетия А.С.Пушкина в Таврическом дворце с участием героев пушкинских произведений.","type":"paragraph"},{"html":"Алексей Вячеславович Демидов, Председатель Совета ректоров вузов Санкт-Петербурга и Ленинградской области, ректор Санкт-Петербургского государственного университета промышленных технологий и дизайна, заместитель председателя Общественной палаты Санкт-Петербурга считает, что команда Международного фестиваля \"Адмиралтейская игла\" и в целом участие университета \"ПромТехДизайн\" смогут внести яркую творческую лепту в организацию и проведение проекта. Важной частью образовательного процесса является расширение кругозора сегодняшних студентов, в том числе в направлении русской национальной культуры, поэзии, развития национальных креативных индустрий. Уверен, этот Бал будет по-настоящему зрелищным и незабываемым!","type":"paragraph"},{"html":"По словам Любови Джикия, художественного руководителя Международного фестиваля молодых дизайнеров \"Адмиралтейская игла\", — \"Пушкин даже в своих произведениях порядка 84 раз обращал внимание на моду, в частности, в романе \"Евгений Онегин\", и, конечно, если рассмотреть взгляд нашего классика на феномен моды под этим ракурсом, то для ребят, безусловно, будет масса открытий в Конкурсе, поскольку сама эпоха Пушкина — классицизм, ампир дает большую фантазию для творчества\".","type":"paragraph"},{"html":"Елена Демидова, директор Санкт-Петербургского Пушкинского фонда, отметила, что проект поддержан Президентским фондом культурных инициатив. Призовой фонд конкурса — 600 000 рублей. Также обьявляется открытый конкурс на разработку логотипа и айдентики Международного Конкурса дизайнеров, модельеров и художников \"Пушкинский бал\". Экспозиция лучших конкурсных работ будет представлена на выставках в музеях и других культурных центрах, связанных с именем А.С. Пушкина в разных регионах России.","type":"paragraph"},{"html":"Антон Алфер (Москва), генеральный директор ALFER GROUP* (IT-партнер проекта \"Международный конкурс дизайнеров и художников на лучший костюм героев произведений А.С.Пушкина \"Пушкинский бал\"), продюсер, визионер, президент Ассоциации участников индустрии моды \"Модная сеть\", основатель портала MODA.RU и платформы FASHION.RU рассказал об уникальных возможностях платформы при проведении конкурса.","type":"paragraph"},{"html":"Вера Иванова (Москва), программный директор деловых мероприятий СОЮЗЛЕГПРОМа, председатель комитета СОЮЗЛЕГПРОМа по коммуникации и взаимодействию со СМИ охарактеризовала широкий спектр возможностей сегодня для развития у специалистов, занятых в сфере моды, эксперт уверена, что участие в этом проекте даст положительный опыт молодым дизайнерам.","type":"paragraph"},{"html":"Игорь Иванов (Минск, Беларусь), заведующий отделом моды и дизайна Национального центра художественного творчества детей и молодежи, организатор Республиканского фестиваля-конкурса моды и фото «Мельница моды» выразил готовность к вовлечению студентов и творческой молодёжи Беларуси к участию в проекте, так как юбилей Пушкина, и его творческое наследие станут прекрасным поводом к созданию новых авторских коллекций и глубокому изучению национальной русской культуры.","type":"paragraph"},{"html":"Ботагоз Алдонгарова (Алматы, Казахстан), соучредитель, исполнительный директор Национальной Недели моды Kazakhstan Fashion Week и конкурса молодых дизайнеров New Generashion-Open way, предложила усилить взаимодействие по участию студентов двух стран в творческих культурных проектах, что всегда способствует созданию уникальных дизайн-проектов с изучением национальной и общемировой культуры.","type":"paragraph"},{"html":"<i>Контактная информация для представителей СМИ: Катерина Туголукова +7(921) 942-64-67</i>","type":"paragraph"},{"html":"<i>Справочный телефон:​ +7 (921) 943-16-62</i><br /><i><a href=\"https://e.mail.ru/compose?To=support@id.community\" target=\"_blank\" rel=\"noopener noreferrer\">support@id.community</a></i>","type":"paragraph"},{"html":"*Проект реализуется при поддержке Президентского фонда культурных инициатив","type":"paragraph"},{"html":"* IT-партнер: на облачной конкурсной платформе КОНКУРС.РФ, разработанной ALFER.GROUP, реализована вся онлайн составляющая конкурса, включая сбор заявок, голосование членов жюри и информационные материалы о конкурсе.","type":"paragraph"},{"html":"(Текст: Катерина Туголукова, иллюстрация : Александра Некерова)","type":"paragraph"},{"type":"image","mediaId":"cmrmqqxew002ruktav90yf9hj"}]'::jsonb,'cmrmqqx7n002quktafjo8pdrp','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2024-02-07T06:00:00.000Z'::timestamp,NULL,NULL,NULL,638,'/fashion/news-2/638-v-sankt-peterburge-pri-podderzhke-pfki-startoval-konkurs-pushkinskij-bal.html','2026-07-15T20:58:35.467Z'::timestamp,'2026-07-16T13:56:56.739Z'::timestamp,'''+7'':924C,934C ''-16'':937C ''-62'':938C ''-64'':927C ''-67'':928C ''000'':659C ''1899'':250C ''2024'':309C ''225'':28B,58C ''600'':658C ''84'':591C ''921'':925C,935C ''942'':926C ''943'':936C ''alfer'':710C ''alfer.group'':964C ''cmrmqqxew002ruktav90yf9hj'':995C ''fashion'':877C ''fashion.ru'':745C ''generashion'':885C ''generashion-open'':884C ''group'':711C ''imag'':993C ''it-партнер'':712C,954C ''kazakhstan'':876C ''moda.ru'':742C ''new'':883C ''open'':886C ''paragraph'':73C,169C,233C,265C,286C,345C,362C,374C,403C,483C,571C,637C,703C,755C,800C,864C,915C,930C,941C,952C,982C,991C ''support@id.community'':939C ''way'':887C ''week'':878C ''xix​'':342C ''xviii​'':340C ''авторск'':855C ''адмиралтейск'':400C,520C,583C ''айдентик'':669C ''академик'':414C ''аксессуар'':105C ''аксессуары​'':154C ''ал'':378C ''алдонгаров'':867C ''алекс'':485C ''александр'':33B,63C,988C ''алмат'':868C ''алфер'':706C ''амбициозн'':91C ''ампир'':630C ''антон'':705C ''ассоциац'':734C ''бал'':11A,26B,56C,2