66C,542C ''ярк'':77C,530C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsmig008xuktaop5womj3','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Луиза Автандилян. «Диета» для зубов: ТОП-7 продуктов для сохранения красоты и здоровья зубов','Для того, чтобы создать тело своей мечты, нужно придерживаться специальной диеты, выбирая полезные продукты и ограничивая себя в сладком, в остром и в прочих «вредностях».','582-luiza-avtandiljan-dieta-dlja-zubov-top-7-produktov-dlja-sohranenija-krasoty-i-zdorovja-zubov','[{"html":"Для того, чтобы создать тело своей мечты, нужно придерживаться специальной диеты, выбирая полезные продукты и ограничивая себя в сладком, в остром и в прочих «вредностях». А каким должно быть питание, чтобы сохранить красоту и здоровье зубов? На эти вопросы отвечает российский врач-стоматолог, предприниматель и основатель «Smilestudio» Луиза Автандилян.","type":"paragraph"},{"html":"Как говорил великий философ и медик Гиппократ: «Мы — то, что мы едим». Действительно, еда — это то, что наполняет нас силами и энергией, помогает чувствовать себя лучше и жить полной жизнью. Сбалансированное питание позволяет укрепить зубы и челюстной аппарат, предупреждает развитие кариеса и заболеваний полости рта. Ниже — 7 полезных продуктов, которые должны обязательно присутствовать в рационе каждого человека.","type":"paragraph"},{"html":"<i><b>Молоко</b></i>","type":"paragraph"},{"html":"Всем известно ещё с детских лет, что натуральное молоко полезно для здоровья. Богатый кальцием и лактозой напиток при употреблении всего одного стакана в день может помочь укрепить зубы и сделать кости более прочными. Кроме того, молоко с помощью казеина смягчает воздействие кариесогенных и агрессивных веществ: например, при его добавлении в чай или кофе связываются танины, которые вредят зубной эмали.","type":"paragraph"},{"html":"<i><b>Твёрдый сыр</b></i>","type":"paragraph"},{"html":"Кальций — основное минеральное вещество, содержащееся в огромном количестве в твёрдом сыре — до 800 мг на 100 г продукта в зависимости от сорта. Кальций — строительный материал костной и зубной ткани, поэтому очень важно поддерживать его нормальный уровень в организме. Если каждое утро добавлять к своему завтраку пару ломтиков сыра, можно значительно снизить риск образования кариеса и разрушения зубной эмали.","type":"paragraph"},{"html":"<i><b>Перепелиные яйца</b></i>","type":"paragraph"},{"html":"Нужно иметь ввиду, что кальций сам по себе не усваивается в организме и его нужно употреблять в комплексе с витамином D, хороший источник которого — яйца, предпочтительно перепелиные.","type":"paragraph"},{"html":"В перепелиных яйцах «солнечный» витамин содержится в активной форме, а уровень фосфора, калия и железа в них примерно в 5 раз выше, чем в куриных яйцах.","type":"paragraph"},{"html":"Приготовив омлет или яичницу, не стоит спешить и выбрасывать скорлупу от перепелиных яиц: она содержит легкоусвояемый кальций, фтор, фосфор кремний, цинк и тоже может принести большую пользу для здоровья зубов. Ее необходимо измельчать до состояния порошка, «гасить» лимонной или уксусной кислотой и употреблять во второй половине дня.","type":"paragraph"},{"html":"<i><b>Кешью</b></i>","type":"paragraph"},{"html":"Анакардиум, или кешью — очень полезный орех как для зубов, так и для всего организма. В состав кешью входят витамины, насыщенные жирные кислоты, микроэлементы и химические соединения, оказывающие антибактериальное действие и защищающие зубную эмаль от кариеса.","type":"paragraph"},{"html":"<i><b>Зелёное яблоко</b></i>","type":"paragraph"},{"html":"Жевание сочного зелёного яблока благотворно влияет на состояние зубов и десен, оказывая массирующее действие и тем самым усиливая кровоснабжение десен. Кислый яблочный сок стимулирует слюноотделение, нейтрализует кислоты полости рта и размягчает мягкий зубной налёт.","type":"paragraph"},{"html":"<i><b>Морская рыба</b></i>","type":"paragraph"},{"html":"Благодаря высокому содержанию йода, селена, кальция и витамина D морская рыба является неотъемлемой частью здорового рациона. Рекомендуется употреблять этот ценный продукт 2-3 раза в неделю. К тому же, рыба полезна не только для здоровья зубов, но и для организма в целом: она легче усваивается и содержит в своём составе больше незаменимых аминокислот, витаминов и минералов, чем красное мясо.","type":"paragraph"},{"html":"<i><b>Клюква</b></i>","type":"paragraph"},{"html":"Вкусная профилактика стоматологических заболеваний — натуральная клюква. Современные учёные доказали, что ягоды клюквы обладают выраженными антисептическими свойствами и уничтожают бактерии в ротовой полости. Входящие в состав красной ягоды природные полифенолы замедляют образование зубного налёта, предупреждая разрушение эмали.","type":"paragraph"},{"html":"Стоит отметить и ограничения, связанные с «диетой для зубов» — от каких продуктов лучше отказаться или свести их употребление к минимуму ради здоровья полости рта:","type":"paragraph"},{"html":"<em>-</em><em> Сахар;</em>","type":"paragraph"},{"html":"<em>-</em><em> Сладости — карамель, шоколад, выпечка;</em>","type":"paragraph"},{"html":"<em>-</em><em> Сладкие и газированные напитки. </em>","type":"paragraph"},{"html":"Если от «запрещенки» отказаться не получилось, обязательно воспользуйтесь флоссом, зубочисткой или жевательной резинкой без сахара, а также прополоскайте рот чистой водой.","type":"paragraph"},{"html":"Здоровье и красота зубов — это, в первую очередь, правильная, регулярная гигиена полости рта и своевременное обращение к стоматологу для профилактики и соответствующего лечения. Если не пренебрегать этими «золотыми» правилами» и при этом питаться сбалансировано, можно сохранить здоровье зубов и десен на долгие годы.","type":"paragraph"},{"type":"image","mediaId":"cmrmqsmh6008wuktal17u10hq"}]'::jsonb,'cmrmqsm47008vukta4t5i2n4k','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyun0008kwtasfd55v5y','cmrmpdrom0000sstarkqxwts4','2022-11-16T06:00:00.000Z'::timestamp,NULL,NULL,NULL,582,'/beauty/tendencii/582-luiza-avtandiljan-dieta-dlja-zubov-top-7-produktov-dlja-sohranenija-krasoty-i-zdorovja-zubov.html','2026-07-15T20:59:54.616Z'::timestamp,'2026-07-16T13:57:38.579Z'::timestamp,'''-3'':510C ''-7'':7A ''100'':239C ''2'':509C ''5'':339C ''7'':139C ''800'':236C ''cmrmqsmh6008wuktal17u10hq'':710C ''d'':310C,496C ''imag'':708C ''paragraph'':91C,151C,155C,217C,222C,283C,288C,318C,347C,397C,401C,439C,444C,481C,486C,548C,552C,591C,618C,622C,629C,636C,660C,706C ''smilestudio'':87C ''автандиля'':2A,89C ''агрессивн'':200C ''активн'':327C ''аминокислот'':540C ''анакардиум'':403C ''антибактериальн'':430C ''антисептическ'':568C ''аппарат'':130C ''бактер'':572C ''благодар'':488C ''благотворн'':450C ''богат'':169C ''больш'':374C ''важн'':255C ''ввид'':292C ''велик'':95C ''веществ'':201C,227C ''витамин'':309C,324C,421C,495C,541C ''вкусн'':554C ''влия'':451C ''вод'':658C ''воздейств'':197C ''вопрос'':78C ''воспольз'':645C ''врач'':82C ''врач-стоматолог'':81C ''вред'':213C ''вредност'':39B,64C ''всем'':157C ''втор'':393C ''вход'':420C ''входя'':576C ''выбир'':26B,51C ''выбрасыва'':357C ''выпечк'':627C ''выражен'':567C ''высок'':489C ''выш'':341C ''г'':240C ''газирова'':633C ''гас'':385C ''гиг'':672C ''гиппократ'':99C ''говор'':94C ''год'':704C ''действ'':431C,459C ''действительн'':105C ''ден'':180C ''дес'':456C,465C,701C ''детск'':161C ''диет'':3A,25B,50C,599C ''дня'':395C ''добавлен'':205C ''добавля'':265C ''доказа'':562C ''долг'':703C ''должн'':67C,143C ''ед'':104C,106C ''ещ'':159C ''жеван'':446C ''жевательн'':649C ''желез'':334C ''жизн'':122C ''жирн'':423C ''жит'':120C ''заболеван'':135C,557C ''зависим'':243C ''завтрак'':268C ''замедля'':583C ''запрещенк'':640C ''защища'':433C ''здоров'':13A,74C,168C,377C,502C,522C,614C,662C,698C ''зелен'':441C,448C ''значительн'':273C ''золот'':689C ''зуб'':5A,14A,75C,127C,184C,378C,411C,454C,5