5C,281C,589C ''эмал'':435C ''энерг'':114C ''эт'':107C,666C,688C ''яблок'':442C,449C ''яблочн'':467C ''явля'':499C ''ягод'':564C,580C ''яиц'':361C ''яичниц'':352C ''яйц'':286C,314C,322C,345C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqva8u00keuktat3lnln4z','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Екатерина Красюк: "На сцене ты имеешь право на свое слово"','Балерина Михайловского и Мариинского театра, Екатерина Красюк.','457-ekaterina-krasjuk-na-scene-ty-imeesh-pravo-na-svoe-slovo','[{"html":"<strong>Балерина Михайловского и Мариинского театра, Екатерина Красюк. В ее жизни было много сцены, как российской, так и зарубежной. Вернувшись из Лондона в Россию и встретив здесь пандемию, Екатерина закончила с мировым балетом и открыла свою студию в России. Спустя 2 года, это уже большая сеть со своей авторской методикой преподавания. </strong>","type":"paragraph"},{"html":"<strong>Это история о жизни, творчестве и непрекращающейся борьбе за свою любовь – любовь к балету.</strong>","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Екатерина, здравствуйте. Как ваше настроение? Ждете лета?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Здравствуйте! Настроение отличное! Конец весны и лето - мои любимые времена года. Природа просыпается, все оживает и я оживаю вместе с ней.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Расскажите, как в вашу жизнь пришел балет?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Балет в мою жизнь пришел случайно. Я с 4-х лет занималась художественной гимнастикой, около шести лет. В какой-то момент я поняла, что это совершенно не мое и я не хочу больше развиваться в этом направлении.<br />У меня была лучшая подруга, которая в этот момент занималась в детской балетной студии при театре, и я решила тоже попробовать. Через год моего обучения, к нам приехал педагог из Академии Русского Балета им. А. Я Вагановой, выбирать детей на конкурсной программе для поступления в академию. Я была выбрана сразу на третий тур поступления. Приехала и поступила. С этого момента началось мое профессиональное балетное развитие.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>А как сложилась жизнь у подруги?","type":"paragraph"},{"html":"<strong>Екатерина: </strong>Она не стала продолжать заниматься балетом. Позже она увлеклась лошадьми и верховой ездой. Так же профессионально занималась скрипкой, училась в филармонии. Сейчас она живет на Кипре, она product designer. У нее все прекрасно. Но по России она очень скучает. Я ее понимаю.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Балет – это интересный опыт, но он неимоверно тяжелый. Сколько ежедневно нужно заниматься, чтобы стать востребованной балериной?","type":"paragraph"},{"html":"<strong>Екатерина: </strong>Нет определенных рамок по времени. Абсолютно точно, чем больше, тем лучше. В Академии мы учились с 9 утра и до 7 вечера ежедневно. Если мы участвовали в театральных постановках, то приезжали и в 11 вечера. Параллельно с профессиональными занятиями, проходили общеобразовательные уроки. <br />В театре обычно репетиции проходят по 5-7 часов в день, плюс спектакли. У меня бывали дни, когда за 11 часов непрерывных репетиций не было времени даже перекусить. Бывало месяцами работали без единого выходного. <br />Часто после работы с педагогом, остаешься сам и продолжаешь работать самостоятельно. У меня не раз бывали истории, когда охранники меня выгоняли в час ночи из театра. В академии тоже такое случалось.<br />Я привыкла так работать. По-другому уже не умею. И это не всегда хорошо. Надо уметь отдыхать, чтобы силы не иссякли, а я не всегда позволяю себе отдохнуть.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Екатерина, скажите, помимо физической нагрузки, у вас же существует и строгий рацион питания?","type":"paragraph"},{"html":"<strong>Екатерина: </strong>Строгого рациона питания у меня нет и никогда не было. Это не значит, что нужно на меня ровняться. Просто, если я не ем, у меня нет никаких сил продолжать работу. Стараюсь прислушиваться к своему организму. Если мне нужен шоколад, я ем его. Конечно, нужно всегда иметь «золотую середину» и не перегибать. Но по чуть-чуть можно все с такими нагрузками.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Где вам посчастливилось выступать?","type":"paragraph"},{"html":"<strong>Екатерина: </strong>В России я работала в Михайловском театре, Мариинском театре. За время работы там мы много гастролировали и выступали на лучших мировых площадках: в Европе, Америке, Азии, так же ездили и по России.<br />Позже я была приглашена в труппу Universal Ballet Company в Сеуле, Южная Корея. Проработала там 3.5 года и переехала в Лондон.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>А сколько работали в Лондоне?","type":"paragraph"},{"html":"<strong>Екатерина: </strong>В Лондоне успела поработать меньше года, так как началась пандемия. Во время пандемии, оказавшись в России, продолжала работать с ними онлайн. Это длилось еще довольно долго. Сейчас они продолжают ко мне обращаться, как к эксперту, по каким-то вопросам.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Насколько долго готовится программа для выступления? Кто помогает ее придумывать и воплощать в жизнь?","type":"paragraph"},{"html":"<strong>Екатерина: </strong>Нет определенного срока подготовки. Все зависит от партии, которую ты исполняешь. Также зависит от самого балета. Готовится ли премьера или это текущий спектакль в репертуаре. Бывали случаи, когда кого-то надо было срочно заменить и я «влетала» в партию за один день. Это своего рода проверка артиста на прочность. Не все проходят, так называемый, тест. Такое довольно часто случается в театрах. По-хорошему, большая партия готовится несколько месяцев, так же, как и премьера спектакля. Но далеко не всегда получается именно так.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Я знаю, что вы создали свою студию балета. Расскажите о ней.","type":"paragraph"},{"html":"<strong>Екатерина: </strong>Да, верно. Называется «Ballet World». Создала я ее в тот момент, когда началась Пандемия. Я оказалась в России, когда перекрыли сообщение между странами, а позже и между городами.<br />Когда я работала в Сеуле и Лондоне, у меня было время на параллельные дела и я, чтобы не терять время зря, начала там давать уроки для взрослых, для любителей. На мое удивление желающих там было невероятно много. На моих занятиях зал был переполнен людьми. Я поняла, что, действительно, много тех, кто хочет заниматься даже во взрослом возрасте. Те, кто когда-то мечтал заниматься балетом, танцевать, либо тех, кто занимался, но по какой-то причине не смог продолжать, а мечта и любовь к балету осталась. Это великое удовольствие и счастье давать людям возможность воплотить мечту сейчас. Видеть их «горящие» благодарные глаза, ни с чем не сравнимый обмен энергией на занятиях (разве что можно сравнить с тем чувством, когда ты на сцене). Люди в этом возрасте идут сознательно, обычно они знают чего хотят, у них есть цель и это прекрасно, потому что вы сразу оказываетесь на «одной волне».","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Чем она отличается от других российских студии? <br /><strong>Екатерина: </strong>Моя студия от других отличается тем, что мы проводим занятия преимущественно в мини-группах, до шести человек. Это моя принципиальная позиция, так как люди приходят за результатом. Для этого нужно успеть уделить внимание к каждому ученику. Это невозможно сделать в группах из двадцати и более человек. У нас бывают случаи, когда набирается больше учеников на занятиях, но я стараюсь сразу принимать меры, например, увеличивать количество занятий, чтобы все могли заниматься в комфортной остановке.","type":"paragraph"},{"html":"Плюс, у меня прекрасные профессиональные преподаватели, которые также являются солистами балета лучших театров Санкт-Петербурга. Это о многом говорит. К сожалению, не каждая студия может похвастаться уровнем и компетенцией педагогов, что приводит к большим проблемам и даже травмам. У нас были случаи, когда приходили клиенты к нам после таких жутких историй.<br />Мы работаем с телом, поэтому главная составляющая балетной студии - профессионализм педагогов. К тому же, мои педагоги замечательные воспитанные люди. Всегда помогут, подскажут и поддержат. Наши ученики их обожают. Я ими очень дорожу.<br />Также у нас очень удобная система записи, оплаты. Это мелочь, но она тоже очень важна. Клиентам не надо звонить администратору, чтобы получить ответ на свой вопрос, у них вся информация и весь функционал всегда под рукой. Это тоже важно для современных реалий в части экономии времени.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Как при вашей творческой натуре получилось создать такой мощный бизнес?","type":"paragraph"},{"html":"<strong>Екатерина: </strong>Вы знаете, это тоже своего рода творческий процесс. Для этого нужна фантазия, креативность, надо очень хорошо понимать и представлять как продавать, анализировать поведение потенциальных клиентов, ставить себя на их место. Нужно постараться прочувствовать почему то или иное предложение их не устраивает или не интересует. Все, как в театре, когда ты «проживаешь» жизнь своего персонажа. Подумать, что ему было бы интересно. Это и психология, и творчество, и спортивный интерес. В нашей профессии так же. Если что-то не получается, идешь до конца, не сдаваясь, пока не получится. <br />Создавать интересные активности, сделать так, чтобы это были не просто занятия, а давать возможность развития, мотивировать, вдохновлять. Как можно это делать, если ты сам не любишь или не знаешь то, что делаешь? По-настоящему хорошо это может делать человек, который очень хорошо знает свое дело, а главное, очень его любит.","type":"paragraph"},{"html":"Для меня не было цели заработать, это первая мысль и ассоциация, которая обычно приходит при слове «Бизнес». У меня просто стояла цель продолжать заниматься тем, что я люблю и распространить это в массы.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>В связи с санкциями и мировым кризисом, российский балет пострадает? Или же мы редко выступали на мировых площадках?","type":"paragraph"},{"html":"<strong>Екатерина: </strong>Мы очень часто выступали за границей. Русский балет прославлен на весь мир. Наших гастролей всегда и везде ждали и продолжают ждать с нетерпением. Все спектакли проходят с аншлагом. Билеты зачастую раскупаются за месяцы вперед.<br />Русский балет от санкций не пострадает, а иностранный зритель, к сожалению, очень многое теряет. Насколько я знаю, в мире это воспринимается, как огромная потеря. Но хочется верить, что это не навсегда.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Не скучаете по большой сцене?","type":"paragraph"},{"html":"<strong>Екатерина: </strong>По сцене скучаешь всегда, безусловно. Сцена - это тот неповторимый мир, который ничего не может заменить. Нет ничего подобного. Это состояние, когда все бытовые моменты забываются, ты перевоплощаешься, становишься не собой, забываешь обо всем. Делая шаг на сцену, ты оказываешься в настоящем волшебстве. А взаимная передача энергией с публикой заряжает надолго вперед. В жизни, на улице, ты такой же, как все, сливаешься с толпой. На сцене ты имеешь право на свое «слово», иногда даже получается заставить людей задуматься, а иногда и принять решение изменить что-то. Это невероятно.<br />С другой стороны, это было только моим решением, перестать выступать на большой сцене. Связано это не со сценой, как таковой, а с системой в театрах. Я просто устала бороться с тем, что побороть не могу. Моя жизнь стала превращаться не в творчество, а в бесконечную войну с обстоятельствами. Поймала себя на мысли, что это не то, что я хочу делать. Работа в театре больше не приносит мне удовольствие. Я хочу заниматься настоящим творчеством и искусством, а не бесконечной борьбой с «ветряными мельницами».","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Каким вы видите российский балет через 10 лет?","type":"paragraph"},{"html":"<strong>Екатерина: </strong>Это сложный вопрос. Однозначно ответить на него тоже сложно.<br />От санкций мы точно не зависим в нашем развитии, а от других вещей, пожалуй. К моему сожалению, я все чаще вижу спектакли недостойного качества, в тех прославленных театрах, в которых они идут.<br />Артисты выходят на сцену недостаточно подготовленными, недостаточно зрелыми в тех партиях, в которых они выступают. <br />На данный момент, среди молодежи в театрах очень не хватает таких артистов, как Ульяна Лопаткина, Диана Вишнева, Светлана Захарова, Алтынай Асылмуратова. С течением времени я вынуждена признать, что балет, в лице представляющих его артистов, не развивается, а наоборот. <br />Достойной замены пока нет.<br />Сложно сказать, с чем именно это связано. Театр - это очень сложная система и одной точной причины точно нет. Это совокупность факторов, которые влияют на это. Но в жизни всегда есть взлеты и падения. Надеюсь, что через десять лет будет очередной взлет.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Екатерина, спасибо вам за очень интересный разговор. Скажите напоследок пару слов нашим читателям.","type":"paragraph"},{"html":"<strong>Екатерина: </strong>Хочу сказать, чтобы люди не переставали видеть прекрасное везде, что нас окружает. Развивать в себе чувство прекрасного. Ходить на балет, оперу, в филармонию, в музеи. Слушать хорошую музыку, читать хорошие книги, развиваться культурно. В мире современных технологий это уходит на второй план, хотелось бы всем пожелать не терять это чувство прекрасного.<br />И, конечно, я приглашаю всех на занятия в мою студию. Буду рада сделать еще кого-то хоть на чуточку счастливее.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqv8hh00kauktata6bvmpp"},{"mediaId":"cmrmqv8qb00kbukta2v3yuy0c"},{"mediaId":"cmrmqv9vf00kcukta2l487z0f"},{"mediaId":"cmrmqva6f00kdukta5avbwt2l"}]}]'::jsonb,'cmrmqv80b00k9uktamh5diwbo','cmrm8kz36000ckwtabqfh3f4h','cmrm8kzc0000fkwtauqqmw2lw','cmrmpdrom0000sstarkqxwts4','2022-06-17T06:00:00.000Z'::timestamp,NULL,NULL,NULL,457,'/sobytija/teatr/457-ekaterina-krasjuk-na-scene-ty-imeesh-pravo-na-svoe-slovo.html','2026-07-15T21:01:58.686Z'::timestamp,'2026-07-16T13:59:10.108Z'::timestamp,'''-7'':368C ''10'':1650C ''11'':352C,380C ''2'':57C ''3.5'':596C ''4'':144C ''5'':367C ''7'':339C ''9'':335C ''ballet'':588C,782C ''cmrmqv8hh00kauktata6bvmpp'':1893C ''cmrmqv8qb00kbukta2v3yuy0c'':1895C ''cmrmqv9vf00kcukta2l487z0f'':1897C ''cmrmqva6f00kdukta5avbwt2l'':1899C ''compani'':589C ''design'':281C ''esqu'':88C,124C,242C,298C,458C,540C,605C,658C,763C,958C,1177C,1369C,1460C,1643C,1798C ''galleri'':1891C ''paragraph'':69C,86C,97C,122C,133C,240C,250C,296C,316C,456C,473C,538C,546C,603C,612C,656C,674C,761C,776C,956C,1042C,1175C,1189C,1331C,1367C,1389C,1458C,1467C,1641C,1653C,1796C,1813C,1889C ''product'':280C ''univers'':587C ''world'':783C ''абсолютн'':324C ''авторск'':65C ''администратор'':1147C ''аз'':574C ''академ'':204C,219C,331C,422C ''активн'':1281C ''алтына'':1731C ''америк'':573C ''анализирова'':1213C ''аншлаг'':1419C ''артист'':724C,1697C,1723C,1745C ''ассоциац'':1343C ''асылмуратов'':1732C ''балерин'':11B,18C,314C ''балет'':49C,84C,131C,136C,206C,258C,299C,692C,771C,871C,891C,1054C,1378C,1399C,1427C,1648C,1740C,1835C ''балетн'':186C,237C,1103C ''безусловн'':1474C ''бесконечн'':1602C,1635C ''бизнес'':1187C,1349C ''билет'':1420C ''благодарн'':907C ''больш'':61C,742C,1078C,1464C,1569C ''борот'':1586C ''борьб'':78C,1636C ''буд'':1877C ''быва'':376C,389C,410C,702C,1016C ''бытов'':1492C ''ваганов'':210C ''важн'':1142C,1166C ''ваш'':92C,128C,1180C ''вдохновля'':1295C ''ве'':1159C,1402C ''везд'':1408C,1824C ''велик'':894C ''вер'':1452C ''верн'':780C ''вернувш'':36C ''верхов'':264C ''весн'':104C ''ветрян'':1638C ''