INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqte3t00chuktab1pu58ny','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'"Выбирай ЖИЗНЬ" - 13 советов от 60-летних тридцатилетним','Наша жизнь состоит из массы историй, веселых и грустных событий, ошибок и попыток начать все сначала.','542-vybiraj-zhizn-13-sovetov-ot-60-letnih-tridcatiletnim','[{"html":"Наша жизнь состоит из массы историй, веселых и грустных событий, ошибок и попыток начать все сначала. Чтобы мы изменили в 60 лет? А знаем ли мы как жить в 30? Казалось бы, уже собранный багаж опыта, кричит да, но, а что мы имеем в действительности?","type":"paragraph"},{"html":"Возрастные модели агентства Елены Лукмановой с высоты прожитого опыта, дали 13 советов 30-летним женщинам! Читаем, вдохновляемся и учимся!","type":"paragraph"}]'::jsonb,'cmrmqte0q00cgukta6mzhwgbr','cmrm8kzli000ikwtafbw33jnj','cmrm8kzoi000kkwtachb0mt9u','cmrmpdrom0000sstarkqxwts4','2022-09-14T06:00:00.000Z'::timestamp,NULL,NULL,NULL,542,'/persona/dostizhenija/542-vybiraj-zhizn-13-sovetov-ot-60-letnih-tridcatiletnim.html','2026-07-15T21:00:30.377Z'::timestamp,'2026-07-16T13:58:09.355Z'::timestamp,'''13'':3A,83C ''30'':54C,85C ''60'':6A,45C ''paragraph'':71C,93C ''агентств'':75C ''багаж'':59C ''вдохновля'':89C ''весел'':15B,31C ''возрастн'':73C ''выбира'':1A ''высот'':79C ''грустн'':17B,33C ''дал'':82C ''действительн'':69C ''ел'':76C ''женщин'':87C ''жизн'':2A,10B,26C ''жит'':52C ''зна'':48C ''измен'':43C ''име'':67C ''истор'':14B,30C ''каза'':55C ''крич'':61C ''лет'':46C ''летн'':7A,86C ''лукманов'':77C ''масс'':13B,29C ''модел'':74C ''нача'':22B,38C ''наш'':9B,25C ''опыт'':60C,81C ''ошибок'':19B,35C ''попыток'':21B,37C ''прожит'':80C ''снача'':24B,40C ''собра'':58C ''событ'':18B,34C ''совет'':4A,84C ''состо'':11B,27C ''тридцатилетн'':8A ''уч'':91C ''чита'':88C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqr0fn0039uktabftrpws3','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Работа на дому: как совмещать фриланс и ребёнка','Жизнь женщины часто меняется после того, как она узнаёт, что скоро станет мамой.','633-rabota-na-domu-kak-sovmeschat-frilans-i-rebenka','[{"html":"Жизнь женщины часто меняется после того, как она узнаёт, что скоро станет мамой. И многих в этот период начинает волновать вопрос о дальнейшей карьере. Девушки хотят работать, но при этом понимают, что делать это полноценно они смогут только во время беременности. Но после родов работу придется отложить, так как уход за ребенком встанет на первое место. Из-за этого многие женщины уходят во фриланс. Но у многих из них возникает вопрос: как же совмещать работу и дом в таком случае? Уходя в декрет, женщина, решившая начать самостоятельное дело, задается целью организовать всё так, чтобы в дальнейшем совмещать работу и дом. Во время беременности будущая мама представляет идеальную картинку, где она все успевает и со всем справляется. Но после родов часто этот план рушится частично или полностью. Чтобы этого избежать и все-таки грамотно выстроить работу на дому и воспитание ребенка, нужно организовать не только себя, но и ребенка.","type":"paragraph"},{"html":"<br /><b>Как настроить себя на работу из дома</b>","type":"paragraph"},{"html":"<i>1. Ежеминутная уборка дома отменяется</i><br />Если у вас дома всегда была чистота, вы убирались сразу же, как только видели хоть одну пылинку на полке, то с появлением ребенка постоянная уборка невозможна. Конечно, порядок нужно соблюдать, но не стоит зацикливаться на этом и сходить с ума, если где-то<br />не убрано. Нужно начать проще относиться к тому, что не всегда возможна идеальная чистота. То время, которое вы ранее тратили на нескончаемую уборку, можно направить на работу. Также свои домашние обязанности, по возможности, можно делегировать профессионалам. Большой спектр клининговых служб сделают за вас уборку.<br /><i>2. Сон для ребенка, работа для мамы</i>","type":"paragraph"},{"html":"Старайтесь уделять время работе, пока ваш ребенок спит. Первые месяцы жизни младенцы спят большую часть суток. Это свободное время можно провести за решением рабочих задач. Даже если сон у ребенка не спокойный, то какой-то промежуток времени точно найдется на необходимые действия. Также маленькие дети спят во время прогулок на свежем воздухе. Это время тоже можно провести с пользой. Пока ребенок видит сны, вы спокойно работаете через телефон, если это позволяет ваша профессия.<br /><i>3. Просить помощь — не стыдно!</i><br />Многие мамочки придерживаются мнения, что «Я все должна делать сама. Мой дом, мой ребенок — это только мои обязанности. Перекладывать на других свои заботы и проблемы я не должна». Но эти утверждения не верны. Никто не говорит о том, что нужно все полностью переложить на плечи близких и наслаждаться беззаботностью. Нет. Но иногда, когда помощь действительно необходима, можно обратиться к родным. Например, если вы не успеваете сходить в магазин за продуктами, или нет времени приготовить ужин. За это время, которое вам нужно было бы потратить на домашние дела, можно поработать. И не нужно<br />переживать, что что-то будет не сделано. Также не стоит отказываться от помощи, когда её предлагают.","type":"paragraph"},{"html":"<br /><b>Как организовать ребенка</b>","type":"paragraph"},{"html":"<i>1. Самостоятельный ребенок</i><br />И это не значит, что с первого месяца жизни он должен сам добывать себе еду, переодеваться и никого не беспокоить. Всем ясно, что первое время ребенок полностью зависит от родителей, в большей мере от мамы. И понятно, что в 2 месяца научить его<br />самостоятельности невозможно. Но начиная с того времени, когда ребенок становится заинтересованным в том, чтобы самостоятельно делать какие-то примитивные вещи, нужно позволить ему это делать. В тот момент, когда вы начинаете кормить ребенка со столовых приборов, дайте ему научиться самому есть ложкой или вилкой. Да, оставлять его одного нельзя, но, находясь просто рядом, можно уделить время работе. Или со временем научить ребенка складывать свои вещи, убирать за собой игрушки. А ещё лучше, если вы начнете приобщать его к домашним обязанностям. Это в будущем будет полезно и ему самому, и вам, так как дополнительное время можно потратить на рабочие моменты.<br /><i>2. Приобщение к социуму</i><br />Некоторые родители против того, чтобы ребенок ходил в дошкольные учреждения. Они считают, что там дети будут без должного контроля и внимания. Но в таком случае, оставляя ребенка дома, его лишают полноценной адаптации в обществе. К тому же ясельки и детские сады — отличный вариант для работающих родителей. Время, пока ребенок находится под присмотром других, мама-фрилансер может поработать, ни на что не отвлекаясь. Также можно воспользоваться услугами различных детских центров и кружков. Каждый день их посещать, конечно, сложно. Но в дни, когда, например, нужно выполнить сложную работу, можно отправить туда ребенка. Это хорошая альтернатива детским садам.<br /><i>3. Бабушки и дедушки всегда помогут</i>","type":"paragraph"},{"html":"Многие мамы не хотят оставлять своих детей со своими родителями, так как возникает ощущение, что «кроме меня никто с моим ребенком не справится». Но бабушки и дедушки это те люди, которые вырастили вас. Неужели, они не смогут провести пару часов со своим внуком или внучкой. Ребенок также должен видеть рядом с собой других членов семьи. Это позволяет ему постепенно внедряться в социум, понимать, что вокруг есть другие люди, а не только родители. За время нахождения ребенка у бабушек и дедушек, у мамы есть возможность решить рабочие вопросы.","type":"paragraph"},{"html":"О своем решении начать работу на себя поделилась Татьяна Поремская. Она много лет работала на металлургическом предприятии. И только с третьим ребенком, которому уже семь лет, она пришла к мнению, что работать на фрилансе — это лучший вариант.","type":"paragraph"},{"html":"«Я захотела облегчить себе жизнь. Привычный сменный график стал для меня труднореализуемым. Поэтому в свои 43 года решила стать самозанятой. Двое старших детей уже выросли, а вот младшей всего семь лет. Поначалу было сложно распланировать свой день, выделить время для работы. Хоть ребенок и ходит в школу, но лишь до 12 часов дня. Но за счет дополнительных занятий, которые дочка посещает, и помощи родственников, я смогла выстроить удобный для себя график, научилась совмещать работу и дом».","type":"paragraph"},{"html":"<br />Совмещать работу из дома и присмотр за детьми маме непросто. Это требует перестройки своего графика, освоение новых функций, объединения нескольких дел в одно, фокусирования на нескольких задачах одновременно и так далее. Главное — выработать для себя наилучший план по реализации работы на фрилансе. Даже если первое время будет что-то не получаться, с течением времени все станет гармоничным.","type":"paragraph"},{"html":"<i>Текст: Евгения Макарова</i>","type":"paragraph"}]'::jsonb,'cmrmqr0e60038ukta3bprmujz','cmrm8kzpw000mkwtaocyn5161','cmrm8kzra000okwtaqek3edwq','cmrmpdrom0000sstarkqxwts4','2024-01-09T06:00:00.000Z'::timestamp,NULL,NULL,NULL,633,'/psihologija/samosovershenstvovanie/633-rabota-na-domu-kak-sovmeschat-frilans-i-rebenka.html','2026-07-15T20:58:39.347Z'::timestamp,'2026-07-16T13:57:00.037Z'::timestamp,'''1'':185C,485C ''12'':920C ''2'':278C,527C,631C ''3'':362C,731C ''43'':885C ''paragraph'':173C,183C,286C,477C,483C,738C,828C,868C,947C,1008C,1014C ''адаптац'':666C ''альтернатив'':728C ''бабушек'':817C ''бабушк'':732C,764C ''беззаботн'':415C ''беремен'':62C,125C ''беспоко'':507C ''близк'':412C ''больш'':270C,301C,519C ''будут'':650C ''будущ'':126C,614C ''вариант'':677C,866C ''ваш'':293C,360C ''верн'':399C ''вещ'':551C,596C ''вид'':350C ''видел'