44C ''фокусирован'':972C ''фриланс'':6A,86C,863C,990C ''фрилансер'':690C ''функц'':966C ''ход'':641C,914C ''хорош'':727C ''хот'':47C,743C ''цел'':112C ''центр'':704C ''час'':779C,921C ''част'':11B,24C,142C,302C ''частичн'':146C ''чистот'':196C,247C ''член'':793C ''что-т'':461C,996C ''школ'':916C ''эт'':55C,304C,341C,358C,381C,443C,489C,555C,612C,726C,767C,795C,864C,959C ''ясельк'':672C ''ясн'':509C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqedqd0028pota4q6o4dpw','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Надежда Мамаева о первом публичном конфликте с мужем','История скандального развода Павла Мамаева и Аланы Мамаевой, новая семья с Надеждой Санько, футбольная школа в Дубае и возвращение в Москву.','676-nadezhda-mamaeva-o-pervom-publichnom-konflikte-s-muzhem-i-otkaze-zhit-v-dubae','[{"html":"Многие помнят скандальный развод футболиста Павла Мамаева и Аланы Мамаевой. Практически сразу после развода Павел женился на подруге Аланы, Надежде Санько. Женщина пыталась транслировать идеальную жизнь, полную взаимопонимания, любви и уважения в новой семье. У пары родился сын и скоро появится еще ребенок, также они воспитывают сына от первого брака Санько. Долгое время звездная чета жила в Дубае, где Мамаев открыл футбольную школу с Федором Смоловым, и совсем недавно вернулась в Москву.","type":"paragraph"},{"html":"Но Павлу Москва не приглянулась и он намерен снова вернуться в Эмираты, на что его жена отреагировала однозначно, впервые вынеся на публику несогласие со спортсменом.","type":"paragraph"},{"html":"\"Я не знаю, что должно случиться, чтобы я опять согласилась жить в Дубае. Просто приезжать ненадолго - пожалуйста, но жить! Если что, Павел и сам может летать в академию, когда ему нужно. Я же летала в Москву каждый месяц, а иногда и по два раза. Хотя Абдаллах и Тимофей там кайфовали, но они дети, их можно понять\", - поделилась Надежда.","type":"paragraph"},{"html":"Значит ли это, что семья станет жить на 2 страны и у каждого будет своя жизнь. Помня курьезные истории из жизни Мамаева в прошлом браке, стоит предполагать, что мужчина явно скучать не будет!","type":"paragraph"}]'::jsonb,'cmrmqednt0027potak08dwz6d','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-08-11T06:00:00.000Z'::timestamp,NULL,NULL,NULL,676,'/v-mire/676-nadezhda-mamaeva-o-pervom-publichnom-konflikte-s-muzhem-i-otkaze-zhit-v-dubae.html','2026-07-15T20:48:50.053Z'::timestamp,'2026-07-16T13:56:30.313Z'::timestamp,'''2'':202C ''paragraph'':103C,131C,192C,228C ''абдалл'':178C ''академ'':160C ''ала'':15B,38C,48C ''брак'':79C,218C ''вернул'':99C ''вернут'':114C ''взаимопониман'':57C ''возвращен'':27B ''воспитыва'':75C ''вперв'':123C ''врем'':82C ''вын'':124C ''дет'':185C ''долг'':81C ''должн'':137C ''дуба'':25B,87C,145C ''жен'':45C,120C ''женщин'':51C ''жизн'':55C,209C,214C ''жил'':85C ''жит'':143C,151C,200C ''звездн'':83C ''зна'':135C ''знач'':194C ''идеальн'':54C ''истор'':9B,212C ''кажд'':169C,206C ''кайфова'':182C ''конфликт'':6A ''курьезн'':211C ''лета'':158C,166C ''любв'':58C ''мама'':89C ''мамаев'':2A,13B,16B,36C,39C,215C ''месяц'':170C ''мног'':30C ''москв'':29B,101C,107C,168C ''муж'':8A ''мужчин'':222C ''надежд'':1A,20B,49C,190C ''намер'':112C ''недавн'':98C ''ненадолг'':148C ''несоглас'':127C ''нов'':17B,62C ''нужн'':163C ''однозначн'':122C ''откр'':90C ''отреагирова'':121C ''павел'':44C,154C ''павл'':12B,35C,106C ''пар'':65C ''перв'':4A,78C ''подел'':189C ''подруг'':47C ''пожалуйст'':149C ''полн'':56C ''помн'':31C,210C ''поня'':188C ''появ'':70C ''практическ'':40C ''предполага'':220C ''приглянул'':109C ''приезжа'':147C ''прост'':146C ''прошл'':217C ''публик'':126C ''публичн'':5A ''пыта'':52C ''раз'':176C ''развод'':11B,33C,43C ''ребенок'':72C ''род'':66C ''саньк'':21B,50C,80C ''сво'':208C ''сем'':18B,63C,198C ''скандальн'':10B,32C ''скор'':69C ''скуча'':224C ''случ'':138C ''смолов'':95C ''снов'':113C ''соглас'':142C ''спортсмен'':129C ''сраз'':41C ''станет'':199C ''сто'':219C ''стран'':203C ''сын'':67C,76C ''такж'':73C ''тимоф'':180C ''транслирова'':53C ''уважен'':60C ''федор'':94C ''футболист'':34C ''футбольн'':22B,91C ''хот'':177C ''чет'':84C ''школ'':23B,92C ''эмират'':116C ''эт'':196C ''явн'':223C'::tsvector) ON CONFLI