INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqs6d1007iuktahml450jc','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'25 февраля Fashion bitva в Казани в Ак Барс Арене','25 февраля в Ак Барс Арене пройдет региональный этап конкурса дизайнеров Fashion bitva.','592-25-fevralja-fashion-bitva-v-kazani-v-ak-bars-arene','[{"html":"<strong>25 февраля в Ак Барс Арене пройдет региональный этап конкурса дизайнеров </strong><strong>Fashion </strong><strong>bitva. Свои коллекции покажут дизайнеры Татарстана и ближайших регионов.</strong>","type":"paragraph"},{"html":"Организаторы конкурса решили поэкспериментировать с главным элементом мероприятия – подиумом, который предстанет в весьма необычном варианте. В дополнение к белоснежному глянцу, на подиуме появятся кубы, которые смогут разнообразить шоу каждого дизайнера.","type":"paragraph"},{"html":"Дополнит конкурс и выставка российских художников, которые через призму картин расскажут свое видение о моде будущего – главной теме показов.","type":"paragraph"},{"html":"Мода спустя 10 лет – достаточно обсуждаемая тема многие годы. Участники показа пытаются опередить время уже не первый год. И для каждого дизайнера это нелегкий труд.","type":"paragraph"},{"html":"<strong>«Особое внимание я уделила тканям и цветам моделей, которые идеально передают лоск и богемность коллекции» - </strong>рассказывает Виктория Кулева, участница проекта в Казани. Ее коллекция получила весьма необычное название «Коллекция для женщин, которым нравится быть женщинами».","type":"paragraph"},{"html":"<strong>«Сочетание натурального шелка и органзы с кожей передадут исключительную женскую способность быть легкой, нежной, утонченной и одновременно сильной, уверенной, динамичной» - </strong>дополняет Виктория.","type":"paragraph"},{"html":"Наталья Пестова придерживается также темы женщины, но для нее она предстает в образе деловой, серьезной, берущей все в свои руки, яркой, харизматичной и дерзкой.","type":"paragraph"},{"html":"<strong>«В коллекции использованы разные фактуры и формы, соединены жесткость и плавность линий - все это подчеркивает разнообразие женской натуры»</strong> - комментирует коллекцию Наталья.","type":"paragraph"},{"html":"В конкурсе также будут представлены детские и подростковые коллекции.","type":"paragraph"},{"html":"Внеконкурсный показ от Зленко Светланы перенесет нас в сказку, где перед гостями мероприятия предстанут маленькие феи.","type":"paragraph"},{"html":"Новая коллекция<strong> «</strong>Blooming» выполнена дизайнером в нежных красках в сочетании с новыми формами, принтами и фактурами.","type":"paragraph"},{"html":"Казанский дизайнер Светлана Полякова покажет креативную подростковую коллекцию, в основе которой лежит апсайклинг - творческая переработка и добавление креативности в вещи из «бабушкиного сундука».","type":"paragraph"},{"html":"Желаем всем дизайнером творческого вдохновения, а гостям наслаждения от нашего мероприятия!","type":"paragraph"},{"html":"<em>Место проведения: Ак Барс Арена, проспект Ямашева, 115А</em><em><br />Сбор гостей: 17:00<br />Dress code: Black Tie</em>","type":"paragraph"},{"html":"<em>Купить билет:</em><em> fashionbitva.ru </em>","type":"paragraph"},{"type":"image","mediaId":"cmrmqs6br007huktaosmbtui9"}]'::jsonb,'cmrmqs62b007guktayqztq0ix','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2023-02-12T06:00:00.000Z'::timestamp,NULL,NULL,NULL,592,'/projects-esque/fashion-bitva/592-25-fevralja-fashion-bitva-v-kazani-v-ak-bars-arene.html','2026-07-15T20:59:33.685Z'::timestamp,'2026-07-16T13:57:30.724Z'::timestamp,'''00'':346C ''10'':105C ''115а'':342C ''17'':345C ''25'':1A,11B,24C ''bitva'':4A,23B,36C ''black'':349C ''bloom'':278C ''cmrmqs6br007huktaosmbtui9'':362C ''code'':348C ''dress'':347C ''fashion'':3A,22B,35C ''fashionbitva.ru'':356C ''imag