INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqr653003suktazlw4inta','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Как дизайнеру одежды представить свои изделия в универмаге?','14 декабря в 17:00 организаторы X Всероссийского конкурса дизайнеров одежды PROfashion Masters в рамках образовательной программы проведут онлайн-сессию на тему: “Как начинающему дизайнеру попасть в универмаг?”.','628-kak-dizajneru-odezhdy-predstavit-svoi-izdelija-v-univermage','[{"html":"14 декабря в 17:00 организаторы X Всероссийского конкурса дизайнеров одежды PROfashion Masters в рамках образовательной программы проведут онлайн-сессию на тему: “Как начинающему дизайнеру попасть в универмаг?”. К прямому эфиру присоединятся члены жюри конкурса – основатели универмагов и концепт-сторов локальных брендов. Они расскажут, как дизайнерам договориться с ними о сотрудничестве,на каких условиях оно будет проходить и каким критериям должны отвечать коллекции бренда, чтобы заинтересовать<br />ритейлеров. Все желающие смогут задать вопрос в комментариях к онлайн- трансляции и в любой социальной сети журнала PROfashion.","type":"paragraph"},{"html":"<br /><u><i>В качестве спикеров приглашены:</i></u><br />●Александр Перемятов – президент Magic Group, создатель универмагов российских дизайнеров SLAVA и «Йармарка»;<br />●Николай Константинов – генеральный директор универмага Trend Island и основатель универмагов Телеграф;<br />●Святослав Захаров – руководитель бренда RASKROI.","type":"paragraph"},{"html":"<br /><b>Присоединиться к прямому эфиру можно по ссылке:</b><br /><b><a href=\"https://www.youtube.com/watch?v=aZx7ipdySOA\" target=\"_blank\" rel=\"noopener noreferrer\">https://www.youtube.com/watch?v=aZx7ipdySOA</a></b>","type":"paragraph"}]'::jsonb,'cmrmqr63u003ruktatz425f3v','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2023-12-08T06:00:00.000Z'::timestamp,NULL,NULL,NULL,628,'/fashion/news-2/628-kak-dizajneru-odezhdy-predstavit-svoi-izdelija-v-univermage.html','2026-07-15T20:58:46.743Z'::timestamp,'2026-07-16T13:57:03.009Z'::timestamp,'''/watch?v=azx7ipdysoa'':171C ''00'':13B,42C ''14'':9B,38C ''17'':12B,41C ''group'':135C ''island'':149C ''magic'':134C ''master'':21B,50C ''paragraph'':125C,160C,173C ''profashion'':20B,49C,123C ''raskroi'':158C ''slava'':140C ''trend'':148C ''www.youtube.com'':170C ''www.youtube.com/watch?v=azx7ipdysoa'':169C ''x'':15B,44C ''александр'':131C ''бренд'':81C,103C,157C ''вопрос'':111C ''всероссийск'':16B,45C ''генеральн'':145C ''декабр'':10B,39C ''дизайнер'':2A,18B,34B,47C,63C,85C,139C ''директор'':146C ''договор'':86C ''должн'':100C ''жела'':108C ''журна'':122C ''жюр'':72C ''зада'':110C ''заинтересова'':105C ''захар'':155C ''издел'':6A ''йармарк'':142C ''как'':92C,98C ''качеств'':128C ''коллекц'':102C ''комментар'':113C ''конкурс'':17B,46C,73C ''константин'':144C ''концепт'':78C ''концепт-стор'':77C ''критер'':99C ''локальн'':80C ''люб'':119C ''начина'':33B,62C ''никола'':143C ''ним'':88C ''образовательн'':24B,53C ''одежд'':3A,19B,48C ''он'':94C ''онлайн'':28B,57C,115C ''онлайн-сесс'':27B,56C ''организатор'':14B,43C ''основател'':74C,151C ''отвеча'':101C ''перемят'':132C ''попаст'':35B,64C ''представ'':4A ''президент'':133C ''приглаш'':130C ''присоедин'':70C,162C ''проведут'':26B,55C ''программ'':25B,54C ''проход'':96C ''прям'':68C,164C ''рамк'':23B,52C ''расскажут'':83C ''ритейлер'':106C ''российск'':138C ''руководител'':156C ''сво'':5A ''святосла'':154C ''сесс'':29B,58C ''сет'':121C ''смогут'':109C ''создател'':136C ''сотрудничеств'':90C ''социальн'':120C ''спикер'':129C ''ссылк'':168C ''стор'':79C ''телеграф'':153C ''тем'':31B,60C ''трансляц'':116C ''универмаг'':8A,37B,66C,75C,137C,147C,152C ''услов'':93C ''член'':71C ''эфир'':69C,165C'::tsvector) ON CONFLICT (id) DO UPDATE SET "ty