INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsqy7009huktagql2djrt','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Илон Маск начал продавать свой парфюм','Илон Маск написал в твиттере, что за несколько часов продал 10 тысяч флаконов собственного парфюма Burnt Hair.','575-ilon-mask-nachal-prodavat-svoj-parfjum','[{"html":"<b>За несколько часов было продано 10 тысяч флаконов парфюма Илона Маска \"Burnt Hair\". Об этом миллиардер написал в своём твиттере.</b>","type":"paragraph"},{"html":"Ранее Илон Маск опубликовал шуточный твит о том, что создаст парфюм с ароматом жжёных волос. Затем он заменил свой статус в твиттере на \"Продавец парфюмерии\". Шутка оказалась востребованным продуктом, её стоимость составила $100. Парфюм продаётся под одним из брендов Илона Маска The Boring Company.","type":"paragraph"},{"html":"Для флакона был выбран красный цвет. Оформить предзаказ можно на сайте марки. Парфюм начнут поставлять клиентам в начале следующего года. Парфюм уже принёс компании Илона Маска около миллиона долларов. Предприниматель отметил, что имя “Маск” обязывало его заняться парфюмерией. Так как musk на английском означает мускус.","type":"paragraph"},{"html":"Ранее шуточные релизы Илона Маска уже становились популярными товарами. Так, после твитов основателя его компания продавала огнемёты и укороченные шорты.","type":"paragraph"},{"type":"image","mediaId":"cmrmqsqwc009guktavvxd37ff"}]'::jsonb,'cmrmqsqi9009fuktabigqgaz1','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyxz0009kwtay5bvzu16','cmrmpdrom0000sstarkqxwts4','2022-10-12T06:00:00.000Z'::timestamp,NULL,NULL,NULL,575,'/beauty/news-3/575-ilon-mask-nachal-prodavat-svoj-parfjum.html','2026-07-15T21:00:00.367Z'::timestamp,'2026-07-16T13:57:43.006Z'::timestamp,'''10'':17B,29C ''100'':79C ''bore'':89C ''burnt'':22B,35C ''cmrmq