INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqx9xq00q7uktan2d6hey7','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'«И просто так…»: вся правда о жизни женщин за 50','Финальная серия «И просто так…» вышла совсем недавно, а исполнительница роли Кэрри Брэдшоу Сара Джессика Паркер уже с радостью дала согласие на съемки в его продолжении, заявленном накануне сценаристом проекта Майклом Па','399-i-prosto-tak-neprijazn-vozmuschenie-i-ottorzhenie','[{"html":"Финальная серия «И просто так…» вышла совсем недавно, а исполнительница роли Кэрри Брэдшоу Сара Джессика Паркер уже с радостью дала согласие на съемки в его продолжении, заявленном накануне сценаристом проекта Майклом Патриком Кингом. И даже поставила финальную точку в отношениях с Ким Кэтролл, которая отказалась вернуться на съемочную площадку. Сара призналась: она не готова видеть Саманту Джонс в продолжении «И просто так…» из-за окончательно обострившихся личных противоречий. Но это не единственный недостаток сериала, который хоть и стал в России самым популярным шоу на «Амедиатеке», но не сумел повторить успех оригинального «Секса в большом городе». Так ли необходимо было продолжение культовому сериалу?","type":"paragraph"},{"html":"В первом сезоне «И просто так…» мы увидели 10 серий о приключениях пятидесятилетних Кэрри, Шарлотты и Миранды в Нью-Йорке. Выход сериала был анонсирован еще в январе 2021 года: уже тогда одним из главных вопросов, волновавших фанатов, была перспектива появления Саманты Джонс в исполнении Ким Кэтролл. Прежде актриса неоднократно заявляла, что считает выход нового сезона не самой лучшей идеей. А когда ее поклонники стали строить предположения о том, почему она отказалась от появления в «И просто так...», Ким не стала пускаться в объяснения: она просто лайкнула твит с предположениями о том, что она «предпочитает ставить себя на первое место. С выходом сериала многие ее фанаты признали, что ее решение было взвешенным.","type":"paragraph"},{"html":"Отказ Ким сниматься стал не единственной проблемой «И просто так…», хотя сценаристы пытались решить и ее, заранее анонсировав появление сразу трех новых героинь вместо Саманты Джонс. С первых серий стало понятно, что сериал, создатели которого анонсировали как манифест того, что после 50 жизнь только начинается, стал жертвой амбиций его же создателей.","type":"paragraph"},{"html":"Его не назовешь удачной репрезентацией жизни женщин 50+ хотя бы потому, что главные героини сериала безнадежно отстают от повестки, хотя и активно пытаются ей соответствовать. Сценаристы проекта, безусловно, хотели угодить всем, из серии в серию поднимая вопросы расизма и гендера. Так, ребенок Шарлотты пытается понять, к какому полу хочет себя причислять, а Миранда, которая прежде за словом в карман не лезла, пытается сделать комплимент преподавателю, но в итоге ведет себя как расистка.","type":"paragraph"},{"html":"Все эти сюжетные детали создают впечатление того, что сериал соответствует всем трендам «новой этики». Но ровно до тех пор, пока в нем не появляется стереотипная русская эскортница. Вызывает вопросы и сюжетный акцент на том, что Шарлотта ищет чернокожую пару, которую можно было бы пригласить на прием, чтобы другие гости с тем же цветом кожи не чувствовали себя одиноко. Обе сцены стали причиной настоящего хейта в соцсетях, который создателям «И просто так…» так и не удалось нейтрализовать. Избавиться от этого с помощью политкорректных шуток и «они-митцвы» вместо бат-митцвы так и не удалось.","type":"paragraph"},{"html":"Поклонниц глянцевого «Секса в большом городе» может заставить недоумевать и отсутствие гламура, характерного для прежних сезонов сериала. Безусловно, далеко не все предпочитают вести светский образ жизни после 50, но героини не забывают напоминать о том, что они «уже не такие, как 20 лет назад», что звучит довольно угнетающе. Равно как и постоянное жонглирование медицинскими терминами и описанием различных заболеваний. Муж Миранды Стив, которого она (осторожно, спойлер!) оставит ближе к финалу, страдает от потери слуха и вынужден носить слуховой аппарат. Мистер Биг умирает от инфаркта уже в первой серии (сейчас этот сюжетный поворот оправдывают секс-скандалом с участием актера, которого нужно было «убрать» из сериала). Супруг Шарлотты, Гарри, страдает от проблем с мочеиспусканием, пока сама героиня записывает его на колоноскопию. Возникает неприятное ощущение, что средний возраст ассоциируется у сценаристов «И просто так…» исключительно с чередой проблем со здоровьем.","type":"paragraph"},{"html":"И так «повезло» не только мужчинам: Кэрри делают операцию на бедре, а Миранда громкогласно заявляет «Мне 55, мне надо в туалет». Получается еще один штамп с длинным списком характерных возрастных проблем, пришедшим на смену тусовкам и сексуальным приключениям. В целом, «И просто так…» изображает людей за 50 такими, какими они могут стать через 20-30 лет, что скорее вызывает неприязнь, чем желание пересмотреть его снова.","type":"paragraph"}]'::jsonb,'cmrmqx9u600q6ukta74avrqm7','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz6g000dkwtai45m48bj','cmrmpdrom0000sstarkqxwts4','2022-02-13T06:00:00.000Z'::timestamp,NULL,NULL,NULL,399,'/sobytija/kino/399-i-prosto-tak-neprijazn-vozmuschenie-i-ottorzhenie.html','2026-07-15T21:03:31.598Z'::timestamp,'2026-07-16T13:59:48.211Z'::timestamp,'''-30'':686C ''10'':157C ''20'':532C,685C ''2021'':177C ''50'':10A,305C,325C,518C,678C ''55'':648C ''paragraph'':147C,262C,316C,391C,489C,630C,698C ''актер'':589C ''активн'':339C ''актрис'':197C ''акцент'':424C ''амбиц'':311C ''амедиатек'':128C ''анонсирова'':173C,281C,299C ''аппарат'':569C ''ассоциир'':617C ''бат'':482C ''бат-митцв'':481C ''бедр'':642C ''безнадежн'':333C ''безусловн'':345C,508C ''биг'':571C ''ближ'':558C ''больш'':137C,495C ''брэдшо'':23B,55C ''ведет'':386C ''вернут'':88C ''вест'':513C ''в