INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqtgdw00cquktaanqfpx6c','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Елена Блиновская поможет забеременеть. Об этом и многом другом в новом интервью Надежды Стрелец','10 сентября автор популярного тренинга Марафон желаний Елена Блиновская дала интервью журналистке Надежде Стрелец.','538-elena-blinovskaja-pomozhet-zaberemenet-ob-jetom-i-mnogom-drugom-v-novom-intervju-nadezhdy-strelec','[{"html":"10 сентября автор популярного тренинга \"Марафон желаний\" Елена Блиновская дала интервью журналистке Надежде Стрелец. После скандального интервью с Ксенией Собчак прошло 9 месяцев. Как изменилась жизнь самого популярного коуча, как изменилась она сама и что теперь происходит в ее бизнесе?","type":"paragraph"},{"html":"Казалось бы, опытный психолог, может проработать свои ошибки, осознать их и грамотно подготовиться к новому интервью, в котором покажет себя с лучшей стороны. Но это не про Елену Блиновскую.","type":"paragraph"},{"html":"Собственное восхваление и торжество над интервью с Собчак не оставило равнодушным никого из зрителей. Елена так и не смогла подготовить ответ на вопрос: «Почему она предстала в интервью с Собчак в столь смешном и разобранном виде». Постоянно путаясь, она отвечала, что так и было задумано, через минуту мы слышали, что она доверилась журналистке и та ее предала. В итоге она запуталась окончательно, запутав и Надежду Стрелец. Попытка журналистки «отбелить» запятнанную репутацию коуча привела к ее еще большему «загрязнению».","type":"paragraph"},{"html":"Интервью прошло в более мягком виде, чем с Ксенией Собчак, но это добавило образу Блиновской еще большую комичность на фоне мягкой и душевной ведущей.","type":"paragraph"},{"html":"Чего ждать теперь от самого популярного коуча? Елена Блиновская продолжает развиваться и покорять новые вершины, теперь она уверена, в том, что может не только исполнить любое желание, но и помочь женщинам забеременеть, у кого с этим проблемы.","type":"paragraph"},{"html":"Ну и в дополнение несколько самых ярких комментариев от зрителей.","type":"paragraph"},{"html":"«У меня один вопрос к почитателям творчества Елены: ребят, а вас не настораживает, когда в различных интервью человек рассказывает/\"показывает\" то, как он в самых невероятных и неожиданных местах встречает людей, которые благодарят за марафон. То тетка с букетом в тайге \"вдруг\" выскочила и стала благодарить за долгожданную беременность (спойлер, женщина в итоге не беременна), то на вершине Эльбруса Елена встречает \"благодарных за марафон\". Ни на какие мысли не наталкивает, когда человек проговаривает один и тот же сценарий, только со сменой действующих лиц и локаций? Вопрос на умение анализировать и сопоставлять факты. А ну и ещё, вопрос к тем, кто занимается альпинизмом - а вот реально на высоте более 4000 метров прям есть силы и возможности поболтать с малознакомым человеком о его прекрасных инфопродуктах»?","type":"paragraph"},{"html":"«Слушаю с третьего захода. Клиническим психологам можно каждое предложение на цитаты разбирать и в университетах на практике отклонения изучать».","type":"paragraph"},{"html":"«Как бы то ни было: в начале интервью «я не психолог», в середине интервью «я не психолог», к концу интервью «я практикующий психолог».. Просто наблюдение».","type":"paragraph"},{"html":"«Четвертая минута: \"И я поднимаюсь ОДНА на Эльбрус.... и вот МЫ уже идем неделю на вершину».","type":"paragraph"},{"html":"«Если внимательно послушать - там таких нестыковок было очень много))) Не слова правды, постоянные попытки представить себя в выгодном свете. Ее так несёт в рассказе, что через время она забывает, что говорила некоторое время назад, даже дополнительные вопросы задавать не надо, она сама себя палит на одной и той же теме рассказывая».","type":"paragraph"}]'::jsonb,'cmrmqtgch00cpukta0rr5swni','cmrm8kzli000ikwtafbw33jnj','cmrm8kzoi000kkwtachb0mt9u','cmrmpdrom0000sstarkqxwts4','2022-09-12T06:00:00.000Z'::timestamp,NULL,NULL,NULL,538,'/persona/about-life/538-elena-blinovskaja-pomozhet-zaberemenet-ob-jetom-i-mnogom-drugom-v-novom-intervju-nadezhdy-strelec.html','2026-07-15T21:00:33.332Z'::timestamp,'2026-07-16T13:58:11.306Z'::timestamp,'''10'':15B,29C ''4000'':373C ''9'':50C ''paragraph'':70C,102C,183C,210C,250C,263C,389C,411C,439C,458C,512C ''автор'':17B,31C ''альпинизм'':366C ''анализирова'':353C ''беремен'':313C,319C ''бизнес'':68C ''благодар'':297C,310C ''благодарн'':326C ''блиновск'':2A,23B,37C,100C,199C,220C ''больш'':180C,201C ''букет'':303C ''ведущ'':208C ''вершин'':226C,322C,456C ''вид'':139C,190C ''внимательн'':461C ''возможн'':379C ''вопрос'':126C,268C,350C,361C,496C ''восхвален'':105C ''врем'':486C,492C ''встреча'':294C,325C ''выгодн'':477C ''выскоч'':307C ''высот'':371C ''говор'':490C ''грамотн'':83C ''дал'':24B,38C ''действ'':346C ''добав'':197C ''довер'':155C ''долгожда'':312C ''дополнен'':255C ''дополнительн'':495C ''друг'':9A ''душевн'':207C ''ел'':1A,22B,36C,118C,219C,272C,324C ''елен'':99C ''ещ'':360C ''ждат'':213C ''желан'':21B,35C,238C ''женщин'':242C,315C ''жизн'':54C ''журналистк'':26B,40C,156C,171C ''забеременет'':4A,243C ''забыва'':488C ''загрязнен'':181C ''задава'':497C ''задума'':148C ''занима'':365C ''запута'':164C,166C ''запятна'':173C ''заход'':394C ''зрител'':117C,261C ''ид'':453C ''измен'':53C,59C ''изуча'':409C ''интерв'':12A,25B,39C,45C,87C,109C,131C,185C,281C,420C,426C,432C ''инфопродукт'':387C ''исполн'':236C ''итог'':162C,317C ''кажд'':398C ''каза'':72C ''как'':331C ''клиническ'':395C ''ког'':245C ''комичн'':202C ''комментар'':259C ''конц'':431C ''котор'':89C,296C ''коуч'':57C,175C,218C ''ксен'':47C,193C ''лиц'':347C ''локац'':349C ''лучш'':93C ''люб'':237C ''люд'':295C ''малознаком'':382C ''марафон'':20B,34C,299C,328C ''мест'':293C ''месяц'':51C ''метр'':374C ''минут'':150C,442C 