INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqr7f6003yuktaxevnev5b','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'PRO детскую травму','Мы живем в мире сложностей, препятствий и бесконечных задач.','626-pro-detskuju-travmu','[{"html":"Мы живем в мире сложностей, препятствий и бесконечных задач. Редакции ESQUE стало интересно порассуждать о том, как в нашей жизни возникают препятствия и проблемы и кто нам устанавливает задачи и рамки.","type":"paragraph"},{"html":"Мы сами повелители своей жизни, и от того как мы к ней относимся, какой ролью наделяем себя в своем мире, зависит какой путь нам предстоит пройти! Порой наш выбор происходит бессознательно, очень часто мы не знаем, что существуем в рамках и что за ними, какой жизнью мы можем жить. Многие люди, находясь в зрелом возрасте, пребывают все еще в детской инфантильной позиции и в своих жизненных неурядицах обвиняют родителей.","type":"paragraph"},{"html":"Почему одни вырастают победителями, а другие слабыми и неспособными самостоятельно познать жизнь?","type":"paragraph"},{"html":"Детство…","type":"paragraph"},{"html":"Все наши установки, рамки, жизненные позиции, страхи и триггеры родом из детства. В детском возрасте, мы словно губки впитываем родительские слова, требования, подсматриваем общение родителей и формируем свой мир, в котором порой становится тесно в сознательном возрасте.","type":"paragraph"},{"html":"Этот материал о детских травмах и о том, как распознать их, побороть и дать жизни второй шанс на счастливое будущее!","type":"paragraph"},{"html":"<em><u>Благодарим наших психологов, которые помогли найти ответы на все вопросы и дали бесценные советы:</u></em>","type":"paragraph"},{"html":"Валентина Малик – психолог, психотерапевт @malik.psy","type":"paragraph"},{"html":"Ольга Марьяж – психолог, системный психотерапевт @olgamariage","type":"paragraph"},{"html":"Лариса Бабенко – психолог, бизнес-тренер @lora_babenko_psy","type":"paragraph"},{"html":"Наталья Царева – тренер НЛП, психолог, психотерапевт @nataly.tsareva","type":"paragraph"},{"html":"Юлия Петухова – родолог, ансестолог @rod.julia.petuxxova","type":"paragraph"},{"html":"Ксения Нефедова – клинический психолог, системный расстановщик @davai_nachistoty_","type":"paragraph"},{"html":"Анаида Сапричян – психолог, системный расстановщик @anaida_888","type":"paragraph"},{"html":"Леся Филатова – коуч, специалист психотелесных техник, системный расстановщик @lesya.filatova_","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/PWr3L9Yd4VY?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" title=\"PRO детскую травму\"></iframe>","type":"embed"}]'::jsonb,'cmrmqr7df003xuktaf0jde3h8','cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2023-12-05T06:00:00.000Z'::timestamp,NULL,NULL,NULL,626,'/psihologija/intervju-2/626-pro-detskuju-travmu.html','2026-07-15T20:58:48.402Z'::timestamp,'2026-07-16T13:57:04.255Z'::timestamp,'''888'':282C ''anaida'':281C ''babenko'':242C ''davai'':271C ''emb'':298C ''esqu'':23C ''lesya.filatova'':294C ''lora'':241C ''malik.psy'':222C ''nachistoti'':272C ''nataly.tsareva'':253C ''olgamariag'':231C ''paragraph'':45C,117C,132C,136C,176C,199C,216C,224C,233C,245C,255C,263C,274C,284C,296C ''pro'':1A ''psi'':243C ''rod.julia.petuxxova'':261C ''анаид'':276C ''ансестолог'':260C ''бабенк'':236C ''бесконечн'':11B,20C ''бессознательн'':77C ''бесцен'':213C ''бизнес'':239C ''бизнес-тренер'':238C ''благодар'':201C ''будущ'':197C ''валентин'':218C ''возника'':33C ''возраст'':101C,152C,174C ''вопрос'':210C ''впитыва'':156C ''втор'':193C ''выбор'':75C ''выраста'':121C ''губк'':155C ''дал'':212C ''дат'':191C '