INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqeh1u002hpotajanznbvh','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Татьяна Бакальчук и Wildberries. Отвечаем на главные вопросы','Громкое разбирательство в семье Бакальчук продолжается.','674-tatjana-bakalchuk-i-wildberries-otvechaem-na-samye-glavnye-voprosy','[{"html":"Громкое разбирательство между четой Бакальчук, основателями Wildberries, продолжается. 30 июля Татьяна Бакальчук подала иск о расторжении брака. Вести бракоразводный процесс будет Савеловский суд.Если верить Владиславу, о разводе он узнал через социальные сети: «Я не знаю, сколько человек и как именно на нее воздействуют, но Татьяна, с которой мы бок о бок прожили больше 20 лет, никогда бы не заявила об официальной подаче заявления в суд о расторжении брака со мной вот таким образом — сухо, кратко и через соцсети. Я в этом абсолютно уверен».Пока Владислав уверен, что на жену оказывают давление, адвокаты и юристы по всему миру отвечают на главные вопросы.","type":"paragraph"},{"html":"<b>Как будет разделена компания?</b>","type":"paragraph"},{"html":"Ранее Татьяна, заявила, что у Владислава лишь 1% всех акции и к управлению компанией он не имеет никакого отношения. Однако, по словам адвоката Константина Ерохина, при отсутствии брачного договора, компания Wildberries является совместно нажитым имуществом, а это значит, что Владислав имеет право на ее половину и ни одна сделка не может случиться без его согласия. Таким образом, объединение Wildberries с Russ Outdoor должно быть временно приостановлено до урегулирования ситуации между супругами.","type":"paragraph"},{"html":"«Я бы публично действовал так, чтобы показать права мужа. Вероятно, что сделка будет заморожена, как и состав ее участников поменяется», — добавил Ерохин.","type":"paragraph"},{"text":"Как развод Бакальчук может повлиять на работу маркетплейса?","type":"heading"},{"html":"Покупатели обеспокоены усугубившейся семейной ситуацией между владельцами компании, однако Татьяна Бакальчук утверждает, что на работе отделений ни объединение с Russ Outdoor, ни развод с мужем, никак не скажется. Все будет работать в штатном режиме.","type":"paragraph"},{"text":"Зачем такому процветающему бизнесу, как Wildberries объединение с компанией, которая занимается наружней рекламы?","type":"heading"},{"html":"В планах объединенной компании — открытие магазинов, складов и логистических центров практически по всему «дружественному» миру, включая Китай, Индию, страны Азии, Африки, Ближнего Востока и СНГ. А также создание собственной платежной системы для расчетов в российских рублях без применения SWIFT.","type":"paragraph"},{"text":"Причем тут Рамзан Кадыров и Тимати?","type":"heading"},{"html":"На встрече с Рамзаном Кадыровым, с которым Владислав Бакальчук дружит около 10 лет, мужчина пожаловался о проблемах в семье и обвинил в этом братьев Мирзоян (основателей Russ Outdoor). Кадыров назвал все происходящее «рейдерским захватом». И как итог, в сети вспыхнула новость о том, что Татьяну Бакальчук удерживают силой и запрещают общаться с мужем. И как вишенка на торте: видео Тимати, в котором он просит вернуть Татьяну в семью.","type":"paragraph"},{"html":"<br />А мы продолжаем следить за происходящим …","type":"paragraph"}]'::jsonb,'cmrmqeh0l002gpotaiibcz106','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-08-01T06:00:00.000Z'::timestamp,NULL,NULL,NULL,674,'/v-mire/674-tatjana-bakalchuk-i-wildberries-otvechaem-na-samye-glavnye-voprosy.html','2026-07-15T20:48:54.354Z'::timestamp,'2026-07-16T13:56:32.973Z'::timestamp,'''1'':134C ''10'':352C ''20'':69C ''30'':23C ''head'':235C,288C,339C ''outdoor'':188C,257C,368C ''paragraph'':118C,125C,199C,224C,272C,330C,410C,419C ''russ'':187C,256C,367C ''swift'':328C ''wildberri'':4A,21C,157C,185C,279C ''абсолютн'':