INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsgau008cuktay59dckpp','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'«Волшебные лекала,  рулоны ткани, превращающиеся в змей и зачарованные иглы» - какой была выставка художников в рамках проекта «Fashion bitva»','18 декабря в рамках показа 10 сезона проекта “Fashion bitva” прошла выставка художников, где российские представители мира искусства презентовали гостям свои творения.','587-volshebnye-lekala-rulony-tkani-prevraschajuschiesja-v-zmej-i-zacharovannye-igly-kakoj-byla-vystavka-hudozhnikov-v-ramkah-proekta-fashion-bitva','[{"html":"18 декабря в рамках показа 10 сезона проекта “Fashion bitva” прошла выставка художников, где российские представители мира искусства презентовали гостям свои творения. Мероприятие прошло в концертном зале “Arbat Hall” на Новом Арбате.","type":"paragraph"},{"html":"Международный проект “Art &amp; Fashion” @artfashion_project, насчитывающий более 1000 мастеров и 150.000 экспонатов, представил картины трех художников: Швецовой Евгении с произведением “Рыбки со скульптурой”, Харитоновой Нины с “Девушка с бокалом” и Ольги Ноздрини с “Хакамадой”.","type":"paragraph"},{"html":"Кроме арт-проекта выступили и независимые художники, еще юные, но уже подающие надежды.","type":"paragraph"},{"html":"Анастасия Бучацкая @sam_nastena_ в своей картине “Светящая девушка” хотела донести до гостей ощущение теплоты, нежности и домашнего уюта, которого так не хватает жителям современного мегаполиса.","type":"paragraph"},{"html":"Участник и призер международных и российских художественных конкурсов и творческий искатель, Майя Иллисандра @mya_illys выступила со своими работами “Model one”, “Model two”. В своих картинах автор хотел \"передать атмосферу показа, поэтому в них была задана динамика и ритм. Приглушенный свет акцентировал внимание гостей на формах. Для Майи истинное кредо по жизни: “Такого еще не было, надо попробовать!”.","type":"paragraph"},{"html":"Член союза русских художников, Анастасия Киселева @art_chist_a представила свои картины “Взгляд в себя”, \"Япония\", \"Самобытность\". Автор в своих работах показала не только погружение в свой внутренний мир, но и отобразила \"женственность с душой война\". Для Анастасии “живопись- это призвание, самоцель, жизнь\".","type":"paragraph"},{"html":"Анна Горбенко @annett_artist - участница множества творческих международных выставок и организатор своей собственной. Художница в своей картине “Притяжение” показала “любовь с первого взгляда”, ту любовь, которая не подвластна разуму и логике. Это “романтические чувства между двумя совершенно разными людьми, не имеющими еще ничего общего, но разгорающиеся буквально за доли секунды”. Анна в свои работы вкладывает часть души, а вдохновение берет от красоты окружающего мира.","type":"paragraph"},{"html":"Живописец, автор работ, воплощающий на полотнах мифологические образы, Анастасия Туркова @ledbydestiny предстала перед гостями с картиной \"Астрея\". Астрея – Богиня справедливости, посланная на землю, чтобы учить людей порядку и равновесию.","type":"paragraph"},{"html":"Увидели гости и картины, отражающие тематику конкурса «Мода 2032». Художница Мария Бутырина @_mary_artist147_ в своем произведении объединила моду и любовь к кошкам.","type":"paragraph"},{"html":"<em>“Мне хотелось передать и свою собственную любовь к кошкам, и чувство родства с ними, потому что мода будущего должна объединить человека и природу не только за счет цветочных принтов. Все платья бархатные, для создания бархата используются шелковые нити, а для сохранения популяции шелкопрядов нужно заботиться о природе, то есть, создание неэкономного и не синтетического материала требует заботы об экологии”</em> – резюмировала Мария.","type":"paragraph"},{"html":"Автор, создающий экспрессивные, эмоциональные картины, Екатерина Гуськова @risunochkikati в картинке \"Цикличность\" порассуждала о моде разных эпох, ведь будущее – это всегда часть прошлого.","type":"paragraph"},{"html":"Иллюстратор и художник Анастасия Винокурова @fairy_hexe писала на самой выставке в режиме реального времени. В своей работе художница отразила атмосферу показа и совместила логотип «Fashion bitva» и двух персонажей схожих в одной сфере, но и одновременно противоположных друг другу - дизайнера и модель. На эту идею Анастасию натолкнуло слово \"битва\": <em>\"Чем может сражаться воин от моды в фентези мире? Конечно, это волшебные лекала, рулоны ткани, превращающиеся в змей и зачарованные иглы. Иными словами победит лучший из лучших, а выяснить это можно на честном поединке\".</em>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqsfbm0088uktaz9mdpnc3"},{"mediaId":"cmrmqsfw70089uktayvt5x8ma"},{"mediaId":"cmrmqsg1v008auktakgbcgfgz"},{"mediaId":"cmrmqsg9g008buktauyjv84hq"}]}]'::jsonb,'cmrmqsf3o0087ukta4wdlz0ug','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2023-01-08T06:00:00.000Z'::timestamp,NULL,NULL,NULL,587,'/projects-esque/fashion-bitva/587-volshebnye-lekala-rulony-tkani-prevraschajuschiesja-v-zmej-i-zacharovannye-igly-kakoj-byla-vystavka-hudozhnikov-v-ramkah-proekta-fashion-bitva.html','2026-07-15T20:59:46.566Z'::timestamp,'2026-07-16T13:57:35.680Z'::timestamp,'''10'':25B,47C ''1000'':85C ''150.000'':88C ''18'':20B,42C ''2032'':375C ''annett'':270C ''arbat'':69C ''art'':79C,228C ''artfashion'':81C ''artist'':271C ''artist147'':380C ''bitva'':19A,29B,51C,508C ''chist'':229C ''cmrmqsfbm0088uktaz9mdpnc3'':571C ''cmrmqsfw70089uktayvt5x8ma'':573C ''cmrmqsg1v008auktakgbcgfgz'':575C ''cmrmqsg9g008buktauyjv84hq'':577C ''fairi'':487C ''fashion'':18A,28B,50C,80C,507C ''galleri'':569C ''hall'':70C ''hex'':488C ''illi'':175C ''ledbydestini'':345C ''mari'':379C ''model'':180C,182C ''mya'':174C ''nastena'':135C ''one'':181C ''paragraph'':75C,113C,130C,159C,220C,266C,333C,365C,