INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqr8070041uktaurq81uv2','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Как подготовить эскизы к конкурсу дизайнеров?','Всероссийский конкурс дизайнеров одежды PROfashion Masters отмечает 10-ый юбилейный сезон.','625-kak-podgotovit-jeskizy-k-konkursu-dizajnerov','[{"html":"Всероссийский конкурс дизайнеров одежды PROfashion Masters отмечает 10-ый юбилейный сезон. По итогам первого этапа организаторы проекта получили около 400заявок от молодых дизайнеров из разных городов России, ближнего и дальнего зарубежья.","type":"paragraph"},{"html":"Профессиональному жюри предстояла непростая задача: выбрать именно тех конкурсантов, чьи работы будут воплощены в материале и представлены в полуфинале конкурса. После онлайн-голосования в список полуфиналистов вошли 20 участников, в том числе финалисты прошлого сезона: Никита Баранов, Тимур Хамраев и Антон Мажарин. Они представили новые проекты, которые также были высоко оценены","type":"paragraph"},{"html":"судейской коллегией.","type":"paragraph"},{"html":"30 ноября в 18:30 в рамках образовательной программы пройдет онлайн-лекция на тему: “Эскизный этап: работа над ошибками”. В прямом эфире члены жюри подведут итоги эскизного этапа и разберут работы участников с точки зрения общей концепции, художественной подачи, точности конструктивных линий, проработки силуэтов, соответствия трендам. Лекция будет интересна всем начинающим дизайнерам, которые планируют принять участие в профильном конкурсе – она поможет избежать распространенных ошибок и увеличить шансы на победу в эскизном этапе.","type":"paragraph"},{"html":"<i><u>Присоединиться к эфиру может любой желающий по ссылке: </u></i><b><a href=\"https://www.youtube.com/watch?v=HXheXRe8RhU\" target=\"_blank\" rel=\"noopener noreferrer\">https://www.youtube.com/watch?v=HXheXRe8RhU</a></b>","type":"paragraph"},{"html":"После прохождения эскизного этапа все полуфиналисты PROfashion Masters бесплатно получат материалы для изготовления своих коллекций – пальтовые ткани от компании «Ткани Престиж», курточные материалы от компании GRASSER и инновационные утеплители от холдинга «С2 ГРУПП». Помимо этого, всем желающим будут предоставлены базовые лекала и консультация по конструированию от GRASSER.","type":"paragraph"},{"html":"Полуфинал X Всероссийского конкурса PROfashion Masters пройдет в Москве в первой половине февраля в формате арт-выставки, на которой будут представлены все работы конкурсантов. По итогам голосования жюри в финал выйдет 10 коллекций. Они будут показаны на профессиональном подиуме выставки Collection Première Moscow в феврале 2024 года.","type":"paragraph"}]'::jsonb,'cmrmqr7yj0040ukta31d4zzwf','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2023-11-28T06:00:00.000Z'::timestamp,NULL,NULL,NULL,625,'/fashion/news-2/625-kak-podgotovit-jeskizy-k-konkursu-dizajnerov.html','2026-07-15T20:58:49.159Z'::timestamp,'2026-07-16T13:57:04.758Z'::timestamp,'''/watch?v=hxhexre8rhu'':198C ''10'':14B,25C,284C ''18'':115C ''20'':80C ''2024'':298C ''30'':112C,116C ''400заявок'':37C ''collect'':293C ''grasser'':227C,248C ''master'':12B,23C,209C,257C ''moscow'':295C ''paragraph'':50C,105C,110C,186C,200C,250C,301C ''première'':294C ''profashion'':11B,22C,208C,256C ''www.youtube.com'':197C ''www.youtube.com/watch?v=hxhexre8rhu'':196C ''x'':253C ''антон'':93C ''арт'':268C ''арт-выставк'':267C ''базов'':241C ''баран'':89C ''бесплатн'':210C ''ближн'':45C ''будут'':63C,239C,272C,287C ''воплощ'':64C ''вошл'':79C ''всем'':162C,237C ''всероссийск'':7B,18C,254C ''выбра'':57C ''выйдет'':283C ''высок'':102C ''выставк'':269C,292C ''год'':299C ''голосован'':75C,279C ''город'':43C ''групп'':234C ''дальн'':47C ''дизайнер'':6A,9B,20C,40C,164C ''жела'':193C,238C ''жюр'':53C,136C,280C ''за