INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqu1wy00fcuktavxcs04ne','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Принц Чарльз создал аромат вместе с Penhaligon’s','Принц Чарльз и британский парфюмерный бренд Penhaligon’s выпустили совместный аромат «Highgrove Bouquet».','510-princ-charlz-sozdal-aromat-vmeste-s-penhaligons','[{"html":"<b>Принц Чарльз и английская парфюмерная марка Penhaligon’s разработали совместный парфюм «Highgrove Bouquet». Источником вдохновения для него послужил сад резиденции Хайгроув, которой владеет наследник престола. Эту коллаборацию называют одной из самых неожиданных в этом месяце.</b>","type":"paragraph"},{"html":"Основная составляющая парфюма – серебристая липа, которая выращивается в резиденции принца. Кроме того, в парфюме есть ноты герани, лаванды, тубероза, французской мимозы и древесной базы из кедра и мускуса. Всё это сочетание создал лично наследник британского престола Чарльз.<br /><br />Стоимость одного флакона составила £152. 10% доходов от продаж будет перечисляться в The Prince s Foundation – благотворительную организацию принца. С помощью вырученных средств фонд будет спонсировать ряд образовательных программ, в том числе по искусству, традиционным ремеслам и моде.<br /><br />Аромат продаётся во флаконах объёмом 100 мл. Для их создания используется только перерабатываемый материал. Купить парфюм могут только жители Англии на сайте резиденции Хайгроув.","type":"paragraph"}]'::jsonb,'cmrmqu1v500fbuktac6xresdh','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyxz0009kwtay5bvzu16','cmrmpdrom0000sstarkqxwts4','2022-08-25T06:00:00.000Z'::timestamp,NULL,NULL,NULL,510,'/beauty/news-3/510-princ-charlz-sozdal-aromat-vmeste-s-penhaligons.html','2026-07-15T21:01:01.234Z'::timestamp,'2026-07-16T13:58:29.855Z'::timestamp,'''10'':101C ''100'':139C ''152'':100C ''bouquet'':20B,33C ''foundat'':111C ''highgrov'':19B,32C ''paragraph'':57C,159C ''penhaligon'':7A,14B,27C ''princ'':109C ''англ'':153C ''английск'':24C ''аромат'':4A,18B,134C ''баз'':82C ''благотворительн'':112C ''бренд'':13B ''британск'':11B,93C ''вдохновен'':35C ''владеет'':43C ''вмест'':5A ''все'':87C ''выпуст'':16B ''выращива'':65C ''выручен'':117C ''геран'':75C ''доход'':102C ''древесн'':81C ''жител'':152C ''искусств'':129C ''использ'':144C ''источник'':34C ''кедр'':84C ''коллаборац'':47C ''котор'':42C,64C ''кром'':69C ''куп'':148C ''лаванд'':76C ''лип'':63C ''личн'':91C ''марк'':26C ''материа'':147C ''месяц'':55C ''мимоз'':79C ''мл'':140C ''могут'':150C ''мод'':133C ''мускус'':86C ''называ'':48C ''наследник'':44C,92C ''неожида'':52C ''нот'':74C ''образовательн'':123C ''объем'':138C ''одн'':49C,97C ''организац'':113C ''основн'':59C ''парфюм'':31C,61C,72C,149C ''парфюмерн'':12B,25C ''перерабатыва'':146C ''перечисля'':106C ''помощ'':116C ''послуж'':38C ''престол'':45C,94C ''принц'':1A,8B,21C,68C,114C ''программ'':124C ''прода'':135C ''продаж'':104C ''разработа'':29C ''резиденц'':40C,67C,156C ''ремесл'':131C ''ряд'':122C ''сад'':39C ''сайт'':155C ''сам'':51C ''серебрист'':62C ''совместн'':17B,30C ''созда'':3A,90C ''создан'':143C ''состав'':99C ''составля'':60C ''сочетан'':89C ''спонсирова'':121C ''средств'':118C ''стоимост'':96C ''традицион'':130C ''тубероз'':77C ''флакон'':98C,137C ''фонд'':119C ''французск'':78C ''хайгроув'':41C,157C ''чарльз'':2A,9B,22C,95C ''числ'':127C ''эт'':88C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescriptio