INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqxdcw00qhuktaz018p86e','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Фильм «Дом Gucci». Отзывы и оценка фильма','«Дом Gucci» прочно закрепился в списке самых обсуждаемых картин последних месяцев.','396-film-dom-gucci-otzyvy-i-ocenka-filma','[{"html":"«Дом Gucci» прочно закрепился в списке самых обсуждаемых картин последних месяцев. Прямо сейчас в издании Variety обсуждают создание грима для Джареда Лето, которому досталась роль Паоло Гуччи, а в Twitter – секс-сцену между Леди Гагой и Сальмой Хайек, которая так и не попала в финальный монтаж фильма. Общие сборы приближаются к 600 млн. долларов – и если вы еще не видели «Дом Gucci», то мы расскажем, стоит ли тратить время на просмотр.","type":"paragraph"},{"html":"«Дом Gucci» один из тех фильмов, подготовка к съемкам которого заняла гораздо больше времени, чем сама работа на съемочной площадке. Судите сами: режиссером картины Ридли Скотт был назначен еще в 2006 году, но с мертвой точки процесс удалось сдвинуть лишь в 2020-м, когда права на фильм приобрела Metro-Goldwyn-Myer. Премьера картины состоялась 9 ноября 2021 года, в России «Дом Gucci» вышел в прокат 2 декабря.","type":"paragraph"},{"html":"В центре сюжета – амбициозная итальянка Патриция Реджани и весьма неуклюжий Маурицио Гуччи (их играют Леди Гага и Адам Драйвер соответсвенно), наследник 50%-ной доли в модном Доме, который по сей день привлекает к себе интерес каждой новой коллекцией. Отец Маурицио называет Патрицию «охотницей за деньгами», что не мешает его сыну жениться на Патриции. Дальнейшие сюжетные повороты подтверждают, что Родольфо Гуччи был не так уж далек от истины: Патриция подталкивает Маурицио к более активному участию в семейном бизнесе, попутно «расчищая» ему дорогу, порой даже жертвуя ради этого родственниками мужа – они оказываются в тюрьме или, как минимум, на обочине проекта, который, казалось, принадлежит Реджани, а не Гуччи. Наступает момент, когда Патриция открыто демонстрирует мужу, кто здесь главный – и Маурицио понимает, что его папа был не так далек от истины. Он (кажется, впервые в жизни) принимает решение, простить которое Патриция ему не сможет.","type":"paragraph"},{"html":"Как восприняли фильм критики и зрители? Конечно, не обошлось без комментариев от членов клана Гуччи. Дочь Альдо, Патриция, заявила, что картина ее разочаровала. А Патриция Реджани и вовсе раскритиковала Леди Гагу за то, что та не встретилась с ней накануне съемок, чтобы попытаться понять мотивы ее поступка. Что непосредственная участница тех событий, что представительница семейства Гуччи остались недовольны фильмом.","type":"paragraph"},{"html":"А вот мнения профессиональных критиков разделились. На Rotten Tomatoes «Дом Gucci» заработал 63% у профессионалов и 82% - у зрителей. На зарубежных порталах активно обсуждалась не самая глубокая проработка характеров персонажей: прототипов некоторых из них (например, ту же дочь Альдо Гуччи) попросту «забыли» добавить в фильм. Ругают «Дом Gucci» и за частую смену событий, которая порой подталкивает к тому, чтобы мы сами додумывали истинные причины одного из самых громких заказных убийств.","type":"paragraph"},{"html":"На российских порталах у картины больше положительных отзывов, чем негативных. Зрители хвалят Ридли Скотта за «уникальное умение придать драме легкий налет комедии» и отмечают что «Дом Gucci» гораздо лучше той же «Последней дуэли», выпущенной режиссером незадолго до премьеры фильма про люксовый итальянский бренд. Захочется ли нам пересматривать историю того, как наследие Gucci превратилось в тыкву, покажет время.","type":"paragraph"},{"html":"<i>Автор: Анастасия Гагарина</i>","type":"paragraph"}]'::jsonb,'cmrmqxd7o00qgukta9a3dm0zo','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz6g000dkwtai45m48bj','cmrmpdrom0000sstarkqxwts4','2022-01-28T06:00:00.000Z'::timestamp,NULL,NULL,NULL,396,'/sobytija/kino/396-film-dom-gucci-otzyvy-i-ocenka-filma.html','2026-07-15T21:03:36.032Z'::timestamp,'2026-07-16T13:59:50.894Z'::timestamp,'''2'':160C ''2006'':124C ''2020'':135C ''2021'':151C ''50'':186C ''600'':71C ''63'':382C ''82'':386C ''9'':149C ''goldwyn'':144C ''gucci'':3A,9B,20C,81C,95C,156C,380C,417C,469C,494C ''metro'':143C ''metro-goldwyn-my'':142C ''myer'':145C ''paragraph'':92C,163C,306C,368C,441C,501C,507C ''rotten'':377C ''tomato'':378C ''twitter'':48C ''varieti'':34C ''автор'':503C ''ад'':182C ''активн'':237C,392C ''альд'':324C,408C ''амбициозн'':168C ''анастас'':504C ''бизнес'':241C ''бренд'':485C ''весьм'':173C ''видел'':79C ''вовс'':335C ''восприня'':309C ''вперв'':294C ''врем'':88C,499C ''времен'':107C ''встрет'':344C ''выпущен'':476C ''вышел'':157C ''гаг'':54C,180C,338C ''гагарин'':505C ''главн'':279C ''глубок'':396C ''год'':125C,152C ''горазд'':105C,470C ''грим'':37C ''громк'':437C ''гучч'':45C,176C,224C,269C,322C,363C,409C ''далек'':229C,289C ''дальн'':218C ''декабр'':161C ''демонстрир'':275C ''ден'':195C ''деньг'':209C ''джаред'':39C ''добав'':412C ''додумыва'':431C ''дол'':188C ''доллар'':73C ''дом'':2A,8B,19C,80C,94C,155C,191C,379C,416C,468C ''дорог'':245C ''доста'':42C ''доч'':323C,407C ''драйвер'':183C ''драм'':461C ''дуэл'':475C ''жен'':215C ''жертву'':248C ''жизн'':296C ''заб'':411C ''заказн'':438C ''закреп'':11B,22C ''заня'':104C ''заработа'':381C ''зарубежн'':390C ''захочет'':486C ''заяв'':326C ''зрител'':313C,388C,453C ''игра'':178C ''издан'':33C ''интерес'':199C ''истин'':231C,291C,432C ''истор'':490C ''итальянк'':169C ''итальянск'':484C ''кажд'':200C ''кажет'':293C ''каза'':264C ''картин'':16B,27C,117C,147C,328C,447C ''клан'':321C ''коллекц'':202C ''комед'':464C ''комментар'':318C ''котор'':41C,58C,103C,192C,263C,300C,423C ''критик'':311C,374C ''легк'':462C ''лед'':53C,179C,337C ''лет'':40C ''лиш'':133C ''люксов'':483C ''м'':136C ''мауриц'':175C,204C,234C,281C ''мертв'':128C