':359C,422C ''создан'':36C ''соответсвен'':184C ''состоя'':148C ''списк'':13B,24C ''сто'':85C ''суд'':114C ''сцен'':51C ''съемк'':102C ''съемок'':348C ''съемочн'':112C ''сын'':214C ''сюжет'':167C ''сюжетн'':219C ''та'':342C ''тех'':98C,358C ''то'':472C ''том'':427C ''точк'':129C ''трат'':87C ''ту'':405C ''тыкв'':497C ''тюрьм'':256C ''убийств'':439C ''уда'':131C ''умен'':459C ''уникальн'':458C ''участ'':238C ''участниц'':357C ''фильм'':1A,7A,66C,99C,140C,310C,366C,414C,481C ''финальн'':64C ''хайек'':57C ''характер'':398C ''хвал'':454C ''центр'':166C ''част'':420C ''член'':320C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqtsra00e3ukta0ttukgzh','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Александр Давыдов: «Быть русским не стыдно»','«Актер для меня,- это всегда было что-то невероятное.','524-aleksandr-davydov-byt-russkim-ne-stydno','[{"html":"«Актер для меня,- это всегда было что-то невероятное. Как будто бы я хожу по земле, а они, актеры где-то там, на высоте. «А я-то обычный»- так про себя думал я. Я и не думал, что могу стать актером», - ностальгирует Александр с легкой, спокойной улыбкой. Сегодня, давно став известным и полюбившимся зрителю артистом, он будто заглядывает в другую жизнь. О детстве и тяге к независимости, о переломных моментах судьбы и карьеры и о том, что даже в отрицательном персонаже есть светлые стороны в интервью Esque с Александром Давыдовым.","type":"paragraph"},{"html":"<strong>Esque:</strong> Александр, сегодня вы – известный любимый тысячами актер. Что это, сбывшаяся мечта детства или сюрприз судьбы?","type":"paragraph"},{"html":"<strong>Александр:</strong> Скорее второе. В детстве я не мечтал быть актером. Чаще садился за большой стол и изображал директора какой-то крупной фирмы – раздавал задания и указы, вызывал группы инженеров в кабинет на отчеты. Или брал в руки кусок бумаги и карандаш и что-то чирикал, подходя к родителям – это я был официантом и принимал заказ. Нет, я не хотел идти в ресторанный бизнес. Просто, видимо, уже тогда у меня начала потихоньку проявляться тяга к актерскому искусству.","type":"paragraph"},{"html":"<strong>Esque:</strong> А родители заметили эту предрасположенность.","type":"paragraph"},{"html":"<strong>Александр:</strong> Тогда, в детстве, никто не обращал на это особого внимания. Играет ребенок и играет. Я совсем не из творческой семьи. Мой отец –инженер, и изначально предполагалось, что я должен был пойти по его стопам. И я попытался это сделать: после школы я, как и планировалось, поступил в автомеханический институт, чтобы продолжить дело отца. Но быстро понял, что инженер - это точно не мой путь, и через полтора года ушел из института.","type":"paragraph"},{"html":"<strong>Esque:</strong> И вот уже тогда-то и поступили в МХАТ, верно?","type":"paragraph"},{"html":"<strong>Александр:</strong> Да, все так. На тот момент моя душа уже давно тяготела к искусству. Наверное, повлияло воспитание бабушки. Сама она была врачом, но очень любила театр и меня приобщила. С ней я в первый раз попал в Большой театр. Тогда-то у меня и появились первые мысли стать актером. А со временем я только укрепился в своем решении.","type":"paragraph"},{"html":"<strong>Esque:</strong> Как отреагировали родители на ваше желание прервать семейное дело и последовать зову сердца в профессии?","type":"paragraph"},{"html":"<strong>Александр:</strong> Изначально они не поддержали меня. И даже пытались, если можно так сказать, противостоять этому выбору. Причем, все получилось в лучших традициях кино: мой отец обратились к одному хорошему товарищу из актерской среды с просьбой повлиять на меня и отговорить от затеи идти в театральный. Он согласился, и мы с ним долго-долго разговаривали. А потом этот товарищ поступил с точностью да наоборот, во многом определив мою дальнейшую судьбу: после прослушивания меня, он настоятельно посоветовал родителям не мешать. Он разглядел во мне требуемый талант, который обещал хорошее будущее в актерской профессии. Родители послушали его и отступили.","type":"paragraph"},{"html":"<strong>Esque:</strong> А вы были сильно зависимы от родителей?","type":"paragraph"},{"html":"<strong>Александр:</strong> Скажем так, мне было небезразлично их мнение. И мне не хотелось их разочаровывать. Но зависимым от родителей я не хотел быть еще с юношеских лет. По этой причине я начал рано подрабатывать, чтобы самому добывать средства на свои личные расходы. Сначала работал на стройке. Позже, когда готовился к поступлению в театральный, подрабатывал полгода курьером.","type":"paragraph"},{"html":"<strong>Esque: </strong>А как вы вообще относитесь к деньгам?","type":"paragraph"},{"html":"<strong>Александр:</strong> Скажем так, я знаю им цену. Деньги не падали мне на голову и всегда зарабатывались трудом. Но, также я уверен, что деньги нужно тратить. Конечно, с умом, оставляя что-то на черный день. Но тратить. Это же сегодня я говорю и своим родителям, когда помогаю им финансово: «Не жалейте! Тратьте! Себя нужно радовать!». И, говоря о радости, я имею в виду даже самые маленькие теплые моменты: чашка кофе и пирожное отлично поднимают настроение!","type":"paragraph"},{"html":"<strong>Esque:</strong> Или, скажем, долгожданное утверждение на роль, да? Александр, вы помните, какой была ваша первая роль?","type":"paragraph"},{"html":"<strong>Александр:</strong> Думаю, это то, что помнит каждый актер (улыбается). Это уже позже в памяти перемешиваются площадки, страны, картины. Но свои первые роли помнят все артисты. Мой первый опыт в кадре был в 2006 году, за год до окончания института в эпизодах телесериалов «Счастье по рецепту» и «Грозовые ворота».","type":"paragraph"},{"html":"<strong>Esque:</strong> О, эти теплые первые кадры. А какой момент вы считаете переломным в вашей карьере?","type":"paragraph"},{"html":"<strong>Александр:</strong> Это был 2010 год, начало съёмок картины «Баллада о Бомбере». Было эмоционально тяжело, сложно. Меня тогда долго не утверждали на роль. А очередное прослушивание мне сообщили, что, в общем-то, на главного положительного героя уже утвержден Никита Ефремов. Но нужен второй, отрицательный герой. И, в общем-то, я мог бы подойти, только вот очень уж у нас с Никитой похожий типаж: оба молодые, высокие, светловолосые. А для героев-антиподов хотелось бы какого-то контраста. Что-то внутри меня тогда перевернулось. И это что-то подтолкнуло меня бороться до конца. Я предложил перекрасить меня в темный цвет. Это идея понравилось режиссеру, и так я стал Георгием Линько. Правда, параллельно с «Балладой» шли съемки сериала «Маруся», где у меня был прямо противоположный образ - романтичного светловолосого парня. Так что, перед каждой съемкой в «Балладе» я красил волосы баллончиком в черный цвет, а перед «Марусей» смывал.","type":"paragraph"},{"html":"<strong>Esque:</strong> И кто придумал глупость, что на двух стульях не усидеть? У вас отлично получилось! Но, все же, от третьего стула вам пришлось отказаться. Ведь ваш уход из театра тоже пришелся на 2010 год?","type":"paragraph"},{"html":"<strong>Александр:</strong> С 2007 года я служил в театре им. Маяковского. Много работал, репетировал и видел себя на тот момент больше театральным актером, нежели киношным. Но отношения с художественным руководителем театра Сepгeем Аpцибaшeвым не складывались, роли были только эпизодические. И, конечно, я чувствовал некое обесценивание себя, как актера. (<em>примечание редакции: с 2001 по 2011 г художественным руководителем театра им. Масковского был peжиccep и aктep Сepгeй Аpцибaшeв . Большая часть труппы была недовольна, так как руководство двумя театрами пpивeлo к уxудшeнию пocтaнoвoк. Актеры даже обращались с открытым письмом об отставке худрука</em>). В кино же, наоборот, появились серьезные главные роли. Увеличилась нагрузка. В какой-то момент совмещать театр и кино стало очень сложно и спустя 3 года, в 2010 году я принял решение оставить театр.","type":"paragraph"},{"html":"<strong>Esque:</strong> Если посмотреть на вашу фильмографию, то в ней очень много отрицательных персонажей. Почему?","type":"paragraph"},{"html":"<strong>Александр:</strong> Так складывался мой путь в кино. По какой-то причине изначально меня приглашали больше на роли отрицательных персонажей. Так формировалось мое амплуа, и, в дальнейшем, режиссеры только таким и видели меня в своих картинах…","type":"paragraph"},{"html":"<strong>Esque:</strong> А, как вам кажется, кого играть легче: отрицательного или положительного героя?","type":"paragraph"},{"html":"<strong>Александр:</strong> Отрицательного героя играть сложнее, положительного - легче. Но у нас в кино все очень однобоко. Либо ты положительный герой, либо отрицательный. Это не совсем правильно, ведь у каждого человека есть и хорошие черты и плохие. В своих ролях стараюсь сделать так, чтоб даже отрицательного героя зрители полюбили и запомнили, за его светлую сторону...","type":"paragraph"},{"html":"<strong>Esque:</strong> А это правда, что, спустя столько лет, вы наконец-то снова вернулись в театр?","type":"paragraph"},{"html":"<strong>Александр:</strong> Да, верно. Я играю в театральных постановках. Гастролирую со спектаклями. Как раз недавно состоялась премьера в Москве, спектакль «Как в первый раз».","type":"paragraph"},{"html":"<strong>Esque:</strong> А как вы оцениваете сегодняшнюю индустрию кино в разрезе событий, происходящих на Украине?","type":"paragraph"},{"html":"<strong>Александр: </strong>Я очень люблю Украину и многократно бывал там. Это для меня не чужая страна. Раньше там было большое кинопроизводство для российского телевидения. И я всегда с радостью приезжал сниматься на Украину. И даже жил там практически 3 года с 2010 по 2013 год. Там я нашел много друзей. Только вот с началом спецоперации эти самые \"друзья\" устроили мне самую настоящую травлю в социальных сетях за то, что я поддержал моего президента. Но моя Родина - Россия! Я русский человек. Я родился в самом известном роддоме Москвы имени Грауэрмана. И мне не стыдно, что я русский! А тем, кто на каждом углу скандирует, что ему стыдно, я, честно сказать, удивляюсь. Видимо, многие на сегодняшний день все еще не понимают серьезности проводимой нашей страной спецоперации. Но, я надеюсь, что время все расставит по своим местам.","type":"paragraph"},{"html":"<strong>Esque:</strong> Александр, спасибо большое за очень интересное интервью. Есть ли у вас какое-то наставление для наших читателей?","type":"paragraph"},{"html":"<strong>Александр:</strong> Скорее, есть пожелание: пусть в каждом дне будет хотя бы один повод для улыбки.","type":"paragraph"},{"html":"Алена Балагурова","type":"paragraph"},{"html":"Маргарита Мирзеханова","type":"paragraph"},{"type":"image","mediaId":"cmrmqtspz00e2uktaz4r5x77e"}]'::jsonb,'cmrmqtry300e1uktaxutz8o13','cmrm8kzli000ikwtafbw33jnj','cmrm8kzns000jkwtahwuubl9w','cmrmpdrom0000sstarkqxwts4','2022-09-04T06:00:00.000Z'::timestamp,NULL,NULL,NULL,524,'/persona/intervju/524-aleksandr-davydov-byt-russkim-ne-stydno.html','2026-07-15T21:00:49.366Z'::timestamp,'2026-07-16T13:58:18.377Z'::timestamp,'''2001'':977C ''2006'':701C ''2007'':929C ''2010'':741C,922C,1042C,1281C ''2011'':979C ''2013'':1283C ''3'':1039C,1278C ''aктep'':989C ''cmrmqtspz00e2uktaz4r5x77e'':1429C ''esqu'':106C,113C,213C,296C,373C,492C,561C,650C,720C,890C,1052C,1108C,1179C,1224C,1377C ''imag'':1427C ''paragraph'':111C,130C,211C,220C,294C,309C,371C,390C,490C,501C,559C,570C,648C,667C,718C,736C,888C,925C,1050C,1067C,1106C,1121C,1177C,1196C,1222C,1239C,1375C,1397C,1415C,1420C,1425C ''peжиccep'':987C ''аpцибaшeв'':958C,991C ''автомеханическ'':270C ''актер'':7B,17C,36C,60C,120C,141C,360C,676C,948C,973C,1006C ''актерск'':208C,423C,482C ''ал'':1417C ''александр'':1A,62C,108C,114C,132C,222C,311C,392C,503C,572C,658C,669C,738C,927C,1069C,1123C,1198C,1241C,1378C,1399C ''амплу'':1092C ''антипод'':810C ''артист'':74C,693C ''бабушк'':328C ''балагуров'':1418C ''баллад'':746C,854C,875C ''баллончик'':879C ''бизнес'':196C ''больш'':145C,348C,992C,1259C,1380C ''бомбер'':748C ''борот'':831C ''брал'':167C ''будущ'':480C ''бумаг'':171C ''быва'':1248C ''быстр'':277C ''ваш'':378C,663C,733C,915C,1056C ''верн'':307C,1200C ''вернул'':1192C ''вид'':634C ''видел'':941C,1100C ''видим'':198C,1350C ''вниман'':232C ''внутр'':820C ''волос'':878C ''вообщ'':565C ''ворот'':716C ''воспитан'':327C ''врач'':332C ''врем'':1368C ''времен'':363C ''втор'':134C,780C ''выбор'':407C ''вызыва'':159C ''высок'':804C ''высот'':42C ''г'':980C ''гастролир''