INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrjgx004wukta47avzjnt','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Как пережить развод?','Как пережить развод?','622-kak-perezhit-razvod','[{"html":"Как пережить развод? Это острый вопрос, ответ на который ищут 70% людей в современном обществе.","type":"paragraph"},{"html":"50% разводов по статистике приходится на жителей мегаполисов. В провинциях разводятся реже.","type":"paragraph"},{"html":"Почему так происходит?","type":"paragraph"},{"html":"Почему некогда родные люди становятся чужими?","type":"paragraph"},{"html":"Как обрести себя вновь? Поверить в то, что счастье есть, а главное новая любовь обязательно найдет тебя!","type":"paragraph"},{"html":"<b>На все эти вопросы нам ответили наши герои:</b>","type":"paragraph"},{"html":"<i>Ирина Безуглова - интегральный психолог @bezuglova_irina_</i>","type":"paragraph"},{"html":"<i>Алеся Кусабкулова – психосоматолог, телесный практик @alesya_med</i>","type":"paragraph"},{"html":"<i>Алена Зыкова – ведический астролог @mind_alena</i>","type":"paragraph"},{"html":"<i>Галина Алусова – психолог, энергопрактик, игропрактик @galina_alusova</i>","type":"paragraph"},{"html":"<i>Марина Руднева – клинический психолог, гипнотерапевт, психосоматолог @maru_energy</i>","type":"paragraph"},{"html":"<i>Мария Соломатина – энерготерапевт, психолог @mari.wonder</i>","type":"paragraph"},{"html":"<i>Юлия Чистякова – психолог, физиогномист @yuliya_chistyakova</i>","type":"paragraph"},{"html":"<i>Боброва Екатерина – психотерапевт @bobrova.psycholog</i>","type":"paragraph"},{"html":"<i><u>Благодарим бренд @toryzak и стилиста @elenagladkovaa в Санкт-Петербурге, а также бренд @joys.factory в Москве за предоставлением образов нашим героям!</u></i>","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/Ck9AwRRSLhQ?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" title=\"Как пережить развод?\"></iframe>","type":"embed"}]'::jsonb,'cmrmqrjfl004vuktathlajuaz','cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2023-11-20T06:00:00.000Z'::timestamp,NULL,NULL,NULL,622,'/psihologija/intervju-2/622-kak-perezhit-razvod.html','2026-07-15T20:59:04.017Z'::timestamp,'2026-07-16T13:57:06.206Z'::timestamp,'''50'':25C ''70'':17C ''alena'':110C ''alesya'':100C ''alusova'':120C ''bezuglova'':90C ''bobrova.psycholog'':155C ''chistyakova'':148C ''elenagladkovaa'':164C ''emb'':183C ''energi'':131C ''galina'':119C ''irina'':91C ''joys.factory'':172C ''mari.wonder'':139C ''maru'':130C ''med'':101C ''mind'':109C ''paragraph'':23C,38C,44C,53C,73C,84C,93C,103C,112C,122C,133C,141C,150C,157C,181C ''toryzak'':161C ''yuliya'':147C ''ал'':95C,105C ''алусов'':115C ''астролог'':108C ''безуглов'':87C ''благодар'':159C ''бобров'':152C ''бренд'':160C,171C ''ведическ'':107C ''внов'':58C ''вопрос'':12C,78C ''галин'':114C ''геро'':82C,179C ''гипнотерапевт'':128C ''главн'':66C ''екатерин'':153C ''жител'':31C ''зыков'':106C ''игропрактик'':118C ''интегральн'':88C ''ирин'':86C ''ищут'':16C ''клиническ'':126C ''котор'':15C ''кусабкулов'':96C ''любов'':68C ''люд'':18C,49C ''мар'':135C ''марин'':124C ''мегаполис'':32C ''москв'':174C ''найдет'':70C ''нам'':79C ''наш'':81C,178C ''некогд'':47C ''нов'':67C ''образ'':177C ''обрест'':56C ''обществ'':21C ''обязательн'':69C ''остр'':11C ''ответ'':13C,80C ''переж'':2A,5B,8C ''петербург'':168C ''повер'':59C ''поч'':40C,46C ''практик'':99C ''предоставлен'':176C ''приход'':29C ''провинц'':34C ''происход'':42C ''психолог'':89C,116C,127C,138C,145C ''психосоматолог'':97C,129C ''психотерапевт'':154C ''развод'':3A,6B,9C,26C,35C ''реж'':36C ''родн'':48C ''руднев'':125C ''сан