INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqehyy002kpota89tfzyrq','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Павел Дуров и его дети. 3+2+100 = ?','Узнайте о личной жизни основателя Telegram Павла Дурова: кто его дети, как он их воспитывает и какие ценности передает.','673-pavel-durov-i-ego-deti-32100','[{"html":"Весь интернет буквально пестрит заголовками о появлении нового многодетного отца в селебрити-сообществе. Выяснилось, что некогда одиночка, а заодно и владелец многомиллиардного состояния, Павел Дуров оказался отцом более ста детей.","type":"paragraph"},{"html":"Все началось с того, что в интернет-пространстве объявилась мать 3 детей Павла Дурова. Ирина Болгар, жительница Санкт-Петербурга, рассказала, что является матерью детей Павла Дурова, создателя Telegram. На это заявление внезапно последовал ответ и от самого предполагаемого отца. Оказалось, что помимо 3 детей, у Павла есть еще более 100 по всему миру.","type":"paragraph"},{"html":"Молодой миллиардер признался, что 15 лет назад стал донором спермы в одной из российских клиник и на сегодняшний день у него более сотни детей в 12 странах. Предприниматель также заявил, что планирует открыть код своей ДНК, чтобы его биологическим детям было проще найти друг друга.","type":"paragraph"},{"html":"Ирина Болгар подтвердила новость Павла о банке доноров, но свой факт зачатия назвала естественным: \"Наша с Павлом пара не испытывала проблем с репродукцией, чтобы прибегать к помощи специалистов в данном вопросе. Все наши дети были зачаты и рождены естественным путём. И да, дети были признаны официально согласно свидетельствам о признании отцовства и свидетельствам о рождении\".","type":"paragraph"},{"html":"Женщина также отметила, что, несмотря на проживание в разных странах, они часто встречались и даже мать и брат Дурова приезжали в гости к Ирине и детям. Однако совместными фото и сканами свидетельств о рождении детей, женщина свои слова не подкрепила.","type":"paragraph"},{"html":"На шокирующую новость отреагировали многие звезды.","type":"paragraph"},{"html":"«Очевидно, что Павел, сработал на опережение и решил принизить статус Ирины как матери его детей, и всех потенциальных, кто объявится в будущем. Дескать, где три — там и сто» - дала свою оценку происходящему Ксения Собчак.","type":"paragraph"},{"html":"Если вся история правдива, то женщина вполне обоснованно претендует на признание обществом происхождение своих детей, ведь еще о двух детях предпринимателя знает весь мир.","type":"paragraph"},{"html":"«Сейчас, когда дети подросли и начали задавать вопросы, почему о них нет информации в интернете в отличие от двух старших детей их отца, я приняла решение вынести эту информацию в свет. Что касается подтверждающих документов, конечно, они у меня имеются, равно, как и совместные фотографии», — объяснила свою позицию Болгар.","type":"paragraph"},{"html":"Остается только догадываться, как обстоят дела в действительности и ждать новой серии «русской Санты-Барбары».","type":"paragraph"}]'::jsonb,'cmrmqehxq002jpotam08i6yjz','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-07-30T06:00:00.000Z'::timestamp,NULL,NULL,NULL,673,'/v-mire/673-pavel-durov-i-ego-deti-32100.html','2026-07-15T20:48:55.546Z'::timestamp,'2026-07-16T13:56:33.737Z'::timestamp,'''+100'':8A ''+2'':7A ''100'':113C ''12'':145C ''15'':124C ''3'':6A,73C,106C ''paragraph'':60C,118C,166C,224C,267C,276C,313C,340C,392C,411C ''telegram'':14B,91C ''банк'':174C ''барбар'':409C ''биологическ'':158C ''болгар'':78C,169C,390C ''брат'':243C ''будущ'':299C ''буквальн'':30C ''ве'':28C,337C ''владелец'':49C ''внезапн'':95C ''вопрос'':198C,349C ''воспитыва'':23B ''вполн'':321C ''всем'':115C ''встреча'':238C ''вся'':316C ''вынест'':368C ''выясн'':42C ''гост'':247C ''дал'':306C ''дан'':197C ''двух'':333C,