INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsj2f008mukta66jl0exu','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'10 сезон проекта Fashion bitva назвал новые имена в мире российской моды','18 декабря в концертном зале «Arbat Hall» прошел финал 10 сезона проекта «Fashion bitva».','586-10-sezon-proekta-fashion-bitva-nazval-novye-imena-v-mire-rossijskoj-mody','[{"html":"18 декабря в концертном зале «Arbat Hall» прошел финал 10 сезона проекта «Fashion bitva». Свои коллекции на тему «Будущее 32» представили дизайнеры из Благовещенска, Тюмени, Красноярска, Смоленска, Нальчика, Улан-Удэ, Краснодара, Ростова-на-Дону, Нижнего Новгорода, Комсомольска-на-Амуре, Вологды, Казани, Москвы, Санкт-Петербурга и других городов России.","type":"paragraph"},{"html":"Ведущим мероприятия выступил обаятельный Илья Шпак, входящий в состав 100 лучших ведущих России. А открыла мероприятие несравненная Мэри Ян со своим свежим синглом «Огни Москвы».","type":"paragraph"},{"html":"Первая внеконкурсная коллекция, появившаяся на подиуме, была представлена ростовским дизайнером Раисой Мирошниченко. Сочетание пышных ярких платьев и стиля рок произвели на гостей неизгладимое впечатление. Казанский дизайнер Светлана Зленко также выступила с коллекцией платьев для маленьких модниц под названием «Pearl», что в переводе означает «жемчужина». Ручной декор, сочетание тканей и фактур, благородный блеск тканей и вышивки сделали из моделей юных принцесс, которые словно парили по глянцевому подиуму.","type":"paragraph"},{"html":"<i>Дизайнер: Раиса Мирошниченко</i>","type":"paragraph"},{"html":"Коллекция для подростков \"FESTIVE TEEN\" Виктории Надолинской отразила эпатажный характер подростка. Эта коллекция, как признается сам дизайнер, с характером и передает поведение подростка и его отношение с окружающим миром.","type":"paragraph"},{"html":"Этого же правила придерживается и Татьяна Брамарецкая – дизайнер из Комсомольска-на-Амуре.","type":"paragraph"},{"html":"Ее коллекция \"MAD MAX\" выполнена в стиле киберпанк. Носибельный футуризм из ярких цветов плащевой ткани с ручной авторской стежкой.","type":"paragraph"},{"html":"Приятно удивила членов жюри и гостей коллекция иэ экокожи и фатина с инкрустацией стразами swarovski «Fashion Skin Art» дизайнеров Таовы Залины и Карчаевой Лейлы, приехавшей полным составом из Нальчика. Каждый образ в коллекции был дополнен портретом с ручной росписью кабардино-балкарского художника Сабанчиевой Кариной.","type":"paragraph"},{"html":"<i>Дизайнеры: Таова Залина и Карчаева Лейла</i>","type":"paragraph"},{"html":"Впервые на показе приняли участие внеконкурсные коллекции сумок российских брендов «Rovgor» и «MARK&amp;FOX».","type":"paragraph"},{"html":"«MARK&amp;FOX» презентовал коллекцию классических сумок из натуральной кожи с яркой красной подкладкой, украшенные золотой итальянской фурнитурой под названием «Black Heart».","type":"paragraph"},{"html":"Бренд «Rovgor» представил зрителям совершенно отличные от коллег образы. Сумки из натуральной итальянской кожи козы и итальянского краста с боковинами из ясеня, дополненные композицией из сухоцветов в ювелирной смоле нашли своего потребителя среди гостей.","type":"paragraph"},{"html":"Победитель регионального этапа в городе Владивосток, Кожеурова Юлия, продемонстрировала жюри коллекцию под названием «С чистого листа».","type":"paragraph"},{"html":"<em>«Коллекция «С чистого листа» - это как глоток свежего воздуха, белый цвет - главный и сопутствующий, символ чистоты и света, который обязательно ждёт нас в будущем. </em>","type":"paragraph"},{"html":"<em>Девушка 2032 года - это смелая, яркая, стильная, непохожая на всех. Девушка, для которой комфорт, оригинальность, женственность стоит на первом месте. </em>","type":"paragraph"},{"html":"<em>Я уверена, девушки в будущем вспомнят все техники рукоделия и обязательно будут их применять в декорировании своей одежды. Именно в этом будет их изюминка и оригинальность» - так прокомментировала свою коллекцию дизайнер.</em>","type":"paragraph"},{"html":"Гости и участники смогли насладиться не только коллекциями дизайнеров, но и потрясающим голосом еще одной певицы АИЛИ. Ее синглы «Не безопасно» и «Гугл карты» закрыли мероприятие и дали возможность гостям отдохнуть в середине мероприятия!","type":"paragraph"},{"html":"Дизайнер Нелли Крук из Нижнего Новгорода с коллекцией платьев в стиле деконструкции из 57 элементов “Love is peace” заняла почетное 2 место. Ее коллекция образов-трансформеров из натуральных итальянских тканей восхитила не только членов жюри, но и гостей конкурса. Сам дизайнер признается, что она не боится экспериментировать с геометрией, фактурой и силуэтом.","type":"paragraph"},{"html":"<i>Дизайнер: Нелли Крук </i>","type":"paragraph"},{"html":"Первое место было отдано вологодскому «Артелю Нарядно». Автор проекта Снежана Малашина впервые участвовала в конкурсе. На создание льняной одежды с принтами ее вдохновило народное искусство русского севера 19-20 веков. А именно: резьба, росписи, вышивки, набойки. На основе древних орнаментов, росписей с предметов народного быта и была сделана конкурсная коллекция «Черным бело».","type":"paragraph"},{"html":"<i>Артель Нарядно </i>","type":"paragraph"},{"html":"Поздравляем победителей и благодарим всех участников конкурса!","type":"paragraph"},{"html":"<strong><u>Отдельная благодарность жюри за честное судейство и экспертную оценку наших дизайнеров: </u></strong>","type":"paragraph"},{"html":"- Ольге Сысоевой (стилист модного дома «SERGEY SYSOEV», член Союза дизайнеров России, преподаватель Института дизайна РГУ им.А.Н.Косыгина);","type":"paragraph"},{"html":"- Оксане Огневой (стилист FASHION показов, креативных фотопроектов и известных детей-блогеров, главный стилист продюсерского центра «Грани»;","type":"paragraph"},{"html":"- Александру Белову (международный эксперт по стилю, лауреат премий \"Стилист года\" (Будапешт), \"Fashion-эксперт года\" (Милан), \"Глянцевый имиджмейкер года\");","type":"paragraph"},{"html":"- Софье Тихоновой (создатель бренда изделий ручной работы «Sonya Tikhonova», выпускница и преподаватель в Британке. Участница показов MBFW и FUTURUM в Москве. Ее работы можно найти в Vogue Russia, Lofficiel, Tatler Russia. А изделия дизайнера можно увидеть на IOWA, Suzanna, Ян Гэ, ANIKV, Тосе Чайкиной, Алёне Воданаевой и Варваре Шмыковой).","type":"paragraph"},{"html":"<strong><u>А также благодарим звездных участников проекта, украсивших этот снежный день своим присутствием:</u></strong>","type":"paragraph"},{"html":"- Антона Зацепина (талантливый артист, актер, танцор, финалист Фабрики Звезд 4, модель дизайнера Натальи Советской);","type":"paragraph"},{"html":"- Анну Калашникову (российская актриса, ведущая, певица, модель дизайнера Александры Кононенко);","type":"paragraph"},{"html":"- Екатерину Хомчук (российская актриса, модель дизайнера Снежаны Малашиной);","type":"paragraph"},{"html":"- Катрин Асси (российская актриса, модель дизайнера Юлии Кожеуровой).","type":"paragraph"},{"html":"<i>Дизайнер: Наталья Советская </i>","type":"paragraph"},{"html":"<i>Дизайнер: Юлия Кожеурова</i>","type":"paragraph"},{"html":"<i>Дизайнер: Аделя Курносова</i>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqsh8b008fuktapycdsp2m"},{"mediaId":"cmrmqshia008gukta3d54w25e"},{"mediaId":"cmrmqshpv008huktaad765c68"},{"mediaId":"cmrmqsi26008iukta7jbrtb43"},{"mediaId":"cmrmqsihp008juktaobqqhs4z"},{"mediaId":"cmrmqsitn008kuktacba6ar6z"},{"mediaId":"cmrmqsj0m008luktafuag04p1"}]}]'::jsonb,'cmrmqsgs5008euktavzie13mn','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2022-12-29T06:00:00.000Z'::timestamp,NULL,NULL,NULL,586,'/projects-esque/fashion-bitva/586-10-sezon-proekta-fashion-bitva-nazval-novye-imena-v-mire-rossijskoj-mody.html','2026-07-15T20:59:50.151Z'::timestamp,'2026-07-16T13:57:36.432Z'::time