INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrl7b0055ukta0pg7u7e5','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Международный конкурс дизайнеров Fashion bitva открывает академию по пиару и маркетингу в сфере моды','Мир моды в России изменчив, как и настроение дизайнеров.','619-mezhdunarodnyj-konkurs-dizajnerov-fashion-bitva-otkryvaet-akademiju-po-piaru-i-marketingu-v-sfere-mody','[{"html":"Мир моды в России изменчив, как и настроение дизайнеров. И связано это не с творческим кризисом творцов, а с отсутствием помощи и знаний из вне. Российской индустрии моды все сложнее заявить о себе, а с закрытием международных возможностей ситуация становится патовой.","type":"paragraph"},{"html":"Отсутствие государственной поддержки и рабочей силы в виде закройщиков и портных, невозможность развиваться за границей, нехватка знаний, понимания бизнес процессов и стратегии продвижения личного бренда.","type":"paragraph"},{"html":"<em>«В России очень мало качественного образования в сфере моды, а если оно есть, то стоит очень дорого и позволить его себе могут не все. Существуют конкурсы молодых дизайнеров, благодаря которым молодые дарования могут получить стажировки и участие в более значимых проектах, но этого не достаточно. Дизайнеры должны сами уметь шить и сами понимать как сделать свой бренд успешным. Только полное понимание рынка даст возможность построить успешный бренд и создать прочную команду» - рассуждает организатор конкурса </em><em>Fashion </em><em>bitva, Алена Балагурова.</em>","type":"paragraph"},{"html":"Долгие годы, наблюдая за проблемами молодых дизайнеров и понимая чего им так не хватает, организаторы конкурса решили создать свою школу с детальным изучением пиара и маркетинга в сфере моды в России.","type":"paragraph"},{"html":"Fashion Marketing Academy – школа современного формата, позволяющая любому специалисту обрести необходимые навыки для самостоятельного продвижения себя, как дизайнера, или своего бренда в социальных сетях, наладить взаимодействие с глянцевыми изданиями и СМИ, а также выбрать правильную pr-стратегию для успешного развития продукта. Старт проекта уже 22 января 2024 года!","type":"paragraph"},{"html":"<em>«Наша школа заточена только под создание личного бренда с учетом тех сложностей в России, с которыми мы все столкнулись: уход глянца из России, а также многих важных и нужных социальных сетей. Мы будем строить личный бренд в тех условиях, в которых существуем сейчас» - добавляет директор проекта. </em>","type":"paragraph"},{"html":"Отличительная и важная особенность школы – это самостоятельное создание бренда уже в рамках обучения под руководством кураторов. Двухмесячное обучение даст возможность не только получить знания, но и применить их на практике в период обучения!","type":"paragraph"},{"html":"Для каждого дизайнера важна постоянная поддержка, подпитка эмоциями и положительными результатами. Очень часто я наблюдала плачевные истории дизайнеров после прохождения того или иного обучения. Заканчивается обучение, проходит запал и дизайнер перестает развиваться. Так быть не должно!» - делиться своим опытом Алена.","type":"paragraph"},{"html":"Дизайнер – это творческий человек, со своими внешними проблемами и переживаниями, очень часто с неуверенностью в себе и своих силах. Именно поэтому создатели академии добавили в курс школы занятия с психологом. Уроки с психологом будут проходить как в групповом формате, так и индивидуальном! Раскрепощение себя, разбор своего «я» и понимания своих возможностей даст возможность развиваться, здраво оценивать свои силы и после прохождения обучения!","type":"paragraph"},{"html":"Итак, что ждет моду в России?","type":"paragraph"},{"html":"Развитие, успех и преодоление всех трудностей - так считают создатели многих проектов в сфере моды в России, которые помогают молодым дизайнерам расти и развиваться.","type":"paragraph"},{"html":"А мы желаем удачи молодым талантам и развития Fashion Marketing Academy!","type":"paragraph"}]'::jsonb,'cmrmqrl5p0054uktao72xlwuu','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2023-10-26T06:00:00.000Z'::timestamp,NULL,NULL,NULL,619,'/fashion/news-2/619-mezhdunarodnyj-konkurs-dizajnerov-fashion-bitva-otkryvaet-akademiju-po-piaru-i-marketingu-v-sfere-mody.html','2026-07-15T20:59:06.263Z'::timestamp,'2026-07-16T13:57:08.940Z'::timestamp,'''2024'':258C ''22'':256C ''academi'':213C,501C ''bitva'':5A,171C ''fashion'':4A,170C,211C,499C ''market'':212C,500C ''paragraph'':66C,94C,175C,209C,261C,310C,346C,389C,454C,463C,489C,503C ''pr'':247C ''pr-стратег'':246C ''академ'':7A,413C ''ал'':172C,387C ''балагуров'':173C ''бизнес'':86C ''благодар'':124C ''бренд'':92C,152C,162C,231C,270C,298C,320C ''буд'':295C ''будут'':424C ''важн'':289C,314C,351C ''взаимодейств'':236C ''вид'':75C ''вне'':48C ''внешн'':397C ''возможн'':61C,159C,331C,441C,443C ''выбра'':244C ''глянц'':283C ''глянцев'':238C ''год'':178C,259C ''государствен'':69C ''границ'':82C ''группов'':428C ''дарован'':127C ''даст'':158C,330C,442C ''двухмесячн'':328C ''дел'':384C ''детальн'':198C ''дизайнер'':3A,23B,32C,123C,141C,183C,228C,350C,365C,377C,391C,484C ''директор'':307C ''добав'':414C ''добавля'':306C ''долг'':177C ''должн'':142C,383C ''дор'':112C ''достаточн'':140C ''ждет'':458C ''жела'':493C ''заканчива'':372C ''закройщик'':76C ''закрыт'':59C ''занят'':418C ''запа'':375C ''заточ'':265C ''заяв'':54C ''здрав'':445C ''знан'':46C,84C,335C ''значим'':135C ''издан'':239C ''изменч'':19B,28C ''изучен'':199C ''имен'':410C ''ин'':370C ''индивидуальн'':432C ''индустр'':50C ''истор'':364C ''итак'':456C ''кажд'':349C ''качествен'':100C ''команд'':166C ''конкурс'':2A,121C,169C,192C ''котор'':125C,278C,303C,481C ''кризис'':39C ''куратор'':327C ''курс'':416C ''личн'':91C,269C,297C ''люб'':218C ''мал'':99C ''маркетинг'':11