INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqu4nf00frukta6nzaben7','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Dior выпустит полностью натуральный J’Adore','Бренд Dior представил революционный парфюм J''adore Parfum d''Eau – он станет первым ароматом в истории полностью на водной основе.','505-dior-vypustit-polnostju-naturalnyj-jadore','[{"html":"<b>Бренд Dior представил революционный парфюм J''adore Parfum d''Eau – он станет первым ароматом в истории полностью на водной основе. В нём не будет спирта и синтетических соединений.</b>","type":"paragraph"},{"html":"Отказ от спирта стал возможен благодаря технологии, которая была разработана и запатентована Dior. Бренд утверждает, что новый аромат будет даже более стойким, чем предыдущие. Кроме того, он не липкий и не оставляет следов на одежде. В состав войдут флердоранж, жасмин, дамасская роза и магнолия. Лицом аромата J’Adore вновь станет Шарлиз Терон.","type":"paragraph"},{"html":"Флакон будет выполнен из белого стекла в форме античной амфоры. Аромат будет доступен в трёх объёмах: 30, 50 и 100 мл. Продажи новинки от Dior начнутся в сентябре.","type":"paragraph"},{"html":"Аромат J’Adore выпускается с 1999 года и считается одним из самых успешных парфюмов в мире.","type":"paragraph"}]'::jsonb,'cmrmqu4m700fqukta0wyp8zd8','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyxz0009kwtay5bvzu16','cmrmpdrom0000sstarkqxwts4','2022-08-20T06:00:00.000Z'::timestamp,NULL,NULL,NULL,505,'/beauty/news-3/505-dior-vypustit-polnostju-naturalnyj-jadore.html','2026-07-15T21:01:04.779Z'::timestamp,'2026-07-16T13:58:32.930Z'::timestamp,'''100'':132C ''1999'':149C ''30'':129C ''50'':130C ''ador'':6A,13B,33C,105C,146C ''d'':15B,35C ''dior'':1A,8B,28C,70C,137C ''eau'':16B,36C ''j'':5A,12B,32C,104C,145C ''paragraph'':56C,111C,142C,161C ''parfum'':14B,34C ''амфор'':122C ''античн'':121C ''аромат'':20B,40C,75C,103C,123C,144C ''бел'':117C ''благодар'':63C ''бренд'':7B,27C,71C ''внов'':106C ''водн'':25B,45C ''возмож'':62C ''войдут'':95C ''выполн'':115C ''выпуска'':147C ''выпуст'':2A ''год'':150C ''дамасск'':98C ''доступ'':125C ''жасмин'':97C ''запатентова'':69C ''истор'':22B,42C ''котор'':65C ''кром'':82C ''липк'':86C ''лиц'':102C ''магнол'':101C ''мир'':159C ''мл'':133C ''натуральн'':4A ''начнут'':138C ''нем'':48C ''нов'':74C ''новинк'':135C ''объем'':128C ''одежд'':92C ''одн'':153C ''основ'':26B,46C ''оставля'':89C ''отказ'':58C ''парфюм'':11B,31C,157C ''перв'':19B,39C ''полност'':3A,23B,43C ''представ'':9B,29C ''предыдущ'':81C ''продаж'':134C ''разработа'':67C ''революцион'':10B,30C ''роз'':99C ''сам'':155C ''сентябр'':140C ''синтетическ'':53C ''след'':90C ''соединен'':54C ''соста'':94C ''спирт'':51C,60C ''стал'':61C ''станет'':18B,38C,107C ''стекл'':118C ''стойк'':79C ''счита'':152C ''терон'':109C ''технолог'':64C ''трех'':127C ''успешн'':156C ''утвержда'':72C ''флакон'':113C ''флердоранж'':96C ''форм'':120C ''шарлиз'':108C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqyf1u00stukta6kmtqbng','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Нон-фикшн, боллитра и фэнтези: что представляет собой литература XXI века?','Литературное направление меняется с каждым днем.','377-non-fikshn-bollitra-i-fjentezi-chto-predstavljaet-soboj-literatura-xxi-veka','[{"html":"За последние несколько десятков лет литература претерпела значительные изменения, затронувшие всех участников процесса. Читатель больше не ограничен в выборе, а писателю стало гораздо проще явить свое произведение миру. ESQUE пообщался с современными авторами о литературных трендах, популярных жанрах и любви к книге.","type":"paragraph"},{"html":"<b>Краткость и доступность</b>","type":"paragraph"},{"html":"Литературоведы считают, что современная литература как таковая началась порядка трех десятилетий назад. И все же нельзя не заметить отличия в произведениях нынешнего и прошлого веков. Причина тому - веяния времени, поскольку стиль и уклады жизни эпох так или иначе находят свое отражение в большинстве литературных трудов. Эксперты полагают, что 21 век стал началом конца для объемных поэм и многотомных романов. Им на смену пришли более емкие книги, для знакомства с которыми порой хватит и одного дня - идеальное решение для бешеного ритма жизни современного человека.","type":"paragraph"},{"html":"Елена Обухова, писатель, автор циклов “Нормальное аномальное (“Секретное досье”) и “Городские легенды”, видит разницу между прошлым и нынешним веком в том, какие именно произведения сегодня доходят до читателя. Раньше этот вопросы регулировали издательские фильтры, но время глобального распространения интернета и сайтов самиздата диктует свои правила.","type":"paragraph"},{"html":"“Раньше решения принимали редакторы, исходя их своих представлений об интересном, хорошо написанном произведении, имеющем потенциал стать популярным. Были определенные требования к длине, тематике и так далее. Тиражи были больше, разнообразие – меньше. Выгоднее продать один роман тиражом в 50 тысяч, чем 10 романов тиражами по 5 тыс. Если ты не заинтересовал редактора или просто не оказался тем одним из десяти, кого выбрали, то тебе предстоит дальше писать в стол и оставаться неизвестным. Сейчас же можно пойти в электронный самиздат и получить шанс на свою аудиторию. Даже если твое произведение не издадут, ты все равно можешь собрать вокруг себя тех, кому интересны именно твои манера и стиль, именно твои темы”, - рассказала писательница.","type":"paragraph"},{"html":"<b>Изменчивость и стабильность</b>","type":"paragraph"},{"html":"Тренды, как известно, не стоят на месте. По данным портала ЛитРес, наиболее востребованными в 2020-2021 годах стали мотивационные книги, произведения о воспитании детей, инвестированию, управлению бизнесом, психологии, хобби. Познавательная проза заняла особую нишу на книжном рынке, но развлекательная литература также продолжает оставаться на высоких позициях, меняя тенденции с большой скоростью.","type":"paragraph"},{"html":"“Они обновляются чуть ли не каждый год и отличаются в зависимости от того, смотрим ли мы на “боллитру”, развлекательную литературу или нон-фикшн. Если говорить о развлекательной литературе, к которой я отношусь и, соответственно, за которой слежу, то здесь тренды отличаются даже в зависимости от того, где и как ты публикуешь свои произведения. На каждом портале самиздата – своя целевая аудитория со своими запросами, у читателей бумажных книг – другие интересы”, - поделилась Елена Обухова.","type":"paragraph"},{"html":"<b>Знания и развитие</b>","type":"paragraph"},{"html":"Если зайти в книжный магазин, то в большинстве случаев на полках бестселлеров можно встретить книги, представляющие собой познавательную литературу. Это отличная возможность для тех, кто хочет прокачать свои знания и обогатить внутренний мир. В произведениях авторы делятся своими знаниями в медицине, психологии, досуге, бизнесе, искусстве и многих других направлениях. Подобная литература имела популярность и раньше, когда была представлена в виде справочников. Наверняка такие и сегодня найдутся на полках во множестве квартир. С тех пор она прошла некую трансформацию - знания в познавательной литературе теперь подаются доступным, красочным языком.","type":"paragraph"},{"html":"“Думаю, подобные книги нравятся читателям из-за наличия нужной информации. В них собраны советы и личный опыт в той или иной области, а это - лучший способ получить знания по достаточно низкой цене. Люди читают и изучают то, что они смогут повторить самостоятельно. Например, моя книга рассказывает о том, как своими руками грамотно озеленить квартиру. И подобных произведений - множество. При чем новую информацию можно использовать не только в повседневной жизни. Благодаря познавательным книгам люди оттачивают свои профессиональные навыки, а это очень заманчиво”, - поделилась своим мнением Ксения Занина, автор бестселлера “Цветок в горшке”.","type":"paragraph"},{"html":"<b>Расследования и любовь</b>","type":"paragraph"},{"html":"Для большинства читателей романтика художественного мира также не теряет своей привлекательности. Если говорить о развлекательной литературе, то здесь популярность остается за фантастикой, любовными романами, триллерами и детективами. Они давно завоевали читательские сердца и по сей день не выходят из моды. При этом сами писатели отдают наибольшее предпочтение именно детективам.","type":"paragraph"},{"html":"“Детективы дают большой простор для фантазии, поскольку все они очень разные. На книжных полках сегодня можно найти большое многообразие произведений: от веселых, легкомысленных иронических детективов до мрачного скандинавского нуара, а также исторические, фантастические, фэнтезийные, так называемые “женские” (с сильной любовной линией), с уклоном в психологический триллер или мистику… В целом, на детективную интригу можно “повесить” очень многое, и результат будет очень отличаться. Любовный жанр также весьма популярен и среди читателей, и среди писателей. Фэнтези не сдает позиции, а вот фантастика (включая мистику), как мне кажется, сейчас уступает этому жанру”, - уточнила автор.","type":"paragraph"},{"html":"Кстати, эксперты утверждают, что любовь к детективам напрямую связана с работой мозга. История на страницах позволяет полностью окунуться в расследование, напрячь “серые клеточки” (как говорил знаменитый Эркюль Пуаро) и переживать целый спектр эмоций. Некий выброс адреналина без реальной угрозы. Интересно, правда?","type":"paragraph"},{"html":"<b>Книги и соцсети</b>","type":"paragraph"},{"html":"Социальные сети вытеснили книгу. С этим убеждением нередко можно столкнуться, оно особенно распространено у представителей старшего поколения. Частично это можно назвать правдой: глобализация интернета забрала молодежь с библиотечных скамеек и усадила перед компьютером и смартфонами. Тем не менее, со временем всемирная паутина вернула тренд на книги и открыла дорогу новым писателям. Сегодня у читателя есть широкий простор в выборе произведений, а современная литература позволяет удовлетворить более узкие, специализированные читательские потребности.","type":"paragraph"},{"html":"“Соцсети упростили общение писателя и читателя. Через них авторы быстрее получают отклик и могут услышать свою аудиторию, а не только профессиональных рецензентов, критиков. Многие ориентируются на их мнение даже больше, чем на собственное, стараясь подстроиться и удовлетворить определенные запросы. Иногда читатели выступают практически соавторами, когда произведение пишется и публикуется в процессе. На мой взгляд, нынешние литературные произведения более ориентированы на читателя, нежели раньше”, - подчеркнула Елена Обухова.","type":"paragraph"},{"html":"<b>Литература и конкуренция</b>","type":"paragraph"},{"html":"Еще сотню лет назад книгу считали основным источником знаний. Постепенно ей на смену пришло радио, затем телевидение. Поначалу она сопротивлялась, но сдалась под натиском интернета. Сегодня многие говорят, что книга уходит в прошлое. Данное утверждение можно взять на веру, если учитывать исключительно ее бумажную версию. Повинуясь ходу времени, литература не покидает мир окончательно, а приобретает иные формы: электронные версии, аудиокниги. Писатели продолжают делиться своими историями, ежедневно подсчитывая количество прослушиваний и скачиваний своих произведений на различных платформах. Спрос рождает предложение, а оно держит интерес на плаву.","type":"paragraph"},{"html":"“Конечно, у книг сейчас много конкурентов: кино, телешоу, соцсети, игры. Но не надо забывать, что и людей сейчас гораздо больше, чем когда-либо было. Может быть, в процентном соотношении тех, кто отдает предпочтение книге, и становится меньше, но становится ли при этом меньше читающих в абсолютных цифрах? Я вижу, что книги пишутся, издаются, продаются, скачиваются на пиратках – и потом читаются. А еще переходят в аудиоформат и слушаются. До ухода в прошлое им пока еще далеко. Что до чтения в целом - очень многое зависит от семьи. Читающие родители, как правило, прививают интерес к чтению и детям”, - рассказала Елена Обухова.","type":"paragraph"},{"html":"Какой книга будет дальше - вопрос риторический. Пока остается только догадываться, какие трансформации ожидают литературу в дальнейшем, и как это скажется на читательском интересе.","type":"paragraph"},{"html":"“Новое поколение имеет свой образ мышления, больше склоняется к визуальному восприятию информации. Человека нужно успеть заинтересовать в течение 6-30 секунд. Если этого не произошло, скорее всего, он перелистнет видео, закроет страничку с текстом или фотографию. Книгам, определенно, нужно искать свои способы выжить в современном мире. Кстати, недавно у меня был интересный опыт. Я купила своему ребенку произведение “Дети капитана Гранта” Жюля Верна, оформленное в качестве комиксов. Он читал с упоением. Что касается писателей: думаю, в дальнейшем им придется полностью подстроится под читателя. Начинать книгу не так, как того хочешь ты, а так, как ее хочет видеть человек, открывший первую страницу”, - подвела итог Ксения Занина.","type":"paragraph"},{"html":"<i>Журналист: Валентина Поликарпова </i>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqydof00squktant8jyt1n"},{"mediaId":"cmrmqye9c00sruktappstnyls"},{"mediaId":"cmrmqyf0h00ssuktawauoove3"}]}]'::jsonb,'cmrmqycth00spukta45tbo337','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz8q000ekwtadrt5g1dn','cmrmpdrom0000sstarkqxwts4','2021-09-22T06:00:00.000Z'::timestamp,NULL,NULL,NULL,377,'/sobytija/iskusstvo/377-non-fikshn-bollitra-i-fjentezi-chto-predstavljaet-soboj-literatura-xxi-veka.html','2026-07-15T21:04:24.882Z'::timestamp,'2026-07-16T14:00:08.138Z'::timestamp,'''-2021'':338C ''-30'':1229C ''10'':244C ''2020'':337C ''21'':118C ''5'':248C ''50'':241C ''6'':1228C ''cmrmqydof00squktant8jyt1n'':1326C ''cmrmqye9c00sruktappstnyls'':1328C ''cmrmqyf0h00ssuktawauoove3'':1330C ''esqu'':47C ''galleri'':1324C ''paragraph'':62C,68C,154C,202C,315C,321C,375C,451C,457C,547C,642C,648C,700C,794C,838C,844C,917C,986C,992C,1080C,1182C,1208C,1316C,1322C ''xxi'':11A ''абсолютн'':1128C ''автор'':51C,159C,494C,636C,792C,927C ''адреналин'':831C ''аномальн'':162C ''аудиокниг'':1053C ''аудиоформат'':1147C ''аудитор'':287C,437C,935C ''бестселлер'':470C,637C ''бешен'':148C ''библиотечн'':873C ''бизнес'':349C,502C ''благодар'':619C ''боллитр'':4A,394C ''больш'':372C,704C,719C ''большинств'':112C,466C,651C ''бумажн'':443C,1037C ''быстр'':928C ''валентин'':1319C ''век'':12A,94C,119C,174C ''вер'':1032C ''верн'':1272C ''вернул'':888C ''верс'':1038C,1052C ''весел'':723C ''весьм'':767C ''веян'':97C ''взгляд'':972C ''взят'':1030C ''вид'':168C,518C ''виде'':1239C ''видет'':1306C ''виж'':1131C ''визуальн'':1219C ''включ'':782C ''внутрен'':490C ''возможн'':480C ''вокруг'':299C ''вопрос'':186C,1188C ''воспитан'':345C ''восприят