INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmquwmu00j3uktad7j77zd6','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Антонюк Диана: "Ты уже не ты, а иное создание"','Наш разговор с моделью из Хабаровска, Антонюк Дианой получился очень содержательным.','469-antonjuk-diana-ty-uzhe-ne-ty-a-inoe-sozdanie','[{"html":"Наш разговор с моделью из Хабаровска, Антонюк Дианой получился очень содержательным. Юная героиня рассказала нам о чувствах модели на подиуме и фотосъемке, в тот момент, когда на тебя направлены десятки фотовспышек: «ты уже не ты, а иное создание». Запомните эту фразу. Возможно, она станет крылатой. <br /><br />","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Диана, здравствуй. Как закончила школу? В какой класс перешла?","type":"paragraph"},{"html":"<strong>Диана:</strong> Здравствуйте. Школу закончила хорошо, на 4 и 5. Я перешла в 5 класс.<br /><br /><strong>Esque</strong><strong>:</strong> Есть любимые предметы в школе?<br /><strong>Диана:</strong> Да, я с удовольствием занимаюсь всеми предметами, но, к сожалению, пока какой-то конкретный предмет выделить не могу.<br /><br /><strong>Esque</strong><strong>:</strong> Чем занимаешься летом?<strong></strong>","type":"paragraph"},{"html":"<strong>Диана:</strong> Летом гуляю, отдыхаю, читаю книги, уделяю больше времени верховой езде, хожу на тренировки на танцы и, конечно же, участвую в фотопроектах нашего модельного агентства «LiLi Models».<br /><br /><strong>Esque</strong><strong>:</strong> Расскажи о моделинге. Как ты стала моделью?<br /><strong>Диана:</strong> Однажды меня мама привела в модельное агентство на пробный урок. Мне понравилась атмосфера, педагоги и я осталась и стала посещать занятия. Мне всегда все интересно, я с удовольствием участвую в конкурсах дефиле, принимаю участие в рекламных съемках и фотопроектах. Больше всего мне нравится процесс подготовки к съёмкам, когда подбирается образ, делаются макияж и прическа, а сам процесс фотосъемки прекрасен и удивителен. Перед камерой ты в образе, ты уже не ты, а иное создание. Фантастика. Другое дело показы. Я люблю показы. Дизайнер создаёт образ, а модель на подиуме рассказывает историю этого образа. Захватывающе и неповторимо.<br /><br /><strong>Esque</strong><strong>:</strong> С какими дизайнерами удалось поработать? Кто больше всего запомнился?<br /><strong>Диана:</strong> Мне удалось поработать с такими дизайнерами, как Юлия Лимонова (Иркутск), Дарья Полякова (Казань). Самая запоминающаяся работа была с дизайнером из Питера - Герой Скандалом. Этот дизайнер оправдывает своё имя, где он - там скандал.<br /><br /><strong>Esque</strong><strong>:</strong> На сколько я знаю, ты еще танцуешь в школе «Тодес». Как получается совмещать с модельной школой?<br /><strong>Диана:</strong> Пока удаётся все совмещать без проблем. <br /><br /><strong>Esque</strong><strong>:</strong> Как ты считаешь, какие важные качества необходимо развивать модели в твоем возрасте?<br /><strong>Диана:</strong> Самыми важными качествами в работе модели в любом возрасте считаю выдержку и терпение. И ещё в любом деле важна смекалка и креативность.<br /><br />","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Уже думала, кем хочешь стать?","type":"paragraph"},{"html":"<strong>Диана:</strong> Хочу свою жизнь связать с танцами и в будущем вижу себя хореографом.<br /><br /><strong>Esque</strong><strong>:</strong> Диана, дай пару напутственных слов начинающим моделям.<br /><strong>Диана:</strong> Терпение и труд все перетрут. Никогда не бросайте дело на полпути, добросовестно трудитесь и тогда добьётесь успеха.","type":"paragraph"},{"type":"image","mediaId":"cmrmquwlk00j2uktap83fny5g"}]'::jsonb,'cmrmquwbg00j1ukta376dcqk8','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-07-24T06:00:00.000Z'::timestamp,NULL,NULL,NULL,469,'/esquekids/moda-ek/469-antonjuk-diana-ty-uzhe-ne-ty-a-inoe-sozdanie.html','2026-07-15T21:01:41.046Z'::timestamp,'2026-07-16T13:59:00.742Z'::timestamp,'''4'':88C ''5'':90C,94C ''cmrmquwlk00j2uktap83fny5g'':418C ''esqu'':69C,96C,122C,156C,259C,302C,326C,365C,387C ''imag'':416C ''lili'':154C ''model'':155C ''paragraph'':67C,80C,127C,363C,372C,414C ''агентств'':153C,171C ''антонюк'':1A,16B,27C ''атмосфер'':177C ''броса'':403C ''будущ'':383C ''важн'':331C,341C,358C ''верхов'':138C ''виж'':384C ''возможн'':62C ''возраст'':338C,348C ''времен'':137C ''всем'':108C ''выдел'':119C ''выдержк'':350C ''гер'':291C ''героин'':33C ''гуля'':131C ''да'':389C ''дар'':280C ''дел'':240C,357C,404C ''дела'':215C ''десятк'':50C ''дефил'':196C ''диа'':2A,70C,82C,102C,129C,164C,269C,319C,339C,374C,388C,395C ''диан'':17B,28C ''дизайнер'':245C,262C,275C,288C,294C ''добросовестн'':407C ''добьет'':411C ''друг'':239C ''дума'':367C ''езд'':139C ''ещ'':354C ''жизн'':377C ''законч'':73C,85C ''занима'':107C,124C ''занят'':185C ''запомина'':284C ''запомн'':59C,268C ''захватывающ'':256C ''здравств'':71C,83C ''зна'':306C ''им'':297C ''ин'':8A,57C,236C ''интересн'':189C ''иркутск'':279C ''истор'':253C ''казан'':282C ''как'':261C,330C ''какой-т'':114C ''камер'':227C ''качеств'':332C,342C ''кем'':368C ''класс'':77C,95C ''книг'':134C ''конкретн'':117C ''конкурс'':195C ''креативн'':361C ''крылат'':65C ''лет'':125C,130C ''лимонов'':278C ''люб'':347C,356C ''любим'':98C ''любл'':243C ''макияж'':216C ''мам'':167C ''мог'':121C ''модел'':13B,24C,38C,163C,249C,335C,345C,394C ''моделинг'':159C ''модельн'':152C,170C,317C ''момент'':45C ''нам'':35C ''направл'':49C ''напутствен'':391C ''начина'':393C ''наш'':10B,21C,151C ''необходим'':333C ''неповторим'':258C ''нрав'':207C ''образ'':214C,230C,247C,255C ''однажд'':165C ''оправдыва'':295C ''оста'':181C ''отдыха'':132C ''очен'':19B,30C ''пар'':390C ''педагог'':178C ''перетрут'':400C ''перешл'':78C,92C ''питер'':290C ''подбира'':213C ''подготовк'':209C ''подиум'':40C,251C ''пок'':113C,320C ''показ'':241C,244C ''полпут'':406C ''получ'':18B,29C ''получа'':314C ''поляков'':281C ''понрав'':176C ''поработа'':264C,272C ''посеща'':184C ''предмет'':99C,109C,118C ''прекрас'':223C ''привел'':168C ''принима'':197C ''прическ'':218C ''пробл'':325C ''пробн'':173C ''процесс'':208C,221C ''работ'':285C,344C ''развива'':334C ''разговор'':11B,22C ''расскаж'':157C ''рассказа'':34C ''рассказыва'':252C ''рекламн'':200C ''сам'':283C,340C ''сво'':296C ''связа'':378C ''сканда'':301C ''скандал'':292C ''скольк'':304C ''слов'':392C ''смекалк'':359C ''совмеща'':315C,323C ''содержательн'':20B,31C ''сожален'':112C ''созда'':246C ''создан'':9A,58C,237C ''стал'':162C,183C ''станет'':64C ''стат'':370C ''счита'':329C,349C ''съемк'':201C,211C ''так'':274C ''танц'':144C,380C ''танцуеш'':309C ''тво'':337C ''терпен'':352C,396C ''тодес'':312C ''тренировк'':142C ''труд'':398C,408C ''уда'':263C,271C,321C ''уделя'':135C ''удивител'':225C ''удовольств'':106C,192C ''урок'':174C ''успех'':412C ''участ'':198C ''участв'':148C,193C ''фантастик'':238C ''фотовспышек'':51C ''фотопроект'':150C,203C ''фотосъемк'':42C,222C ''фраз'':61C ''хабаровск'':15B,26C ''хож'':140C ''хореограф'':386C ''хоч'':375C ''хочеш'':369C ''чита'':133C ''чувств'':37C ''школ'':74C,84C,101C,311C,318C ''юл'':277C ''юн'':32C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector"