INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrtnk0061ukta7tatpgy6','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Дарья Ходакова: "В любом деле важна насмотренность"','Мы воспринимаем жизнь, как нечто сложное, требующее ежедневных усилий, а иногда и страданий.','608-darja-hodakova-v-ljubom-dele-vazhna-nasmotrennost','[{"html":"Мы воспринимаем жизнь, как нечто сложное, требующее ежедневных усилий, а иногда и страданий. Ничто не дается","type":"paragraph"},{"html":"просто так или за счастье приходится дорого платить – такие установки нам упорно внушали с самого детства.","type":"paragraph"},{"html":"Дарья Ходакова – квантовый психолог. За ее плечами разработка Личной системы достижений целей. Она четко","type":"paragraph"},{"html":"уверена, наши мысли влияют на наши результаты, счастье и гармонию.","type":"paragraph"},{"html":"<b>Esque:</b> Дарья, здравствуйте. Расскажите немного о себе.","type":"paragraph"},{"html":"<b>Дарья:</b> Здравствуйте. Меня зовут<a href=\"https://dk-life.ru\" target=\"_blank\" rel=\"noopener noreferrer\"> Дарья Ходакова</a>.","type":"paragraph"},{"html":"У меня 2 проекта. Один связан с обувью и кожгалантерей, второй – с квантовой психологией.","type":"paragraph"},{"html":"Более 13 лет я проработала в сфере обуви и кожгалантереи, сейчас предоставляю стратегический консалтинг в этой области.","type":"paragraph"},{"html":"Более 5 лет я развивалась в сфере квантовой психологии, сейчас у меня разработан уникальный продукт «Личная система для","type":"paragraph"},{"html":"достижения целей» – это дорожная карта для решения любого запроса.","type":"paragraph"},{"html":"Также сейчас развиваю собственный бренд сумок на российских маркетплэйсах.","type":"paragraph"},{"html":"Говоря о личных достижениях, я 14 лет в спорте, дошла до мастера спорта России по спортивной аэробике, получила 42","type":"paragraph"},{"html":"золотых медали.","type":"paragraph"},{"html":"Мой авторский подход и в жизни и бизнесе – сочетание аналитики и квантовой психологии, где каждый вопрос можно","type":"paragraph"},{"html":"объяснить на основе законов физики и логики. Не зависимо от того, какой запрос решается – личный или бизнес.","type":"paragraph"},{"html":"Все мои проекты объединяет понятие «система».","type":"paragraph"},{"html":"Вне зависимости какой запрос я решаю – личный или бизнес – я вижу ситуацию сверху, автоматически трансформирую запрос","type":"paragraph"},{"html":"в систему, понимаю какие элементы работают некорректно и какой должен быть конечный результат, разрабатываю стратегию","type":"paragraph"},{"html":"решения вопроса.","type":"paragraph"},{"html":"Я улучшаю жизнь и бизнес людей за счет настройки эффективной системы их ресурсов и целей.","type":"paragraph"},{"html":"<b>Esque:</b> Как вам удается долгие годы одинаково успешно развиваться в 2 абсолютно не похожих друг на друга сферах?","type":"paragraph"},{"html":"<b>Дарья:</b> Для меня это сочетание двух сфер – аналитика и квантовая психология.","type":"paragraph"},{"html":"Развивая обувной бизнес, я была погружена в цифры и аналитику.","type":"paragraph"},{"html":"Любовь к цифрам – математике, физике, геометрии со мной с детства, я закончила физико-математический класс с золотой","type":"paragraph"},{"html":"медалью.","type":"paragraph"},{"html":"Мой жизненный путь – это пример того, как мой личный выбор интересующего меня предмета, цифр и аналитики, с детства","type":"paragraph"},{"html":"прошел через всю мою жизнь. Я ни разу не отступила от своего выбора, я изучала цифры, аналитику и занималась любимым","type":"paragraph"},{"html":"делом, постепенно превратившимся в дело моей жизни.","type":"paragraph"},{"html":"Психология вошла в мою жизнь тоже много лет назад.","type":"paragraph"},{"html":"С детства я ездила на спортивные соревнования, была капитаном команд и уже тогда брала на себя лидерские функции,","type":"paragraph"},{"html":"вдохновляла, мотивировала и заряжала свою команду на успех. И получала результат в виде наших побед. Уже тогда я поняла,","type":"paragraph"},{"html":"что мышление, настрой, мотивация играют большую роль в любом деле. Я придерживаюсь этого принципа до сих пор, и в","type":"paragraph"},{"html":"своей личной жизни и в бизнесе.","type":"paragraph"},{"html":"Дальше я точно так же работала с персоналом, я анализировала каждого сотрудника в отдельности и команду в целом,","type":"paragraph"},{"html":"советовала наиболее эффективные модели мышления и поведения, вдохновляла и мотивировала на результаты и достижения.","type":"paragraph"},{"html":"<b>Esque: </b>В чем основа личной системы для достижения результатов?","type":"paragraph"},{"html":"<b>Дарья:</b> В основе моей разработанной системы для достижения целей лежит системный подход.","type":"paragraph"},{"html":"Можно считать системой любой запрос из жизни или бизнеса. Любая система работает, корректно или некорректно. Как","type":"paragraph"},{"html":"понять, что система работает некорректно? Очень просто – она не достигает желаемого результата. В бизнесе – это","type":"paragraph"},{"html":"недополучение прибыли, в жизни – это недостижение личных целей.","type":"paragraph"},{"html":"Если система работает некорректно, то новых результатов не добиться. Именно поэтому необходимо работать с причиной, а не","type":"paragraph"},{"html":"со следствием. Алгоритмы работы с системой и в жизни, и в бизнесе идентичны.","type":"paragraph"},{"html":"Необходима оптимизация системы. С помощью диагностики оценить, какие элементы в системе работают неэффективно.","type":"paragraph"},{"html":"Понять, на какие элементы в первую очередь приложить усилия для корректировки, а какими заняться позже, какими","type":"paragraph"},{"html":"методами и инструментами работать с данной системой.","type":"paragraph"},{"html":"Наша психика – это тоже система. Она состоит из двух элементов – сознательное и бессознательное. И между этими","type":"paragraph"},{"html":"элементами есть связь.","type":"paragraph"},{"html":"Человек и его жизнь – это также система. Связь мышления человека и окружающего его внешнего мира можно также","type":"paragraph"},{"html":"рассматривать с точки зрения системного подхода.","type":"paragraph"},{"html":"Все, что нас окружает, можно рассматривать как совокупность систем, взаимодействующих друг с другом – образовательная","type":"paragraph"},{"html":"система, политическая система, система здравоохранения, экосистема, солнечная система, человек с его гормональной,","type":"paragraph"},{"html":"кровеносной системой и т. д.","type":"paragraph"},{"html":"Любая система состоит из элементов, которые выполняют определенные функции, и связей между ними. Это основные","type":"paragraph"},{"html":"компоненты, без которых не получится системы.","type":"paragraph"},{"html":"Мой системный подход в работе позволяет максимально естественно и комфортно для человека решить любой его запрос.","type":"paragraph"},{"html":"С каким бы запросом ко мне не пришел человек – я всегда сразу вижу корень проблемы, я считываю это на слух и визуально","type":"paragraph"},{"html":"по тому, как рассказывает и объясняет свой запрос сам человек. Это мой накопленный за 21 год опыт работы с аналитикой,","type":"paragraph"},{"html":"логикой и цифрами.","type":"paragraph"},{"html":"Я вижу ситуацию сверху, трансформирую запрос в систему, понимаю, какие элементы работают некорректно и какой должен","type":"paragraph"},{"html":"быть конечный результат, разрабатываю стратегию решения вопроса.","type":"paragraph"},{"html":"Мне важно, чтобы человек сам понял причину, мешающую ему решить его вопрос, чтобы решение запроса прошло комфортно","type":"paragraph"},{"html":"и естественно для самого человека. Именно поэтому я не сообщаю свое видение причины сразу «в лоб», я отхожу на три шага","type":"paragraph"},{"html":"вперед, и мы начинаем постепенно подходить к этой причине, к которой естественным путем выстраивается линия,","type":"paragraph"},{"html":"построенная на логике. К моменту, когда мы подходим к истинной причине, человеку легко ее понять, и он очень быстро","type":"paragraph"},{"html":"«проскакивает» эту проблему, начиная действовать по новому эффективному пути, решив свой запрос.","type":"paragraph"},{"html":"<b>Esque:</b> Все ваши созданные открытия в области психологии, это результат изучения окружающих людей или, в первую","type":"paragraph"},{"html":"очередь, ваш личный опыт?","type":"paragraph"},{"html":"<b>Дарья:</b> Это и изучение окружающих людей, и мой личный опыт. Все инструменты, которые я использую в работе, я прошла","type":"paragraph"},{"html":"сама. В моём авторском подходе каждая техника и практика испробована мной. Я знаю какие можно получить результаты.","type":"paragraph"},{"html":"Помимо этого, во время изучения теории и освоения практики, я наблюдала, как эти же техники и практики работают с","type":"paragraph"},{"html":"другими людьми, применяла их в своей работе. Я провела более 300 консультаций с разными людьми – мужчинами и","type":"paragraph"},{"html":"женщинами, разного уровня дохода и мышления. И я знаю, какие инструменты будут эффективны для любого запроса, с","type":"paragraph"},{"html":"которым мне предстоит работать.","type":"paragraph"},{"html":"Слушаю человека, строю гипотезы – почему он оказался в этой точке, так называемой точке А. То есть я занимаю позицию","type":"paragraph"},{"html":"наблюдателя и сразу вижу те элементы личной системы человека, которые работают неэффективно. А дальше – дело моей","type":"paragraph"},{"html":"техники и уровня мастерства.","type":"paragraph"},{"html":"Также я считаю, что в любом деле важна насмотренность. Поэтому я постоянно наблюдаю за людьми. Люди дают очень много","type":"paragraph"},{"html":"невербальных сигналов. На слух воспринимается только 20% информации, смысл слов, всё остальное наш мозг считывает по","type":"paragraph"},{"html":"физиогномике, темпу и тембру речи, по положению тела человека и т.д. И на базе полученной информации выстраивается","type":"paragraph"},{"html":"мнение о человеке. Я люблю это анализировать, потому что это помогает мне в работе быстро находить эффективные методы","type":"paragraph"},{"html":"решения запроса. Я могу между строк прочитать то, о чем умолчал человек или что хотел сказать на самом деле.","type":"paragraph"},{"html":"<b>Esque:</b> Дарья, что дает сочетание аналитики и квантовой психологии?","type":"paragraph"},{"html":"<b>Дарья:</b> За счет аналитики и квантовой психологии можно максимально эффективно настроить два самых ценных ресурса в","type":"paragraph"},{"html":"жизни – время и состояние.","type":"paragraph"},{"html":"Внедряя аналитику и логику, вы освобождаете время для себя. Вы можете оптимизировать и автоматизировать процессы в","type":"paragraph"},{"html":"жизни и бизнесе так, что будете получать эффективный результат за меньший промежуток времени, освобождая время для","type":"paragraph"},{"html":"нахождения с семьей, путешествий, открытия новых проектов и т. д.","type":"paragraph"},{"html":"Внедряя психологию, вы получаете дополнительное время на себя. Прорабатывая негативные установки, которые находятся в","type":"paragraph"},{"html":"нашем бессознательном в виде страхов и тревог, вы получаете здоровое психологическое состояние, в котором вы действуете","type":"paragraph"},{"html":"более эффективно и это занимает меньше времени, чем состояние тревоги и страха, которое всегда ворует наше время,","type":"paragraph"},{"html":"растягивая по времени достижение результата и препятствуя этому.","type":"paragraph"},{"html":"<b>Esque:</b> В Личной системе для достижения целей также задействовано сочетание аналитики и квантовой психологии?","type":"paragraph"},{"html":"В чем суть продукта?","type":"paragraph"},{"html":"<b>Дарья:</b> У каждого свои личные цели, своя жизнь, свои результаты и свое мышление.","type":"paragraph"},{"html":"Мы используем знания разных дисциплин и экспертный опыт людей для того, чтобы проработать свое мышление, стать более","type":"paragraph"},{"html":"эффективным, осознанным и счастливым. Мы развиваемся, идем вперед и достигаем своих целей.","type":"paragraph"},{"html":"Как бы мы не работали над собой, эффект и знания постепенно размываются, и мы можем периодически скатываться в своём","type":"paragraph"},{"html":"мышлении к исходным точкам, которые прорабатывали. Это вполне нормально, важно это осознавать и возвращаться к","type":"paragraph"},{"html":"эффективному типу мышления, потому что в основе достижения или не достижения целей всегда лежит наше мышление, у","type":"paragraph"},{"html":"кого-то получается результат, а кто-то до него не доходит.","type":"paragraph"},{"html":"Представьте, что у вас есть документ или свод правил, разработанный индивидуально для вас, в котором описано, как","type":"paragraph"},{"html":"достигать именно ваши цели с учетом вашего взгляда на жизнь, характера и отношения к результату.","type":"paragraph"},{"html":"Как было бы удобно в любой момент заглянуть в такой документ, если наметили себе новую цель, и следовать всем указаниям,","type":"paragraph"},{"html":"чтобы ее достичь.","type":"paragraph"},{"html":"Не важно какая у вас цель – из жизни или бизнеса, ее реализация всегда построена на определенном вашем алгоритме,","type":"paragraph"},{"html":"который помогает или мешает. Мы действуем, исходя из нашего мышления и наших установок.","type":"paragraph"},{"html":"Суть моего продукта Личная система по достижению целей – это разработка для человека его индивидуальной дорожной","type":"paragraph"},{"html":"карты для достижения целей, которой он может пользоваться в будущем самостоятельно для решения любого запроса.","type":"paragraph"},{"html":"Это 3-месячная программа. В течение 3 месяцев ведется работа по любому вашему запросу из жизни или бизнеса, который","type":"paragraph"},{"html":"рассматривается как система, где есть элементы, часть которых работают корректно и приводят к цели, часть – работают","type":"paragraph"},{"html":"некорректно и препятствуют достижению цели.","type":"paragraph"},{"html":"Согласно закону замещения – при изменении и улучшении одного элемента системы, меняется результат работы системы в","type":"paragraph"},{"html":"целом.","type":"paragraph"},{"html":"Поэтому главная задача – выявить некорректно работающие элементы и настроить их так, чтобы они стали приносить нужный","type":"paragraph"},{"html":"вам результат.","type":"paragraph"},{"html":"<b>Esque:</b> Кому подходит эта программа?","type":"paragraph"},{"html":"<b>Дарья:</b> Программа по разработке Личной системы для достижения целей подходит всем, кто хочет достигать результатов в","type":"paragraph"},{"html":"поставленных целях и проработать свое мышление – сделать его более эффективным.","type":"paragraph"},{"html":"<b><u><i>Программа вам подходит, если:</i></u></b>","type":"paragraph"},{"html":"<i>У вас есть цель, вы выполняете действия, но НЕТ РЕЗУЛЬТАТА</i>","type":"paragraph"},{"html":"<i>Почти всегда у нас взгляд на самого себя замылен и тяжело раскопать причины, почему не получается добиться </i>","type":"paragraph"},{"html":"<i>результата, находясь в «гуще событий».</i>","type":"paragraph"},{"html":"<i>У вас есть цель, но вы НЕ ЗНАЕТЕ С ЧЕГО НАЧАТЬ</i>","type":"paragraph"},{"html":"<i>Например, вы построили карьеру и хотите расти и развиваться дальше – начать петь, танцевать или обучать других. </i>","type":"paragraph"},{"html":"<i>Но всю жизнь вы учились чему-то одному и теперь не знаете, как приступить к новому делу. </i>","type":"paragraph"},{"html":"<i>У вас НЕТ ЦЕЛИ, и вы не понимаете, почему её нет</i>","type":"paragraph"},{"html":"<i>Кажется, как будто жизнь проходит мимо, и вы в ней не участвуете. Есть работа, семья, деньги, а счастья нет. Вы не </i>","type":"paragraph"},{"html":"<i>понимаете, что делать дальше, ваши прошлые достижения уже не мотивируют и не получается сформулировать новые </i>","type":"paragraph"},{"html":"<i>желания.</i>","type":"paragraph"},{"html":"<i>У вас есть успех в какой-то одной сфере, а в другой – никак НЕ МОЖЕТЕ СДЕЛАТЬ ПРОРЫВ</i>","type":"paragraph"},{"html":"<i>Например, у вас может быть успешные успешная карьера и доход, но никак не складываются отношения с </i>","type":"paragraph"},{"html":"<i>противоположным полом, нет семьи.</i>","type":"paragraph"},{"html":"<i>Вам НЕ ХВАТАЕТ ПОДДЕРЖКИ, «исповеди», доброго окружения</i>","type":"paragraph"},{"html":"<i>Вас тяготит одиночество или вы, несмотря на окружение, чувствуете себя одиноким и непонятым.</i>","type":"paragraph"},{"html":"<i>У вас НЕ ХВАТАЕТ ЭНЕРГИИ И ВРЕМЕНИ на то, чтобы начать заниматься тем, чем вы реально хотите заниматься</i>","type":"paragraph"},{"html":"<i>Вам всё время не хватает времени, вас отвлекают, вам сложно выставить приоритеты. Каждый ваш день как день </i>","type":"paragraph"},{"html":"<i>сурка или белки в колесе. Жизнь напоминает гонку.</i>","type":"paragraph"},{"html":"<i>Вы НЕ УПРАВЛЯЕТЕ СВОИМИ ЭМОЦИЯМИ, эмоции управляют вами</i><i></i>","type":"paragraph"},{"html":"<i>Вы не можете экологично прожить негативные эмоции, срываетесь на окружающих, вам трудно выражать свои </i>","type":"paragraph"},{"html":"<i>эмоции, вы часто их прячете. Вы постоянно пребываете в негативе. Часто плачете, вам кажется, что мир только и </i>","type":"paragraph"},{"html":"<i>делает, что строит вам козни и жизнь несправедлива.</i>","type":"paragraph"},{"html":"<i>Вы В СОСТОЯНИИ АПАТИИ И ВЫГОРАНИЯ, не знаете, как восполнить свой ресурс, как поддержать себя на пути к </i>","type":"paragraph"},{"html":"<i>целям</i>","type":"paragraph"},{"html":"<i>Часто такое бывает после принятия важных решений в жизни – переезд, окончание отношений, уход с работы, смена </i>","type":"paragraph"},{"html":"<i>работы, начало нового дела или работа на себя. Человек теряется, кажется, что ничего не получается, настроение </i>","type":"paragraph"},{"html":"<i>меняется от «я всё могу» до «я бездарность и на большее не способен».</i>","type":"paragraph"},{"html":"<i>Вы понимаете, что для выхода на новый уровень или достижения целей НУЖНО ИЗМЕНИТЬ МЫШЛЕНИЕ, но не </i>","type":"paragraph"},{"html":"<i>понимаете, как это сделать</i><i></i>","type":"paragraph"},{"html":"<i>Здесь вы осознанно подходите к цели, и вам нужен человек с опытом и знаниями в этой области, чтобы он вас </i>","type":"paragraph"},{"html":"<i>поддержал и скорректировали установки. Вы выбираете наставника, который подходит именно вам по духу и </i>","type":"paragraph"},{"html":"<i>ценностям.</i>","type":"paragraph"},{"html":"<b>Esque:</b> Если мы слышим слово «Достижение», то сразу же относим его к сфере бизнес-процессов. Успевать больше,","type":"paragraph"},{"html":"экологично экономя свои ресурсы. Но можно ли его адаптировать в вопросах личной жизни?","type":"paragraph"},{"html":"<b>Дарья:</b> Мне очень нравится цитата Генри Форда. Смысл её в том, что думаете ли вы, что вы добьетесь успеха, или вас","type":"paragraph"},{"html":"постигнет неудача – вы в любом случае правы. Логичный вывод – думать об успехе. Один из моих жизненных принципов –","type":"paragraph"},{"html":"всё возможно. На невозможное требуется чуть больше времени. Вот почему программа «Личная система» рассчитана на 3","type":"paragraph"},{"html":"месяца. Это минимальный срок, с точки зрения нейрофизиологии, который требуется на перестройку нейронных связей в","type":"paragraph"},{"html":"нашем мозге. То есть именно столько времени нужно, чтобы разрушить старые негативные установки о самом себе и начать","type":"paragraph"},{"html":"думать по-новому. Менять мышление. Новое мышление – новые действия – новые привычки – новый результат.","type":"paragraph"},{"html":"<b>Esque:</b> Дарья, что такое эмотология и к кому она применима?","type":"paragraph"},{"html":"<b>Дарья:</b> Эмотология – это управление эмоциями и развитие эмоционального интеллекта.","type":"paragraph"},{"html":"Я сертифицированный эмотолог. Я учу вас идентифицировать и экологично проживать свои эмоции.","type":"paragraph"},{"html":"Высвобождать психическую энергию, занятую «подавлением» негативных эмоций, «дружить» с негативными эмоциями. Ведь","type":"paragraph"},{"html":"они показывают нам, что мы где-то сбились с пути к цели и требуется корректировка курса. И чем дальше мы от цели, чем","type":"paragraph"},{"html":"ошибочнее наши действия, тем интенсивнее будут негативные эмоции. Взяв за базу какую-либо негативную эмоцию, мы","type":"paragraph"},{"html":"раскрутим целый клубок установок, которые мешают вам жить так, как хотите вы.","type":"paragraph"},{"html":"<b>Esque:</b> Мне бы хотелось в конце разговора затронуть тему развития обуви и кожгалантереи в России. Все больше мы","type":"paragraph"},{"html":"видим российских брендов сумок и обуви. В чем ваша задача, как эксперта, в этой области?","type":"paragraph"},{"html":"<b>Дарья:</b> Я предоставляю компаниям из сферы обуви и кожгалантереи стратегический консалтинг по разработке и реализации","type":"paragraph"},{"html":"эффективной системы закупок и продаж для максимальной прибыли и минимальных затрат.","type":"paragraph"},{"html":"За счет моего 13 летнего опыта в федеральной обувной компании, представленной в 80 городах России, у меня есть все знания","type":"paragraph"},{"html":"и практические кейсы для успешной оптимизации и автоматизации бизнеса с учетом трендов и прогнозов в сфере обуви,","type":"paragraph"},{"html":"сумок и кожгалантереи.","type":"paragraph"},{"html":"Во время консалтинга я работаю с комплексом: товарная матрица; товарный запас; ценовая политика; штат сотрудников;","type":"paragraph"},{"html":"работа торговых точек; бизнес-процессы для закупок и продаж, анализ, прогнозирование и отчетность.","type":"paragraph"},{"html":"В результате консалтинга компания получает план с конкретными шагами для увеличения КПД компании в целом –","type":"paragraph"},{"html":"максимальная прибыль при минимально затраченных усилиях. Максимальная эффективность работы коммерческого отдела,","type":"paragraph"},{"html":"где сотрудники по закупкам сосредоточены на ассортименте, сотрудники отдела продаж – на продажах. Остальные бизнес--","type":"paragraph"},{"html":"процессы настроены с помощью аналитики и отчетности, оптимизированы и автоматизированы.","type":"paragraph"},{"html":"<b>Esque:</b> Можно личный совет для наших читателей: как правильно расставлять приоритеты и управлять своим","type":"paragraph"},{"html":"временем?","type":"paragraph"},{"html":"<b>Дарья:</b> У меня разработана авторская методика тайм-менеджмента, составленная на базе личных знаний и опыта, обучений и","type":"paragraph"},{"html":"тренингов. Методика включает 5 шагов, внедрив которые вы станете более эффективным и сможете успевать больше.","type":"paragraph"},{"html":"Например, один из шагов – это правило переключения. Я им пользуюсь каждый день на протяжении последних пяти лет. Это","type":"paragraph"},{"html":"правило позволяет быть эффективнее, меньше уставать и успевать больше. Звучит, как магия, да? Но нет, ничего волшебного","type":"paragraph"},{"html":"тут нет. Это навык, который нарабатывается и со временем становится частью вашей жизни. Главное, как и в любом новом","type":"paragraph"},{"html":"деле, в начале соблюдать дисциплину, и вы скоро увидите результат.","type":"paragraph"},{"html":"На 3-месячной программе по разработке Личной системы для достижения целей мы разбираем с каждым клиентом","type":"paragraph"},{"html":"индивидуально технику тайм-менеджмента и внедряем ее в жизнь.","type":"paragraph"},{"html":"<b>Esque:</b> И пару напутственных слов!","type":"paragraph"},{"html":"<b>Дарья:</b> Никогда не поздно что-то поменять в своей жизни или начать заново. Ошибок не существует – всё есть опыт. Только","type":"paragraph"},{"html":"вы решаете, получилось у вас или нет. Работа над собой, изучение и понимание себя, раскрытие новых граней своей личности","type":"paragraph"},{"html":"– это бесконечный процесс. И чем больше у вас граней, тем ярче вы сияете!","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqrszv005zuktal9omyul1"},{"mediaId":"cmrmqrtjy0060ukta3oqqyg4t"}]}]'::jsonb,'cmrmqrsmg005yukta9s4sc7dy','cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2023-08-23T06:00:00.000Z'::timestamp,NULL,NULL,NULL,608,'/psihologija/intervju-2/608-darja-hodakova-v-ljubom-dele-vazhna-nasmotrennost.html','2026-07-15T20:59:17.216Z'::timestamp,'2026-07-16T13:57:14.524Z'::timestamp,'''13'':126C,2770C ''14'':195C ''2'':110C,336C ''20'':1268C ''21'':912C ''3'':1793C,1798C,2519C,3050C ''300'':1155C ''42'':208C ''5'':146C,2958C ''80'':2779C ''cmrmqrszv005zuktal9omyul1'':3153C ''cmrmqrtjy0060ukta3oqqyg4t'':3155C ''esqu'':89C,326C,577C,1055C,1345C,1501C,1887C,2423C,2579C,2696C,2913C,3081C ''galleri'':3151C ''paragraph'':38C,57C,74C,87C,97C,106C,123C,143C,164C,176C,188C,210C,215C,235C,255C,264C,283C,301C,306C,324C,345C,359C,372C,393C,397C,418C,441C,451C,463C,484C,506C,528C,537C,558C,575C,587C,602C,621C,639C,650C,670C,686C,702C,721C,731C,750C,756C,776C,785C,802C,817C,825C,843C,852C,871C,896C,919C,925C,944C,954C,974C,998C,1016C,1038C,1053C,1072C,1079C,1101C,1121C,1143C,1163C,1183C,1190C,1212C,1231C,1238C,1260C,1279C,1300C,1321C,1343C,1355C,1374C,1381C,1400C,1419C,1432C,1449C,1468C,1488C,1499C,1516C,1523C,1539C,1559C,1574C,1596C,1614C,1634C,1650C,1670C,1688C,1711C,1717C,1738C,1754C,1772C,1790C,1812C,1831C,1839C,1857C,1861C,1880C,1885C,1893C,1912C,1925C,1932C,1945C,1965C,1973C,1987C,2006C,2027C,2041C,2065C,2083C,2087C,2108C,2127C,2134C,2144C,2160C,2181C,2201C,2212C,2223C,2240C,2261C,2272C,2293C,2297C,2316C,2335C,2351C,2370C,2377C,2400C,2417C,2421C,2442C,2458C,2482C,2502C,2521C,2539C,2560C,2577C,2590C,2602C,2617C,2632C,2659C,2679C,2694C,2715C,2733C,2751C,2765C,2788C,2808C,2814C,2832C,2849C,2867C,2881C,2898C,2911C,2928C,2932C,2953C,2971C,2992C,3012C,3034C,3047C,3066C,3079C,3087C,3111C,3133C,3149C ''абсолютн'':337C ''автоматизац'':2797C ''автоматизирова'':1396C,2909C ''автоматическ'':279C ''авторск'':218C,