INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqein8002npota8aji5upk','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Мемуары Бритни Спирс выйдут в Росии','Узнайте о выходе мемуаров знаменитой певицы Бритни Спирс на российском рынке и погрузитесь в историю ее жизни и карьеры.','672-memuary-britni-spirs-vyjdut-v-rosii','[{"html":"Жизненный путь Бритни Спирс – это одна из самых показательных историй взлета и падения. 20 лет назад она была кумиром миллиардов девушек и мальчиков по всему миру. Ее песни можно было услышать везде: от российской местечковой дискотеки до Four Seasons в Нью-Йорке. Но как правило слишком ранняя слава дала о себе знать … Сейчас Бритни Спирс – это уже не та красотка с белоснежной улыбкой, а «отяжелевшая» от мрачной судьбы женщина с кучей психологических триггеров.","type":"paragraph"},{"html":"В октябре 2023 года на свет вышли мемуары Бритни Спирс, в которых певица рассказывает о тяжелом и болезненном детстве, сложных отношениях с мужчинами, послеродовой депрессии и психологических проблемах, из-за которых попала под опеку отца на 13 лет. Не забыла Спирс упомянуть и об аборте от Джастина Тимберлейка в 19 лет. Это признание наделало немало шума и певец даже собирался подавать в суд на женщину.","type":"paragraph"},{"html":"Теперь же автобиография Бритни появится в России. Издательство «Бомбора» сообщило, что достигло предварительных договоренностей с представителями певицы.","type":"paragraph"},{"html":"«Мы получили права на выпуск книги Бритни Спирс The Woman in Me (\"Женщина во мне\"), уже ставшей лучшей книгой года по версии Washington Post, Rolling Stone и других изданий», — <a href=\"https://vk.com/bomborabooks?w=wall-28648244_181551\" target=\"_blank\" rel=\"noopener noreferrer\">говорится</a> в заявлении «Бомборы» в соцсетях.","type":"paragraph"},{"html":"Предварительно уже этой осенью книга с переводом на русский появится на книжных полках.","type":"paragraph"},{"html":"Ранее в России проводились торги на право стать правообладателем русской версии автобиографии. Претендентами были группа «Альпина», «Бомбора» и АСТ. По данным собеседника, заключительная ставка «Бомборы» составила 91 500 долларов (примерно 8 млн рублей).","type":"paragraph"},{"html":"А хотите ли бы вы прочесть историю славы и краха Бритни Спирс?","type":"paragraph"}]'::jsonb,'cmrmqeim0002mpota65sqdja2','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-07-20T06:00:00.000Z'::timestamp,NULL,NULL,NULL,672,'/v-mire/672-memuary-britni-spirs-vyjdut-v-rosii.html','2026-07-15T20:48:56.420Z'::timestamp,'2026-07-16T13:56:34.537Z'::timestamp,'''13'':140C ''19'':153C ''20'':39C ''2023'':105C ''500'':273C ''8'':276C ''91'':272C ''four'':63C ''paragraph'':101C,170C,190C,228C,244C,280C,295C ''post'':215C ''roll'':216C ''season'':64C ''stone'':217C ''washington'':214C ''woman'':201C ''аборт'':148C ''автобиограф'':174C,257C ''альпин'':261C ''аст'':264C ''белоснежн'':88C ''болезнен'':120C ''бомбор'':180C,224C,262C,270C ''бритн'':2A,13B,28C,80C,111C,175C,198C,292C ''везд'':57C ''верс'':213C,256C ''взлет'':36C ''всем'':50C ''выйдут'':4A ''выпуск'':196C ''выход'':9B ''вышл'':109C ''говор'':221C ''год'':106C,211C ''групп'':260C ''дал'':75C ''дан'':266C ''девушек'':46C ''депресс'':127C ''детств'':121C ''джастин'':150C ''дискотек'':61C ''договорен'':185C ''доллар'':274C ''достигл'':183C ''друг'':219C ''женщин'':95C,168C,204C ''жизн'':23B ''жизнен'':26C ''заб'':143C ''заключительн'':268C ''заявлен'':223C ''знаменит'':11B ''знат'':78C ''из-з'':131C ''издан'':220C ''издательств'':179C ''истор'':21B,35C,288C ''йорк'':68C ''карьер'':25B ''книг'':197C,210C,234C ''книжн'':241C ''котор'':114C,134C ''красотк'':86C ''крах'':291C ''кумир'':44C ''куч'':97C ''лет'':40C,141C,154C ''лучш'':209C ''мальчик'':48C ''мемуар'':1A,10B,110C ''местечков'':60C '