INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqslg3008tukta5aoya10k','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Fashion bitva в Arbat hall: конкурсные показы, шоу программа, выставка художников и фотокарточки памяти','18 декабря в Arbat Hall на Новой Арбате пройдет финал 10 сезона конкурса дизайнеров Fashion bitva.Проект, зародившийся в 2016 году в Санкт-Петербурге, насчитывает порядка 60 показов за всю историю существования проекта, ','583-fashion-bitva-v-arbat-hall-konkursnye-pokazy-shou-programma-vystavka-hudozhnikov-i-fotokartochki-pamjati','[{"html":"18 декабря в Arbat Hall на Новой Арбате пройдет финал 10 сезона конкурса дизайнеров Fashion bitva.","type":"paragraph"},{"html":"Проект, зародившийся в 2016 году в Санкт-Петербурге, насчитывает порядка 60 показов за всю историю существования проекта, ежегодно проходящих в разных уголках мира. Каждый из них – это уникальная история.","type":"paragraph"},{"html":"В этом году финал Fashion bitva будет особенным. Нас ждут конкурсные показы дизайнеров, а также шоу выступления хедлайнеров проекта. Перед нами предстанут коллекции из Владивостока, Нижнего Новгорода, Санкт-Петербурга, Комсомольска-на-Амуре, Ростова-на-Дону, Сочи, Казани, Самары, Вологды, Красноярска, Иркутска, Тюмени, Смоленска и Москвы.","type":"paragraph"},{"html":"Второй год подряд конкурс развивает собственную выставку картин российских художников, рассказывающих и показывающих мир, который предстанет перед нами спустя 10 лет. Именно на эту тему, «Мода спустя 10 лет», второй год подряд мы предлагаем порассуждать и нашим участникам, ведь, начиная с 2020 года, мы как никогда обеспокоены будущим и что ждет нас впереди.","type":"paragraph"},{"html":"«Волнующие силуэты, яркие цвета и необычная стилизация коллекции словно отправляет нас в будущее, крича об изменчивости мира и новых порядках в нем» - так кратко комментирует посыл конкурсных коллекции организатор проекта, оставляя для гостей и неравнодушных место для полета фантазии.","type":"paragraph"},{"html":"Также в этом году впервые организаторами проекта будет представлена fashion-елка. «Праздничное дерево» расположится в месте фотозоны и проведет экскурс для гостей и участников по самым запоминающимся показам уходящего 2022 года! Каждый участник сможет найти себя и забрать себе в подарок фотокарточку памяти!","type":"paragraph"},{"html":"Ждем вас 18 декабря в в Arbat Hall! Dress code: Black Tie","type":"paragraph"},{"html":"Фуршет: 17:00","type":"paragraph"},{"html":"Купить билет: https://moscow.qtickets.events/50472-final-moskva-fashion-bitva-10<br />Аккредитация для СМИ и блогеров: alena@esque.su (ФИО, издание, ссылка на инстаграм, цель посещения, количество сопровождающих, контактный номер телефона)<br />Подать заявку модели: info@esque.su (город участия, фото, отделение: детское или взрослое, кратко о себе, рост и размерный ряд).","type":"paragraph"}]'::jsonb,'cmrmqsle8008suktagtqvjxm8','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2022-11-21T06:00:00.000Z'::timestamp,NULL,NULL,NULL,583,'/projects-esque/fashion-bitva/583-fashion-bitva-v-arbat-hall-konkursnye-pokazy-shou-programma-vystavka-hudozhnikov-i-fotokartochki-pamjati.html','2026-07-15T20:59:53.235Z'::timestamp,'2026-07-16T13:57:38.119Z'::timestamp,'''/50472-final-moskva-fashion-bitva-10'':322C ''00'':314C ''10'':25B,59C,171C,179C ''17'':313C ''18'':15B,49C,299C ''2016'':34B,71C ''2020'':193C ''2022'':280C ''60'':42B,79C ''alena@esque.su'':328C ''arbat'':4A,18B,52C,303C ''bitva'':2A,30B,64C,106C ''black'':307C ''code'':306C ''dress'':305C ''fashion'':1A,29B,63C,105C,260C ''fashion-елк'':259C ''hall'':5A,19B,53C,304C ''info@esque.su'':344C ''moscow.qtickets.events'':321C ''moscow.qtickets.events/50472-final-moskva-fashion-bitva-10'':320C ''paragraph'':66C,99C,150C,206C,248C,295C,