INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrq35005nuktay68n86we','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Рваный свитер - главный тренд сезона Осень-2023','Новый тренд осеннего сезона – рваный свитер!','614-rvanyj-sviter-glavnyj-trend-sezona-osen-2023','[{"html":"Новый тренд осеннего сезона – рваный свитер! Этот тренд приглянулся всем: от уличных хиппи до столичных модниц. Успех нового веяния прост. Поддерживать sustainable fashion не только модно, но и невероятно удобно. Состаренный деним, свободного кроя джинсы, тяжелые ботинки на подошве, не на каблуках, лоскутные сумки – кочевой «style» как нельзя, кстати подходит для жителей мегаполиса.","type":"paragraph"},{"html":"Оказаться в давке метро или спеша по Тверской в час пик будет гораздо комфортнее в свитере свободного кроя, чем в обтягивающем худи – не так ли! А если уж свитер можно дополнить чем-нибудь интересным родом из старины, то кто же будет против?","type":"paragraph"},{"html":"Смотрим нашу подборку!","type":"paragraph"},{"html":"Свитер Evgrafova, 9900 RUB","type":"paragraph"},{"html":"Свитер Eve&amp;Esther, 32500 RUB","type":"paragraph"},{"html":"Свитер Brusnika, 10900 RUB","type":"paragraph"},{"html":"Свитер 2Mood, 10980 RUB","type":"paragraph"},{"html":"Свитер Maneken, 13500 RUB","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqrop0005iuktacnslnkg5"},{"mediaId":"cmrmqrp0k005juktauomvwvyy"},{"mediaId":"cmrmqrpac005kukta7xz3oe93"},{"mediaId":"cmrmqrpjf005luktakjm3uv41"},{"mediaId":"cmrmqrq1e005muktaqop2hzhd"}]}]'::jsonb,'cmrmqroc2005huktaf0qqjus2','cmrm8ky9t0000kwta6h8ifq47','cmrm8kyf80001kwta3v4nh5f0','cmrmpdrom0000sstarkqxwts4','2023-09-06T06:00:00.000Z'::timestamp,NULL,NULL,NULL,614,'/trand/614-rvanyj-sviter-glavnyj-trend-sezona-osen-2023.html','2026-07-15T20:59:12.593Z'::