INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqu63f00fyuktaak7fpew3','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Эмма Уотсон официально объявлена лицом Prada Beauty','Prada Beauty, новое подразделение Prada, официально объявило, что лицом бренда станет актриса Эмма Уотсон.','503-jemma-uotson-oficialno-objavlena-licom-prada-beauty','[{"html":"<b>Prada Beauty, новое подразделение Prada, официально объявило, что лицом бренда станет актриса Эмма Уотсон. Кроме того, она будет режиссёром первого рекламного ролика Prada Beauty.</b>","type":"paragraph"},{"html":"Информация о том, что Эмма Уотсон будет работать c Prada Beauty появлялась и раньше. Теперь бренд сообщил об этом официально. В Instagram (принадлежит Meta Inc., которая в России объявлена экстремистской организацией и запрещена) Prada Beauty отмечает, что Эмма Уотсон – не только актриса, но и активистка, «воплощение современной женственности» и поэтому отражает ценности бренда.","type":"paragraph"},{"html":"22 августа выйдет первый рекламный ролик Prada Beauty. Режиссировать его также будет Эмма Уотсон. В качестве режиссёра она попробует себя впервые.","type":"paragraph"},{"html":"О создании бьюти-подразделения Prada стало известно 11 августа. Уже анонсировано, что в линейку войдёт новый парфюм Paradox. В СМИ предполагают, что основной продукцией Prada Beauty будет уходовая косметика.","type":"paragraph"},{"html":"Эмма Уотсон получила известность благодаря роли Гермионы во франшизе «Гарри Поттер». Также она снималась в таких фильмах, как «Красавица и Чудовище» и «Маленькие женщины». Восемь лет назад Эмма Уотсон стала послом доброй воли структуры ООН по вопросам гендерного равенства.","type":"paragraph"}]'::jsonb,'cmrmqu62200fxukta12r5owxn','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyxz0009kwtay5bvzu16','cmrmpdrom0000sstarkqxwts4','2022-08-19T06:00:00.000Z'::timestamp,NULL,NULL,NULL,503,'/beauty/news-3/503-jemma-uotson-oficialno-objavlena-licom-prada-beauty.html','2026-07-15T21:01:06.651Z'::timestamp,'2026-07-16T13:58:34.636Z'::timestamp,'''11'':137C ''22'':105C ''beauti'':7A,9B,23C,45C,59C,83C,112C,155C ''c'':57C ''inc'':73C ''instagram'':70C ''meta'':72C ''paradox'':147C ''paragraph'':47C,103C,127C,160C,202C ''prada'':6A,8B,12B,22C,26C,44C,58C,82C,111C,134C,154C ''август'':106C,138C ''активистк'':93C ''актрис'':19B,33C,90C ''анонсирова'':140C ''благодар'':166C ''бренд'':17B,31C,64C,101C ''бьют'':132C ''бьюти-подразделен'':131C ''войдет'':144C ''вол'':194C ''воплощен'':94C ''вопрос'':198C ''восем'':186C ''вперв'':125C ''выйдет'':107C ''гарр'':171C ''гендерн'':199C ''гермион'':168C ''добр'':193C ''женствен'':96C ''женщин'':185C ''запрещ'':81C ''известн'':136C,165C ''информац'':49C ''качеств'':120C ''косметик'':158C ''котор'':74C ''красавиц'':180C ''кром'':36C ''лет'':187C ''линейк'':143C ''лиц'':5A,16B,30C ''маленьк'':184C ''назад'':188C ''нов'':10B,24C,145C ''объяв'':14B,28C ''объявл'':4A,77C ''оон'':196C ''организац'':79C ''основн'':152C ''отмеча'':84C ''отража'':99C ''официальн'':3A,13B,27C,68C ''парфюм'':146C ''перв'':41C,108C ''подразделен'':11B,25C,133C ''получ'':164C ''попроб'':123C ''посл'':192C ''поттер'':172C ''поэт'':98C ''появля'':60C ''предполага'':150C ''принадлеж'':71C ''продукц'':153C ''работа'':56C ''равенств'':200C ''раньш'':62C ''режиссер'':40C,121C ''режиссирова'':113C ''рекламн'':42C,109C ''рол'':167C ''ролик'':43C,110C ''росс'':76C ''сми'':149C ''снима'':175C ''современ'':95C ''создан'':130C ''сообщ'':65C ''стал'':135C,191C ''станет'':18B,32C ''структур'':195C ''так'':177C ''такж'':115C,173C ''уотсон'':2A,21B,35C,54C,87C,118C,163C,190C ''уходов'':157C ''фильм'':178C ''франшиз'':170C ''ценност'':100C ''чудовищ'':182C ''экстремистск'':78C ''эмм'':1A,20B,34C,53C,86C,117C,162C,189C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXC