INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqyo8x00touktay516fswt','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'"Секс в большом городе" уже не тот','«Секс в большом городе» для многих модниц долгие десятилетия является нестареющим источником вдохновения.','368-seks-v-bolshom-gorode-uzhe-ne-tot','[{"html":"«Секс в большом городе» для многих модниц долгие десятилетия является нестареющим источником вдохновения. На этом фильме выросло не одно поколение, более того и наши дети будут его просматривать не раз. Режиссерам и сценаристам удалось создать фильм, который будет актуален во все времена, даже через сто лет.","type":"paragraph"},{"html":"Однако насколько правильным является решение снять продолжение фильма? Нет ли опасности, что продолжение с уже не молодыми актрисами потеряет интерес и к прошлому успеху комедии?","type":"paragraph"},{"html":"Седина, морщины не совсем ассоциируются с тематикой фильма, а особенно с его названием. Женщина бесспорно прекрасна в любом возрасте, но говорить о сексе 60-летней дамы – это ли нужно зрителю?","type":"paragraph"},{"html":"В социальных сетях мнения разделились. Как оказалось, не все зрители ждут продолжения как раз по этой причине.","type":"paragraph"},{"html":"@lilieva_14 Я их обожала, но нельзя до бесконечности снимать их, мы все к сожалению стареем, та история была актуальна именно тогда, когда они были 30-40 лет.","type":"paragraph"},{"html":"@kuznetsova_hairstyle Все же уже не те они … время берет свое … такое ощущения, что Синтия пришла к Саре в больницу навестить и они сидят там на кушетке! Да простят меня их поклонники.","type":"paragraph"},{"html":"@888di_na888 Может надо было раньше снимать, когда они были в форме? А теперь какой «секс в большом городе» с такими бабулями (мы все будем ими конечно же).","type":"paragraph"},{"html":"Как известно, 65-летняя актриса Ким Кэттролл, сыгравшая в комедии Саманту Джонс, отказалась от съемок. И даже внушительные гонорары не заставили ее передумать.","type":"paragraph"},{"html":"<i><u>Я не хочу портить созданный экранный образ — фанаты бы тоже этого не захотели»</u></i>, - своего мнения Ким не изменила с 2016 года.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqynsp00tmuktaykwkapu4"},{"mediaId":"cmrmqyo7j00tnuktaoq2dxrgc"}]}]'::jsonb,'cmrmqynkx00tlukta7qw6yx5k','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz6g000dkwtai45m48bj','cmrmpdrom0000sstarkqxwts4','2021-08-27T06:00:00.000Z'::timestamp,NULL,NULL,NULL,368,'/sobytija/kino/368-seks-v-bolshom-gorode-uzhe-ne-tot.html','2026-07-15T21:04:36.801Z'::timestamp,'2026-07-16T14:00:13.906Z'::timestamp,'''-40'':174C ''14'':149C ''2016'':290C ''30'':173C ''60'':118C ''65'':247C ''888di'':214C ''cmrmqynsp00tmuktaykwkapu4'':297C ''cmrmqyo7j00tnuktaoq2dxrgc'':299C ''galleri'':295C ''hairstyl'':180C ''kuznetsova'':179C ''lilieva'':148C ''na888'':215C ''paragraph'':65C,93C,126C,146C,177C,212C,243C,269C,293C ''актрис'':84C,249C ''актуал'':56C ''актуальн'':167C ''ассоциир'':99C ''бабул'':235C ''берет'':188C ''бесконечн'':156C ''бесспорн'':109C ''больниц'':198C ''больш'':3A,7B,20C,231C ''буд'':238C ''будут'':43C ''вдохновен'':17B,30C ''внушительн'':262C ''возраст'':113C ''врем'':59C,187C ''выросл'':34C ''говор'':115C ''год'':291C ''гонорар'':263C ''город'':4A,8B,21C,232C ''дам'':120C ''десятилет'':13B,26C ''дет'':42C ''джонс'':256C ''долг'':12B,25C ''ждут'':138C ''женщин'':108C ''застав'':265C ''захотел'':283C ''зрител'':124C,137C ''известн'':246C ''измен'':288C ''им'':239C ''имен'':168C ''интерес'':86C ''истор'':165C ''источник'':16B,29C ''ким'':250C,286C ''комед'':91C,254C ''котор'':54C ''кушетк'':205C ''кэттролл'':251C ''лет'':63C,175C ''летн'':119C,248C ''люб'':112C ''мнен'':131C,285C ''мног'':10B,23C ''модниц'':11B,24C ''молод'':83C ''морщин'':96C ''навест'':199C ''назван'':107C ''наско