INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmquxwu00j7ukta4rwkmqu5','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Полина Перцевая: "Думаю, моя одежда будет стильной, яркой и удобной"','Хабаровск не останется без модной индустрии.','468-polina-percevaja-dumaju-moja-odezhda-budet-stilnoj-jarkoj-i-udobnoj','[{"html":"<strong>Хабаровск не останется без модной индустрии. Подрастает целое поколение молодых дизайнеров, которые уже в своем весьма юном возрасте грезят о карьере дизайнера и даже знают, какими будут их будущие коллекции. Знакомьтесь! Полина Перцевая. Юная восьмилетняя модель уже готова покорять подиумы не только в качестве модели, но и дизайнера. </strong>","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Полина, здравствуй. Расскажи немного о себе.","type":"paragraph"},{"html":"<strong>Полина:</strong> Здравствуйте. Мне 8 лет. Я закончила первый класс, собираюсь во второй, мне очень нравится учиться, хоть иногда я немного устаю от уроков.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Как ты решила стать моделью?","type":"paragraph"},{"html":"<strong>Полина: </strong>С раннего детства мама очень много фотографировала меня и мне это нравилось, поэтому решили записаться на занятия по фотопозированию.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Ты занимаешься в модельном агентстве «Lili Models» в Хабаровске. Какие дисциплины вам преподают?","type":"paragraph"},{"html":"<strong>Полина: </strong>Очень много интересных занятий в нашем агентстве: дефиле, фотопозирование, этикет, развитие творческих способностей, фитнес, актёрское мастерство, стилистика и даже уроки по визажу.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Полина, каких показах ты уже успела принять участие?","type":"paragraph"},{"html":"<strong>Полина: </strong>Я три раза участвовала в конкурсном дефиле, получала призовые места, также принимала участие в рекламных показах от партнёров нашего агентства, а в марте 2022 г. побывала на Fashion bitva в г. Иркутске.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Я знаю, что помимо моделинга, ты любишь рисовать. Что обычно рисуешь?","type":"paragraph"},{"html":"<strong>Полина: </strong>Люблю рисовать животных, мультгероев и красивых принцесс в нарядных платьях.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Ты мечтаешь стать модельером, верно? Какой будет твоя одежда?","type":"paragraph"},{"html":"<strong>Полина: </strong>Я очень люблю наряжаться, придумывать сама себе образы и иногда практикую на своих куклах. Думаю, моя одежда будет стильной, яркой и удобной.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> А какой стиль в повседневной жизни ты выберешь для себя? Наверное, красивые платья?","type":"paragraph"},{"html":"<strong>Полина: </strong>Нет, скорее я выбрала бы стиль кэжуал. Я за комфорт, удобство и практичность.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Хороший выбор).","type":"paragraph"},{"html":"Полина, мне сказали, что ты хочешь побывать в Дисней Лэнде? Расскажи о своей мечте.","type":"paragraph"},{"html":"<strong>Полина: </strong>А какой ребёнок не мечтает побывать в мире Диснея. Я смотрела в интернете, это настоящий волшебный город с множеством аттракционов и знакомых персонажей из любимых мультфильмов.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Спасибо большое за интересное интервью. Пожелай что-нибудь хорошее нашим читателям.","type":"paragraph"},{"html":"<strong>Полина: </strong>Читателям я желаю, чтобы все мечты обязательно сбывались и каждый день был ярким и незабываемым.","type":"paragraph"},{"type":"image","mediaId":"cmrmquxs900j6ukta76l497xg"}]'::jsonb,'cmrmquxa800j5uktav5ayhna9','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-07-24T06:00:00.000Z'::timestamp,NULL,NULL,NULL,468,'/esquekids/moda-ek/468-polina-percevaja-dumaju-moja-odezhda-budet-stilnoj-jarkoj-i-udobnoj.html','2026-07-15T21:01:42.702Z'::timestamp,'2026-07-16T13:59:01.395Z'::timestamp,'''2022'':215C ''8'':81C ''bitva'':220C ''cmrmquxs900j6ukta76l497xg'':419C ''esqu'':68C,104C,136C,179C,227C,256C,295C,329C,382C ''fashion'':219C ''imag'':417C ''lili'':142C ''model'':143C ''paragraph'':66C,76C,102C,111C,134C,151C,177C,189C,225C,240C,254C,267C,293C,310C,327C,333C,350C,380C,396C,415C ''агентств'':141C,160C,211C ''актерск'':168C ''аттракцион'':372C ''больш'':384C ''будут'':43C ''будущ'':45C ''верн'':261C ''весьм'':32C ''визаж'':175C ''возраст'':34C ''волшебн'':368C ''восьмилетн'':51C ''втор'':89C ''выбереш'':303C ''выбор'':331C ''выбра'':316C ''г'':216C,222C ''город'':369C ''готов'':54C ''грез'':35C ''ден'':409C ''детств'':116C ''дефил'':161C,198C ''дизайнер'':27C,38C,64C ''дисн'':343C ''дисне'':361C ''дисциплин'':147C ''дума'':3A,284C ''жела'':401C ''животн'':245C ''жизн'':301C ''законч'':84C ''занима'':138C ''занят'':130C,157C ''записа'':128C ''здравств'':70C,79C ''зна'':229C ''знаком'':374C ''знакомьт'':47C ''знают'':41C ''индустр'':16B,22C ''интерв'':387C ''интересн'':156C,386C ''интернет'':365C ''иркутск'':223C ''кажд'':408C ''как'':42C,146C,181C ''карьер'':37C ''качеств'':60C ''класс'':86C ''коллекц'':46C ''комфорт'':322C ''конкурсн'':197C ''котор'':28C ''красив'':248C,307C ''кукл'':283C ''кэжуа'':319C ''лет'':82C ''лэнд'':344C ''люб'':234C ''любим'':377C ''любл'':243C,272C ''мам'':117C ''март'':214C ''мастерств'':169C ''мест'':201C ''мечт'':348C,404C ''мечта'':258C,357C ''мир'':360C ''множеств'':371C ''модел'':52C,61C,109C ''моделинг'':232C ''модельер'':260C ''модельн'':140C ''модн'':15B,21C ''молод'':26C ''мультгеро'':246C ''мультфильм'':378C ''наверн'':306C ''нарядн'':251C ''наряжа'':273C ''настоя'':367C ''наш'':159C,210C