INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqru3w0064uktarwm9si2c','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Я не могу найти свою любовь','Что такое любовь?','607-ja-ne-mogu-najti-svoju-ljubov','[{"html":"Что такое любовь? Как найти любовь? Как ее понять, а главное удержать?<br />Наш материал – это большое исследование, разговор по душам со специалистами из разных сфер психологии. Мы порассуждали на вечные темы: любовь и ненависть, брак и его место в современном обществе, одиночество среди толпы и сложность обретения счастья в личной жизни.<br />Невозможно однозначно сказать к каким выводам мы пришли, ведь каждый разговор – это отдельный мир, в котором все непросто, но совершенно точно мы поняли одно: «Любви быть и кто ищет, тот всегда найдет»!<br /><br /><u><b><i>Благодарим наших специалистов:</i></b></u><br /><i>Ирина Магарина – духовный психолог, мотивационный спикер @magarina_irina</i><br /><i>Лидия Гордеева – клинический психолог, коуч, гипнолог @lidiia.gordeeva</i><br /><i>Татьяна Крюкова – кармолог, таролог @metod_taro</i><br /><i>Марианна Садовникова – психолог, энергопрактик, кандидат наук @mariannasadovnikova</i><br /><i>Алена Миллер – психолог, гипнотерапевт, наставник @milleralena.ru</i><br /><i>Лариса Тернер – врач-психиатр, кинезиолог @psychokinesiolog</i><br /><i>Мария Балабова – астролог, гипнотерапевт @balabova_astrolog</i><br /><i>Юлия Герц – эксперт холистической регрессионной терапии, регрессолог @yuliyagerts1</i><br /><i>Ольга Якушкина – психолог, регрессолог, сексолог @ya_olga_psyhomag</i>","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/WzLScxEZkzI?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" title=\"Я не могу найти свою любовь\"></iframe>","type":"embed"}]'::jsonb,'cmrmqru2j0063ukta8h12f1dp','cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2023-08-23T06:00:00.000Z'::timestamp,NULL,NULL,NULL,607,'/psihologija/intervju-2/607-ja-ne-mogu-najti-svoju-ljubov.html','2026-07-15T20:59:17.805Z'::timestamp,'2026-07-16T13:57:15.687Z'::timestamp,'''astrolog'':142C ''balabova'':141C ''emb'':162C ''irina'':103C ''lidiia.gordeeva'':110C ''magarina'':102C ''mariannasadovnikova'':123C ''metod'':115C ''milleralena.ru'':129C ''olga'':157C ''paragraph'':160C ''psychokinesiolog'':136C ''psyhomag'':158C ''taro'':116C ''ya'':156C ''yuliyagerts1'':150C ''ал'':124C ''астролог'':139C ''балабов'':138C ''благодар'':93C ''больш'':25C ''брак'':44C ''вечн'':39C ''врач'':133C ''врач-психиатр'':132C ''вывод'':66C ''герц'':144C ''гипнолог'':109C ''гипнотерапевт'':127C,140C ''главн'':20C ''гордеев'':105C ''духовн'':98C ''душ'':29C ''жизн'':60C ''ирин'':96C ''исследован'':26C ''ищет'':89C ''кажд'':70C ''как'':65C ''кандидат'':121C ''кармолог'':113C ''кинезиолог'':135C ''клиническ'':106C ''котор'':76C ''коуч'':108C ''крюков'':112C ''ларис'':130C ''лид'':104C ''личн'':59C ''любв'':85C ''любов'':6A,9B,12C,15C,41C ''магарин'':97C ''мар'':137C ''мариан'':117C ''материа'':23C ''мест'':47C ''миллер'':125C ''мир'':74C ''мог'':3A ''мотивацион'':100C ''найдет'':92C ''найт'':4A,14C ''наставник'':128C ''наук'':122C ''наш'':22C,94C ''невозможн'':61C ''ненавист'':43C ''непрост'':78C ''обретен'':56C ''обществ'':50C ''одиночеств'':51C ''одн'':84C ''однозначн'':62C ''ольг'':151C ''отдельн'':73C ''поня'':18C,83C ''порассужда'':37C ''пришл'':68C ''психиатр'':134C ''психолог'':35C,99C,107C,119C,126C,153C ''разговор'':27C,71C ''разн'':33C ''регрессион'':147C ''регрессолог'':149C,154C ''садовников'':118C ''сексолог'':155C ''сказа'':63C ''сложност'':55C ''совершен'':80C ''современ'':49C ''специалист'':31C,95C ''спикер'':101C ''сред'':52C ''сфер'':34C ''счаст'':57C ''так'':8B,11C ''таролог'':114C ''татья'':111C ''тем'':40C ''терап'':148C ''тернер'':131C ''толп'':53C ''точн'':81C ''удержа'':21C ''холистическ'':146C ''эксперт'':145C ''энергопрактик'':120C ''эт'':24C,72C ''юл'':143C ''якушкин'':152C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqejkv002qpotage0xcr7i','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Бунтарский путь "зачарованной"','На этой неделе мир потерял талантливую актрису Шеннен Доэрти, известную по роли Прю Холливел в сериале Зачарованные.','671-vsemirnaja-izvestnost-i-mnogomillionnye-dolgi-buntarskij-put-zacharovannoj','[{"html":"На этой неделе мир узнал о смерти одной из «Зачарованных». 14 июля Шеннен Доэрти, сыгравшая Прю Холливел в знаменитом сериале, умерла от рака в 53 года. Ее жизненный путь был ярким и неоднозначным.","type":"paragraph"},{"html":"Актриса уже в 19 лет ощутила на себе всемирную известность. Помните очаровательную Бренду Уолш в сериале «Беверли-Хиллз 90210»? Это была первая серьезная роль Шеннен. Актриса быстро стала любимицей публики и разделила фанатов сериала на два лагеря: команду Келли и команду Бренды. Две героини боролись за сердце красавца Дилана (Люк Перри).","type":"paragraph"},{"html":"Несмотря на буйное поведение и сложности с законом, продюсер «Беверли-Хиллз» Аарон Спеллинг, дал актрисе второй шанс, а вместе с ним и главную роль в жизни Шеннен. В 1998 году с участием звезды на экраны вышел сериал о молоденьких ведьмах, сражавшихся с демонами и ищущих свою любовь. «Зачарованные» стал хитом, а героини кумирами многих молодых девушек по всему миру. Прю – так звали главную героиню, была старшей сестрой ведьм. Ее слушались, любили и уважали. Скромная Прю кардинально отличалась от настоящей натуры актрисы. В жизни Шеннен все также горел бунтарский дух и вскоре на площадке начались конфликты. Постоянные ссоры с Алисой Милано, вынудили создателей сериала выбирать и в 2001 году девушке пришлось покинуть «Зачарованных». Гибель главной героини стала одним из самых грустных эпизодов за всю историю шоу. На этом сериале закончилась и карьера актрисы в Голливуде.","type":"paragraph"},{"html":"К слову, вражда двух знаменитостей, продолжалась всю жизнь и лишь незадолго до смерти, в одном из подкастов о знаменитом шоу, Шеннен высоко оценила работу Алисы Милано в сериале.","type":"paragraph"},{"html":"\"Ни для кого не секрет, что у нас с Шеннен были сложные отношения, но в основе их лежал человек, которого я глубоко уважала и перед которым благоговела. Она была талантливой актрисой, любимой многими, и мир без нее стал меньше. Мои соболезнования всем, кто ее любил\" - высказалась и Милано, но уже после смерти Шеннен.","type":"paragraph"},{"text":"Сложный характер актрисы подвел ее и в личной жизни. 3 мужа и отсутствие детей.","type":"heading"},{"html":"С последним супругом, Шеннен официально развелась за день до смерти! Длившийся более года, судебный процесс, закончился 13 июля.","type":"paragraph"},{"html":"В дни кончины актрисы, все СМИ писали о желании Курта Исвариенко (мужа звезды), заполучить многомиллионное состояние женщины. Именно этим и объяснялся долгий бракоразводный процесс. Однако стало известно, что родственников ждет не только наследство актрисы, но и ее многомиллионные долги. Ипотека на 3 миллиона долларов, кредиты на 150 тысяч долларов и гонорары адвокатам на четверть миллиона долларов – мы явно подсчитали не все.","type":"paragraph"},{"html":"«Она проиграла битву с раком после многих лет борьбы с болезнью &lt;…&gt; Преданная дочь, сестра, тетя и подруга, она была окружена своими близкими» - так публицист Лесли Слоун подвердила кончину Шеннен Доэрти в интервью People.","type":"paragraph"},{"html":"Неуемная жажда познать мир, бунтарский дух и огромное сердце – несмотря на все перипетии жизни, именно этим Шеннен заполнится всем, кто любил ее творчество!","type":"paragraph"}]'::jsonb,'cmrmqejif002ppotaa63i1252','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-07-18T06:00:00.000Z'::timestamp,NULL,NULL,NULL,671,'/v-mire/671-vsemirnaja-izvestnost-i-mnogomillionnye-dolgi-buntarskij-put-zacharovannoj.html','2026-07-15T20:48:57.631Z'::timestamp,'2026-07-16T13:56:35.793Z'::timestamp,'''13'':370C ''14'':31C ''150'':421C ''19'':60C ''1998'':141C ''2001'':219C ''3'':346C,416C ''53'':45C ''90210'':76C ''head'':352C ''paragraph'':55C,110C,248C,279C,335C,373C,437C,473C,499C ''peopl'':471C ''аарон'':124C ''адвокат'':426C ''актрис'':10B,57C,83C,127C,193C,244C,311C,339C,378C,408C ''алис'':211C,274C ''беверл'':74C,122C ''беверли-хиллз'':73C,121C ''битв'':441C ''благоговел'':307C ''близк'':460C ''болезн'':449C ''борол'':102C ''борьб'':447C ''бракоразводн'':397C ''бренд'':69C,99C ''буйн'':114C ''бунтарск'':1A,200C,479C ''быстр'':84C ''ведьм'':152C,180C ''вмест'':131C ''вражд'':252C ''всем'':170C,322C,493C ''всемирн'':65C ''вскор'':203C ''втор'':128C ''выбира'':216C ''вынуд'':213C ''высказа'':326C ''высок'':271C ''вышел'':148C ''героин'':101C,164C,176C,227C ''гибел'':225C ''главн'':135C,175C,226C ''глубок'':302C ''год'':46C,142C,220C,366C ''голливуд'':246C ''гонорар'':425C ''горел'':199C ''грустн'':232C ''дал'':126C ''две'':100C ''двух'':253C ''девушек'':168C ''девушк'':221C ''демон'':155C ''ден'':361C ''дет'':350C ''дила'':106C ''дливш'':364C ''дни'':376C ''долг'':396C,413C ''доллар'':418C,423C,430C ''доч'':451C ''доэрт'':12B,34C,468C ''дух'':201C,480C ''жажд'':476C ''ждет'':404C ''желан'':383C ''женщин'':391C ''жизн'':138C,195C,257C,345C,488C ''жизнен'':48C ''закон'':119C ''законч'':241C,369C ''заполн'':492C ''заполуч'':388C ''зачарова'':3A,20B,30C,160C,224C ''звал'':174C ''звезд'':145C,387C ''знаменит'':39C,254C,268C ''известн'':13B,66C,401C ''имен'':392C,489C ''интерв'':470C ''ипотек'':414C ''исвариенк'':385C ''истор'':236C ''ищущ'':157C ''июл'':32C,371C ''кардинальн'':188C ''карьер'':243C ''келл'':96C ''ког'':283C ''команд'':95C,98C ''конфликт'':207C ''кончин'':377C,466C ''котор'':300C,306C ''красавц'':105C ''кредит'':419C ''кумир'':165C ''курт'':384C ''лагер'':94C ''лежа'':298C ''лесл'':463C ''лет'':61C,446C ''личн'':344C ''