анс'':129C ''шен'':11B,33C,82C,139C,196C,270C,290C,333C,357C,467C,491C ''шо'':237C,269C ''экра'':147C ''эпизод'':233C ''эт'':77C,393C,490C ''явн'':432C ''ярк'':51C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsro7009kukta5flld44s','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Ход Конем – объявлена эксклюзивная концепция нового сезона Fashion Bitva','Один из главных дизайнерских конкурсов страны ломает рамки и предлагает поиграть в моду, как в шахматы.','574-hod-konem-objavlena-jekskljuzivnaja-koncepcija-novogo-sezona-fashion-bitva','[{"html":"***","type":"paragraph"},{"html":"<i>Шаг. Еще шаг. Смело и от бедра.</i>","type":"paragraph"},{"html":"<i>Стук каблука. Стук сердца.</i>","type":"paragraph"},{"html":"<i>Так живет подиум. Так идет жизнь.</i>","type":"paragraph"},{"html":"***","type":"paragraph"},{"html":"<b><i>Один из главных дизайнерских конкурсов страны ломает рамки и предлагает поиграть в моду, как в шахматы. Классический подиум превращается в шахматную доску, а модели - в отражение духа времени. Такого еще не было!</i></b>","type":"paragraph"},{"html":"Принцип антагонизма в fashion-индустрии – одна из основных идей. Что мы можем сказать на языке моды? Добро и зло, лед и пламя, сила и слабость, черное и белое. Да все. Именно это и делают участники проекта Fashion Bitva – говорят с нами на языке моды.","type":"paragraph"},{"html":"Проект Fashion Bitva всегда отличался своим новаторским и современным подходом к реализации мероприятий. Не даром это один из крупнейших российских конкурсов индустрии моды, чья география и узнаваемость давно уже вышла за пределы страны. Вот уже 6 лет дизайнеры презентуют на нем свои лучшие коллекции, творческие подходы и инновационные наработки, соревнуясь за звание победителя сезона. А их, к слову, был уже десяток. Каждый новый сезон проект растет вместе со своими участниками. Теперь победа в нем – это не только про красивые платья. В расчет идет все: возраст, идея, экологичность, социальная ориентированность. А теперь еще и интеллект.","type":"paragraph"},{"html":"Дорогие гости и участники! Мы объявляем перенос запланированных в ноябре показов В Казани и Краснодаре на начало 2023 года. Мы ценим вашу любовь, время и усилия, поэтому всегда изыскиваем для вас лучшие условия: самые комфортные и престижные площадки, самых искусных фотографов и визажистов, самых непредвзятых судей и максимально благоприятное время для проведения нашего проекта. Мировые события и логика шепнули нам сделать этот ход – Ход конем. Увидимся с вами 25 и 26 февраля в Казани и 11-12 марта в Краснодаре.","type":"paragraph"},{"html":"Эти города предстанут перед нами в эксклюзивном формате. Мы готовы поразить гостей и участников эксклюзивным, совершенно новым для российского мира fashion форматом. Это будет не просто показ, а настоящий турнир красоты, интеллекта и новаторства в мире моды на подиуме в виде шахматной доски. Нет-нет, привычный подиум как символ моды никуда не девается. Просто его глянец на время уступит место черно-белой клетке, а зона выступления моделей превратится в настоящую шахматную доску. Ладья на F5.","type":"paragraph"},{"html":"У шахмат и моды общего гораздо больше, чем может показаться. И то, и другое – про качество, уровень, интеллект. Что такое победа в шахматах без стратегии? Не более чем везение. Случайность. Разовый момент. Для того, чтобы выигрывать раунд за раундам, нужна подготовка. И в шахматах. И в fashion-индустрии.","type":"paragraph"},{"html":"Мода – это отражение жизни. Если присмотреться, то можно разглядеть в ней отголоски всех важных процессов, происходящих в мире. И в ней, как в шахматах, есть свои черные и белые клетки. А еще, своя логика, стратегия и тактика. И там, и там золотое правило гласит: то, куда ты попадешь – зависит от тебя и от возможностей твоей фигуры. С каждым годом мы все больше убеждаемся: мода – это не только про ткани и софиты. За всей глянцевостью финального результата стоит колоссальный труд, изучение истории, анализ рынка, прогноз явлений на годы вперед. Это то, что остается за кадром. То, что определяет, кто будет пешкой, а кто – королевой. Но это то, о чем мы хотим заявить во всеуслышание!","type":"paragraph"},{"html":"Мы ждем вас на показах и рады презентовать вам концепцию нового сезона Fashion Bitva – Ход Конем. Это будет нечто! Главная идея: раскрыть философию внутреннего мира моды и глубину работы дизайнера. Продемонстрировать не только эстетический, но и интеллектуальный аспект индустрии.","type":"paragraph"},{"html":"Мы тут, чтобы творить. И мы будем делать это, несмотря на то, какая клетка сегодня под нашими ногами. Отсчет начался. Мы переходим в «выжидательный ход». Кому «шах», кому «мат», кому «пат» - покажет начало 2023 года.","type":"paragraph"}]'::jsonb,'cmrmqsrls009juktajlfyjept','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2022-10-12T06:00:00.000Z'::timestamp,NULL,NULL,NULL,574,'/projects-esque/fashion-bitva/574-hod-konem-objavlena-jekskljuzivnaja-koncepcija-novogo-sezona-fashion-bitva.html','2026-07-15T21:00:01.303Z'::timestamp,'2026-07-16T13:57:44.154Z'::timestamp,'''-12'':312C ''11'':311C ''2023'':253C,642C ''25'':304C ''26'':306C ''6'':174C ''bitva'':9A,129C,141C,580C ''f5'':395C ''fashion'':8A,95C,128C,140C,339C,446C,579C ''fashion-индустр'':94C,445C ''paragraph'':26C,36C,43C,52C,54C,89C,137C,234C,317C,397C,449C,565C,607C,645C ''анализ'':532C ''антагонизм'':92C ''аспект'':604C ''бедр'':34C ''бел'':119C,382C,479C ''благоприятн'':284C ''буд'':615C ''важн'':464C ''вам'':303C ''ваш'':257C ''везен'':427C ''вид'':359C ''визажист'':278C ''вмест'':205C ''внутрен'':590C ''возможн'':504C ''возраст'':223C ''вперед'':538C ''врем'':259C,285C,377C ''времен'':83C ''все'':523C ''всеуслышан'':563C ''выжидательн'':632C ''выигрыва'':434C ''выступлен'':386C ''вышл'':168C ''географ'':163C ''главн'':12B,58C,586C ''глас'':494C ''глубин'':594C ''глянец'':375C ''глянцев'':524C ''говор'':130C ''год'':254C,509C,537C,643C ''горазд'':404C ''город'':320C ''гост'':