INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrv8j006auktaxyssw5wc','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Анна Баева: "Мода в России есть и она живая"','Многие люди при слове дизайнер рисуют образ молодого юноши или девушки в мешковатой одежде с карандашом за ухом и ножницами в руках, без устали творящего очередной шедевр.','606-anna-baeva-moda-v-rossii-est-i-ona-zhivaja','[{"html":"<u>Многие люди при слове \"дизайнер\" рисуют образ молодого юноши или девушки в мешковатой одежде с карандашом за ухом и ножницами в руках, без устали творящего очередной шедевр. Он абсолютен свободен в своих мыслях и высказываниях, а главный наркотик для него - это мода!</u>","type":"paragraph"},{"html":"<u>В реальной же жизни проблем у российского дизайнера куда больше, чем муки творчества! Недостаточное финансирование и поддержка государства, не всегда качественный уровень образования, нехватка портных и швей!</u>","type":"paragraph"},{"html":"<u>Анна Баева - дизайнер, прошедший всю школу выживания в российской индустрии моды, а наше интервью - это небольшое учебное пособие для начинающиего дизайнера. Совершенно открыто, бех фальши, обнажая все реальные проблемы, с которыми столкнешься ТЫ, когда скажешь \"Я - ДИЗАЙНЕР\". </u>","type":"paragraph"},{"html":"<strong>Esque: Анна, здравствуйте. Расскажите, как вы стали дизайнером. </strong>","type":"paragraph"},{"html":"Анна: Свой путь дизайнера я начала в старших классах школы. Я хотела быть заметной и яркой - лихие 90-е, конечно, отличались пестротой продаваемой одежды - НО качество было не всегда способствующим покупке. Да, и часто/много покупать не было возможности, и я стала шить сама для себя! Придумывала модели, перекраивала мамины платья и была счастлива! Я была и творцом и исполнителем.","type":"paragraph"},{"html":"После окончания школы - у меня уже не было вопросов - куда идти учиться! Я выбрала Институт легкой промышленности, факультет технологии. Как и многие студенты - в разных специальностях и вузах - на старших курсах, я начала шить изделия на заказ. Рисовала эскизы, обсуждала их с клиентами и отшивала готовое изделие. Я думала, что создавать уникальный образ для клиента - это просто часть работы портного.","type":"paragraph"},{"html":"Закончив институт, мы с подругой решили открыть свадебный салон, где продавали наши авторские образы. Стартовый капитал нашего юного бизнеса был минимальный. Но у нас было четкое понимание технологии пошива, тканей и фурнитуры! Мы использовали в своим работах и портерные ткани! Вы думаете это было плохо? Нет! Как технолог могу вам сказать, изделие может быть оригинальным и презентабельным! Мы нашли компромисс и наше уникальное качество/цена. Свадебные образы отличались оригинальным фасоном, декором и весьма приятными ценами. Наши платья успешно продавались и к нам шел поток невест!","type":"paragraph"},{"html":"Более 10 лет я занималась свадебными и вечерними нарядами. Мои клиентки - выходили замуж и приходили с запросами на повседневную одежду. Бэкграунд из вечерних нарядов вы точно заметите во всех изделиях, которые я творю. Это может быть просто отделка подкада офисного пиджака кружевом шантильи! Но это и делает даже строгий офисный наряд женственным.","type":"paragraph"},{"html":"Когда я стал дизайнером? Я жила своим творчеством и делала, что мне нравится! В 2018 году в летнем лагере для дизайнеров, я сказала себе, что я не просто «шью на заказ», Я - дизайнер! А дальше - больше: я создала свою первую коллекцию «Восхождение Венеры» , с которой объехала уже много недель мод .","type":"paragraph"},{"html":"Вот так и получилось! Я Анна Баева – дизайнер, который пришел к своей мечте и самой любимой профессии сквозь долгие года творчества и мук.","type":"paragraph"},{"html":"<strong>Esque: Что для вас мода? Как, на ваш взгляд, она развивается в России?</strong>","type":"paragraph"},{"html":"Анна: Мода достаточно емкое и разностороннее понятие. Мода от Анны Баевой - это внутренняя красота каждой женщины, которую я извлекаю на свет и показываю в той одежде, которую будет носить женщина.","type":"paragraph"},{"html":"Это срез психологии человека, цвета, фактуры ткани - искусство найти эти смыслы и сигналы для каждого образа в одежде. Здесь же и мое внимание к функциональности и современности изделия - одежда не должна быть просто модной, ее нужно еще носить с комфортом и удовольствием! И не важно, создаешь ли ты изделия для дефиле на подиуме или же одежду для обыденной жизни.","type":"paragraph"},{"html":"Мода в России существует. Уже обращает на себя внимание! Рада сейчас видеть, как она развивается не только в Москве и Санкт-Петербурге. Модные дизайнеры покидают свой узкий замкнутый круг и становятся доступными для среднего класса. Их успешно преследуют молодые агрессивные свежие Дизайнеры. Выстраивается конкуренция - это хорошо! Значит, мода в России есть и она живая!","type":"paragraph"},{"html":"<strong>Esque: Но несмотря на обилие молодых и креативных дизайнеров, нас по-прежнему не воспринимают за границей. Почему?</strong>","type":"paragraph"},{"html":"Анна: Давайте подумаем - в какой момент Модный Дом расширяет свою экспансию за границу? Когда он увеличивает рынок продаж? Когда он уже освоил рынок внутри и его единственная точка роста - расширение региона его присутствия. Я считаю - что молодые новые дизайнеры - сейчас активно заполняют и делят рынок внутри страны. Зачем агрессивно вкладывать деньги (и приковать ими) и идти в перегретую нишу западного рынка - когда здесь в РФ еще есть \"место и возможность\" для роста?","type":"paragraph"},{"html":"Мало кто имеет избыточный стартовый капитал для сразу выхода на двух рынках. Опять же, давайте не забывать, что мы живем в условиях рыночной, юнит-экономики. Продавать здесь, работать с аудиторией, которую ты понимаешь и знаешь экономически безопаснее выгоднее нежели идти за Границу.","type":"paragraph"},{"html":"<strong>Esque: Какие основные ошибки совершают начинающие дизайнеры?</strong>","type":"paragraph"},{"html":"Анна: Начинающим дизайнерам не хватает хватки и базовых знаний маркетинга и экономики. Нет понимания, что мода - это не просто «я придумал, создал и это должны ценить». Всегда нужно понимать: для кого ты творишь, нужно знать свою ЦА. Молодым дизайнерам иногда кажется, что умение рисовать эскизы - это уже успех. Причем успех финансовый! <br /> Но нет, нужно помнить про то, что мы, дизайнеры, творим для людей. Любой модный дом - это еще и бизнес. А основная задача бизнеса - приносить прибыль и зарабатывать деньги.","type":"paragraph"},{"html":"<strong>Esque: Можете назвать нескольких дизайнеров, за творчеством которых наблюдаете? </strong>","type":"paragraph"},{"html":"Анна: Ivolga by Ольга Малюга, бренд 12 stories – отслеживаю развитие их бизнеса регулярно!","type":"paragraph"},{"html":"<strong>Esque: Анна, дизайнеру необходимо получать профильное образование или же достаточно таланта и желания?</strong>","type":"paragraph"},{"html":"Анна: Давайте подумаем с точки зрения философии. Есть базис и есть надстройка. Базовое образование всегда облегчает путь, делает вас увереннее и увеличивает кругозор и также учить учиться и систематизировать информацию. Далее я отмечу - работоспособность! И третий кит любого профессионала - талант, желание, насмотренность и личная энергия и оптимизм!<br />Добавлю еще раз - сейчас нужно не только сшить коллекцию или изделие - НО и найти под него заинтересованную аудиторию. Бренд и Модный дом, у которого никто не будет покупать одежду обречен на провал. <br />Имея насмотренность и умея раскладывать придуманное изделие на части (технологически, по материалам, эстетически), рождение шедевра становится проще!","type":"paragraph"},{"html":"Также важно умение чувствовать. Чувствовать ткани, чувствовать изделие на себе, чувствовать стиль. Считаю, что дизайнер - это путь, и идти по нему стоит всегда, всегда учиться чему-то новому, всегда быть в потоке (как внешнем, так и внутреннем).","type":"paragraph"},{"html":"<strong>Esque: Расскажите о вашем бренде. Что лежит в основе ДНК?</strong>","type":"paragraph"},{"html":"Анна: <strong>ДНК</strong> <strong>бренда</strong> — <strong>это</strong> совокупность особенностей <strong>бренда</strong>, в том числе внутренних и внешних отличительных параметров, которые определяют уникальность всего предприятия. Полноценная система <strong>этих</strong> характеристик формирует <strong>бренд</strong> как самостоятельную личность и позволяет создать максимально результативную стратегию позиционирования на рынке.","type":"paragraph"},{"html":"Основа моего Бренда «Anna Baeva» - как и следует из названия - я Анна Баева.","type":"paragraph"},{"html":"Перечислю тезисно:","type":"paragraph"},{"html":"<strong>1. Красота - функциональность.</strong> Не шью просто красивые изделия - я шью изделия, которые можно носить - причем носить их комфортно!","type":"paragraph"},{"html":"<strong>2. Красота - даже изнутри</strong>. Высокие стандарты обработки - не только снаружи изделия - но и в самых потайных местах. Все должно быть прекрасно - я же ставлю свои Имя на все изделия - и он не может соседствовать с неаккуратными швами или дешевой подкладкой.<br /><strong>3. Красота и индивидуальность.</strong> Не навязываю клиентам модные образы и ткани. Все просто в рамках личности моего клиента. <br />4. <strong>Красота - даже в офисном стиле</strong>. Офисный стиль может быть сексапильным, и деловым и удобным. <br />5. <strong>Красота и разумное потребление,</strong> создаю капсульный гардероб. Сейчас красота экологична. Начиная работать с клиентом, сразу думаю, как он может вписать свое новое платье в имеющийся гардероб.<br /><strong>6. Красота - в комбинации</strong>. Сила и слабость. Жесткость и мягкость. Использую все приемы, создавая образы в своей одежде.","type":"paragraph"},{"html":"<strong>Esque: Спасибо. Пусть это будет небольшим учебным материалом для начинающих дизайнеров!</strong>","type":"paragraph"},{"html":"<strong>Вы не так давно переехали в Санкт-Петербург из маленького сибирского городка. Как жизнь в северной столице отразилась на вашем творчестве?</strong>","type":"paragraph"},{"html":"Анна: Давайте просмотрим мой путь. Я родилась и выросла в Новосибирске, третьем городе в России. В какой-то момент мне стало тесно в нем, стало мало драйва. Новосибирск не мешал мне творить, но хотелось большего, более мистического и вдохновляющего. И я была готова сделать шаг... но шаг это растянулся на несколько лет. Сейчас есть небольшое сожаление, что я не сделала этого сразу. Но что есть - то есть, переехав в Санкт-Петербург, я как будто расправила крылья и вдохнула полной грудью. Мое творчество и концепция моего Бренда не изменились - свободнее и активнее стала я сама. Могу сказать - здесь, в большом городе, меня еще больше понимают и ценят. Теперь я точно знаю , что я в нужном месте.","type":"paragraph"},{"html":"<strong>Esque: Назовите 5 основных проблем легкой промышленности в России. С какими столкнулись вы?</strong>","type":"paragraph"},{"html":"Анна: Интересный вопрос, по сути к портному и модному Дизайнеру. Сложно оценить макро экономику и проблемы больших предприятия в РФ. Давайте я попробую, воспользуюсь своим вторым образование по направлению Продажи и маркетинг.","type":"paragraph"},{"html":"Я выделю основную проблему мелкого и среднего бизнеса - это недостаток рабочих кадров. Найти хорошего специалиста очень сложно. В России выпускается все больше дизайнеров и стилистов, а вот кто эту одежду будет создавать руками? Важно взращивать кадры и уже сейчас это делать, иначе совсем скоро нам просто нечего будет носить кроме вещей, созданных в Китае или Киргизии.","type":"paragraph"},{"html":"Планирую возобновить работу своей школы шитья - оцифровать все уроки и готовить высококвалифицированных портных и мастеров индивидуального пошива.","type":"paragraph"},{"html":"<strong>Esq