INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqufkc00h4uktap4pmef6q','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Dior вновь будет сотрудничать с Джонни Деппом','Джонни Депп снимется в рекламе бренда Dior и вновь станет лицом парфюма Sauvage, по информации издания TMZ.','491-dior-vnov-budet-sotrudnichat-s-dzhonni-deppom','[{"html":"<b>Джонни Депп снимется в рекламе бренда Dior и вновь станет лицом парфюма Sauvage, по информации издания TMZ. Рекламный контракт станет первым для Джонни Деппа после судебных разбирательств с бывшей супругой Эмбер Хёрд.</b>","type":"paragraph"},{"html":"Источники TMZ сообщают, что рекламная фотосессия Джонни Деппа для Dior уже проведена. Фотографом стал Грег Уильямс. Рекламный контракт бренда с актёром будет действовать несколько лет.","type":"paragraph"},{"html":"Ранее Грег Уильямс и руководство Dior пришли на парижский рок-концерт Джонни Деппа и гитариста Джеффа Бека, чтобы поддержать актёра и снять рекламу. Dior уже опубликовал эти фотографии в Instagram (принадлежит Meta Inc., которая в России объявлена экстремистской организацией и запрещена).","type":"paragraph"},{"html":"Dior последовательно поддерживал Джонни Деппа, несмотря на обвинения в домашнем насилии, которые были предъявлены актёру его бывшей супругой Эмбер Хёрд. Бренд не расторгал предыдущего контракта с актёром и теперь снова его продлил. Dior работает с Джонни Деппом семь лет.","type":"paragraph"},{"html":"В начале лета бывшая супруга актёра Эмбер Хёрд была признана американским судом виновной в клевете. Чтобы возместить ущерб, она обязана выплатить Джонни Деппу $15 млн. В 2018 году в колонке для Washington Post Эмбер Хёрд обвинила Джонни Деппа в домашнем насилии, при этом ни разу не назвав его имя. После этого актёр лишился всех крупных ролей.","type":"paragraph"}]'::jsonb,'cmrmqufia00h3ukta2qw2ev5r','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyxz0009kwtay5bvzu16','cmrmpdrom0000sstarkqxwts4','2022-08-10T06:00:00.000Z'::timestamp,NULL,NULL,NULL,491,'/beauty/news-3/491-dior-vnov-budet-sotrudnichat-s-dzhonni-deppom.html','2026-07-15T21:01:18.924Z'::timestamp,'2026-07-16T13:58:45.773Z'::timestamp,'''15'':198C ''2018'':201C ''dior'':1A,14B,31C,69C,93C,112C,133C,165C ''inc'':121C ''instagram'':118C ''meta'':120C ''paragraph'':58C,86C,131C,173C,232C ''post'':207C ''sauvag'':20B,37C ''tmz'':24B,41C,61C ''washington'':206C ''актер'':80C,108C,147C,159C,180C,226C ''американск'':185C ''бек'':105C ''бренд'':13B,30C,78C,153C ''бывш'':53C,149C,178C ''виновн'':187C ''внов'':2A,16B,33C ''возмест'':191C ''выплат'':195C ''гитарист'':103C ''год'':202C ''грег'':74C,89C ''действова'':82C ''депп'':7A,9B,26C,48C,67C,101C,137C,169C,197C,212C ''джефф'':104C ''джон'':6A,8B,25C,47C,66C,100C,136C,168C,196C,211C ''домашн'':142C,214C ''запрещ'':129C ''издан'':23B,40C ''им'':223C ''информац'':22B,39C ''источник'':60C ''клевет'':189C ''колонк'':204C ''контракт'':43C,77C,157C ''концерт'':99C ''котор'':122C,144C ''крупн'':229C ''лет'':84C,171C,177C ''лиц'':18B,35C ''лиш'':227C ''млн'':199C ''назва'':221C ''насил'':143C,215C ''начал'':176C ''нескольк'':83C ''несмотр'':138C ''обвин'':210C ''обвинен'':140C ''объявл'':125C ''обяза'':194C ''опубликова'':114C ''организац'':127C ''парижск'':96C ''парфюм'':19B,36C ''перв'':45C ''поддержа'':107C ''поддержива'':135C ''последовательн'':134C ''предъявл'':146C ''предыдущ'':156C ''призна'':184C ''принадлеж'':119C ''пришл'':94C ''провед'':71C ''продл'':164C ''работа'':166C ''раз'':219C ''разбирательств'':51C ''ран'':88C ''расторга'':155C ''реклам'':12B,29C,111C ''рекламн'':42C,64C,76C ''рок'':98C ''рок-концерт'':97C ''рол'':230C ''росс'':124C ''руководств'':92C ''сем'':170C ''снимет'':10B,27C ''снов'':162C ''снят'':110C ''сообща'':62C ''сотруднича'':4A ''стал'':73C ''станет'':17B,34C,44C ''суд'':186C ''судебн'':50C ''супруг'':54C,150C,179C ''уильямс'':75C,90C ''ущерб'':192C ''фотограф'':72C,116C ''фотосесс'':65C ''херд'':56C,152C,182C,209C ''экстремистск'':126C ''эмбер'':55C,151C,181C,208C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqza8p00vpukta95ujmwlv','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Чикатило. 2021','В марте этого года состоялась премьера сериала Сарика Андреасяна про самого известного советского убийцу - Андрея Чикатило.','345-chikatilo-2021','[{"html":"В марте этого года состоялась премьера сериала Сарика Андреасяна про самого известного советского убийцу - Андрея Чикатило. События сериала происходят в Ростовской области, где то и дело находят изуродованные детские трупы. На помощь в местной полиции прибывает группа сыщиков из столицы. Кесаев - один из самых суровых следователей и психологически подкованный криминалист Кесаев понимаю, что все те подозреваемые, которые признались в убийствах, их не совершали. Тем временам количество убитых детей непрестанно растет. <br /><br />","type":"paragraph"},{"html":"<i>“Наша команда работала над проектом со всей ответственностью к материалу и с желанием показать уникальную историю становления и поимки жестокого убийцы, а точнее как именно это стало возможным”, - рассказывает Сарик Андреасян.</i>","type":"paragraph"},{"html":"<br />Главный состав “Чикатило” удивил всех зрителей. Особенно, когда в главной роли - самого Чикатило - они увидели Дмитрия Нагиева. <br /><br /><br /> <br />","type":"paragraph"},{"html":"<i>“У меня были сомнения, так как играть таких мерзких персонажей мне еще не доводилось. Чикатило - откровенная мразь. Я с удовольствием играю положительных героев, отрицательных героев или слабых людей, но я не умею и и не хочу играть мерзких, мерзких на уровне физиологии. Как это ни парадоксально, именно это и помогло мне понять глубину мерзости этого персонажа, именно физиологические вещи, которые я придумывал. На съемках этого сериала мне было страшно и отвратительно”, - признался Нагиев. </i>","type":"paragraph"},{"html":"<br />Автор сценария Алексей Гравицкий рассказал, что во время написания сценария они не держали в голове конкретного актёра, чтобы не подстраивать образ под него. Тем не менее, Нагиев сделал, все, как надо.<br /><br />","type":"paragraph"},{"html":"<i>«Дмитрий добавил к образу своих красок. Но самое главное — он создал образ, не вызывающий симпатии. Чикатило в кадре неприятен, ему не хочется сопереживать. Это было заложено в сценарии, и Дмитрий блестяще это считал и воплотил. На мой взгляд, в создании образа Чикатило это самое важное», — отмечает Гравицкий.</i>","type":"paragraph"},{"html":"<br />В сериале также приняли участие Юлия Проскурякова, Константин Лавроненко, Виктория Богатырева, Николай Козак и другие.<br /><br /><br /> Сериал перенял образы и стилистику у иностранных коллег, так резко смонтированные вступительные титры точно напомнят “Американскую историю ужасов”, залитые кровью кукурузные поля - точно момент экранизации Стивена Кинга и еще ни одно такое совпадение на протяжении всего сериала. Но, посмотреть стоит, однозначно.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqz9vn00vnuktageel4tig"},{"mediaId":"cmrmqza4b00voukta9i60mp8w"}]}]'::jsonb,'cmrmqz8il00vmukta0u0bwgv3','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz6g000dkwtai45m48bj','cmrmpdrom0000sstarkqxwts4','2021-05-10T06:00:00.000Z'::timestamp,NULL,NULL,NULL,345,'/sobytija/kino/345-chikatilo-2021.html','2026-07-15T21:05:05.305Z'::timestamp,'2026-07-16T14:00:40.047Z'::timestamp,'''2021'':2A ''cmrmqz9vn00vnuktageel4tig'':367C ''cmrmqza4b00voukta9i60mp8w'':369C ''galleri'':365C ''paragraph'':90C,124C,144C,220C,254C,304C,363C ''автор'':222C ''актер'':238C ''алекс'':224C ''американск'':336C ''андре'':17B,33C ''андреася'':11B,27C,122C ''блестящ'':286C ''богатырев'':316C ''важн'':300C ''вещ'':204C ''взгляд'':293C ''виктор'':315C ''возможн'':119C ''воплот'':290C ''врем'':229C ''времен'':83C ''все'':98C ''вступительн'':332C ''вызыва'':269C ''гер