INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqv06m00jhuktackouamwn','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'София Филиппова: "Кто знает, может в будущем я стану знаменитым дизайнером"','В 6 лет София Филиппова из города Хабаровск заняла 1 место по рисованию по Хабаровскому краю.','465-sofija-filippova-kto-znaet-mozhet-v-buduschem-ja-stanu-znamenitym-dizajnerom','[{"html":"<u><strong>В 6 лет София Филиппова из города Хабаровск заняла 1 место по рисованию по Хабаровскому краю. Сейчас она также много рисует, но несмотря на основное хобби, в жизни юной красавицы появилось еще одно увлечение - мода! За ее плечами подиумы Санкт-Петербурга, Сочи, Иркутска, Хабаровска и Москвы. Кто знает, возможно, в будущем София попробует себя по ту сторону закулисья и станет дизайнером. </strong></u>","type":"paragraph"},{"html":"<strong>Esque</strong>: София, здравствуй. В какой класс ты пойдешь этой осенью? Нравится в школе?","type":"paragraph"},{"html":"<strong>София:</strong> Здравствуйте! Я пойду в 4 класс. Да в школу я люблю ходить. У меня очень дружный класс.","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>:</strong> Есть любимые предметы в школе?","type":"paragraph"},{"html":"<strong>София:</strong> Да, мне очень нравится русский язык и литература.","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>:</strong> Ты также посещаешь школу изобразительных искусств. Что тебе нравится рисовать больше всего: пейзажи, людей, животных или, может быть предметы?","type":"paragraph"},{"html":"<strong>София:</strong> Я начала рисовать в 3 года. В 6 лет заняла 1 место на конкурсе рисунков по Хабаровскому краю. В последнее время больше рисую людей и животных.","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>: </strong>Совсем недавно ты стала заниматься моделингом и уже решила, что с ним свяжешь свою будущую профессию. Может, ещё подумаешь?","type":"paragraph"},{"html":"<strong>София:</strong> Точно ещё не решила, но мне безумно нравится. Когда я выхожу на подиум, во мне столько эмоций, которые переполняют меня. А какие классные фото, у меня уже даже есть свое портфолио. Здорово, правда?","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>: </strong>Конечно, это здорово. А какую модельную школу ты посещаешь?","type":"paragraph"},{"html":"<strong>София:</strong> Я занимаюсь в самом лучшем модельном агентстве @lili_models_khv. Если честно, я никогда об этом не думала и пошла на пробное занятие, чтобы поддержать подругу. И решила, что сама хочу и буду заниматься.","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>: </strong>Какая дисциплина из учебной программы тебе нравится больше всего?","type":"paragraph"},{"html":"<strong>София:</strong>Хореография и визаж.","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>: </strong>Уже успела посетить показы в качестве модели?","type":"paragraph"},{"html":"<strong>София:</strong> О, да! Я была в Санкт-Петербурге, Иркутске, Сочи. Каждая поездка - это удивительное приключение.","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>: </strong>Каких дизайнеров для себя отметила?","type":"paragraph"},{"html":"<strong>София:</strong> Если смотреть с точки зрения креативности, то это, несомненно, Гера Скандал! Но его одежда не предназначена для повседневной носки. В Иркутске на показе я демонстрировала одежду Ольги Чи и скажу Вам, что была в восторге от того как можно сочетать в образе: стиль, яркость и комфортность одновременно. При этом надевать одежду в обычной жизни и быть в центре внимания.","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>: </strong>Не пробовала нарисовать наряды, в которых выступала на показе?","type":"paragraph"},{"html":"<strong>София: </strong>Нет, не пробовала. Но это отличная идея! Кто знает, может в будущем я стану знаменитым дизайнером.","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>: </strong>Давай пофантазируем. Представь, что тебе нужно нарисовать показ мод. В каких цветах была бы твоя картина?","type":"paragraph"},{"html":"<strong>София:</strong> Вы знаете, наверное, это будет зависеть от времени года. Но вообще я люблю яркие цвета.","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>: </strong>София, пару пожеланий напоследок для наших читателей.","type":"paragraph"},{"html":"<strong>София:</strong>Я хочу пожелать всем, чтобы каждый день начинался с улыбки. Ведь это важно, когда ты улыбаешься, мир улыбается тебе в ответ!","type":"paragraph"},{"type":"image","mediaId":"cmrmqv05l00jguktan35ri95n"}]'::jsonb,'cmrmquzzm00jfuktac9g9eidk','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-07-21T06:00:00.000Z'::timestamp,NULL,NULL,NULL,465,'/esquekids/moda-ek/465-sofija-filippova-kto-znaet-mozhet-v-buduschem-ja-stanu-znamenitym-dizajnerom.html','2026-07-15T21:01:45.646Z'::timestamp,'2026-07-16T13:59:04.110Z'::timestamp,'''1'':21B,37C,185C ''3'':179C ''4'':114C ''6'':13B,29C,182C ''cmrmqv05l00jguktan35ri95n'':547C ''esqu'':93C,130C,151C,204C,264C,315C,335C,365C,437C,470C,509C ''imag'':545C ''khv'':287C ''lili'':285C ''model'':286C ''paragraph'':91C,107C,128C,137C,149C,172C,202C,225C,262C,275C,313C,326C,333C,344C,363C,372C,435C,448C,468C,488C,507C,518C,543C ''агентств'':284C ''безумн'':234C ''буд'':310C ''будущ'':7A,79C,219C,462C ''важн'':533C ''визаж'':331C ''вниман'':433C ''возможн'':77C ''вообщ'':501C ''восторг'':409C ''врем'':195C ''времен'':498C ''всем'':524C ''выступа'':444C ''выхож'':238C ''гер'':384C ''год'':180C,499C ''город'':18B,34C ''дава'':471C ''демонстрирова'':399C ''ден'':527C ''дизайнер'':11A,89C,367C,466C ''дисциплин'':317C ''дружн'':125C ''дума'':295C ''ещ'':222C,229C ''животн'':166C,200C ''жизн'':55C,428C ''зависет'':496C ''закулис'':86C ''з