INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrvsp006duktav08vgwey','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Идеальный шторм','Наша серия интервью: «Идеальный шторм» - попытка разобраться с нашими стрессами и тревогами вместе со специалистами из различных сфер психологии: гипнотерапии, регрессологии, тетахилинга, кинезиологии и emdr-терапии.','605-idealnyj-shtorm','[{"html":"Мы живем в крайне непростое время и каждый день сталкиваемся с тревогами и страхами! У каждого из нас они свои. Кто-то боится остаться без средств к существованию, кто-то боится потерять близких людей, есть те, кто боятся ядерной войны и ежедневно тонут в ленте новостей, жадно поглощая каждый интернет-ресурс в надежде найти успокоение.","type":"paragraph"},{"html":"Когда мы готовили этот материал, то на повестке дня не стоял готовящийся бунт. Сегодня нам всем страшно проснуться в другой России!","type":"paragraph"},{"html":"Но … всегда есть помощь! И мы можем и должны за ней обращаться. Для кого-то будет достаточно близкого человека рядом, а кому-то не обойтись без помощи специалистов. Ради себя, своих близких и счастливого будущего, которое мы обязательно построим вместе.","type":"paragraph"},{"html":"Наша серия интервью: «Идеальный шторм» - попытка разобраться с нашими стрессами и тревогами вместе со специалистами из различных сфер психологии: гипнотерапии, регрессологии, тетахилинга, кинезиологии и emdr-терапии. У каждой из наших героинь своя интересная история жизни и свой путь к профессии. У каждой свой взгляд на этот мир и на то, как стать счастливой! Мы очень надеемся, что с помощью этого материала, вам станет немного легче и вы найдете ответы на свои вопросы!","type":"paragraph"},{"html":"Благодарим за интервью наших героинь:","type":"paragraph"},{"html":"Юлия Готовская – энерготерапевт, кинезиолог <br />Анастасия Смородинская – клинический психолог, астролог, член СОТА и ЕАТА в модальности ТА<br />Оксана Минькова – психолог, гипнотеравт","type":"paragraph"},{"html":"Екатерина Мухина – практик тетахилинг <br />Алена Багинова – регрессолог <br />Катерина Соломкина – психолог, регрессолог, мастер духовных практик <br />Людмила Сенник – Еmdr терапевт, член ассоциации Emdr РФ","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/xe0bRt4RzOs?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" title=\"Идеальный шторм\"></iframe>","type":"embed"}]'::jsonb,'cmrmqrvp7006cuktaygr0grzt','cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2023-06-24T06:00:00.000Z'::timestamp,NULL,NULL,NULL,605,'/psihologija/intervju-2/605-idealnyj-shtorm.html','2026-07-15T20:59:19.993Z'::timestamp,'2026-07-16T13:57:18.394Z'::timestamp,'''emb'':292C ''emdr'':28B,185C,287C ''emdr-терап'':27B,184C ''paragraph'':89C,113C,158C,234C,242C,265C,290C ''ал'':271C ''анастас'':248C ''ассоциац'':286C ''астролог'':252C ''багинов'':272C ''благодар'':236C ''близк'':64C,133C,148C ''бо'':53C,62C,69C ''будущ'':151C ''бунт'':103C ''взгляд'':204C ''вмест'':15B,156C,172C ''войн'':71C ''вопрос'':232C ''врем'':35C ''всем'':106C ''героин'':191C,240C ''гипнотеравт'':263C ''гипнотерап'':22B,179C ''готов'':93C ''готовск'':245C ''готовя'':102C ''ден'':38C ''дня'':99C ''должн'':123C ''достаточн'':132C ''духовн'':279C ''еmdr'':283C ''еат'':256C ''ежедневн'':73C ''екатерин'':267C ''жадн'':78C ''жив'':31C ''жизн'':195C ''идеальн'':1A,6B,163C ''интерв'':5B,162C,238C ''интересн'':193C ''интернет'':82C ''интернет-ресурс'':81C ''истор'':194C ''кажд'':37C,45C,80C,188C,202C ''катерин'':274C ''кинезиолог'':25B,182C,247C ''клиническ'':250C ''ког'':129C ''кого-т'':128C ''ком'':138C ''кому-т'':137C ''котор'':152C '