INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqel32002ypota1aw7dcro','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Дональд Трамп - главная сакральная жертва Америки','13 июля в США в Батлере в штате Пенсильвания во время предвыборного митинга было совершено покушение на Дональда Трампа.','668-donald-tramp-glavnaja-sakralnaja-zhertva-ameriki','[{"html":"13 июля в США в Батлере в штате Пенсильвания во время предвыборного митинга было совершено покушение на Дональда Трампа. Экс-президента спасло чудо, в нужный момент он повернул голову.","type":"paragraph"},{"html":"<br />Всего было произведено 9 выстрелов, один из присутствующих убит, двое получили тяжелые ранения. Трамп ранен в ухо. <br />ФБР установило личность стрелявшего. Им оказался 20-летний местный житель Томас Мэтьтю Крукс. Мотивы нападения остались неизвестными. Однако большая часть общественности обвинила Байдена в произошедшем и требует выдвинуть президенту обвинение за подстрекательство.","type":"paragraph"},{"html":"Сам же президент сразу после нападения связался с Дональдом Трампом и дал своей комментарии: \"Я рад слышать, что он в безопасности и чувствует себя хорошо. Я молюсь за него и его семью, а также за всех, кто был на митинге, поскольку мы ждем дальнейшей информации. Мы с Джилл благодарны Секретной службе за то, что она доставила его в безопасное место. В Америке нет места такому насилию. Мы должны объединиться как одна нация, чтобы осудить это\".","type":"paragraph"},{"html":"<br />Не остался в стороне и еще один экс-президент США Барак Обама: <i>\"В нашей демократии нет абсолютно никакого места насилию по политическим мотивам. Хотя мы пока точно не знаем, что произошло, мы все должны чувствовать облегчение в связи с тем, что бывший президент Трамп не пострадал серьезно, и воспользоваться этим моментом, чтобы заново подтвердить свою приверженность цивилизованности и уважению в нашей политике\".</i>","type":"paragraph"},{"html":"<br />В России на ситуацию в США отреагировали молниеносно. Дмитрий Песков выразил свое мнение о причастности администрации Америки к покушению на главного конкурента Байдена в предвыборной гонке.","type":"paragraph"},{"html":"<br />Пока секретная служба, обеспечивающая безопасность первых лиц США, получает выговоры, маркетинговый отдел справился на отлично: в продажу уже поступили футболки с фото Трампа с окровавленным ухом и лозунгами. Стоит отметить, что шансы на победу у экс-президента резко выросли.","type":"paragraph"},{"type":"image","mediaId":"cmrmqel1r002xpotaivlozew7"}]'::jsonb,'cmrmqekp9002wpota9o0vs2ds','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-07-14T06:00:00.000Z'::timestamp,NULL,NULL,NULL,668,'/v-mire/668-donald-tramp-glavnaja-sakralnaja-zhertva-ameriki.html','2026-07-15T20:48:59.582Z'::timestamp,'2026-07-16T13:56:38.800Z'::timestamp,'''13'':7B,26C ''20'':82C ''9'':62C ''cmrmqel1r002xpotaivlozew7'':329C ''imag'':327C ''paragraph'':57C,109C,187C,253C,282C,325C ''абсолютн'':206C ''администрац'':270C ''америк'':6A,172C,271C ''байд'':98C,277C ''барак'':200C ''батлер'':12B,31C ''безопасн'':131C,169C,288C ''благодарн'':159C ''больш'':94C ''бывш'':231C ''воспользова'':238C ''врем'':17B,36C ''выговор'':293C ''выдвинут'':103C ''выраз'':265C ''выросл'':323C ''выстрел'':63C ''главн'':3A,275C ''голов'':55C ''гонк'':280C ''дал'':122C ''дальн'':154C ''дво'':68C ''демократ'':204C ''джилл'':158C ''дмитр'':263C ''должн'':178C,223C ''дональд'':1A,24B,43C,119C ''достав'':166C ''ждем'':153C ''жертв'':5A ''жител'':85C ''занов'':242C ''зна'':218C ''информац'':155C ''июл'':8B,27C ''комментар'':124C ''конкурент'':276C ''крукс'':88C ''летн'':83C ''лиц'':290C ''личност'':78C ''лозунг'':311C ''маркетингов'':294C ''мест'':170C,174C,208C ''местн'':84C ''митинг'':19B,38C,150C ''мнен'':267C ''мол'':137C ''молниеносн'':