INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqvzp400n0uktaex20w4h2','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Fashion bitva в Иркутске стала обсуждением женской энергии и культуры','26 марта в Иркутске на арт-заводе Доренберг состоялся региональный этап 10 сезона международного проекта Fashion bitva.','423-fashion-bitva-v-irkutske-stala-obsuzhdeniem-zhenskoj-jenergii-i-kultury','[{"html":"27 марта в Иркутске на арт-заводе Доренберг состоялся региональный этап 10 сезона международного проекта Fashion bitva. Уже третий год региональным организатором в Иркутске проекта «Fashion bitva» является модельное агентство «Proobraz» во главе с Юлианой Брандер. В этом году в мероприятии произошли кардинальные изменения, которые, несомненно, скажутся на развитии моды в регионе.","type":"paragraph"},{"html":"Свои коллекции представили дизайнеры из Иркутска, Улан-Удэ и Владивостока. В дополнении к иркутским моделям по подиуму прошлись модели из Хабаровска и Красноярска.","type":"paragraph"},{"html":"Иркутский дизайнер Анна Мандро в своей конкурсной коллекции «Natural beauty» продемонстрировала сопричастность женщины к природе, к ее спокойным натуральным цветам, фактурам и формам. Дизайнер хотела подчеркнуть самобытную красоту женщины, природную архитектуру ее тела, легкость и изящность. Задачей же дизайнера Люси Шалобод в своей коллекции «Руки» было отражение человеческих эмоции. По словам участницы, ее коллекция о людях и настоящих эмоциях, о человеческой доброте и отзывчивости.","type":"paragraph"},{"html":"Детский дизайнер Марина Матыцына вдохновилась рисунками-валентинками своих детей, ведь наше будущее за нашими детьми. Коллекция состояла из платьев радужных цветов, дополненных воланами, рюшами и пышными юбками, как у принцесс. На вопрос, почему в коллекции были только платья, дизайнер ответил просто: «Женщина олицетворяет любовь, мир, спокойствие, счастье, а наши девочки – будущие женщины».","type":"paragraph"},{"html":"Коллекция детских платьев была и у Марии Прокопьевой. Она также рассказывает нам о женской силе и неповторимой энергии.","type":"paragraph"},{"html":"Победитель в номинации «Детская мода», бренд из Улан-Удэ «Teddy kids», представил гостям необычную коллекцию школьной формы для современных подростков. В ней сочетаются свобода, уверенность и стиль.","type":"paragraph"},{"html":"Teddy Kids","type":"paragraph"},{"html":"Всеобщий восторг вызвал гость города – дизайнер Наталья Лопаткина из Владивостока. Каждое изделие в коллекции было изготовлено вручную в единственном экземпляре из природных материалов: 100% овечьей шерсти, шелка, льна, хлопка, конопли и крапивы.","type":"paragraph"},{"html":"Наталья Лопаткина","type":"paragraph"},{"html":"Победителем регионального показа стал бренд «Kuashaka». Цель бренда – дать девушкам понимание того, что культура демонстрации физических параметров закончилась. С такой интересной философией мы ждем победителей на финале в Москве в декабре.","type":"paragraph"},{"html":"Бренд \"Kuashaka\"","type":"paragraph"},{"html":"Юлия Лимонова","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqvyzx00mwuktavh0yhmg9"},{"mediaId":"cmrmqvz6f00mxuktabz3x03ol"},{"mediaId":"cmrmqvzeb00myuktahee1sua9"},{"mediaId":"cmrmqvzna00mzuktaxpod289x"}]}]'::jsonb,'cmrmqvyok00mvukta7d0qc1l5','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2022-04-04T06:00:00.000Z'::timestamp,NULL,NULL,NULL,423,'/projects-esque/fashion-bitva/423-fashion-bitva-v-irkutske-stala-obsuzhdeniem-zhenskoj-jenergii-i-kultury.html','2026-07-15T21:02:31.672Z'::timestamp,'2026-07-16T13:59:26.089Z'::timestamp,'''10'':23B,41C ''100'':315C ''26'':11B ''27'':29C ''beauti'':121C ''bitva'':2A,28B,46C,56C ''cmrmqvyzx00mwuktavh0yhmg9'':378C ''cmrmqvz6f00mxuktabz3x03ol'':380C ''cmrmqvzeb00myuktahee1sua9'':382C ''cmrmqvzna