INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrxfo006iuktapmuw0r7d','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Цифровая мода в действии','Ни для кого не секрет, что цифровая мода последние годы развивается достаточно быстро.','604-cifrovaja-moda-v-dejstvii','[{"html":"<strong><u>Ни для кого не секрет, что цифровая мода последние годы развивается достаточно быстро. Но дизайнеры и модельеры не спешат переходить в цифровой формат, оставив создание привычных сезонных коллекции и участие в </u></strong><strong><u>fashion</u></strong> <strong><u>показах в реальной жизни, в жизни, которую можно потрогать на ощупь!</u></strong>","type":"paragraph"},{"html":"<strong><u>А готов ли к цифровой моде потребитель?</u></strong>","type":"paragraph"},{"html":"Тренд на виртуальную одежду пришел к нам из видеоигр, где игроманы тратили огромные суммы на апгрейд лука своего аватара.Эту идею поддержали и продолжили развивать мировые бренды, скупив землю в метавселенных и построив там магазины, где представили свои первые коллекции!","type":"paragraph"},{"html":"Как-то нереалистично звучит, правда?","type":"paragraph"},{"html":"Но в реальности мировые бренды – это всеми нам известные Adidas, Nke, Zara и многие другие! Не первый год они создают свои виртуальные коллекции и уже не только в игре!","type":"paragraph"},{"html":"<strong><u>Несомненно, новое веяние в индустрии моды вызывает огромной интерес. </u></strong>Так, например, American Eagle в партнерстве с DressX создали коллекцию виртуальных джинсов. Посыл коллекции – забота об экологии, бережное отношение к водным ресурсам, ведь на изготовление одной пары уходит около 11 000 литров воды.","type":"paragraph"},{"html":"К услугам цифровой моды прибегают и глянцевые издания. Так, например, Haute Living выпустил новый номер, где на обложке блистательная Меган Каспар (соосновательница Red DAO, первого в мире DAO в фэшн-индустрии) красуется в виртуальных образах от Fendi.","type":"paragraph"},{"html":"Порой виртуальный лук становится незаменимой услугой для тех, кто создает свой идеальный образ в социальных сетях! Тонна одежды в гардеробе и многочасовые походы в магазины заменит лишь пару нажатий кнопочек на андроиде или айфоне и ты уже примеряешь несколько луков в виртуальной примерочной! Еще пару нажатий и твоя фото в новом образе красуется во всех социальных сетях!","type":"paragraph"},{"html":"Будем следить и дальше за развитием цифрового мира и появления в нем новых дизайнеров с цифровыми коллекциями, ведь ниша, несмотря на ее развитие, еще достаточно свободна!","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqrwn0006guktax1b5330q"},{"mediaId":"cmrmqrxeg006huktaq89sx48d"}]}]'::jsonb,'cmrmqrwgd006fuktas7hrnq40','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2023-06-23T06:00:00.000Z'::timestamp,NULL,NULL,NULL,604,'/fashion/news-2/604-cifrovaja-moda-v-dejstvii.html','2026-07-15T20:59:22.116Z'::timestamp,'2026-07-16T13:57:19.485Z'::timestamp,'''000'':197C ''11'':196C ''adida'':135C ''american'':169C ''cmrmqrwn0006guktax1b5330q'':335C ''cmrmqrxeg006huktaq89sx48d'':337C ''dao'':226C,230C ''dressx'':174C ''eagl'':170C ''fashion'':49C ''fendi'':240C ''galleri'':333C ''haut'':213C ''live'':214C ''nke'':136C ''paragraph'':62C,72C,115C,124C,156C,201C,242C,302C,331C ''red'':225C ''zara'':137C ''аватар'':92C ''айфон'':277C ''андроид'':275C ''апгрейд'':89C ''бережн'':184C ''блистательн'':221C ''бренд'':100C,130C ''буд'':304C ''быстр'':17B,30C ''веян'':160C ''видеоигр'':82C ''виртуальн'':76C,147C,177C,237C,245C,285C ''вод'':199C ''водн'':187C ''всем'':132C ''вызыва'':164C ''выпуст'':215C ''гардероб'':263C ''глянцев'':209C ''год'':14B,27C,143C ''гот'':65C ''дальш'':307C ''действ'':4A ''джинс'':178C ''дизайнер'':32C,317C ''достаточн'':16B,29C,328C ''др