INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmquqal00iauktamo9hv9qz','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Осторожно, косметология!','Красота блогеров Инстаграма требует от женщин решительных действий.','478-ostorozhno-kosmetologija','[{"html":"Красота блогеров Инстаграма требует от женщин решительных действий. Скорректировать нос или подбородок, подкачать губы, улучшить форму бюста – признайтесь, вы тоже об этом думали? Рынок косметологических услуг растет и приносит владельцам клиник баснословную прибыль. Но всегда ли мы получаем тот результат, который ожидали?","type":"paragraph"},{"html":"Несколько лет назад всех потрясла трагическая история супермодели Линды Евангелисты. Она обратилась в косметологическую клинику, где ей сделали процедуру криолиполиза – расщепление жировой ткани методом воздействия холодом. Но эффект от процедуры был обратным: вместо уменьшения жировой ткани произошла парадоксальная жировая гиперплазия (ПАГ), то есть разрастание жировой ткани. Этот эффект возникает в одном случает из 4 тысяч процедур и еще до конца не изучен. Трагедия Линды Евангелисты потрясла fashion-комьюнити, и супермодели, стилисты и дизайнеры выразили Линде свое сочувствие. Только вот ей от этого не легче.","type":"paragraph"},{"html":"Этот случай широко известен, поскольку от рук косметолога пострадала супермодель. А сколько обычных женщины, разного возраста и финансового положения, с ужасом смотрят на себя в зеркало после неудачной пластики или процедуры аппаратной косметологии?","type":"paragraph"},{"html":"Как не стать жертвой непрофессионального косметолога? Как обезопасить себя от осложнений после косметологических процедур? Об этом рассуждает ведущий врач-косметолог петербургской косметологической клиники «Миррамед» Мария Верткина.","type":"paragraph"},{"html":"«Очень важно правильно выбрать для себя косметологическую процедуру или хирургическое вмешательство, – говорит Мария, – И в этом выборе нужно ориентироваться на индивидуальный подход к вам профессионального врача-косметолога. Что касается блогеров из Инстаграма, то некоторые из них разоблачают непрофессиональных косметологов и рассказывают о клиниках, куда точно не следует ходить. Прислушайтесь к их мнению. Помогут сделать правильный выбор сайты с отзывами пациентов. Они расскажут о клинике, которой можно доверять. При беседе с врачом ориентируйтесь на свои ощущения: доверяете ли вы ему? Очень важно наличие у клиники медицинской лицензии. Допустим, вам подходит косметологическая клиника и ее ценовая политика, но вас что-то настораживает. Начните лечение с более простых процедур, которые не несут в себе никаких рисков вашему здоровью. Это позволит вам понять, ваша ли это клиника и доверяете ли вы этому врачу. Идеально, если ваша знакомая пользуется услугами косметолога, прекрасно выглядит и процессы старения у нее замедляются. Можно воспользоваться ее рекомендациями».","type":"paragraph"},{"html":"Если вы нашли врача, которому вы доверяете, перед проведением косметологической процедуры расскажите ему обо всех своих проблемах со здоровьем. Аутоиммунные заболевания, патологии щитовидной железы, сахарный диабет, иммунодефицитные состояния нарушают заживление тканей, и после процедуры что-то может пойти не так.","type":"paragraph"},{"html":"Нужно различать нежелательные эффекты, которые могут быть после процедур или хирургического вмешательства, и осложнения. О нежелательных эффектах расскажет врач. Это может быть краснота и отек после лазерной шлифовки кожи, гематомы после инъекционных процедур. Пациента об этом информируют, он настраивается на это и находит время на реабилитацию после процедуры. Если вам кажется, что что-то пошло не так, нужно срочно прийти к врачу на консультацию и быстро получить необходимую медицинскую помощь. Это позволит избежать каких-то нежелательных явлений.","type":"paragraph"},{"html":"Если вы решились на серьезное хирургическое вмешательство, например, хотите поставить импланты, то можно посетить несколько клиник и услышать мнение разных врачей. Перед серьезным вмешательством врач посоветует сделать чек-ап, проверить свое здоровье. Существует даже генетические панели (исследования), которые позволяют предсказать процесс заживления тканей и помогут избежать рубцов. Современная косметология – это не только омоложение, но и лечение различных дефектов кожи. Дополнительная информация о здоровье пациента поможет врачу-косметологу составить безопасный протокол на омоложение или лечение.","type":"paragraph"},{"html":"Но что делать, если косметолог или пластический хирург навредил вашей внешности? Адвокат Екатерина Зернова считает, что паниковать не надо.","type":"paragraph"},{"html":"«Если говорить о пластических операциях, то срок реабилитации может быть длительным, от месяца до полугода. И только после этого можно определить, есть дефекты или нет, – говорит Екатерина, – Допустим, реабилитация прошла, и результат вам не нравится. Поговорите со своим косметологом или хирургом. Если он отрицает дефект, обращайтесь в другую клинику за независимой консультацией. По закону «О защите прав потребителей» вы имеет право на:","type":"paragraph"},{"html":"Наиболее распространен третий вариант, потому что пациент вряд ли будет обращаться за бесплатным устранением дефектов к тому же специалисту.","type":"paragraph"},{"html":"Для того, чтобы такое возмещение состоялось, нужно зафиксировать на фото и видео дефекты, сделать заключение от сторонней клиники (а лучше от нескольких) о том, что дефекты имеются. Также независимые специалисты должны указать, что необходимо сделать для устранения дефектов и сколько это будет стоить. И, наконец, надо написать заявление в клинику о возмещении стоимости устранения дефектов.","type":"paragraph"},{"html":"Допустим, клиника, в которой обезобразили вашу внешность, не желает возмещать вам расходы на исправление и устранение нежелательных явлений. Значит, нужно подавать в суд.","type":"paragraph"},{"html":"«Пациентов интересует, когда лучше начинать судебный процесс – до или после устранения дефектов. Я бы посоветовала сначала пройти через судебный процесс, взыскать предстоящие расходы и устранять дефекты после суда. Дело в том, что по таким делам практически всегда назначается медицинская экспертиза, в ходе которой эксперты обследуют пациента. Им будет легче установить наличие дефектов, если они не устранены. Если же вас обезобразили настолько, что вы не можете появиться на людях, устраняйте дефекты. Но предварительно максимально их зафиксируйте» - дополняет юрист.","type":"paragraph"},{"html":"По мнению Екатерины Зерновой, выиграть судебный процесс о некачественном оказании услуг косметологом или пластическим хирургом реально. Решающее значение играет судебная медицинская экспертиза, которую суд назначает по таким делам. Если эксперт приходит к выводу, что медицинская ошибка была, суд выносит решение в пользу пациента. Екатерина Зернова говорит о том, что приятным бонусом в этом случае будет еще и компенсация морального ущерба, а также штраф в размере половины от взысканных сумм с клиники. Например, с косметологической клиники взыскали 500 000 рублей, бонусом будет еще 250 000 рублей штрафа, который тоже заплатить клиника. Так «Закон о защите прав потребителей» охраняет право женщин на безопасную и высокопрофессиональную косметологию и пластическую хирургию.","type":"paragraph"},{"html":"Елена Шульгина","type":"paragraph"},{"type":"image","mediaId":"cmrmquq9j00i9uktazk84e8yl"}]'::jsonb,'cmrmquq1d00i8uktako9e5swb','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyz0000akwtaq6w9733r','cmrmpdrom0000sstarkqxwts4','2022-08-01T06:00:00.000Z'::timestamp,NULL,NULL,NULL,478,'/beauty/mnenie/478-ostorozhno-kosmetologija.html','2026-07-15T21:01:32.829Z'::timestamp,'2026-07-16T13:58:55.043Z'::timestamp,'''000'':918C,924C ''250'':923C ''4'':109C ''500'':917C ''cmrmqu