INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqzgc300w5uktaplx7nl7m','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Мода: 5 книг об индустрии','Все бумажные и интернет издания забиты статьями про модные тенденции и вариациями модных образов между собой.','341-moda-5-knig-ob-industrii','[{"html":"Все бумажные и интернет издания забиты статьями про модные тенденции и вариациями модных образов между собой. Однако не стоит слепо следовать моде и забывать, что такое собственный стиль и вкус. Сегодня мы познакомим вас с книгами, которые вдохновляют, знакомят с истоками моды и ее историей, учат видеть и понимать модные тенденции правильно и трезво.","type":"paragraph"},{"html":"<u><b><i>Фиона Ффулкс “Как читать моду. Интенсивный курс по</i><i> с</i><i>тилю</i><i> и моде”</i></b></u>","type":"paragraph"},{"html":"Книга моды для тех, кто интересуется историческими фактами: кто придумал корсет, почему сумочка Chanel 2.55 носит именно такое название, какое влияние оказали художники на моду. Текст мягко украшен иллюстрациями, что позволяет еще глубже понять и прочувствовать моду, какая она есть.<br /><br /><br />","type":"paragraph"},{"html":"<u><b><i>Николас Колридж \"Модный заговор”</i></b></u>","type":"paragraph"},{"html":"Издание от директора английского Conde Nast. Более 400 важных фигур мира моды опрошено за несколько лет. Все для того, чтобы принести миру “Модный заговор” - серия интервью, в которых опрошены самые великие творцы модной индустрии!","type":"paragraph"},{"html":"Книга, в которой, наконец, раскрыли секреты модного закулисья и рассказали шуточки модных дизайнеров.","type":"paragraph"},{"html":"Книге уже более 20 лет, и сейчас в печатном виде и на русском языке ее найти практически невозможно. С момента выхода она так и не переиздавалась. <br /><br /><br />","type":"paragraph"},{"html":"<i><u>Жером Готье \"Chanel. Энциклопедия стиля\"</u><br /></i>Коко Шанель - главная фигура в моде ХХ века. Это целая религия со своим именем и брендом, где стиль является эталоном, а творение классикой.","type":"paragraph"},{"html":"Книга показывает эволюцию стиля (от маленького черного платья до твидового костюма). Уникальные фотографии усиливают эффект от прочитанного и надолго остаются в памяти.<br /><br /><br />","type":"paragraph"},{"html":"<i><u><i>Инес де ла Фрессанж, Софи Гаше “Парижанка и ее стиль”</i></u><br /></i>Сегодня стиль парижанок все чаще приводит нас в восторг своей легкостью, непринужденностью и простотой. Они живут по воле сердце. По этому же принципу они и выбирают себе луки. Инес де ла Фрессанж пишет в этой книге, казалось бы, о таком банальном, но таком важном одновременно. Ее книга — это лучший гид по базовым вещам гардероба настоящих парижанок. Кроме этого автор поделилась полезными адресами в прекрасном Париже, городе любви и центре моды: где стоит покупать одежду, обувь и косметику. <br /><br /><br />","type":"paragraph"},{"html":"<u><i>Арнтцен Мари Гринде “Дресс-код. Голая правда о моде”</i></u>","type":"paragraph"},{"html":"Для мира моды характерны не только изысканные образы, но и перепроизводство, масштабные экологические проблемы и слепое поклонение брендам. Мода превозносит узкий круг людей, создающих тренды и влияющих на умы миллионов, заставляет потреблять, не задумываясь о последствиях. Мари Арнтцен рассказывает о пятой по величине мировой индустрии и об одной из величайших и, возможно, самых бессмысленных проблем нашего времени. О том, что такое на самом деле мода. Почему бренды наделяют людей властью. И почему красота так важна в нашей жизни.<br /><br />","type":"paragraph"},{"html":"<u><b><i>Моде научиться нельзя, к ней можно только прислушиваться.</i></b></u>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqzett00w1uktatu0mpl4i"},{"mediaId":"cmrmqzfer00w2ukta5i3gup94"},{"mediaId":"cmrmqzfrh00w3uktamwwd87vb"},{"mediaId":"cmrmqzgai00w4uktaugb9ua62"}]}]'::jsonb,'cmrmqzeez00w0uktaebguxanz','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz8q000ekwtadrt5g1dn','cmrmpdrom0000sstarkqxwts4','2021-05-06T06:00:00.000Z'::timestamp,NULL,NULL,NULL,341,'/sobytija/iskusstvo/341-moda-5-knig-ob-industrii.html','2026-07-15T21:05:13.203Z'::timestamp,'2026-07-16T14:00:42.286Z'::timestamp,'''2.55'':108C ''20'':200C ''400'':151C ''5'':2A ''chanel'':107C,228C ''cmrmqzett00w1uktatu0mpl4i'':479C ''cmrmqzfer00w2ukta5i3gup94'':481C ''cmrmqzfrh00w3uktamwwd87vb'':483C ''cmrmqzgai00w4uktaugb9ua62'':485C ''cond'':148C ''galleri'':477C ''nast'':149C ''paragraph'':77C,92C,135C,142C,179C,195C,224C,255C,280C,370C,383C,464C,475C ''автор'':350C ''адрес'':353C ''английск'':147C ''арнтц'':372C,422C ''базов'':343C ''банальн'':332C ''бессмыслен'':438C ''бренд'':246C,402C,451C ''бумажн'':7B,23C ''важн'':152C,335C,459C ''вариац'':17B,33C ''вдохновля'':59C ''век'':238C ''велик'':174C ''величайш'':434C ''величин'':427C ''вещ'':344C ''вид'':206C ''видет'':68C ''вкус'':51C ''власт'':454C ''влия'':411C ''влиян'':114C ''возможн'':436C ''вол'':309C ''восторг'':300C ''времен'':441C ''выбира'':317C ''выход'':217C ''гардероб'':345C ''гаш'':287C ''гид'':341C ''главн'':233C ''глубж'':126C ''гол'':378C ''город'':357C ''гот'':227C ''гринд'':374C ''де'':283C,321C ''дел'':448C ''дизайнер'':193C ''директор'':146C ''дресс'':376C ''дресс-код'':375C ''жер'':226C ''живут'':307C ''жизн'':462C ''забит'':11B,27C ''забыва'':45C ''заговор'':140C,167C ''задумыв'':418C ''закулис'':188C ''заставля'':415C ''знаком'':60C ''издан'':10B,26C,144C ''изыска'':391C ''иллюстрац'':122C ''имен'':110C,244C ''индустр'':5A,177C,429C ''инес'':282C,320C ''интенсивн'':84C ''интерв'':169C ''интерес'':99C ''интернет'':9B,25C ''исток'':62C ''истор'':66C ''историческ'':100C ''каза'':328C ''как'':113C ''классик'':253C ''книг'':3A,57C,94C,181C,197C,257C,327C,338C ''код'':377C ''кок'':231C ''колридж'':138C ''корсет'':104C ''косметик'':368C ''костю