':409C ''узк'':405C ''украш'':121C ''ум'':413C ''уникальн'':268C ''усилива'':270C ''учат'':67C ''факт'':101C ''фигур'':153C,234C ''фион'':79C ''фотограф'':269C ''фрессанж'':285C,323C ''ффулкс'':80C ''характерн'':388C ''художник'':116C ''хх'':237C ''цел'':240C ''центр'':360C ''чащ'':296C ''черн'':263C ''чита'':82C ''шанел'':232C ''шуточк'':191C ''эволюц'':259C ''экологическ'':397C ''энциклопед'':229C ''эт'':239C,312C,339C ''эталон'':250C ''эффект'':271C ''явля'':249C ''язык'':210C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqv2ov00jquktaf2735arb','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Денис Нурулин: "Я хочу, чтобы мои фильмы отзывались в сердцах людей"','Актер Денис Нурулин Нурулин ( Сиделка, Нищеброды, Этерна, Елизавета) родился и вырос в городе Бавлы, республики Татарстан.','463-denis-nurulin-ja-hochu-chtoby-moi-filmy-otzyvalis-v-serdcah-ljudej','[{"html":"Актер Денис Нурулин <strong>(\"Сиделка\", \"Нищеброды\", \"Этерна\", \"Елизавета\") </strong>родился и вырос в городе Бавлы, республики Татарстан. Будучи ребенком, он об актерской карьере и не помышлял, поскольку в то время его мысли были заняты исключительно спортом, а именно - футболом. Но все изменил Его Величество Случай - однажды Денис поехал в столицу, после чего его жизнь потекла в совершенно ином направлении.","type":"paragraph"},{"html":"В эксклюзивном интервью ESQUE актер рассказал, как начинался его творческий путь и поделился своими фобиями.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Можно сказать, что ваша актерская карьера началась в 13 лет - тогда вы впервые попробовали себя перед камерой, снимаясь в массовке сериала «Путейцы-2». Расскажите, как удалось попасть на съемочную площадку? </strong>","type":"paragraph"},{"html":"<strong>Денис:</strong> Вся эта история началась примерно в 2010 году. В то время я приехал с родителями в Москву и попал на экскурсию на студию «Мосфильм». Мы рассматривали съемочные павильоны и это время меня и еще одну женщину из нашей группы заприметил режиссер. Он пригласил нас попробовать сыграть в массовке. Сказал: \"Главное - не смотри в камеру!\". А для меня все это в новинку, к тому же, я очень боялся. И вот мы делаем первый дубль, после чего ко мне подходит режиссер и говорит: «Ну что ты стоишь весь зажатый? Сделай что-нибудь!». Конечно, сейчас все это кажется забавным, но тогда я безумно впечатлился происходящим и появилось огромное желание сниматься в кино.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: С этого момента начались первые шаги на пути к актерской профессии?</strong>","type":"paragraph"},{"html":"<strong>Денис:</strong> Именно так. После окончания школы я поступил в Московский театральный колледж Олега Табакова. Другие варианты не рассматривал - знал, что понесу документы именно туда. Поступал в 2013 году после 9-го класса и в 15 лет уже переехал жить в Москву. Родители восприняли эту новость нормально - наши отношения всегда строились на доверии. Мама понимала, что отдает меня в надёжные руки, поскольку колледж был и остается очень достойным заведением.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Насколько известно, Сергей Безруков сыграл важную для вас роль во всей вашей карьере в целом. Расскажите, как вы с ним познакомились?</strong>","type":"paragraph"},{"html":"<strong>Денис:</strong> Ещё будучи студентами, мы очень любили всех учеников Олега Павловича. Сергей Безруков - один из них. На 4-м курсе я начал думать о том, куда устраиваться на работу, в какой театр. Губернский театр привлекал меня изначально - тогда я пришел к Сергею Безрукову, он выслушал меня и сказал, чтобы я прислал свое резюме. А спустя время к нам на учебу пришел кастинг-директор - он выбирал актеров в кинокомедию «Нищеброды». Генеральным продюсером фильма выступил Сергей Безруков. Я принял участие в пробах и через какое-то время меня утвердили. А ещё позже выяснилось, что Сергей Витальевич будет играть моего экранного отца. С этого момента началась наша совместная работа. После окончания съемок он сказал, что ждет меня в театре.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Многие считают вашу роль в постановке «Веселый солдат» одной из самых ярких. А какую свою театральную роль можете выделить вы?</strong>","type":"paragraph"},{"html":"<strong>Денис:</strong> «Веселый солдат» действительно очень хорошая постановка. Но лично я могу выделить роль в спектакле Олега Табакова «На всякого мудреца довольно простоты». Он шел в Московском театре Табакова в течение 17 лет, главную роль всегда играл Сергей Безруков. В 2019 году он предложил возродить постановку - как дань памяти Олегу Павловичу. Свою роль Гумова Сергей Витальевич передал мне по наследству. В свое время я уже видел этот спектакль, но наблюдая за ним с самого дальнего балкона я даже не мог представить, что когда-то исполню эту роль.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Насколько известно, вы любите исторические романы и фильмы. Почему?</strong>","type":"paragraph"},{"html":"<strong>Денис:</strong> Меня изначально приглашали на роли в такие кинокартины. Самым первым был фильм «Охота на дьявола», а за ним - большой проект «Безсоновъ», где мне досталась главная роль. Я очень комфортно чувствую себя в таких проектах, буквально погружаюсь в эту атмосферу. Костюмы, невероятно красивые декорации - все это доставляет колоссальное удовольствие.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: В одном из интервью вы рассказали о своей боязни лошадей. Все мы пониманием, что актеры - тоже люди, со своими страхами. Однако людям такой профессии приходится с ними бороться чаще остальных. Как вам это удается?</strong>","type":"paragraph"},{"html":"<strong>Денис:</strong> У меня до этого был небольшой опыт съемок с лошадьми. В фильме \"Этерна\" была одна сцена, где мне нужно было просто сидеть в седле и ехать шагом. А в «Елизавете» уже начались настоящие скачки, причем их было много. Я ходил на тренировки и учился скакать галопом - к концу съёмок я уже уверенно сидел в седле. Но при этом большие пробеги и погони за нас все равно выполняли дублеры. Одну могу сказать - чтобы побороть страх, нужно идти ему навстречу. Иначе ничего не получится. Лично я не только избавился от страхов перед лошадьми, но и вошел во вкус, сейчас мне очень нравится верховая езда.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Наша беседа подходит к концу. Денис, поделитесь своим мнением - в чем смысл актерской профессии?</strong>","type":"paragraph"},{"html":"<strong>Денис:</strong> Знаете, в свое время многие выдающиеся люди оставили после себя большое наследие. Именно этого я хочу - чтобы и мои фильмы как-то повлияли на людей, отозвались в их сердцах. Ради этого стоит работать.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Что можете пожелать нашим читателям? </strong>","type":"paragraph"},{"html":"<strong>Денис:</strong> Любите и цените жизнь, каждый ее момент и любую мелочь. Именно они делают обычные будни красочными и наполненными. Умение радоваться мелочам – непростое занятие, но, однажды ему научившись, вы начнете испытывать от жизни настоящее наслаждение!","type":"paragraph"},{"type":"image","mediaId":"cmrmqv2ms00jpuktaoxr523nz"}]'::jsonb,'cmrmqv26l00jouktay3tsedg5','cmrm8kzli000ikwtafbw33jnj','cmrm8kzns000jkwtahwuubl9w','cmrmpdrom0000sstarkqxwts4','2022-07-02T06:00:00.000Z'::timestamp,NULL,NULL,NULL,463,'/persona/intervju/463-denis-nurulin-ja-hochu-chtoby-moi-filmy-otzyvalis-v-serdcah-ljudej.html','2026-07-15T21:01:48.895Z'::timestamp,'2026-07-16T13:59:05.329Z'::timestamp,'''-2'':129C ''13'':115C ''15'':303C ''17'':540C ''2010'':147C ''2013'':295C ''2019'':549C ''4'':382C ''9'':298C ''cmrmqv2ms00jpuktaoxr523nz'':914C ''esqu'':91C,106C,254C,340C,486C,600C,665C,809C,865C ''imag'':912C ''paragraph'':86C,104C,138C,252C,267C,338C,363C,484C,508C,598C,611C,663C,701C,807C,825C,863C,872C,910C ''актер'':12B,28C,92C,431C,680C ''актерск'':47C,111C,264C,822C ''атмосфер'':652C ''бавл'':25B,40C ''балкон'':584C ''безрук'':344C,377C,440C,547C ''безруков'':407C ''безсоновъ'':634C ''безумн'':241C ''бесед'':811C ''больш'':632C,762C,838C ''борот'':693C ''боя'':207C ''боязн'':674C ''будн'':889C ''будуч'':43C,367C ''буквальн'':648C ''важн'':346C ''вариант'':284C ''ваш'':110C,352C,489C ''ве'