INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqs58k007bukta2gvt4qk0','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Кризис в России глазами психологов','За последние 3 года наш мир изменился до неузнаваемости.','595-krizis-v-rossii-glazami-psihologov','[{"html":"За последние 3 года наш мир изменился до неузнаваемости. Пандемия и военные действия оставили неизгладимый след в нашем сознании, в наших мыслях и действиях. Для кого-то прежний мир исчез навсегда, а кто-то лишился близких и дорогих сердцу людей! Вместе со специалистами из сферы психологии и гипнокоучинга мы постарались поговорить о насущных проблемах современного общества, нашли, как, нам кажется, ответы на важные вопросы и даже смогли дать советы как самостоятельно улучшить качество жизни, находясь в стрессовых и тревожных состояниях.","type":"paragraph"},{"html":"Приятного просмотра!","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/KwMsWe9RXxg?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\" allowfullscreen=\"\" title=\"Кризис в России глазами психологов\"></iframe>","type":"embed"}]'::jsonb,NULL,'cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2023-04-20T06:00:00.000Z'::timestamp,NULL,NULL,NULL,595,'/psihologija/intervju-2/595-krizis-v-rossii-glazami-psihologov.html','2026-07-15T20:59:32.228Z'::timestamp,'2026-07-16T13:57:28.309Z'::timestamp,'''3'':8B,17C ''emb'':105C ''paragraph'':98C,103C ''близк'':52C ''важн'':79C ''вмест'':57C ''воен'':26C ''вопрос'':80C ''гипнокоучинг'':64C ''глаз'':4A ''год'':9B,18C ''дат'':84C ''действ'':27C,38C ''дорог'':54C ''жизн'':90C ''измен'':12B,21C ''исчез'':45C ''кажет'':76C ''качеств'':89C ''ког'':41C ''кого-т'':40C ''кризис'':1A ''кто-т'':48C ''лиш'':51C ''люд'':56C ''мир'':11B,20C,44C ''мысл'':36C ''навсегд'':46C ''нам'':75C ''насущн'':69C ''наход'':91C ''наш'':10B,19C,32C,35C ''нашл'':73C ''неизгладим'':29C ''неузнаваем'':14B,23C ''обществ'':72C ''остав'':28C ''ответ'':77C ''пандем'':24C ''поговор'':67C ''последн'':7B,16C ''постара'':66C ''прежн'':43C ''приятн'':100C ''проблем'':70C ''просмотр'':101C ''психолог'':5A,62C ''росс'':3A ''самостоятельн'':87C ''сердц'':55C ''след'':30C ''смогл'':83C ''совет'':85C ''современ'':71C ''сознан'':33C ''состоян'':96C ''специалист'':59C ''стрессов'':93C ''сфер'':61C ''тревожн'':95C ''улучш'':88C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqem9d0034potag84xvxjt','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'"У Яна нет детей и другой семьи": Киркоров призвал Алсу опомниться','Кажется, в связи с предстоящим разводом Алсу и Яна Абрамова мир шоубизнеса разделился на два лагеря.','665-u-jana-net-detej-i-drugoj-semi-kirkorov-prizval-alsu-opomnitsja','[{"html":"Кажется, в связи с предстоящим разводом Алсу и Яна Абрамова мир шоу бизнеса разделился на два лагеря. Одни выступают за примирение пары и утверждают, что ни детей, ни любовниц у Абрамова нет. По очевидной случайности представителями этой стороны являются мужчины. Другие сетуют на горькую участь певицы и советуют держаться!","type":"paragraph"},{"html":"Мы же не знаем подробностей, но смело можем заявить: Когда в браке нажит не 1 млрд рублей, то очень больно говорить о разводе.","type":"paragraph"},{"html":"«С Алсу говорили, но старались не задевать эту тему, с Яном чаще говорим по душам. Состояние у обоих так себе, мягко говоря. Знаю, что, несмотря на массу слухов — Ян сейчас не состоит ни с кем в отношениях. Все его переживания и поступки говорят, что он хочет сохранить семью», - прокомментировал скандальный развод друг семьи Алексей Чумаков.","type":"paragraph"},{"html":"Попытался примирить супругов и Филипп Киркоров. Правда, получилось весьма специфически.","type":"paragraph"},{"html":"«Я точно знаю, что никакой параллельной семьи и детей на стороне у Яна нет» - по логике Киркорова, надо радоваться, что нет детей и семьи, а только любовница.","type":"paragraph"},{"html":"Однако на все доводы друзей, Алсу реагирует холодно и уже обратилась в Савеловский суд с заявлением о разделе имущества. Первое заседание уже назначено на 26 июля!","type":"paragraph"},{"html":"Громкий развод певицы и бизнесмена очень показателен! В один момент ты можешь лишиться всего, что так упорно строил в течение долгих лет: имени, имущества и любящий семьи. Стоит ли это того?","type":"paragraph"},{"html":"К слову, в сети уже прошлась яростная волна «Долой эскортниц» во главе со Степановой и Гордон.","type":"paragraph"},{"html":"А мы следим за громким делом!","type":"paragraph"}]'::jsonb,'cmrmqem6x0033potajq6mqopj','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-07-10T06:00:00.000Z'::timestamp,NULL,NULL,NULL,665,'/v-mire/665-u-jana-net-detej-i-drugoj-semi-kirkorov-prizval-alsu-opomnitsja.html','2026-07-15T20:49:01.106Z'::timestamp,'2026-07-16T13:56:40.517Z'::timestamp,'''1'':94C ''26'':231C ''paragraph'':78C,104C,162C,175C,205C,234C,268C,287C,296C ''абрамов'':21B,37C,58C ''алекс'':159C ''алс'':10A,18B,34C,107C,212C ''бизнес'':40C ''бизнесм'':240C ''больн'':99C ''брак'':91C ''весьм'':172C ''волн'':277C ''выступа'':46C ''глав'':281C ''говор'':100C,108C,118C,127C,148C ''гордон'':285C ''горьк'':71C ''громк'':236C,293C ''дел'':294C ''держа'':76C ''дет'':4A,54C,185C,198C ''довод'':210C ''дол'':278C ''долг'':256C ''друг'':68C,157C ''друз'':211C ''душ'':120C ''задева'':112C ''заседан'':227C ''заяв'':88C ''заявлен'':222C ''зна'':83C,128C,179C ''имен'':258C ''имуществ'':225C,259C ''июл'':232C ''кажет'':12B,28C ''кем'':140C ''киркор'':8A,169C ''киркоров'':193C ''лагер'':27B,44C ''лет'':257C ''лиш'':248C ''логик'':192C ''любовниц'':56C,203C ''любя'':261C ''масс'':132C ''мир'':22B,38C ''млрд'':95C ''мож'':87C ''можеш'':247C ''момент'':245C ''мужчин'':67C ''мягк'':126C ''наж'':92C ''назнач'':229C ''несмотр'':130C ''никак'':181C ''обо'':123C ''обрат'':217C ''одн'':45C ''однак'':207C ''опомн'':11A ''отношен'':142C ''очевидн'':61C ''очен'':98C,241C ''пар'':49C ''параллельн'':182C ''певиц'':73C,238C ''перв'':226C ''переживан'':145C ''подробн'':84C ''показател'':242C ''получ'':171C ''попыта'':164C ''поступк'':147C ''правд'':170C ''представител'':63C ''предстоя'':16B,32C ''призва'':9A ''примир'':165C ''примирен'':48C ''прокомментирова'':154C ''прошл'':275C ''радова'':195C ''развод'':17B,33C,102C,156C,237C ''раздел'':24B,41C,224C ''реагир'':213C ''рубл'':96C ''савеловск'':219C ''связ'':14B,30C ''сем'':7A,153C,158C,183C,200C,262C ''сет'':69C,273C ''скандальн'':155C ''след'':291C ''слов'':271C ''слух'':133C ''случайн'':62C ''смел'':86C ''совет'':75C ''состо'':137C ''состоян'':121C ''сохран'':152C ''специфическ'':173C ''стара'':110C ''степанов'':283C ''сто'':263C ''сторон'':65C,187C ''стро'':253C ''суд'':220C ''супруг'':166C ''тем'':114C ''течен'':255C ''точн'':178C ''упорн'':252C ''утвержда'':51C ''участ'':72C ''филипп'':168C ''холодн'':214C ''хочет'':151C ''чащ'':117C ''чумак'':160C ''шо'':39C ''шоубизнес'':23B ''эскортниц'':279C ''эт'':265C ''явля'':66C ''ян'':2A,20B,36C,116C,134C,189C ''яростн'':276C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqwx4200pluktajq052ph6','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Fashion bitva в Москве. Финал 9 сезона в Яровит Якиманка Холл','24 февраля в Яровит Якиманка Холл состоялся финал 9 сезона международного проекта Fashion bitva.','405-fashion-bitva-v-moskve-final-9-sezona-v-jarovit-jakimanka-holl','[{"html":"26 февраля в Яровит Якиманка Холл состоялся финал 9 сезона международного проекта Fashion bitva.","type":"paragraph"},{"html":"Cвои коллекции на тему «Будущее 32» презентовали 19 дизайнеров, включая внеконкурсные коллекции участников прошлых сезонов Климовой Евгении и Надолинской Виктории.","type":"paragraph"},{"html":"Евгения Климкова","type":"paragraph"},{"html":"Виктория Надолинская","type":"paragraph"},{"html":"Мероприятие началось в весьма неожиданном формате.","type":"paragraph"},{"html":"Для гостей битвы организаторы подготовили выставку работ конкурсантов. В перфомансе приняли участие и московские художники, которые рисовали образы участников, представленные на манекенах.","type":"paragraph"},{"html":"«Это был интересный опыт. Эта идея мне очень понравилась и я точно буду дорабатывать и внедрять ее в наши следующие показы» – поделилась своими впечатлениями организатор Fashion bitva, Балагурова Алена.","type":"paragraph"},{"html":"Для многих тема будущего оказалось нелегкой, ведь сложно представить что нас ждет через 10 лет. Однако многие дизайнеры приложили максимум усилий и весьма интересно стилизовали образы. Юлия Куренкова, победитель регионального показа в Нижнем Новгороде, выступила с коллекцией-победителем «KARSIKKO», в дополнении к которой использовала воинственные головные уборы и украшения. Жюри оценили данный подход и вручили Юлии 2 место.","type":"paragraph"},{"html":"Юлия Куренкова","type":"paragraph"},{"html":"Не менее интересно представила свою коллекцию и Ирина Карпенко. Модели уверенно дефилировали под звуки скрипки, держа во рту цветы. Голову моделей закрывал объемный вакуум из прозрачного капронового материала.","type":"paragraph"},{"html":"«В основе моего бренда лежит личная история возрождения и мечта о будущем. Мой бренд про искусство и наследие, создающее будущее» – поделилась замыслом коллекции дизайнер.","type":"paragraph"},{"html":"Ирина Карпенко","type":"paragraph"},{"html":"Детский бренд «Safinelli» в своей новой коллекции платьев «Сruella with love» рассказал о моде будущего через любовь и свободу духа. Эту же мысль поддержал и бренд «Cust» из Владивостока. В основе кастомной коллекции бренда «Мысли вслух» лежит свобода самовыражения и уникальность. «Я вдохновлялась смелыми, интересными людьми, которые не боятся быть собой и заявлять о себе миру» - поделилась своими секретами дизайнер бренда Александра Марчук.","type":"paragraph"},{"html":"Бренд \"Safinelli\"","type":"paragraph"},{"html":"Бренд \"Cust\"","type":"paragraph"},{"html":"Бренд \"Estco\"","type":"paragraph"},{"html":"Коллекция корсетных платьев «BOHEMIA» дизайнера Аллы Беловой рассказывает о том, как стать музой, стать смыслом, стать неиссякаемым источником женственности и красоты. Эту же идею в создании конкурсных коллекции разделили и другие участники.","type":"paragraph"},{"html":"«Коллекция из шелка для женщин, которые прекрасны каждый день. Не бывает некрасивых женщин, бывает неправильно подбородная одежда» - рассказала о своей коллекции дизайнер из Санкт-Петербурга, Анета Шмель.","type":"paragraph"},{"html":"Основная идея в коллекции Инны Триандофиловой из Владикавказа - это утончённость и женственность, сочетание тонких тканей, кружева и ручной вышивки!","type":"paragraph"},{"html":"Московский дизайнер Ольга Плохова создала коллекцию для сильных женщин, не нуждающихся в том, чтобы произвести фурор. Коллекция построена без контрастов, без вызова, из однотонных тканей природного цвета, но сложных архитектурных силуэтов.","type":"paragraph"},{"html":"Ольга Плохова","type":"paragraph"},{"html":"Алла Белова","type":"paragraph"},{"html":"Инна Триандофилова","type":"paragraph"},{"html":"Были и дизайнеры, поддерживающие мечту об экологичном будущем. Главной идеей в коллекции дизайнера из Тюмени Елены Филиновой стало возвращение к корням, использование ручного труда и ремесла. За основу взята стеганая ткань с серо-бронзовым отливом, джут и мешковина.","type":"paragraph"},{"html":"Экологичная коллекция из натуральных материалов «Свободная Африка» дизайнера Олеси Пановой выполнена в стиле Африки и хиппи. Она также считает, что будущее за экологичной модой.","type":"paragraph"},{"html":"Апсайклинг-коллекция бренда «Ecoolska» в стиле глэм рок создана из б/у вещей, купленных в секонд хенде. Коллекция будет продана весной 2022 на благотворительном аукционе. Это весьма интересное направление в моде, стремительно набирающее обороты.","type":"paragraph"},{"html":"«Использование шёлка, льна и полиэтилена - отображение обостренной темы будущего - экологии. А смешение этнических элементов одежды кричит о подчеркивании своей культурной принадлежности» - так высказалась о своих конкурсных образах ростовский дизайнер Елизавета Толпинская.","type":"paragraph"},{"html":"Оксана Фетисова в своей коллекции «Блики будущего» подготовила для гостей приятный сюрприз: коллекция выполнена из переработанной бумаги в сочетании с фатином и синтетической плащевой тканью.","type":"paragraph"},{"html":"«Мы не знаем как будет выглядеть мода будущего, но очертания уже видны» - так считает дизайнер.","type":"paragraph"},{"html":"Видимо, экологичность в моде – это то, что не может быть беспроигрышным в наше время. Мария Овсянникова, победитель 9 сезона, представила коллекцию «FORZA A PASSIONE/Сила и страсть». Коллекция выполнена из натуральных тканей с применением конского волоса - это свежий глоток воздуха, сочетание нежности и брутальности, хрупкости и необыкновенной силы и страсти. Коллекция была высоко оценена жюри и выбрана в качестве победителя практически единогласно.","type":"paragraph"},{"html":"«Участие в конкурсе Fashion Bitva - это невероятный опыт и огромный шаг в становлении моего бренда. Я дополнила коллекцию новыми луками, успела реализовать все задуманное и наметила новые направления для развития» - поделилась своими впечатлениями о показе и планами на будущее волгоградский дизайнер, Наталья Кузнецова.","type":"paragraph"},{"html":"Олеся Панова","type":"paragraph"},{"html":"Наталия Кузнецова","type":"paragraph"},{"html":"Мария Овсянникова","type":"paragraph"},{"html":"Татьяна Рыжая","type":"paragraph"},{"html":"Елизавета Толпинская","type":"paragraph"},{"html":"Оксана Фетисова","type":"paragraph"},{"html":"Анета Шмель","type":"paragraph"},{"html":"Елена Филинова","type":"paragraph"},{"html":"Бренд \"Ecoolska\"","type":"paragraph"},{"html":"Организаторы конкурса выражают благодарность членам жюри за честное судейство и советы конкурсантам: Ольге Сысоевой (тренданалитик, fashion-консультант, арт-коуч, член Союза дизайнеров России, преподаватель РГУ им. А.Н.Косыгина), Андрею Пономареву (известный российский дизайнер) и Ларисе Смирновой (директор института дизайна, РГУ им. А.Н.Косыгина).","type":"paragraph"},{"html":"<u><i>Фото: @kapotfoto</i></u>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqwjpx00p2uktayrfeb2is"},{"mediaId":"cmrmqwkb600p3ukta8y0cjohj"},{"mediaId":"cmrmqwkyd00p4ukta40kizans"},{"mediaId":"cmrmqwll300p5uktactgkg0vn"},{"mediaId":"cmrmqwmby00p6ukta7xjgmfbj"},{"mediaId":"cmrmqwn3u00p7uktarg43jm43"},{"mediaId":"cmrmqwnq600p8uktavj765qse"},{"mediaId":"cmrmqwo2g00p9ukta4j5a68bw"},{"mediaId":"cmrmqwoha00pauktaoom5kx1k"},{"mediaId":"cmrmqwpaf00pbuktahxhfd46y"},{"mediaId":"cmrmqwq3900pcuktavtfj8oa1"},{"mediaId":"cmrmqwqmr00pduktauvx06079"},{"mediaId":"cmrmqwry200peukta10a0blef"},{"mediaId":"cmrmqwsoe00pfuktavl7fg228"},{"mediaId":"cmrmqwtit00pguktaxuo5xrjh"},{"mediaId":"cmrmqwuip00phuktaueiglzyy"},{"mediaId":"cmrmqwuyi00piukta1a8cryg1"},{"mediaId":"cmrmqwvs700pjukta5ycwujfp"},{"mediaId":"cmrmqwx1300pkuktaswyiof2e"}]}]'::jsonb,'cmrmqwipd00p1uktafzdh68xw','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2022-03-08T06:00:00.000Z'::timestamp,NULL,NULL,NULL,405,'/projects-esque/fashion-bitva/405-fashion-bitva-v-moskve-final-9-sezona-v-jarovit-jakimanka-holl.html','2026-07-15T21:03:14.978Z'::timestamp,'2026-07-16T13:59:42.636Z'::timestamp,'''10'':155C ''19'':50C ''2'':199C ''2022'':581C ''24'':12B ''26'':26C ''32'':48C ''9'':6A,20B,34C,694C ''bitva'':2A,25B,39C,136C,746C ''bohemia'':356C ''cmrmqwjpx00p2uktayrfeb2is'':890C ''cmrmqwkb600p3ukta8y0cjohj'':892C ''cmrmqwkyd00p4ukta40kizans'':894C ''cmrmqwll300p5uktactgkg0vn'':896C ''cmrmqwmby00p6ukta7xjgmfbj'':898C ''cmrmqwn3u00p7uktarg43jm43'':900C ''cmrmqwnq600p8uktavj765qse'':902C ''cmrmqwo2g00p9ukta4j5a68bw'':904C ''cmrmqwoha00pauktaoom5kx1k'':906C ''cmrmqwpaf00pbuktahxhfd46y'':908C ''cmrmqwq3900pcuktavtfj8oa1'':910C ''cmrmqwqmr00pduktauvx06079'':912C ''cmrmqwry200peukta10a0blef'':914C ''cmrmqwsoe00pfuktavl7fg228'':916C ''cmrmqwtit00pguktaxuo5xrjh'':918C ''cmrmqwuip00phuktaueiglzyy'':920C ''cmrmqwuyi00piukta1a8cryg1'':922C ''cmrmqwvs700pjukta5ycwujfp'':924C ''cmrmqwx1300pkuktaswyiof2e'':926C ''cust'':298C,344C ''cво'':43C ''ecoolska'':563C,829C ''estco'':349C ''fashion'':1A,24B,38C,135C,745C,849C ''fashion-консультант'':848C ''forza'':698C ''galleri'':888C ''kapotfoto'':884C ''karsikko'':181C ''love'':282C ''paragraph'':41C,64C,69C,74C,83C,108C,140C,202C,207C,238C,265C,270C,336C,341C,346C,351C,386C,417C,439C,473C,478C,483C,488C,530C,557C,595C,629C,657C,675C,740C,786C,791C,796C,801C,806C,811C,816C,821C,826C,831C,881C,886C ''passion'':700C ''safinelli'':274C,339C ''ал'':138C ''александр'':333C ''алл'':358C,480C ''андр'':864C ''анет'':414C,818C ''апсайклинг'':560C ''апсайклинг-коллекц'':559C ''арт'':852C ''арт-коуч'':851C ''архитектурн'':470C ''аукцион'':584C ''африк'':538C,545C ''б'':570C ''балагуров'':1