сов'':632C,814C ''филинов'':506C,824C ''фина'':5A,19B,33C ''формат'':81C ''фот'':883C ''фурор'':456C ''хенд'':576C ''хипп'':547C ''холл'':11A,17B,31C ''хрупкост'':721C ''художник'':99C ''цвет'':227C,467C ''честн'':840C ''член'':837C,854C ''шаг'':752C ''шелк'':390C,598C ''шмел'':415C,819C ''эколог'':606C ''экологичн'':496C,532C,554C,678C ''элемент'':610C ''эт'':110C,114C,427C,585C,681C,713C,747C ''этническ'':609C ''юл'':168C,198C,204C ''якиманк'':10A,16B,30C ''яров'':9A,15B,29C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqrzzj006puktas097o6h6','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Ксения Тен: "Основной массе дизайнеров не хватает вдохновения и поддержки со стороны государства"','Путь дизайнера в России крайне сложен.','602-ksenija-ten-osnovnoj-masse-dizajnerov-ne-hvataet-vdohnovenija-i-podderzhki-so-storony-gosudarstva','[{"html":"<i><strong>Путь дизайнера в России крайне сложен. Нехватка бюджетов, знаний и опыта. Мы поговорили с молодым дизайнером из Сочи, Ксенией Тен о сложностях в развитии </strong><strong>fashion-индустрии, о том, как тяжело начинающему бренду на начальном этапе и что не стоит делать на первых этапах!</strong></i>","type":"paragraph"},{"html":"<strong>Esque: Ксения, расскажите, как вы стали дизайнером одежды? </strong>","type":"paragraph"},{"html":"<strong>Ксения:</strong> Источником вдохновения послужило мое желание шить после материнства. Во мне резко проснулось желание творить! Я села за машинку и начала. До этого у меня не было опыта в создании одежды и не было швейных навыков работы за оборудованием, в то время я создавала аксессуары для волос из атласных лент, фоамирана и полимерной глины. У меня был свой небольшой магазин по продаже изделий ручных работ, где представлялись не только мои работы, но и работы других мастериц, ремесленников Краснодарского края.","type":"paragraph"},{"html":"<strong>Esque: Что лежит в основе вашего бренда? Его ДНК. </strong>","type":"paragraph"},{"html":"<strong>Ксения:</strong> В основе ДНК бренда лежит стиль милитари, это женщина воин в мегаполисе, которая вынуждена сражаться ежедневно с социальными проблемами и решать их не хуже мужчин. Но иногда Она (женщина) позволяет себе отдохнуть и быть женственной, мягкой и нежной.","type":"paragraph"},{"html":"<strong>Esque: Вы получали профильное образование?</strong>","type":"paragraph"},{"html":"<strong>Ксения:</strong> Профильного образования у меня нет, я самоучка, если мне нужно было выучить технологию обработки или конструирование, я брала и изучала, методом проб и ошибок создавала свои изделия. Я люблю то, что я создаю своими руками, это моя личная медитация. Постоянно занимаюсь саморазвитием, посещаю семинары с экспертами, читаю литературу, общаюсь с дизайнерами и каждый день оттачиваю свое мастерство практически. Здесь самое главное, это самодисциплина.","type":"paragraph"},{"html":"<strong>Esque: Очень многие критикуют человека, занимающегося любимым делом, не имея профильного образования в этой специализации. Это неправильная позиция?</strong>","type":"paragraph"},{"html":"<strong>Ксения:</strong> Я считаю, что дизайнер может быть самоучкой. Для этого нужен талант, любовь к делу, большое трудолюбие и желание развиваться. Это трудоемкий процесс и порой творческие муки. Создание новой коллекции создаются через собственную призму переживаний. Это интеллектуально-эмоциональный процесс.","type":"paragraph"},{"html":"<strong>Esque: Из каких источников вы черпаете знания?</strong>","type":"paragraph"},{"html":"<strong>Ксения:</strong> Знания черпаю у более опытных коллег, также книги, видеоролики, документальные фильмы, социальные сети.","type":"paragraph"},{"html":"<strong>Esque: Что не хватает в вашем понимании основной массе дизайнеров? Основные ошибки при создании бренда?</strong>","type":"paragraph"},{"html":"<strong>Ксения:</strong> Основной массе дизайнеров не хватает вдохновения и поддержки со стороны государства, на собственных ресурсах очень тяжело двигаться вперед. Специальность сильно материальна: ткань, оборудование, прикладные материалы, фурнитура, реклама, з/п сотрудникам, арендованные помещения для производства и это все ложится на одни плечи дизайнера. Необходимо подключать союз дизайнеров России, но не на бумаге, чтобы в отчетах это значилось, а конкретные действия: субсидии, гранды, премии, стипендии. Ведь пошив коллекции - это огромный бюджет, а регистрация бренда, ТМ, декларации. И государство должно понимать, что не поддерживая наших дизайнеров, они так и останутся в тени зарубежных брендов. А ведь у нас столько по-настоящему талантливых людей и им просто нужна поддержка и финансирование.","type":"paragraph"},{"html":"<strong>Esque: Назовите основные ошибки при создании бренда.</strong>","type":"paragraph"},{"html":"<strong>Ксения:</strong> В первую очередь, это копирование западных брендов, не умение самовыражаться, страх быть не принятым обществом своей выразительностью и необычностью. Необходимо выходить из зоны комфорта и не бояться признания, ведь дорогу осилит идущий!","type":"paragraph"},{"html":"Индивидуальность можно выразить только тогда, когда есть внутренняя наполняемость своего мира, есть что сказать внешнему миру, выразить свое мнение через одежду.","type":"paragraph"},{"html":"Необходимо освободить себя от стереотипов, не смотреть назад, выражать свое видение. Только так может сформироваться свой фирменный стиль дизайнера. Все зависит от того, чем ты наполнен. Основой служит любовь к своему делу.","type":"paragraph"},{"html":"<strong>Esque: А какие ошибки вы допускали? Анализировали начальный период вашего старта?</strong>","type":"paragraph"},{"html":"<strong>Ксения:</strong> Я допускала прозаичные ошибки дизайнера. Мне не хватало специальных знаний, так как я все делала на интуиции, как чувствовала, это чистый талант, но все же необходимо понимать и знать основные законы композиции и цветоведения. Поэтому в процессе создания каждой коллекции я параллельно учусь и набираюсь опыта, через собственные ошибки. Это трудный путь и не каждому под силу, не сбиться с пути терпения, трудолюбия и вдохновения.","type":"paragraph"},{"html":"<strong>Esque: Сейчас бы если вернуть время назад, повторили тот же самый путь сначала со всеми взлетами и падениями?</strong>","type":"paragraph"},{"html":"<strong>Ксения:</strong> Возможно, я бы поменяла некоторые свои шаги, где был финансовый слив. Но у меня такой путь, он не из легких и если бы он был другим, возможно, все бы было по-другому . Через свои ошибки мы становимся сильнее и умнее. Я научилась принимать свои поражения и победы.","type":"paragraph"},{"html":"<strong>Esque: Ксения, спасибо и напоследок пару напутственных слов начинающим дизайнерам.</strong>","type":"paragraph"},{"html":"<strong>Ксения:</strong> Дизайнер - это в первую очередь зов сердца, этот труд должен приносить удовольствие и от процесса и от результата. Иначе ничего не получится. Поэтому в первую очередь слушайте себя. Это творческая работа, а значит требует и от себя особых условий, таких как: упорство, способность концентрироваться, фантазия и интуиция.","type":"paragraph"},{"html":"Нужно быть разносторонним человеком, потому что эта профессия требует очень большого вовлечения в трудовой процесс. Не бояться, что всё уже придумали и сшили. Это не так. Всегда есть место новому!","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqrz3n006muktahcq3hadg"},{"mediaId":"cmrmqrzic006nuktaq986u6si"},{"mediaId":"cmrmqrzyc006ouktao2q1nvb0"}]}]'::jsonb,'cmrmqry6g006lukta3qqcu0nr','cmrm8ky9t0000kwta6h8ifq47','cmrm8kyog0005kwta01b9favo','cmrmpdrom0000sstarkqxwts4','2023-05-07T06:00:00.000Z'::timestamp,NULL,NULL,NULL,602,'/fashion/interview/602-ksenija-ten-osnovnoj-masse-dizajnerov-ne-hvataet-vdohnovenija-i-podderzhki-so-storony-gosudarstva.html','2026-07-15T20:59:25.423Z'::timestamp,'2026-07-16T13:57:21.513Z'::timestamp,'''cmrmqrz3n006muktahcq3hadg'':870C ''cmrmqrzic006nuktaq986u6si'':872C ''cmrmqrzyc006ouktao2q1nvb0'':874C ''esqu'':67C,160C,214C,289C,353C,380C,510C,615C,698C,771C ''fashion'':45C ''fashion-индустр'':44C ''galleri'':868C ''paragraph'':65C,76C,158C,170C,212C,220C,287C,308C,351C,361C,378C,396C,508C,518C,554C,578C,613C,627C,696C,717C,769C,782C,833C,866C ''аксессуар'':122C ''анализирова'':621C ''арендова'':429C ''атласн'':126C ''больш'':325C,845C '