эксперт'':268C ''эмоциональн'':348C ''эт'':180C,258C,284C,304C,330C,345C,434C,453C,465C,524C,649C,679C,786C,813C,841C,858C ''этап'':55C,63C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqwbws00ofuktawpr0s2th','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Петербургский бренд косметики из экстрактов грибов и трав "Нюктайна" о развитии beauty-рынка в России','Последнее время тема косметики в нашем журнале появляется особенно часто, но первый раз мы так подробно разбираем и рассказываем о натуральной косметике российского производства.','412-peterburgskij-brend-kosmetiki-ih-jekstraktov-gribov-i-trav-njuktajna-o-razvitii-beauty-rynka-v-rossii','[{"html":"Последнее время тема косметики в нашем журнале появляется особенно часто, но первый раз мы так подробно разбираем и рассказываем о натуральной косметике российского производства. Благодаря Анне Баловой, микологу и травнику, а также основателю бренда натуральной косметики «Нюктайна» @nuktayna, на примере ее бренда, мы разобрали все плюсы натурального сырья и как правильно выбрать крем для себя любимой и что не менее важно, почему эту ценную находку для нашей кожи нельзя хранить долго.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Анна, здравствуйте! Расскажите, как на свет появился ваш бренд?","type":"paragraph"},{"html":"<strong>Анна: </strong>Добрый день! Создание косметического бренда «Нюктайна» стало результатом долгих поисков и экспериментов, накопления опыта и знаний, которые мы с моим мужем и единомышленником Юрием собирали в течение многих лет. Знаю, что многие приходят к кремоварению после производства домашнего мыла, сухих букетов или сьедобных домашних заготовок. Но у нас все получилось иначе. Мы оба с детства любим лес, собираем грибы, ягоды и травы. Нам интересно бывать на природе в любой сезон и мы с удовольствием узнаем традиции использования даров природы местными жителями, собираем сведения и пробуем рецепты. Мы побывали во многих регионах России, в частности, несколько месяцев путешествовали по Байкалу. Сначала мы делали различные травяные сборы, чаи, настойки и целебные масла, которыми пользовались сами и раздавали друзьям. Со временем передо мной, как и перед большинством женщин, встала проблема поддержания здоровья и красоты, сохранения молодости кожи и привлекательного внешнего вида. Ведь все мы хотим быть юными и красивыми. И вот тут мне очень помогли накопленные знания, с помощью которых я стала создавать первые косметические средства для себя и своих близких. Я стала совершенствоваться, засела за книги, стала искать современные научные и практические публикации на интересующую тему и плотно занялась практикой. В результате появились гели и крема, которые были оценены не только мной, но и подругами, а после все более и более широким кругом. Тогда и была сформулирована основная миссия нашего косметического бренда, нашедшая отражение и в его названии, а также его основные цели и задачи. Наша основная миссия - поиск эликсира вечной молодости и красоты, а главная задача - создание косметических средств, способствующих сохранению естественной красоты и здоровья кожи с помощью природных средств. Да, да, именно так. И успешное выполнение нашей миссии тесно связано именно с постижением тайн природы, которая уже создала все необходимое, вот только мы не всегда умеем это найти и правильно использовать.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Сейчас очень актуальна российская натуральная косметика и достаточно много компаний появляется на рынке. Какие у вас преимущества перед ними?","type":"paragraph"},{"html":"<strong>Анна: </strong>В первую очередь, косметические средства нашего бренда - это совершенно уникальные составы, не имеющие аналогов. В их основе экстракты грибов и трав, они эффективные и при этом натуральные, сбалансированные и максимально безопасные. Травами, конечно, никого не удивишь, хотя многообразие их видов и свойств позволяет постоянно находить новые интересные решения. А вот экстракты дикорастущих грибов вообще практически не встречаются в рецептурах российской производственной косметики, да и в авторских продуктах их крайне мало. Некоторые же используемые нами компоненты, вроде экстрактов таких грибов как саркосома шаровидная и лангерманния, насколько я знаю, вообще не встретишь ни в российской, ни в зарубежной косметике. Подобные ингредиенты мы сами бережно собираем в дикой природе и обрабатываем вручную. Косметика «Nuktayna» – особенная от природы. Именно в наличии в ее составе редких природных компонентов, собираемых в ограниченном количестве, и заключается уникальность и целебная сила нашей косметики.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Я уже ранее сказала о возросшем спросе на натуральной российскую косметику. Почему все больше наших женщин отдают предпочтение натуральной косметике и, что особенно важно, российской?","type":"paragraph"},{"html":"<strong>Анна: </strong>Думаю, это закономерно. Натуральная косметика имеет многовековую историю и позволяет использовать опыт, накопленный предыдущими поколениями, поэтому обладает кредитом доверия. Кроме того, человечество, видимо, понемногу устает от современных каменных джунглей и стремится к истокам, к природе, естественности. Это отражается и на выборе косметики. И это абсолютно оправдано. Ведь именно природные средства наиболее безопасны для человека и способны обеспечить комплексный и долгосрочный результат, а активные компоненты в составе природных соединений лучше переносятся и усваиваются человеческим организмом, чем синтетические. Известно также, что наиболее положительное влияние на человека оказывают именно природные компоненты, собранные на территориях его проживания. Проще говоря, свои продукты самые полезные. Да и знакомые, понятные, опробованные. Поэтому косметика на основе растений, произрастающих на территории России, созданная с учетом лучших традиций и опыта предков, хорошо подходит нашим, российским женщинам. Радует и то, что качество российской косметики повышается. В настоящее время многие российские косметические средства не уступают иностранным конкурентам, встречаются и абсолютно уникальные.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Какая продукция у вас в ассортименте? И что пользуется наибольшим спросом?","type":"paragraph"},{"html":"<strong>Анна: </strong>В настоящее время это уходовая косметика – в основном разнообразные крема для лица, рук, тела. Самыми востребованными традиционно являются антивозрастные крема и крема с оздоровительным эффектом. Кстати, в нашем ассортименте продукция не только для женщин. Есть и средства для мужчин, например, крем для лица, который хорошо использовать как крем после бритья, для восстановления кожи после мелких повреждений, чувствительной и проблемной кожи.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Планируете расширять ассортимент? Как часто появляются новинки?","type":"paragraph"},{"html":"<strong>Анна:</strong> Да, у нас множество идей и планов. Мы постоянно работаем над новыми рецептурами, изучаем перспективные компоненты, ищем наиболее эффективные их сочетания. При этом потребителям представляются только тщательно проверенные составы. Мы учитываем и поступающие нам отзывы и пожелания, актуальные запросы потребителей, которые могут меняться, например, в зависимости от сезона или даже уровня популярности тех или иных конкретных компонентов. Новинки появляются регулярно, а их право занять постоянное место в ассортименте определяется их успешностью у потребителей. Так как в нашей косметике много компонентов, получаемых из дикорастущих растений и грибов, очень большое значение имеет сезонность. Да и потребности кожи в зависимости от погодных условий меняются. Поэтому и актуальный ассортимент меняется несколько раз в год. Кроме того, мы работаем и над упаковкой нашей продукции, стараясь повысить не только ее эстетическую привлекательность, гигиеничность и удобство, но и экологичность. Что-то новое появляется постоянно.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Очень важный вопрос: Способ хранения и срок годности у натуральной косметики несколько другой, верно?","type":"paragraph"},{"html":"<strong>Анна: </strong>Да, совершенно верно. Мне часто задают подобные вопросы, так как многие не знают, как правильно хранить натуральную косметику, а некоторых смущает небольшой срок годности. Отвечу немного подробнее. Именно потому, что натуральная косметика содержит большое количество высокоактивных «живых» компонентов и минимум консервантов, она не может храниться годами. Срок годности такой косметики обычно не превышает 3-6 месяцев. Хочу обратить внимание, что такой срок годности возможен при хранении ее в холодильнике. При комнатной температуре натуральная косметика хранится 1.5-2 месяца, ее не следует оставлять на открытом солнце или рядом с нагревательными приборами. Поэтому чаще всего подобные косметические средства выпускаются в упаковках небольшого объема. Например, крема для лица «Нюктайна» производятся в основном в упаковках по 20 и 30 мл, максимальный объем 50 мл. Кстати, следует помнить, что хороший результат от использования косметических средств можно получить только при регулярном применении. При соблюдении этого правила баночка крема полностью используется за месяц-полтора, а то и меньше. Так что сроки годности у натуральной косметики вполне достаточные. Главное обстоятельно - подходить к вопросу и не набирать сразу слишком много средств, которые не успеете использовать. Таким образом, наша косметика также подвигает нас всех делать шаги в сторону разумного потребления. Это, мне кажется, можно считать еще одним из ее плюсов.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Анна, какие проблемы помогает решить косметика вашего бренда? И как правильно подобрать крем, который подойдёт именно вашей коже?","type":"paragraph"},{"html":"<strong>Анна: </strong>Мы создаем различные средства и каждое из них выполняет свои конкретные задачи. Но главная задача нашей косметики, конечно, это борьба со старением и негативным влиянием окружающей среды, сохранение молодости и здоровья кожи, обеспечение поддержания ее лучших кондиций естественным путем. При выборе крема нужно по возможности точно определить для себя особенности вашей кожи и тот результат, который вы хотели бы получить от использования крема в настоящее время. Потребности кожи у человека могут меняться и важно определить, что именно требуется ей в данный конкретный момент. Необходимо решить, какие задачи для Вас сейчас самые главные, например, интенсивное питание или борьба с излишней пигментацией. Как правило, основные свойства и особенности использования крема указываются производителями на упаковке, что позволяет определить, насколько данный продукт отвечает Вашим целям и задачам. Отсутствие особых указаний обычно означает, что крем имеет универсальное назначение и должен подходить для любого типа кожи. Говорить о том, как правильно выбрать крем для лица, можно долго. Но самый точный ответ тут будет такой: попробовать. Потому что учесть все личные особенности довольно трудно и на 100% определить заранее результат использования крема конкретным человеком невозможно.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Вы пользуетесь своей косметикой? Что именно Вы, как потребитель, можете отметить в своем бренде?","type":"paragraph"},{"html":"<strong>Анна: </strong>Конечно, постоянно пользуюсь. И лично для меня особенно важно, что вся продукция «Нюктайна» имеет максимально эффективные, но безопасные составы и подходит даже людям, склонным к аллергии. Мы стараемся не использовать компоненты с повышенным риском аллергических реакций. При этом наши средства богаты высокоэффективными ингредиентами, показывающими заметные результаты. Безусловно, полностью исключить возможность индивидуальной непереносимости каких-либо компонентов конкретным человеком мы не можем, однако делаем все, чтобы свести этот риск к минимуму. Так как я человек подверженный аллергии и мне подходит далеко не всякая косметика, этот фактор имеет для меня важное значение.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: </strong>Огромное спасибо за столько развернутое интервью. Дайте напоследок пару советов нашим читательницам.","type":"paragraph"},{"html":"<strong>Анна:</strong> Это скорее пожелания, чем советы. Желаю всем девушкам и женщинам находить побольше времени для сна и отдыха, беречь свое здоровье, чаще улыбаться и стараться в любой ситуации сохранять позитивный настрой. Ведь даже самой эффективной косметике трудно обеспечить красоту и свежесть кожи, когда организм переутомлен или болен, негативное влияние на кожу оказывают стресс и слишком большие нагрузки. А вот положительные эмоции, напротив, помогают активизировать в коже естественные восстановительные процессы, улучшить ее качество и внешний вид. Будьте счастливы и красивы!","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqwbhn00oduktanals6coj"},{"mediaId":"cmrmqwbue00oeuktabm295no4"}]}]'::jsonb,'cmrmqwb3k00ocuktatdloiqve','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyz0000akwtaq6w9733r','cmrmpdrom0000sstarkqxwts4','2022-03-23T06:00:00.000Z'::timestamp,NULL,NULL,NULL,412,'/beauty/mnenie/412-peterburgskij-brend-kosmetiki-ih-jekstraktov-gribov-i-trav-njuktajna-o-razvitii-beauty-rynka-v-rossii.html','2026-07-15T21:02:47.500Z'::timestamp,'2026-07-16T13:59:37.157Z'::timestamp,'''-2'':1094C ''-6'':1072C ''1.5'':1093C ''100'':1414C ''20'':1130C ''3'':1071C ''30'':1132C ''50'':1136C ''beauti'':13A ''beauty-рынк'':12A ''cmrmqwbhn00oduktanals6coj'':1638C ''cmrmqwbue00oeuktabm295no4'':1640C ''esqu'':115C,423C,585C,767C,846C,999C,1222C,1426C,1538C ''galleri'':1636C ''nuktayna'':78C,557C ''paragraph'':113C,126C,421C,444C,583C,612C,765C,780C,844C,855C,997C,1015C,1220C,1242C,1424C,1442C,1536C,1552C,1634C ''абсолютн'':659C,762C ''авторск'':512C ''активизирова'':1617C ''активн'':