INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqztth00xauktai085rsr3','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'«Природа женственности» глазами Светланы Селиверстовой','Ярким акцентом в культурной жизни столицы стало открытие нового таланта, фотохудожника Светланы Селиверстовой, которая представила публике свою дебютную выставку «Природа женственности».','330-priroda-zhenstvennosti-glazami-svetlany-seliverstovoj','[{"html":"Ярким акцентом в культурной жизни столицы стало открытие нового таланта, фотохудожника Светланы Селиверстовой, которая представила публике свою дебютную выставку <i>«Природа женственности»</i>. Искусство многогранно, разные его ветви пересекаются, рождая что-то новое и удивительное. Примером такой гармонии служат работы Светланы, в которых перекликаются грация танца, красота природы и искусство фотографии.<br /><br /> <br />Событие состоялось в богемной атмосфере ресторана «Премьер» в отеле Ренессанс Монарх 5* и собрало более 200 ценителей прекрасного, среди которых были отмечены: деятель культуры, топ-менеджер промышленного холдинга и поэтесса Динара Камалеева, общественный деятель, эксперт в области благотворительности, журналист и продюсер Мила Соловьева, дизайнер Наира Арутинян, актер, ведущий и продюсер канала «Отцыфровка» Николай Цонку, актриса и певица Антонина Клименко.<br />Настроение вечера создавали и поддерживали организаторы Виктория Мирошниченко и Лариса Шапиева, а так же ведущий и комментатор телеканала Матч ТВ, поэт и актер театра Tabula Rasa Никита Войнов, Dj Beatmaster (Артем Комогоров), музыкальный дуэт Desert Rose в лице виолончелистки Дарьи Сулиной и скрипачки Любови Морской, рэп-исполнитель Njohn, певицы I-ma и Анастасия Неонова, поэтесса Любава Трофимова, певец Максим Заяц, флорист Людмила Храпова, мастерская съедобной флористики Buket by Daria.<br /><br />","type":"paragraph"},{"html":"<br />Каждый гость стал участником беспроигрышной лотереи от партнеров события: косметического бренда Levrana, студии художественной татуировки Ermaktattoo, косметолога Виктории Цатуровой, топ-парикмахера-стилиста Игоря Попова, салона элитной бижутерии Эдера, дизайнера украшений ручной работы Анны Скороходовой, компании Эврос и гастрономического бренда La Gente.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqzpqm00x2uktakrgmw9yo"},{"mediaId":"cmrmqzq9f00x3uktake9p2hb4"},{"mediaId":"cmrmqzqpi00x4ukta5a08uvm7"},{"mediaId":"cmrmqzrc900x5uktanfde866o"},{"mediaId":"cmrmqzs2b00x6uktaa7zeuwjb"},{"mediaId":"cmrmqzsni00x7uktaxfz5kvob"},{"mediaId":"cmrmqzt5y00x8uktabcql3b2x"},{"mediaId":"cmrmqztoj00x9uktae6ynligv"}]}]'::jsonb,'cmrmqzp9u00x1uktajx1etb5x','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz8q000ekwtadrt5g1dn','cmrmpdrom0000sstarkqxwts4','2021-04-26T06:00:00.000Z'::timestamp,NULL,NULL,NULL,330,'/sobytija/iskusstvo/330-priroda-zhenstvennosti-glazami-svetlany-seliverstovoj.html','2026-07-15T21:05:30.677Z'::timestamp,'2026-07-16T14:00:49.417Z'::timestamp,'''200'':92C ''5'':88C ''beatmast'':166C ''buket'':205C ''cmrmqzpqm00x2uktakrgmw9yo'':258C ''cmrmqzq9f00x3uktake9p2hb4'':260C ''cmrmqzqpi00x4ukta5a08uvm7'':262C ''cmrmqzrc900x5uktanfde866o'':264C ''cmrmqzs2b00x6uktaa7zeuwjb'':266C ''cmrmqzsni00x7uktaxfz5kvob'':268C ''cmrmqzt5y00x8uktabcql3b2x'':270C ''cmrmqztoj00x9uktae6ynligv'':272C ''daria'':207C ''desert'':171C ''dj'':165C ''ermaktattoo'':226C ''galleri'':256C ''gent'':252C ''i-ma'':187C ''la'':251C ''levrana'':222C ''ma'':189C ''njohn'':185C ''paragraph'':209C,254C ''rasa'':162C ''rose'':172C ''tabula'':161C ''актер'':124C,159C ''актрис'':132C ''акцент'':7B,28C ''ан'':244C ''анастас'':191C ''антонин'':135C ''арт'':167C ''арутиня'':123C ''атмосфер'':81C ''беспроигрышн'':215C ''бижутер'':238C ''благотворительн'':115C ''богемн'':80C ''бренд'':221C,250C ''ведущ'':125C,151C ''ветв'':52C ''ве