INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqvc2j00kiukta23dx8u1a','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Олифиренко Анна: "Спорт занимает у меня 1 место в жизни"','Олифиренко Анна учится в 8 классе и живет на Сахалине.','456-olifirenko-anna-sport-zanimaet-u-menja-1-mesto-v-zhizni','[{"html":"<strong>Олифиренко Анна учится в 8 классе и живет на Сахалине. Несмотря на то, что на острове не так много дизайнеров, нашей героине это не мешает. Путешествия, показы и подиумы в разных городах России – родители могут гордиться, а сверстницы немного завидовать. </strong>","type":"paragraph"},{"html":"<strong>ESQUE</strong><strong>:</strong> Аня, здравствуй. Как закончила школу?<br /><strong>Анна:</strong> Здравствуйте. Школу закончила хорошо. Я перешла в 8 класс.<br /><br /><strong>ESQUE</strong><strong>:</strong> Молодец, поздравляем тебя. Какие планы на лето?<br /><strong>Анна:</strong> Я лечу в Таиланд с моей семьёй на 2 месяца.<br /><br /><strong>ESQUE</strong><strong>:</strong> Ты достаточно долго время занималась спортивной гимнастикой, а потом акробатикой. Чем они отличаются друг от друга?<br /><strong>Анна:</strong> Отличие спортивной гимнастики от акробатики заключается в том что, гимнастика представляет собой комплекс упражнений на силу и ловкость, которые по большей части выполняются на спортивных снарядах. Акробатика – это подраздел гимнастики, в котором делается большой акцент именно на ловкость и умение балансировать.<br /><br /><strong>ESQUE</strong><strong>:</strong> Какое место в твоей жизни занимает спорт? И каким его видом ты занимаешься сейчас?<br /><strong>Анна:</strong> Спорт занимает у меня 1 место в жизни. Он научил меня быть ловкой, выносливой, достигать больших наград и ставить новые цели. На данный момент, я занимаюсь тхэквондо и мне очень нравится этот вид спорта.<br /><br /><strong> ESQUE</strong><strong>:</strong> Аня, расскажи о моделинге. Как ты стала моделью?<br /><strong>Анна: </strong>Однажды мама записала меня на пробную фотосъёмку. Мне очень понравилась эта атмосфера и я начала ходить на занятия. Мне всегда интересно принимать участие в съёмках и показах. Каждый раз, когда я прихожу на занятия, я узнаю для себя что-то новое. Мне очень нравится работать на камеру и показывать разные эмоции.<br /><br /><strong>ESQUE</strong><strong>:</strong> На Сахалине, где ты живешь, очень мало дизайнеров, но ты часто путешествуешь по России. С какими дизайнерами удалось поработать?<br /><strong>Анна: </strong>Мне удалось поработать с Юлией Лимоновой и Ольгой Че из Иркутска, а также с Герой Скандал из Москвы. <br /><br /><strong>ESQUE</strong><strong>:</strong> Помнишь свой первый показ?<br /><strong>Анна: </strong>Конечно. Мой первый показ был в Питере, он назывался: “Kids Fashion Fest 2022”. Как раз там мне и удалось поработать с Герой Скандал. Это был мой самый запоминающейся показ.<br /><br /><strong>ESQUE</strong><strong>:</strong> Спорт или мода – что интереснее?<br /><strong>Анна: </strong>Конечно же, мода намного интереснее спорта. <br /><br /><strong>ESQUE</strong><strong>:</strong> Аня, ты изучаешь языки. И один из них корейский. Это большая редкость. Почему именно корейский?<br /><strong>Анна: </strong>Не знаю почему, но мне понравился этот язык. Мне интересна корейская культура и после окончании школы, я бы хотела полететь туда учиться.<br /><br /><strong>ESQUE</strong><strong>:</strong> Спасибо за интересную беседу. Пару слов нашим читателям напоследок.<br /><strong>Анна: </strong>Никогда не бойтесь начинать что-то новое. Верьте в себя и достигайте новых целей.","type":"paragraph"},{"type":"image","mediaId":"cmrmqvc1800khuktaw1zi4i2r"}]'::jsonb,'cmrmqvb9x00kguktaigxf191y','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-06-12T06:00:00.000Z'::timestamp,NULL,NULL,NULL,456,'/esquekids/moda-ek/456-olifirenko-anna-sport-zanimaet-u-menja-1-mesto-v-zhizni.html','2026-07-15T21:02:01.051Z'::timestamp,'2026-07-16T13:59:10.950Z'::timestamp,'''1'':7A,178C ''2'':97C ''2022'':327C ''8'':15B,25C,78C ''cmrmqvc1800khuktaw1zi4i2r'':427C ''esqu'':64C,80C,99C,158C,208C,270C,309C,344C,357C,396C ''fashion'':325C ''fest'':326C ''imag'':425C ''kid'':324C ''paragraph'':62C,423C ''акробатик'':109C,121C,143C ''акцент'':151C ''ан'':2A,12B,22C,65C,70C,88C,116C,173C,209C,217C,290C,314C,350C,358C,373C,406C ''атмосфер'':229C ''балансирова'':157C ''бесед'':400C ''бойт'':409C ''больш'':137C,150C,189C,368C ''верьт'':415C ''вид'':169C,206C ''врем'':103C ''вынослив'':187C ''выполня'':139C ''гер'':305C,336C ''героин'':42C ''гимнастик'':106C,119C,126C,146C ''горд'':56C ''город'':52C ''дан'':196C ''дела'':149C ''дизайнер'':40C,278C,287C ''долг'':102C ''достаточн'':101C ''достига'':188C,419C ''друг'':113C,115C ''живет'':18B,28C ''живеш'':275C ''жизн'':10A,163C,181C ''завидова'':60C ''заключа'':122C ''законч'':68C,73C ''занима'':4A,104C,164C,171C,175C,199C ''занят'':235C,251C ''записа'':220C ''запомина'':342C ''здравств'':66C,71C ''зна'':375C ''изуча'':360C ''имен'':152C,371C ''интересн'':238C,349C,355C,383C,399C ''иркутск'':301C ''кажд'':245C ''как'':84C,159C,167C,286C ''камер'':265C ''класс'':16B,26C,79C ''комплекс'':129C ''корейск'':366C,372C,384C ''котор'':135C,148C ''культур'':385C ''лет'':87C ''леч'':90C ''лимонов'':296C ''ловк'':186C ''ловкост'':134C,154C ''мал'':277C ''мам'':219C ''мест'':8A,160C,179C ''месяц'':98C ''меша'':45C ''мо'':94C ''могут'':55C ''мод'':347C,353C ''модел'':216C ''моделинг'':212C ''молодец'':81C ''момент'':197C ''москв'':308C ''наград'':190C ''называ'':323C ''намн'':354C ''напоследок'':405C ''науч'':183C ''нача'':232C ''начина'':410C ''наш'':41C,403C ''немн'':59C ''несмотр'':31C ''нов'':193C,259C,414C,420C ''нрав'':204C,262C ''однажд'':218C ''окончан'':388C ''олифиренк'':1A,11B,21C ''ольг'':298C ''остров'':36C ''отлич'':117C ''отлича'':112C ''очен'':203C,226C,261C,276C ''пар'':401C ''перв'':312C,317C ''перешл'':76C ''питер'':321C ''план'':85C ''подиум'':49C ''подраздел'':145C ''поздравля'':82C ''показ'':47C,244C,313C,318C,343C ''показыва'':267C ''полетет'':393C ''помн'':310C ''понрав'':227C,379C ''поработа'':289C,293C,334C ''поч'':370C,376C ''представля'':127C ''принима'':239C ''прихож'':249C ''пробн'':223C ''путешеств'':46C ''путешествуеш'':282C ''работа'':263C ''разн'':51C,268C ''расскаж'':210C ''редкост'':369C ''родител'':54C ''росс'':53C,284C ''сам'':341C ''сахалин'':20B,30C,272C ''сверстниц'':58C ''сво'':311C ''сем'':95C ''сил'':132C ''сканда'':306C,337C ''слов'':402C ''снаряд'':142C ''соб'':128C ''спасиб'':397C ''спорт'':3A,165C,174C,207C,345C,356C ''спортивн'':105C,118C,141C ''став'':192C ''стал'':215C ''съемк'':242C ''таиланд'':92C ''такж'':303C ''тво'':162C ''туд'':394C ''тхэквонд'':200C ''уда'':288C,292C,333C ''узна'':253C ''умен'':156C ''упражнен'':130C ''уч'':13B,23C,395C ''участ'':240C ''фотосъемк'':224C ''ход'':233C ''хотел'':392C ''цел'':194C,421C ''част'':138C,281C ''че'':299C ''читател'':404C ''что-т'':256C,411C ''школ'':69C,72C,389C ''эмоц'':269C ''эт'':43C,144C,228C,338C,367C ''юл'':295C ''язык'':361C,381C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqu75700g4uktadb6u6p9z','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Медитация от А до Я. Разбираются эксперты','Мы живем в очень неспокойное время, волны болезней, кризисов и войн накрывают человечество беспрерывно.','501-meditacija-ot-a-do-ja-zabluzhdenie-ili-volshebstvo','[{"html":"Мы живем в очень неспокойное время, волны болезней, кризисов и войн накрывают человечество беспрерывно. Как удержаться на плаву в океане всех жизненных перипетий? Этот вопрос, думаю, задает себе практически каждый житель нашей планеты и ищет разные методы помочь себе. Кто-то ищет успокоение в вине, хорошей компании, кто-то находит себе любимое занятие, хобби и это дает жизненный ресурс, кто-то занимается спортом, выбрасывая негативные эмоции через физическую нагрузку, кто-то идет в храм и обретает Бога на Земле. Все эти способы хорошо нам знакомы. В последнее время приобрел популярность еще один метод восстановления жизненных сил – это медитация. В марафонах и прямых эфирах в Инстаграм обучают правильной технике, видео и звукозаписями для самостоятельной медитации пестрит всё интернет-пространство. Гуру этой практики организовывают совместные медитации офлайн и онлайн, рассказывают о сплошной пользе для организма на всех уровнях – физическом, психическом, психологическом, вплоть до того, что медитация творит чудеса и способна вылечить самые тяжелые болезни. Так ли это на самом деле?","type":"paragraph"},{"html":"Для начала попробуем разобраться в самом механизме этого процесса на физиологическом уровне. Заведующая лабораторией нейрофизиологии Института физиологии Светлана Пашкевич определяет медитацию как состояние, которое характеризуется изменением мозговых волн. Это торможение нервных процессов, включение парасимпатической нервной системы. С точки зрения науки во время медитации в мозге происходят определенные процессы. Главный эффект медитации, который фиксирует множество исследований, переключение мозга из системы бей-беги в систему релакса.","type":"paragraph"},{"html":"“Медитация- это способ для мозга переключиться на другой ритм мозговой активности,","type":"paragraph"},{"html":"позволяющий организму отдыхать, устанавливать эмоциональные связи, слушать интуицию, улучшать свое воображение, креативность, слушать свое тело, ощущать внутренний баланс и быть в гармонии с миром. Нейроны – нервные клетки мозга образуют серое вещество. Миллионы нейронов производят электрические разряды. Эти разряды создают ритм, который получил название «мозговая волна». Электроэнцефалограмма фиксирует изменения ритмов волн мозговой активности. В зависимости от их частот они делятся на Бета, Альфа, Тета и Дельта. Эти частоты определяют настроение и состояние организма. Бета волны - самые быстрые. Это состояние бодрствования, внимания и концентрации. Альфа-волны - характерны для расслабленного состояния. Это состояние покоя для мозга, невозбудимости, медитации, гипноза. Тета-волны увеличивают творческий потенциал, образное мышление, воспоминания, встречаются в мечтательном состоянии, в состоянии сновидений. Дельта волны - самые медленные. Обычно, люди спят во время дельта волн, однако есть доказательство, что возможно остаться в со6знании и в этом состоянии —чрезвычайно глубокого, подобного трансу. Чаще всего они встречаются у маленьких детей. Чем мы старше, тем меньше дельта волн производится организмом, даже во время глубокого сна”- так характеризует процессы, происходящие в нашем организме психолог, психотерапевт Виктория Ивченко.","type":"paragraph"},{"html":"Переизбыток или недостаток ритма любой из волн влечет за собой сбой в работе нашего мозга и как итог проявляется в виде беспокойства, тревоги, бессоннице, гиперактивности, невнимательности; стресс, депрессия.","type":"paragraph"},{"html":"“В большинстве случаев медитация- это лучший способ, чтобы перейти из состояния активной","type":"paragraph"},{"html":"мыслительной деятельности к состоянию большей расслабленности, восприимчивости, осознанности и внутреннего баланса”, - резюмирует Виктория.","type":"paragraph"},{"html":"Именно поэтому психологи часто используют в своей практики именно медитацию.","type":"paragraph"},{"html":"Психолог, гештальт-консультант Алёна Капуста применяет медитативные техники в работе с различными психоэмоциональными состояниями.","type":"paragraph"},{"html":"<u><i>“Хоть мы и не выбираем, с каким мозгом нам родиться, и не можем контролировать все, что с нами происходит, мы в состоянии использовать свой мозг, чтобы отремонтировать его, поэтому медитация имеет исцеляющее воздействие на наш мозг, а значит и в целом на наше состояние”. </i></u>","type":"paragraph"},{"html":"Кроме того Алена сама медитирует.","type":"paragraph"},{"html":"<i><u>«В моей жизни было достаточно стрессовых ситуаций, развод, переезд на ПМЖ в другой город с детьми, в голове начиналась мыслемешалка, которую порой невозможно было остановить, тогда я начала слушать медитации, уже через несколько дней я заметила, что становится спокойнее, нет тревожных и беспокойных мыслей, а когда появлялись я начинала медитировать. Именно медитации помогли мне быстрее восстановиться, и по сегодняшний день я использую этот инструмент для расслабления и снятия тревоги, беспокойства, стресса любого происхождения».</u></i>","type":"paragraph"},{"html":"Психолог, арт-терапевт Галина Швец рассказывает, как медитация помогает детям справиться со своими страхами, тревогами и путем практики найти выход из проблемной ситуации. Кроме того, этот метод способствует развитию внимательности, самоконтролю и учит осознанности.","type":"paragraph"},{"html":"Однако, в практики Галины встречались случаи, когда клиенты говорят о бесполезности медитации: человеку не становится лучше, не уходят симптомы тревоги, страхов и т.п. Но чаще, причина тому не сама практика медитации, а сложности (которые возникают при выполнении практики) в умении сосредоточиться и отогнать от себя беспокоящие мысли.","type":"paragraph"},{"html":"<u>“Но ведь медитация – это практика работы ума и тела, которая тренирует осознанность и человек учиться концентрироваться на своем теле и своих мыслях. Многие обесценивают медитацию, считая, что помочь такое обычное упражнение вряд ли сможет\".</u> Но Галина убеждена, что медитация - хоть и простой, но действенный способ улучшить качество жизни.","type":"paragraph"},{"html":"Правда, быстро улучшить жизнь вряд ли получиться.","type":"paragraph"},{"html":"\"Для достижения хорошего результата чаще всего нужна практика, даже в медитации. Мы можем думать, что тратим время, не получая расслабления или другого желаемого результата. Как в любом деле, так и в медитации нужно приложить определенные усилия, очень важна работа над собой.\" Делится своим профессиональным мнением детский психолог, лечебный педагог Лия Иванова.","type":"paragraph"},{"html":"Да, действительно, медитация может послужить хорошим инструментом справиться со многими психоэмоциональными состояниями и этому свидетельствует, и наука, и опыт специалистов-психологов. Получается, правда, сплошная польза или все же есть противопоказания, как у любого лекарства? Этот вопрос задали экспертам. <i>“У некоторых людей мозг и так большую часть времени находится в состояние рассредоточенности, чрезмерной расслабленности, то в этом случае бывает более полезно \"проснуться\" и дать организму почувствовать физическую и умственную нагрузку”</i>- отвечает психолог, психотерапевт Виктория Ивченко.","type":"paragraph"},{"html":"“Гормон серотонин обычно приносит состояние счастья, характерное для некоторых трансовых состояний и медитации, но если человек принимает дополнительные лекарства его содержащие, то переизбыток этого гормона может вызвать сильную тревогу. Медитации и гипноз не проводятся или проводятся с большой осторожностью и только опытными специалистами с людьми, страдающими психическими заболеваниями, так как могут вызвать их обострение» - обращает внимание специалист.","type":"paragraph"},{"html":"Популярность медитации с одной стороны оправдана, но, имея влияние на процессы происходящие в нашем мозге - эта техника способна, как излечить, так и навредить.","type":"paragraph"},{"html":"Медитация привлекает многих простотой в выполнении и доступностью, но, требует серьёзного подхода и осторожности.","type":"paragraph"},{"html":"Вера Бубнова","type":"paragraph"}]'::jsonb,'cmrmqu72a00g3ukta6qag1rcy','cmrm8kzpw000mkwtaocyn5161','cmrm8kzra000okwtaqek3edwq','cmrmpdrom0000sstarkqxwts4','2022-08-17T06:00:00.000Z'::timestamp,NULL,NULL,NULL,501,'/psihologija/samosovershenstvovanie/501-meditacija-ot-a-do-ja-zabluzhdenie-ili-volshebstvo.html','2026-07-15T21:01:08.011Z'::timestamp,'2026-07-16T13:58:36.037Z'::timestamp,'''paragraph'':186C,254C,268C,443C,474C,489C,505C,518C,536C,583C,591C,667C,705C,756C,807C,817C,871C,949C,1009C,1035C,1052C,1057C ''активн'':266C,321C,487C ''ал'':524C,587C ''альф'':331C,353C ''альфа-волн'':352C ''арт'':671C ''арт-терапевт'':670C ''баланс'':287C,501C ''бе'':248C ''бег'':249C ''бей-бег'':247C ''беспокойн'':635C ''беспокойств'':466C,662C ''беспокоя'':753C ''бесполезн'':717C ''беспрерывн'':21B,35C ''бессонниц'':468C ''бет'':330C,342C ''бог'':102C ''бодрствован'':348C ''болезн'':15B,29C,178C ''больш'':495C,918C,988C ''большинств'':477C ''бубнов'':1055C ''быва'':931C ''быстр'':345C,647C,810C ''важн'':856C ''вер'':1054C ''веществ'':300C ''вид'':465C ''виде'':134C ''виктор'':440C,503C,946C ''вин'':67C ''включен'':220C ''влечет'':452C ''влиян'':1019C ''вниман'':349C,1006C ''внимательн'':699C ''внутрен'':286C,500C ''воздейств'':570C ''возможн'':398C ''возника'':742C ''войн'':18B,32C ''волн'':14B,28C,215C,314C,319C,343C,354C,369C,384C,393C,423C,451C ''воображен'':280C ''вопрос'':46C,909C ''воспоминан'':375C ''восприимчив'':497C ''восстанов'':648C ''восстановлен'':119C ''вплот'':166C ''врем'':13B,27C,113