INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqemsx0037pota1a4l7kul','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'В сизо за искусство. Беркович и Петрийчук приговорили к 6 годам колонии','Вчера в военном суде к 6 годам колонии приговорили режиссера Евгению Беркович и драматурга Светлану Петрийчук по делу «об оправдании терроризма» в спектакле «Финист Ясный Сокол».','664-v-sizo-za-iskusstvo-berkovich-i-petrijchuk-prigovorili-k-6-godam-kolonii','[{"html":"Вчера в военном суде к 6 годам колонии приговорили режиссера Евгению Беркович и драматурга Светлану Петрийчук по делу «об оправдании терроризма» в спектакле «Финист Ясный Сокол». Произведение рассказывало о судьбе женщин, попадающих под влияние радикального ислама. Спектакль был поставлен Беркович в 2020 году в Москве по пьесе Петрийчук.","type":"paragraph"},{"html":"Женщины находились под стражей с 4 мая 2023-го. После отбытия срока им также запретили на три года администрировать интернет-страницы. Обе внесены в российский перечень террористов и экстремистов.","type":"paragraph"},{"html":"«Эти девушки абсолютно невиновны. Конечно, у нас нет выхода, и мы будем обжаловать [приговор]. Но я считаю, что те люди, которые причастны к этому решению, они будут с этим жить. И возможно, когда-нибудь справедливость восторжествует», - заявила у здания суда адвокат женщин Ксения Карпинская.","type":"paragraph"},{"html":"Решение вынес судья Юрий Массин. Приговор проходил в закрытом режиме с присутствием десятка СМИ. Услышав приговор, Светлана Петрийчук расплакалась, а Беркович была невозмутима и на вопрос понятен ли приговор, бодро ответила: «О, да».","type":"paragraph"},{"html":"На улице, уезжающий автозак с заключенными, провожали воскриками «Женя и Света».","type":"paragraph"},{"html":"«Ужасный приговор.. У меня просто нет слов. Дать срок, да еще и по такой тяжелой статье людям, которые этот самый терроризм своей постановкой вообще-то изобличают, а не оправдывают — это позор для нашего правосудия», — дала свой комментарий Ксения Собчак.","type":"paragraph"}]'::jsonb,'cmrmqemrk0036potaeo4scczs','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-07-09T06:00:00.000Z'::timestamp,NULL,NULL,NULL,664,'/v-mire/664-v-sizo-za-iskusstvo-berkovich-i-petrijchuk-prigovorili-k-6-godam-kolonii.html','2026-07-15T20:49:01.809Z'::timestamp,'2026-07-16T13:56:41.613Z'::timestamp,'''..'':223C ''2020'':80C ''2023'':97C ''4'':95C ''6'':10A,18B,44C ''paragraph'':88C,121C,169C,205C,219C,263C ''абсолютн'':125C ''автозак'':210C ''адвокат'':164C ''администрирова'':108C ''беркович'':5A,24B,50C,78C,191C ''бодр'':200C ''буд'':134C ''будут'':149C ''влиян'':72C ''внес'':113C ''воен'':15B,41C ''возможн'':154C ''вообщ'':246C ''вообще-т'':245C ''вопрос'':196C ''воскрик'':214C ''восторжеств'':159C ''вчер'':13B,39C ''вынес'':172C ''выход'':131C ''го'':98C ''год'':11A,19B,45C,81C,107C ''дал'':257C ''дат'':229C ''девушк'':124C ''дел'':30B,56C ''десятк'':183C ''драматург'':26B,52C ''евген'':23B,49C ''жен'':215C ''женщин'':69C,90C,165C ''жит'':152C ''заключен'':212C ''закрыт'':179C ''запрет'':104C ''заяв'':160C ''здан'':162C ''изоблича'':248C ''интернет'':110C ''интернет-страниц'':109C ''искусств'':4A ''ислам'':74C ''карпинск'':167C ''когда-нибуд'':155C ''колон'':12A,20B,46C ''комментар'':259C ''котор'':143C,239C ''ксен'':166C,260C ''люд'':142C,238C ''ма'':96C ''массин'':175C ''москв'':83C ''наход'':91C ''наш'':255C ''невиновн'':126C ''невозмутим'':193C ''об'':112C ''обжалова'':135C ''оправдан'':32B,58C ''оправдыва'':251C ''отбыт'':100C ''ответ'':201C ''перечен'':116C ''петрийчук'':7A,28B,54C,86C,188C ''позор'':253C ''понят'':197C ''попада'':70C ''поставл'':77C ''постановк'':244C ''правосуд'':256C ''приговор'':8A,21B,47C,136C,176C,186C,199C,222C ''присутств'':182C ''причастн'':144C ''провожа'':213C ''произведен'':65C ''прост'':226C ''проход'':177C ''пьес'':85C ''радикальн'':73C ''расплака'':189C ''рассказыва'':66C ''режим'':180C ''режиссер'':22B,48C ''решен'':147C,171C ''российск'':115C ''сам'':241C ''свет'':217C ''светла'':187C ''светлан'':27B,53C ''сво'':243C,258C ''сиз'':2A ''слов'':228C ''сми'':184C ''собчак'':261C ''сокол'':38B,64C ''спектакл'':35B,61C,75C ''справедлив'':158C ''срок'':101C,230C ''стат'':237C ''страж'':93C ''страниц'':111C ''суд'':16B,42C,163C,173C ''судьб'':68C ''счита'':139C ''такж'':103C ''те'':141C ''терроризм'':33B,59C,242C ''террорист'':117C ''тяжел'':236C ''уезжа'':209C ''ужасн'':221C ''улиц'':208C ''услыша'':185C ''финист'':36B,62C ''экстремист'':119C ''эт'':146C,151C,252C ''юр'':174C ''ясн'':37B,63C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqxm2l00r7uktat9bkh4lv','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Александра Марчук о кастомизации и ее развитии в России','Тренд на кастомизацию, так популярную уже несколько лет во всем мире, не новость, а возвращение модной тенденции 1970-х годов, когда в Нью-Йорке молодёжь переделывала джинсовые куртки под себя.','389-marchuk-bitva-vladivistok','[{"html":"<u>Тренд на кастомизацию, так популярную уже несколько лет во всем мире, не новость, а возвращение модной тенденции 1970-х годов, когда в Нью-Йорке молодёжь переделывала джинсовые куртки под себя. С тех пор стремление к уникальности в обществе только возросло, а тенденция на преображение той или иной вещи под конкретного человека приобрела глобальные масштабы. Победитель регионального этапа конкурса Fashion битва во Владивостоке и основательница бренда «CUST» Александра Марчук рассказала подробнее об этом направлении в дизайне и поделилась впечатлениями о конкурсе.</u>","type":"paragraph"},{"html":"<i><b>Esque:</b></i> Александра, здравствуйте. Как вы нашли себя в дизайне?","type":"paragraph"},{"html":"<u><i>Александра:</i></u> Здравствуйте. Гуляя по городу и путешествуя по миру, я стала замечать, насколько однообразно мы все выглядим. Не смотря на тонны разнообразной одежды, продающейся в масс-маркетах, в нас отсутствует какая-то уникальность, скрытая изюминка. Еще с детства постоянно выбирала интересную и необычную одежду, шила сама, рисовала принты. Я хотела выглядеть не так, как все. Мне всегда была близка тема кастомизации. Кстати, в западных странах она получила свою популярность довольно давно. Благодаря этому направлению в дизайне я создаю не просто одежду, а вещи, которые несут в себе смысл и привлекают внимание. Их хочется разглядывать.","type":"paragraph"},{"html":"<i><b>Esque:</b></i> А у вас есть дизайнерское образование?","type":"paragraph"},{"html":"<u><i>Александра:</i></u> К сожалению, нет. Только художественная школа и различные курсы по шитью и росписи одежды. После окончания школы мне очень хотелось получить специальность, напрямую связанную с дизайном, но на ее обучении не было бюджетных мест. Обременять родителей оплатой моего образования я просто не могла, поэтому ушла в сферу физики и математики. Со временем поняла, что не представляю свою жизнь без творчества. Во время первого декрета вновь вернулась в дизайн.","type":"paragraph"},{"html":"<i><b>Esque:</b></i> Вспомните тот день, когда вам пришла идея создать свой бренд одежды.","type":"paragraph"},{"html":"<u><i>Александра:</i></u> Стать частью fashion-индустрии было моей мечтой. Благодаря инстаграм я наткнулась на онлайн-курсы по созданию бренда и решила попробовать. Сначала я создавала костюмы из футера, пользующиеся большим спросом у моих клиентов. Позже стала делать из них эксклюзивные модели с ручным окрашиванием тай-дай, кастомизированные надписями и рисунками.","type":"paragraph"},{"html":"<i><b>Esque:</b></i> С какой целью вы решили поучаствовать в конкурсе Fashion битва?","type":"paragraph"},{"html":"<u><i>Александра:</i></u> Для меня это был прекрасный шанс заявить о себе и рассказать о кастомизации. Мне предложили принять участие, и я просто не смогла не согласиться, потому что даже атмосфера закулисья показов мод доставляет мне невероятное удовольствие, вдохновляет и наполняет.","type":"paragraph"},{"html":"<i><b>Esque:</b></i> Как проходила подготовка коллекций для показа? Откуда брали вдохновение для их создания?","type":"paragraph"},{"html":"<u><i>Александра:</i></u> На подготовку коллекций у меня было всего две недели, так как о конкурсе я узнала в последний момент. Учитывая мою загруженность заказами и то, что я мама двоих детей, которым необходимо уделять внимание, казалось нереальным что-то придумать. Благодаря поддержке мужа и родных, я смогла взять себя в руки. Пришлось работать днем и ночью. Радует, что мои старания не прошли зря! На создание подростковой кастомной коллекции меня вдохновили интересные и креативные молодые люди, не боящиеся раскрыть свою индивидуальность и показать себя миру, не смотря на юный возраст.","type":"paragraph"},{"html":"<i><b>Esque:</b></i> Что вы почувствовали, когда члены жюри обьявили вас победителем Fashion битвы?","type":"paragraph"},{"html":"<u><i>Александра:</i></u> Я испытала легкий шок. По моему телу побежали мурашки. Не могла поверить, что члены жюри назвали мое имя! На смену этому чувству пришла приятная эйфория и осознание того, что мне удалось сделать все задуманное. Я безумно благодарна за то, что в меня поверили. Мне приятно, что кастомизация начала наконец-то по достоинству оцениваться в России.","type":"paragraph"},{"html":"<i><b>Esque:</b></i> Вы занимаетесь кастомизацией вещей - адаптацией их под конкретные запросы клиентов. Что вы используете для этого?","type":"paragraph"},{"html":"<u><i>Александра:</i></u> Краски по ткани и коже, специальные маркеры, контуры, баллончики и даже аэрограф, нашивки и вышивку. Я могу воплотить на одежде или аксессуарах любую идею клиента, сделать вещь поистине уникальной и отражающей его внутренний мир.","type":"paragraph"},{"html":"<i><b>Esque:</b></i> Александра, расскажите о самом необычном заказе росписи одежды, который вам приходилось делать.","type":"paragraph"},{"html":"<u><i>Александра:</i></u> Наверное, это джинсовка с изображением дьявола в классическом костюме, кепке и кроссовках, с трубкой и виски в руке, сидящем на кресле с множеством денежных купюр и кучей других элементов. Замысел клиента раскрывать нельзя, но одно могу сказать точно - было непросто соединить все эти вещи в гармоничную картину. Думаю, мне это удалось, так как клиент остался доволен.","type":"paragraph"},{"html":"<i><b>Esque: </b></i>Кастомизация для вас - это возможность дать старой вещи вторую жизнь или придать новой изюминку и индивидуальность?","type":"paragraph"},{"html":"<u><i>Александра:</i></u> Для меня равноценны обе эти задачи. Я с удовольствием помогу сохранить любимую вещь клиента, если она испорчена. Часто после кастомизации вещи обретают вторую, более яркую и интересную историю и носятся годами, становясь ещё более любимыми. Безусловно, я испытываю особенный кайф, когда индивидуализирую одежду собственного производства. Нет ничего лучше, чем сделать ее неповторимой и эксклюзивной, а после увидеть восторг в глазах заказчика.","type":"paragraph"},{"html":"<i><b>Esque: </b></i>Говорят, что кастомизация - это отличный способ быть на шаг впереди конкурентов. Согласны с этим?","type":"paragraph"},{"html":"<u><i>Александра:</i></u> Я думаю в эпоху массового потребления, крайне непросто чем-то удивить клиента. Кастомизация - отличная возможность выделиться на фоне конкурентов. Она позволяет создавать одежду в соответствии с желаниями каждого клиента и повышать лояльность к бренду. На сегодняшний день этот тренд приобрёл глобальные масштабы не только в одежде.","type":"paragraph"},{"html":"<i><b>Esque: </b></i>Опишите свой бренд \"CUST\" тремя словами.","type":"paragraph"},{"html":"<u><i>Александра:</i></u> Индивидуальность, самовыражение и свобода. \"CUST\" – это уникальная одежда со смыслом.","type":"paragraph"},{"html":"<i><b>Esque: </b></i>Что ждёте от финала конкурса? Какой у вас настрой?","type":"paragraph"},{"html":"<u><i>Александра:</i></u> От финала жду фееричного показа, креативных коллекций дизайнеров, новых интересных, ценных знакомств и заряда вдохновляющей творческой энергии. Не буду скрывать: мне хочется стать победителем Fashion битвы. Хотя, честно сказать, участие в финале среди лучших профессионалов своего дела для меня уже победа!","type":"paragraph"},{"type":"image","mediaId":"cmrmqxm0l00r6uktao4j81ck4"}]'::jsonb,'cmrmqxlqc00r5uktag8axtzgu','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2021-12-31T06:00:00.000Z'::timestamp,NULL,NULL,NULL,389,'/p