INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqs2v20070uktaii7gm3dv','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Ecology Fashion Week 2023. Мы за безопасную моду!','Подиум – это транслятор ценностей человечества.','599-ecology-fashion-week-2023-my-za-bezopasnuju-modu','[{"html":"Подиум – это транслятор ценностей человечества. Именно тут вскрываются самые острые проблемы и болевые точки общества. Современная мода – не просто про ткани и фасоны. Это лакмусовая бумажка того, что острее всего стоит на повестке дня.","type":"paragraph"},{"html":"Растущая осознанность человека не могла не сказаться на Fashion-индустрии. Новый сезон <strong>Ecology Fashion Week</strong> своей целью ставит помощь дизайнерам в формировании устойчивой моды с заботой о природе и сохранением окружающей среды. Общество потребления остается в прошлом, а на смену ему приходит человек будущего, что и докажут участники проекта 10 и 11 июня.","type":"paragraph"},{"html":"<strong>Татьяна Семенцова</strong>, дизайнер и основательница эко-бренда <strong>CROMA</strong> и участница нового сезона модной недели, считает, что начать сохранять ресурсы планеты нужно было «еще вчера». Дизайнер уверена, что натуральные ткани – это не только про здоровье, но и про стиль и образ жизни. Татьяна четко задалась целью внести свой вклад в поддержку осознанного потребления и отойти от политики вещизма. «<em>В поисках личного дизайн-кода и смыслов я влюбилась в конструктивизм. Так в бушующем котле идей и жизненных контекстов создалась моя первая коллекция «ИНАЯ» </em>–<em> самобытная, смелая и свободная. Четкость линий, смелые образы, неповторимая авторская стежка и только, конечно же, использование только натуральных тканей и наполнителей – вот наша философия. Бренд CROMA – это про медленную моду</em>», – рассказывает его основательница, четко осознавая взаимосвязи своих действий, как дизайнера, и их глобальных последствий, которые отражаются на всем земном шаре. Качественная, износостойкая, стильная одежда, которую производит бренд, способна не только подсветить индивидуальность, но и показать пример, как можно работать с безотходным производством, сохраняя бережность к экосистеме планеты.","type":"paragraph"},{"html":"Развитие сферы легкой промышленности, увы, «легкое» только на словах и проходит с тяжелейшими последствиями для Земли. Тот же полиэстер, который отнюдь не экологичен, занимает более 50% доли всего сырья, которое используется в производстве одежды. Скупаемые ежегодно тонны одежды заполоняют свалки, в то время, как ее бывшие владельцы в погоне за модой уже стоят в очереди за новыми коллекциями.","type":"paragraph"},{"html":"Хватит! Ecology Fashion Week заявляет, что отныне в моде бережливость и натуральность!","type":"paragraph"},{"html":"«<em>Fashion-компании должны отвечать за те немалые ресурсы, которые они используют. Но свой вклад могут внести не только те, кто создает одежду, но и те, кто ее покупает</em>», уверена <strong>Юлия Комарова</strong>, одна из основательниц бренда <strong>Your New Story</strong> и участница нового сезона Экологичной модной недели, «<em>наша команда выступает за защиту природы, поэтому мы создаем изделия из натуральных тканей. Коллекция весна-лето 23 \"My Garden\" (Мой Сад), которую мы представим на событии в июне - это коллаборация из насыщенных светом тканей (хлопок, лен, крапиву, коноплю, бамбук, эвкалипт), гаммы радостных цветов и сложного кроя. Участие в ECO FW для нашего бренда – это самая настоящая пропаганда защиты окружающей среды</em>». Дизайнер советует потребителю выбирай вещи из натуральных тканей: хлопка, шелка, льна. Они могут стоить дороже, зато дольше прослужат и сделают выбор более осознанным.","type":"paragraph"},{"html":"<strong>Организатор </strong><strong>Ecology</strong> <strong>Fashion</strong> <strong>Week,</strong><strong> Алена Балагурова</strong> транслирует ценности защиты окружающей среды. Другой ее проект индустрии моды, соревнование дизайнеров Fashion bitva, зачастую имеет в своей основе тему переработки и разумного использования. Так, еще в рамках самой первой битвы 7 лет назад, когда тема экологии не гремела и не стояла на повестке дня, одним из заданий для дизайнеров было создание модных образов в направлениях upcycling и recycling из вторсырья и сподручных материалов: то, философия чего сейчас растиражирована самыми крупными компаниями и мировыми брендами.","type":"paragraph"},{"html":"Развитие науки и новых технологий дарят человечеству огромный толчок и упрощают жизнь. Но они же разрушают взаимосвязь людей с тем естественным биологическим и нравственным фундаментом, потеряв который они не смогут существовать. Вот почему многие деятели искусства, работники души и сердца, черпают вдохновение из своего детства.","type":"paragraph"},{"html":"«<em>Я выросла в деревне, где на моих глазах пряли пряжу, валяли валенки из шерсти, трепали лен, а также шили и перешивали вещи, давая им новые жизни</em>», вспоминает участница модной недели, дизайнер <strong>Наталья Островская</strong>, «<em>Бабушкин сундук не оставил меня равнодушной. Перебирая натуральные шелка, лен, бархат, шифон, хлопок, я навсегда запомнила их тактильность и красоту. На мой взгляд, с развитием цивилизации, на всей планете произошло перенасыщение всем искусственным. Я счастлива, что своей работой могу принести хотя бы крошечную пользу на этой Земле. И считаю, что проект ECO FW должен расти и становиться одним из основных в развитии модной индустрии России</em>».","type":"paragraph"},{"html":"В основе развития бренда <strong>OSTROVSKAYA NATALYA</strong> лежит создание одежды, которая несет смысловую нагрузку, заставляет думать, вызывает эмоции, чувства, ассоциации. Авторские технологии позволяют добиваться необыкновенных фактур. В результате рождается не просто одежда, а долговечное и красивое изделие, которое не вредит ни нам, ни нашей природе. Большим плюсом в работе бренда является безотходное производство. Каждое изделие с помощью определенных технологий может получить новое рождение совершенно в другом амплуа. И, конечно же, в каждой коллекции заложен экологичный смысл, чистые мысли, поиск и познания своей души.","type":"paragraph"},{"html":"В прошлом году <strong>Наталья Островская</strong> приняла участие в ECO FW с коллекцией из экомеха, созданной в авторской технологии из шерсти. В этом году она планирует представить коллекцию «Зазеркалье» с использованием натуральных шелковых и шерстяных волокон, а также шифона.","type":"paragraph"},{"html":"Встретиться на подиуме и продемонстрировать свою открытость к эко-повестке участники Ecology Fashion Week 2023 смогут в Красной поляне уже в середине июня, 10 и 11 числа. Экологичный подиум и декорации в сочетании с красотой горной природы еще раз докажут гостям мероприятия, что экология – это не только про безопасность, но и про эстетику.","type":"paragraph"},{"html":"<br />На протяжении всей Ecology Fashion Week на площадке будет работать Open Market, на котором будут представлены коллекции дизайнеров из экологических материалов, эко-украшения, товары для дома, косметика российского производства и многое другое. Гости маркета смогут приобрести любой подиумный образ по специальным скидочным ценам.","type":"paragraph"},{"html":"<br />Мероприятие пройдет 10 и 11 июня по адресу: Красная поляна, Русский двор \"Рыбино\", микрорайон 2-й Садовый, д.83.","type":"paragraph"},{"html":"<i><u>Вспомним об окружающей среде через красоту вместе.</u></i>","type":"paragraph"},{"html":"<i><u>«Любви к природе нет без чувства красоты» - <b>Я.П. Полонский</b></u></i>","type":"paragraph"}]'::jsonb,'cmrmqs2sn006zukta9l0i6m0p','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2023-04-29T06:00:00.000Z'::timestamp,NULL,NULL,NULL,599,'/fashion/news-2/599-ecology-fashion-week-2023-my-za-bezopasnuju-mo