8C,918C ''эко-бренд'':113C ''эко-повестк'':847C ''эко-украшен'':917C ''эколог'':522C,883C ''экологич'':293C ''экологическ'':915C ''экологичн'':390C,786C,867C ''экомех'':811C ''экосистем'':266C ''эмоц'':729C ''эстетик'':892C ''эт'':10B,15C,37C,138C,217C,422C,447C,884C ''юл'':377C ''явля'':762C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqx0t300psuktallo0dmqm','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Мария Логинова: "Я стремлюсь к тому, чтобы моя косметика, возвращала коже способность защищаться от ежедневных стрессов"','Тема натуральной косметики все чаще и чаще напоминает о себе.','402-marija-loginova-ja-stremljus-k-tomu-chtoby-moja-kosmetika-vozvraschala-kozhe-sposobnost-zaschischatsja-ot-ezhednevnyh-stressov','[{"html":"Тема натуральной косметики все чаще и чаще напоминает о себе. Ежегодно ее востребованность возрастает на 30% и в связи с ситуацией в мире, скорее всего, мы все перейдем на косметику российского производства. Именно поэтому мы решили более подробно углубиться в ее производство и ответить на волнующие нас вопросы.","type":"paragraph"},{"html":"Благодарим Марию Логинову, основательницу бренда \"Mary’s Cosmetics\" @kosmetika_ruchnoy_raboti за подробное интервью!","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Мария, здравствуйте. Расскажите, как на свет появился ваш бренд?</strong>","type":"paragraph"},{"html":"Мария: Здравствуйте. Много лет назад меня перестала устраивать моя уходовая косметика: она не только перестала помогать в борьбе с какими-то недостатками, но ещё и стала ухудшать состояние кожи: стало появляться ощущение стянутости, сухости кожи, покраснения после её применения. И тогда я впервые задумалась, как было бы хорошо самой делать средства по уходу, подходящие именно мне. И, что немало важно, в этом случае я бы была на 100% уверена в составе. Но, на тот момент я работала и у меня не было возможности уделить достаточно времени изучению этого вопроса. К этой теме я вернулась 1,5 года назад, будучи в декрете. Прошла курсы по мыловарению. Потом последовало ни одно обучение по основам косметологии, кремоварению и подключила курсы по созданию косметики для волос. Сначала моей продукцией пользовались только близкие. Потом я стала продавать друзьям и знакомым мамам по детской площадке. Получала положительные отзывы. И решила, а почему бы не попробовать хобби превратить в своё дело. Так и появился мой бренд «Mary’s Cosmetics».","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: У вас есть девиз?</strong>","type":"paragraph"},{"html":"Мария: Да. Подари своей коже волшебство.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: В чем ваши основные преимущества косметики перед другими российскими брендами? </strong>","type":"paragraph"},{"html":"Мария: Основная «фишка» Mary’s Cosmetics в том, что каждый продукт разрабатывается конкретно под каждого клиента. В зависимости от его запросов, его типа кожи, его предпочтений готовится продукт с тем набором компонентов и активов, которые направлены на решение проблемы именно этого человека. Сегодня очень многие производители косметики делают ставку на быстрое достижение видимого результата. Но, зачастую такой эффект достигается за счёт того, что в долгосрочной перспективе такие средства будут только вредить коже и волосам. Например, возьмём силикон, вазелин, минеральные масла, парафин. Эти компоненты содержатся в промышленных кремах. Они образуют на коже плёнку, которая очень хорошо и надёжно удерживает воду. Следовательно, липидный барьер разучивается держать воду самостоятельно. Поэтому пока крем на коже, всё хорошо. Когда мы крем снимаем, кожа уже не может удержать влагу, регулировать процессы испарения, и начинается очень сильная сухость. И это неправильно, так как крем должен помогать коже восстанавливаться, а не выполнять за неё функции, пока он на ней.","type":"paragraph"},{"html":"Я поставила задачу своей косметикой влиять именно на причину проблемы. Я стремлюсь к тому, чтобы моя косметика, возвращала коже способность защищаться от ежедневных стрессов. Важно, чтобы косметика имела накопительный.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: А если поговорить о зарубежных брендах, особенно о корейских, которые были очень актуальны среди женской российской аудитории еще несколько лет назад, то какие общие плюсы вы можете назвать у российского производства? </strong>","type":"paragraph"},{"html":"Мария: Согласно статистике и отзывам косметологов российская косметология за последние годы совершила большой прорыв. При создании косметики используются новейшие научные разработки и современные технологии. Кроме того, растёт конкуренция, что также способствует развитию и улучшению технологий и конечного продукта. На производстве используется как отечественное, так и импортное сырьё.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Какая продукция у вас в ассортименте? И что пользуется наибольшим спросом? </strong>","type":"paragraph"},{"html":"Мария: Мыло, скрабы для тела и лица, суфле для тела, гидрофильные и массажные плитки, бомбочки для ванной, пралине, массажные свечи, бальзамы для губ, кремы, сыворотки, пенки для умывания, тоники, мицеллярная вода, косметика для кожи головы и волос с разным действием (скрабы, пилинги, шампуни, кондиционеры), масла (гидрофильные, для кутикулы, для ресниц и т.п.). Не могу выделить, какой именно продукт пользуется наибольшим спросом. Вся моя аудитория разделилась на несколько сегментов: кто-то постоянно берёт косметику для ванной, кто-то уходовую косметику, популярны кремы в целом, сыворотки. Очень многим нравятся массажные плитки и бальзамы для губ.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Планируете расширять ассортимент? Как часто появляются новинки? </strong>","type":"paragraph"},{"html":"Мария: Да, конечно. Планирую в скором времени ввести мужскую линейку и ближе к лету солнцезащитную косметику. В линейке кремов тоже планируется расширение. Новые продукты запускаются медленно, так как требуется достаточно времени на разработку рецептуры, тестирование и тщательную проверку. Обычно от идеи до выпуска проходит 6-8 месяцев.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Скажите, на ваш взгляд, популярность российской натуральной косметики возрастает в нашей стране? </strong>","type":"paragraph"},{"html":"Мария: Конечно. Потребители во всём мире хотят пользоваться безопасными средствами по уходу за кожей. И Россия не исключение. Причём, резко интерес к Natur Product возрос буквально несколько лет назад. Если раньше потребители ориентировались на обещания производителя, то сейчас они читают и разбирают состав, самостоятельно изучают свойства тех или иных компонентов – более критично относятся к составу косметических средств. Согласно прогнозам, рост рынка натуральной косметики в России, начавшийся в 2011 году, продолжится. Рынок натуральной косметики растёт в среднем на 30%. Согласно прогнозам, в ближайшее время он догонит рынки европейских стран.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Мария, какие проблемы помогает решить косметика вашего бренда? И как правильно подобрать крем, который подойдет именно твоей коже?</strong>","type":"paragraph"},{"html":"Мария: Если говорить о коже лица, тела и рук, то в этом случае косметика нашего бренда направлена на восстановление липидного барьера, на решение проблем в зависимости от типа кожи (нормальная, жирная, сухая, комби, зрелая), на решение проблем кожи вокруг глаз, связанных с угревой сыпью, морщинами, куперозом, пигментацией, целлюлитом. Если касаться косметики для кожи головы и волос, то здесь средства направлены на укрепление и на борьбу с выпадением волос. Чтобы подобрать крем, подходящий именно вам, нужно в первую очередь разобраться, какие проблемы с кожей нужно решить. И уже от этого отталкиваться и подбирать косметику, которая в своём составе содержит те компоненты и активы, которые направлены на устранение и работу с конкретной проблемой. <br /><br />","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: Вы пользуетесь своей косметикой? Что именно вы, как потребитель, можете отметить в своем бренде? </strong>","type":"paragraph"},{"html":"Мария: Конечно, пользуюсь. Скажу больше: я полностью перешла на неё. Как и для любого потребителя, для меня самое главное, чтобы косметика отвечала конкретно моим запросам, а именно, работала конкретно над моими недостатками. И продукция «Mary’s Cosmetics» отлично справляется с этой задачей. И как приятное и немаловажное дополнение – широкий выбор великолепных ароматов.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>: И напоследок, пару советов нашим читательницам. </strong>","type":"paragraph"},{"html":"Мария: Нужно заботиться не только о внешней привлекательности, но и о здоровье. Правильно подобранная косметика – это то, что в любом возрасте помогает нам, женщинам, выглядеть ухоженно и чувствовать себя красивой. Поэтому выбирайте ту уходовую косметику, которая подходит именно вам. Если вашей коже не подходит уход или средство, которым вы пользуетесь, она начинает моментально подавать сигналы. И не пренебрегайте этими сигналами. Но, что важно учитывать при использовании натуральной косметики. Перед её применением лучше провести тест. Дело в том, что эфирные масла и растительные экстракты, использующие в натуральной косметике - это природные аллергены, которые, при попадании на кожу, могут вызвать соответствующую реакцию.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqwzi600pquktad1enzkbx"},{"mediaId":"cmrmqx0pc00pruktawhknelhx"}]}]'::jsonb,'cmrmqwyis00ppuktaxu9mbp06','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyz0000akwtaq6w9733r','cmrmpdrom0000sstarkqxwts4','2022-03-02T06:00:00.000Z'::timestamp,NULL,NULL,NULL,402,'/beauty/mnenie/402-marija-loginova-ja-stremljus-k-tomu-chtoby-moja-kosmetika-vozvraschala-kozhe-sposobnost-zaschischatsja-ot-ezhednevnyh-stressov.html','2026-07-15T21:03:19.767Z'::timestamp,'2026-07-16T13:59:45.168Z'::timestamp,'''-8'':744C ''1'':201C ''100'':174C ''2011'':832C ''30'':40C,842C ''5'':202C ''6'':743C ''cmrmqwzi600pquktad1enzkb