INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqzvrx00xkuktad4j2c7ni','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Стартовал 43-й Московский Международный кинофестиваль','22 апреля стартовал 43-й Международный кинофестиваль, который так ждали все представители данной индустрии.','327-startoval-moskovskij-mezhdunarodnyj-kinofestival','[{"html":"22 апреля стартовал 43-й Международный кинофестиваль, который так ждали все представители данной индустрии. Звезды, соскучившиеся по подобным мероприятиям и выходам в свет, с удовольствием позировали на красной дорожке у Театра мюзикла на Пушкинской площади, освещая ее бриллиантами Mercury. Кстати, официального партнера ММКФ с этого года.","type":"paragraph"},{"html":"Впервые Московский международный кинофестиваль прошел в 1935 году, где возглавил жюри Сергей Эйзенштейн - советский режиссёр театра и кино. <br /><br />","type":"paragraph"},{"html":"Программа фестиваля этого года, который продлится с 22 по 29 апреля, полностью отразит шатание и разброд самого кинопроцесса, который, конечно, как и другие сферы жизни, был затронут в 2020.","type":"paragraph"},{"html":"В программе представлено более 200 фильмов лучших современных отечественных и зарубежных режиссеров. <u><b>Откроет Московский Международный кинофестиваль 2021 фильм «Девятаев» Сергея Трофимова и Тимура Бекмамбетова</b></u>, который посетил столицу с женой Наталией Фишман. Интернациональную сторону события отражали актриса Мерьем Узерли из сериала “Великолепный век” и солист группы Rammstein, который и написал саундтрек к фильму Бекмамбетова. <b>Жюри основного конкурса возглавил филиппинский режиссер Брильянте Мендоса, документального конкурса – польский продюсер Дорота Рожковская</b>.","type":"paragraph"},{"html":"<u>29 апреля, в последний день фестиваля, будут вручены статуэтки золотого и серебряного святого Георгия, которые так же изготовили мастера Mercury.</u>","type":"paragraph"},{"type":"image","mediaId":"cmrmqzvpg00xjuktax8kuayrr"}]'::jsonb,'cmrmqzvb800xiuktal4ud43bb','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz6g000dkwtai45m48bj','cmrmpdrom0000sstarkqxwts4','2021-04-23T06:00:00.000Z'::timestamp,NULL,NULL,NULL,327,'/sobytija/kino/327-startoval-moskovskij-mezhdunarodnyj-kinofestival.html','2026-07-15T21:05:33.213Z'::timestamp,'2026-07-16T14:00:51.936Z'::timestamp,'''1935'':76C ''200'':127C ''2020'':119C ''2021'':139C ''22'':7B,21C,98C ''29'':100C,193C ''43'':2A,10B,24C ''cmrmqzvpg00xjuktax8kuayrr'':218C ''imag'':216C ''mercuri'':59C,212C ''paragraph'':68C,89C,121C,191C,214C ''rammstein'':168C ''актрис'':158C ''апрел'':8B,22C,101C,194C ''бекмамбетов'':146C,175C ''бриллиант'':58C ''брильянт'':182C ''будут'':199C ''век'':164C ''великолепн'':163C ''возглав'':79C,179C ''вперв'':70C ''вруч'':200C ''выход'':41C ''георг'':206C ''год'':66C,77C,94C ''групп'':167C ''дан'':19B,33C ''девята'':141C ''ден'':197C ''документальн'':184C ''дорожк'':49C ''дорот'':188C ''друг'':113C ''ждал'':16B,30C ''жен'':151C ''жизн'':115C ''жюр'':80C,176C ''зарубежн'':133C ''затронут'':117C ''звезд'':35C ''золот'':202C ''изготов'':210C ''индустр'':20B,34C ''интернациональн'':154C ''й'':3A,11B,25C ''кин'':87C ''кинопроцесс'':108C ''кинофестивал'':6A,13B,27C,73C,138C ''конкурс'':178C,185C ''котор'':14B,28C,95C,109C,147C,169C,207C ''красн'':48C ''кстат'':60C ''лучш'':129C ''мастер'':211C ''международн'':5A,12B,26C,72C,137C ''мендос'':183C ''мер'':159C ''мероприят'':39C ''ммкф'':63C ''московск'':4A,71C,136C ''мюзикл'':52C ''написа'':171C ''натал'':152C ''освещ'':56C ''основн'':177C ''отечествен'':131C ''откроет'':135C ''отража'':157C ''отраз'':103C ''официальн'':61C ''партнер'':62C ''площад'':55C ''подобн'':38C ''позирова'':46C ''полност'':102C ''польск'':186C ''посет'':148C ''последн'':196C ''представител'':18B,32C ''представл'':125C ''программ'':91C,124C ''пр