INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqvda200kmuktac1hl8gfs','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Екатерина Бугай: "Не стесняться, держать спину прямо, быть уверенной в себе"','Бугай Екатерина из города Хабаровск, пример для многих.','455-ekaterina-bugaj-ne-stesnjatsja-derzhat-spinu-prjamo-byt-uverennoj-v-sebe','[{"html":"<strong>Бугай Екатерина из города Хабаровск, пример для многих. С 5 лет в жизни Кати была хореография, но когда пришло время чему-то новому появиться на горизонте, наша героиня не побоялась трудностей и начала все сначала. Теперь она модель и участник школьной программы «КВН». И на сцене, как и на подиуме, Катя чувствует себя легко и непринужденно. </strong>","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Катя, здравствуй. Расскажи, какие у тебя планы на это лето?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Добрый день! Я хорошо сдала переводные экзамены в школе, поэтому теперь радуюсь каникулам.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Как ты решила стать моделью?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Если честно, я мечтала об этом с раннего детства. Но сначала у меня были занятия хореографией, потом еще год я занималась актерским мастерством. И вот только летом прошлого года мама предложила пойти в модельную школу.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Какие показы ты уже успела посетить? В каких городах?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Я участвовала только в двух показах. Это участие в январе 2022 г. в фестивале \"Эклектика\", который проходил в нашем городе Хабаровске и в Иркутске 26-27 марта в показе конкурса дизайнеров \"Fashion Bitva\".","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Скорее всего, помимо моделинга у тебя еще есть увлечения? Расскажи о них.","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Я поклонница юмористического шоу \"Импровизация\". Люблю смотреть новые и пересматривать старые выпуски и писать фанфики.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> К юмору мы еще вернемся, а сейчас расскажи тяжело ли тебе было расставаться с хореографией, ведь ты занималась ей с 5 лет?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Да, это был большой этап в моей жизни, с бесконечными репетициями, красивыми костюмами и ярким макияжем, выступлениями на разных сценах, поездками в другие города. Это ценный опыт.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Те знания, которые ты получила, в хореографической школе, как-то помогают тебе в дефиле в моделинге?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Да, одно из них, это умение держать осанку.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Что тебе больше всего нравится в показах: подиум, подготовка, эмоции, наряды?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Наряды, я очень люблю примерять новую одежду.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> У тебя есть любимые дизайнеры?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Мне очень понравились дизайнеры, которых я представляла на показе в Иркутске. Это Мария Прокопьева и Кузьмина Надежда. Платье, которое мне посчастливилось показывать, было просто шикарным.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Катя, теперь перейдем к «КВН». Давно им занимаешься?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Нет, с начала учебного года. Я так обрадовалась, когда осенью мне предложили стать участником нашей школьной команды «КВН» с названием \"Переулок Энштейна\". В этот год наша команда смогла дойти до финала Юниор «КВН» в нашем городе.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Что самое важное в «КВН»? Наверное, умение смешить и придумывать шутки?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Да, согласна. Но еще важно легко, без напряжения держаться на сцене. Тогда и шутки будут естественнее и смешнее. В «КВН» важно ещё уметь креативить и импровизировать .","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> И все же, на чем ты делаешь больший упор: на моделинге или «КВН»?","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Наверное, и там и там. Мне все интересно.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>:</strong> Дай пару советов начинающим моделям.","type":"paragraph"},{"html":"<strong>Екатерина:</strong> Не стесняться, держать спину прямо, быть уверенной в себе и в том, что ты делаешь.","type":"paragraph"},{"type":"image","mediaId":"cmrmqvd8j00kluktaliry1ogv"}]'::jsonb,'cmrmqvctb00kkuktaze1c4ywr','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-06-12T06:00:00.000Z'::timestamp,NULL,NULL,NULL,455,'/esquekids/moda-ek/455-ekaterina-bugaj-ne-stesnjatsja-derzhat-spinu-prjamo-byt-uverennoj-v-sebe.html','2026-07-15T21:02:02.618Z'::timestamp,'2026-07-16T13:59:11.559Z'::timestamp,'''-27'':196C ''2022'':181C ''26'':195C ''5'':27C,263C ''bitva'':203C ''cmrmqvd8j00kluktaliry1ogv'':552C ''esqu'':78C,109C,157C,207C,242C,299C,332C,358C,396C,448C,493C,522C ''fashion'':202C ''imag'':550C ''paragraph'':76C,90C,107C,116C,155C,168C,205C,221C,240C,266C,297C,318C,330C,345C,356C,365C,394C,406C,446C,461C,491C,508C,520C,529C,548C ''актерск'':140C ''бесконечн'':278C ''больш'':272C,501C ''буга'':2A,10B,18C ''будут'':478C ''важн'':451C,468C,484C ''верн'':247C ''врем'':37C ''выпуск'':235C ''выступлен'':285C ''г'':182C ''героин'':46C ''год'':137C,147C,413C,433C ''горизонт'':44C ''город'':13B,21C,166C,190C,292C,444C ''да'':523C ''давн'':402C ''двух'':175C ''дела'':500C,546C ''ден'':94C ''де