INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqug1s00h7uktabd1zmkif','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Бьет, значит, любит? Как подать в суд на тирана?','Выходя из дома, вы надеваете темные очки.','490-bet-znachit-ljubit-kak-podat-v-sud-na-tirana','[{"html":"Выходя из дома, вы надеваете темные очки. Утром придирчиво разглядываете себя в зеркале и запудриваете синяки. На расспросы подруг отделываетесь шутками. Но в глубине души живет страх - а вдруг он снова это сделает? Если это про вас, вы не одиноки. Каждую минуту на нашей планете мужья или партнеры избивают сотни женщин. И все они находятся в растерянности, унижены и напуганы. Ситуация осложняется, если у супругов или партнеров есть общие дети. В этом случае женщина убеждает себя, что надо потерпеть, все образуется, он изменится. Не изменится.","type":"paragraph"},{"html":"Ольга - цветущая тридцатилетняя женщина, обеспеченная и привлекательная. Сегодня, несмотря на пасмурный день, она приехала ко мне в черных очках. На вопросы отвечает односложно, не шутит, не демонстрирует свои новые часы от Cartier. «Что случилось?» - спрашиваю. В ответ – монолог: «Сергей всегда отличался крутым характером. Запрещал разговаривать с другими мужчинами, ревновал, был подозрителен. А тут прочитал в моем телефоне переписку с парикмахером. Клянусь, там ничего такого не было! Просто мы шутили и обсуждали мою новую прическу. Сергей не стал слушать мои оправдания и жестоко избил меня. Вот, посмотри, все тело в синяках. По лицу он старался не бить, но один раз заехал по скуле, теперь под глазом отвратительный фиолетовый синяк. Он кричал, что запретит мне выходить из дома. Что делать? Я боюсь его. Боюсь снова чем-то спровоцировать его ревность. Кстати, после побоев у нас был восхитительный секс. Кажется, избиение и мои крики его возбудили».","type":"paragraph"},{"html":"Видимо, Ольга будет терпеть и еще несколько раз нарвется на побои.","type":"paragraph"},{"html":"Ситуация только усугубится. Распоясавшийся тиран будет пьянеть от криков и слез своей жертвы. Это только подольет масла в огонь. Но порой терпение жертвы заканчивается. Женщина решает подать в суд на тирана.","type":"paragraph"},{"html":"Реально ли выиграть такой судебный процесс? Об этом мы побеседуем с адвокатом Михаилом Агаповым.","type":"paragraph"},{"html":"<b>Esque:</b> Михаил, здравствуйте. С чего нужно начинать женщине, пережившей побои и физическое насилие? Как начать борьбу за свои права?","type":"paragraph"},{"html":"<b>Михаил:</b> Добрый день! Прежде всего, жертве нельзя отчаиваться, ничего нельзя бояться. Следует обратиться к профессиональному адвокату и вместе с ним готовить все доказательства и документы, в том числе обращения в полицию, правоохранительные органы.","type":"paragraph"},{"html":"После побоев незамедлительно следует обратиться в травмпункт или вызвать скорую помощь для того, чтобы зафиксировать травмы. Посетить травмпункт необходимо в день нанесения побоев или на следующий день. Проследите, чтобы все рассказанное вами было задокументировано, стояла дата нанесения побоев, а врач направил в полицию телефонограмму о предполагаемом правонарушении. Позже, при проведении судебно-медицинской экспертизы, эти данные будут иметь большое значение.","type":"paragraph"},{"html":"Важно соблюдать все рекомендации врача - сдать анализы, обратиться к узким специалистам. Это позволит определить тяжесть вреда, причиненного здоровью.","type":"paragraph"},{"html":"Необходимо составить заявление с просьбой выдать заверенные копии всех медицинских документов. Они пригодятся, если оригиналы будут потеряны.","type":"paragraph"},{"html":"Второе - вам нужно найти свидетелей и записи камер видеонаблюдения. Прямые свидетели в делах о домашнем насилии находятся редко. Но косвенные свидетели: родители, друзья, соседи, могут подтвердить, что вчера вы были в добром здравии, а сегодня – в синяках.","type":"paragraph"},{"html":"Если вас избили в общественном месте, можно найти прямых свидетелей. А в случае, если в этом месте установлены камеры видеонаблюдения, нужно узнать, кому они принадлежат и попросить предоставить нужную запись. Делать это следует быстро, потому что такие записи хранятся от 3 до 5 дней.","type":"paragraph"},{"html":"И, наконец, необходимо обратиться в полицию. Нужно прийти в участок и написать заявление. Сделать это надо на следующий день после обращения в травмпункт. Промедление вызовет вопросы у защиты мужа-тирана и судьи. Если вы не уверены в своих силах, нужно проконсультироваться с адвокатом или даже попросить адвоката пойти в участок вместе с вами.","type":"paragraph"},{"html":"<b>Esque:</b> Как правильно написать заявление в полиции?","type":"paragraph"},{"html":"<b>Михаил:</b> Изложение ситуации в заявлении должно быть четким и максимально подробным. Сотрудники полиции будут вам говорить: «Расскажите обо всем кратко, чтобы сэкономить время, а позже изложите все в подробностях». Не поддавайтесь на их уговоры! Настаиваете на составлении подробнейшего объяснения. Это необходимо для судебного разбирательства. Полезно будет заранее расписать последовательность действий мужа-тирана и взять эти записи с собой в полицию. Обязательно отметьте, подвергались ли вы насилию со стороны мужа ранее, обращались ли за медицинской помощью, сообщали ли в полицию о побоях. Внимательно читайте любые документы, прежде чем их подписывать. Если обнаружите в объяснении неточности, не стесняйтесь внести правки. И не удивляйтесь, если вас спросят о количестве нанесенных ударов и их локализации.","type":"paragraph"},{"html":"Попросите сотрудников полиции опросить свидетелей и изъять записи с камер видеонаблюдения. Если они не торопятся, поможет адвокатский запрос.","type":"paragraph"},{"html":"Полиция обязана провести экспертизу ваших повреждений. Если их признают побоями, должно быть проведено административное расследование по ст. 6.1.1 КоАП РФ («Побои»). Затем дело направят в районный суд. Если расследования не было – в мировой суд.","type":"paragraph"},{"html":"Даже если вам был нанесен легкий вред, но он вызвал расстройство здоровья или утрату общей трудоспособности, полиция вынесет постановление о передаче материалов в участок мирового судьи. Вам придется направиться туда и написать заявление о возбуждении уголовного дела частного обвинения по ст. 115 УК РФ («Умышленное причинение легкого вреда здоровью»).","type":"paragraph"},{"html":"В обоих случаях привлечь обидчика к ответственности можно в течение двух лет.","type":"paragraph"},{"html":"<b>Esque:</b> Какое наказание ждет мужа-агрессора?","type":"paragraph"},{"html":"<b>Михаил:</b> Закон таков, что за домашнее насилие, совершенное впервые, к уголовной ответственности человека не привлекут. Это может случиться, только если он раньше подвергался административному наказанию за аналогичные деяния (ст. 116.1 УК РФ) или если побои повлекли расстройство здоровья жертвы насилия или стойкую утрату общей трудоспособности (ст. 115 УК РФ). Однако тирану будет грозить административная ответственность по ст 6.1.1 КоАП РФ («Побои»). Это влечет за собой:","type":"paragraph"},{"html":"Начать жизнь с чистого листа и перестать терпеть нужно прямо сейчас, не мечтая о светлом будущем с мужем-тираном! Он не изменится! Именно об этом нужно думать, делая первый шаг навстречу счастливому завтра!","type":"paragraph"},{"html":"Елена Шульгина","type":"paragraph"}]'::jsonb,'cmrmqufzs00h6uktaww3nf8d4','cmrm8kzpw000mkwtaocyn5161','cmrm8kzts000pkwtapdodj5ob','cmrmpdrom0000sstarkqxwts4','2022-08-10T06:00:00.000Z'::timestamp,NULL,NULL,NULL,490,'/psihologija/intervju-2/490-bet-znachit-ljubit-kak-podat-v-sud-na-tirana.html','2026-07-15T21:01:19.552Z'::timestamp,'2026-07-16T13:58:46.742Z'::timestamp,'''115'':847C,929C ''116.1'':912C ''3'':559C ''5'':561C ''6.1.1'':786C,940C ''cartier'':136C ''esqu'':317C,623C,873C ''paragrap