INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqengk003apotajkbutbew','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Мажор отбирает детей у матери! Часть 2','Судебные разбирательства между Агатой Муцениеце и Павлом Прилучным набирают новые обороты.','663-mazhor-otbiraet-detej-u-materi-chast-2','[{"html":"Судебные разбирательства между Агатой Муцениеце и Павлом Прилучным набирают новые обороты. На днях состоялся новый суд, где рассматривался вопрос проживания детей. Из-за отсутствия актрисы на слушании, суд был перенесен на 29 августа.","type":"paragraph"},{"html":"Видимо так и не смирившись с большой суммой алиментов, звезда «Мажора» пошел на крайние меры и в судебные баталии вмешал детей! И в следующем судебном заседании примут участие и сами дети, именно им придется выбрать, с кем они будут жить.","type":"paragraph"},{"html":"Актриса узнала эту новость, будучи на отдыхе и немедленно отреагировала в своем личном блоге:","type":"paragraph"},{"html":"«Мой медвежонок, такой большой и в душе еще такой ребенок! Люблю всем сердцем. И никому не позволю тебя тревожить и пытаться разрушить твое счастье, я — мама медведица».","type":"paragraph"},{"html":"Для чего Прилучный затеял эту игру не совсем понятно, ведь отобрать детей у такой матери в России достаточно сложно и если даже по какой-то причине и личным связям это получится сделать, то общественность взбунтуется и актер рискует остаться без дохода и вовсе, ведь отмены в наше время не редкое явление.","type":"paragraph"},{"html":"По словам эксперта Дениса Хузиахметова , при рассмотрении вопроса о проживании детей у того или иного родителя учитывается ряд аспектов: возраст, привязанность к маме и папе, доход, жилищные условия. Пожелания самих детей суд, безусловно, берет во внимание, однако не считает их определяющими.","type":"paragraph"},{"html":"«При этом следует отметить, что российская судебная практика складывается в пользу матерей. Как правило, местом жительства детей определяется место жительства их матери. Думаю, что настоящее дело не станет исключением», — заключил Хузиахметов.","type":"paragraph"},{"html":"А мы продолжаем следить за процессом и желаем Агате Муцениеце, сил и терпения!","type":"paragraph"}]'::jsonb,'cmrmqenf90039potaqb6852v3','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-07-06T06:00:00.000Z'::timestamp,NULL,NULL,NULL,663,'/v-mire/663-mazhor-otbiraet-detej-u-materi-chast-2.html','2026-07-15T20:49:02.660Z'::timestamp,'2026-07-16T13:56:42.651Z'::timestamp,'''2'':7A ''29'':51C ''paragraph'':54C,97C,114C,144C,199C,243C,277C,293C ''август'':52C ''агат'':11B,22C,287C ''актер'':183C ''актрис'':44C,99C ''алимент'':64C ''аспект'':219C ''батал'':74C ''безусловн'':233C ''берет'':234C ''блог'':112C ''больш'':62C,119C ''будут'':94C ''будуч'':103C ''взбунт'':181C ''видим'':56C ''вмеша'':75C ''вниман'':236C ''вовс'':189C ''возраст'':220C ''вопрос'':37C,208C ''врем'':194C ''всем'':127C ''выбра'':90C ''дел'':270C ''денис'':204C ''дет'':3A,39C,76C,86C,157C,211C,231C,261C ''днях'':31C ''достаточн'':163C ''доход'':187C,226C ''дума'':267C ''душ'':122C ''жела'':286C ''жилищн'':227C ''жит'':95C ''жительств'':260C,264C ''заключ'':274C ''заседан'':81C ''затея'':149C ''звезд'':65C ''игр'':151C ''из-з'':40C ''имен'':87C ''ин'':215C ''исключен'':273C ''какой-т'':169C ''кем'':92C ''крайн'':69C ''личн'':111C,174C ''любл'':126C ''мажор'':1A,66C ''мам'':141C,223C ''матер'':5A,160C,256C,266C ''медведиц'':142C ''медвежонок'':117C ''мер'':70C ''мест'':259C,263C ''муцениец'':12B,23C,288C ''набира'':16B,27C ''настоя'':269C ''наш'':193C ''немедлен'':107C ''ник'':130C ''нов'':17B,28C,33C ''новост'':102C ''оборот'':18B,29C ''обществен'':180C ''однак'':237C ''определя'':241C,262C ''оста'':185C ''отбира'':2A ''отдых'':105C ''отм'':191C ''отмет'':248C ''отобра'':156C ''отреаг