INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqxw9v00rnukta22py4j15','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Финал 9 сезона Fashion bitva в Яровит Холле','26 февраля в Яровит Холле пройдет одно из самых долгожданных модных событий – финал 9 сезона конкурса FASHION BITVA.','385-final-9-sezona-fashion-bitva-v-jarovit-holle','[{"html":"26 февраля в Яровит Холле пройдет одно из самых долгожданных модных событий – финал 9 сезона конкурса FASHION BITVA. В нем примут участие 20 дизайнеров из разных уголков России - победителей региональных этапов и отборочных онлайн туров. Каждым участником на суд жюри на 15-метровом глянцевом подиуме будет представлена коллекция на тему «Год 2031».","type":"paragraph"},{"html":"Что станет с модой спустя 10 лет? Заглянем в будущее, обернувшись назад.","type":"paragraph"},{"html":"До финала остается еще 2 месяца, однако участники уже активно занимаются подготовкой к нему.","type":"paragraph"},{"html":"«Подготовка двигается очень сложно, так как нужно забежать вперед на 10 лет. Придумать оригинальную концепцию, которая будет транслироваться в коллекции одежды, получается не сразу. Как правило, это самый тяжелый этап. Как только рождается идея, процесс создания линейки одежды идет максимально быстро», - рассказала дизайнер из Тюмени, Елена Филипова.","type":"paragraph"},{"html":"Несмотря на трудности, появляющиеся у финалистов при подготовке к показу, они решительно настроены на победу.","type":"paragraph"},{"html":"«Для меня выиграть в первом этапе конкурса было чем-то неожиданным и невероятным. А поездка на финал в Москву, как заветное желание, которое сбылось! От финала я жду новых встреч, знакомств и возможностей. Коллекцию для него я шью только с мыслями о победе!», - поделилась Инна Триандофилова, победитель регионального этапа, проходившего в Ростове-на-Дону.","type":"paragraph"},{"html":"Напомним, что победитель конкурса отправится представлять свою коллекцию на Russian Fashion Display в Италии.","type":"paragraph"},{"html":"Желаем всем дизайнерам вдохновения, воплощения в жизнь всех задумок и, конечно, удачи на показе! Будем продолжать следить за процессом подготовки к финалу конкурса и держать вас в курсе событий.","type":"paragraph"}]'::jsonb,'cmrmqxw5e00rmuktaozfxju2f','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2021-12-17T06:00:00.000Z'::timestamp,NULL,NULL,NULL,385,'/projects-esque/fashion-bitva/385-final-9-sezona-fashion-bitva-v-jarovit-holle.html','2026-07-15T21:04:00.547Z'::timestamp,'2026-07-16T14:00:01.250Z'::timestamp,'''10'':87C,124C ''15'':68C ''2'':101C ''20'':49C ''2031'':78C ''26'':9B,27C ''9'':2A,22B,40C ''bitva'':5A,26B,44C ''display'':252C ''fashion'':4A,25B,43C,251C ''paragraph'':80C,95C,112C,162C,180C,239C,256C,288C ''russian'':250C ''активн'':106C ''буд'':272C ''будущ'':91C ''быстр'':154C ''вдохновен'':261C ''возможн'':215C ''воплощен'':262C ''вперед'':122C ''всем'':259C ''встреч'':212C ''выигра'':184C ''глянцев'':70C ''год'':77C ''двига'':115C ''держа'':282C ''дизайнер'':50C,156C,260C ''долгожда'':18B,36C ''дон'':237C ''ел'':159C ''жду'':210C ''жела'':258C ''желан'':204C ''жизн'':264C ''жюр'':66C ''забежа'':121C ''заветн'':203C ''заглян'':89C ''задумок'':266C ''занима'':107C ''знакомств'':213C ''иде'':147C ''идет'':152C ''ин'':227C ''итал'':254C ''кажд'':62C ''коллекц'':74C,133C,216C,248C ''конкурс'':24B,42C,188C,244C,280C ''концепц'':128C ''котор'':129C,205C ''курс'':285C ''лет'':88C,125C ''линейк'':150C ''максимальн'':153C ''месяц'':102C ''метров'':69C ''мод'':85C ''модн'':19B,37C ''москв'':201C ''мысл'':223C ''назад'':93C ''напомн'':241C ''настро'':176C ''невероятн'':195C ''нем'':46C,110C ''неожида'':193C ''несмотр'':164C ''нов'':211C ''нужн'':120C ''обернувш'':92C ''одежд'':134C,151C ''одн'':15B,33C ''однак'':103C ''онлайн'':60C ''оригина