INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqs51q0079ukta0udlikec','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'27 марта в Москве открываются флагманские бутики Maag – вместо ушедшей эпохи Zara','В крупных столичных торговых центрах уже завтра, 27 марта, на месте флагманских магазинов Zara открываются бутики под названием «Maag».','596-27-marta-v-moskve-otkryvajutsja-flagmanskie-butiki-maag-vmesto-ushedshej-jepohi-zara','[{"html":"В крупных столичных торговых центрах уже завтра, 27 марта, на месте флагманских магазинов Zara открываются бутики под названием «Maag». Стоит отметить, что массмаркет сохранил те же ценовые диапазоны, что и его предшественник.","type":"paragraph"},{"html":"<strong><u>Что стоит знать о новом бренде?</u></strong>","type":"paragraph"},{"html":"<em>- Бренд «</em><em>Maag</em><em>» принадлежит ливанской группе компаний Daher Group, которая никоим образом не относится к бренду </em><em>Zara</em>","type":"paragraph"},{"html":"<em>- Большая часть вещей отшита в Турции, и малая в Камбоджи, Пакистане и Китае</em>","type":"paragraph"},{"html":"<em>- Новые владельцы сохранили интерьер </em><em>Zara</em><em>, изменив лишь расположения зон детского, мужского и женского отделов</em>","type":"paragraph"},{"html":"<em>- В </em><em>Maag</em> <em>вы можете приобрести базовые луки от футболок и маек до брюк, костюмов и верхней одежды. Бренд отвел особое внимание одежде из хлопка, денима, вискозы, органзы и экокожи.</em>","type":"paragraph"},{"html":"В ближайшее время в России откроется более 60 магазинов Maag. Будем следить за обновлениями ассортимента, а также ждать открытия «преемников» брендам Bershka и Pull&amp;Bear. На их месте все та же компания Daher Group откроет флагманские бутики под названием Inditex (замена Bershka) и Ecru (замена Pull&amp;Bear).","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqs4or0077uktad71bb6v4"},{"mediaId":"cmrmqs50d0078uktaxeqj3shc"}]}]'::jsonb,'cmrmqs4bz0076uktad5mb823j','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2023-04-26T06:00:00.000Z'::timestamp,NULL,NULL,NULL,596,'/fashion/news-2/596-27-marta-v-moskve-otkryvajutsja-flagmanskie-butiki-maag-vmesto-ushedshej-jepohi-zara.html','2026-07-15T20:59:31.982Z'::timestamp,'2026-07-16T13:57:27.142Z'::timestamp,'''27'':1A,20B,39C ''60'':167C ''bear'':184C,206C ''bershka'':181C,201C ''cmrmqs4or0077uktad71bb6v4'':212C ''cmrmqs50d0078uktaxeqj3shc'':214C ''daher'':82C,192C ''ecru'':203C ''galleri'':210C ''group'':83C,193C ''inditex'':199C ''maag'':8A,31B,50C,77C,129C,169C ''paragraph'':65C,74C,93C,109C,126C,158C,208C ''pull'':183C,205C ''zara'':12A,26B,45C,91C,115C ''ассортимент'':174C ''базов'':133C ''ближайш'':161C ''больш'':95C ''бренд'':72C,76C,90C,145C,180C ''брюк'':140C ''буд'':170C ''бутик'':7A,28B,47C,196C ''верхн'':143C ''вещ'':97C ''вискоз'':153C ''владельц'':112C ''вмест'':9A ''вниман'':148C ''врем'':162C ''групп'':80C ''деним'':152C ''детск'':120C ''диапазон'':59C ''ждат'':177C ''женск'':123C ''завтр'':19B,38C ''зам'':200C,204C ''знат'':69C ''зон'':119C ''измен'':116C ''интерьер'':114C ''камбодж'':104C ''кита'':107C ''компан'':81C,191C ''костюм'':141C ''котор'':84C ''крупн'':14B,33C ''ливанск'':79C ''лиш'':117C ''лук'':134C ''магазин'':25B,44C,168C ''маек'':138C ''мал'':102C ''март'':2A,21B,40C ''массмаркет'':54C ''мест'':23B,42C,187C ''может'':131C ''москв'':4A ''мужск'':121C ''назван'':30B,49C,198C ''нико'':85C ''нов'':71C,111C ''обновлен'':173C ''образ'':86C ''одежд'':144C,149C ''органз'':154C ''особ'':147C ''отвел'':146C ''отдел'':124C ''откроет'':165C,194C ''открыва'':5A,27B,46C ''открыт'':178C ''отмет'':52C ''относ'':88C ''отшит'':98C ''пакистан'':105C ''предшественник'':63C ''преемник'':179C ''принадлеж'':78C ''приобрест'':132C ''расположен'':118C ''росс'':164C ''след'':171C ''сохран'':55C,113C ''сто'':51C,68C ''столичн'':15B,34C ''та'':189C ''такж'':176C ''те'':56C ''торгов'':16B,35C ''турц'':100C ''ушедш'':10A ''флагманск'':6A,24B,43C,195C ''футболок'':136C ''хлопк'':151C ''ценов'':58C ''центр'':17B,36C ''част'':96C ''экокож'':156C ''эпох'':11A'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqx2kv00pxukta0hqot325','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'«Alpaca Ollie» о преимуществах российской косметики и предпочтениях наших женщин','Подбор правильной косметической линии для женщины особенно важен и если еще 5 лет назад мы покупали исключительно зарубежные бренды, то сейчас поклонников косметики российского производства становится все больше, как и с','401-alpaca-ollie-o-preimuschestvah-rossijskoj-kosmetiki-i-predpochtenijah-nashih-zhenschin','[{"html":"Подбор правильной косметической линии для женщины особенно важен и если еще 5 лет назад мы покупали исключительно зарубежные бренды, то сейчас поклонников косметики российского производства становится все больше, как и самих косметических брендов, созданных в России. Что особенно важно, большая часть косметики в России натуральная и адаптирована под наш тип кожи, экологию и погодные условия. Мы пообщались с руководителями бренда «Alpaca Ollie» @alpacaollie Беловой Ольгой и Каштановой Олесей и узнали преимущества российской косметики и предпочтения российских женщин, а также как хобби превращается в интересный и прибыльный бизнес.","type":"paragraph"},{"html":"<strong>Esque: Здравствуйте. Расскажите, как на свет появился ваш бренд?</strong>","type":"paragraph"},{"html":"Здравствуйте. История нашего бренда началась с маленькой идеи: под Новый год мы решили сделать оригинальные подарки нашим друзья – бомбочки для ванны. Рецепт был прост: большая часть ингредиентов нашлась на кухне, а недостающие – в ближайшем магазине рукоделия. Мы тогда учились по рецептам из интернета, и, как это не странно, гейзеры с первого раза получились идеальными. Все было красиво упаковано и подарено, а после праздников мы получили столько восторженных отзывов и просьб сделать еще бомбочек, что в какой-то момент решили: может из этого получится интересный проект. Дальше было много обучения (и самостоятельного, и под руководством профессионалов), множество новых идей и переработки старых.","type":"paragraph"},{"html":"<strong>Esque: Почему «Alpaca Ollie»?</strong>","type":"paragraph"},{"html":"Альпака – милое домашнее животное, спокойное, которое хочется погладить, ему легко доверять, как будто бы все время с улыбкой на мордочке. Каждый раз, когда смотришь на них, понимаешь, что мир прекрасен, что нет ничего сложного в том, чтобы просто радоваться жизни. А Ollie – это своеобразное объединение натурального масла (oil), Оли и Олеси.","type":"paragraph"},{"html":"<strong>Esque: В чем основные преимущества косметики перед другими российскими брендами? </strong>","type":"paragraph"},{"html":"Мы используем качественные натуральные масла, избегаем компонентов, которые не пропускает Ecocert и Cosmos, производим косметику с минимальным количеством консервантов. Да, такая косметика не будет храниться годами, как из масс маркета, но нам это и не нужно. Мы за то, чтобы составить идеальный рецепт именно для вашей кожи, учесть все нюансы и пожелания и использовать баночку с кремом до последней капли.","type":"paragraph"},{"html":"<strong>Esque: Ольга, а сколько хранится натуральная косметика?</strong>","type":"paragraph"},{"html":"Так как мы используем безопасные консерванты в минимальных дозировках, то срок годности водосодержащей продукции, до 3 месяцев. Чтобы продукт можно было использовать максимально долго, нужно соблюдать условия хранения: герметично закрытый флакон хранить в темном и прохладном месте. И, конечно же, доставать свое средство шпателем или хотя бы чистыми руками. Про это мы подробно писали в посте «Что убивает косметику?» в нашем инстаграмм-аккаунте.","type":"paragraph"},{"html":"<strong>Esque: А если поговорить о зарубежных брендах, особенно о корейских, которые были очень актуальны среди женской российской аудитории еще несколько лет назад, то какие общие плюсы вы можете назвать российского производства? </strong>","type":"paragraph"},{"html":"Во-первых, нужно учитывать, что косметика разных стран в первую очередь адаптирована под издержки экологии и как следствие дефицита конкретных микроэлементов. Почему кореянки уделяют такое большое внимание очищению? Ответ прост: плохая окружающая среда, повышенная влажность летом и сухие пыльные ветра зимой. Соответственно в уходе в первую очередь нужно учитывать этническое влияние и это не только климат, подход нужен разный. Но в корейской косметике, есть очень хорошие универсальные средства. Во-вторых, при подборе косметики надо опираться именно на свои особенности кожи, проблемы, которые следует скорректировать, все нюансы нужно учесть, не только состав, но и как средство наносится.","type":"paragraph"},{"html":"Из общих плюсов: сейчас стало появляться много косметики с натуральными маслами и экстрактами, не всегда правда остальные компоненты безвредны, но такая тенденция не может не радовать.","type":"paragraph"},{"html":"<strong>Esque: Какая продукция у вас в ассортименте? И что пользуется наибольшим спросом? </strong>","type":"paragraph"},{"html":"Всю нашу продукцию можно разделить на 3 большие группы: уходовая косметика для лица и тела, spa-продукты и свечи. Популярность зависит от сезона и праздников: под новый год и гендерные праздники к нам приходят за универсальными подарками из линейки spa-продуктов и свечей, а в обычное – наши покупатели возвращаются за новой порцией пенки для умывания и ежедневным кремом по индивидуальному рецепту.","type":"paragraph"},{"html":"<strong>Esque: Основные затраты в производстве косметики уходят на сырье или оборудование? Если говорить о конкурентах, то на чем важном экономят бренды? </strong>","type":"paragraph"},{"html":"В основном на сырье, с начала 2022 года очень выросли цены на масла и активные компоненты.","type":"paragraph"},{"html":"Если говорить о крупных брендах, то экономия идет за счет крупных масштабов закупок сырья, оптовые закупки всегда дешевле. Но, с другой стороны, чтобы сохранить продукцию свежей на протяжении длительного времени, используются совсем другие системы консервации, да и сами ингредиенты. Например, нерафинированные масла быстро окисляются, экстракты плохо переносят перепады температуры, значит, такие компоненты нельзя добавлять в продукт, который может долго лежать на полке в магазине. Очень часто для более приятных тактильных ощущений добавляют минеральные масла, которые не просто не помогают коже, но и вредят.","type":"paragraph"},{"html":"<strong>Esque: Планируете расширять ассортимент? </strong>","type":"paragraph"},{"html":"Расширение ассортимента – это наша волнующая тема. Постоянно хочется придумывать что-то уникальное, улучшать и делать по-новому. Поэтому в запасе у нас еще очень много идей, которые скорее всего будут представлены в ближайшее время.","type":"paragraph"},{"html":"<strong>Esque: В вашем инстаграмм сказано, что вы составляете рецепты индивидуально под потребности кожи. Как это происходит? </strong>","type":"paragraph"},{"html":"Да, индивидуальный подход для нас концептуально важен. Для начала мы просим всех наших новых клиентов заполнить небольшую анкету, главная цель которой определить тип кожи и узнать особенности, на которые стоит обратить внимание. Например, если человек склонен к аллергии, то мы исключим эфирные масла. Цель – чтобы конечный продукт максимально соответствовал всем вашим потребностям, а после мы собираем полноценную обратную связь, чтобы в дальнейшем, если это понадобится, можно было скорректировать рецепт.","type":"paragraph"},{"html":"<strong>Esque: Какие основные проблемы с кожей могут решить уходовые средства? Реально ли избавиться от морщин?</strong>","type":"paragraph"},{"html":"Тусклость, обезвоженность, недостаток питания, высыпания, купероз, расширенные поры, излишняя выработка себума, пигментация. Практически любую проблему может решить правильно подобранная косметика и сбалансированный образ жизни. Что касается морщин: от мелких, связанных с недостатком питания и влаги избавиться реально, а также возможно предотвратить появление глубоких морщин и заломов с помощью средств с активными компонентами, нацеленными именно на решение этой проблемы.","type":"paragraph"},{"html":"<strong>Esque: Пару советов нашим читательницам. </strong>","type":"paragraph"},{"html":"Нет универсальных средств, если это подошло вашей подружке, не факт, что подойдет вам. Всегда ориентируйтесь на собственные ощущения и потребности. И конечно же, читайте состав, это очень важно, так как многие скрытые ингредиенты в составе могут иметь отрицательный накопительный эффект.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqx24e00pvukta9y0g5b33"},{"mediaId":"cmrmqx2ix00pwukta63ofpsz3"}]}]'::jsonb,'cmrmqx1i200puukta5zfrfg57','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyz0000akwtaq6w9733r','cmrmpdrom0000sstarkqxwts4','2022-02-28T06:00:00.000Z'::timestamp,NULL,NULL,NULL,401,'/beauty/mnenie/401-alpaca-ollie-o-preimuschestvah-rossijskoj-kosmetiki-i-predpochtenijah-nashih-zhenschin.html','2026-07-15T21:03:22.063Z'::timestamp,'2026-07-16T13:59:46.205Z'::timestamp,'''2022'':733C ''3'':406C,643C ''5'':22B,48C ''alpaca'':1A,97C,246C ''alpacaolli'':99C ''cmrmqx24e00pvukta9y0g5b33'':1101C ''cmrmqx2ix00pwukta63ofpsz3'':1103C ''cosmos'':330C ''ecocert'':328C ''esqu'':127C,244C,305C,381C,458C,622C,703C,832C,878C,969C,1048C ''galleri'':1099C ''oil'':298C ''olli'':2A,98C,247C,292C ''paragraph'':125C,137C,242C,249C,303C,316C,379C,389C,456C,490C,591C,620C,635C,701C,725C,744C,830C,837C,876C,895C,967C,985C,1046C,1054C,1097C ''spa'':653C,678C ''spa-продукт'':652C,677C ''адаптирова'':83C,504C ''аккаунт'':454C ''активн'':741C,1037C ''актуальн'':471C ''аллерг'':934C ''альпак'':251C ''анкет'':914C ''ассортимент'':628C,835C,840C ''аудитор'':475C ''баночк'':372C ''безвредн'':611C ''безопасн'':395C ''белов'':100C ''бизнес'':123C ''ближайш'':172C,873C ''больш'':76C,163C,518C,644C ''бомбочек'':211C ''бом