INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr04fz00yluktarkkbh430','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Такая «Эйфория». Как сериал помог обществу раскрыть себя?','Сериал, который помог многим раскрыть себя и понять других.Сегодня мы поговорим о нашумевшем сериале Эйфория, время при просмотре которого мчится со скоростью света.','319-takaja-jejforija-kak-serial-pomog-obschestvu-raskryt-sebja','[{"html":"Сериал, который помог многим раскрыть себя и понять других.","type":"paragraph"},{"html":"Сегодня мы поговорим о нашумевшем сериале Эйфория, время при просмотре которого мчится со скоростью света. И вот нас уже ждет второй специальный эпизод сериала. Но сначала давайте вспомним, о чем был первый сезон.","type":"paragraph"},{"html":"Мы знакомимся с Ру Беннет – 17-летней школьницей, которая только что вернулась из длительного лечения в наркологической больнице. Весь сериал она пытается жить нормальной, обычной жизнью, как у ее родных, которые безумно ее любят и всегда за нее. Но это дается достаточно сложно. Этому не помогает даже ее новая подруга Джулс, которая явно хочет от Ру больше, чем дружбу. Сериал затрагивает самые важные вопросы в подростковом (и не только) периоде: от секса и отношений до гендерной самоидентификации.","type":"paragraph"},{"html":"Критики объявили сериал лучшей школьной драмой, отметив его за дерзость и эффектность.<br /><br /><br />","type":"paragraph"},{"html":"ЭЙФОРИЮ ОДОБРЯЕТ ЛГБТ-СООБЩЕСТВО","type":"paragraph"},{"html":"Конечно, сейчас в каждом втором сериале есть отголоски гендерных историй и представители нетрадиционной ориентации, но именно «Эйфорию» называют самым прорывным сериалом в плане репрезентации людей из ЛГБТ – сообщества. Один из главных персонажей – Джулс, у которой возникают сильные чувства к Ру, как раз относится к этой группе. Да, и сама Ру, сама того не понимая, а может не признавая, выдает все качества девушки нетрадиционной ориентации. «Мне просто неудобно в платьях», - говорит Ру. Ни у кого нет вопросов.","type":"paragraph"},{"html":"Смелость подхода оценил даже Gay Times – один из самых старых и популярных британских журналов для геев и бисексуалов.<br /><br />","type":"paragraph"},{"html":"<b>«Новаторским является сам способ изображения квир-людей, потому что их идентичность не главная черта их характера, — писало издание. — Они сталкиваются с определенными испытаниями, но их сексуальные и гендерные особенности показаны только как дополнительные сложности и никогда не являются ключевым свойством героев».</b>","type":"paragraph"},{"html":"ЭЙФОРИЯ УЧИТ ОТКРЫТО ГОВОРИТЬ О МЕНТАЛЬНОМ ЗДОРОВЬЕ","type":"paragraph"},{"html":"Пока мы только учимся выпускать сериалы о самообразовании и воспитании, в Америке уже давно все решено. Эйфория, как раз один из таких сериалов. У каждого героя своя история: Ру изначально родилась в нездоровой атмосфере, и абъюзерские отношения с родителями дали о себе знать. Джулс пережила тяжелую травму в детстве и в моменте занимается сексом с взрослыми мужчинами и наносит себе раны: и душевные, и физические. Все герои «Эйфории» выходят далеко за рамки пубертатного бунта. Каждый из них борется со своими внутренними комплексами, триггерами и зависимостями.","type":"paragraph"},{"html":"ЭЙФОРИЯ ПОКАЗАЛА НОВУЮ МОДУ<br />Запросы «Лучшие образы Ру», «Макияж как у Джулс» - одни из популярных после выхода сериала. Рекламная компания и маркетинг неплохо поработали, и поэтому каждый из нас смотрел хотя бы одну серию. «Эйфория» уже вошла в список самых стильных сериалов. Художнику по костюмам Хайди Бивенс удалось передать аутентичный стиль поколения и создать долгоиграющий тренд, которым вдохновляются сейчас все: от подростков в Instagram до дизайнеров Moschino.","type":"paragraph"},{"html":"Кстати, мода на глиттер, стразы и яркие стрелки пошла именно из этого сериала и точно продержится с нами целый 2021. Так что не спешите убирать любимую акцентную косметику.","type":"paragraph"},{"html":"ЧЕГО ЖДАТЬ ОТ ВТОРОГО СЕЗОНА?","type":"paragraph"},{"html":"Первый сезон закончился падением Ру на землю под песню «ALL OF US». Ру, ты что, умерла?","type":"paragraph"},{"html":"Вопросов гораздо больше, чем ответов. А точнее, их вообще нет. <br />Набираемся терпения)","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmr047s00yjuktaxomzgaqe"},{"mediaId":"cmrmr04e900ykukta0fzcnoy2"}]}]'::jsonb,'cmrmr03pj00yiuktaua0xlbhc','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz6g000dkwtai45m48bj','cmrmpdrom0000sstarkqxwts4','2021-04-19T06:00:00.000Z'::timestamp,NULL,NULL,NULL,319,'/sobytija/kino/319-takaja-jejforija-kak-serial-pomog-obschestvu-raskryt-sebja.html','2026-07-15T21:05:44.447Z'::timestamp,'2026-07-16T14:00:59.365Z'::timestamp,'''17'':85C ''2021'':515C ''cmrmr047s00yjuktaxomzgaqe'':571C ''cmrmr04e900ykukta0fzcnoy2'':573C ''galleri'':569C ''gay'':266C ''instagram'':489C ''moschino'':492C ''paragraph'':42C,78C,158C,173C,181C,260C,281C,326C,336C,424C,494C,525C,533C,552C,567C ''time'':267C ''us'':546C ''абъюзерск'':373C ''акцентн'':522C ''америк'':349C ''атмосфер'':371C ''аутентичн'':475C ''безумн'':111C ''беннет'':84C ''бивенс'':472C ''бисексуал'':279C ''больниц'':97C ''борет'':415C ''британск'':274C ''бунт'':411C ''важн'':142C ''вдохновля'':483C ''ве'':98C ''вернул'':91C ''взросл'':393C ''внутрен'':418C ''возника'':218C ''вообщ'':562C ''вопрос'':143C,258C,554C ''воспитан'':347C ''вошл'':462C ''врем'':24B,51C ''вспомн'':71C ''втор'':64C,187C,530C ''выда'':241C ''выпуска'':342C ''выход'':406C,442C ''ге'':277C ''гендерн'':155C,191C,311C ''геро'':324C,363C,404C ''главн'':213C,296C ''глиттер'':499C ''говор'':252C,331C ''горазд'':555C ''групп'':228C ''дава'':70C ''давн'':351C ''дает'':120C ''дал'':377C ''далек'':407C ''девушк'':244C ''дерзост'':169C ''детств'':386C ''джулс'':130C,215C,381C,437C ''дизайнер'':491C ''длительн'':93C ''до