INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqvlv400laukta8j8zqznp','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Наташа Савинова: "Моделинг - это мой "билет в будущее"','Жизнь полна неожиданных сюрпризов и как она сложится, никто не знает.','438-natasha-savinova-modeling-jeto-moj-bilet-v-buduschee','[{"html":"<strong>Жизнь полна неожиданных сюрпризов и как она сложится, никто не знает. Наташа Савинова из города Киров, возможно, в будущем врач, а возможно, мы не раз еще увидим ее на российских и даже зарубежных подиумах. Главное, заниматься любимым делом, которое предназначено тебе судьбой.</strong>","type":"paragraph"},{"html":"<strong>Esque.kids</strong><strong>:</strong> Наташа, здравствуй. Ощущаешь приход весны?","type":"paragraph"},{"html":"<strong>Наташа:</strong> Здравствуйте! Я думаю, каждый ощущает приход весны. Лично у меня это - прилив энергии и бодрости, ну и хорошее настроение.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Ты уже скоро заканчиваешь школу. Размышляла о будущем?","type":"paragraph"},{"html":"<strong>Наташа: </strong>Сейчас я заканчиваю обучение в девятом классе, но пока не определилась с будущей профессией.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>: </strong>Твои родители врачи и учишься ты в школе с медицинским уклоном, но свою жизнь ты хочешь связать с моделингом?","type":"paragraph"},{"html":"<strong>Наташа: </strong>Несмотря на то, что мои родители - врачи, эта профессия меня не очень привлекает. А в моделинге я чувствую себя на своем месте.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>: </strong>В каких показах уже принимала участие?","type":"paragraph"},{"html":"<strong>Наташа: </strong>Я принимала участие во множестве показов, проводимых в моем родном городе Кирове, организованных агентством \"Viva Models\", моделью которого я являюсь. Также в конкурсах в России: в Нижнем Новгороде, Ижевске, Санкт- Петербурге. Особенно хочется отметить \"Star Step\" (Cочи) и \"Fashion bitva\" ( Москва), где я была удостоена звания \"Лучшая подиумная модель\". А также конкурсы в Чехии \" Pearl of Europe\" и показы в Германии в рамках творческого проекта \"Встречи на Эльбе \".","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>: </strong>Как все же возможный будущий врач и модель, скажи свое мнение о медицинской одежде.","type":"paragraph"},{"html":"<strong>Наташа: </strong>Я думаю, медицинская одежда вполне соответствует образу врачей, особенно мне нравится форма специалистов Скорой помощи.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>: </strong>Что можно было бы в ней изменить?","type":"paragraph"},{"html":"<strong>Наташа:</strong> Мне кажется, в одежде медицинских работников нужно доработать некоторые нюансы в плане комфорта. По опыту работы родителей, я знаю, как тяжело долгое время находиться в спецодежде, предназначенной для работы в условиях пандемии.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> А если говорить о моде в целом в России? Она есть?","type":"paragraph"},{"html":"<strong>Наташа: </strong>Безусловно, мода в России есть. Несмотря на то, что принято думать, что основные модные тенденции приходят из-за рубежа, у нас много творческих и талантливых дизайнеров одежды и Россия ещё \"скажет\" свое слово в мире моды.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Твои любимые российские дизайнеры?","type":"paragraph"},{"html":"<strong>Наташа: </strong>На сегодняшний день у меня нет предпочтений между дизайнерами или брендами, в одежде я люблю простоту, комфорт и лёгкость.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Какой должна быть подиумная модель? Без чего нельзя на подиуме?","type":"paragraph"},{"html":"<strong>Наташа: </strong>Подиумная модель помимо основных профессиональных требований, должна быть выносливой: множественные примерки, порой длительная работа с визажистами и парикмахерами по образу, не всегда удобная и в размер обувь, репетиции и строгий режим дня. Немало трудностей нужно преодолеть на пути к своему успеху, тогда все получится.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Наташа, и пару слов нашим читателям.","type":"paragraph"},{"html":"<strong>Наташа: </strong>Каждому желаю найти свой путь, хотя, возможно, придется многое перепробовать. Лично я считаю, что моделинг - это мой \"билет в будущее. Главное помнить, что нужно стремиться к цели и можно добиться всего, ведь зависит все от нас самих!","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqvldz00l8uktaqmxm38v9"},{"mediaId":"cmrmqvlss00l9uktahu07vwvt"}]}]'::jsonb,'cmrmqvkvo00l7uktagxhe5f6t','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-04-25T06:00:00.000Z'::timestamp,NULL,NULL,NULL,438,'/esquekids/obrazovanie-ek/438-natasha-savinova-modeling-jeto-moj-bilet-v-buduschee.html','2026-07-15T21:02:13.744Z'::timestamp,'2026-07-16T13:59:14.844Z'::timestamp,'''bitva'':229C ''cmrmqvldz00l8uktaqmxm38v9'':553C ''cmrmqvlss00l9uktahu07vwvt'':555C ''cоч'':226C ''esqu'':97C,128C,178C,261C,299C,347C,404C,436C,499C ''esque.kids'':65C ''europ'':246C ''fashion'':228C ''galleri'':551C ''kid'':98C,129C,179C,262C,300C,348C,405C,437C,500C ''model'':205C ''paragraph'':63C,72C,95C,108C,126C,150C,176C,187C,259C,278C,297C,309C,345C,361C,402C,411C,434C,449C,497C,508C,549C ''pearl'':244C ''star'':224C ''step'':225C ''viva'':204C