INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqxfs500qluktakzo12fvp','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Вся правда о марафонах желаний. Почему люди хотят получить волшебную таблетку?','Увидеть падающую звезду с неба или сесть между двумя тезками — непростая задача.','395-vsja-pravda-o-marafonah-zhelanij-pochemu-ljudi-hotjat-poluchit-volshebnuju-tabletku','[{"html":"Увидеть падающую звезду с неба или сесть между двумя тезками — непростая задача. На замену привычным способам загадывания желаний пришли инстаграм-марафоны, прохождение которых порой стоит не только времени, но и денег. Блогеры один за другим выпускают собственные инфопродукты и обещают исполнить любые мечты: от увеличения заработка и привлечения счастья в семейную жизнь до излечения от болезней. Несмотря на большое количество негативных отзывов, марафоны не теряют свою популярность и находят довольных покупателей, готовых приобретать новые продукты. О причинах заинтересованности общества в марафонах и правильной постановке целей рассказала семейный психолог и коуч Марина Яхницкая @marisabel_ya.","type":"paragraph"},{"html":"<i>«Долгое время в России люди воспитывались на идее служения государству, а желание хотеть что-то для себя осуждалось. Тот, кто выделялся из массы, подвергался наказанию. Собственные желания в момент импульса пресекаются «внутренним критиком» в виде установок, ограничивающих убеждений, основанных на страхе» — утверждает психолог.</i>","type":"paragraph"},{"html":"Некоторые люди посвящают свою жизнь близким: детям, родителям, мужьям или женам. В таком случае мысли о своих интересах вызывают чувство стыда, и человек начинает преуменьшать их важность.","type":"paragraph"},{"html":"Уклониться от привычного ритма жизни может быть не только трудно, но и страшно. Кажется, что лучше заниматься привычными делами и не тратить время на путь к исполнению мечты, если нет уверенности в ее достижении.","type":"paragraph"},{"html":"<i>«Наш мозг не различает — происходило событие или ему только предстоит произойти. Проживая исполнение желания или свой самый большой страх в мыслях, человек формирует «опыт будущего». Его мозг убеждён, что это с ним уже было в реальности, поэтому действия в сторону исполнения желания совершаются легче» — отмечает Марина.</i>","type":"paragraph"},{"html":"<b>Какие люди более склонны к прохождению марафонов?</b>","type":"paragraph"},{"html":"При создании марафонов желаний блогеры ориентируются на определенную аудиторию, которая с большей вероятностью захочет принять участие. Как правило, подобные курсы привлекают внимание людей, которые не готовы тратить много времени на достижение желаемого. Им хочется как можно быстрее приблизиться к мечте с чужой помощью.","type":"paragraph"},{"html":"<i>«Интерес проявляют люди, зависимые от чужого мнения. Они склонны уходить от ответственности и выбирают идти свой путь с проводником, знающим, как это сделать легче, лучше и быстрее» — полагает Марина Яхницкая.</i>","type":"paragraph"},{"html":"Также человек может принять участие в марафоне «за компанию». Нам проще дисциплинировать себя и не лениться, если наши близкие заняты тем же делом. Обмен впечатлениями с друзьями от прохождения курса может не только помочь рассмотреть предоставленную информацию с разных сторон, но и поднять дух соперничества.","type":"paragraph"},{"html":"<i>«Многие знакомые прошли марафон, и мне стало интересно. Также я увидела в Инстаграме положительные отзывы. После прохождения осталось послевкусие, как от какой-то массовой мотивационной книги. Вроде и так все это знаешь, но настроение поднялось» — <u>рассказывает участница марафона желаний Анастасия Преснякова @a_presnyakova.</u></i>","type":"paragraph"},{"html":"Одной из причин, по которой человек может обратить внимание на марафон, является желание стать такими же успешными, как любимый блогер. Развитие своей индивидуальности уходит на второй план. Такой подход не дает реально оценить свои возможности и мешает получить положительные эмоции от прохождения курса.","type":"paragraph"},{"html":"<i>«Марафоны желаний «подращивают» те части личности, которые у человека находятся в недостатке. Курсы рассчитаны на психологически здоровых людей, которым необходимо уравновесить материальный и духовный мир» — дополняет психолог.</i>","type":"paragraph"},{"html":"Также покупка курса мотивирует находить время на выполнения заданий, ведь после траты денег человек серьезнее относится к инфопродукту и стремится извлечь из него как можно больше пользы.","type":"paragraph"},{"html":"<b>Вред и польза марафонов желаний</b>","type":"paragraph"},{"html":"Во время прохождения марафона человек берет свою жизнь на себя. Он анализирует свои поступки и понимает, в результате каких действий или бездействий оказался в этой точке своей жизни. Ему становится проще ставить цели и достигать их. Однако вреда от прохождения курса может быть больше, чем пользы.","type":"paragraph"},{"html":"<i>«Вред может быть в том случае, если человек затрагивает интересы других и жаждет получить желаемое любой ценой. Сюда можно отнести и огромные кредиты на исполнение желаний, которые нет возможности выплачивать. Или решение выйти замуж за первого встречного, потому что дата исполнения желания уже проставлена» — разъясняет психолог.</i>","type":"paragraph"},{"html":"Важно понимать, что ни один марафон не способен решить проблемы человека, если тот не перейдет от размышлений об успешном будущем к действиям. Также есть ситуации, которые невозможно исправить, даже если очень постараться.","type":"paragraph"},{"html":"<i>«Платную часть курса я приобрела после рассказа про ребенка, победившего аутизм. Марафон дал надежду, которая росла в процессе его прохождения. Ты все время выполняешь задания и находишься при деле. При этом в голове лишь мысль о том, что вселенная услышит и поможет. Увы, чуда не произошло. Никакой марафон не исцелит больного ребенка. Взывание к вселенной и колесо баланса не помогут. Вот составление ближайших целей и планов можно считать полезным. В других марафонах участие я не принимала, в чудеса больше не верю» — <u>делится участница марафона желаний Юлия Маляренко @jyly1979.</u></i>","type":"paragraph"},{"html":"<b>Как мечтать и получать желаемое?</b>","type":"paragraph"},{"html":"Достигать желаемого помогают не мечты, а цели. Они не являются одним и тем же понятием, однако имеют схожие черты. Марафоны желаний предлагают составлять список целей на ближайшее время. Задание приносит удовольствие участникам, о чем они охотно пишут в отзывах. При написании желаний необходимо следить за порядком слов, поскольку от его перемены может поменяться смысл предложения.","type":"paragraph"},{"html":"Подводя итоги, Марина Яхницкая отмечает: «Цель — это точно что-то реальное и ощутимое, к ней необходимо двигаться самому шаг за шагом. Мечта кажется чем-то нереальным, но очень желаемым. Этим обязательно кто-то обладает, поэтому нереальной мечта является до того момента, пока ты не узнал, как другой человек это получил. К ним лучше двигаться через легкость, разрешая исполниться самым неожиданным образом».","type":"paragraph"},{"html":"Автор: Анастасия Федосеенко","type":"paragraph"},{"type":"image","mediaId":"cmrmqxfp200qkuktau8id5e6n"}]'::jsonb,'cmrmqxelw00qjuktacvd6m8yv','cmrm8kzpw000mkwtaocyn5161','cmrm8kzra000okwtaqek3edwq','cmrmpdrom0000sstarkqxwts4','2022-01-20T06:00:00.000Z'::timestamp,NULL,NULL,NULL,395,'/psihologija/samosovershenstvovanie/395-vsja-pravda-o-marafonah-zhelanij-pochemu-ljudi-hotjat-poluchit-volshebnuju-tabletku.html','2026-07-15T21:03:39.173Z'::timestamp,'2026-07-16T13:59:51.725Z'::timestamp,'''cmrmqxfp200qkuktau8id5e6n'':948C ''imag'':946C ''jyly1979'':803C ''marisabel'':117C ''paragraph'':120C,167C,197C,234C,283C,293C,339C,372C,420C,467C,513C,543C,573C,581C,630C,679C,714C,805C,813C,871C,938C,944C ''