82C ''сто'':49C ''сторон'':275C,413C ''страх'':163C,254C ''страшн'':211C ''стрем'':564C ''стыд'':189C ''схож'':832C ''счаст'':73C ''счита'':783C ''сюд'':649C ''таблетк'':11A ''так'':181C,483C ''такж'':374C,430C,545C,703C ''те'':518C ''тезк'':21B,33C ''теря'':89C ''точк'':608C ''точн'':880C ''трат'':220C,321C,556C ''трудн'':208C ''убежд'':263C ''убежден'':160C ''ув'':758C ''увеличен'':69C ''уверен'':229C ''увидел'':432C ''увидет'':12B,24C ''удовольств'':845C ''узна'':920C ''уклон'':199C ''уравновес'':535C ''услыш'':755C ''успешн'':485C,699C ''установок'':158C ''утвержда'':164C ''уход'':350C,492C ''участ'':310C,378C,788C ''участник'':846C ''участниц'':459C,798C ''федосеенк'':942C ''формир'':258C ''хот'':8A ''хотет'':134C ''хочет'':328C ''цел'':109C,615C,779C,821C,839C,878C ''цен'':648C ''част'':519C,717C ''человек'':191C,257C,375C,474C,523C,558C,587C,639C,691C,923C ''чем-т'':897C ''черт'':833C ''что-т'':135C,881C ''чувств'':188C ''чуд'':759C ''чудес'':793C ''чуж'':336C,346C ''шаг'':892C,894C ''эмоц'':508C ''эт'':265C,362C,453C,879C,904C,924C ''юл'':801C ''явля'':480C,824C,913C ''яхницк'':116C,370C,876C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqeps6003ipotaxxwzwqiv','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Череда ярких культурных событий ждет гостей ВДНХ на неделе восточной культуры  «Караван Парад»','С 27 июня по 3 июля павильон Казахстан на ВДНХ станет эпицентром яркой культурной жизни столицы, принимая в своих стенах «Караван Парад» - уникальное событие, которое погрузит гостей в многогранную и многослойную культур','661-chereda-jarkih-kulturnyh-sobytij-zhdet-gostej-vdnh-na-nedele-vostochnoj-kultury-karavan-parad','[{"html":"<b>Череда ярких культурных событий ждет гостей ВДНХ на неделе восточной культуры «Караван Парад» </b><br /><br /><i>С 27 июня по 3 июля павильон \"Казахстан\" на ВДНХ станет эпицентром яркой культурной жизни столицы, принимая в своих стенах «Караван Парад» - уникальное событие, которое погрузит гостей в многогранную и многослойную культуру и искусство тюркских народов России и Центральной Азии.</i><i><br /></i><br />В рамках «Караван Парада» в течение недели гостей ожидает насыщенная программа. Ежедневно будет работать невероятный маркет дизайнеров «Тюбетейка Fashion», с разнообразными современными коллекциями дизайнеров с элементами этностиля, ставшей востребованной далеко за пределами тюркских стран и республик и выставка-экспозиция тюркского искусства.","type":"paragraph"},{"html":"Организаторы также приготовили деловую программу для эффективного нетворкинга: круглые столы с представителями республик, незаурядные мастер-классы, в числе которых урок по мультипликации с восточным колоритом, в итоге которого, самими участниками будет создан настоящий мультфильм!И, разумеется, кульминацией станут красочные культурные мероприятия – закрытый показ мод «Тюбетейка Fashion» от дизайнеров из Казахстана, Якутии, Азербайджана, Татарстана, Кыргызстана, Узбекистана, праздничный концерт «Слово Музыканта» с участием ведущей Адель Старостиной и юных финалистов громких музыкальных телепроектов: «Голос. Дети», «Х-фактор», «Ты - Первый», «Фабрика звезд». А также пройдет анонсирование первого этапа конкурса красоты Мисс «Жемчужина востока», финал которого пройдет здесь же, в павильоне «Казахстан», осенью 2024 года, все участницы получат подарки и ценные призы, а его победительница отправится на международный конкурс «Мисс Дубай 2024» уже в ноябре этого же года.<br /><br />«Караван Парад» несет в себе миссию консолидации тюркских народов России и народов Центральной Азии, а цель мероприятия - в популяризации знаний о цивилизации и культуре тюркских народов России и народов Центральной Азии, а также создание платформы для межкультурного диалога, укрепление экономических, культурных и социальных связей.","type":"paragraph"},{"html":"<br /><b>Подробная программа «Караван Парада»:</b>","type":"paragraph"},{"html":"<b>27 июня</b>","type":"paragraph"},{"html":"<i>11:00 - 20:00 </i>Открытие маркета дизайнеров «Тюбетейка Fashion» - актуальные коллекции выставляют дизайнеры из Казахстана, Якутии, Азербайджана, Татарстана, Кыргызстана, Узбекистана. Также открывается выставка-экспозиция \"Платья, сошедшие с картин\", которая будет радовать глаз в течение дня и всей недели.","type":"paragraph"},{"html":"<i>13:00 </i>Торжественное открытие с представителями казахской и других диаспор.","type":"paragraph"},{"html":"<i>14:00 </i>Круглый стол на актуальные темы. Среди спикеров: Б<b>айрамов Шаиг Якуб Оглы, Альфия Амирова, Саниям Коваль, Руслан Мигранов, Ольга Иркли, Диана Кобалава, Ингрид, Александр (ТВ шанс), Антон Алфер, Калиста, Анатолий Вовк, Беатрис Малахова </b>и другие.","type":"paragraph"},{"html":"В рамках круглого стола состоится небольшая культурная программа, в которой примет участие известная оперная певица <b>Гульнара Куспакова.</b>","type":"paragraph"},{"html":"<b>28-29 июня</b>","type":"paragraph"},{"html":"<i>11:00 - 20:00 </i>Продолжение работы маркета дизайнеров и выставки-экспозиции \"Платья, сошедшие с картин\"","type":"paragraph"},{"html":"<b>29 июня</b>","type":"paragraph"},{"html":"<i>14:00 – 16:00 </i>Мастер-класс от знаменитой мультипликационной мастерской анимационного сериала «Цветняшки» позволит проявить себя в качестве мультипликатора и создать свой собственный авторский мультфильм! Эта мастерская посвящена легендарным героям народного эпоса.","type":"paragraph"},{"html":"<b>30 июня </b>","type":"paragraph"},{"html":"11:00 - 20:00 Продолжение маркета «Тюбетейка Fashion» и проекта «Платья, сошедшие с картин».","type":"paragraph"},{"html":"17:00 – 19:00 *Закрытый модный показ «Тюбетейка Fashion» от дизайнеров из Казахстана, Якутии, Азербайджана, Татарстана, Кыргызстана, Узбекистана. В показах участвуют модели агентства «Slava Models» <b>Аэлиты Качаровой </b>и «Юная Мисс Москва 2018» – <b>Кожасаева Дина.</b> Режиссер fashion-шоу – <b>Дарья Мельникова,</b> известна по показам на таким масштабных проектах, как «Уникальная Россия» в Гостином дворе на ВДНХ.","type":"paragraph"},{"html":"<i><u>(*Вход строго по приглашениям от организаторов)</u></i>","type":"paragraph"},{"html":"<b>01 июля</b>","type":"paragraph"},{"html":"<i>11:00 - 20:00 </i>Продолжение маркета «Тюбетейка Fashion» и экспозиции творческих работ художников.","type":"paragraph"},{"html":"<b>02 июля</b>","type":"paragraph"},{"html":"<i>11:00 - 20:00</i> Продолжение работы маркета дизайнеров и экспозиции «Платья, сошедшие с картин».","type":"paragraph"},{"html":"<i>17:00 </i>Конференция с дизайнерами и экспертами модной индустрии.","type":"paragraph"},{"html":"<b>03 июля</b>","type":"paragraph"},{"html":"<i>11:00 - 20:00 </i>Завершающий день маркета дизайнеров «Тюбетейка Fashion» и спец. проекта «Платья, сошедшие с картин».","type":"paragraph"},{"html":"<i>17:00 – 19:00 </i>Праздничный концерт «Слово музыканта» с участием ведущей <b>Адель Старостиной и Таисии Скомороховой </b>(СТС Кидс) Концерт посвящен семейным ценностям и приурочен «Году Семьи» в России и «Дню семьи, любви и верности», на котором юные таланты (участники популярных телепроектов «Голос. Дети», «Х-фактор», «Ты - Первый», «Фабрика звезд» и других) продемонстрируют вокальные и хореографические номера. Это отличная познакомиться с творчеством и многогранными традициями разных народов.","type":"paragraph"},{"html":"<i>19:00 – 20:00 </i>Торжественное закрытие с вручением дипломов и подарков.<br /><br />Организатором мероприятия выступает АНО «Развитие межнациональных культурных инициатив и искусства» («РАМКИ»).","type":"paragraph"},{"html":"АНО «РАМКИ» - это компания, видящая своей главной задачей - создание единой платформы для межэтнического общения, и поддерживающая сохранение богатых национальных традиций народов России. В частности, она занимается популяризацией культурных ценностей многонационального народа России, разрабатывая и реализуя программы, проекты и мероприятия в области межнациональных культурных инициатив и искусства. Организация создает благоприятные условия для сохранения, возрождения и развития национальных культур и языков народов Российской Федерации. Также она оказывает содействие в реализации национально-культурных прав граждан Российской Федерации, относящих себя к определенным этническим общностям.","type":"paragraph"},{"html":"Не упустите возможность окунуться в атмосферу единения тюркских культур на «Караване Парадов» на ВДНХ!","type":"paragraph"},{"html":"<br /><i>Адрес: пр-т Мира, 119, ВДНХ, Выставочно-торговый центр Республики Казахстан, павильон №11.</i><i><br /></i><i><br /></i><i>АККРЕДИТАЦИЯ +79093406131</i>","type":"paragraph"},{"html":"<i><br /></i><i>Фото предоставлено организаторами</i><br />","type":"paragraph"}]'::jsonb,'cmrmqepql003hpotahif5gg15','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-06-25T06:00:00.000Z'::timestamp,NULL,NULL,NULL,661,'/svetskaja-hronika/661-chereda-jarkih-kulturnyh-sobytij-zhdet-gostej-vdnh-na-nedele-vostochnoj