INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqy05900ryuktac6j6j8dc','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'В Казани состоялся 9 сезон Fashion битвы','5 декабря в Казани в АК Барс Арене прошел региональный этап конкурса дизайнеров FASHION BITVA.За выход в финал боролись 11 дизайнеров из Москвы, Смоленска, Самары, Казани, Пензы, Дмитровграда и республики Марий-Эл.','383-v-kazani-sostojalsja-9-sezon-fashion-bitvy','[{"html":"5 декабря в Казани в АК Барс Арене прошел региональный этап конкурса дизайнеров FASHION BITVA.","type":"paragraph"},{"html":"За выход в финал боролись 11 дизайнеров из Москвы, Смоленска, Самары, Казани, Пензы, Дмитровграда и республики Марий-Эл. Одни представили на суд жюри линейки одежды в двух номинациях: «Год 2031» и «Осень-Зима 2022».","type":"paragraph"},{"html":"Мероприятие открыл внеконкурсный показ детской коллекции одежды «Ловушка для солнца» победительницы 7 сезона Fashion битвы Аллы Желтухиной.","type":"paragraph"},{"html":"Ольга Юдина покорила всех присутствующих коллекциями вечерних платьев - \"IDA\" (детское и взрослое направление), \" Incanto\" и \"Enchanted Gardens\". Каждое платье, включая мельчайшие детали и аксессуары к нему, дизайнер сделала с особым трепетом и своими руками. Ее наряды уникальны и созданы в единственном экземпляре.","type":"paragraph"},{"html":"В номинации «Год 2031» создательницы бренда «Mosya» сестры Лиана Садыкова и Лениза Габделхаковна представили коллекцию одежды из натуральных тканей «Уроборос». Урборос – змея, кусающая свой хвост. Это древнеегипетский символ, обозначающий бесконечность и цикличность всего происходящего в мире, в том числе и модных тенденций.","type":"paragraph"},{"html":"В линейке одежды «Дерзость», продемонстрированной в номинации «Осень-Зима 2022» дизайнеры поэкспериментировали с фактурами тканей и фасонами. Они соединили твид со стёганной тканью, кожу с пальтовой и все разбавили французским кружевом.","type":"paragraph"},{"html":"Кристина Белоглазова увидела моду будущего в объединении прошлого и настоящего. Она продемонстрировала женственные, элегантные и утонченные луки. Для номинации «Осень-Зима 2022» дизайнер создала стильную одежду для повседневной жизни.","type":"paragraph"},{"html":"<i>Дизайнер: Кристина Белоглазова </i>","type":"paragraph"},{"html":"Светлана Черкашина коллекцией одежды в номинации «Год 2031» попыталась обратить внимание на проблему экологии. При помощи ресайклинга и апсайклинга дизайнер дала новую жизнь старым вещам. В процессе создания нарядов Светлана использовала старые джинсы и 6500 металлических пробок. Он вдохновилась образами русских богатарей, гладиаторов и амазонок.","type":"paragraph"},{"html":"<i>Дизайнер: Светана Черкашина</i>","type":"paragraph"},{"html":"В коллекции «Осень-Зима 2022» Светлана Черкашина представила комфортную и тёплую одежду из натуральных тканей: шерсти, хлопка, вискозы, а также уютные пальто и экодубленки в серо-синей цветовой гамме из линейки ее нового бренда \"iNei\".","type":"paragraph"},{"html":"Ольга Соловьева продемонстрировала свое авторское видение на fashion-трикотаж. Одежда Ольги каждой своей мягкой и красивой петелькой способна украсить любую женщину.","type":"paragraph"},{"html":"Евгения Кошкина представила на суд жюри современную одежду для женщин с национальной изюминкой. Для дизайнера важно сохранить традиционные марийские узоры, именно поэтому они являются основой орнаментов используемых в создании нарядов.","type":"paragraph"},{"html":"По мнению Тани Рыжей, fashion-индустрия все больше переходит на производство одежды из переработанных и экологичных материалов. Для создания коллекции «Год 2031» дизайнер использовала остатки ткани, фурнитуры и межлекальных отходов. К каждому образу она также добавила qr-коды, которые все прочнее входят в нашу реальность. В коллекции «Осень-Зима 2022» Таня объединила плащевку с синтепоном и продемонстрировала на подиуме необычную верхнюю одежду.","type":"paragraph"},{"html":"<i>Дизайнер: Таня Рыжая</i>","type":"paragraph"},{"html":"Творческий подход и особенное видение развития модной индустрии Тани Рыжей восхитили не только членов жюри, но и всех присутствующих на мероприятии. Дизайнер безоговорочно стала победителем регионального этапа 9 сезона Fashion битвы. Она отправится представлять свою коллекцию на финальном показе, который пройдет 26-27 февраля в Москве.","type":"paragraph"},{"html":"<em>«Я шла на конкурс за эмоциями, которых так не хватает в моих рабочих буднях. Получила их сполна! До сих пор не верю, что выиграла»,</em> - поделилась Таня Рыжая.","type":"paragraph"},{"html":"Нельзя не отметить, что дизайнеры, принявшие участие в отделении «Детская мода», также поразили своими линейками одежды.","type":"paragraph"},{"html":"Создательница детского бренда «Aniol.Store» Ната Гурская впервые представила коллекцию одежды для подростков, показав в ней своё видение моды будущего. Четкость линий, немного геометрии и необычное сочетание тканей позволили - как объясняет дизайнер - подчеркнуть подростковую фигуру при максимальной закрытости тела. Таким образом, дизайнер сделала акцент на актуальной сегодня тенденции принятия своего тела, которая, как она считает, будет сохраняться и активно поддерживаться следующими поколениями.","type":"paragraph"},{"html":"В номинации «Осень-Зима 2022» Натой были продемонстрированы лаконичные образы в стиле smart casual, выполненные из итальянских тканей премиум-класса. Следуя трендам взрослой моды, дизайнер отдала предпочтение твиду сложного состава, мягкому бархату и натуральным хлопковым тканям, добавив к ним кружево и дорогую фурнитуру.","type":"paragraph"},{"html":"Коллекцией «Год 2031» Елена Миклашевская обратила внимание на время, которое скоротечно и неуловимо. По ее словам, будущее - это и есть время. Оно наступает уже сегодня, и никто не знает, будет ли оно двигать нас вперёд или отбросит назад к первоистокам.","type":"paragraph"},{"html":"В номинации «Осень - зима 2021» дизайнер продемонстрировала одежду для девочек и молодых девочек, которые не боятся и любят экспериментировать смешивать разные стили. Она представила как вечерние наряды, перекликающиеся с casual, так и более повседневные платья и костюмы, дополненные яркими и нестандартными аксессуарами.","type":"paragraph"},{"html":"<i>Дизайнер: Елена Миклашевская </i>","type":"paragraph"},{"html":"Альбина Гилязова дебютировала на подиуме Fashion битвы в качестве дизайнера. Она представила одежду для детей, созданной с одной главной целью – быть удобной.","type":"paragraph"},{"html":"У Дарьи Поляковой мода будущего ассоциируется с космосом. Именно эта тематика была отражена в нарядах дизайнера. В коллекции «Осень-Зима 2022» Дарья теплую и уютную одежду.","type":"paragraph"},{"html":"<i>Дизайнер: Дарья Полякова </i>","type":"paragraph"},{"html":"14-летняя дизайнер покорила сердца членов жюри своими оригинальными луками, в особенности из коллекции «Год 2031». Дарье Поляковой единогласно была присуждена победа в отделении «Детская мода». Она получила возможность пройти стажировку на 4-дневном мастер-классе весной 2022 года в очном или заочном формате на Fashion Department Summit.","type":"paragraph"},{"html":"<em>«Увидев коллекции других дизайнеров во время подготовки к показу, поняла, что шансов на победу у меня мало. У всех конкурентов были очень крутые и креативные наряды. Когда во время награждения услышала свое имя, не смогла поверить в происходящее. От переполняющих эмоций я даже расплакалась»,</em> - рассказала Дарья.","type":"paragraph"},{"html":"Организаторы проекта выражают благодарность членам жюри за компетентное судейство, а также желают всем дизайнеров дальнейших успехов и удачи.","type":"paragraph"},{"html":"<i>Текст: Влада Холкина</i>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqxzba00ruuktagllmu5a5"},{"mediaId":"cmrmqxzm