INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqskif008quktabp5seeua','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'La Boheme Awards 2022 закрыла первый день Neva Fashion Week в Санкт-Петербурге','1-2 октября 2022 на Neva Fashion Week прошёл 12-ый за 6 лет сезон модных показов в Санкт-Петербурге.','585-la-boheme-awards-2022-zakryla-pervyj-den-neva-fashion-week-v-sankt-peterburge','[{"html":"1-2 октября 2022 на Neva Fashion Week прошёл 12-ый за 6 лет сезон модных показов в Санкт-Петербурге. День открытия недели моды завершили 3 мероприятия Москластера — члена Ассоциации «Палата Текстиля и Моды» (г. Санкт-Петербург):<br />Вековой юбилей — 100-летие Журнала «Крестьянка»/krestyanka.ru отметили показом дизайнера Надежды Иншаковой.<br />На исторической родине Журнала «Богема» прошел Гала-показ Журнала «Богема» или Ga-La Boheme Fashion Show, в котором приняли участие 15 дизайнеров и 70 моделей, под музыку Dj Nil.","type":"paragraph"},{"html":"<br />И закрыла день открытия недели моды Премия Журнала «Богема» или La Boheme Awards 2022.<br />В недавнем совместном исследовании европейской версии модного журнала Harper’s BAZAAR Serbia (дата основания — 1867 г.) и Журнала «Богема» модные премии неоднократно назывались авторитетными специалистами важными для поддержки российских дизайнеров и всей текстильной отрасли промышленности.","type":"paragraph"},{"html":"<br />Премия Журнала «Богема» / La Boheme Awards является Системой добровольной сертификации ООО «Москластер» (учредителя Журнала «Богема») и зарегистрирована Федеральным агентством по техническому регулированию и метрологии (Росстандартом) в Едином государственном реестре систем добровольной сертификации Российской Федерации 2 декабря 2019 г., регистрационный № РОСС RU.З2168.04СБА0. Работы по сертификации объектов проводит Международный сертификационный центр Москластера. Премия Журнала «Богема» проходила также в рамках Estet Fashion Week 2018, Неделе трикотажной моды 2021 и Инновационном центре «Сколково» в рамках Moscow Fashion Fair (MFF) 2022.","type":"paragraph"},{"html":"<br /><u><i>В 2022 г. на Neva Fashion Week премия прошла на 4 языках:</i></u> русском, французском, английском и китайском. Ведущим шоу и премии были главный редактор Журнала «Богема» и Журнала «Крестьянка» (krestyanka.ru), дизайнер — участник Всероссийского конкурса дизайнеров «Код Моды» — Владислав Ананишнев @ananishnev, а также лауреаты Премии Журнала «Богема» Сунь Яовэй (SUN YAOWEI), Наталья Касьянова (дизайнер бренда «NK Fashion»).","type":"paragraph"},{"html":"<br />Эксперты в течение всего 2022 года отбирали лучших представителей, соответствующих разработанным нами критериям, и анализировали их проекты в различных номинациях. Представляем лауреатов Премии Журнала «Богема» / La Boheme Awards 2022:<br />Фэшн-шоу – Moscow Fashion Fair, организатор Джабниашвили Кристина;<br />Фэшн-ивент – Neva Fashion Week, организатор Екатерина Иванюшкина;<br />Организатор недели моды – Екатерина Иванюшкина, Neva Fashion Week;<br />Дизайнер – Ольга Малярова (http://malyarovaolga.ru/) ;<br />Модист — Константин Гайдай, http://www.konstantingayday.com/ ;<br />Открытие года – Проект «Московская неделя моды», https://moscowfashion.ru/;<br />Дизайнер с лучшей коллекцией одежды — «Rina Collection» в рамках Московской недели моды 2022, дизайнер Екатерина Иванюшкина;<br />Бутик – АО «Московский ДОМ Моды Вячеслава Зайцева», Генеральный директор Зайцев Егор Вячеславович;","type":"paragraph"},{"html":"Информационный партнер мероприятия:<br />Информационное агентство «РИА Мода», Главный редактор Валентина Кузнецова, https://riamoda.ru/;<br />Intermoda.ru, Главный редактор Дима Бабушкин, https://babushkin.ru/;<br />World Fashion Magazine (WFM), Главный редактор Николай Гавришев;<br />Moda.ru, Главный редактор Антон Алфер;","type":"paragraph"},{"html":"<br />Блогер – Варвара Странже;","type":"paragraph"},{"html":"<br />Художник-гример – Эстель Семенчук;","type":"paragraph"},{"html":"<br />Ведущий телевизионной программы – Зотова Наталья, телеканал ТВЦ;","type":"paragraph"},{"html":"<br />Ведущий мероприятий – Анна Калашникова;","type":"paragraph"},{"html":"<br />Диджей — Dj Nil, Даниил Кизилов;<br />Артист-вокалист — Алиса Мон;","type":"paragraph"},{"html":"<br />Заслуженный деятель в области моды – Зайцев Вячеслав Михайлович, Бренд «SLAVA ZAITSEV»;<br />Директор музейно-выставочного центра — Попова Юлия Анатольевна, директор «Галереи Slava Zaitsev», АО «Московский Дом моды Вячеслава Зайцева»;","type":"paragraph"},{"html":"<br />Студент высшего образовательного учреждения в сфере культуры — Сунь Яовэй / SUN YAOWEI / 孙耀威 .","type":"paragraph"},{"type":"image","mediaId":"cmrmqskh9008puktanbjwolve"}]'::jsonb,'cmrmqsjwy008ouktau8u3ekl1','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2022-11-23T06:00:00.000Z'::timestamp,NULL,NULL,NULL,585,'/fashion/news-2/585-la-boheme-awards-2022-zakryla-pervyj-den-neva-fashion-week-v-sankt-peterburge.html','2026-07-15T20:59:52.023Z'::timestamp,'2026-07-16T13:57:37.340Z'::timestamp,'''-2'':16B,37C ''/)'':373C ''/;'':386C,431C,439C ''/krestyanka.ru'':81C ''1'':15B,36C ''100'':77C ''12'':24B,45C ''15'':109C ''1867'':149C ''2'':207C ''2018'':235C ''2019'':209C ''2021'':239C ''2022'':4A,18B,39C,134C,250C,255C,317C,341C,399C ''3'':62C ''4'':264C ''6'':27B,48C ''70'':112C ''ananishnev'':293C ''award'':3A,133C,178C,340C ''babushkin.ru'':438C ''babushkin.ru/;'':437C ''bazaar'':145C ''bohem'':2A,102C,132C,177C,339C ''cmrmqskh9008puktanbjwolve'':549C ''collect'':393C ''dj'':116C,488C ''estet'':232C ''fair'':248C,347C ''fashion'':9A,21B,42C,103C,233C,247C,259C,309C,346C,355C,366C,441C ''ga'':100C ''ga-la'':99C ''harper'':143C ''imag'':547C ''intermoda.ru'':432C ''krestyanka.ru'':283C ''la'':1A,101C,131C,176C,338C ''magazin'':442C ''malya