INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqxh0u00qouktauvct9xlt','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Как подготовиться к весне правильно. О витаминах','Новогодние праздники прошли и весна уже не за горами.','394-vsja-pravda-o-vitaminah-kak-podgotovitsja-k-vesne-pravilno','[{"html":"Новогодние праздники прошли и весна уже не за горами. Как подготовить свой организм к весне? Пить или не пить витамины? А если пить, то какие? На этот вопрос нам ответит врач-диетолог филиала израильского госпиталя Hadassah Moscow - Анна Коробкина.","type":"paragraph"},{"html":"Витамины – это низкомолекулярные органические соединения с высокой биологической активностью, которые не синтезируются или синтезируются в незначительном количестве. Они необходимы для полноценной работы всех органов нашей системы. В настоящее время известно 30 видов витамин, 20 из них поступают в организм вместе с растительной и животной пищей. Отсутствие витаминов в ежедневном рационе питания приводит к развитию различных заболеваний, авитоминоза, гиповитаминоза. А наш ежедневный ритм жизни и климат способствует этому.","type":"paragraph"},{"html":"В связи с пандемией все очень обеспокоились состоянием своего иммунитета, а ему нужно совсем немного: достаточно нормального сбалансированного питания и чуточку витаминов и микроэлементов.","type":"paragraph"},{"html":"Сразу отмечу, что точно не жирорастворимых (А, Е, К). Это, конечно же, очень полезные биологически активные вещества, безусловно, но в организме у нас есть для них «домик», депо. Поэтому даже небольшой избыток может сказаться негативно и не помочь, а, наоборот, усугубить наше состояние. Это же касается и витамина Д. Сегодня мы наблюдаем ситуацию, когда СМИ раструбили информацию о том, что колекальциферол помогает при короновирусе, а на небезызвестном айхербе можно купить любую дозу, в том числе и 10000 ЕД в 1 таблетке. Я впервые за свою практику увидела случаи гипервитаминоза витамина Д. Такое состояние приводит к отложению кальцинатов в сосудах и органах, нарушая их функцию.","type":"paragraph"},{"html":"<b>Так какие же витамины пить?</b>","type":"paragraph"},{"html":"Лично мне нравятся комплексы для беременных, это мой лайфхак. Именно там содержится отличный состав витаминов группы В, переизбыток которых организму не грозит - то, что будет лишнее - выведется с мочой. И что очень важно, эти витамины содержат большое количество витамина В9. Это именно тот витамин, который много где содержится, но практически не попадает к нам с пищей, очень быстро разрушается. Для жителей мегаполисов и особенно курящим людям, потребуется повышенная доза витамина С - 500-1000 мг в сутки.","type":"paragraph"},{"html":"Что касается необходимости принимать витамин Д, скажу да, если вы раньше его не принимали и не сдавали анализ крови на содержание его в организме - рекомендую принимать в профилактической дозе 2000 ЕД в сутки с контролем его уровня через 3 месяца. Чаще всего я вижу эффект после приема витамина Д, когда он применялся как лекарственный препарат (аквадетрим, вигантол, дэтриферол), колекальциферол зарегистрирован в реестре лекарственных средств, прошел весь путь лекарственного препарата с клиническими исследованиями и поэтому мы точно можем ожидать результат.","type":"paragraph"},{"html":"Что касается бадов, содержащих колекальциферол - у меня доверия нет: они могут быть хорошими, а могут и содержать не ту дозу или «сработать» не так.","type":"paragraph"},{"html":"Бады могу лишь посоветовать, когда речь идет о витаминах В и С. Фирмы Now foods (B50, B-100), Natrol (B complex), Solgar, немецкий Doppel herz (витамины В+Mg или глицин + витамины В) зарекомендовали себя на фармацевтическом рынке, как хорошие и качественные добавки.","type":"paragraph"},{"html":"!!! Не стоит принимать комплекс водорастворимых витаминов (С, группа B, H, pp) вместе с витамином D.","type":"paragraph"},{"html":"!!!! Не забываем, что биологически активные добавки к пищи на то и называются добавками к пище и принимаются либо с едой, либо сразу после нее для лучшего усвоения.","type":"paragraph"}]'::jsonb,'cmrmqxgz400qnuktanmddsngu','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyun0008kwtasfd55v5y','cmrmpdrom0000sstarkqxwts4','2022-01-13T06:00:00.000Z'::timestamp,NULL,NULL,NULL,394,'/beauty/tendencii/394-vsja-pravda-o-vitaminah-kak-podgotovitsja-k-vesne-pravilno.html','2026-07-15T21:03:40.782Z'::timestamp,'2026-07-16T13:59:53.276Z'::timestamp,'''-100'':477C ''-1000'':344C ''1'':236C ''10000'':233C ''20'':93C ''2000'':380C ''3'':389C ''30'':90C ''500'':343C ''b'':476C,479C,513C ''b50'':475C ''complex'':480C ''d'':519C ''doppel'':483C ''food'':474C ''h'':514C ''hadassah'':53C ''herz'':484C ''mg'':487C ''moscow'':54C ''natrol'':478C ''paragraph'':58C,128C,155C,262C,270C,349C,431C,458C,503C,521C,551C ''pp'':515C ''solgar'':481C ''авитоминоз'':116C ''айхерб'':224C ''аквадетр'':406C ''активн'':68C,172C,527C ''ан'':55C ''анализ'':368C ''бад'':435C,460C ''безусловн'':174C ''беремен'':277C ''биологическ'':67C,171C,526C ''больш'':308C ''быстр'':329C ''в9'':311C ''важн'':304C ''ве'':416C ''весн'':4A,12B,21C,31C ''веществ'':173C ''вигантол'':407C ''вид'':91C ''виж'':394C ''витамин'':7A,36C,60C,92C,106C,151C,204C,246C,267C,286C,306C,310C,315C,341C,355C,398C,468C,485C,490C,510C,518C ''вмест'':99C,516C ''водорастворим'':509C ''вопрос'':44C ''вперв'':239C ''врач'':48C ''врач-диетолог'':47C ''врем'':88C ''выведет'':298C ''высок'':66C ''гипервитаминоз'':245C ''гиповитаминоз'':117C ''глицин'':489C ''гор'':16B,25C ''госпитал'':52C ''гроз'':293C ''групп'':287C,512C ''д'':205C,247C,356C,399C ''деп'':184C ''диетолог'':49C ''добавк'':501C,528C,535C ''довер'':440C ''доз'':228C,340C,379C,452C ''домик'':183C ''достаточн'':145C ''дэтриферол'':408C ''е'':164C ''ед'':234C,381C,542C ''ежедневн'':108C,120C ''животн'':103C ''жизн'':122C '