INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr0lvn010iuktatvcuus9n','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Два билета в кино','Порой весной нас настигают абсолютно противоречивые чувства: от любви до раздражения, от радости до ненависти, от вдохновения до депрессии.','304-dva-bileta-v-kino','[{"html":"Порой весной нас настигают абсолютно противоречивые чувства: от любви до раздражения, от радости до ненависти, от вдохновения до депрессии. Спасти от таких эмоциональных наваждений может плитка шоколада, теплая ванна, сеанс с психологом или вдохновляющий фильм. Сегодня перед вами подборка 5 фильмов, которые точно приведут вас в чувства за несколько часов.<br /><br />","type":"paragraph"},{"html":"<u>1. В погоне за счастьем</u><br />Крис Гарднер – отец-одиночка, который воспитывает пятилетнего сына. Он изо всех сил старается сделать детство своего ребенка счастливым, но работая продавцом это сделать очень сложно. Сложно настолько, что нет возможности даже оплатить квартиру. Крис и сын оказываются на улице. <br />","type":"paragraph"},{"html":"Отец, не желая сдаваться, устраивается стажером в броккерскую компанию и рассчитывает получить должность специалиста. Но судьба несправедлива...на протяжении 6 месяцев, что длится стажировка, Крис не получает никаких денег…","type":"paragraph"},{"html":"Сюжет развивается в лучших традициях доброй сказки и показывает, как жизнь уважает сильных и непрогибаемых…<br /><br /><br /><br />","type":"paragraph"},{"html":"<u>2. Ешь, молись, люби </u><br />Фильм, перевернувший умы множества женщин по всему миру. Как многие могут подумать, эта история не только для женщин, мужчинам тоже можно вынести порцию вдохновения. Джулия Робертс играет саму писательницу и автора исходного романа Элизабет Гилберг, которая отправилась в незабываемое путешествие. Оно то и перевернуло всю ее жизнь. За порогом тридцатилетия у Элизабет было все, о чем может мечтать любая женщина в ее возрасте. Отличный просторный дом, верный работящий муж и любимая работа, которая еще и приносит неплохие деньги. Но вместе с этим она постоянно чувствовала, что живет не своей жизнью, и это медленно съедало ее сущность изнутри. В итоге она рассталась с мужем, и, не дождавшись окончания долгого и неприятного бракоразводного процесса, улетела на Бали по заданию своего издателя. Старый и мудрый балийский знахарь предсказал писательнице, что на этом острове она наконец обретет смысл жизни и истинную любовь. Ухх, это интересно...<br /><br /> <br /><u>3. Заплати другому</u>","type":"paragraph"},{"html":"Перед нами уникальный художественный фильм о благодарности и доброте. Представьте сейчас, что вы оказываете кому-либо услугу и просите этого человека отблагодарить не вас, а трех других людей, которые, в свою очередь, отблагодарят еще троих, и так далее, в глобальном масштабе, даря доброту и тепло. Насколько действенной может оказаться такая идея? Ученик седьмого класса Тревор Маккинни решил это проверить и показать нам. <br /><br /> <br /><u>4. Танец-вспышка</u><br />Юная красавица по имени Алекс мечтает стать балериной, но избегает публичных выступлений. Страх провала слишком велик, а веры в себя недостаточно. Грезя ночами о своей мечте, девушка днем работает на заводе, а по ночам танцует в ночном клубе. Но в один момент ее жизнь кардинальным образом изменится. К переменам ее подтолкнет знакомство с бывшей знаменитой балериной и богатым кавалером. Какие трудности ждут Алекс на пути к заветной мечте?<br /><br /><br /><u>5. Эта замечательная жизнь</u>","type":"paragraph"},{"html":"Джордж Бейли, владелец кредитной компании, честный, отзывчивый, любящий муж и отец, подавлен свалившимися на него невзгодами и подумывает о самоубийстве.","type":"paragraph"},{"html":"А как мы могли догадаться, человек, отказывающийся от жизни, в срочном порядке нуждается в помощи ангела-хранителя. И Небеса отправляют ему на выручку Кларенса, единственного свободного на тот момент Ангела Второго Класса, но не имеющего крыльев. Если он сделает свою работу хорошо и сможет отговорить Джорджа от смертного греха, он их получит. Но времени у него совсем мало… <br />Запасаемся попкорном, господа.<br /><br /> <br />","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmr0l10010eukta7xvabqgr"},{"mediaId":"cmrmr0l6k010fuktag5ng8m5p"},{"mediaId":"cmrmr0lmq010guktabbe0nlu1"},{"mediaId":"cmrmr0ltq010hukta013qaq89"}]}]'::jsonb,'cmrmr0km7010duktaa6o1p0xe','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz6g000dkwtai45m48bj','cmrmpdrom0000sstarkqxwts4','2021-04-06T06:00:00.000Z'::timestamp,NULL,NULL,NULL,304,'/sobytija/kino/304-dva-bileta-v-kino.html','2026-07-15T21:06:07.043Z'::timestamp,'2026-07-16T14:01:12.756Z'::timestamp,'''1'':77C ''2'':175C ''3'':320C ''4'':389C ''5'':63C,461C ''6'':144C ''cmrmr0l10010eukta7xvabqgr'':558C ''cmrmr0l6k010fuktag5ng8m5p'':560C ''cmrmr0lmq010guktabbe0nlu1'':562C ''cmrmr0ltq010hukta013qaq89'':564C ''galleri'':556C ''paragraph'':75C,123C,155C,173C,324C,466C,489C,554C ''абсолютн'':9B,28C ''автор'':209C ''алекс'':397C,455C ''ангел'':507C,521C ''ангела-хранител'':506C ''бал'':293C ''балерин'':400C,448C ''балийск'':301C ''бейл'':469C ''билет'':2A ''благодарн'':332C ''богат'':450C ''бракоразводн'':289C ''броккерск'':132C ''бывш'':446C ''вам'':61C ''ван'':52C ''вдохновен'':21B,40C,202C ''вдохновля'':57C ''велик'':408C ''вер'':410C ''верн'':245C ''весн'':6B,25C ''владелец'':470C ''вмест'':258C ''возможн'':112C ''возраст'':241C ''воспитыва'':88C ''времен'':545C ''всем'':185C ''вспышк'':392C ''втор'':522C ''вынест'':200C ''выручк'':514C ''выступлен'':404C ''гарднер'':83C ''гилберг'':213C ''глобальн'':366C ''господ'':552C ''грез'':414C ''грех'':540C ''дал'':364C ''дар'':368C ''девушк'':419C ''действен'':373C ''денег'':153C ''деньг'':256C ''депресс'':23B,42C ''детств'':97C ''джордж'':468C,537C ''джул'':203C ''длит'