INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqvn9k00lfuktaytls7b5s','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Полина Малых: "Мода России развивается, думаю, что у нас много достойных внимания дизайнеров"','Полине из города Киров уже скоро исполнится 18 лет.','437-polina-malyh-moda-rossii-razvivaetsja-dumaju-chto-u-nas-mnogo-dostojnyh-vnimanija-dizajnerov','[{"html":"<strong>Полине из города Киров уже скоро исполнится 18 лет. И она как никогда задумывается о будущем, о том, как сложится ее жизнь. Хотя уже сейчас за плечами юной модели немало подиумов и показов и не только в России, но и в Германии. </strong>","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Полина, здравствуй. У тебя скоро совершеннолетие, как будешь праздновать?","type":"paragraph"},{"html":"<strong>Полина: </strong>Здравствуйте. В узком семейном кругу.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Задумывалась о будущем?","type":"paragraph"},{"html":"<strong>Полина: </strong> Сейчас задумываюсь часто, потому что скоро стану совершеннолетней и многие вопросы придется решать самой.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Ты учишься на 2 курсе колледжа «ВятГУ» в Кирове в отделении Земельно-имущественных отношений. Почему выбрала такую специализацию?","type":"paragraph"},{"html":"<strong>Полина: </strong>Посещая День открытых дверей «ВятГУ», очень понравилась эта специализация. А сейчас учась на 2 курсе, убедилась, что профессия является трудной, но очень интересной.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Будешь работать по специальности?","type":"paragraph"},{"html":"<strong>Полина: </strong> Очень бы хотелось работать по данной специализации, если найду подходящее место работы.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Сколько лет ты занимаешься моделингом?","type":"paragraph"},{"html":"<strong>Полина: </strong> 5 лет, с 13 лет.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> В каких показах успела поучаствовать?","type":"paragraph"},{"html":"<strong>Полина: </strong> Их было множество. Участвовала в показах в Нижнем Новгороде «Podium Art Volkswagen Fashion Day», VI Фестиваль Star Step, Fashion Bitva и в Ижевске на Неделе моды «Мода на все времена». Ездила в Сочи на VII Международный Fest Star Step. 2 года подряд летала в Германию на Festival Nascha Russia. Были показы и в Москве и своем родном Кирове.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Кого из дизайнеров, с которыми ты работала, ты можешь выделить?","type":"paragraph"},{"html":"<strong>Полина: </strong> Juli Jarvi, она вдохновилась природой Карелии и создала прекрасную коллекцию одежды.","type":"paragraph"},{"html":"Понравилась в Москве Натали Алавердян. Ее коллекция вечерних платьев не только красивая, но и удобная в повседневной жизни.","type":"paragraph"},{"html":"Kseniia Fok, ее коллекция из переработанной бумаги, очень глубоко меня потрясла, не только оригинальностью, но приятно удивила, что такое может быть! В Нижнем понравился бренд «Kichka Style». Ее образы созданы в стиле древней Руси, но интегрирована в наше время, выглядит очень стильно и необычно.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Твое мнение о моде в России?","type":"paragraph"},{"html":"<strong>Полина: </strong> Мода России развивается, думаю, что у нас много достойных внимания дизайнеров, которые смогут моду России вывести на самый высокий уровень.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Твоя самая сокровенная мечта?","type":"paragraph"},{"html":"<strong>Полина: </strong> Хочу быть востребованной моделью.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> А что нужно для ее исполнения?","type":"paragraph"},{"html":"<strong>Полина: </strong> Участие в показах, конкурсах и сотрудничество с известными дизайнерами.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Пару слов нашим читателям.","type":"paragraph"},{"html":"<strong>Полина: </strong> Хочу сказать, что в жизни, человек может достичь трудом, умением и терпением, всего, что сам себе пожелает. Нужно верить в свои силы и не останавливаться на достигнутом!","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqvmsd00ldukta09u9i4nc"},{"mediaId":"cmrmqvn7e00leuktab0t9831o"}]}]'::jsonb,'cmrmqvmbv00lcuktau0v7nw7p','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-04-21T06:00:00.000Z'::timestamp,NULL,NULL,NULL,437,'/esquekids/moda-ek/437-polina-malyh-moda-rossii-razvivaetsja-dumaju-chto-u-nas-mnogo-dostojnyh-vnimanija-dizajnerov.html','2026-07-15T21:02:15.560Z'::timestamp,'2026-07-16T13:59:15.683Z'::timestamp,'''13'':207C ''18'':21B,30C ''2'':122C,155C,262C ''5'':204C ''art'':233C ''bitva'':242C ''cmrmqvmsd00ldukta09u9i4nc'':500C ''cmrmqvn7e00leuktab0t9831o'':502C ''day'':236C ''esqu'':68C,91C,117C,168C,193C,212C,284C,382C,417C,434C,458C ''fashion'':235C,241C ''fest'':259C ''festiv'':269C ''fok'':336C ''galleri'':498C ''jarvi'':301C ''juli'':300C ''kichka'':360C ''kid'':69C,92C,118C,169C,194C,213C,285C,383C,418C,435C,459C ''kseniia'':335C ''nascha'':270C ''paragraph'':66C,80C,89C,97C,115C,139C,166C,175C,191C,201C,210C,220C,282C,297C,312C,333C,380C,391C,415C,424C,432C,443C,456C,4