INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqyb6800snuktarbcny73n','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'«Как перестать раздавать советы окружающим». Советы от Марии Погребняк','Как вы относитесь к нарушению личных границ?','378-kak-perestat-razdavat-sovety-okruzhajuschim-sovety-ot-marii-pogrebnjak','[{"html":"Как вы относитесь к нарушению личных границ? А к непрошенных советам? Скорее всего вам неприятно, когда люди лезут не в свое дело и навязывают мнение. К сожалению, остановить поток нежеланных рекомендаций от посторонних или друзей очень сложно, но возможно. Мария Погребняк — популярный блогер и дизайнер — рассказала, как перестать реагировать на советы окружающих и как самому не нарушать чужие границы.","type":"paragraph"},{"html":"Психологи уже давно выяснили, почему люди склонны лезть в жизнь других и постоянно навязывать свои мысли тем, кто не просил этого делать. Все дело в своеобразных человеческих архетипах, которые отвечают за желание «советчиков» поделиться своими взглядами на проблему.","type":"paragraph"},{"html":"<i>Первый вид</i> — <b>«страждущий внимания»</b>. Такие люди лезут в жизнь посторонних с целью, обратить на себя внимание. Им не важно, с чем вы столкнулись и нуждаетесь ли в поддержке. Они желают оказаться в центре внимания. Чаще всего это одинокие, непонятые обществом люди, которым нужен банальный человеческий интерес к себе и общение. Не стоит воспринимать советы таких людей близко к сердцу, так как взгляды и отношение к чему-то у некоторых может меняться почти каждый день, и они даже не вспомнят, что говорили вам на прошлой неделе.","type":"paragraph"},{"html":"<i>Второй вид</i> — <b>«тревожные»</b>. Люди этого типа привыкли все контролировать как в своей жизни, так и в чужой. Они не умеют отпускать ситуацию и считают, что, если не вмешаются в ваши трудности, не дадут свой «экспертный» совет, то с вами непременно что-то случится и это будет на их совести. Ими руководит страх и забота, так что не обижайтесь на них, но их советы все-таки лучше делить на два и руководствоваться собственными ощущениями и мнением.","type":"paragraph"},{"html":"<i>Третий вид</i> — <b>«родитель»</b>. Человек с таким архетипом всегда ставит себя выше собеседника и лишает его права самостоятельного выбора. Они всегда все знают лучше других, у них «больше опыта» и знания глубже, да и на мир они смотрят правильнее других. И таких людей достаточно много, они пытаются задавить оппонента авторитетом, или возрастом, или другими «заслугами». И очень часто делают это в уверенной и несколько агрессивной форме, так что поверить им не составит труда.","type":"paragraph"},{"html":"<i>Четвертый вид</i> — <b>«опытные»</b>. Они считают, что через многое в этой жизни прошли, эдакие философы-скитальцы, и имеют право раздавать советы на основе прожитых ситуаций. Люди этого типа привыкли, что к их мнению прислушиваются, не ставят сказанное под сомнение, их считают мудрыми. Они не упускают возможность в разговоре подчеркнуть свое превосходство, чем очень похожи на «родителей», их даже можно отнести к одной категории, но различия в атмосфере разговора с ними есть.","type":"paragraph"},{"html":"Теперь, при общении с людьми, мы можем определять их архетипы и понимать, почему человек начинает раздавать советы, когда его об этом не просят. Но понимание не решает основную проблему: «Как не реагировать на чужие высказывания и защитить личные границы?».","type":"paragraph"},{"html":"– Старайтесь всегда помнить, что ваша жизнь принадлежит только вам! У каждого в этом мире свой путь, свои ошибки. Чужой опыт не сделает вас мудрым и счастливым. Берите все в свои руки, принимайте свои решения и не оглядывайтесь на других.","type":"paragraph"},{"html":"– Мягко объясните собеседнику, что в его советах вы не нуждаетесь. Старайтесь ссылаться на уже принятые решения, не давайте возможность другим людям вставить свои «пять копеек». Если вы боитесь обидеть оппонента своим нежеланием прислушиваться к нему, то сделайте вид, что согласились с его мыслями, а на деле придерживайтесь собственного мнения.","type":"paragraph"},{"html":"Однако, что делать, если это вы постоянно лезете в жизнь других и не можете укротить внутри себя «советчика»? Тут все просто. Поставьте себя на место собеседника. Вам не нравится, когда кто-то нарушает ваше личное пространство, и негативно реагируете на подобные вмешательства? Другие люди тоже. Просто помните это и не пытайтесь демонстрировать авторитет там, где от вас этого не ждут. Молчание — это не игнорирование проблемы и не проявление равнодушия, а, наоборот, показатель воспитанности и проявление уважение к собеседнику.","type":"paragraph"},{"html":"Давать советы нужно с умом и только когда вас об этом просят. Уважение личных границ — невероятно важное качество для любого человека, в особенности в современном мире, когда мы живем в эпоху Интернета и постоянного общения с сотнями людей как в сетях, так и в жизни. <i>«Молчание — золото»</i> — так говорил классик. Придерживайтесь этого правила и так вы никогда никого не обидите нежелательными комментариями.","type":"paragraph"},{"type":"image","mediaId":"cmrmqyb3700smuktax4nqapbq"}]'::jsonb,'cmrmqya2c00slukta7izropw6','cmrm8kzpw000mkwtaocyn5161','cmrm8kzra000okwtaqek3edwq','cmrmpdrom0000sstarkqxwts4','2021-09-24T06:00:00.000Z'::timestamp,NULL,NULL,NULL,378,'/psihologija/samosovershenstvovanie/378-kak-perestat-razdavat-sovety-okruzhajuschim-sovety-ot-marii-pogrebnjak.html','2026-07-15T21:04:19.856Z'::timestamp,'2026-07-16T14:00:07.378Z'::timestamp,'''cmrmqyb3700smuktax4nqapbq'':723C ''imag'':721C ''paragraph'':77C,118C,207C,287C,362C,436C,478C,520C,572C,654C,719C ''авторитет'':337C,627C ''агрессивн'':352C ''архетип'':106C,295C,447C ''атмосфер'':430C ''банальн'':163C ''бер'':506C ''близк'':176C ''блогер'':59C ''бо'':549C ''важн'':138