INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqeqxq003opotai0p31enz','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Telegram запустил свой сервис знакомств TON Dating','Telegram запустил свой сервис знакомств TON Dating.','659-telegram-zapustil-svoj-servis-znakomstv-ton-dating','[{"html":"Telegram запустил свой сервис знакомств TON Dating. Основная цель приложения – сэкономить время пользователя и подобрать наиболее качественного партнера, избегая мошенников и ботов.","type":"paragraph"},{"html":"При регистрации на сервисе, каждый пользователь проходит многоступенчатую верификацию, сравнимую с системой безопасности онлайн-банков. Это исключает попадание ботов и анонимов. В период двух месяцев тестовой работы модерацию в TON Dating прошло лишь 3% от поданных заявок.","type":"paragraph"},{"html":"К тому же, для мужского населения планеты пользование приложением станет платным, первый месяц составит 5 700 рублей, для женщин подписка, как и на других сайтах знакомств, будет бесплатной.","type":"paragraph"},{"html":"«Для меня, как для женщины, желающей познакомиться с хорошим мужчиной, хорошим плюсом стала платная регистрация для мужчин. Заходя на сайт, я понимаю, что мимолетных мужчин здесь нет. Очень раздражает, когда зайдя на сайт, ты встречаешь или извращенцев, или мужчин, жалеющих деньги даже на чашку кофе» - поделилась своим мнением жительница Санкт-Петербурга, Ирина Лоскутова, пользующаяся сервисами для знакомств.","type":"paragraph"},{"html":"К 2027 году с учётом роста показатель должен превысить 1 млн активных пользователей в месяц, считает основатель TON Dating Владимир Махов. По его словам, ядром географии охвата аудитории станут бывшие страны СНГ, регион MeNa, Европа и Азия.","type":"paragraph"},{"html":"Что касается нашего мнения, то сомнений, что приложение станет актуальным для женщин, нет, а вот будут ли пользоваться им мужчины, учитывая существование сайтов знакомств с бесплатными подписками, пока остается под вопросом.","type":"paragraph"}]'::jsonb,'cmrmqeqvc003npotam2k8ac75','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-06-19T06:00:00.000Z'::timestamp,NULL,NULL,NULL,659,'/v-mire/659-telegram-zapustil-svoj-servis-znakomstv-ton-dating.html','2026-07-15T20:49:07.166Z'::timestamp,'2026-07-16T13:56:46.602Z'::timestamp,'''1'':182C ''2027'':174C ''3'':74C ''5'':95C ''700'':96C ''date'':7A,14B,21C,71C,191C ''mena'':206C ''paragraph'':38C,79C,110C,171C,211C,245C ''telegram'':1A,8B,15C ''ton'':6A,13B,20C,70C,190C ''аз'':209C ''активн'':184C ''актуальн'':222C ''аноним'':61C ''аудитор'':200C ''банк'':55C ''безопасн'':52C ''бесплатн'':108C,238C ''бот'':36C,59C ''будут'':228C ''бывш'':202C ''верификац'':48C ''владимир'':192C ''вопрос'':243C ''врем'':26C ''встреча'':146C ''географ'':198C ''год'':175C ''двух'':64C ''деньг'':152C ''долж'':180C ''друг'':104C ''европ'':207C ''жалеющ'':151C ''жела'':117C ''женщин'':99C,116C,224C ''жительниц'':160C ''зайд'':142C ''запуст'':2A,9B,16C ''заход'':129C ''заявок'':77C ''знакомств'':5A,12B,19C,106C,169C,236C ''избег'':33C ''извращенц'':148C ''ирин'':164C ''исключа'':57C ''кажд'':44C ''каса'':214C ''качествен'':31C ''коф'':156C ''лиш'':73C ''лоскутов'':165C ''мах'':193C ''месяц'':65C,93C,187C ''мимолетн'':135C ''млн'':183C ''мнен'':159C,216C ''многоступенчат'':47C ''модерац'':68C ''мошенник'':34C ''мужск'':85C ''мужчин'':121C,128C,136C,150C,232C ''наибол'':30C ''населен'':86C ''наш'':215C ''онлайн'':54C ''онлайн-банк'':53C ''основател'':189C ''основн'':22C ''оста'':241C ''охват'':199C ''очен'':139C ''партнер'':32C ''перв'':92C ''период'':63C ''петербург'':163C ''планет'':87C ''платн'':91C,125C ''плюс'':123C ''пода'':76C ''подел'':157C ''подобра'':29C ''подписк'':100C,239C ''познаком'':118C ''пок'':240C ''показател'':179C ''польз'':166C ''пользова'':230C ''пользован'':88C ''пользовател'':27C,45C,185C ''понима'':133C ''попадан'':58C ''превыс'':181C ''приложен'':24C,89C,220C ''проход'':46C ''прошл'':72C ''работ'':67C ''раздража'':140C ''регион'':205C ''регистрац'':41C,126C ''рост'':178C ''рубл'':97C ''сайт'':105C,131C,144C,235C ''санкт'':162C ''санкт-петербург'':161C ''сво'':3A,10B,17C,158C ''сервис'':4A,11B,18C,43C,167C ''систем'':51C ''слов'':196C ''снг'':204C ''сомнен'':218C ''состав'':94C ''сравним'':49C ''стал'':124C ''станет'':90C,221C ''станут'':201C ''стран'':203C ''существован'':234C ''счита'':188C ''сэконом'':25C ''тестов'':66C ''том'':82C ''учет'':177C ''учитыв'':233C ''хорош'':120C,122C ''цел'':23C ''чашк'':155C ''эт'':56C ''ядр'':197C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqy3fa00s6uktanuxhyykc','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'В Сочи прошел 9 сезон Fashion bitva','В Сочи в event-пространстве «MONOTONE» в закрытом формате прошел региональный этап конкурса дизайнеров FASHION BITVA.','381-v-sochi-proshel-9-sezon-fashion-bitva','[{"html":"В Сочи в event-пространстве «MONOTONE» в закрытом формате прошел региональный этап конкурса дизайнеров FASHION BITVA. Из-за ограничений, связанных с пандемией коронавируса, мероприятие состоялось в закрытом формате.","type":"paragraph"},{"html":"За выход в финал боролись 9 дизайнеров. Каждый из них представил по две коллекции одежды на темы: «Год 2031» и «Осень-Зима 2022».","type":"paragraph"},{"html":"На суд жюри были представлены платья на основе корсетных технологий Натальи Алавердян. По ее словам, любая женщина мечтает о тонкой талии с идеальными пропорциями песочных часов. Именно эту мечту дизайнер постаралась воплотить в реальность.","type":"paragraph"},{"html":"Марианна Григорян продемонстрировала элегантные платья с элементами этники и романтические образы, приближенные к 60-годам.","type":"paragraph"},{"html":"Линейки одежды от бренда женской одежды «DE ''ANJ» продемонстрировала Анжела Гончарова.","type":"paragraph"},{"html":"Ангелина Догуоглу представила коллекцию джинсовой одежды и одежды для путешествий. Дизайнер сделала главный акцент на крой изделий и не стала перегружать их ярким декором для того, чтобы их можно было легко комбинировать с абсолютно любой обувью и аксессуарами.","type":"paragraph"},{"html":"<em>«Во время конкурса мне говорили, что в моей коллекции чувствуются европейские мотивы. Действительно, большинство моделей я придумала во время путешествий по Европе, где дизайнеры уделяют огромное внимание качеству»</em>, - рассказала Ангелина.","type":"paragraph"},{"html":"Все вещи, которые она представила на конкурсе, высокого качества и сделаны из натуральных тканей и материалов: хлопок, лен, шёлк, жемчуг, перламутр, кокос.","type":"paragraph"},{"html":"Члены жюри во главе с председателем Устяном Грачем по достоинству оценили старания Ангелины Догуоглу и единогласно присудили ей победу в региональном этапе. Она отправится представлять свою коллекцию на финальном показе, который пройдет 18-19 декабря в Москве.","type":"paragraph"},{"html":"<em>«Признаюсь честно, показ для меня был очень волнительным. Это мой первый конкурс в качестве дизайнера. Мне кажется, что я переживала больше всех, потому что я - перфекционист, и для меня очень важно, чтобы все было идеально. Я получила огромное удовольствие от самого конкурса и от атмосферы, которая там царила. Сейчас вспоминаю, и такое ощущение, что все было как во сне. Мне нравится цитата Хемингуэя, который сказал, раз уж начал - побеждай. У меня было отличное начало, поэтому от финала я жду только победы»</em>, - поделилась своими эмоциями дизайнер.","type":"paragraph"},{"html":"Дизайнеры, принявшие участие в отделении «Детская мода», тоже удивили членов жюри.","type":"paragraph"},{"html":"Лариса Полюбина в отделении «Детская мода» представила коллекцию – «Цветение». По словам дизайнера, дети как цветы расцветают, меняются и показывают нам, как важно наслаждаться и ценить все периоды своей жизни.","type":"paragraph"},{"html":"Елена Бручаева в создании одежды использовала исключительно хлопок, вельвет, кружево. Ее посыл – никакой синтетики. Как отметила дизайнер, вне зависимости от времени и изменения модных тенденций одежда для детей должна быть натуральной.","type":"paragraph"},{"html":"Ольга Колибри продемонстрировала наряды, которые были созданы из тканей, уже использовавшихся в производстве. Она подарила им новую жизнь в современной вариации.","type":"paragraph"},{"html":"Екатерина Счастливая представила на конкурсе коллекции одежды своего бренда «Podium kids». Цель ее бренда – помочь ребенку создать правильный утонченный гардероб, раскрывая тем самым его индивидуальность, особенности, характер и внутреннее «Я».","type":"paragraph"},{"html":"Основательница бренда детской и подростковой одежды «SOVANA» Анна Рожина восхитила членов жюри своими линейками одежды, в особенности коллекцией «На грани». Грань – это, когда подросток уже большой, но еще не взрослый. Он имеет свое мнение, но при этом ограничивается взглядами родителей.","type":"paragraph"},{"html":"<em>«Предпочтения при выборе материала я отдаю только натуральным тканям люксового качества. Все образы отшиваются в небольшом количестве, а некоторые наряды и в единственном экземпляре. </em><em>За последний год бренд «SOVANA» настолько сроднился со мной, что модели стали обращаться ко мне, как Анна Сована»,</em> - отметила дизайнер.","type":"paragraph"},{"html":"Анна Рожина стала победителем регионального этапа в отделении «Детская мода». Она получила возможность пройти стажировку на 4-дневном мастер-классе весной 2022 года в очном или заочном формате на Fashion Department Summit.","type":"paragraph"},{"html":"<em>«Во время конкурса очень волновалась. Когда прошел показ моих коллекций, члены жюри сказали, что у них пробежали мурашки. Для меня это было высшей оценкой»,</em> - рассказала Анна.","type":"paragraph"},{"html":"Организаторы проекта выражают благодарность членам жюри за компетентное судейство и ценные советы участникам.","type":"paragraph"},{"html":"<i>Текст: Влада Холкина</i>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqy1fd00s1ukta2n26yh8d"},{"mediaId":"cmrmqy1z700s2uktaqa4q7s7y"},{"mediaId":"cmrmqy2hc00s3uktaovqd45e9"},{"mediaId":"cmrmqy2wk00s4uktaqbljp5ub"},{"mediaId":"cmrmqy3cw00s5uktad7hf9cjk"}]}]'::jsonb,'cmrmqy0wy00s0uktavogmxtb3','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2021-11-12T06:00:00.000Z'::timestamp,NULL,NULL,NULL,381,'/projects-esque/fashion-bitva/381-v-sochi-proshel-9-sezon-