INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsntk0094uktad7o8q0wc','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'LVMH провёл глобальные “дни открытых дверей”','Конгломерат крупнейших модных домов LVMH провёл на выходных “дни открытых дверей” в своих мастерских по всему миру.','579-lvmh-provel-globalnye-dni-otkrytyh-dverej','[{"html":"<b>Конгломерат крупнейших модных домов LVMH провёл на выходных “дни открытых дверей” в своих мастерских по всему миру. Мероприятие состоялось впервые за несколько лет.</b>","type":"paragraph"},{"html":"“Дни открытых дверей”, которые компания называет “Journées Particulières”, проходили с 14 по 16 октября. Можно было попасть в мастерские Dior, Kenzo, Lois Vuitton, Tiffany&amp;Co и многих других влиятельных модных домов. Всего было открыто 90 локаций. Посетители смогли увидеть работу инженеров и ювелиров, которые создают предметы из коллекций брендов. В рамках акции Kenzo открыл выставку 60 архивных образов основателя модного дома Кензо Такады.","type":"paragraph"},{"html":"Во время “Journées Particulières” в мастерские брендов пришло рекордное число посетителей – более 200 тысяч человек. Для участия нужно было заранее зарегистрироваться.","type":"paragraph"},{"html":"В этом году LVMH продолжает оставаться одним из самых успешных игроков в модной индустрии. Согласно недавнему отчёту, его продажи превысили прогнозы аналитиков. Они выросли на 19% по сравнению с тем же периодом за прошлый год. Среди всех модных домов, входящих в конгломерат, наиболее успешным оказался Dior.","type":"paragraph"}]'::jsonb,'cmrmqsnr30093uktaux4qe06q','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2022-10-17T06:00:00.000Z'::timestamp,NULL,NULL,NULL,579,'/fashion/news-2/579-lvmh-provel-globalnye-dni-otkrytyh-dverej.ht