INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqxj0s00qvuktaojg2xv36','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Советы по уходу за кожей от химика-технолога Васильевой Елены','Грамотный уход за кожей позволит избежать множества эстетических проблем.','392-sovety-po-uhodu-za-kozhej-ot-himika-tehnologa-vasilevoj-eleny','[{"html":"<em>Меня зовут Васильева Елена и я химик-технолог косметики, владелица частной косметической лаборатории, разработчик косметических формул уходовой и декоративной косметики. Уже много лет я изучаю химию, биохимию, микробиологию и анатомию для создания качественных рецептур по уходу за кожей. 11 лет занимаюсь разработками косметических формул, создала уже несколько сотен рецептур как уходовой, так и декоративной косметики.</em>","type":"paragraph"},{"html":"Грамотный уход за кожей позволит избежать множества эстетических проблем. Начиная от высыпаний, заканчивая морщинами. Но чтобы правильно выбрать уходовые средства, нужно хоть немного научиться разбираться в составах. Это поможет не разочароваться в выбранной косметике и сэкономит немало ваших денег!","type":"paragraph"},{"html":"<u><i>Очень важные моменты в уходе за кожей:</i></u>","type":"paragraph"},{"html":"✅ Правильное очищение. Ваши средства не должны содержать сульфаты (Sodium Lauryl Sulfate, Sodium Laureth Sulfate, Ammonium Lauryl Sulfate, Sodium Coco Sulfate и пр.), они разрушают клетки кожи и липидный слой, чем провоцируют обезвоженность, истончение эпидермиса и даже возникновение дерматитов. Мягкие ПАВы в составе не сушат кожу и не травмируют ее клетки. Но при этом очищение должно быть тщательным, чтобы убирать жир и грязь не только с поверхности, но и из пор.","type":"paragraph"},{"html":"✅ Увлажнение. Недостаток увлажнения на сухой и нормальной коже провоцирует возникновение морщин, а на жирной избыточное выделение кожного сала. Но увлажнение тоже должно быть грамотным.","type":"paragraph"},{"html":"В составе обязательно должны быть увлажняющие активы. Самые физиологичные из них - компоненты натурального увлажняющего фактора (NMF) кожи. Ищите на упаковке:","type":"paragraph"},{"html":"✔️гиалуроновая кислота (hylauronic acid);","type":"paragraph"},{"html":"✔️мочевина (urea);","type":"paragraph"},{"html":"✔️аминокислоты (amino acids, arginine PCA, glycine, proline, serine, tirozine, lysine, sodium aspartate, sodium polyaspartate).","type":"paragraph"},{"html":"✅ Восстановление кожи. Важный момент, особенно для зимнего времени года, когда кожа подвергается очень агрессивному воздействию окружающей среды. Кожу восстанавливают жиры: растительные масла, сквалан, лецитин, керамиды и фосфолипиды. Ещё хорошими восстановительными свойствами обладает ламеллярная эмульсия. Своим строением она повторяет липидный слой кожи, поэтому встраивается в него как «родная» и очень быстро восстанавливает кожу.","type":"paragraph"},{"html":"✅ SPF. Защита от солнца - важный этап ухода. Актуальна не только летом, но и в любое другое солнечное время года. Ультрафиолет разрушает коллаген и в целом плохо влияет на организм, поэтому пренебрегать ей не стоит. Смотрите на упаковке, чтобы защита была не только SPF, но и от UVA лучей. Или маркировка BROAD SPECTRUM.","type":"paragraph"},{"html":"<i>Что в моей косметичке?</i>","type":"paragraph"},{"html":"В моей косметичке 35+ средств немного. Все потому, что я выбрала идеальные продукты для ухода за кожей. Я люблю многофункциональность и быстрый результат, при этом желания пользоваться 10 баночками у меня нет, поэтому косметику я выбираю максимально эффективную и совмещающую в себе несколько функций.","type":"paragraph"},{"type":"image","mediaId":"cmrmqxiz800quuktajfiixbhu"}]'::jsonb,'cmrmqxidx00qtuktaaufdw2ck','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyz0000akwtaq6w9733r','cmrmpdrom0000sstarkqxwts4','2022-01-10T06:00:00.000Z'::timestamp,NULL,NULL,NULL,392,'/beauty/mnenie/392-sovety-po-uhodu-za-kozhej-ot-himika-tehnologa-vasilevoj-eleny.html','2026-07-15T21:03:43.372Z'::timestamp,'2026-07-16T13:59:54.860Z'::timestamp,'''10'':428C ''11'':60C ''35'':404C ''acid'':258C,269C ''amino'':268C ''ammonium'':146C ''arginin'':270C ''aspart'':278C ''broad'':389C ''cmrmqxiz800quuktajfiixbhu'':450C ''coco'':150C ''glycin'':272C ''hylauron'':257C ''imag'':448C ''laureth'':144C ''lauryl'':141C,147C ''lysin'':276C ''nmf'':247C ''paragraph'':78C,120C,130C,203C,230C,253C,260C,265C,282C,337C,392C,399C,446C ''pca'':271C ''polyaspart'':280C ''prolin'':273C ''serin'':274C ''sodium'':140C,143C,149C,277C,279C ''spectrum'':390C ''spf'':339C,381C ''sulfat'':142C,145C,148C,151C ''tirozin'':275C ''urea'':263C ''uva'':385C ''агрессивн'':297C ''актив'':238C ''актуальн'':346C ''аминокислот'':267C ''анатом'':51C ''баночк'':429C ''биохим'':48C ''быстр'':333C,422C ''важн'':123C,286C,343C ''васильев'':10A,23C ''ваш'':117C,134C ''владелиц'':31C ''влия'':365C ''воздейств'':298C ''возникновен'':168C,214C ''восстанавлива'':302C,334C ''восстановительн'':313C ''восстановлен'':284C ''врем'':356C ''времен'':291C ''встраива'':326C ''выбира'':436C ''выбра'':97C,112C,411C ''выделен'':220C ''высыпан'':91C ''гиалуронов'':255C ''год'':292C,357C ''грамотн'':12B,80C,228C ''гряз'':193C ''декоративн'':40C,75C ''денег'':118C ''дерматит'':169C ''должн'':137C,186C,226C,235C ''друг'':354C ''ел'':11A,24C ''ещ'':311C ''желан'':426C ''жир'':191C,303C ''жирн'':218C ''заканчив'':92C ''занима'':62C ''защит'':340C,377C ''зимн'':290C ''зовут'':22C ''идеальн'':412C ''избежа'':17B,85C ''избыточн'':219C ''изуча'':46C ''истончен'':164C ''ищ'':249C ''качествен'':54C ''керамид'':308C ''кислот'':256C ''клетк'':156C,181C ''кож'':5A,15B,59C,83C,128C,157C,176C,212C,248C,285C,294C,301C,324C,335C,417C ''кожн'':221C ''коллаг'':360C ''компонент'':243C ''косметик'':30C,41C,76C,113C,434C ''косметическ'':33C,36C,64C ''косметичк'':397C,403C ''лаборатор'':34C ''ламел