svector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr0xkp011gukta6otgpait','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Я приглашаю тебя на спектакль','Сейчас все чаще хочется находиться на свежем воздухе и активно получать витамин D, приумножая удовольствие и здоровье.','300-ja-priglashaju-tebja-v-kino-','[{"html":"Сейчас все чаще хочется находиться на свежем воздухе и активно получать витамин D, приумножая удовольствие и здоровье. Но афиша весны 2021 буквально тянет нас невидимой рукой к себе. Какие спектакли будем смотреть этой весной и вспоминать о них осенью?","type":"paragraph"},{"html":"Записываем.","type":"paragraph"},{"html":"<strong>Мюзикл “Анна Каренина” </strong>","type":"paragraph"},{"html":"<strong>Длительность: около 2 часов </strong>","type":"paragraph"},{"html":"Шедевр мировой культуры, который смотрится на одном дыхании!","type":"paragraph"},{"html":"Мюзикл «Анна Каренина» уже покорил сердца миллионов по всему миру и заслужил признание множества театральных критиков. Более 500 спектаклей в России и за рубежом сыграно с момента выхода премьеры.","type":"paragraph"},{"html":"В труппе постановки – звезды столичного мюзикла: Екатерина Гусева, Валерия Ланская, Дмитрий Ермак, Сергей Ли, Ольга Беляева, Наталия Быстрова, Игорь Балалаев, Лика Рулла, Андрей Бирин, Александр Маракулин, Максим Заусалин и многие другие.","type":"paragraph"},{"html":"Герои мюзикла переживают яркие и противоречивые чувства: любовь и предательство, страсть и долг, надежду и отчаянье. И хотя от происходящего на сцене нас отделяют почти полтора столетия – события, разворачивающиеся перед глазами, по-настоящему увлекают и захватывают: во все времена они близки и понятны каждому.","type":"paragraph"},{"html":"Еще есть возможность посмотреть мюзикл “Анна Каренина” в Московском театре оперетты.","type":"paragraph"},{"html":"<strong>Мюзикл «ПраймТайм»</strong>","type":"paragraph"},{"html":"<strong>Длительность: около 3 часов </strong>","type":"paragraph"},{"html":"5 марта 2020 г. в Московском театре мюзикла состоялась мировая премьера мюзикла «ПраймТайм». Это второй спектакль в истории театра после знаменитой «Принцессы цирка», который будет поставлен совместно с прославленным цирковым коллективом The 7 Fingers («7 пальцев», Канада).","type":"paragraph"},{"html":"У каждой девушки, желающей покорить Москву, есть мечта. И даже не одна. Анна хочет выиграть в главном вокальном телевизионном конкурсе страны. Или стать первой девушкой, победившей в рэп-баттле. Или попасть на сцену. Что бы ни произошло, Аня решительно не хочет возвращаться в свой заштатный городок.","type":"paragraph"},{"html":"Мюзикл по идее художественного руководителя театра Михаила Швыдкого написали композитор Максим Лепаж (Канада), автор либретто Елена Киселева и автор стихов Алексей Кортнев. В творческую команду проекта вошли режиссеры-постановщики Себастьян Солдевилья (Франция/Канада) и Марина Швыдкая, музыкальный руководитель Татьяна Солнышкина, художник-постановщик Оливье Ландревиль (Канада), хореограф Женевьев Дорион-Купаль (Канада), художник по костюмам Галя Солодовникова и художник по свету Эрик Шампу.","type":"paragraph"},{"html":"Мюзикл «ПраймТайм» - мюзикл об увлекательной кухне телевидения, закулисье шоу-бизнеса и изнурительной борьбе за популярность. Вторая сторона этого спектакля о счастье творчества, поисках своего места под солнцем, настоящей дружбе. И, конечно, о любви.","type":"paragraph"},{"html":"<strong>Спектакль «Реверс»</strong>","type":"paragraph"},{"html":"<strong>Длительность: около 2 часов </strong>","type":"paragraph"},{"html":"Спектакль “Реверс” - это история о внешней и внутренней борьбе человека с самим собой. Но, как обычно, самые прекрасные или обратные качества проявляются только в самой экстренной ситуации. Спектакль рассказывает о метаниях между противоположными частями сущности, о стремлении измениться и изменить, о главном выборе, который хоть раз в жизни встает перед человеком.","type":"paragraph"},{"html":"Режиссеры Андрей Кольцов и Ирина Дрожжина вместе с хореографом Деброй Браун (Канада) создали динамичное действие, которое не вписывается в стандартные понятие воспринимаемого. Актеры «Реверса» стирают границы между драматическим и физическим театром, хореографией и акробатикой. Однако падения с высоты, полеты над зрителями, балансирование на динамических пилонах и прочие трюки – не просто эффектные приемы, но средство повествования и раскрытия внутреннего мира персонажей спектакля «Реверс».","type":"paragraph"},{"html":"<b>Спектакль «What women want»</b>","type":"paragraph"},{"html":"<b>Длительность: около 2 часов</b>","type":"paragraph"},{"html":"Что скрывает женщина за смелым жонглирование многочисленных образов и ролей? Как понять за ширмами женской души всю ее суть и уникальность? И возможно ли это? Есть ли там что-то? В дебютной постановке нового театрального пространства в самом сердце Москвы Василий Козарь исследует тему женственности с разных точек зрения и ищет ответ актуальный для каждого мужчины вопрос: «Чего хочет женщина?».","type":"paragraph"},{"html":"Постановка «What women want» создана на стыке французского кабаре и танцевального театра, с элементами современной хореографии, медиа-арта, цирковой акробатики и вокального исполнения.","type":"paragraph"},{"html":"Шоу проходит в камерном зале, оборудованном мягкими диванами, дизайнерскими столиками с подсветкой и ледяным игристым в качестве комплимента. Эстетика чувственности и элегантности, обволакивающая атмосфера роскоши являются неотъемлемой частью каждого представления.","type":"paragraph"},{"html":"Мы уже купили билеты на первый ряд.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmr0x5s011duktad5bmg10x"},{"mediaId":"cmrmr0xdt011euktaonpwhw62"},{"mediaId":"cmrmr0xjo011fuktas1ls8z3e"}]}]'::jsonb,'cmrmr0wx7011cuktaciy7xhc