INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqvp1600loukta6zmzovo1','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Алексей Кан: "Я хочу связать свою профессию с автомобилями"','Алексей Кан из города Иркутск уже 2 года профессионально занимается моделингом, стрельбой из лука и мечтает связать свою жизнь с автомобилями.','435-aleksej-kan-ja-hochu-svjazat-svoju-professiju-s-avtomobiljami','[{"html":"<strong>Алексей Кан из города Иркутск уже 2 года профессионально занимается моделингом, стрельбой из лука и мечтает связать свою жизнь с автомобилями. </strong>","type":"paragraph"},{"html":"<strong>У него очень взрослые размышления о жизни и ясные цели. Мы желаем Алексею, чтобы всего его задумки и планы, обязательно сбылись. </strong>","type":"paragraph"},{"html":"<strong>Esque.kids</strong><strong>:</strong> Леша, здравствуй. Сколько лет ты занимаешься моделингом?","type":"paragraph"},{"html":"<strong>Алексей:</strong> Здравствуйте. В сентябре 2020 года я пришел на первую фотосесси и мне понравилось, с тех пор я занимаюсь моделингом.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Что для тебя мода?","type":"paragraph"},{"html":"<strong>Алексей:</strong> Мода - это свобода выражения меня, красота и стиль.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Каких интересных дизайнеров ты можешь назвать в Иркутской области?","type":"paragraph"},{"html":"<strong>Алексей:</strong> Больше всех мне запомнился бренд «Аnlisisters».","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> В каких показах ты принимал участие?","type":"paragraph"},{"html":"<strong>Алексей</strong><strong>: </strong>Proobraz fashion show, Fashion bitva 9 и Fashion bitva 10. В этом году на битве я выиграл в номинации «Лучшая фотомодель».","type":"paragraph"},{"html":"Также ездил в Крым в 2021 году. Показ проходил в Воронцовском дворце. Еще участвовал в показах, посвященных Хэллоуину в 2020 и в 2021 годах. Мы сами изготавливали костюмы.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Что тебе больше всего нравится в показах?","type":"paragraph"},{"html":"<strong>Алексей: </strong>Идти по подиуму в свете софитов. Сделать так, чтобы одежда от дизайнера, понравилась зрителям в зале. Люблю примерять образы, прически. У меня уже есть некоторые модели одежды, из коллекций дизайнеров, которых я представлял.","type":"paragraph"},{"html":"<strong> Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Перейдем к другим твоим увлечениям. Ты профессионально занимаешься стрельбой из лука. Расскажи нам немного подробнее об этом виде спорта.","type":"paragraph"},{"html":"<strong>Алексей: </strong>Я еще в начале моего пути к званиям и достижениям в этом виде спорта, до этого занимался армейским рукопашным боем. Тренируюсь я на классическом луке. Для этого спорта нужно огромное терпение, как говорит мой тренер Татьяна Борисовна, которое я вырабатываю в себе, а также внимание, сила рук и выдержка, концентрация, чтобы не выстрелить раньше времени, чтобы не пораниться. Ну и потом на соревнованиях чтобы хватило сил отстрелять 60 серий по три выстрела.","type":"paragraph"},{"html":"Надеюсь, что мне хватит таланта и стремления попасть в сборную и выступить на олимпийских играх.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> А у вас проходят какие-то соревнования, конкурсы? Где ты принимал участие?","type":"paragraph"},{"html":"<strong>Алексей: </strong>Да у нас проходят соревнования, я был несколько раз в Усть-Орде и в Иркутске. Призового места не получил, но результат с каждым разом увеличиваю. На соревнованиях много спортсменов из разных школ и клубов. Скоро поеду на очередные соревнования в Усть Орду, они будут в конце апреля. Буду стараться.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Мне сказали, что ты хочешь связать свою будущую профессию с машинами. Расскажи подробнее.","type":"paragraph"},{"html":"<strong>Алексей: </strong>Так и есть. Я хочу связать свою профессию с автомобилями. Это мое увлечение с малого возраста, было бы интересно создавать новые виды автомобилей, быть механиком, профессиональным водителем и участвовать в гонках. Но маме не нравится идея про гонки. Когда закончу школу, поеду в Санкт-Петербург поступать в институт автомобилестроения.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Через 5 лет тебе исполнится 18 лет. Пойдешь учиться на права?","type":"paragraph"},{"html":"<strong>Алексей: </strong>Тут у меня хитрый план. Хочу отучиться на права в 16 лет, а когда исполнится 18 лет сдать уже на сами права. Вы, наверное, хотите узнать почему в 16 лет, это потому что в 17 лет нужно готовиться к поступлению в институт.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Думал, какую себе машину хочешь в будущем?","type":"paragraph"},{"html":"<strong>Алексей: </strong>Мне нравятся Тойота Супра А80, BMW E38, Wiss An Skyline R34 GTR","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Леш, и напоследок пару слов нашим читателям.","type":"paragraph"},{"html":"<strong>Алексей: </strong>Что пожелать. Взрослым терпения и понимания с детьми, а детям помогать и заботиться о взрослых, они хоть и считают себя взрослыми, иногда ведут себя как дети.","type":"paragraph"},{"html":"А вообще, конечно, мира на всей земле и чтобы войн не было. И все были живые, здоровые и счастливые.","type":"paragraph"},{"html":"<i>Я Вконтакте vk.com/id9249421</i>","type":"paragraph"},{"html":"<i>Телеграмм t.me/alexseykan09</i>","type":"paragraph"},{"type":"image","mediaId":"cmrmqvozf00lnuktajs1dtmdc"}]'::jsonb,'cmrmqvosi00lmuktahsr5581t','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-04-19T06:00:00.000Z'::timestamp,NULL,NULL,NULL,435,'/esquekids/obrazovanie-ek/435-aleksej-kan-ja-hochu-svjazat-svoju-professiju-s-avtomobiljami.html','2026-07-15T21:02:17.850Z'::timestamp,'2026-07-16T13:59:16.997Z'::timestamp,'''/alexseykan09'':701C ''/id9249421'':694C ''10'':179C ''16'':563C,581C ''17'':587C ''18'':543C,568C ''2'':16B,37C ''2020'':94C,213C ''2021'':199C,216C ''5'':539C ''60'':366C ''9'':175C ''bitva'':174C,178C ''bmw'':616C ''cmrmqvozf00lnuktajs1dtmdc'':707C ''e38'':617C ''esqu'':113C,134C,158C,225C,274C,392C,464C,536C,598C,626C ''esque.kids'':79C ''fashion'':171C,173C,177C ''gtr'':622C ''imag'':705C ''kid'':114C,135C,159C,226C,275C,393C,465C,537C,599C,627C ''paragraph'':53C,77C,88C,111C,120C,132C,146C,156C,167C,192C,223C,235C,272C,296C,372C,390C,408C,462C,480C,534C,550C,596C,608C,624C,636C,666C,688C,696C,703C ''proobraz'':170C ''r34'':621C ''show'':172C ''skylin'':620C ''t.me'':700C ''t.me/alexseykan09'':699C ''vk.com'':693C ''vk.com/id9249421'':692C ''wiss'':618C ''а80'':615C ''аnlisisters'':154C ''автомобил'':9A,30B,51C,492C,505C ''автомобилестроен'':532C ''алекс'':1A,10B,31C,67C,90C,122C,148C,169C,237C,298C,410C,482C,552C,610C,638C ''апрел'':458C ''армейск'':316C ''битв'':184C ''бо'':318C ''борисовн'':335C ''бренд'':153C ''буд'':459C ''будут'':455C ''будущ'':473C,606C ''ведут'':661C ''взросл'':58C,641C,653C,659C ''вид'':293C,311C,504C ''вконтакт'':691C ''вниман'':343C ''водител'':509C ''возраст'':498C ''войн'':677C ''вообщ'':669C ''воронцовск'':204C ''времен'':353C ''все'':673C ''выдержк'':347C ''выигра'':186C ''вырабатыва'':338C ''выражен'':126C ''выстрел'':351C,370C ''выступ'':385C ''говор'':331C ''год'':17B,38C,95C,182