INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqygaa00sxuktaj8krhp8v','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Иллюзия или успех: куда приводят марафоны личностного роста?','Марафоны личностного роста стали обыденностью для современного человека.','376-illjuzija-ili-uspeh-kuda-privodjat-marafony-lichnostnogo-rosta','[{"html":"Марафоны личностного роста буквально захватили интернет. От коучей поступают весьма соблазнительные предложения: самосовершенствование, а вместе с ним - исполнение желаний и изменение жизни в лучшую сторону. И все это за пару месяцев ежедневных заданий и несколько тысяч рублей. Заманчиво, не правда ли? А если копнуть немного глубже?.. Что такое марафоны личностного роста - реальная помощь или заработок для организаторов - разбираемся в нашей статье.","type":"paragraph"},{"html":"Для начала необходимо понять, что такое личностный рост. Во многом это понятие знает каждый, кто ставил цель и упорно ее добивался. Одни приходят к этому еще в детстве, другие переходят на этап самопознания гораздо позже. Так или иначе, в каждом человеке заложен огромный потенциал для внутреннего развития. В любом из нас существует идеальный внутренний “Я”, путь к которому долог и тернист, наполнен множеством преград, в том числе - психологических. Тренеры марафонов внутреннего роста предлагают снять существующие блоки, используя собственные приемы. Какие именно, рассказала семейный психолог Алла Кристалл.","type":"paragraph"},{"html":"<u><b>Распространенные проблемы</b></u>","type":"paragraph"},{"html":"Семейный психолог Алла Кристалл утверждает, что коучам достаточно просто выделить ряд проблем, наиболее часто встречающихся у современных людей.","type":"paragraph"},{"html":"“Как правило, это обычный мониторинг интернета. Здесь легко найти распространенные причины для обращения к психотерапевтам. В основном это семейные и денежные вопросы: измена супруга, недопонимание в отношениях с ребенком, отсутствие карьерного роста. Далее остается только составить рейтинг основных проблем - и некий психологический портрет будущего участника марафона готов”, - рассказала Алла Кристалл в интервью с ESQUE.","type":"paragraph"},{"html":"<u><b>Марафон - не панацея</b></u>","type":"paragraph"},{"html":"Может ли подобная практика помочь абсолютно всем? Вопрос неоднозначный. Большую роль играет уникальность психологического состояния человека, и порой даже у опытного психотерапевта возникают сложности с той или иной проблемой.","type":"paragraph"},{"html":"“У каждого специалиста, даже профессионала с большой буквы, есть свое “кладбище”. Это люди, которые не смогли пройти курс консультаций полностью, так и не дошли до финальной сессии, покинув специалиста в травмированном состоянии. Если это сравнивать с операцией, то выглядит приблизительно так: человеку сделали надрез, а до наложения швов дело не продвинулось. Поэтому марафоны могут быть опасны для травмированных людей, с настоящей психологической болью”, - поделилась Алла Кристалл.","type":"paragraph"},{"html":"Марафоны могут нанести вред депрессивному психотипу людей, уверена психолог. Такие клиенты могут “зашиться” в своей проблеме, так и не дойдя до психотерапевта. Разбитой личности, прежде, чем строить свою жизнь, необходимо собрать самого себя по кусочкам. В то же время наполненный человек, испытывающий в основном положительные эмоции, придет к достатку и гармонии гораздо проще.","type":"paragraph"},{"html":"<u><b>Помощь или способ заработка?</b></u>","type":"paragraph"},{"html":"Грамотно выстроенный марафон, несомненно, работающий механизм. Однако его проработкой необходимо заниматься специалисту, а плата за услуги должна быть символической.","type":"paragraph"},{"html":"“Очень здорово, когда человек бесплатно или за небольшую цену может помочь себя практически самостоятельно, с небольшим использованием практик. Некоторые после марафонов начинают более глубокую работу над собой и видят результат. Поэтому лично я “за” марафоны. Другой вопрос, когда за подобный коучинг берется не компетентный человек. Делиться своим опытом, конечно, можно, но не выдавая это за марафон”, - <b>уточнила психолог.</b>","type":"paragraph"},{"html":"Самих участников марафона можно разделить на два лагеря: тех, у кого сбылись желания и мечты, и остальных, считающих данные тренинги пустой тратой времени и денег. При этом многие убеждены, что марафоны - это своеобразный толчок к действию для людей, которые не могут начать работу над собой самостоятельно.","type":"paragraph"},{"html":"“Я проходила два марафона личностного роста. После первого не было никакого результата, и я решилась на второй. Нельзя сказать, что мне не понравилось, в целом, осталась довольна. Но сейчас я понимаю, что единственным тормозящим фактором лично для меня была лень и нежелание брать на себя ответственность за собственную жизнь. Постоянно хотелось, чтобы кто-то решал все за меня, подталкивал к осуществлению мечты. Не знаю, является ли мое осознание проблемы заслугой марафона, но я в любом случае рада себе настоящей, жизнь изменилась. А вообще хочу заметить, что исход подобной практики зависит не только от марафона, но и от усилий участника. Ничего не получится, если ты будешь топтаться на месте”, - <b>поделилась своими впечатлениями участница марафонов Мария Никонова. </b>","type":"paragraph"},{"html":"Подводя итог, отметим, что семейный психолог Алла Кристалл также уверена: добиться поставленных задач любой человек может самостоятельно. Для этого требуется несколько лет постоянной работы над собой, собственный опыт и терпение.","type":"paragraph"},{"html":"<i>Журналист: Валентина Поликарпова</i>","type":"paragraph"},{"type":"image","mediaId":"cmrmqyg7600swuktaegz76uuv"}]'::jsonb,'cmrmqyfwk00svukta2gkm69eo','cmrm8kzpw000mkwtaocyn5161',NULL,'cmrmpdrom0000sstarkqxwts4','2021-09-16T06:00:00.000Z'