4C,332C,400C,448C,489C,688C ''числ'':147C ''швов'':338C ''эмоц'':405C ''эт'':44C,91C,105C,198C,213C,302C,324C,498C,537C ''этап'':112C ''явля'':620C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqeqhw003lpotazz0c0zv2','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Умер Егор Зайцев','В возрасте 64 лет умер наследник великого кутюрье Егор Зайцев.','660-umer-egor-zajcev','[{"html":"В возрасте 64 лет умер наследник великого кутюрье Егор Зайцев. Причиной стало заболевание онкологией. По сообщению родственников, Егор умер в районе 20:00 в одной из московских клиник, куда был доставлен в связи ухудшением состояния здоровья. Последние дни мужчина был подключен к аппарату искусственного дыхания.","type":"paragraph"},{"html":"<br />В феврале этого года модельер попал в больницу с подозрением на коронавирус. Там его ждало плачевное известие, врачи обнаружили рак кишечника с образованиями в легких и печени. Шансов на выздоровление не было уже практически тогда.","type":"paragraph"},{"html":"<br />Егор Зайцев был модельером и членом Российской академии художеств. Также Зайцев-младший был академиком Национальной академии индустрии моды.","type":"paragraph"},{"html":"<br />Приносим соболезования родным близким!","type":"paragraph"}]'::jsonb,'cmrmqeqfs003kpota3wsclrgb','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-06-19T06:00:00.000Z'::timestamp,NULL,NULL,NULL,660,'/v-mire/660-umer-egor-zajcev.html','2026-07-15T20:49:06.596Z'::timestamp,'2026-07-16T13:56:45.661Z'::timestamp,'''00'':36C ''20'':35C ''64'':6B,16C ''paragraph'':60C,98C,120C,127C ''академ'':107C,116C ''академик'':114C ''аппарат'':56C ''близк'':125C ''больниц'':69C ''велик'':10B,20C ''возраст'':5B,15C ''врач'':79C ''выздоровлен'':91C ''год'':65C ''дни'':51C ''доставл'':44C ''дыхан'':58C ''егор'':2A,12B,22C,31C,100C ''ждал'':76C ''заболеван'':26C ''зайц'':3A,13B,23C,101C,111C ''зайцев-младш'':110C ''здоров'':49C ''извест'':78C ''индустр'':117C ''искусствен'':57C ''кишечник'':82C ''клиник'':41C ''коронавирус'':73C ''кутюр'':11B,21C ''легк'':86C ''лет'':7B,17C ''младш'':112C ''мод'':118C ''модельер'':66C,103C ''московск'':40C ''мужчин'':52C ''наследник'':9B,19C ''национальн'':115C ''обнаруж'':80C ''образован'':84C ''одн'':38C ''онколог'':27C ''печен'':88C ''плачевн'':77C ''подключ'':54C ''подозрен'':71C ''попа'':67C ''последн'':50C ''практическ'':95C ''принос'':122C ''причин'':24C ''район'':34C ''рак'':81C ''родн'':124C ''родственник'':30C ''российск'':106C ''связ'':46C ''соболезован'':123C ''сообщен'':29C ''состоян'':48C ''стал'':25C ''такж'':109C ''умер'':1A,8B,18C,32C ''ухудшен'':47C ''феврал'':63C ''художеств'':108C ''член'':105C ''шанс'':89C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqy82e00sgukta3u6dakq8','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'В Волгограде прошел 9 сезон Fashion bitva','3 октября в Волгограде в шатре «Ангарский Экопарк» прошел региональный этап 9 сезона конкурса дизайнеров FASHION BITVA.','380-v-volgograde-proshel-9-sezon-fashion-bitva','[{"html":"3 октября в Волгограде в шатре «Ангарский Экопарк» прошел региональный этап 9 сезона конкурса дизайнеров FASHION BITVA. За выход в финал боролись 7 дизайнеров.","type":"paragraph"},{"html":"В этом сезоне региональным представителем в городе Волгоград стала Ирина Бабушкина и модельное агентство Soni de Russo.","type":"paragraph"},{"html":"Елена Близнюк, создатель бренда Create Yourself, представила две коллекции на темы: «Год 2031» и «Осень-Зима 2021». В коллекции «Год 2031» продемонстрированы яркие, неоновые костюмы и платья, бросающие вызов современной моде на нюд. Оттенки фуксии, лайма, неона и фасон оверсайз стали своеобразным символом, показывающим, что быть в тренде и вместе с этим иметь собственный, неповторимый стиль — это реально. Коллекция «Осень-Зима» порадовала тёплыми и благородными костюмами и платьями, изготовленными из футера с эффектом велюр. Они отражают осеннее настроение и подчеркивают уют холодного времени года. В таких изделиях очень тепло и комфортно, а значит, можно чувствовать себя уверенно при любых обстоятельствах.","type":"paragraph"},{"html":"Виола Зауэрвейн своей линейкой одежды, представленной на показе, постаралась передать индивидуальность личности, которая не боится экспериментов. Сложное сочетание цветов, фактур и образов, минимальное количество аксессуаров и исключительно натуральные ткани – составляющие ее коллекции.","type":"paragraph"},{"html":"Дизайнер Виола Зауэрвейн","type":"paragraph"},{"html":"Надежда Арешина при создании коллекции «Осень-Зима» прежде всего думала о комфорте для ребенка.","type":"paragraph"},{"html":"«В этой коллекции я собрала множество светоотражающих элементов, крутых тканей и аксессуаров. Это не просто верхняя одежда для детей, а прежде всего безопасность, комфорт и красота в каждой модели», - отметила дизайнер.","type":"paragraph"},{"html":"Коллекция детских платьев от Елены Павловой, бренд ELENASAMSKIDS, подчёркивает красоту и индивидуальность девочек, а также воспитывает и прививает чувство стиля и эстетики с ранних лет.","type":"paragraph"},{"html":"«Главной идеей является воспитание в детях чувства стиля, а также заботы о своем здоровье и окружающей среде. В коллекции использованы только натуральные материалы: хлопок, лён, шерсть и эвкалипт», - подчеркнула Елена Павлова.","type":"paragraph"},{"html":"Бренд ELENASAMSKIDS восхитил членов жюри своей оригинальностью и экологичностью. Елена Павлова стала победителем регионального этапа в отделении «Детская мода». Она получила возможность пройти стажировку на 4-дневном мастер-классе весной 2022 года в очном или заочном формате на Fashion Department Summit.","type":"paragraph"},{"html":"Дизайнер Елена Павлова","type":"paragraph"},{"html":"В отделении «Женская мода» Елена Герман продемонстрировала две коллекции одежды «Таинственный сад» и «Big city life».","type":"paragraph"},{"html":"<u><i>«Первая коллекция сочетает в себе приглушенные цвета, мягкие и интригующие формы, нежный фатин и благородный атлас. Она о нежности, изящности и волшебстве. Вторая же о том, как современной, смелой женщине не потерять женственность в бешеном ритме и остаться мягкой и сильной одновременно»</i></u>, - рассказала дизайнер.","type":"paragraph"},{"html":"Дизайнер Елена Герман","type":"paragraph"},{"html":"Девиз бренда женской одежды «Х-VADA», представленного на региональном этапе дизайнером Аленой Федоровой: <u><i>«Тебе во мне удобно, а значит и красиво»</i></u>. Эта одежда о женственности, чувственности и комфорте.","type":"paragraph"},{"html":"Дизайнер Алена Федорова","type":"paragraph"},{"html":"Наталия Кузнецова в создании своей коллекции использовала новые, передовые ткани, такие как объемная и металлизированная мемори, воздушный неопрен.","type":"paragraph"},{"html":"«Миссия моего бренда заключается в том, чтобы помочь женщине быть стильной и одновременно женственной, ощущать себя свободной и желанной. Более 10 лет я работаю в сфере вечерней моды, и за это время у меня сформировалось собственное, неповторимое видение стиля. Нестандартные решения, оригинальный крой и опережение мировых трендов - вот мои инструменты в работе», - поделилась Наталия.","type":"paragraph"},{"html":"Члены жюри в свою очередь по заслугам оценили старания дизайнера и присудили ей первое место. За победу в региональном этапе в отделении «Женская мода» Наталия отправится представлять свою коллекцию на финальном показе, который пройдет 18-19 декабря в Москве. Пожелаем ей удачи!","type":"paragraph"},{"html":"Дизайнер Наталия Кузнецова","type":"paragraph"},{"html":"Организаторы проекта выражают благодарность Татьяне Левиной, Екатерине Феоктистовой и Анастасии Корниловой за компетентное судейство и ценные советы участникам.","type":"paragraph"},{"html":"<i>Текст: Влада Холкина</i>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqy44x00s9uktayv9d4wv2"},{"mediaId":"cmrmqy4tz00sauktaggaobkha"},{"mediaId":"cmrmqy5ug00sbukta3hl9y774"},{"mediaId":"cmrmqy6cw00scuktapmoz2lf6"},{"mediaId":"cmrmqy76u00sdukta3douzk95"},{"mediaId":"cmrmqy7ml00seukta9gk1jzar"},{"mediaId":"cmrmqy7zc00sfuktaw5knhpep"}]}]'::jsonb,'cmrmqy3sz00s8uktanvueessc','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2021-10-08T06:00:00.000Z'::timestamp,NULL,NULL,NULL,380,'/projects-esque/fashion-bitva/380-v-volgograde-proshel-9-sezon-fashion-bitva.html','2026-07-15T21:04:15.830Z'::timestamp,'2026-07-16T14:00:05.220Z'::timestamp,'''-19'':606C ''10'':534C ''18'':605C ''2021'':89C ''2022'':363C ''2031