INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsofg0097uktai3va9zvu','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Итальянские фэшн-компании создали эко-объединение','Шесть крупнейших итальянских фэшн-компаний, среди которых Prada Group и DolceGabbana, запустили совместный консорциум Re.Crea.','578-italjanskie-fjeshn-kompanii-sozdali-jeko-obedinenie','[{"html":"<b>Шесть крупнейших итальянских фэшн-компаний, среди которых Prada Group и Dolce&amp;Gabbana, запустили совместный консорциум Re.Crea. Он будет заниматься переработкой отходов модной индустрии.</b>","type":"paragraph"},{"html":"Сейчас в консорциум входят Prada, Zegna, OTB, Moncler, Max Mara и Dolce &amp; Gabbana. С помощью переработки бренды планируют дать новую жизнь текстильным отходам индустрии. Это поможет в борьбе с загрязнением окружающей среды. Полноценная презентация нового проекта пройдёт 28 октября на Венецианском форуме устойчивой моды (Venice Sustainable Fashion Forum).","type":"paragraph"},{"html":"В прошлом году текстильные отходы Италии оценивались в 480 тысяч тонн. Консорциум итальянских фэшн-компаний нацелен переработать 15% от общего объёма. Десять лет назад схожая инициатива была запущена во Франции. Сейчас там перерабатывается 38% отходов французской текстильной индустрии.","type":"paragraph"}]'::jsonb,'cmrmqsody0096uktanilx6g79','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2022-10-16T06:00:00.000Z'::timestamp,NULL,NULL,NULL,578,'/fashion/news-2/578-italjanskie-fjeshn-kompanii-sozdali-jeko-obedinenie.html','2026-07-15T20:59:57.100Z'::timestamp,'2026-07-16T13:57:40.717Z'::timestamp,'''15'':121C ''28'':89C ''38'':137C ''480'':111C ''dolc'':36C,63C ''dolcegabbana'':20B ''fashion'':98C ''forum'':99C ''gabbana'':37C,64C ''group'':18B,34C ''mara'':61C ''max'':60C ''moncler'':59C ''otb'':58C ''paragraph'':50C,101C,143C ''prada'':17B,33C,56C ''re.crea'':24B,41C ''sustain'':97C ''venic'':96C ''zegna'':57C ''борьб'':79C ''бренд'':68C ''венецианск'':92C ''вход'':55C ''год'':105C ''дат'':70C ''деся'':125C ''жизн'':72C ''загрязнен'':81C ''занима'':44C ''запуст'':21B,38C ''запущ'':131C ''индустр'':48C,75C,141C ''инициатив'':129C ''итал'':108C ''итальянск'':1A,11B,27C,115C ''компан'':4A,14B,30C,118C ''консорциум'':23B,40C,54C,114C ''котор'':16B,32C ''крупн'':10B,26C ''лет'':126C ''мод'':95C ''модн'':47C ''назад'':127C ''нацел'':119C ''нов'':71C,86C ''общ'':123C ''объединен'':8A ''объем'':124C ''окружа'':82C ''октябр'':90C ''отход'':46C,74C,107C,138C ''оценива'':109C ''перерабатыва'':136C ''переработа'':120C ''переработк'':45C,67C ''планир'':69C ''полноцен'':84C ''поможет'':77C ''помощ'':66C ''презентац'':85C ''проект'':87C ''пройдет'':88C ''прошл'':104C ''совместн'':22B,39C ''созда'':5A ''сред'':15B,31C,83C ''схож'':128C ''текстильн'':73C,106C,140C ''тон'':113C ''тысяч'':112C ''устойчив'':94C ''форум'':93C ''франц'':133C ''французск'':139C ''фэшн'':3A,13B,29C,117C ''фэшн-компан'':2A,12B,28C,116C ''шест'':9B,25C ''эк'':7A ''эко-объединен'':6A ''эт'':76C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqxtqd00rhuktabtqam8b5','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Кто такие скинтеллектуалы?  Осознанное потребление во время пандемии','Сейчас, когда существует изобилие средств как уходовой, так и декоративной косметики, очень сложно представить, как поколение наших бабушек в свое время обходились одним увлажняющим средством и минимальным набором дефици','387-kto-takie-skintellektualy-osoznannoe-potreblenie-vo-vremja-pandemii','[{"html":"Сейчас, когда существует изобилие средств как уходовой, так и декоративной косметики, очень сложно представить, как поколение наших бабушек в свое время обходились одним увлажняющим средством и минимальным набором дефицитной декоративной косметики.","type":"paragraph"},{"html":"Сейчас же социальные сети, блогеры и всевозможная реклама все больше и больше оказывают на нас давление, из-за которого многим очень трудно удержаться и не купить новую палетку в красивой упаковке, даже несмотря на то, что аналогичные уже стоят на полке в ряд.","type":"paragraph"},{"html":"Некоторые инфлюенсеры сами признаются, что зависимы от покупки новых «баночек» и даже считают, что в глазах подписчиков их экспертность прямо пропорциональна количеству имеющейся косметики.","type":"paragraph"},{"html":"В противовес этому на фоне огромного изобилия средств и широкого доступа к информации, потребление косметики для многих стало более осознанным и даже появился новый тип покупателей, так называемые скинтеллектуалы (skintellectual).","type":"paragraph"},{"html":"<strong>Кто они такие и чем отличаются от всех остальных?!</strong><i></i>","type":"paragraph"},{"html":"Это совершенно обычные люди, как мы с вами, просто однажды им надоело, что после покупки очередного чудодейственного (по словам производителя) средства, этого самого чуда не произошло и они решили изменить свои потребительские привычки, вооружившись собственными знаниями и научными доказательствами.","type":"paragraph"},{"html":"Скинтеллектуаллы представляют собой новых потребителей косметики, которые отлично разбираются в составах средств. Они никогда не побегут покупать сыворотку, если её рекламирует их любимая медийная личность, или если производитель утверждает, что она сотрет с лица любые, даже самые глубокие морщины. Скинтеллектуалы подходят к покупке средств с научной точки зрения и знают, чем салициловая кислота отличается от молочной, а также почему при их использовании обязательно наносить SPF и прочее.","type":"paragraph"},{"html":"<u><i>Почему важно обращать внимание на </i></u><u><i>INCI (International Nomenclature of Cosmetic Ingredients)?</i></u> INCI – это официальный список ингредиентов, расположенный на упаковке, который может рассказать нам о количестве ингредиентов, их качестве, безопасности. Именно по наличию или отсутствию некоторых ингредиентов вы можете отличить действительно натуральную косметику от псевдо-натуральной.","type":"paragraph"},{"html":"На первый взгляд чтение составов может показаться посложнее высшей математики, но на самом деле сейчас можно найти очень много понятной и доступной информации в интернете, а еще можно воспользоваться специальными сервисами-помощниками, которые помогут оценить состав средства и расскажут о каждом ингредиенте. Например, ecogolik.ru и kosmokis.ru.","type":"paragraph"},{"html":"Движение скинтеллектуалов очень тесно переплетается с движением <a href=\"https://www.instagram.com/explore/tags/nobuy/\" target=\"_blank\" rel=\"noopener noreferrer\">#NoBuy</a>, призывающим к отказу от импульсивных покупок косметики, а также её осознанному потреблению.","type":"paragraph"},{"html":"Осознанное потребление, в свою очередь, представляет собой соблюдение баланса цена/качества, разумную экономию и радость от приобретения в долгосрочной перспективе. Это не просто ответственное использование ресурсов, но, можно сказать, жизненная философия со множеством достоинств.","type":"paragraph"},{"html":"Сторонники этого движения делают всё, чтобы снизить разрушительное влияние человека на природу, животных и других людей: внимательно изучают составы и происхождение ингредиентов перед покупкой, стараются использовать косметику до конца, сдают пустую упаковку на переработку или ищут новые способы применения.","type":"paragraph"},{"html":"Осознанное (оно же ответственное и разумное) потребление — это термин, который впервые был использован британским журналом «Ответственный потребитель» аж в 1989 году. Сторонники данного движения нацелены на то, чтобы снизить разрушительное влияние человека на природу, животных и других людей: изучают ингредиенты и их происхождение, стараются использовать косметику до конца, сдают пустую упаковку на переработку или ищут новые способы применения.","type":"paragraph"},{"html":"Свое влияние на осознанное потребление оказала и пандемия. Доказано, что нахождение на самоизоляции и работая дистанционно снизили количество приобретаемой декоративной косметики (т.к. сократилась частота социальных контактов) и увеличили количество покупаемых уходовых средств для лица и тела. Поскольку возросло количество покупок, совершаемых посредством онлайн-магазинов, подход к выбору средств стал более тщательным, так как в онлайне нет возможности «пощупать» средство и приходится внимательно изучать его свойства.","type":"paragraph"},{"html":"Кстати, хоть изначально и было заявлено, что пока на планете бушует COVID-19, природа очищалась и можно было наблюдать как очищались реки и воздух, а в города возвращались дикие животные, позже мы увидели обратную сторону монеты. За это время увеличилось использование одноразовых упаковок, доставок еды в разовой пластиковой посуде, а о медицинских масках и говорить нечего – сколько их используется по всему Земному шару ежедневно по сей день не счесть.","type":"paragraph"},{"html":"В свете всего этого мир однозначно стал больше задумываться об окружающей среде и сохранении планеты, именно поэтому такие тренды, как разумное, этичность составов и экологичность упаковок стали новой характеристикой текущей реальности.","type":"paragraph"},{"html":"А в этом и есть суть осознанного потребления, которое нацелено не только на экономию денег и места на полках, но и на помощь окружающей среде. Подумайте только, как мы загрязняем её всеми нашими банками, тюбиками и упаковками. И, к счастью, есть производители (их пока, правда не так много), выпускающие «многоразовые палетки» (рефилы), которые являются сменными. Рекомендую обращать на них внимание, так как это не только экологично и выгодно, но ещё и мегаудобно - закончился один оттенок, купили только его и поставили на место прежнего. Не надо выбрасывать упаковку, не надо тратить деньги на новую палетку, не надо ломать голову как быстрее добить менее популярные у Вас оттенки.","type":"paragraph"},{"html":"<b>Как стать осознанным потребителем?! С чего начать?!</b>","type":"paragraph"},{"html":"Не откладывая в долгий ящик, найдите время на то, чтобы перебрать «запасы» и проанализировать свое потребительское отношение. Очень здорово в этом может помочь челлендж Project Pan, который придумала бьюти-блогер Laura Farrant. Термин «Project Pan» переводится как «использовать и выбросить». Челлендж призывает замедлиться в покупках новых средств для того, чтобы успеть израсходовать всю уже имеющуюся косметику до конца. И только после этого совершать новые покупки.","type":"paragraph"},{"html":"<em>Автор: Заец Анастасия, визажист, бьюти-эксперт, финалист международного чемпионата The IMC, Лауреат II степени Всероссийского шоу-фестиваля авангардной моды в номинации \"Авангардный макияж\"</em>","type":"paragraph"},{"html":"<em>Instagram</em><em>: @</em><em>stasya</em><em>_</em><em>makeup</em><em>_61</em>","type":"paragraph"}]'::jsonb,'cmrmqxtfy00rgukta2oy3q4wa','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyz0000akwtaq6w9733r','cmrmpdrom0000sstarkqxwts4','2021-12-22T06:00:00.000Z'::timestamp,NULL,NULL,NULL,387,'/beauty/mnenie/387-kto-takie-skintellektualy-osoznannoe-potreblenie-vo-vremja-pandemii.html','2026-07-15T21:03:57.253Z'::timestamp,'2026-07-16T13:59:59.488Z'::timestamp,'''-19'':647C ''1989'':523C ''61'':960C ''cosmet'':312C ''covid'':646C ''ecogolik.ru'':396C ''farrant'':892C ''ii'':942C ''imc'':940C ''inci'':308C,314C ''ingredi'':313C ''instagram'':957C ''intern'':309C ''kosmokis.ru'':398C ''laura'':891C ''makeup'':959C ''nobuy'':409C ''nomenclatur'':310C ''pan'':885C,895C ''paragraph'':70C,117C,144C,177C,189C,231C,301C,350C,400C,423C,460C,502C,563C,633C,705C,739C,848C,858C,927C,955C,962C ''project'':884C,894C ''skintellectu'':175C ''spf'':297C ''stasya'':958C ''авангардн'':948C,952C ''автор'':929C ''аж'':521C ''аналогичн'':109C ''анастас'':931C ''бабушек'':26B,55C ''баланс'':433C ''банк'':774C ''баночек'':128C ''безопасн'':331C ''блогер'':76C,890C ''британск'':517C ''буш'':645C ''быстр'':840C ''бьют'':889C,934C ''бьюти-блогер'':888C ''бьюти-эксперт'':933C ''важн'':304C ''вам'':198C ''взгляд'':354C ''визажист'':932C ''влиян'':470C,534C,566C ''вниман'':306C,800C ''внимательн'':478C,628C ''возвраща'':662C ''воздух'':658C ''возможн'':623C ''возросл'':603C ''вооруж'':224C ''воспользова'':380C ''вперв'':514C ''врем'':7A,29B,58C,673C,866C ''все'':466C ''всевозможн'':78C ''всем'':695C,772C ''всероссийск'':944C ''выбор'':613C ''выбрасыва'':826C ''выброс'':900C ''выгодн'':808C ''выпуска'':789C ''высш'':360C ''глаз'':134C ''глубок'':270C ''говор'':689C ''год'':524C ''голов'':838C ''город'':661C ''давлен'':87C ''дан'':526C ''движен'':402C,408C,464C,527C ''действительн'':342C ''декоративн'':18B,47C,67C,584C ''дел'':365C ''дела'':465C ''ден'':701C ''денег'':755C ''деньг'':831C ''дефиц'':37B ''дефицитн'':66C ''дик'':663C ''дистанцион'':580C ''доб'':841C ''доказа'':573C ''доказательств'':229C ''долг'':863C ''долгосрочн'':443C ''доставок'':678C ''достоинств'':458C ''доступ'':156C ''доступн