INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr12w60122uktagy326jjm','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Земфира. Почему "Бордерлайн"?','Зимой 2021, после долгого дистанцирования, на свет с новым альбомом под названием Бордерлайн вышла Земфира.','296-zemfira-pochemu-borderlajn','[{"html":"<br /> Зимой 2021, после долгого дистанцирования, на свет с новым альбомом под названием \"Бордерлайн\" вышла Земфира. Ранее она давала о себе знать только совместной с Mujuice композицией «Джозеф» на стихи Бродского в 2018 году и «Крымом» в 2020-м. \"Бордерлайн\" - это первый за 8 лет полноформатный студийный альбом.","type":"paragraph"},{"html":"“Бордерлайн - пограничное расстройство личности, при котором человек не в состоянии контролировать свои эмоции, не выносит отказов и критики. Так и весь альбом вышел пограничным”, - говорит музыкальный критик Борис Барабанов. Альбом и правда наполнен депрессией и мраком, беспросветностью и отчаянием, что неустанно доказывает песня за песней нового альбома. Свою лепту еще внесла прошедшая пандемия, которая показала, насколько мы все уязвимы и на каком расстоянии от обрыва каждый из нас.","type":"paragraph"},{"html":"<br /><b>“Она давно “все””</b>","type":"paragraph"},{"html":"Зумеры в твиттере и заложники современной системы мышления негодуют над тематикой альбома. Нет ни слова про Навального и политику, а некоторые названия песен вообще написаны с ошибкой, что сильно может вывести из себя любого перфекциониста и филолога.","type":"paragraph"},{"html":"«Такой альбом мог бы выйти в любом году, что в 2007-м, что в 2021-м!» — он не в моменте, возмущена молодежь.","type":"paragraph"},{"html":"Земфира вырастила на своем творчестве не одно поколение, и у каждого есть хотя бы одна ее песня, которая стала некой точкой отсчета. У критика Максима Семеляка это целый альбом «Вендетта» (2005), который бросил его в холодный пот от накала эмоций и страстей. Тогда еще громко хлопали и падали в колени Земфире в специальном выпуске программы Андрея Малахова, посвященной разбору такого простого необычного творчества.","type":"paragraph"},{"html":"Альбом по статусу получился сродни самой Земфире. Такой же угрюмый и великий по статусу, как и она сама. Причем величие Земфиры сложилось буквально вопреки всему. У нее сложный характер. Отсюда и имидж. Все это с сочетанием ее заманчивой сексуальности и противоречивым молчанием. Такой микс буквально сбивает с толку еще перед прослушиванием пластинок.","type":"paragraph"},{"html":"<br /> Альбом однозначно требует внимания и времени, чтобы его послушать и понять. “Бордерлайн” - это теперь не только медицинский диагноз, поясняющий расстройство личности, но и рубеж, а в чем-то и обнуление Земфиры.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmr12bk0120uktabfi7096g"},{"mediaId":"cmrmr12v10121uktag0xuegdm"}]}]'::jsonb,'cmrmr11z4011zuktaq6drd8ue','cmrm8kz36000ckwtabqfh3f4h','cmrm8kze2000gkwtad8wkij5y','cmrmpdrom0000sstarkqxwts4','2021-03-28T06:00:00.000Z'::timestamp,NULL,NULL,NULL,296,'/sobytija/muzyka/296-zemfira-pochemu-borderlajn.html','2026-07-15T21:06:29.094Z'::timestamp,'2026-07-16T14:01:20.309Z'::timestamp,'''2005'':241C ''2007'':196C ''2018'':50C ''2020'':55C ''2021'':5B,20C,200C ''8'':61C ''cmrmr12bk0120uktabfi7096g'':369C ''cmrmr12v10121uktag0xuegdm'':371C ''galleri'':367C ''mujuic'':43C ''paragraph'':67C,138C,144C,184C,209C,275C,330C,365C ''альб'':65C,90C,98C,187C,239C,277C,332C ''альбом'':13B,28C,115C,157C ''андре'':266C ''барабан'':97C ''беспросветн'':105C ''бордерлайн'':3A,16B,31C,57C,69C,343C ''борис'':96C ''бродск'':48C ''брос'':243C ''буквальн'':299C,321C ''ве'':89C ''велик'':288C ''велич'':296C ''вендетт'':240C ''внесл'':119C ''вниман'':335C ''возмущ'':206C ''вообщ'':169C ''вопрек'':300C ''времен'':337C ''всем'':301C ''вывест'':176C