тус'':279C,290C ''стих'':47C ''страст'':252C ''студийн'':64C ''так'':270C ''твиттер'':148C ''творчеств'':215C,273C ''тематик'':156C ''толк'':324C ''точк'':231C ''треб'':334C ''угрюм'':286C ''уязвим'':127C ''филолог'':182C ''характер'':305C ''хлопа'':256C ''холодн'':246C ''хот'':223C ''цел'':238C ''человек'':75C ''чем-т'':358C ''эмоц'':81C,250C ''эт'':58C,237C,310C,344C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqvoc700lkuktanp3hkcv4','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Эвилина Заляева: "Пусть все дороги ведут к успеху"','В сутках всего 24 часа и как все успеть.','436-jevilina-zaljaeva-pust-vse-dorogi-vedut-k-uspehu','[{"html":"<strong>В сутках всего 24 часа и как все успеть. В жизни юной модели Эвилины есть место для танцев, моделинга, музыки. Она успевает все и даже занимает призовые места, однако не против заняться еще чем-нибудь интересным, ведь жизнь – это удивительное приключение и успеть нужно все!</strong>","type":"paragraph"},{"html":"<strong>Esque.kids:</strong> Эвилина, здравствуй. В каком классе ты учишься? -","type":"paragraph"},{"html":"<strong>Эвилина:</strong> Здравствуйте. Я учусь в 3 классе.","type":"paragraph"},{"html":"<strong>Esque.</strong><strong>kids:</strong> Ты тренируешься в Спортивной школе олимпийского резерва «Первая» и имеешь 2 взрослый разряд. Расскажи о школе и как ты получила уже 2 разряд?","type":"paragraph"},{"html":"<strong>Эвилина: </strong>Я с трех лет занималась в различных спортивных кружках, и все таки выбрала акробатику.","type":"paragraph"},{"html":"Для получения спортивного разряда необходимо очень много тренироваться, принимать участие в соревнованиях и выполнять нормы и требования по своему виду спорта, чем я и занимаюсь практически каждый день. Я неоднократно участвовала в межмуниципальных и республиканских соревнованиях и занимала призовые места, выполняла все необходимые требования и поэтому получила 2 взрослый разряд.","type":"paragraph"},{"html":"Все это благодаря моим любимым тренерам – Батмановой Юлии Александровне и Батмановой Ангелине Олеговне! Они очень чуткие и внимательные, всегда видят, какое у меня настроение, учат преодолевать страхи и неудачи, тренировки проходят эффективно и разнообразно. Я благодарна своим тренерам за то, что они учат меня упорству и силе характера – это пригодится мне не только в спорте, но и в моделинге.","type":"paragraph"},{"html":"<strong>Esque.</strong><strong>kids:</strong> Кроме спортивной школы, в твоей жизни есть танцы, музыка и моделинг. В каких танцевальных конкурсах и модельных показах ты принимала участие?","type":"paragraph"},{"html":"<strong>Эвилина: </strong>Только осенью я пришла в школу танцев Дарьи Шаровой, и сразу влюбилась в танцы! Мне очень помогли акробатика и гимнастика, поэтому я быстро втянулась. Принимала участие в детском новогоднем шоу «STAR SHINE» в г. Казани. Неоднократно участвовала в соревнованиях РОО «ФФАРТ» в составе команды хип-хоп «LIL FLAMERS». Участвовала в VII ежегодном открытом международном хореографическом конкурсе «ЯТАНЦЕВАСТЕЕ» в номинации «Уличный танец» соло и заняла 1 место","type":"paragraph"},{"html":"Участвовала в модных показах: «ESTET Fashion Week», (Москва); «Fashion Bitva 2021» (Казань), «Volga Fashion Week» (Казань), «Fashion Bitva 2022» (Москва), а также приняла участие в VIII Республиканском детском конкурсе «Little TOP MODEL of TATARSTAN 2022», даже вышла в финал и вошла в ТОП-10.","type":"paragraph"},{"html":"<strong>Esque.</strong><strong>kids:</strong> Я знаю, что ты занимаешься в 3 модельных школах. Каких? Почему именно несколько школ?","type":"paragraph"},{"html":"<strong>Эвилина: </strong>Просто не могла сразу определиться. Я закончила курс актерского мастерства в модельной школе «ПРЕСТИЖ», занималась в «KIDS STUDIO MODELS», где узнала много нового и интересного, прошла 2 сезона в модельной школе «Ильдан Лик» и решила продолжить занятия в этой школе.","type":"paragraph"},{"html":"<strong>Esque.</strong><strong>kids:</strong> Расскажи подробнее о своих музыкальных увлечениях. Ты занимаешься вокалом?","type":"paragraph"},{"html":"<strong>Эвилина:</strong> Да, я учусь в музыкальной школе по классу вокала в 3 классе и у меня супер преподаватель по вокалу Марина Николаевна Григорьева. Мне кажется, она сможет научить петь любого!!!","type":"paragraph"},{"html":"<strong>Esque.</strong><strong>kids:</strong> Эвилина, всем нам стало интересно узнать, как же ты все успеваешь?","type":"paragraph"},{"html":"<strong>Эвилина: </strong>Иногда мне кажется, что в сутках слишком мало часов для всех моих занятий, но будь на пару часов больше я обязательно дополнила бы свой список.","type":"paragraph"},{"html":"<strong>Esque.</strong><strong>kids:</strong> И все же, какое из твоих занятий основное?","type":"paragraph"},{"html":"<strong>Эвилина:</strong> Для меня пока они все главные – ведь благодаря им я развиваю такие качества как гибкость, пластику, чувство ритма, грацию.","type":"paragraph"},{"html":"<strong>Esque.</strong><strong>kids:</strong> Ты уже понимаешь с какой профессией хочешь связать свою жизнь?","type":"paragraph"},{"html":"<strong>Эвилина: </strong>Мечтаю вырасти и стать чемпионкой мира по акробатике.","type":"paragraph"},{"html":"<strong>Esque.</strong><strong>kids:</strong> А как же моделинг?","type":"paragraph"},{"html":"<strong>Эвилина: </strong>О, это еще все новое для меня, но мне очень нравится и я буду стараться правильно распределять свое время, чтобы успеть все, ведь кроме показов в моделинге, я учусь быть стильной и модной, а также учусь красиво ходить и чувствовать себя уверенно на подиуме, учусь правильно ухаживать за собой и перевоплощаться в разные образы.","type":"paragraph"},{"html":"<strong>Esque.</strong><strong>kids:</strong> Эвилина и напоследок, пару слов нашим читательницам.","type":"paragraph"},{"html":"<strong>Эвилина: </strong>Быть на позитиве! Никогда не терять оптимизма, желаю только положительных эмоций!","type":"paragraph"},{"html":"Встречать в жизни поменьше преград, а если они и будут, то уверенно преодолевать. Пусть все дороги ведут к успеху, а все планы воплощаются в жизнь на максимальной скорости!","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqvo0u00liuktaxlncc1dk"},{"mediaId":"cmrmqvoax00ljuktalpf1k5w9"}]}]'::jsonb,'cmrmqvnpx00lhuktambdhxg2d','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-04-19T06:00:00.000Z'::timestamp,NULL,NULL,NULL,436,'/esquekids/obrazovanie-ek/436-jevilina-zaljaeva-pust-vse-dorogi-vedut-k-uspehu.html','2026-07-15T21:02:16.951Z'::timestamp,'2026-07-16T13:59:16.402Z'::timestamp,'''-10'':389C ''1'':341C ''2'':100C,111C,181C,439C ''2021'':356C ''2022'':364C,380C ''24'':12B,21C ''3'':83C,401C,481C ''bitva'':355C,363C ''cmrmqvo0u00liuktaxlncc1dk'':738C ''cmrmqvoax00ljuktalpf1k5w9'':740C ''esqu'':88C,249C,393C,456C,503C,548C,584C,611C,678C ''esque.kids'':67C ''estet'':350C ''fashion'':351C,354C,359C,362C ''flamer'':324C ''galleri'':736C ''kid'':89C,250C,394C,429C,457C,504C,549C,585C,612C,679C ''lil'':323C ''littl'':375C ''model'':377C,431C ''paragraph'':65C,76C,86C,114C,132C,185C,247C,273C,344C,391C,410C,454C,468C,501C,517C,546C,559C,582C,597C,609C,618C,676C,688C,703C,734C ''shine'':307C ''star'':306C ''studio'':430C ''tatarstan'':379C ''top'':376C ''vii'':327C ''viii'':371C ''volga'':358C ''week'':352C,360C ''акробатик'':130C,293C,607C ''актерск'':421C ''александровн'':195C ''ангелин'':198C ''батманов'':193C,197C ''благодар'':189C,569C ''благодарн'':222C ''буд'':534C,634C ''будут'':714C ''быстр'':298C ''ведут'':6A,721C ''взросл'':101C,182C ''вид'':153C,206C ''влюб'':287C ''внимательн'':204C ''вока'':479C ''вокал'':466C,489C ''воплоща'':727C ''вошл'':386C ''врем'':639C ''всем'':506C ''встреча'':705C ''втянул'':299C ''выбра'':129C ''выполня'':147C,174C ''выраст'':601C ''вышл'':382C ''г'':309C ''гибкост'':576C ''гимнастик'':295C ''главн'':567C ''грац'':580C ''григорьев'':492C ''дар'':283C ''ден'':161C ''детск'':303C,373C ''дополн'':541C ''дорог'':5A,720C ''ежегодн'':328C ''жела'':698C ''жизн'':28C,56C,256C,595C,707C,729C ''законч'':419C ''заляев'':2A ''занима'':43C,121C,158C,171C,399C,427C,465C ''заня'':49C,340C ''занят'':449C,532C,556C ''здравс