INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqymwb00tjuktaj9saxbnn','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'“Бояться нельзя вакцинироваться”: откуда берется страх перед прививкой от COVID-19?','Вспышка коронавирусной инфекции в прошлом году оказалась внезапной и вызвала сильный страх у россиян.','370-bojatsja-nelzja-vakcinirovatsja-otkuda-beretsja-strah-pered-privivkoj-ot-covid-19','[{"html":"Коронавирусная инфекция, от которой уже свободно можно отбросить слово “новая”, за полтора года стала вполне привычной. Весь мир пережил ряд волн заболеваемости, месяцы изоляции и масочные режимы. Просвет в темноте пандемии появился достаточно быстро: в июне прошлого в Китае была зарегистрирована первая вакцина от COVID-19, а тем же летом, в августе, Россия представила свой препарат - “Спутник V”. Однако желающих сделать прививку от новой инфекции оказалось немного. Более того: даже спустя год после выхода вакцины, россияне все еще трепещут при слове “вакцинация”. В чем причина страха и как от него избавиться? ESQUE провел опрос среди россиян и узнал мнение психолога. Как оказалось, у страха целый ряд причин.","type":"paragraph"},{"html":"Многие респонденты утверждают, что боятся реакции организма и саму вакцину, поскольку уверены - она еще недостаточно исследована. С их мнением согласен и психолог Александр Цапенко.","type":"paragraph"},{"html":"“Дело в том, изначально шла речь о схожести симптомов гриппа, ОРВИ и COVID-19. У большинства людей уже был опыт вакцинации от гриппа, и не всегда успешный. Вирус постоянно мутирует, поэтому многие не верят, что вакцина подойдет к уже изменившейся инфекции. “Зачем рисковать здоровьем, если в конечном счете это не поможет?” - одна из распространенных причин отказа от вакцинации”, - рассказал Александр Цапенко.","type":"paragraph"},{"html":"Свою роль сыграли неудачные эксперименты в борьбе с другими болезнями, например, с созданием вакцины от туберкулеза, уверен психолог. Над ней работали годами, а результат получился достаточно неэффективным. Что уж говорить о вакцине от коронавирусной инфекции, которая была создана в короткие сроки.","type":"paragraph"},{"html":"“Если говорить об опасениях относительно реакции организма, они также оказались не беспочвенными. Каждый перенес вакцинацию по-разному. Люди знают и понимают, что прививка помогает переболеть коронавирусом в легкой форме, не доводя ситуацию до летального исхода. Но у них на глазах были примеры, когда человек после прививки оказывался тяжело больным, вплоть до попадания в больницу”, - добавил специалист.","type":"paragraph"},{"html":"Вторая волна заболеваемости COVID-19 началась сразу после массового ажиотажа вокруг прививок. Он пришелся на время глобальной недоступности, когда для непривитых закрылись выезды из страны, входы в рестораны и другие общественные заведения. Началась тотальная вакцинация, в места массового скопления выстроились очереди, что привело к новой вспышке заболеваемости.","type":"paragraph"},{"html":"“Медицинские работники связывают данный факт с началом периода отпусков, когда люди массово вырвались на отдых. Но некоторые россияне продолжают винить вакцину. Они уверены, что именно после прививки люди с подорванным иммунитетом заражали других”, - поделился Александр Цапенко.","type":"paragraph"},{"html":"Когда коронавирус вспыхнул в Ухани, весь мир решил, что болезнь далеко. С приходом инфекции в Россию жители отдаленных городов были уверены, что до них ей точно никак не добраться. Увы, COVID-19 прошелся практически по каждому уголку земли, но многие до сих пор продолжают верить, что новая инфекция - не более, чем обычный грипп. На арену выходят даже сторонники теории заговора, утверждающие, что информация о “мифической” болезни предана огласке намеренно.","type":"paragraph"},{"html":"“Я знаю тех, кто уверен, что это общая политическая акция, к примеру, для списания денег. Они не понимают, насколько на самом деле серьезен COVID-19, им нужны прямые доказательства: собственная заболеваемость или болезнь близкого человека”, - сообщил Александр Цапенко.","type":"paragraph"},{"html":"Сторонники так называемой конспирологии активизировались сразу после вспышки коронавируса. Масла в огонь добавили СМИ, предоставившие информацию о прививках под кривым углом еще до начала массовой прививочной кампании.","type":"paragraph"},{"html":"<i>“Многие средства массовой информации связывали вакцинацию с планами руководителя компании Microsoft о чипировании населения. Якобы, перед компанией стояла задача о сокращении населения и тотальный контроль над людьми, а вакцинация поможет воплотить эти планы в жизнь. Людская фантазия безгранична, поэтому теория постоянно дополнялась новыми подробностями”, - рассказал психолог.</i>","type":"paragraph"},{"html":"Видимо, со временем эта мысль сошла на нет: среди респондентов нашего опроса не нашлось ни одного, кто проводит параллели между вакцинацией и чипированием.","type":"paragraph"},{"html":"Все больше регионов вводят обязательную вакцинацию для сотрудников, а города и страны остаются закрытыми для антипрививочников. Этот факт сыграл на руку любителям подзаработать. В начале лета активизировались “бизнесмены”, желающие нажиться на продаже поддельных сертификатов о вакцинации. При чем подобные услуги предоставляют не только обычные мошенники, но и игроки теневого рынка, предлагающие практически официальный сертификат со всеми вытекающими: выбор региона, дата прививки и оформление через “Госуслуги”. Немалое количество россиян выбирают сделку на черном рынке сертификатов куда охотнее, чем саму прививку. Данный шаг кажется вполне выгодным: цена вопроса в среднем составляет 5 тысяч рублей. На деле любой подобный сертификат приравнивается к подделке официального документа и является уголовно-наказуемым деянием.","type":"paragraph"},{"html":"Тем ни менее, несмотря на не угасающие страхи россиян, психолог Александр Цапенко уверен - в дальнейшем ситуация все же изменится. Правда, ее исход зависит в первую очередь от того, как скоро прекратится навязывание вакцинации.","type":"paragraph"},{"html":"“В нашей стране отлично работает принцип дефицита. Если люди поймут, что единственным спасением является вакцина, но она имеется в ограниченном количестве, спрос на нее возрастет, - подчеркнул Александр. - Что касается самой необходимости в прививке, у меня есть сомнения насчет того, нужна ли она переболевшим людям. При этом я уверен, что тем, кто еще не сталкивался с COVID-19, прививаться нужно. Других вариантов защиты в настоящий момент нет”. <br /><br />Журналист: Валентина Поликарпова <br />","type":"paragraph"}]'::jsonb,'cmrmqymuw00tiuktaw2zj7xl1','cmrm8kzpw000mkwtaocyn5161',NULL,'cmrmpdrom0000sstarkqxwts4','2021-09-06T06:00:00.000Z'::timestamp,NULL,NULL,NULL,370,'/psihologija/370-bojatsja-nelzja-vakcinirovatsja-otkuda-beretsja-strah-pered-privivkoj-ot-covid-19.html','2026-07-15T21:04:35.051Z'::timestamp,'2026-07-16T14:00:12.818Z'::timestamp,'''-19'':11A,71C,176C,335C,451C,516C,841C ''5'':727C ''covid'':10A,70C,175C,334C,450C,515C,840C ''esqu'':117C ''microsoft'':573C ''paragraph'':134C,161C,225C,269C,329C,379C,418C,490C,531C,561C,610C,636C,747C,783C,855C ''v'':83C ''август'':77C ''ажиотаж'':340C ''активизирова'':537C,664C ''акц'':501C ''александр'':158C,222C,415C,528C,759C,811C ''антипрививочник'':653C ''арен'':474C ''безграничн'':600C ''берет'':5A ''беспочвен'':282C ''бизнесм'':665C ''близк'':525C ''бо'':140C ''болезн'':236C,429C,485C,524C ''больн'':320C ''больниц'':325C ''большинств'':178C ''борьб'':233C ''боя'':1A ''быстр'':59C ''вакцин'':68C,100C,145C,198C,240C,258C,401C,799C ''вакцинац'':107C,183C,220C,285C,365C,568C,591C,632C,643C,673C,781C ''вакцинирова'':3A ''валентин'':852C ''вариант'':845C ''ввод'':641C ''ве'':42C,425C ''вер'':196C,464C ''видим'':612C ''вин'':400C ''вирус'':190C ''внезапн'':19B ''возрастет'