еловек'':315C,526C ''черн'':709C ''чипирован'':575C,634C ''шаг'':718C ''шла'':167C ''эксперимент'':231C ''эт'':211C,498C,615C ''явля'':741C,798C ''якоб'':577C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqesm0003xpotas0q6s6hq','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Под знаком ''Звезды'': Вечер, который объединил сердца и усилия','Московским представительством была организована презентация Гуманитарного Центра Звезда в популярном заведении Руки Вверх!Бар.','656-pod-znakom-zvezdy-vecher-kotoryj-obedinil-serdca-i-usilija','[{"html":"Московским представительством была организована презентация Гуманитарного Центра \"Звезда\" в популярном заведении \"Руки Вверх!","type":"paragraph"},{"html":"Бар\". Это событие стало значимым моментом, собрав общественных и культурных деятелей, а также политиков, объединив их общей целью — привлечением новых друзей и партнеров для поддержки военнослужащих и их семей.","type":"paragraph"},{"html":"Мероприятие возглавил Андрей Карасёв, руководитель московского отделения ГЦ \"Звезда\" и организационного отдела общественного","type":"paragraph"},{"html":"движения \"Зов Народа\". Благодаря его энергии и преданности социальным инициативам, вечер стал платформой для взаимодействия и","type":"paragraph"},{"html":"сотрудничества.","type":"paragraph"},{"html":"Среди выступавших артистов были Вячеслав Цуканов, лидер рок-группы \"Tsukanov-Studio\" и руководитель ГЦ \"Звезда\", Андрей Гуров, солист","type":"paragraph"},{"html":"группы \"Ласковый май\", оперная певица Дарина Чижик, Константин Легостаев, известный певец, композитор и актёр, певица Юлия Лой,","type":"paragraph"},{"html":"Михаил Долотов из группы Песняры, Евгений Холмский из \"Турбомода\" и Тэя Татвиль, обаятельная певица.","type":"paragraph"},{"html":"Присутствовали также знаменитости и значимые общественные деятели: Михаил Владимирович Кузьмин, депутат Государственной думы; Сергей Зайцев - председатель общественного движения «Зов Народа», Земфира Алиева, боец смешанных единоборств; Мария Пасека, призёр Олимпийских игр и чемпионка мира; Елена Москалева, представитель Кавминвод; Марина Ильина, руководитель Подольского отделения АНО \"Звезда\"; Александр Торбенков, представитель компании Эстель; Сергей Валерьевич Терехов, генеральный директор «Русского Торгового Дома»; Елена Волкова - общественная организация «Справедливый Север»; Кира Смитт, продюсер и общественный деятель, а также Роман Синьков, шоумен, актёр и режиссёр, который не только присутствовал на","type":"paragraph"},{"html":"мероприятии, но и выступал в роли соорганизатора и ведущего вечера.","type":"paragraph"},{"html":"Особенно важную роль в организации мероприятия сыграл Удай Абу- Зарук, руководитель \"Тренд Студио\". Благодаря его усилиям и","type":"paragraph"},{"html":"использованию медийных ресурсов, презентация получила широкое общественное внимание и поддержку. Удай продемонстрировал, как медиа могут служить благим делам, мобилизуя ресурсы и поддержку для социальных инициатив.","type":"paragraph"},{"html":"Эта презентация ГЦ \"Звезда\" подчеркнула значимость культуры и общественной активности в поддержке нуждающихся, демонстрируя, как","type":"paragraph"},{"html":"совместные усилия могут приводить к значительным изменениям и помощи тем, кто в этом нуждается.","type":"paragraph"}]'::jsonb,'cmrmqeskc003wpota5vf3ny28','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-05-15T06:00:00.000Z'::timestamp,NULL,NULL,NULL,656,'/svetskaja-hronika/656-pod-znakom-zvezdy-vecher-kotoryj-obedinil-serdca-i-usilija.html','2026-07-15T20:49:09.336Z'::timestamp,'2026-07-16T13:56:49.476Z'::timestamp,'''paragraph'':38C,70C,86C,105C,109C,132C,152C,169C,254C,267C,287C,315C,333C,350C ''studio'':123C ''tsukanov'':122C ''tsukanov-studio'':121C ''аб'':277C ''актер'':147C,245C ''активн'':326C ''александр'':215C ''алиев'':192C ''ан'':213C ''андр'':74C,128C ''артист'':113C ''бар'':23B,40C ''благ'':305C ''благодар'':91C,282C ''боец'':193C ''