INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqy8zd00sjuktahn152pp6','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Fashion bitva в Сочи','7 ноября в Сочи состоится региональный этап конкурса дизайнеров FASHION BITVA.','379-fashion-bitva-v-sochi','[{"html":"7 ноября в Сочи состоится региональный этап конкурса дизайнеров FASHION BITVA. В конкурсе примут участие 10 дизайнеров из разных регионов страны. Оценит участников опытное жюри, председателем которого станет глава модного дома Grach HAUTE Couture Устян Грач Завенович.","type":"paragraph"},{"html":"Для Юга России это важное событие, об этом рассказала региональный представитель конкурса Fashion bitva в Сочи - Лиана Вартанова:","type":"paragraph"},{"html":"<em>“Этот конкурс - значимое событие для мира моды города Сочи и всего Юга России. Вдохновляющие примеры успешных дизайнеров из Москвы и Санкт-Петербурга, которые приедут на показ мод, будут способствовать развитию fashion-индустрии нашего региона”.</em>","type":"paragraph"},{"html":"В этом году конкурс пройдет в двух направлениях: дизайн взрослой и детской одежды.","type":"paragraph"},{"html":"Победитель во взрослом направлении, традиционно получит в награждение поездку в Москву на финал Fashion Битва. Проезд, проживание и участие предоставляют организаторы конкурса.","type":"paragraph"},{"html":"Победитель в детском направлении получит уникальную возможность пройти стажировку в Fashion Dept Association – 4-х дневный курс повышения квалификации. Обучение возможно, как на очной, так и на заочной форме.","type":"paragraph"},{"html":"“Однажды, я сшила дочке платье на день рождения и не смогла остановиться. Думаю, что предстоящая битва откроет большие перспективы перед победителем”, - отметила дизайнер из Сочи, владелица бренда \"Domini\", Лариса Полюбина.","type":"paragraph"},{"html":"Каждого гостя ждет вдохновляющая обстановка роскошного автосалона Audi, фуршет и только положительные эмоции, а главное - новые знания о современном мире моды.","type":"paragraph"},{"html":"Битва проходит 9-й раз при поддержке глянцевого издания ESQUE. Финал состоится в декабре 2021 года, в котором примут участие все победители 9 сезона.","type":"paragraph"},{"html":"Раскроем секрет и об изменении формата полуфинала. Каждый гость и участник сможет познакомиться с творчеством дизайнеров еще до начала конкурса. На мероприятии будет представлена фотовыставка, на которой экспонаты передадут главный посыл каждой коллекции.","type":"paragraph"},{"html":"Для молодых дизайнеров это возможность ярко заявить о себе:","type":"paragraph"},{"html":"<em>“У меня молодой развивающийся бренд одежды. Пока что имеющегося количества моделей недостаточно, поэтому я еще занимаюсь созданием. Я представлю сразу два направления. Это коллекция из денима, включающая в себя повседневные, вечерние и даже классические образы. Второе направление - круиз линия. В нее вошла круглогодичная, комфортная одежда для путешествий. Подготовка к показу идет полным ходом. Я очень переживаю и надеюсь на победу”, - рассказала дизайнер из Москвы, Ангелина Догуоглоу.</em>","type":"paragraph"},{"html":"А для многих – это не только соревнование, но и рождение чего-то нового:","type":"paragraph"},{"html":"<em>“Конкурсы, показы и создание собственной линии - вся моя жизнь. Я обожаю создавать, ведь эмоции, которые ты испытываешь от процесса - создания и вынашивания идеи - сравнимы с рождением ребенка!”, - поделилась участница из Краснодара, Анжелла Гончарова. </em>","type":"paragraph"},{"html":"После пандемии многие дизайнеры пересмотрели свой взгляд на моду и то, какой мода предстанет перед нами после эпидемии, узнаем в Сочи.","type":"paragraph"},{"html":"<i>Место проведения: г. Сочи,</i>","type":"paragraph"},{"html":"<i>Audi Центр, ул. Кипарисовая, 16/1.</i>","type":"paragraph"},{"html":"<i>Время: 17:00</i>","type":"paragraph"}]'::jsonb,'cmrmqy8xo00siuktau9fsu12y','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2021-09-30T06:00:00.000Z'::timestamp,NULL,NULL,NULL,379,'/projects-esque/fashion-bitva/379-fashion-bitva-v-sochi.html','2026-07-15T21:04:17.017Z'::timestamp,'2026-07-16T14:00:06.359Z'::timestamp,'''00'':484C ''10'':31C ''16/1'':478C ''17'':483C ''2021'':260C ''4'':170C ''7'':5B,16C ''9'':248C,268C ''associ'':169C ''audi'':229C,474C ''bitva'':2A,15B,26C,69C ''coutur'':49C ''dept'':168C ''domini'':216C ''esqu'':255C ''fashion'':1A,14B,25C,68C,109C,145C,167C ''fashion-индустр'':108C ''grach'':47C ''haut'':48C ''paragraph'':54C,75C,114C,130C,155C,187C,220C,244C,271C,307C,319C,388C,405C,441C,465C,472C,480C,486C ''автосалон'':228C ''ангелин'':385C ''анжелл'':438C ''битв'':146C,204C,246C ''больш'':206C ''бренд'':215C,325C ''будут'':105C ''важн'':60C ''вартанов'':73C ''вдохновля'':90C,225C ''вечерн'':351C ''взгляд'':449C ''взросл'':125C,134C ''включа'':347C ''владелиц'':214C ''возможн'':163C,177C,313C ''вошл'':362C ''врем'':482C ''вся'':413C ''втор'':356C ''вынашиван'':428C ''г'':469C ''глав'':44C ''главн'':236C,302C ''глянцев'':253C ''год'':118C,261C ''гончаров'':439C ''город'':84C ''гост'':223C,281C ''грач'':51C ''двух'':122C ''декабр'':259C ''ден'':195C ''деним'':346C ''детск'':127C,159C ''дизайн'':124C ''дизайнер'':13B,24C,32C,93C,211C,288C,311C,382C,446C ''дневн'':172C ''догуогло'':386C ''дом'':46C ''дочк'':192C ''дума'':201C ''ждет'':224C ''жизн'':415C ''жюр'':40C ''завенович'':52C ''занима'':336C ''заочн'':184C ''заяв'':315C ''знан'':238C ''значим'':79C ''ид'':429C ''идет'':371C ''издан'':254C ''изменен'':277C ''имеющ'':329C ''индустр'':110C ''испытыва'':423C ''й'':249C ''кажд'':222C,280C,304C ''квалификац'':175C ''кипарисов'':477C ''классическ'':354C ''количеств'':330C ''коллекц'':305C,344C ''комфортн'':364C ''конкурс'':12B,23C,28C,67C,78C,119C,153C,292C,407C ''котор'':42C,100C,263C,299C,421C ''краснодар'':437C ''круглогодичн'':3