INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsso6009quktacjvdxu27','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Ряд британских брендов проведут «пятую Неделю моды»','В ближайшие дни в Лондоне пройдут показы крупных брендов, которые ранее отменили свои шоу на сентябрьской Неделе моды в английской столице из-за смерти королевы Елизаветы II.','572-rjad-britanskih-brendov-provedet-pjatuju-nedelju-mody','[{"html":"<b>В ближайшие дни в Лондоне пройдут показы крупных брендов, которые ранее отменили свои шоу на сентябрьской Неделе моды в английской столице из-за смерти королевы Елизаветы II. Новые коллекции представят Alexander McQueen, Raf Simons и Ralph Lauren.</b>","type":"paragraph"},{"html":"Издание Business of Fashion назвало эти показы «пятой Неделей моды». Четыре основные Недели прошли в сентябре: миланская, парижская, нью-йоркская и лондонская. Сейчас в британской столице проходит крупная ярмарка современного искусства Frieze. Благодаря ей в городе много туристов, что, вероятно, хорошо отразиться на популярности показов.","type":"paragraph"},{"html":"<br />Официальная Неделя моды в Лондоне проходила с 16 по 20 сентября. В это время в Великобритании был объявлен национальный траур по умершей королеве Елизавете II. <b> </b>В знак уважения к монарху Alexander McQueen, Raf Simons и Ralph Lauren, которые должны были представить свои коллекции на Неделе моды в Лондоне, перенесли показы на октябрь.","type":"paragraph"}]'::jsonb,'cmrmqsslz009puktab2d0d3fr','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2022-10-10T06:00:00.000Z'::timestamp,NULL,NULL,NULL,572,'/fashion/news-2/572-rjad-britanskih-brendov-provedet-pjatuju-nedelju-mody.html','2026-07-15T21:00:02.598Z'::timestamp,'2026-07-16T13:57:45.899Z'::timestamp,'''16'':133C ''