INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr1ak0012uukta4ubdo8kc','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Я все смогу','Покажите нам ту, которая не мечтает о своем бизнесе, и мы докажем, что скоро эта мечта ее тоже настигнет.','290-ja-vse-smogu','[{"html":"Покажите нам ту, которая не мечтает о своем бизнесе, и мы докажем, что скоро эта мечта ее тоже настигнет. Это определенный этап, который возникает у каждой. Хотя бы на минуту, но обязательно возникает. И тут острым встает вопрос гендерных разделений и стереотипов. Как успешно вести бизнес и не поддаваться на провокации современного общества, которое так и пытается отнять у девочек лакомый кусочек?","type":"paragraph"},{"html":"Читаем и впитываем.","type":"paragraph"},{"html":"<strong>Это ее дело. 10 историй о том, как делать бизнес красиво | «Однажды» Лаборатория</strong>","type":"paragraph"},{"html":"Вдохновляющие истории о женщинах, которые слышат себя и добиваются исключительно желаемого. История бывшей учительницы по физике, а ныне владелицы кондитерской фабрики, придаст вам уверенности, а рассказ девушки, прошедшей путь от мастера цеха Микояновского мясокомбината до совладелицы \"Велком\", покажет, как можно добиться всего на свете, если ты дружишь сам с собой.","type":"paragraph"},{"html":"<b>Девочки делают бизнес. Или как открыть свое дело и начать зарабатывать | Пигалева Екатерина</b>","type":"paragraph"},{"html":"Екатерина Пигалева - молодая предпринимательница с миллионными оборотами и основатель сети студий эпиляции Sweet Epil на своем примере показывает принципиально важные вещи в действии, которые помогут каждой девушке встать на ноги финансово и морально. В 99% случаев после прочтения данного издания идея собственного проекта или полного бизнеса приходит, как во сне: так же быстро и ярко. Как придумать, создать, реализовать и не падать? Об этом и еще многом пишет Екатерина в своей книге «Девочки делают бизнес. Или как открыть свое дело и начать зарабатывать».","type":"paragraph"},{"html":"<strong>#</strong><strong>Girlboss</strong><strong>. Как я создала миллионный бизнес, не имея денег, офиса и высшего образования | София Аморузо</strong>","type":"paragraph"},{"html":"История 20-летней Софи Аморузо, в которой она была уволена с позором из обувного бутика, гласит о колоссальной уверенности и вере в себя. Уже через пару лет она стала владелицей бизнеса, стоимость которого составляет 100 миллионов долларов. Как она жила эти годы, которые по итогу научили ее здоровому феминизму и правильному ведения бизнеса? Особое внимание уделяется тому, что у Софи нет образования и богатых родителей. История, которая коротко звучит, как «все сама».","type":"paragraph"},{"html":"Эта книга – сборник лайфхаков и коллекция личного практического опыта. В ней вы узнаете, как добиться невероятного успеха, даже если ты совершенно не умеешь играть по правилам бизнес-сообщества. Источник вдохновения в 200 страницах.","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmr1a4x012suktagfmh5awp"},{"mediaId":"cmrmr1ahv012tukta4jyjcj74"}]}]'::jsonb,'cmrmr19oz012ruktarg7r9mbb','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz8q000ekwtadrt5g1dn','cmrmpdrom0000sstarkqxwts4','2021-03-23T06:00:00.000Z'::timestamp,NULL,NULL,NULL,290,'/sobytija/iskusstvo/290-ja-vse-smogu.html','2026-07-15T21:06:39.024Z'::timestamp,'2026-07-16T14:01:26.234Z'::timestamp,'''10'':97C ''100'':317C ''20'':284C ''200'':390C ''99'':213C ''cmrmr1a4x012suktagfmh5awp'':397C ''cmrmr1ahv012tukta4jyjcj74'':399C ''epil'':192C ''galleri'':395C ''girlboss'':265C ''paragraph'':86C,92C,108C,161C,177C,263C,281C,356C,393C ''sweet'':191C ''аморуз'':279C,287C ''бизнес'':12B,31C,68C,103C,165C,224C,253C,270C,313C,335C,385C ''бизнес-сообществ'':384C ''богат'':346C ''бутик'':297C ''бывш'':122C ''быстр'':231C ''важн'':198C ''вдохнов