''пут'':138C ''пыта'':79C ''разделен'':62C ''рассказ'':135C ''реализова'':237C ''родител'':347C ''сам'':354C ''сборник'':360C ''свет'':153C ''сво'':11B,30C,169C,194C,249C,257C ''сет'':188C ''скор'':17B,36C ''случа'':214C ''слышат'':115C ''смог'':3A ''сне'':228C ''соб'':159C ''собствен'':220C ''совершен'':378C ''совладелиц'':145C ''современ'':74C ''созда'':236C,268C ''сообществ'':386C ''составля'':316C ''соф'':278C,286C,342C ''стал'':311C ''стереотип'':64C ''стоимост'':314C ''страниц'':391C ''студ'':189C ''том'':339C ''ту'':6B,25C ''уверен'':133C,301C ''увол'':292C ''уделя'':338C ''узна'':370C ''умееш'':380C ''успех'':374C ''успешн'':66C ''учительниц'':123C ''фабрик'':130C ''феминизм'':331C ''физик'':125C ''финансов'':209C ''хот'':49C ''цех'':141C ''чита'':88C ''эпиляц'':190C ''эт'':18B,37C,42C,94C,358C ''этап'':44C ''ярк'':233C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqvs3u00m0uktak21mg6b6','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Даша Куликова: "Если любишь то, что делаешь - успех придёт"','Наша новая героиня – Дарья Куликова из города Рязань.','432-dasha-kulikova-esli-ljubish-to-chto-delaesh-uspeh-pridet','[{"html":"<i><strong>Наша новая героиня – Дарья Куликова из города Рязань. Ей 15 лет, она учится в 9 классе и точно знает, что хочет от жизни и даже знает как этого добиться: много трудиться, быть целеустремленной, </strong><strong>развиваться и всегда смотреть на себя со стороны.</strong></i>","type":"paragraph"},{"html":"<strong>Esque.kids</strong><strong>:</strong> Даша, здравствуй. Как дела в школе? В каком классе ты учишься?","type":"paragraph"},{"html":"<strong>Даша:</strong> Здравствуйте, в школе у меня все хорошо. У нас очень дружный и весёлый класс. Учусь я в 9 классе.","type":"paragraph"},{"html":"<br /><strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Есть любимые предметы в школе?","type":"paragraph"},{"html":"<strong>Даша:</strong> Да, есть. Один из них - обществознание. Мне нравится этот предмет, он очень интересный и познавательный. Мне нравится узнавать новое о политике и законах, социальной психологии.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Я знаю, что помимо школы у тебя множество увлечений, одно их которых моделинг. Давно занимаешься?","type":"paragraph"},{"html":"<strong>Даша:</strong> В моделинге я недавно, но мне все больше и больше нравится это направление. Я буду стараться и смогу достичь своих целей.<br /><br />","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>: </strong>В каких показах уже успела принять участие?","type":"paragraph"},{"html":"<strong>Даша:</strong> Я участвовала в «Fashion bitva Moscow». Эмоции переполняли меня. Я получила огромный опыт.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Какие дизайнеры тебе особенно запомнились?","type":"paragraph"},{"html":"<strong>Даша:</strong> Больше всего мне понравился дизайнер Алла Белова. Я разделяю ее взгляды на современную моду. <br /><br />","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>: </strong>Помимо моделинга, ты занимаешься волейболом и современными танцами. Расскажи подробнее о каждом увлечении.","type":"paragraph"},{"html":"<strong>Даша:</strong> Волейболом я занимаюсь с раннего возраста. В классе я играла лучше всех и поэтому решила заниматься этим видом спорта. Также я увлекаюсь танцами. С детства меня влекли танцы и поэтому моя мама отдала меня на хореографию. Сначала мне давалось это не легко, но если любишь то, что делаешь - успех придёт.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>: </strong>Если выбирать одно из увлечении, что тебе интереснее и с чем ты хочешь связать свое будущее?","type":"paragraph"},{"html":"<strong>Даша: </strong>Свое будущее я хочу связать с моделингом, но я также понимаю, что нужно получить высшее образование. Уверена, у меня получиться совместить учебу и моделинг.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>: </strong>Какой должна быть модель, способная покорить мировые подиумы, как ты считаешь?<br /><strong>Даша: </strong>Я считаю, чтобы стать успешной моделью нужно быть целеустремлённой, много трудиться, развиваться и всегда смотреть на себя со стороны.<br /><br />","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>: </strong>Даша, ты уже думала, куда будешь поступать? Ведь высшее образование необходимо даже востребованной модели.","type":"paragraph"},{"html":"<strong>Даша: </strong>Да, я думала куда я буду поступать. Это будет связано с творчеством - дизайнер , стилист, реклама.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>: </strong>И напоследок, пару слов нашим читателям.","type":"paragraph"},{"html":"<strong>Даша: </strong>Я желаю всем идти к своей цели, верить в себя, не прогибаться под обстоятельства, а жить, руководствуясь своими принципами и убеждениями.","type":"paragraph"},{"type":"image","mediaId":"cmrmqvs2m00lzuktao2dm1nki"}]'::jsonb,'cmrmqvro600lyukta5plxd0bj','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-04-17T06:00:00.000Z'::timestamp,NULL,NULL,NULL,432,'/esquekids/moda-ek/432-dasha-kulikova-esli-ljubish-to-chto-delaesh-uspeh-pridet.html','2026-07-15T21:02:21.834Z'::timestamp,'2026-07-16T13:59:19.173Z'::timestamp,'''15'':27C ''9'':32C,95C ''bitva'':201C ''cmrmqvs2m00lzuktao2dm1nki'':474C ''esqu'':100C,139C,184C,213C,241C,313C,362C,398C,436C ''esque.kids'':62C ''fashion'':200C ''imag'':472C ''kid'':101C,140C,185C,214C,242C,314C,363C,399C,437C ''moscow'':202C ''paragraph'':60C,75C,98C,108C,137C,157C,182C,194C,211C,221C,239C,257C,311C,332C,360C,396C,415C,434C,445C,470C ''алл'':229C ''белов'':230C ''буд'':174C,423C ''будеш'':405C ''будущ'':330C,336C ''вер'':455C ''весел'':90C ''взгляд'':234C ''вид'':277C ''влекл'':286C ''возраст'':265C ''волейбол'':247C,260C ''востребова'':412C ''всем'':450C ''выбира'':316C ''высш'':349C,408C ''героин'':12B,20C ''город'':16B,24C ''дава'':298C ''давн'':154C ''дар'':13B,21C ''даш'':1A,63C,77C,110C,159C,196C,223C,259C,334C,375C,400C,417C,447C ''дел'':66C ''дела'':7A,307C ''детств'':284C ''дизайнер'':216C,228C,430C ''доб'':46C ''должн'':365C ''достич'':178C ''дружн'':88C ''дума'':403C,420C ''жела'':449C ''жизн'':40C ''жит'':463C ''закон'':133C ''занима'':155C,246C,262C,275C ''запомн'':219C ''здравств'':64C,78C ''зна