ONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqyy3u00uluktas10gwjp8','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Гендер всему голова. Готовы ли мы к гендерному воспитанию?','Сегодня только ленивый не говорит о равноправии и феминизме, и, казалось бы, все как на ладони.','357-gender-vsemu-golova-gotovy-li-my-k-gendernomu-vospitaniju','[{"html":"Сегодня только ленивый не говорит о равноправии и феминизме, и, казалось бы, все как на ладони. Но если покопаться и дойти до истины, то истоки совсем в другом. Что творится за пределами наших привычных понятий и стереотипов?<br /><br />","type":"paragraph"},{"html":"Шайло - дочь Джоли и Брэда Питта с детства облачилась в мужской стиль, а сын Меган Фокс, наоборот, примеряет юбки, и никто его в этом не останавливает. И для нас это уже не новости, сфера моды - обычная территория либерализма. Но как показывает себя гендерное равноправие за пределами моды?","type":"paragraph"},{"html":"На Западе уже все, казалось бы, очевидно: во многих странах выдают паспорта, где в графе “пол” ставят не “м” или “ж”, а “х”, что показывает нейтральное мнение о себе, как о гендере. Человек не определился, или определился в понятную всем сторону. И многие учреждения работают так же с условием этих нововведений - “вне гендерных пониманий”.","type":"paragraph"},{"html":"Так же как и в США, там давно уже нет четкого “он” и “она”. Если человек на стадии определения, то он называет себя “они”. И все к этому готовы. Даже крупнейший словарь английского языка признал возможность использования местоимения “they” в единственном числе.","type":"paragraph"},{"html":"<u><b>Почему так происходит? Откуда возникают такие понятия?</b></u>","type":"paragraph"},{"html":"Изначально понятие “гендер” использовалось для определения маскулинности и женственности людей. Именно тогда впервые признали и многообразие пола наряду с его постоянством. Практически в это же время американский психолог Лоренц Кольберг представил свою теорию развития гендерного типирования, где дети проходят три этапа в понимании своего пола.","type":"paragraph"},{"html":"На первом он осознает, кто он - мальчик или девочка, на втором - понимает, что это навсегда, на третьем приходит понимание, что внешние изменения (прически или яркий свитер цвета фуксии) не способны повлиять на изменения гендера. Его теория так же показывает четкое отличие между понятиями “пол” и “гендер”, где “пол” - понятие биологическое, а “гендер”- совокупность культурных, психологических и этических черт.","type":"paragraph"},{"html":"Из-за непонимания многих родителей и возникают мифы и споры по поводу гендерно-полового воспитания.","type":"paragraph"},{"html":"Первый и главные: это ведет к развития гомосексуальности. Хотя с научной точки зрения такие страхи беспочвенны: ученые давно доказали генетическую предрасположенность к гомосексуальным направлениям. Длина волос или маникюр у мальчиков совсем не повод для тревоги.","type":"paragraph"},{"html":"Другой миф - ребенок воспитанный в гендерно-нейтральной среде получит проблемы с психикой. <br /><br />","type":"paragraph"},{"html":"“Гендер - это социальный конструкт, а пол - биологический. Путаница возникает там, где родители не отличают эти два понятия. Бить тревогу и задумываться на эту тему не стоит, если ваш ребенок еще ходит пешком под стол.”, - говорит психолог Марина Мелия.","type":"paragraph"},{"html":"<br />Лично нам близка позиция гендерно-нейтрального воспитания. “Yes, you can”, а я буду любить тебя любым.<br />","type":"paragraph"}]'::jsonb,'cmrmqyxz300ukuktaeklkg3d5','cmrm8kzpw000mkwtaocyn5161',NULL,'cmrmpdrom0000sstarkqxwts4','2021-05-29T06:00:00.000Z'::timestamp,NULL,NULL,NULL,357,'/psihologija/357-gender-vsemu-golova-gotovy-li-my-k-gendernomu-vospitaniju.html','2026-07-15T21:04:49.578Z'::timestamp,'2026-07-16T14:00