INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqqycq002xukta9uyq2jib','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Благотворительный бал в поддержку 15-летия фонда Оксаны Федоровой пройдет в Доме Пашкова','11 февраля в одном из самых красивых особняков Москвы - Доме Пашкова впервые пройдет благотворительный бал - турнир среди пар ProAm при поддержке Российского танцевального союза (РТС).','637-blagotvoritelnyj-bal-v-podderzhku-15-letija-fonda-oksany-fedorovoj-projdet-v-dome-pashkova','[{"html":"11 февраля в одном из самых красивых особняков Москвы - Доме Пашкова впервые пройдет благотворительный бал - турнир среди пар ProAm при поддержке Российского танцевального союза (РТС).","type":"paragraph"},{"html":"Бал откроет серию мероприятий, приуроченных к 15-летию благотворительного фонда Оксаны Федоровой, ключевым направлением деятельности которого является развитие культурно-просветительских проектов и поддержка юных талантов.","type":"paragraph"},{"html":"Основатель и бессменный президент фонда – Мисс Вселенная, телеведущая, певица <strong>Оксана Федорова</strong> выступит ведущей бала в паре с президентом РТС, знаменитым балетмейстером, Заслуженным деятелем искусств РФ <strong>Станиславом Поповым.</strong>","type":"paragraph"},{"html":"Организаторы бала <strong>Вадим Владыкин и Анастасия Усанова</strong> отметили: «<em>Для нас очень близка и созвучна тема деятельности фонда – именно культура является тем фундаментом, на котором воспитывается юное поколение в целом, и новое поколение артистов, музыкантов, в частности. И мы рады, что можем внеси свой вклад в деятельность фонда, объединяя творчество и благотворительность</em>».","type":"paragraph"},{"html":"В рамках дневной программы состоятся соревнования во всех возрастах и категориях в европейской и латиноамериканской программе, а также американ смус. В вечернем отделении состоятся финалы основных категорий турнира, VIP шоу ProAm, шоу профессиональных дуэтов и танцы для гостей вечера. Среди основных категорий турнира также пройдет Кубок Евроазиатского Танцевального Совета по Шоу среди пар ProAm.","type":"paragraph"},{"html":"Оценивать выступления участников будет оценивать судейская коллеги, в состав которой вошли чемпионы мира и России по бальным танцам.","type":"paragraph"},{"html":"В рамках бала состоится благотворительная лотерея и аукцион, на котором будут представлены картины в стиле нео-импрессионизма известной художницы, амбассадора фонда Анастасии Маслаковой.","type":"paragraph"},{"html":"Также в рамках бала-турнира будет объявлена специальная номинация от Оксаны Федоровой, все регистрационные взносы в которой будут направлены в фонд, а победители номинации получат специальный приз от Мисс Вселенной.","type":"paragraph"},{"html":"Все благотворительные взносы, собранные в рамках бала, будут направлены в фонд Оксаны Федоровой на программу поддержки юных талантов в области академического искусства в рамках проекта «Моя Россия: музыкальное путешествие».","type":"paragraph"},{"html":"Регистрация на турнир: https://lifeis.dance/competitions/?id=339","type":"paragraph"},{"html":"Бронь билетов: +7 (924) 411-44-33 Ксения","type":"paragraph"},{"html":"<strong>Пресс-служба Фонда Оксаны Федоровой</strong>","type":"paragraph"},{"html":"<a href=\"mailto:pressa@fedorovafond.ru\">pressa@fedorovafond.ru</a>","type":"paragraph"},{"html":"<strong>Информация о фонде Оксаны Федоровой</strong>","type":"paragraph"},{"html":"Благотворительный фонд создан в 2009 году известной телеведущей, Мисс Вселенная Оксаной Федоровой в целях создания и продвижение культурно - просветительских программ и проектов, направленных на поддержку и популяризацию культурного наследия, духовных и семейных ценностей России, а также патриотическое воспитание молодежи. Фонд находится в Москве, не имеет филиалов и отделений. <a href=\"http://fedorovafond.ru\" target=\"_blank\" rel=\"noopener noreferrer\">http://fedorovafond.ru </a>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqqy4s002vukta637mlj8c"},{"mediaId":"cmrmqqybe002wuktagqaokr6y"}]}]'::jsonb,'cmrmqqxtz002uuktacefsqlbe','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-02-02T06:00:00.000Z'::timestamp,NULL,NULL,NULL,637,'/svetskaja-hronika/637-blagotvoritelnyj-bal-v-podderzhku-15-letija-fonda-oksany-fedorovoj-projdet-v-dome-pashkova.html','2026-07-15T20:58:36.650Z'::timestamp,'2026-07-16T13:56:57.421Z'::timestamp,'''+7'':362C ''-33'':366C ''-44'':365C ''/competitions/?id=339'':356C ''11'':14B,39C ''15'':5A,73C ''2009'':396C ''411'':364C ''924'':363C ''cmrmqqy4s002vukta637mlj8c'':446C ''cmrmqqybe002wuktagqaokr6y'':448C ''fedorovafond.ru'':440C ''galleri'':444C ''lifeis.dance'':355C ''lifeis.dance/competitions/?id=339'':354C ''paragraph'':65C,94C,124C,178C,235C,256C,283C,317C,349C,358C,369C,378C,382C,390C,442C ''pressa@fedorovafond.ru'':380C ''proam'':32B,57C,210C,233C ''vip'':208C ''академическ'':339C ''амбассадор'':278C ''америка'':198C ''анастас'':131C,280C ''артист'':158C ''аукцион'':265C ''бал'':2A,28B,53C,67C,109C,127C,260C,289C,325C ''бала-турнир'':288C ''балетмейстер'':116C ''бальн'':253C ''бессмен'':98C ''билет'':361C ''благотворительн'':1A,27B,52C,75C,176C,262C,320C,392C ''близк'':137C ''брон'':360C ''будут'':268C,303C,326C ''вад'':128C ''ведущ'':108C ''вечер'':218C ''вечерн'':201C ''взнос'':300C,321C ''вклад'':169C ''владыкин'':129C ''внес'':167C ''возраст'':188C ''воспитан'':429C ''воспитыва'':150C ''вошл'':247C ''вперв'':25B,50C ''вселен'':102C,315C,401C ''выступ'':107C ''выступлен'':238C ''год'':397C ''гост'':217C ''деятел'':118C ''деятельн'':81C,141C,171C ''дневн'':182C ''дом'':12A,23B,48C ''духовн'':421C ''дуэт'':213C ''евроазиатск'':226C ''европейск'':192C ''заслужен'':117C ''знаменит'':115C ''известн'':276C,398C ''имеет'':436C ''имен'':143C ''импрессионизм'':275C ''и