2C,336C ''танц'':215C,254C ''танцевальн'':36B,61C,227C ''творчеств'':174C ''телеведущ'':103C,399C ''тем'':140C ''турнир'':29B,54C,207C,222C,290C,353C ''усанов'':132C ''участник'':239C ''феврал'':15B,40C ''федоров'':9A,78C,106C,297C,331C,376C,388C,403C ''филиал'':437C ''финал'':204C ''фонд'':7A,76C,100C,142C,172C,279C,306C,329C,374C,386C,393C,431C ''фундамент'':147C ''художниц'':277C ''цел'':154C,405C ''ценност'':424C ''частност'':161C ''чемпион'':248C ''шо'':209C,211C,230C ''юн'':91C,151C,335C ''явля'':83C,145C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr03ds00ygukta3dduv19a','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Fashion bitva 9 сезон. Санкт-Петербург','11 апреля в Санкт-Петербурге в отеле «Введенский» прошел региональный этап 9 сезона конкурса дизайнеров FASHION BITVA.','320-fashion-bitva-9-sezon','[{"html":"11 апреля в Санкт-Петербурге в отеле «Введенский» прошел региональный этап 9 сезона конкурса дизайнеров FASHION BITVA. 9 сезон, в отличие от 8, прошел в привычном формате. Свои коллекции представили дизайнеры из Санкт-Петербурга, Москвы и Московской области.<br /><br />","type":"paragraph"},{"html":"Были представлены образы в стиле оверсайз от Натальи Советской. Главной целью дизайнера является стиль и в то же время комфорт, именно к этому стремится большинство потребителей в постпандемическое время. Этой же цели придерживается и молодой бренд <i>«Ocean kids wear»</i>, который представил свободную детскую повседневную одежду.<br /><br />","type":"paragraph"},{"html":"<i>Деловой стиль от Аннеты Шмель</i>, в дополнение к которому шли элегантные маски, уже так привычные нашему лицу, приятно удивил гостей своей новизной и свежестью творческого взгляда.<br />Показ московского бренда <i>«Nurban»</i> впечатлил гостей не меньше. Облегающие фигуру бархатные платья и костюмы в желто-черной гамме, широкие шляпы и прикрывающие глаза очки. Модели уверенно дефилировали, ловя восхищающие взгляды гостей.<br />Петербургский бренд <i>«Marina Weller»</i> представил коллекцию пальто разных цветов – поистине сложная и кропотливая работа.","type":"paragraph"},{"html":"Нежные струящиеся платья от бренда «Femellet» разбавили конкурс своей нежностью и романтичностью.<br />Вспышки фотокамер внезапно угасли перед появлением на подиуме коллекции подросткового бренда <i>«Toria»</i>, ведь «светятся» модели, в прямом смысле этого слова, только при выключенных световых приборах. Такой материал для коллекции молодой 19-летний дизайнер выбирала самостоятельно, исходя из молодежных трендов, главной целью которых, чтобы одежда была яркой и максимально удобной.<br /><br />","type":"paragraph"},{"html":"<br /><i>А теперь о призовых коллекциях.</i><br /><i>Второе место получил петербургский детский бренд Leya.me</i>. Именно у него уже построена система производства одежды с дальнейшей реализацией через магазины. Современные и актуальные взгляды на детскую моду и команда профессионалов дало преимущество Светлане Злотниковой перед другими брендами.<br /><br />","type":"paragraph"},{"html":"<b><i>Первое место занял бренд «Werdandi», дизайнер Наталья Угольникова</i></b>. Модели со шпагами, облаченные в элегантные ассиметричные белоснежные платья, не оставили равнодушным ни одного члена жюри!<br /><br />","type":"paragraph"},{"html":"<i>Наталья Угольникова: «<em>Для меня это было мое первое участие в конкурсе. Волнение начало накатывать ещё за сутки до мероприятия. Однако я победила, но осознание этого пришло спустя три дня. Благодарю организаторов за возможность принять участие, членов жюри за ценные замечания. Эта победа дала мне очередной прилив вдохновения</em>».</i>","type":"paragraph"},{"html":"<b>Поздравляем Наталью Угольникову с победой!</b> <br />Встретимся снова с ее творчеством уже в Москве 18-19 декабря.","type":"paragraph"},{"html":"Желаем развития всем конкурсантам, ведь участие – это уже маленькая победа.","type":"paragraph"},{"html":"<b>Благодарим членов жюри Дмитрия Зорина, Светлану Кузнецову и Александру Матвееву за ценные советы и честное судейство!</b>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmr02ob00ycuktai05hb9vr"},{"mediaId":"cmrmr02va00ydukta3h0ft14p"},{"mediaId":"cmrmr034d00yeuktaxk78dn1w"},{"mediaId":"cmrmr03ac00yfukta0vgqzd38"}]}]'::jsonb,'cmrmr028u00ybukta8mimr7er','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2021-04-19T06:00:00.000Z'::timestamp,NULL,NULL,NULL,320,'/projects-esque/fashion-bitva/320-fashion-bitva-9-sezon.html','2026-07-15T21:05:43.072Z'::timestamp,'2026-07-16T14:00:58.012Z'::timestamp,'''-19'':392C ''11'':8B,26C ''18'':391C ''19'':234C ''8'':49C ''9'':3A,20B,38C,44C ''bitva'':2A,25B,43C ''cmrmr02ob00ycuktai05hb9vr'':431C ''cmrmr02va00ydukta3h0ft14p'':433C ''cmrmr034d00yeuktaxk78dn1w'':435C ''cmrmr03ac00yfukta0vgqzd38'':437C ''fashion'':1A,24B,42C ''femellet'':197C ''galleri'':429C ''kid'':106C ''leya.me'':267C ''marina'':177C ''nurban'':146C ''ocean'':105C ''paragraph'':67C,115C,190C,254C,299C,326C,376C,395C,408C,427C ''toria'':215C ''wear'':107C ''weller'':178C ''werdandi'':305C ''актуальн'':283C ''александр'':418C ''аннет'':120C ''апрел'':9B,27C ''ассиметричн'':315C ''бархатн'':153C ''белоснежн'':316C ''благодар'':357C,410C ''большинств'':93C ''бренд'':104C,145C,176C,196C,214C,266C,297C,304C ''введенск'':16B,34C ''вдохновен'':374C ''взгляд'':142C,173C,284C ''внезапн'':206C ''возможн'':360C ''волнен'':339C ''восхища'':172C ''впечатл'':147C ''врем'':87C,97C ''всем'':399C ''вспышк'':204C ''встрет'':383C ''втор'':261C ''выбира'':237C ''выключен'':226C ''гамм'':161C ''главн'':78C,243C ''глаз'':166C ''гост'':136C,148C,174C ''дал'':291C,370C ''дальн'':277C ''декабр'':393C ''делов'':117C ''детск'':111C,265C,286C ''дефилирова'':170C ''дизайнер'':23B,41C,57C,80C,236C,306C ''дмитр'':413C ''дня'':356C ''дополнен'':123C ''друг'':296C ''ещ'':342C ''жела'':397C ''желт'':159C ''желто-черн'':158C ''жюр'':324C,364C,412C ''замечан'':367C ''заня'':303C ''злотников'':294C ''зорин'':414C ''имен'':89C,268C ''исход'':239C ''коллекц'':55C,180C,212C,232C,260C ''команд'':289C ''комфорт'':88C ''конкурс'':22B,40C,199C,338C ''конкурсант'':400C ''костюм'':156C ''котор'':108C,125C,245C ''кропотлив'':187C ''кузнецов'':416C ''летн'':235C ''лиц'':133C ''лов'':171C ''магазин'':280C ''максимальн'':251C ''маленьк'':405C ''маск'':128C ''матвеев'':419C ''материа'':230C ''