INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsvol00a2uktabw7da102','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Дизайнер Louis Vuitton создаст костюмы для мюзикла','Дизайнер Николя Жескьер, ответственный за женскую коллекцию Louis Vuitton, создаст сценические костюмы для мюзикла «Стармания».','567-dizajner-louis-vuitton-nikolja-zhesker-sozdast-kostjumy-dlja-mjuzikla','[{"html":"<b>Дизайнер Николя Жескьер, ответственный за женскую коллекцию Louis Vuitton, создаст сценические костюмы для мюзикла «Стармания». Для модельера это будет первый подобный опыт.</b>","type":"paragraph"},{"html":"Об этом сообщает издание WWD. Мюзикл с костюмами от Николя Жескьера можно будет увидеть 8 ноября в центре La Seine Musicale. Модельер рассказал, что видел «Старманию» в детстве и был сильно ей впечатлён.","type":"paragraph"},{"html":"Первая версия рок-оперы «Стармания» была поставлена в 1970-ых годах. Это один из самых известных французских мюзиклов. За новую постановку отвечают режиссер Томас Джолли и хореограф Сиди Ларби Шеркауи.","type":"paragraph"},{"html":"Николя Жескьер стал креативным директором женской линии Louis Vuitton в 2013 году. Ранее он уже пробовал себя в новых форматах. Так, три года назад он создал дизайн героев популярной видеоигры League of Legends.","type":"paragraph"}]'::jsonb,'cmrmqsvnm00a1ukta2p1idy5a','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2022-10-04T06:00:00.000Z'::timestamp,NULL,NULL,NULL,567,'/fashion/news-2/567-dizajner-louis-vuitton-nikolja-zhesker-sozdast-kostjumy-dlja-mjuzikla.html','2026-07-15T21:00:06.501Z'::timestamp,'2026-07-16T13:57:49.197Z'::timestamp,'''1970'':93C ''2013'':128C ''8'':62C ''la'':66C ''leagu'':148C ''legend'':150C ''loui'':2A,15B,30C,125C ''musical'':68C ''paragraph'':46C,82C,116C,152C ''sein'':67C ''vuitton'':3A,16B,31C,126C ''wwd'':52C ''верс'':85C ''видел'':72C ''видеоигр'':147C ''впечатл'':80C ''геро'':145C ''год'':95C,129C,140C ''детств'':75C ''джолл'':109C ''дизайн'':144C ''дизайнер'':1A,8B,23C ''директор'':122C ''женск'':13B,28C,123C ''жескьер'':10B,25C,58C,119C ''известн'':100C ''издан'':51C ''коллекц'':14B,29C ''костюм'':5A,19B,34C,55C ''креативн'':121C ''ларб'':113C ''лин'':124C ''модельер'':39C,69C ''мюзикл'':7A,21B,36C,53C,102C ''назад'':141C ''никол'':9B,24C,57C,118C ''нов'':104C,136C ''ноябр'':63C ''оп'':44C ''опер'':88C ''ответствен'':11B,26C ''отвеча'':106C ''перв'':42C,84C ''подобн'':43C ''популярн'':146C ''поставл'':91C ''постановк'':105C ''пробова'':133C ''ран'':130C ''рассказа'':70C ''режиссер'':107C ''рок'':87C ''рок-опер'':86C ''сам'':99C ''сид'':112C ''сильн'':78C ''созда'':143C ''создаст'':4A,17B,32C ''сообща'':50C ''стал'':120C ''старман'':22B,37C,73C,89C ''сценическ'':18B,33C ''томас'':108C ''увидет'':61C ''формат'':137C ''французск'':101C ''хореограф'':111C ''центр'':65C ''шеркау'':114C ''ых'':94C ''эт'':40C,96C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqyzmq00uquktayn0anfkd','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Важные советы, как защитить лицо, тело и волосы от ультрафиолета','Лето в самом разгаре, и, кажется, самыми главными буквами и понятиями в этот период является расшифровка значков UVB и UVA. Как обезопасить себя и свою красоту в жаркую пору? Давайте разбираться вместе.','356-vazhnye-sovety-kak-zaschitit-lico-telo-i-volosy-ot-ultrafioleta','[{"text":"Лицо","type":"heading"},{"text":"Экономия - не выход","type":"heading"},{"text":"Большая ошибка — использовать на все тело 2-3 капли солнцезащитного крема. Впрочем, его избыток тоже не гарант счастья. Для надежной защиты понадобится понятное количество средства ─ шарик размером с пятируб­левую монету. Нанесите его за 20 до выхода на солнце, чтобы крем начал свою работу, как следует.","type":"heading"},{"text":"Все внимание буквам","type":"heading"},{"text":"Чтобы обезопасить себя, вы просто обязаны знать обозначения на упаковке. В любом случае выбирайте солнцезащитные средства широкого спектра действия, обещающие защиту от UVB- и UVA-лучей. Сегодня их на разный вкус и цвет: нынешним летом вышло много новинок с матирующим эффектом.","type":"heading"},{"text":"Держите в сумочке стик","type":"heading"},{"text":"Сегодня необходимость кремов от солнца очевидна так же, как и красный сгоревший нос на лице при пренебрежении этим простым правилом. Именно ему нужно уделяем ему особое внимание. Кожа в этой капризной области имеет тенденцию к жирности, поэтому действие солнцезащитного препарата довольно быстро становится малоэффективной. В зонах повышенной опасности традиционно хорошо работают стики.","type":"heading"},{"text":"Помните о защите всегда","type":"heading"},{"text":"Пасмурные дни летом совсем не повод игнорировать солнцезащитный крем. Тем более что именно в такую погоду особенно опасны лучи спектра А, которые способствуют появлению рака.","type":"heading"},{"text":"Успокаивайте кожу","type":"heading"},{"text":"Иногда на солнце лицо покрывается красными пятнышками. Это не столько ожог, сколько микровоспаление ─ специфическая реакция на ультрафиолет ─ которое довольно легко снять. Достаточно взять капсулу с маслом примулы вечерней, проколоть ее и на ночь нанести содержимое на чистую кожу. Благодаря большому содержанию незаменимой гамма-линоленовой кислоты, восстанавливающей водный барьер и уменьшающей покраснения, утром от досадных проблем не останется и следа.","type":"heading"},{"text":"Тело","type":"heading"},{"text":"Охлаждайтесь вовремя","type":"heading"},{"text":"Если чувствуете, что находитесь на грани теплового\\солнечного удара, вспомните о прохладительных напитках: ледяная диетическая кола может стать хорошим охлажда­ющим фактором. Успокоим приверженцев ЗОЖ: ее не обязательно пить. Достаточно положить баночку на шею сзади и подождать, пока она не станет вашей температуры. Именно шея задает тон кровотоку, поэтому именно в этой области важно понизить температуру в первую очередь.","type":"heading"},{"text":"Используйте термальную воду","type":"heading"},{"text":"Орошайте термальной водой не только лицо, но и все тело. Она заставляет работать в полную силу самый мощный терморегулятор — вашу кожу. Работает это следующим образом: часть жидкости впитывается моментально и понижает температуру крови в увлажненной области. Минеральный фонтан лучше всего направлять на области пульса: шею, внутреннюю часть колен, тыльную сторону запястий.","type":"heading"},{"text":"Лечите ожоги правильно","type":"heading"},{"text":"Если вы все-таки сгорели, коже срочно нужно помочь. Прежде всего, охладите обожженное место: примите прохладный душ или приложите мокрый холодный компресс (избегайте льда, так как он может только усилить повреждение кожи). Затем место ожога можно обработать восстанавливающим и заживляющим средством, которое ускоряет процесс регенерации кожи и восстанавливает ее защитный барьер, успокаивает, оказывает противовоспалительное действие и предотвращает развитие поствоспалительной гиперпигментации. Такие средства, как правило, содержат пантенол и термальную воду. Не используйте мази и присыпки, так как под ними гораздо медленнее снижается температура обожженных тканей. Также нельзя смазывать ожог одеколоном или спиртом — это может вызвать болевой шок.","type":"heading"},{"text":"Волосы","type":"heading"},{"text":"Следите за кончиками","type":"heading"},{"text":"Смесь соли и хлорки — вот из-за чего локоны становятся похожими на солому. Чтобы замаскировать повреждения, возьмите стайлинг-крем или помаду для волос с восковой текстурой и нанесите на кончики прядей. Это — во всех смыслах слова — сгладит ситуацию. А после «жаркого отпуска» устройте голове spa-ритуал и пройдите серьезный восстанавливающий курс в салоне или в домашних условиях.","type":"heading"},{"html":"<i>Поддерживайте цвет</i>","type":"paragraph"},{"text":"Играющие солнечными бликами пряди до сих пор один из модных hair-трендов, а вот выгоревшие блеклые и безжиненные пряди —совсем нет. Поэтому не забывайте про оттеночные шампуни. Фиолетовый цвет нейтрализует нежелательные теплые оттенки, а золотой пигмент убирает неприятный зеленый отблеск, который часто заявляет о себе после взаимодействия с минеральными солями воды бассейна.","type":"heading"},{"text":"Используйте защитный спрей","type":"heading"},{"text":"Собираясь на пляж или к бассейну, сбрызните волосы­ спреем с UV-фильтрами: тогда они не будут, как губка, впитывать соленую и хлорированную воду. Когда будете дома или в номере отеля, хорошо промойте голову и нанесите косметическое масло для волос. Оно поможет восстановить их жизненную силу.","type":"heading"},{"type":"gallery","items":[{"mediaId":"cmrmqyz4h00uouktaw091jzns"},{"mediaId":"cmrmqyzfq00upuktadxzrn3uf"}]}]'::jsonb,'cmrmqyyr700unuktaji2lre00','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyun0008kwtasfd55v5y','cmrmpdrom0000sstarkqxwts4','2021-05-28T06:00:00.000Z'::timestamp,NULL,NULL,NULL,356,'/beauty/tendencii/356-vazhnye-sovety-kak-zaschitit-lico-telo-i-volosy-ot-ultrafioleta.html','2026-07-15T21:04:51.554Z'::timestamp,'2026-07-16T14:00:32.744Z'::timestamp,'''-3'':60C ''2'':59C ''20'':86C ''cmrmqyz4h00uouktaw091jzns'':744C ''cmrmqyzfq00upuktadxzrn3uf'':746C ''galleri'':742C ''hair'':642C ''hair-тренд'':641C ''head'':45C,51C,99C,105C,150C,157C,212C,219C,247C,252C,315C,319C,324C,385C,391C,445C,451C,551C,555C,561C,624C,685C,691C,740C ''paragraph'':629C ''spa'':610C ''spa-ритуа'':609C ''uv'':704C ''uv-фильтр'':703C ''uva'':30B,132C ''uva-луч'':131C ''uvb'':28B,129C ''баночк'':356C ''барьер'':302C,504C ''бассейн'':683C,698C ''безжинен'':649C ''благодар'':292C ''блекл'':647C ''блик'':633C ''болев'':548C ''больш'':53C,293C ''будет'':718C ''будут'':709C ''букв'':19B,103C ''быстр'':200C ''важн'':1A,378C ''ваш'':366C,412C ''вечерн'':281C ''взаимодейств'':678C ''взят'':276C ''вкус'':138C ''вмест'':42B ''вниман'':102C,185C ''внутрен'':438C ''воврем'':322C ''вод'':389C,395C,522C,682C,716C ''водн'':301C ''возьм'':580C ''волос'':8A,553C,587C,732C ''волосы­'':700C ''восков'':589C ''восстанавлива'':300C,491C,501C,615C ''восстанов'':735C ''впитыва'':420C,712C ''все-так'':455C ''вспомн'':335C ''выбира'':120C ''выгоревш'':646C ''вызва'':547C ''выход'':49C,88C ''вышл'':143C ''гамм'':297C ''гамма-линоленов'':296C ''гарант'':69C ''гиперпигментац'':513C ''главн'':18B ''голов'':608C,726C ''горазд'':532C ''гран'':331C ''губк'':711C ''дава'':40B ''действ'':125C,196C,508C ''держ'':152C ''диетическ'':340C ''дни'':222C ''довольн'':199C,272C ''дом'':719C ''домашн'':621C ''досадн'':308C ''достаточн'':275C,354C ''душ'':470C ''жарк'':38B,605C ''жидкост'':419C ''жизнен'':737C ''жирност'':194C ''забыва'':655C ''зада'':370C ''заживля'':493C ''замаскирова'':578C ''запяст'':443C ''заставля'':404C ''зат'':486C ''защ'':216C ''защит'':4A,73C,127C ''защитн'