INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr1s69014lukta0niysqit','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Теона Дольникова выпустила новый клип','Первая вокалистка группы Slot, актриса театра и кино Теона Дольникова (TEONA) в честь дня всех влюблённых представила клип на песню Вуди Вуди, написанную в соавторстве с Юрием Тополян.','280-teona-dolnikova-vypustila-novyj-klip','[{"html":"Первая вокалистка группы Slot, актриса театра и кино Теона Дольникова (TEONA) в честь дня всех влюблённых представила клип на песню \"Вуди Вуди\", написанную в соавторстве с Юрием Тополян. Над продакшном трека работал продюсер Fargo (Арутюн Таманян), известный по работе с Zivert, Сабриной, Miguel и другими исполнителями.","type":"paragraph"},{"html":"Легендарный мощный вокал Теоны, электро-гитары и басы, даже немного фанка и инди-рока - всё это сочетается в единой энергичной песне, способной растопить лёд этой зимы. Пропитанный калифорнийским солнцем трек имеет все шансы стать главным прорывом этого года.","type":"paragraph"},{"html":"Клип, снятый в Лос Анджелесе, полностью передаёт лёгкое и тёплое настроение песни: пальмы, лонгборды, набережная самого популярного района среди меломанов - Venice beach.","type":"paragraph"},{"html":"Режиссёром клипа стал Павел Поборуев.","type":"paragraph"},{"html":"Несмотря на известность в качестве сильнейшей вокалистки России, до 2020 года Теона не выпускала ранее официальных синглов. Прошлой осенью, накопив достаточно авторского материала, Дольникова начала работу над своим первым сольным альбомом. Сингл \"Вуди Вуди\" - уже 3-я работа с грядущей пластинки. Ранее были представлены \"I''m not afraid again\" и \"Когда я стану взрослой\".","type":"paragraph"},{"html":"Новинка доступна на всех цифровых площадках.","type":"paragraph"},{"html":"<a href=\"https://www.youtube.com/watch?v=bKLfOy4rYVs\" target=\"_blank\" rel=\"noopener noreferrer\">https://www.youtube.com/watch?v=bKLfOy4rYVs</a>","type":"paragraph"}]'::jsonb,'cmrmr1s4k014kuktazy3pz3xr','cmrm8kz36000ckwtabqfh3f4h','cmrm8kze2000gkwtad8wkij5y','cmrmpdrom0000sstarkqxwts4','2021-02-18T06:00:00.000Z'::timestamp,NULL,NULL,NULL,280,'/sobytija/muzyka/280-teona-dolnikova-vypustila-novyj-klip.html','2026-07-15T21:07:01.857Z'::timestamp,'2026-07-16T14:01:34.629Z'::timestamp,'''/watch?v=bklfoy4ryvs'':227C ''2020'':168C ''3'':194C ''afraid'':206C ''beach'':147C ''fargo'':67C ''m'':204C ''miguel'':76C ''paragraph'':81C,124C,149C,157C,214C,223C,229C ''slot'':9B,37C ''teona'':16B,44C ''venic'':146C ''www.youtube.com'':226C ''www.youtube.com/watch?v=bklfoy4ryvs'':225C ''zivert'':74C ''авторск'':180C ''актрис'':10B,38C ''альбом'':189C ''анджелес'':130C ''арутюн'':68C ''бас'':91C ''взросл'':212C ''влюблен'':21B,49C ''вока'':85C ''вокалистк'':7B,35C,165C ''все'':99C ''вуд'':26B,27B,54C,55C,191C,192C ''выпуска'':172C ''выпуст'':3A ''гитар'':89C ''главн'':119C ''год'':122C,169C ''групп'':8B,36C ''грядущ'':198C ''дня'':19B,47C ''дольников'':2A,15B,43C,182C ''достаточн'':179C ''доступн'':217C ''друг'':78C ''един'':103C ''зим'':110C ''известн'':70C,161C ''имеет'':115C ''инд'':97C ''инди-рок'':96C ''исполнител'':79C ''калифорнийск'':112C ''качеств'':163C ''кин'':13B,41C ''клип'':5A,23B,51C,126C,152C ''легендарн'':83C ''легк'':133C ''лед'':108C ''лонгборд'':139C ''лос'':129C ''материа'':181C ''меломан'':145C ''мощн'':84C ''набережн'':140C ''накоп'':178C ''написа'':28B,56C ''настроен'':136C ''нача'':183C ''немн'':93C ''несмотр'':159C ''нов'':4A ''новинк'':216C ''осен'':177C ''официальн'':174C ''павел'':154C ''пальм'':138C ''перв'':6B,34C,187C ''переда'':132C ''песн'':25B,53C,105C,137C ''пластинк'':199C ''площадк'':221C ''побору'':155C ''полност'':131C ''популярн'':142C ''представ'':22B,50C ''представл'':202C ''продакшн'':63C ''продюсер'':66C ''пропита'':111C ''прорыв'':120C ''прошл'':176C ''работ'':72C,184C,196C ''работа'':65C ''район'':143C ''ран'':173C,200C ''растоп'':107C ''режиссер'':151C ''рок'':98C ''росс'':166C ''сабрин'':75C ''сам'':141C ''сво'':186C ''сильн'':164C ''сингл'':175C,190C ''снят'':127C ''соавторств'':30B,58C ''солнц'':113C ''сольн'':188C ''сочета'':101C ''способн'':106C ''сред'':144C ''стал'':153C ''стан'':211C ''стат'':118C ''таманя'':69C ''театр'':11B,39C ''теон'':1A,14B,42C,86C,170C ''тепл'':135C ''тополя'':33B,61C ''трек'':64C,114C ''фанк'':94C ''цифров'':220C ''чест'':18B,46C ''шанс'':117C ''электр'':88C ''электро-гитар'':87C ''энергичн'':104C ''эт'':100C ''юр'':32B,60C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqvr6i00lwukta2l2bhzf2','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Настя Лысакова: ""Точка Будущего"- это школа моей мечты"','Наше будущее в надежных руках.','433-nastya-lysakova-tochka-buduschego-jeto-shkola-moej-mechty','[{"html":"<strong>Наше будущее в надежных руках. Молодое поколение стремится к знаниям уже с раннего возраста. Они точно знают кем будут и где хотят учиться. Множество дополнительных секции заменяют прогулки во дворе и это не может не радовать. Насте Лысаковой 11 лет, а ее мечта – не новая игрушка, а поступление в «Точку Будущего».</strong>","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Настя, здравствуй. Как твои дела?","type":"paragraph"},{"html":"<strong>Настя:</strong> Здравствуйте. Все хорошо.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Мне сказали, что ты занимаешься современными танцами? Какими?","type":"paragraph"},{"html":"<strong>Настя: </strong>Я занимаюсь танцами 7 лет. Последние пять лет занимаюсь в танцевальном коллективе \"Малинки\" в Доме детского творчества №2. В наших танцевальных номерах нет какого-то одного стиля современного танца, мы используем разные элементы, например хип-хоп.<br /><br />","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Помимо танцев, ты профессионально занимаешься моделингом. В каких показах принимала участие?","type":"paragraph"},{"html":"<strong>Настя: </strong>Я принимала участие в показах от модельной школы \"Open Stars\" в 2021 г. и недавно в \"Fashion bitva 10\"","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Элементы танцев не пробовала внедрить в показы? Существуют театральные постановки, это очень интересно.","type":"paragraph"},{"html":"<strong>Настя: </strong>Не пробовала, но думаю, было бы очень интересно и необычно.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Что для тебя мода? Какие ощущения ты испытываешь, когда идешь по подиуму?","type":"paragraph"},{"html":"<strong>Настя: </strong>Для меня мода - это самовыражение. Зачем одеваться как все? У каждого свой вкус. Но и твой внешний вид твоя \"визитная карточка\", поэтому важно подбирать правильную одежду. А мода подскажет, как красиво одеться.<br /><br />","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Давай немного забежим вперед. Какой ты видишь себя спустя 5 лет?","type":"paragraph"},{"html":"<strong>Настя: </strong>Я даже не задумывалась. Через 5 лет мне будет 16 лет, почти 17, я вижу себя стильным, уверенным в себе человеком.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> О будущей профессии успела поразмышлять?","type":"paragraph"},{"html":"<strong>Настя: </strong>Еще пока не думала.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Расскажи подробнее о «Точке будущего».","type":"paragraph"},{"html":"<strong>Настя: </strong>\"Точка Будущего\"- это школа моей мечты. Благодаря этой школе, ты полюбишь учиться, ведь в ней к каждому ученику есть индивидуальный подход. Также в этой школе ты не соскучишься, всегда будут какие-то мероприятия, а я их очень люблю. Как только я узнала об этой школе, я в неё влюбилась, и загорелась желанием поступить в нее. Надеюсь, что моё желание обязательно сбудется.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Пару слов нашим читателям.","type":"paragraph"},{"html":"<strong>Настя: </strong>Верьте в свои мечты, и они обязательно сбудутся.","type":"paragraph"},{"type":"image","mediaId":"cmrmqvr4k00lvuktarjzjgbmf"}]'::jsonb,'cmrmqvqwp00luuktafiancayd','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-04-17T06:00:00.000Z'::timestamp,NULL,NULL,NULL,433,'/esquekids/obrazovanie-ek/433-nastya-lysakova-tochka-buduschego-jeto-shkola-moej-mechty.html','2026-07-15T21:02:20.634Z'::timestamp,'2026-07-16T13:59:18.502Z'::timestamp,'''10'':175C ''11'':52C ''16'':290C ''17'':293C ''2'':116C ''2021'':168C ''5'':275C,286C ''7'':102C ''bitva'':174C ''cmrmqvr4k00lvuktarjzjgbmf'':422C ''esqu'':68C,85C,140C,179C,211C,264C,305C,323C,399C ''fashion'':173C ''imag'':420C ''kid'':69C,86C,141C,180C,212C,265C,306C,324C,400C ''open'':165C ''paragraph'':66C,76C,83C,96C,138C,154C,177C,195C,209C,226C,262C,278C,303C,313C,321C,331C,397C,406C,418C ''star'':166C ''благодар'':340C ''будут'':32C,363C ''будущ'':4A,10B,15C,64C,308C,329C,335C ''важн'':251C ''верьт'':409C ''вид'':246C,272C ''виж'':295C ''визитн'':248C ''вкус'':241C ''влюб'':383C ''внедр'':185C ''внешн'':245C ''возраст'':27C ''вперед'':269C ''г'':169C ''дава'':266C ''двор'':43C ''дел'':74C ''детск'':114C ''дом'':113C ''дополнительн'':38C ''дума'':201C,319C ''желан'':386C,393C ''забеж'':268C ''загорел'':385C ''задумыва'':284C ''заменя'':40C ''занима'':91C,100C,107C,146C ''здравств'':71C,79C ''знан'':23C ''знают'':30C ''игрушк'':59C ''идеш'':222C ''индивидуальн'':353C ''интересн'':193C,205C ''использу'':130C ''испытыва'':220C ''кажд'':239C,350C ''как'':94C,123C,149C,217C,365C ''какие-т'':364C ''какого-т'':122C ''карточк'':249C ''кем'':31C ''коллектив'':110C ''красив'':259C ''лет'':53C,103C,106C,276C,287C,291C ''лысаков'':2A,51C ''любл'':372C ''малинк'':111C ''мероприят'':367C ''мечт'':8A,56C,339C,412C ''множеств'':37C ''мо'':7A,338C,392C ''мод'':216C,231C,256C ''моделинг'':147C ''модельн'':163C ''молод'':19C ''над'':390C ''надежн'':12B,17C ''например'':133C ''наст'