INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqz0pk00uwuktaynyghtsa','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'"Хочу и буду". Почему эта книга до сих пор популярна?','2017 год.','353-chto-interesnogo-pishet-m-labkovskij-v-svoej-knige-hochu-i-budu','[{"html":"2017 год. Выходит нашумевшая книга известного психолога М. Лабковского “Хочу и буду”. От колоссально огромного количества партий и популярности в книжных магазинах не выдерживают полки и нервы ожидающих. Раскрыт секрет счастливой и здоровой жизни и каждый стремится скорее перейти от теории к практике. Но так ли верна и ясна теория М. Лабковского, что можно жить так, как желает твое эго? И почему эта книга популярна до сих пор?","type":"paragraph"},{"html":"Михаил Лабковский - популярный психолог и большая его популярность от простых двух слов Хочу и Буду. Казалось бы, обычные слова, но на практике они несут совершенно иной подтекст. Он убеждает, что мы сами творцы своего счастья и наша цель - сделать жизнь уникальной и неповторимой. Это полностью верное суждение, если не внедряться в подробности, как именно это сделать. Если сказать просто - берешь и делаешь.","type":"paragraph"},{"html":"Михаил руководствуется практикой, которая на примере выглядит так:","type":"paragraph"},{"html":"Всем телом и душой не перевариваешь работу и коллег, офис душен, как натопленная баня. Не нравится? - Уходи. Иди пиши заявление по собственному.","type":"paragraph"},{"html":"Муж не уделяет должного внимания, не дарит подарки и не возит в отпуск. Вчера вечером опоздал на час и не предупредил. Кажется, я его больше не люблю. - Не любишь? Разводись. Найдешь лучше.","type":"paragraph"},{"html":"Сын не хочет учиться. Прямо отказывается ходить в школу и грызть гранит науки. Руки опускаются, не знаю, что делать. - Поднимите руки и отстаньте от сына. Когда захочет, тогда и пойдет в школу.","type":"paragraph"},{"html":"Мы тоже считаем, что он прав, но лишь в конечной точке. Результат будет именно такой, как он и говорит, но вопрос в преподнесении. Михаил использует в письме и в терапии практику “рубить с плеча”. Метод донесения знаний и информации достаточно сжат. Нет расшифровки, почему я должна уволиться с работы, если мне всего лишь там не нравится (для большого количества людей это неуважительная причина, но сейчас не об этом). <br /><br />","type":"paragraph"},{"html":"Давайте вместе разберем одну из ситуаций: Анна занимает должность бухгалтера, получает зарплату 60000р в месяц, трудится в офисе по стандартному графику 5/2 и в выходные позволяет детям занять ее досуг. По ночам девушка рисует, картины дают ей глоток свежего воздуха и запах желанной свободы. Но все это остается в ночи и с восходом солнца Анна по - прежнему бухгалтер. Она недовольна своим статусом, но что делать тоже не знает.","type":"paragraph"},{"html":"Будем опираться на решение Михаила Лабковского - уволиться. Но перед этим посетить несколько консультаций психолога, понять причину возникшей тревоги и желания все изменить, выяснить, какая деятельность приносит Анне удовольствие и как сделать так, чтобы в будущем приносила еще и доход. Сложить пазл, пожить с этими мыслями и потом только увольнение.","type":"paragraph"},{"html":"Михаил Лабковский прав, но он идет с конца.","type":"paragraph"},{"html":"Работа М. Лабковского “Хочу и буду” безусловно важна при изучении психологии, и, наше мнение, что с нее и нужно начать, но надо учитывать, что это всего лишь база. Сухая база.","type":"paragraph"}]'::jsonb,'cmrmqz0ne00uvuktaj06b1vvi','cmrm8kzpw000mkwtaocyn5161','cmrm8kzra000okwtaqek3edwq','cmrmpdrom0000sstarkqxwts4','2021-05-18T06:00:00.000Z'::timestamp,NULL,NULL,NULL,353,'/psihologija/samosovershenstvovanie/353-chto-interesnogo-pishet-m-labkovskij-v-svoej-knige-hochu-i-budu.html','2026-07-15T21:04:52.952Z'::timestamp,'2026