INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqqzx10036uktat6ouvisc','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Блиновскую отправили в СИЗО','Сегодня в Замоскворецком суде состоялось очередное слушание по делу блогера Елены Блиновской.','634-blinovskuju-v-sizo','[{"html":"Сегодня в Замоскворецком суде состоялось очередное слушание по делу блогера Елены Блиновской. Напомним, что весной прошлого года на «королеву марафонов» завели уголовное дело, причиной послужила неуплата налогов почти в 1 млрд рублей.","type":"paragraph"},{"html":"После 9 месяцев домашнего ареста суд отправил Блиновскую в СИЗО. По версии следствия, 23 декабря 2023 года блогер-миллиардер провела вечеринку, на которой общалась со свидетелем по делу Викторией Асмоловой. Вечеринка освещалась в СМИ. Так как общение со свидетелями Блиновской было запрещено, следствие потребовало изменение меры пресечения для блогера на «заключение под стражу». Все эти факты были установлены при допросе свидетеля Асмоловой.","type":"paragraph"},{"html":"Одновременно с ходатайством об аресте следствие предъявило Блиновской новые обвинения.","type":"paragraph"},{"html":"Блогера хотят привлечь по статье о неправомерном обороте средств платежей группой лиц по предварительному сговору , cообщило РИА Новости. Ей грозит до 16 лет колонии.","type":"paragraph"},{"html":"В данный момент полиция перевозит задержанную в изолятор №6 в «Печатники». После райской жизни в дорогостоящих пентхаусах с немалым количеством обслуживающего персонала, блогеру придется мыть туалеты, ведь в этом СИЗО чистоту поддерживают сами женщины.","type":"paragraph"}]'::jsonb,'cmrmqqzw00035ukta1o8fmq9k','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2024-01-22T06:00:00.000Z'::timestamp,NULL,NULL,NULL,634,'/v-mire/634-blinovskuju-v-sizo.html','2026-07-15T20:58:38.677Z'::timestamp,'2026-07-16T13:56:59.436Z'::timestamp,'''1'':46C ''16'':152C ''2023'':67C ''23'':65C ''6'':166C ''9'':53C ''cообщ'':146C ''paragraph'':50C,116C,129C,156C,193C ''арест'':56C,122C ''асмолов'':82C,114C ''блиновск'':1A,16B,28C,59C,92C,125C ''блогер'':14B,26C,70C,101C,131C,180C ''блогер-миллиардер'':69C ''верс'':63C ''весн'':31C ''вечеринк'':73C,83C ''виктор'':81C ''год'':33C,68C ''гроз'':150C ''групп'':141C ''дан'':159C ''декабр'':66C ''дел'':13B,25C,39C,80C ''домашн'':55C ''допрос'':112C ''дорогостоя'':173C ''ел'':15B,27C ''женщин'':191C ''жизн'':171C ''завел'':37C ''задержа'':163C ''заключен'':103C ''замоскворецк'':7B,19C ''запрещ'':94C ''изменен'':97C ''изолятор'':165C ''количеств'':177C ''колон'':154C ''королев'':35C ''котор'':75C ''лет'':153C ''лиц'':142C ''марафон'':36C ''мер'':98C ''месяц'':54C ''миллиардер'':71C ''млрд'':47C ''момент'':160C ''мыт'':182C ''налог'':43C ''напомн'':29C ''немал'':176C ''неправомерн'':137C ''неуплат'':42C ''нов'':126C ''новост'':148C ''обвинен'':127C ''оборот'':138C ''обслужива'':178C ''обща'':76C ''общен'':89C ''одновремен'':118C ''освеща'':84C ''отправ'':2A,58C ''очередн'':10B,22C ''пентхаус'':174C ''перевоз'':162C ''персона'':179C ''печатник'':168C ''платеж'':140C ''поддержива'':189C ''полиц'':161C ''послуж'':41C ''потребова'':96C ''предварительн'':144C ''предъяв'':124C ''пресечен'':99C ''привлеч'':133C ''придет'':181C ''причин'':40C ''провел'':72C ''прошл'':32C ''райск'':170C ''ри'':147C ''рубл'':48C ''сам'':190C ''свидетел'':78C,91C,113C ''сговор'':145C ''сегодн'':5B,17C ''сиз'':4A,61C,187C ''следств'':64C,95C,123C ''слушан'':11B,23C ''сми'':86C ''состоя'':9B,21C ''средств'':139C ''стат'':135C ''страж'':105C ''суд'':8B,20C,57C ''туалет'':183C ''уголовн'':38C ''установл'':110C ''факт'':108C ''ходатайств'':120C ''хот'':132C ''чистот'':188C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","