INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr0wgw011aukta7kr7pnhe','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Как прошел Russian Fashion Display 2021?','Russian Fashion Display вернулся в Милан в Первый месяц весны и порадовал итальянскую fashion-публику новыми именами российской моды.','301-kak-proshel-russian-fashion-display-2021','[{"html":"Russian Fashion Display вернулся в Милан в Первый месяц весны и порадовал итальянскую fashion-публику новыми именами российской моды.","type":"paragraph"},{"html":"Второй сезон культового модного события не заставил себя долго ждать - Russian Fashion Display digital пригласил любителей моды на fashion-шоу в Италии, которое прошло 27 марта.","type":"paragraph"},{"html":"Ограничений по посадке и дресс-коду не было, ведь шоу проходило в формате digital-трансляции, которую можно было посмотреть из любого уголка мира. Пять сильных дизайнеров, отобранных со всей России, выставили на суд искушенного зрителя свои лучшие наработки: <i><b><u>Мила Берсенева</u> презентовала новую коллекцию \"Secrets of the Magic forest\" - русский стиль в современном прочтении:</b></i>","type":"paragraph"},{"html":"<b><u>Виктория Надолинская</u> - традиционный участник Russian Fashion Display:</b><br /><br /><i></i>","type":"paragraph"},{"html":"<i><b><u>N&amp;S Vasenkovy</u> представила коллекцию \"Маленькая хозяйка медной горы\" - тематический показ прошел в деревянных избах в национальных русских кокошниках:</b></i><br /><br /><i></i>","type":"paragraph"},{"html":"<i><b><u>Ирина Акулина</u> дебютировала на мероприятии с капсульной коллекцией \"Ритм моего сердца\":</b></i><br /><br />","type":"paragraph"},{"html":"<b><i><u>Елена Мелякина - ТОП-5 свадебный дизайнер по версии \"Wedding Awards Russia\":</u></i></b><br /><br />","type":"paragraph"},{"html":"Целью проведения мероприятия Russian Fashion Display являлась не просто демонстрация очередных коллекций, но также активное продвижение российского синдиката Моды в рамках международного сотрудничества. Организаторы из раза в раз прилагают немало усилий для того, чтобы предложить публике, действительно, качественный fashion - продукт. Высочайшее уважение к зрителю и любовь к делу позволило организаторам и участникам Russian Fashion Display представить этой весной шоу, которое точно не было для вас «одним из…».","type":"paragraph"},{"html":"<iframe width=\"356\" height=\"200\" src=\"https://www.youtube.com/embed/S-FREowmXo0?feature=oembed\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen=\"\"></iframe>","type":"embed"},{"type":"gallery","items":[{"mediaId":"cmrmr0qha010vukta0kavc0y9"},{"mediaId":"cmrmr0r8l010wuktakhc6cyl9"},{"mediaId":"cmrmr0spu010xuktalr24m6ia"},{"mediaId":"cmrmr0t1n010yukta5l5k6r1c"},{"mediaId":"cmrmr0t7x010zukta4pxjii9u"},{"mediaId":"cmrmr0tiw0110uktahlxrrzp5"},{"mediaId":"cmrmr0tyn0111uktap99o6kqv"},{"mediaId":"cmrmr0u4k0112ukta3gbdsg5n"},{"mediaId":"cmrmr0ui30113uktacw6l33aq"},{"mediaId":"cmrmr0uo10114uktardok9i3j"},{"mediaId":"cmrmr0uv40115uktakezgtx80"},{"mediaId":"cmrmr0v560116uktackwjpw0t"},{"mediaId":"cmrmr0vle0117uktaaez2aev1"},{"mediaId":"cmrmr0w1p0118uktamszs2obn"},{"mediaId":"cmrmr0wds0119uktapfq0jfdh"}]}]'::jsonb,'cmrmr0ppv010uuktauah8xy5g','cmrm8kzv6000rkwtaq1nnscn1',NULL,'cmrmpdrom0000sstarkqxwts4','2021-04-03T06:00:00.000Z'::timestamp,NULL,NULL,NULL,301,'/projects-esque/russian-fashion-display/301-kak-proshel-russian-fashion-display-2021.html','2026-07-15T21:06:20.768Z'::timestamp,'2026-07-16T14:01:16.666Z'::timestamp,'''-5'':187C ''2021'':6A ''27'':75C ''award'':193C ''cmrmr0qha010vukta0kavc0y9'':272C ''cmrmr0r8l010wuktakhc6cyl9'':274C ''cmrmr0spu010xuktalr24m6ia'':276C ''cmrmr0t1n010yukta5l5k6r1c'':278C ''cmrmr0t7x010zukta4pxjii9u'':2