INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsw6500a5uktaknhnqd4v','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Канье Уэст рассказал о секретном шоу Yezzy','Канье Уэст поделился подробностями секретного шоу его бренда Yezzy, которое пройдёт сегодня в Париже только для 50 человек.','566-kane-ujest-rasskazal-o-sekretnom-shou-yezzy','[{"html":"Канье Уэст поделился подробностями \"секретного\" шоу его бренда Yezzy, которое пройдёт сегодня в Париже только для 50 человек. О том, что оно состоится, стало известно этим утром.","type":"paragraph"},{"html":"С Канье Уэстом поговорил критик журнала Vogue Люк Лейтч. Хип-хоп исполнитель и основатель Yezzy рассказал, что был очень рад работать с такими дизайнерами, как Шейн Оливер, Демна Гвасалия и Рикардо Тиши. Ранее СМИ сообщали, что новая коллекция Yezzy создавалась несколькими дизайнерами. Канье Уэст сравнил себя с Джорджом Лукасом, продюсером \"Звёздных войн\": он также \"берет симфонию идей, а потом играет песню\".","type":"paragraph"},{"html":"Описывая концепцию коллекции, Канье Уэст вспомнил старшую школу. В этот период жизни многим кажется, что они не вписываются в общество. Вероятно, на это отсылали школьные фотографии Ким Кардашьян, Анджелины Джоли и других известных женщин, которые Канье Уэст ранее разместил в своих соцсетях. Именно для антиконвенциональных людей будет предназначена новая коллекция Yezzy.","type":"paragraph"}]'::jsonb,'cmrmqsw5500a4uktajgm48cqj','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2022-10-03T06:00:00.000Z'::timestamp,NULL,NULL,NULL,566,'/fashion/news-2/566-kane-ujest-rasskazal-o-sekretnom-shou-yezzy.html','2026-07-15T21:00:07.133Z'::timestamp,'2026-07-16T13:57:49.935Z'::timestamp,'''50'':24B,42C ''paragraph'':54C,119C,173C ''vogu'':62C ''yezzi'':7A,16B,34C,71C,95C,171C ''анджелин'':149C ''антиконвенциональн'':165C ''берет'':111C ''бренд'':15B,33C ''вероятн'':141C ''войн'':108C ''вписыва'':138C ''вспомн'':126C ''гвасал'':85C ''демн'':84C ''джол'':150C ''джордж'':104C ''дизайнер'':80C,98C ''друг'':152C ''женщин'':154C ''жизн'':132C ''журна'':61C ''звездн'':107C ''игра'':116C ''ид'':113C ''известн'':50C,153C ''имен'':163C ''исполнител'':68C ''кажет'':134C ''кан'':1A,8B,26C,57C,99C,124C,156C ''кардашья'':148C ''ким'':147C ''коллекц'':94C,123C,170C ''концепц'':122C ''котор'':17B,35C,155C ''критик'':60C ''лейтч'':64C ''лукас'':105C ''люд'':166C ''люк'':63C ''мног'':133C ''нескольк'':97C ''нов'':93C,169C ''обществ'':140C ''оливер'':83C ''он'':47C ''описыв'':121C ''основател'':70C ''отсыла'':144C ''очен'':75C ''париж'':21B,39C ''период'':131C ''песн'':117C ''поговор'':59C ''подел'':10B,28C ''подробн'':11B,29C ''предназнач'':168C ''продюсер'':106C ''пройдет'':18B,36C ''работа'':77C ''рад'':76C ''размест'':159C ''ран'':89C,158C ''рассказа'':3A,72C ''рикард'':87C ''сво'':161C ''сегодн'':19B,37C ''секретн'':5A,12B,30C ''симфон'':112C ''сми'':90C ''создава'':96C ''сообща'':91C ''состо'':48C ''соцсет'':162C ''сравн'':101C ''стал'':49C ''старш'':127C ''так'':79C ''такж'':110C ''тиш'':88C ''утр'':52C ''уэст'':2A,9B,27C,58C,100C,125C,157C ''фотограф'':146C ''хип'':66C ''хип-хоп'':65C ''хоп'':67C ''человек'':25B,43C ''шейн'':82C ''школ'':128C ''школьн'':145C ''шо'':6A,13B,31C ''эт'':51C,143C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","crea