INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqzjj900wguktahqjx9ot2','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'“Подтяжка манекенщицы” или как обрести идеальное лицо','Спрос на пластическую хирургию хоть и сменил направление, но не утратил своей популярности.','339-podtjazhka-manekenschicy-ili-kak-obresti-idealnoe-lico','[{"html":"Спрос на пластическую хирургию хоть и сменил направление, но не утратил своей популярности. Так, в последнее время в бьюти-индустрии появилось много хирургов, которые обещают вам не просто красивое лицо, а прямо таки преображение, которое называется Rich Girl Face или по-другому в России лицо манекенщицы. Что скрывается за этой процедурой и насколько это верный способ приобрести модельную внешность?<br /><br />","type":"paragraph"},{"html":"<i><b><u>Что такое подтяжка манекенщицы?</u><u><br /><br /></u></b></i>","type":"paragraph"},{"html":"<i>Эта процедура обещает легкое и быстрое исполнение заветной мечты каждой девушки - миндалевидный разрез глаз и потрясающий разлет бровей. Такой эффект без каких-либо “но” и “если” должен быть у нас уже спустя 2 недели после операции. Но насколько это реально и безопасно?<br /><br /> </i>","type":"paragraph"},{"html":"<b><u>Есть несколько видов данной операции:</u></b><br /><br />1.<b> височный лифтинг или темпоральная подтяжка - боковая диагональная подтяжка лица</b>","type":"paragraph"},{"html":"Обычно такая операция дает хороший и достаточно долгий эффект и достаточно быструю реабилитацию. Но не все так сладко: к недостаткам можно отнести не нужный нам эффект распахнутого взгляда, а просто раскосый разрез. Конечно, это дело вкуса, но…","type":"paragraph"},{"html":"<b>Есть и еще недостатки</b>: слишком длинный шов, искажение черт (брови опускаются вниз, раскосый разрез глаз).","type":"paragraph"},{"html":"<br />2. э<b>ндоскопический лифтинг</b>","type":"paragraph"},{"html":"Имеет главное достоинство - отсутствие разрезов. При проведении эндоскопической подтяжки мягкие ткани лица отслаиваются через небольшие проколы и подтягиваются назад. При этом кожа не иссекается, а только перемещается.","type":"paragraph"},{"html":"<b>Плюсы</b>: нет разрезов, правильное направление подтяжки, красивый результат.","type":"paragraph"},{"html":"<b>Минусы:</b> долговременная потеря чувствительности по всей площади проведения операции, менее устойчивый эффект при длительной реабилитации.","type":"paragraph"},{"html":"3. <b>ТОП-лифтинг (темпароорбитальная пластика)</b>","type":"paragraph"},{"html":"Это улучшенная версия операции «подтяжка манекенщицы». Главное достоинство эндоскопической подтяжки — сохранение вертикального вектора перемещения тканей, при котором становится возможна качественная коррекция разреза глаз и линии бровей.","type":"paragraph"},{"html":"<b>Плюсы:</b> идеальный эффект, легкая быстрая реабилитация, долгосрочность результата, отсутствие отеков, синяков и быстрая реабилитация за счет того, что подтяжка выполняется на уровне поднадкостницы — самого нижнего слоя тканей лица. Она отличается высокой жесткостью, поэтому не будет растягиваться после подтяжки и поможет сохранить эффект на продолжительный срок.","type":"paragraph"},{"html":"ТОП-лифтинг проводится очень глубоко, но именно это гарантирует бескровность, «безотечность», безопасность и практически пожизненную эффективность операции.","type":"paragraph"},{"type":"image","mediaId":"cmrmqzjg500wfuktaqmak98tw"}]'::jsonb,'cmrmqzj6y00weuktach7cfrww','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyun0008kwtasfd55v5y','cmrmpdrom0000sstarkqxwts4','2021-05-04T06:00:00.000Z'::timestamp,NULL,NULL,NULL,339,'/beauty/tendencii/339-podtjazhka-manekenschicy-ili-kak-obresti-idealnoe-lico.html','2026-07-15T21:05:17.349Z'::timestamp,'2026-07-16T14:00:44.103Z'::timestamp,'''1'':143C ''2'':125C,214C ''3'':280C ''cmrmqzjg500wfuktaq