INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr1vzk014yukta6g0j6fmo','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Топ-5 современных российских художников','Их работы меняют привычные представления об искусстве и продаются на аукционах за сотни тысяч фунтов стерлингов.','278-top-5-sovremennyh-rossijskih-hudozhnikov','[{"html":"Их работы меняют привычные представления об искусстве и продаются на аукционах за сотни тысяч фунтов стерлингов. Рассказываем о самых успешных ныне живущих российских художниках, чьи имена должен знать каждый ценитель искусства.","type":"paragraph"},{"html":"<u><b><i>1. Илья Кабаков</i></b></u>","type":"paragraph"},{"html":"Самый \"дорогой\" современный российский художник в советское время был вынужден иллюстрировать детские книги и журналы и писать картины \"для себя\". Илья Кабаков прославился только после переезда в США, где он стал работать в соавторстве со своей женой Эмилией.","type":"paragraph"},{"html":"Художник переосмыслил жанры и темы, впоследствии ставшие ключевыми для московского концептуализма. Он работал в жанре альбома и стенда, писал картины от лица вымышленных персонажей и экспериментировал с текстом.","type":"paragraph"},{"html":"<br />Илья Кабаков первым начал создавать \"тотальные инсталляции\" – небольшие декорированные комнаты, заглянув в которые зритель будто оказывается в другой реальности. Такие инсталляции позволяют отобразить \"тотальное\" влияние пространства на человеческую жизнь.","type":"paragraph"},{"html":"<i>Изображение 1. Илья Кабаков </i><i>\"</i><i>Человек, улетевший в космос из своей комнаты</i><i>\"</i><i> (1985). Источник: the-village.ru </i>","type":"paragraph"},{"html":"По словам искусствоведа Дарьи Ворониной, картины Ильи Кабакова носят отпечаток эпохи застоя: «Художник показывает быт коммунальных квартир и жизнь \"маленького человека\", пытающегося вырваться из этого замкнутого круга, – как герой инсталляции \"Человек, улетевший в космос из своей комнаты\"».","type":"paragraph"},{"html":"<u><i><b>2. Эрик Булатов</b></i></u>","type":"paragraph"},{"html":"<br />Работы одной из самых знаменитых фигур московского концептуализма сегодня принадлежат ведущим российским и зарубежным музеям. Однако Эрик Булатов не был востребован в родном СССР. Так же, как и Илья Кабаков, он тридцать лет создавал иллюстрации, параллельно занимаясь живописью, и приобрел широкую известность лишь в эмиграции.","type":"paragraph"},{"html":"Стиль Эрика Булатова представляет собой слияние традиционной живописи и советской пропагандистской символики.","type":"paragraph"},{"html":"<i><b>«Соединяя привычные образы с текстом, художник показывает всю абсурдность и несостоятельность идеологических лозунгов эпохи застоя»</b></i>, – объясняет Дарья Воронина.","type":"paragraph"},{"html":"<i>Изображение 2. Эрик Булатов </i><i>\"</i><i>Свобода есть свобода </i><i>II</i><i>\"</i><i> (2000</i><i>–2001). Источник: arzamas.academy</i>","type":"paragraph"},{"html":"Эрика Булатова часто называют одним из основателей соц-арта. Но как считает художник, от представителей этого направления его отличает понимание ограниченности социальной действительности и стремление обрести подлинную свободу за её пределами.","type":"paragraph"},{"html":"<i><u><b>3. Виталий Комар и Александр Меламид</b></u></i>","type":"paragraph"},{"html":"Участники арт-группы \"Комар и Меламид\" считаются основоположниками соц-арта. «Они первыми в Советском Союзе позволили себе смеяться над властью в искусстве. Соц-арт стал ироническим аналогом поп-арта. Но если поп-арт возник как реакция на перепроизводство товаров потребления, то соц-арт был реакцией на \"перепроизводство\" пропаганды», – считает искусствовед Наталья Самкова.","type":"paragraph"},{"html":"Специально для ESQUE, Виталий Комар рассказал, что одним из своих несомненных достижений он считает работу \"Биография современника\", созданную в 1973 году: <i>«Тогда мы первыми объединили разные художественные стили в форме диптихов, триптихов и полиптихов, каждая часть которых была выполнена в разных стилях и воспринималась как стилистический словарь визуальных интонаций. По моему мнению, полистистилистика – это самое перспективное и интересное направление в искусстве. Её открытие было по-настоящему инновационной работой, хотя за неё мы не получили никаких премий».</i>","type":"paragraph"},{"html":"<i>Изображение 3. Виталий Комар и Александр Меламид </i><i>\"</i><i>Биография современника</i><i>\"</i><i> (1973). Источник: artguide.com </i>","type":"paragraph"},{"html":"Сегодня Виталий Комар чаще всего опирается на работы представителей академического стиля и кубофутуризма. Художник одинаково ценит все направления в искусстве: «Меня можно назвать концептуальным эклектиком. Сейчас эклектика играет в искусстве роль синтеза. Она очень реалистично отражает концепцию сознания – например, то, что сегодня мы верим одновременно и в бога, и в Дарвина. Будущее, как мне кажется, принадлежит эклектическому мировоззрению».","type":"paragraph"},{"html":"<br />По словам художника, соц-арт остается актуальным и для современной России: «Соц-арт, как мне кажется, актуален для всякого рода авторитарных форм мышления и правления».","type":"paragraph"},{"html":"<u><i><b>4. Семён Файбисович</b></i></u>","type":"paragraph"},{"html":"Работы мастера фотореализма ценятся как в России, так и за рубежом. Семён Файбисович поначалу пробовал себя в скульптуре, графике и традиционной живописи. Но известным его сделал именно фотоаппарат.","type":"paragraph"},{"html":"Вдохновившись эстетикой советской повседневности, в 70-х художник начал фотографировать обычных людей в обычной обстановке: пассажиров и пешеходов, демонстрантов и милиционеров, пьяниц и бомжей.","type":"paragraph"},{"html":"<b><i>«Его картины написаны по фотографиям. В этом причина такого правдивого и беспристрастного изображения деталей, одежды, мимики персонажей»,</i></b> – считает Дарья Воронина.","type":"paragraph"},{"html":"<i>Изображение 4. Семён Файбисович. Подружки из цикла </i><i>\"</i><i>На скамейках</i><i>\"</i><i> (1989). Источник: vladey.net </i>","type":"paragraph"},{"html":"Позднее, в 2000-х, Семён Файбисович стал фотографировать на телефон, а затем обрабатывать снимки в фотошопе и дополнять их живописными элементами.","type":"paragraph"},{"html":"<i><u><b>5. Григорий (Гриша) Брускин</b></u></i>","type":"paragraph"},{"html":"<br />Работы одного из самых успешных российских художников в советское время не были известны широкой публике. Популярность пришла к Грише Брускину лишь в 1988 году, после аукциона Сотбис (Sotheby’s) в Москве, на котором его работу \"Фундаментальный лексикон\" продали за рекордные 200 тыс. фунтов стерлингов.","type":"paragraph"},{"html":"<i>Изображение 5. Гриша Брускин </i><i>\"</i><i>Фундаментальный лексикон</i><i>\"</i><i>(1986). Источник: magisteria.ru</i>","type":"paragraph"},{"html":"По мнению Дарьи Ворониной, эту работу можно назвать азбукой советского человека: <b><i>«В этой картине художник собирает все типично советские образы – пионерки до работника НКВД, от свинарки до партийного работника»</i></b>.","type":"paragraph"},{"html":"В 1999 году Гриша Брускин создал триптих для реконструированного Рейхстага в Берлине. В 2012 году он стал лауреатом премии Кандинского. Художник активно использует в своем творчестве символы средневекового христианства, древневосточной философии и советской пропаганды. Он обращает внимание на эстетическую сторону упадка советской культуры и воспроизводит его в виде художественного перформанса.","type":"paragraph"},{"html":"<i>Текст: Анастасия Кулагина</i>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmr1vaf014uuktax2v0wzrz"},{"mediaId":"cmrmr1vhn014vuktac1c8pqba"},{"mediaId":"cmrmr1vqe014wuktamay50zls"},{"mediaId":"cmrmr1vy8014xukta8pbfje0p"}]}]'::jsonb,'cmrmr1v1g014tuktawkkpdgr1','