INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqvttd00m8ukta6bvqj7nn','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Лейла Мамедова: "Я выделяю стиль оверсайз"','Лейле 8 лет и уже в этом году она пойдет в первый класс.','430-lejla-mamedova-ja-vydeljaju-stil-oversajz','[{"html":"<strong>Лейле 8 лет и уже в этом году она пойдет в первый класс. Со своей будущей профессией юная модель уже давно определилась. Она хочет стать стилистом и подбирать девушкам красивые образы. </strong>","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Лейла, здравствуй. Расскажи немного о себе.","type":"paragraph"},{"html":"<strong>Лейла:</strong> Меня зовут Лейла. Мне 8 лет. В этом году я иду в первый класс. Мне нравится рисовать и пользоваться маминой косметикой.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Как ты решила стать моделью?","type":"paragraph"},{"html":"<strong>Лейла:</strong> Раньше я была фото моделью. Потом мне захотелось пойти в модельное агентство, чтобы стать популярной моделью.","type":"paragraph"},{"html":"<strong> Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Ты занимаешься в модельном агентстве «Premier Art» в Нижнем Новгороде. Какие дисциплины вам преподают?","type":"paragraph"},{"html":"<strong>Лейла:</strong> Нам нужно держать прямо осанку на дефиле и ходить крестом.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> В каких показах уже успела принять участие?","type":"paragraph"},{"html":"<strong>Лейла:</strong> Я участвовала на показе «Fashion bitva».","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Я знаю, что помимо моделинга у тебя еще очень много увлечений. Расскажи о каждом.","type":"paragraph"},{"html":"<strong>Лейла:</strong> Кроме модельного агентства, я хожу на плавание, чтобы быть сильной и здоровой. Ещё я люблю рисовать!","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Что ты для себя больше выделишь: рисование или плавание?","type":"paragraph"},{"html":"<strong>Лейла:</strong> Наверно, я для себя больше выделяю плавание.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Идем дальше. Как ты пришла к тому, что хочешь стать стилистом? Ты хочешь подбирать образы девушкам, верно?","type":"paragraph"},{"html":"<strong>Лейла:</strong> Да, верно. Я хочу стать стилистом, потому что хочу подбирать красивые образы девушкам.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Лейла, какой стиль в повседневной жизни ты выберешь для себя? Наверное, красивые платья?","type":"paragraph"},{"html":"<strong>Лейла:</strong> Для себя я, наверно, больше выделю стиль оверсайз, но точно не платья.","type":"paragraph"},{"html":"<strong>Esque</strong><strong>.</strong><strong>kids</strong><strong>:</strong> Пару слов нашим читателям.","type":"paragraph"},{"type":"image","mediaId":"cmrmqvts900m7uktaci582l6t"}]'::jsonb,'cmrmqvtg700m6ukta702dld77','cmrm8kzli000ikwtafbw33jnj','cmrm8l06k000wkwtaypf4yr7u','cmrmpdrom0000sstarkqxwts4','2022-04-09T06:00:00.000Z'::timestamp,NULL,NULL,NULL,430,'/esquekids/moda-ek/430-lejla-mamedova-ja-vydeljaju-stil-oversajz.html','2026-07-15T21:02:24.050Z'::timestamp,'2026-07-16T13:59:20.392Z'::timestamp,'''8'':8B,21C,70C ''art'':128C ''bitva'':171C ''cmrmqvts900m7uktaci582l6t'':323C ''esqu'':54C,90C,120C,153C,175C,214C,239C,278C,312C ''fashion'':170C ''imag'':321C ''kid'':55C,91C,121C,154C,176C,215C,240C,279C,313C ''paragraph'':52C,63C,88C,98C,118C,137C,151C,163C,173C