INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqz21a00v3uktaiyp3rtw2','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'«Ты такой деловой»: секреты делового общения','Собеседование с руководителем, встреча с президентом кампании или просто еженедельная «летучка» - во всех таких ситуациях деловое общение необходимо, как воздух.','350-ty-takoj-delovoj-sekrety-delovogo-obschenija','[{"html":"Собеседование с руководителем, встреча с президентом кампании или просто еженедельная «летучка» - во всех таких ситуациях деловое общение необходимо, как воздух. Нас учат спокойно держаться, чтобы «не упасть лицом в грязь», обращаться к собеседнику на Вы и не скрещивать руки на груди, чтобы не показать закрытой позой безразличие. Так ли это на самом деле и правда, что медленная и плавная речь лучше воспринимается в диалоге? Давайте разбираться со специалистами этой сферы.","type":"paragraph"},{"html":"Для того, чтобы встреча прошла эффективно и успешно, давайте рассмотрим несколько рекомендаций, которые сразу выделят вас из толпы и вы предстанете в лучшем свете.<br /><br />","type":"paragraph"},{"html":"Не пытайтесь сделать что-то нарочито правильно. Поступайте изначально верно.","type":"paragraph"},{"type":"image","mediaId":"cmrmqz20a00v2uktajep4jxw1"}]'::jsonb,'cmrmqz1ri00v1ukta9fwmxkid','cmrm8kzpw000mkwtaocyn5161','cmrm8kzra000okwtaqek3edwq','cmrmpdrom0000sstarkqxwts4','2021-05-15T06:00:00.000Z'::timestamp,NULL,NULL,NULL,350,'/psihologija/samosovershenstvovanie/350-ty-takoj-delovoj-sekrety-delovogo-obschenija.html','2026-07-15T21:04:54.670Z'::timestamp,'2026-07-16T14:00:35.807Z'::timestamp,'''cmrmqz20a00v2uktajep4jxw1'':143C ''imag'':141C ''paragraph'':98C,125C,139C ''безразлич'':73C ''верн'':137C ''воздух'':26B,46C ''воспринима'':88C ''встреч'':10B,30C,103C ''выдел'':114C ''груд'':67C ''гряз'':56C ''дава'':91C,108C ''дел'':79C ''делов'':3A,5A,22B,42C ''держа'':50C ''диалог'':90C ''еженедельн'':16B,36C ''закрыт'':71C ''изначальн'':136C ''кампан'':13B,33C ''котор'':112C ''летучк'':17B,37C ''лиц'':54C ''лучш'':122C ''медлен'':83C ''нарочит'':133C ''необходим'':24B,44C ''нескольк'':110C ''обраща'':57C ''общен'':6A,23B,43C ''плавн'':85C ''поз'':72C ''показа'':70C ''поступа'':135C ''правд'':81C ''правильн'':134C ''предстанет'':120C ''президент'':12B,32C ''прост'':15B,35C ''прошл'':104C ''пыта'':128C ''разбира'':92C ''рассмотр'':109C ''рекомендац'':111C ''реч'':86C ''рук'':65C ''руководител'':9B,29C ''сам'':78C ''свет'':123C ''сдела'':129C ''секрет'':4A ''ситуац'':21B,41C ''скрещива'':64C ''собеседник'':59C ''собеседован'':7B,27C ''специалист'':94C ''спокойн'':49C ''сраз'':113C ''сфер'':96C ''так'':20B,40C ''толп'':117C ''упаст'':53C ''успешн'':107C ''учат'':48C ''что-т'':130C ''эт'':76C ''эффективн'':105C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqr1cx003duktaoz2o37rs','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'"Голый" наряд сменился на русскую косу и крестьянскую рубашку: Ивлеева экспериментирует','20 декабря в московском клубе «Мутадор» состоялась вечеринка Анастасии Ивлеевой с весьма смелым дресс кодом «almost naked («почти голый»).Множество приглашенных звезд, украшения за 23 млн рублей, выступления артистов, мо','632-golyj-narjad-smenilsja-na-russkuju-kosu-i-krestjanskuju-rubashku-ivleeva-jeksperimentiruet','[{"html":"20 декабря в московском клубе «Мутадор» состоялась вечеринка Анастасии Ивлеевой с весьма смелым дресс кодом «almost naked («почти голый»).","type":"paragraph"},{"html":"Множество приглашенных звезд, украшения за 23 млн рублей, выступления артистов, море шампанского. Казалось, жизнь удалась. Могла ли об этом мечтать простая девочка из провинции?","type":"paragraph"},{"html":"Однако бал закончился и, сладкая жизнь золушки, тоже!","type":"paragraph"},{"html":"Уже утром 21 декабря новостные ленты СМИ пестрели заголовками: «Бал сатаны» от Насти Ивлеевой во время СВО», «Пир во время чумы», а комментарии возмущенных простых смертных лились рекой. Привыкшая к эпатажу героиня вечеринки, принялась просить у негодующей публики обсуждать вечеринку, как можно больше и дольше, чтобы \"сделать из тусовки крутой скандал\".","type":"paragraph"},{"html":"Новогоднее желание сбылось и скандал вышел поистине грандиозный, не утихающий и по сей день! А восторг от вечера и дерзость Ивлеевой, сменились на слезы, извинения, русскую косу и скромный наряд. Случилось бы это, если бы вокруг не поднялась волна шума и хейта в адрес организатора и гостей вечера?","type":"paragraph"},{"html":"<strong><em><u>Что имеем в итоге?</u></em></strong>","type":"paragraph"},{"html":"<strong>Тинькоф и МТС (</strong>по слухам — за один рекламный ролик звёзды получали от 10 до 20 млн рублей) <strong>расторгли рекламные контракты с Анастасией Ивлеевой. Известный продюсер </strong>Александр Иншаков и его инициативная группа подали иск в Хамовнический суд на 1 млрд","type":"paragraph"},{"html":"рублей за нанесение морального вреда.","type":"paragraph"},{"html":"«Принимая во внимание грубое нарушение ответчиком морально-нравственных принципов российского государства и общества, традиционных и культурных ценностей, считаем необходимым принять обеспечительные меры в виде наложения ареста на имущество Ивлеевой», — говорится в иске к блогерше.","type":"paragraph"},{"html":"<strong><em><u>Отмены участников бала</u></em></strong>","type":"paragraph"},{"html":"Стоит ли говорить, что гости вечера, громко ненавидят блогершу, ведь проблемы начались и у них.","type":"paragraph"},{"html":"Все концерты Лолиты Милявской отменены, Киркорова вырезают из новогодних шоу и даже эпизоды с участием Филиппа Бедросовича в фильме «Иван Васильевич меняет все» переснимают.","type":"paragraph"},{"html":"Отмены коснулись и других селебрити, побывавших на «голом» вечере Ивлеевой. В интервью Ксении Собчак отказали уже 2 человека, а Диму Билана и вовсе хотят лишить звания народного артиста.","type":"paragraph"},{"html":"Гости вечера наперебой стали записывать видео с извинениями и оправданиями. Примечательно, что опомнились они только тогда, когда в расписании их занятости стало пусто, а кошельки не досчитались круглых сумм за отмены выступлений, корпоративов и концертов.","type":"paragraph"},{"html":"«Я зашел не в ту дверь», - парировал в своем видео Филипп Киркоров.","type":"paragraph"},{"html":"Весь год мы видели отмены и уголовные преследования, еще вчера популярных и, казалось бы, неприкосновенных звезд, блогеров и телеведущих. Теперь же их судьба плачевна. Весьма очевидно, что как бы, не плакала и не изливала душу перед простым народом Анастасия Ивлеева, она повторит их путь и о светской и сытой жизни ей придется забыть!","type":"paragraph"},{"type":"image","mediaId":"cmrmqr19z003cuktachdmkri6"}]'::jsonb,'cmrmqr0z5003bukta7mn1xerg','cmrm8kzui000qkwtasyhozku0',NULL,'cmrmpdrom0000sstarkqxwts4','2023-12-29T06:00:00.000Z'::timestamp,NULL,NULL,NULL,632,'/v-mire/632-golyj-narjad-smenilsja-na-russkuju-kosu-i-krestjanskuju-rubashku-ivleeva-jeksperimentiruet.html','2026-07-15T20:58:40.545Z'::timestamp,'2026-07-16T13:57:00.698Z'::timestamp,'''1'':251C ''10'':226C ''2'':369C ''20'':12B,42C,228C ''21'':104C ''23'':36B,69C ''almost'':27B,57C ''cmrmqr19z003cuktachdmkri6'':495C ''imag'':493C ''nake'':28B,58C ''paragraph'':62C,89C,100C,154C,205C,212C,254C,262C,300C,306C,324C,351C,382C,420C,435C,491C ''адрес'':199C ''александр'':239C ''анастас'':20B,50C,235C,475C ''арест'':290C ''артист'':40B,73C,380C ''бал'':92C,111C,304C ''бедросович'':342C ''била'':373C ''блогер'':453C ''блогерш'':298C,316C ''васильевич'':346C ''ве'':437C ''весьм'':23B,53C,461C ''вечер'':173C,203C,313C,361C,385C ''вечеринк'':19B,49C,134C,141C ''вид'':288C ''виде'':389C,431C ''видел'':440C ''вниман'':266C ''вовс'':375C ''возмущен'':125C ''вокруг'':191C ''волн'':194C ''восторг'':171C ''вред'':260C ''врем'':117C,121C ''вчер'':446C ''выреза'':332C ''выступлен'':39B,72C,415C ''вышел'':161C ''героин'':133C ''говор'':294C,310C ''год'':438C ''гол'':1A,30B,60C,360C ''гост'':202C,312C,384C ''государств'':275C ''грандиозн'':163C ''громк'':314C ''груб'':267C ''групп'':244C ''двер'':427C ''девочк'':85C ''декабр'':13B,43C,105C ''ден'':169C ''дерзост'':175C ''дим'':372C ''дольш'':146C ''досчита'':410C ''дресс'':25B,55C ''друг'':356C ''душ'':471C ''желан'':157C ''жизн'':77C,96C,486C ''заб'':489C ''заголовк'':110C ''законч'':93C ''занят'':404C ''записыва'':388C ''зашел'':423C ''зван'':378C ''звезд'':33B,66C,223C,452C ''золушк'':97C ''ива'':345C ''ивлеев'':10A,21B,51C,115C,176C,236C,293C,362C,476C ''известн'':237C ''извинен'':180C,391C ''излива'':470C ''име'':208C ''имуществ'':292C ''инициативн''