ух'':218C ''случ'':186C ''смел'':24B,54C ''смен'':3A,177C ''смертн'':127C ''сми'':108C ''собчак'':366C ''состоя'':18B,48C ''стал'':387C,405C ''сто'':308C ''суд'':249C ''судьб'':459C ''сумм'':412C ''счита'':282C ''сыт'':485C ''телеведущ'':455C ''тинькоф'':214C ''традицион'':278C ''ту'':426C ''тусовк'':150C ''уголовн'':443C ''уда'':78C ''украшен'':34B,67C ''утиха'':165C ''утр'':103C ''участ'':340C ''участник'':303C ''филипп'':341C,432C ''фильм'':344C ''хамовническ'':248C ''хейт'':197C ''хот'':376C ''ценност'':281C ''человек'':370C ''чум'':122C ''шампанск'':75C ''шо'':335C ''шум'':195C ''экспериментир'':11A ''эпатаж'':132C ''эпизод'':338C ''эт'':188C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr1r6j014iuktax4rncy38','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Fashion Bitva. Хроника дня','21 февраля.','282-fashion-bitva-grandioznyj-final','[{"html":"21 февраля. Fashion bitva. Финал конкурса. Как подходит подготовка к итоговому показу сезона? Как себя насраивают конкурсанты? Какие секреты хранит в себе закулисье проекта? - Все это мы узнаем сегодня вместе с журналом Esque и его журналистом Коцур Викторией. Оставайтесь с нами!","type":"paragraph"},{"html":"<br /><b>12:07 </b>","type":"paragraph"},{"html":"Евгения Березуцкая - финалист из Санкт-Петербурга. Несмотря на волнение, присутствующее перед показом, дизайнер с радостью рассказала нам о гордости своей коллекции - пальто и юбка с портретом Сальвадора Дали. Вдохновением для Евгении стали ранние отношения художника и его музы. Работы дизайнера можно будет увидеть сегодня на показе.","type":"paragraph"},{"html":"<b>1</b><b>3:30</b> <br />В показе принимает участие сумки Elen Kaa. Все изделия выполнены из натуральной кожи итальянского производства. А микросумки - главный элемент коллекции. Кропотливая ручная работа с мелкими деталями никого не оставит равнодушным!","type":"paragraph"},{"html":"<b>14:07</b><br />На протяжении всего дня время дизайнеров расписано по минутам: нужно привести в порядок изделия, поработать с моделями и принять участие в предпоказе, чтобы успеть внести коррективы перед началом конкурса.","type":"paragraph"},{"html":"<b>14:32</b> <br />Алиса Гайфутдинова - финалист из Казани. Дизайнер представит изделия двух своих коллекций - из эко-кожи и из «белой коллекции». Практичность, стиль, женственность - ориентиры, которые Алиса берет за основу в своём творчестве.","type":"paragraph"},{"html":"<b>14:50</b><br />Показ - уникальное событие, которое привлекает внимание окружающих и модели находятся в самом эпицентре. Как сохранить спокойствие и продемонстрировать изделие дизайнера в лучшем свете? Поделилась с Esque одна из моделей показа - Ульяна Кулешова:","type":"paragraph"},{"html":"«Для меня это первый показ такого масштаба. Мне нравится быть моделью и демонстрировать такие красивые дизайнерские изделия. Если одолевает волнение, то я сразу прибегаю к дыхательной технике и состояние вновь нормализуется!»","type":"paragraph"},{"html":"<b>15:30</b>","type":"paragraph"},{"html":"Татьяна Чекенеева - финалист из Москвы. Концепция ее бренда - вектор, одежда для людей, которые знают своё направление и цель. <br />Дизайнера всегда вдохновляли бандажно-портупейные темы, поэтому Татьяна решила адаптировать такие изделия под обыденную жизнь. Как ей удалось воплотить свою идею - узнаем во время показа!","type":"paragraph"},{"html":"<b>15:50</b><br />В показе будут представлены детские коллекции четырёх дизайнеров: из Москвы, Санкт-Петербурга, Владивостока и Хабаровска. До начала мероприятия остались считанные минуты!","type":"paragraph"},{"html":"<b>16:20</b> <br />Несмотря на то, что мы находимся за кулисами финала конкурса, здесь царит дружественная атмосфера! Дизайнеры помогают друг другу приводить изделия в порядок, обмениваются контактами, опытом и добрыми пожеланиями.","type":"paragraph"},{"html":"<b>16:30</b><br />Прямо сейчас проходит репетиция показа коллекции Марины Толстовой. Дизайнер с детства вдохновлялась модой и уже сегодня воплотит в жизнь свою мечту - примет участие в финале конкурсе Fashion Bitva!","type":"paragraph"},{"html":"<b>16:57</b><br />Считанные минуты до показа, а у модели не та причёска. Что делать? Переделывать и скорее переодеваться! Показ мод - это мероприятие, которое предполагает огромное количество неординарных ситуаций, выход из которых нужно искать очень быстро!","type":"paragraph"},{"html":"<b>17:05</b>","type":"paragraph"},{"html":"Также зрители показа смогут увидеть выступление Samoilovaballet. Прямо сейчас, за кулисами конкурса, проходит их репетиция.","type":"paragraph"},{"html":"<b>17:20</b>","type":"paragraph"},{"html":"Чем ближе начало конкурса, тем больше накаляется обстановка. Ломается техника, волнуются модели, нервничают и сами конкурсанты. Как пройдёт показ их коллекции? Как отреагируют челны жюри? Все это узнаем совсем скоро!","type":"paragraph"},{"html":"<b>17:40</b>","type":"paragraph"},{"html":"Финал конкурса Fashion Bitva начался!","type":"paragraph"},{"html":"<b>17:50</b> <br />Алена Меркурьва открыла мероприятие этого вечера! Ее бренду \"ОТ МАМЫ С ЛЮБОВЬЮ\" всего два года, но он пользуется огромным успехом и популярностью. Жюри отметили подход дизайнера к выбору лаконичных и натуральных оттенков коллекции.","type":"paragraph"},{"html":"<b>17:59</b><br />Евгения Климкова продемонстрирована свой бренд \"Klimkova Kids\", который разработан специально для детей индиго. Главный ориентир дизайнера - свобода и потенциал.. За плечами Евгении более 20 лет работы с крупными корпорациями одежды и обуви, также она - участница Milano Fashion Week.","type":"paragraph"},{"html":"<b>18:04</b><br />Ирина Акулина - дизайнер из Владивостока. Ирина никогда не делает эскизов при создании моделей, вся работа происходит в реальном времени.","type":"paragraph"},{"html":"<b>18:10</b><br />Свою коллекцию представила Вера Григорьева - дизайнер из Хабаровска. Дизайнер пыталась воплотить главную идею - сделать платья для девочек такими же нарядными, как и для взрослых. Один из членов жюри (Ольга Сысоева) дала дизайнеру несколько рекомендаций.","type":"paragraph"},{"html":"<b>18:33</b>","type":"paragraph"},{"html":"Прямо сейчас проходит награждение моделей дипломами. Позже будет выбрана лучшая, которая получит сертификат на участие в Russian Fashion display в качестве модели.","type":"paragraph"},{"html":"<b>18:45</b>","type":"paragraph"},{"html":"Алина Сергеева и ее бренд \"Sergali\" открывает взрослое отделение. Алина из Барнаула, а ее бренду всего полгода, но у него уже есть свои поклонники. Своими работами дизайнер стремилась подчеркнуть индивидуальность и элегантность каждой женщины.","type":"paragraph"},{"html":"<b>18:50</b>","type":"paragraph"},{"html":"Сейчас на подиуме бренд \"Nadi Detel\" и его дизайнер Надежда Мочалова. Надежда - дизайнер из Йошкар-олы, ее бренду всего два месяца, но участие в конкурсе - трамплин и вдохновление для будущих побед и творческих идей! Ведущая мероприятия была одета в платье от Nadi Detel.","type":"paragraph"},{"html":"<b>18:57</b>","type":"paragraph"},{"html":"Светлана Кобзева - финалист из Краснодара. Через свои изделия пытается донести особый взгляд на моду. Удивительным остается тот факт, что за плечами дизайнера более 35 бухгалтерской деятельности, но это не помешало Светлане воплотить в жизнь свою давнюю мечту.","type":"paragraph"},{"html":"<b>19:00</b>","type":"paragraph"},{"html":"Евгения Березуцкая - финалист из Санкт-Петербурга, бренд \"Jenyaber\". Члены жюри поблагодарили дизайнера за выбор лаконичных и актуальных цветов, преобладающих в коллекции Евгении.","type":"paragraph"},{"html":"<b>19:05</b>","type":"paragraph"},{"html":"Алиса Гайфутдинова - финалист из Казани. С девушкой мы разговаривали до показа, в ее образах действительно преобладает женственность и элегантность, а элемент в виде цветов в руках у моделей лишь дополнил образ целиком.","type":"paragraph"},{"html":"<b>19:08</b>","type":"paragraph"},{"html":"Татьяна Чекенеева и ее бренд. Члены жюри отметили удачный выбор дизайнера в порядковом расположении моделей коллекции.","type":"paragraph"},{"html":"<b>19:08</b>","type":"paragraph"},{"html":"Наталья Стрельбицкая продемонстрировала свою линейку одежды. Наталья из Омска, а ее коллекция - возможность продемонстрировать ссвой потенциал и виденье моды.","type":"paragraph"},{"html":"<b>19:18</b>","type":"paragraph"},{"html":"На подиуме изделия дизайнера из Ногинска Марины Толстовой. После демонстрации коллекции, члены жюри поделились мнением и наставлениями относительно коллекции Марины.","type":"paragraph"},{"html":"<b>19:23</b>","type":"paragraph"},{"html":"Ольга Костюкова и ее бренд \"KOSOLA\". Образ моделей дополняли сумки от Анны Родионовой.","type":"paragraph"},{"html":"<b>19:28</b>","type":"paragraph"},{"html":"Ольга Дмитриева продемонстрировала свою линейку одежды. Пока весь мир сотрясала пандемия, Ольга решила воплотить свою давнюю мечту и создать свой fashion brаnd.","type":"paragraph"},{"html":"<b>19:30</b>","type":"paragraph"},{"html":"Ирина Дмитриева и ее бренд \"MAZARI TRADITION\".","type":"paragraph"},{"html":"<b>19:38</b>","type":"paragraph"},{"html":"Юлия Дежоли и ее бренд \"D.Jolie\". Юлия - дизайнер из Барнаула и ее главная задача - помочь женщинам жить в либви к своему телу, не сравнивая себя ни с кеми иным.","type":"paragraph"},{"html":"<b>19:42</b>","type":"paragraph"},{"html":"Полина Песковская - финалист из Волгограда. Девушке 16 лет и она ещё учится в школе. Ее модели вызвали восторг не только у зрителей, но и у членов жюри, которые настоятельно просили девушку развиваться и ни в коем случае не останавливаться на достигнутом!","type":"paragraph"},{"html":"<b>19:48</b>","type":"paragraph"},{"html":"Ая Левская - финалист из Самары. Яркие цвета коллекции и необычные решения в выборе моделей изделий. Члены жюри <u><i>(*сноска внизу)</i> </u>поделились своим мнением и ценными советами.","type":"paragraph"},{"html":"<b>19:54</b>","type":"paragraph"},{"html":"Прямо сейчас на подиуме коллекция Аи Москаленко - финалиста из Иркутска. Необычные модели и креативный подход в демонстрации своих изделий никого не оставил равнодушным.","type":"paragraph"},{"html":"<b>20:03</b>","type":"paragraph"},{"html":"Саша Гапанович и ее бренд одежды с Крайнего Севера. При создании одежды, Александра пыталась воплотить особенности культуры и природы Крайнего Севера. По-моему, дизайнеру это удалось!","type":"paragraph"},{"html":"<b>20:05 </b>","type":"paragraph"},{"html":"Начало второго отделения конкурса.","type":"paragraph"},{"html":"<b>20:36</b>","type":"paragraph"},{"html":"Второе отделение конкурса в самом разгаре. Прямую трансляцию финала можно увидеть в нашем аккаунте Instagram.","type":"paragraph"},{"html":"<b>20:50</b>","type":"paragraph"},{"html":"Прямо сейчас на подиуме коллекция Аи Москаленко. Дизайнер определенно пользуется популярностью среди зрителей!","type":"paragraph"},{"html":"<b>20:58</b>","type":"paragraph"},{"html":"Саша Гапанович и ее коллекция завершает конкурсный день битвы.<br />Члены жюри удалились для совещания.","type":"paragraph"},{"html":"<b>21:14</b>","type":"paragraph"},{"html":"Прямо сейчас проходит награждение дипломами и подарками всех финалистов конкурса.","type":"paragraph"},{"html":"<b>21:18</b>","type":"paragraph"},{"html":"Евгения Климкова стала победителем детского отделения!!!","type":"paragraph"},{"html":"<b>21:20</b>","type":"paragraph"},{"html":"В номинации взрослой коллекции победу одержала Ая Москаленко!!! Финал восьмого сезона конкурса Fashion Bitva Подошел к концу. Поздравляем всех конкурсантов и победителей!","type":"paragraph"},{"html":"<i><b>*</b> Жюри Конкурса</i>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmr1f28013guktaugsmgcba"},{"mediaId":"cmrmr1f7j013huktaevb3uu8h"},{"mediaId":"cmrmr1fcf013iuktam4l1cka5"},{"mediaId":"cmrmr1flx013juktakulbsyab"},{"mediaId":"cmrmr1fxm013kuktakh4p3tmr"},{"mediaId":"cmrmr1g91013luktalodldtue"},{"mediaId":"cmrmr1gjj013muktasjrc5670"},{"mediaId":"cmrmr1gpp013nukta4m03m3cj"},{"mediaId":"cmrmr1h5u013oukta8bfhivbq"},{"mediaId":"cmrmr1hm1013puktaz02ct80x"},{"mediaId":"cmrmr1i7o013qukta1gfsyus2"},{"mediaId":"cmrmr1ijq013rukta4bbb8zfc"},{"mediaId":"cmrmr1iso013suktaxpr1ozbw"},{"mediaId":"cmrmr1j5n013tuktaitth53em"},{"mediaId":"cmrmr1jhv013uuktajgjvh0qd"},{"mediaId":"cmrmr1jqh013vukta74gi8f2n"},{"mediaId":"cmrmr1jyv013wuktas5qt05zh"},{"mediaId":"cmrmr1kd7013xuktavvs2c1c2"},{"mediaId":"cmrmr1knv013yukta2tqpeknt"},{"mediaId":"cmrmr1kx9013zukta3du6ju26"},{"mediaId":"cmrmr1lac014