INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmqsybj00aeukta2aqfevr0','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Показ Balenciaga в Париже прошёл в пространстве из грязи','В рамках Недели моды в Париже состоялся показ новой коллекции Balenciaga на лето 2023 года.','564-pokaz-balenciaga-v-parizhe-proshel-v-prostranstve-iz-grjazi','[{"html":"<b>В рамках Недели моды в Париже состоялся показ новой коллекции Balenciaga на лето 2023 года. Модели шли по подиуму из земли.</b>","type":"paragraph"},{"html":"Основными предметами коллекции стали сумка-рукав и клоги. Последним образом показа стало платье, которое было вдохновлено сумкой Le Cagole.","type":"paragraph"},{"html":"Шоу открыл хип-хоп исполнитель и основатель бренда Yeezy Канье Уэст. Все модели шли по луже, которая была создана на подиуме из земли. Креативный директор Balenciaga Демна Гвасалия объяснил такой сет-дизайн стремлением «оставаться приземлённым». Также это отражает желание дизайнера «докопаться до правды».","type":"paragraph"},{"html":"Перед показам Демна Гвасалия признался, что ненавидит лейблы, которые ограничивают его. Дизайнер хочет чувствовать себя свободным от них. Также он призвал людей к миру: «Занимайтесь любовью, а не войной».","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmqsxko00abuktakewtta25"},{"mediaId":"cmrmqsxye00acukta0c8721co"},{"mediaId":"cmrmqsyak00aduktaah24edzo"}]}]'::jsonb,'cmrmqsxb200aauktahms0o69z','cmrm8ky9t0000kwta6h8ifq47','cmrm8kym30004kwtau27ffeiw','cmrmpdrom0000sstarkqxwts4','2022-10-02T06:00:00.000Z'::timestamp,NULL,NULL,NULL,564,'/fashion/news-2/564-pokaz-balenciaga-v-parizhe-proshel-v-prostranstve-iz-grjazi.html','2026-07-15T21:00:09.920Z'::timestamp,'2026-07-16T13:57:51.642Z'::timestamp,'''2023'':23B,38C ''balenciaga'':2A,20B,35C,98C ''cagol'':68C 