INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr08jj00yzuktafdd3cysg','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Косметичка этой весной: ее содержимое','Весной мы расправляем крылья во всех смыслах и наслаждаемся свободой, которая должна быть во всем.','316-kosmetichka-jetoj-vesnoj-ee-soderzhimoe','[{"html":"Весной мы расправляем крылья во всех смыслах и наслаждаемся свободой, которая должна быть во всем. Сегодня поговорим о свободе в нашей косметичке: как она меняется с весной, какие средства мы оставляем, а какие меняем.","type":"paragraph"},{"html":"<i><u>Оставляем<br /></u><br /></i>","type":"paragraph"},{"html":"<i>Яркие румяна</i>","type":"paragraph"},{"html":"Не скупимся на оттенки, смешиваем разные текстуры и цвета. К счастью, сейчас мы можем эксперементировать еще и с форматами: кушон, стики, шайбы. Наносим румяна на яблочки щек и мягко протягиваем к виску. А чтобы создать эффект загара, наносим на кончик носа и подбородок. Все оттенки розового и кораллового - все они модники это весной!<br /><br />","type":"paragraph"},{"html":"<i>румяна для лица MAC POWDER BLUSH </i><br />","type":"paragraph"},{"html":"<i>Черный карандаш для глаз <br /></i>Он один из наших любимчиков этой весной - обводим глаза, делаем растушевку, заполняем межресничку. Выбирайте гелевую формулу - такой грифель мягко скользит по коже век и не оставляет повреждений.<br /><br /><i>карандаш-подводка для век Yves Saint Laurent</i>","type":"paragraph"},{"html":"<i>Кушон вместо тонального крема<br /></i>Ухоженная кожа всегда в тренде, но уход бывает разным. Весной и летом в приоритете легкое покрытие. С такой задачей справится кушон. Вы за считанные секунды приведете свой макияж в порядок, принеся коже при этом только пользу.<br /><br /><i>кушон DIOR</i> <br /><br />","type":"paragraph"},{"html":"<i><u>Добавляем<br /></u><br /></i><i>Яркие тени</i>","type":"paragraph"},{"html":"Насыщенные цвета набирают обороты и палеток с яркими оттенками этой весной должно быть, как минимум две. Визажисты советуют обращать внимание на розовые, желтые, голубые и зеленые оттенки. Вдохновляемся видео-обзорами в Инстаграмме, Tik Tok и повторяем незамедлительно. <br /><br />","type":"paragraph"},{"html":"<i>тени для век NYX </i><br />","type":"paragraph"},{"html":"<i><b>НЕ</b>черная тушь</i>","type":"paragraph"},{"html":"<i> </i>Чередуем с яркими оттенками теней. Черная тушь медленно уходит с наших полок - вернем зимой. Даже такой обычный цвет туши, как коричневый, может придать блеск и красоту вашему натуральному цвету глаз. А еще лучше, попробуйте цвет индиго или изумрудный. Уверены, вам понравится и вы побежите за розовой или желтой).<br /><br />","type":"paragraph"},{"html":"<i>тушь для ресниц Yves Saint Laurent Mascara Vinyl Couture </i><br />","type":"paragraph"},{"html":"<i>Естественный тинт для губ</i>","type":"paragraph"},{"html":"Эффект зацелованных губ снова в трендах. Тинт поможет вам создать такой эффект, без привлечения вашего мужчины. Способ нанесения максимально простой: наносим по контуру и небрежно растушевываем.<br /><br />","type":"paragraph"},{"html":"<i>тинт для губ CLARINS</i>","type":"paragraph"},{"html":"<u>ИМ НЕ МЕСТО В КОСМЕТИЧКЕ </u>","type":"paragraph"},{"type":"gallery","items":[{"mediaId":"cmrmr074500ytuktauaid2288"},{"mediaId":"cmrmr07de00yuukta9kwjr8xu"},{"mediaId":"cmrmr07lw00yvuktab117r06t"},{"mediaId":"cmrmr080200ywukta39eoe2zp"},{"mediaId":"cmrmr08by00yxukta1gzber96"},{"mediaId":"cmrmr08ic00yyuktakqt6uf7e"}]}]'::jsonb,'cmrmr06dl00ysukta4z2sh189','cmrm8kyru0007kwta7gtx5jk3','cmrm8kyun0008kwtasfd55v5y','cmrmpdrom0000sstarkqxwts4','2021-04-16T06:00:00.000Z'::timestamp,NULL,NULL,NULL,316,'/beauty/tendencii/316-kosmetichka-jetoj-vesnoj-ee-soderzhimoe.html','2026-07-15T21:05:49.759Z'::timestamp,'2026-07-16T14:01:02.313Z'::timestamp,'''b