82C ''палеток'':230C ''побеж'':322C ''поврежден'':162C ''повторя'':261C ''поговор'':37C ''подбородок'':109C ''подводк'':165C ''покрыт'':193C ''полок'':290C ''польз'':213C ''поможет'':356C ''понрав'':319C ''попроб'':312C ''порядок'':207C ''приведет'':203C ''привлечен'':362C ''прида'':301C ''прин'':208C ''приоритет'':191C ''прост'':368C ''протягива'':96C ''разн'':72C,186C ''расправля'':8B,23C ''растушевк'':146C ''растушевыва'':374C ''ресниц'':332C ''розов'':112C,246C,324C ''румя'':63C,90C,123C ''сво'':204C ''свобод'':15B,30C,39C ''сегодн'':36C ''секунд'':202C ''скольз'':155C ''скуп'':68C ''смешива'':71C ''смысл'':12B,27C ''снов'':352C ''совет'':242C ''содержим'':5A ''созда'':101C,358C ''способ'':365C ''справ'':197C ''средств'':49C ''стик'':87C ''счаст'':77C ''счита'':201C ''текстур'':73C ''тен'':221C,266C,283C ''тинт'':343C,355C,378C ''тональн'':176C ''тренд'':182C,354C ''туш'':275C,285C,297C,330C ''увер'':317C ''уход'':184C,287C ''ухожен'':178C ''формат'':85C ''формул'':151C ''цвет'':75C,226C,296C,307C,313C ''череду'':279C ''черн'':132C,274C,284C ''шайб'':88C ''щек'':93C ''эксперементирова'':81C ''эт'':118C ''эффект'':102C,349C,360C ''яблочк'':92C ''ярк'':62C,220C,232C,281C'::tsvector) ON CONFLICT (id) DO UPDATE SET "type"=EXCLUDED."type","status"=EXCLUDED."status","title"=EXCLUDED."title","subtitle"=EXCLUDED."subtitle","slug"=EXCLUDED."slug","content"=EXCLUDED."content","coverId"=EXCLUDED."coverId","sectionId"=EXCLUDED."sectionId","rubricId"=EXCLUDED."rubricId","authorId"=EXCLUDED."authorId","publishedAt"=EXCLUDED."publishedAt","scheduledAt"=EXCLUDED."scheduledAt","seoTitle"=EXCLUDED."seoTitle","seoDescription"=EXCLUDED."seoDescription","legacyId"=EXCLUDED."legacyId","legacyUrl"=EXCLUDED."legacyUrl","createdAt"=EXCLUDED."createdAt","updatedAt"=EXCLUDED."updatedAt","searchVector"=EXCLUDED."searchVector";
INSERT INTO "Post" ("id","type","status","title","subtitle","slug","content","coverId","sectionId","rubricId","authorId","publishedAt","scheduledAt","seoTitle","seoDescription","legacyId","legacyUrl","createdAt","updatedAt","searchVector") VALUES ('cmrmr2743015uukta4zvkg062','ARTICLE'::"PostType",'PUBLISHED'::"PostStatus",'Как изменился российский кинематограф в период пандемии?','Изменения в российском кинематографе из-за пандемии можно сравнить с переворотом или фильмом ужасов.','273-kak-izmenilsja-rossijskij-kinematograf-v-period-pandemii','[{"html":"Изменения в российском кинематографе из-за пандемии можно сравнить с переворотом или фильмом ужасов. Стоит ли нам ждать премьер, вернется ли зритель в пустующие залы кинотеатров и какие картины посмотреть, оставаясь на карантине? Эти вопросы беспокоят не только простых граждан, но и экспертов в этой области.","type":"paragraph"},{"text":"Отсутствие зрителей","type":"heading"},{"html":"Традиционный бизнес кинотеатров сильно пострадал от пандемии. Так, за время карантина сильно изменился способ потребления кинопродукции. Сейчас все больше людей отдают предпочтение онлайн просмотру фильмов и сериалов. Повышение спроса подтолкнуло владельцев онлайн-кинотеатров предоставлять скидки или бесплатный просмотр каналов, фильмов. Это позволило им нарастить аудиторию. Сегодня даже премьеры мирового уровня переходят в онлайн-режим.","type":"paragraph"},{"html":"Что касается традиционных кинозалов, то здесь ситуация плачевная. При уменьшении количества кинозрителей, расходы не снизились, за исключением аренды. Большую часть премьер перенесено на весну. Даже новая версия фильма о Джеймсе Бонде откладывалась дважды. Зритель меняет свое отношение к просмотру киноконтента.","type":"paragraph"},{"text":"Смогут ли онлайн-платформы заменить традиционные кинозалы?","type":"heading"},{"html":"Часть российских кинокомпаний совсем отказались от проката своих лент в кинотеатрах. Так, на платформе «Кинопоиск HD» можно посмотреть новые фильмы: «Фея», «Спутник» и другие. Многие онлайн-платформы для удержания пользователей используют сериалы с оригинальным сюжетом, часто снятые на заказ. В числе таких сериалов есть комедии, триллеры и политические антиутопии. И все это расширяет аудиторию и повышает прибыль онлайн-кинотеатров.","type":"paragraph"},{"html":"Многие кинопродюсеры и режиссеры признают, что больно отдавать новый фильм сразу в сеть без показа на большом экране. Но в то же время, этот вариант может быть выгодным для картин с бюджетом среднего размера. Крупные блокбастеры от показа в интернете только проигрывают, ведь онлайн-показы не помогут окупить колоссальные затраты.","type":"paragraph"},{"text":"Будут ли премьеры в новом году?","type":"heading"},{"html":"Обычно сезон новогодних праздников – главный период громких премьер. Но этот год стал необычным. Раньше за первый месяц года кинотеатры собирали треть годового оборота, в этом январе ситуация плачевная.","type":"paragraph"},{"html":"Из-за второй волны пандемии российские режиссеры не могут завершить съемки, а кинотеатры отказываются включать в прокат новинки, когда заполняемость залов минимальная. Вводимые ограничения не позволяют собирать одновременно на съемочных площадках много людей.","type":"paragraph"},{"html":"В результате российских кинофильмов в 2021 году выйдет на 25% меньше. Это связано с переносом съемок, изменением дат премьерных показов и отсутствием финансирования. Нередко выпуск российского кино зависит от государственных субсидий, без которых крупные проекты запустить сложно. Драм будет меньше – они дороже, а комедий больше. Последние привлекают больше зрителей, дешевле в производстве и являются тем, что необходимо людям, чтобы пережить тяжелые периоды в жизни.","type":"paragraph"},{"html":"Участники кинематографической отрасли не теряют надежд. Восстановление кинорынка ожидают уже в середине наступившего года, когда пандемия пойдет на спад. С учетом того, что многие громкие премьеры перенесены на весну 2021 года, есть надежда, что кинорынок будет восстанавливаться стремительными темпами.","type":"paragraph"}]'::jsonb,'cmrmr270n015tuktat6z9f5ue','cmrm8kz36000ckwtabqfh3f4h','cmrm8kz8q000ekwtadrt5g1dn','cmrmpdrom0000sstarkqxwts4','2021-01-19T06:00:00.000Z'::timestamp,NULL,NULL,NULL,273,'/sobytija/iskusstvo/273-kak-izmenilsja-rossijskij-kinematograf-v-period-pandemii.html','2026-07-15T21:07:21.219Z'::timestamp,'2026-07-16T14:01:40.758Z'::timestamp,'''2021'':391C,482C ''25'':395C ''hd'':206C ''head'':76C,189C,316C ''paragraph'':71C,135C,178C,253C,307C,347C,384C,451C,493C ''антиутоп'':240C ''аренд'':154C ''аудитор'':123C,245C ''бесплатн'':115C ''беспоко'':59C ''бизнес'':79C ''блокбастер'':290C ''больн'':261C ''больш'':155C,271C ''бонд'':167C ''будут'':309C ''бюджет'':286C ''вариант'':279C ''вводим'':372C ''вернет'':43C ''верс'':163C ''весн'':160C,481C ''включа'':364C ''владельц'':108C ''волн'':353C ''вопрос'':58C ''восстанавлива'':489C ''восстановлен'':459C ''врем'':87C,277C ''втор'':352C ''выгодн'':282C ''выйдет'':393C ''выпуск'':410C ''главн'':322C ''год'':314C,328C,335C,392C,466C,483C ''годов'':339C ''государствен'':415C ''гражда'':63C ''громк'':324C,477C ''дат'':403C ''дважд'':169C ''дешевл'':435C ''джеймс'':166C ''дорож'':427C ''драм'':423C ''друг'':214C ''ждат'':41C ''жизн'':449C ''заверш'':359C ''завис'':413C ''заказ'':230C ''зал'':48C,370C ''замен'':185C ''заполняем'':369C ''запуст'':421C ''затрат'':305C ''зрител'':45C,74C,170C,434C ''из-з'':12B,27C,349C ''измен'':2A,90C ''изменен'':8B,23C,402C ''интернет'':294C ''исключен'':153C ''использ'':222C ''как'':51C ''канал'':117C ''карантин'':56C,88C ''картин'':52C,284C ''каса'':138C ''кин'':412C ''кинематограф'':4A,11B,26C ''кинематографическ'':454C ''кинозал'':140C,187C ''кинозрител'':148C ''кинокомпан'':193C ''киноконтент'':176C ''кинопоиск'':205C ''кинопродукц'':93C ''кинопродюсер'':256C ''кинорынк'':460C ''кинорынок'':487C ''кинотеатр'':49C,80C,111C,201C,251C,336C,362C ''кинофильм'':389C ''количеств'':147C ''колоссальн'':304C ''комед'':